const SCENARIOS = {
  pitcher: [
    {id:"p1",title:"Full Count Pressure",diff:3,cat:"pressure",conceptTag:"count-leverage",ageMin:9,ageMax:99,
      description:"Bottom 9th, bases loaded, 2 outs. Tie game. The cleanup hitter has been hot. Count is full 3-2. What's your pitch?",
      situation:{inning:"Bot 9",outs:2,count:"3-2",runners:[1,2,3],score:[4,4]},
      options:["Fastball down the middle — challenge him","Slider low and away — make him chase","Changeup — keep him off balance","Inside fastball — brush him back"],
      best:1,explanations:["Too risky! MLB hitters bat .350+ on middle-middle fastballs in high-leverage spots, so you are asking to get crushed.","Perfect! The slider low-away gets a 34% whiff rate in full counts, because you make him chase out of the zone.","On 3-2 with bases loaded, a changeup that misses becomes ball four — walk-off walk.","Inside on 3-2 with bases loaded? If you miss, it's a walk-off walk. Too much risk."],
      rates:[30,85,55,15],concept:"Pitch location beats velocity in pressure situations",anim:"strikeout"},
    {id:"p2",title:"First Batter of the Game",diff:1,cat:"counts",conceptTag:"first-pitch-strike",ageMin:6,ageMax:99,
      description:"Top of the 1st. You're facing the leadoff hitter — a contact guy who gets on base. What's your approach?",
      situation:{inning:"Top 1",outs:0,count:"0-0",runners:[],score:[0,0]},
      options:["First-pitch fastball for a strike","Start with a curveball to surprise him","Throw a changeup to set up your fastball","Waste a pitch high and inside"],
      best:0,explanations:["Great! Getting ahead 0-1 is huge, since pitchers who throw first-pitch strikes have ERAs nearly 2 runs lower.","Risky to start with a breaking ball — if it hangs, he'll jump on it, because the downside outweighs the potential gain.","Changeups work best when he expects fastball, because first pitch, he doesn't know yet.","Wasting pitches against a leadoff hitter just drives up your pitch count."],
      explSimple:["Nice! Throwing a strike first makes the batter have to worry. You're in charge now.","Starting with a tricky pitch can go wrong because it's hard to control.","A changeup works better later when the batter is expecting a fastball.","Throwing balls on purpose just wastes pitches and lets the batter get comfortable."],
      rates:[85,40,50,30],concept:"Getting ahead in the count is a pitcher's biggest advantage",anim:"strike"},
    {id:"p3",title:"Runner Threatening to Steal",diff:2,cat:"baserunners",conceptTag:"steal-breakeven",ageMin:11,ageMax:99,
      description:"Speedster on 1st — 40 stolen bases this year. He's taking a big lead. Count is 1-0.",
      situation:{inning:"Top 4",outs:0,count:"1-0",runners:[1],score:[2,1]},
      options:["Throw over to first","Quick-pitch with a slide step","Pitch out","Stick with your full windup to maximize pitch quality"],
      best:1,explanations:["Throwing over is fine, but the runner is still fast afterward.","The slide step cuts delivery from 1.5s to 1.2s, giving the catcher a real chance to throw him out.","A pitchout on 1-0 makes it 2-0 — terrible count.","Sticking with your full windup against a speedster is risky — the windup takes too long and gives the runner a huge jump."],
      explSimple:["Throwing to first is okay, but it doesn't stop him from running next time.","A quick pitch helps your catcher throw the runner out because you get the ball there faster.","A pitchout means another ball, and now the count is bad for you.","Your full windup gives the runner way too much time to steal!"],
      rates:[50,80,35,25],concept:"The slide step controls the running game without hurting pitch count",anim:"strike"},
    {id:"p4", conceptTag:"pitch-sequencing",title:"Protecting a Lead",diff:2,cat:"late-game",ageMin:9,ageMax:99,
      description:"Top 8th, up 3-1, runners on 1st and 2nd, 1 out. Power hitter up. Your arm is tired.",
      situation:{inning:"Top 8",outs:1,count:"0-0",runners:[1,2],score:[3,1]},
      options:["Fastballs — go right after him","Pitch around him","Mix speeds — work the corners","Ask to come out"],
      best:2,explanations:["Tired arm = less velocity, which means challenging a power hitter with diminished stuff is dangerous.","Pitching around loads the bases — tying run comes to the plate.","Smart! Changing speeds when tired beats trying to overpower, because you keep him guessing.","That is the manager's decision to make — your job is to compete and give everything you have until he tells you otherwise."],
      explSimple:["When your arm is tired, your fastball isn't as fast — a big hitter could crush it.","Pitching around him fills up the bases, and that makes things even scarier.","Smart! When you're tired, trick the batter by mixing slow and fast pitches instead of throwing hard.","It's not your decision to leave the game — keep competing and do your best."],
      rates:[30,40,80,55],concept:"When fatigued, pitching smart (mixing speeds) beats pitching hard",anim:"strike"},
    {id:"p5",title:"Setting Up the Strikeout",diff:2,cat:"counts",conceptTag:"count-leverage",ageMin:9,ageMax:99,
      description:"2 outs, 6th inning, nobody on. Count is 0-2 on a slugger who homered off you earlier.",
      situation:{inning:"Bot 6",outs:2,count:"0-2",runners:[],score:[5,3]},
      options:["Waste one in the dirt","Fastball up in the zone","Slider on the outside corner","Fastball down the middle — dare him"],
      best:0,explanations:["Waste one in the dirt — with 0-2 you can afford a ball, and it expands his zone before you finish him off.","He already homered off your fastball, so giving him another one he can see is just asking for trouble.","Good but risky — if the slider hangs, it's right in his wheelhouse, and one mistake could end up in the seats.","Never challenge a guy who already went deep off you!"],
      explSimple:["You have two strikes already, so you can throw one in the dirt and see if he chases it.","He already hit a home run off your fastball — don't give him the same pitch again!","A slider could work, but if you don't throw it perfectly, he might hit it hard.","Throwing it right down the middle to a guy who already homered off you is a bad idea!"],
      rates:[85,35,60,10],concept:"Use waste pitches on 0-2 to expand the zone before the strikeout pitch",anim:"strikeout"},
    {id:"p6",title:"Double Play Groundball",diff:2,cat:"situational",conceptTag:"dp-positioning",ageMin:9,ageMax:99,
      description:"Runners on 1st and 2nd, nobody out. Need a ground ball. Lefty batter likes the ball up. Count 1-1.",
      situation:{inning:"Bot 3",outs:0,count:"1-1",runners:[1,2],score:[2,2]},
      options:["Sinker down in the zone","High fastball where he likes it","Curveball in the dirt","Changeup away"],
      best:0,explanations:["Sinkers generate ground balls at nearly 2x the rate of four-seamers — double play time.","Throwing where a hitter is comfortable when you need a groundball = bad combo.","Curveball in the dirt could be a wild pitch advancing both runners.","Changeup away can work, but the sinker is the ground ball gold standard."],
      explSimple:["A sinker dips down and makes batters hit the ball on the ground — perfect for a double play!","Throwing where the batter likes it makes it easy for him to get a hit.","A curveball in the dirt could bounce away and let the runners move up.","A changeup is okay, but a sinker is the best pitch for getting ground balls."],
      rates:[85,15,25,55],concept:"Sinkers and two-seamers are the best double play pitches",anim:"groundout"},
    {id:"p7", conceptTag:"pitch-sequencing",title:"Inherited Runners",diff:3,cat:"pressure",ageMin:12,ageMax:99,
      description:"You just entered in relief. Runners on 2nd and 3rd, 1 out, tie game. Right-handed contact hitter up.",
      situation:{inning:"Bot 7",outs:1,count:"0-0",runners:[2,3],score:[3,3]},
      options:["Go right after him","Walk him to set up a force at home","Try for the strikeout","Pitch carefully — nothing to drive"],
      best:3,explanations:["Coming in cold and challenging a contact hitter with RISP is reckless.","Loading bases means a walk or HBP scores the go-ahead run.","Striking out a contact hitter when you're cold is tough.","Smart! Pitch the corners and make him get himself out on weak contact — nothing in the heart of the zone."],
      rates:[35,30,40,80],concept:"In high-leverage relief, pitch to contact carefully — don't try to overpower",anim:"groundout"},
    {id:"p8", conceptTag:"count-leverage",title:"Pitcher's Count",diff:2,cat:"counts",ageMin:9,ageMax:99,
      description:"Nobody on, 2 outs. 0-2 count on the #8 hitter who's been swinging at everything.",
      situation:{inning:"Top 5",outs:2,count:"0-2",runners:[],score:[4,2]},
      options:["Fastball up and in","Slider down and away","Fastball off the plate","Curveball in the dirt"],
      best:3,explanations:["Fastball in on 0-2 can work, but if you miss over the plate...","Decent but predictable, because in this situation, there are better options that give you more control of the at-bat.","A fastball off the plate is unpredictable for strikeouts — breaking balls that look like strikes are more effective.","The 0-2 curveball in the dirt is a classic strikeout pitch, since an aggressive hitter will chase it."],
      explSimple:["A fastball inside could work, but if it goes over the plate he might hit it.","A slider is okay but the batter might be expecting it.","A fastball outside the zone isn't the best way to trick him.","A curveball in the dirt is the best trick pitch! He'll swing and miss because it looks like a strike but drops down."],
      rates:[33,35,31,80],concept:"The 0-2 curveball in the dirt is baseball's classic strikeout pitch",anim:"strikeout"},
    {id:"p9", conceptTag:"times-through-order",title:"Third Time Through the Order",diff:3,cat:"adjustments",ageMin:12,ageMax:99,
      description:"6th inning, facing the lineup a 3rd time. Leadoff hitter crushed your fastball last time.",
      situation:{inning:"Top 6",outs:0,count:"0-0",runners:[],score:[3,2]},
      options:["Throw the fastball again","Lead with a changeup","Start with a slider","Pitch inside"],
      best:1,explanations:["He crushed it last time, and hitters' BA rises 40+ points the 3rd time through the order.","The changeup arrives 8-10mph slower, completely disrupting his fastball timing.","Slider first can work but changeup is better for disrupting timing.","Throwing inside without setting it up first risks a wild pitch or hitting the batter — you need to establish the outside first before going in."],
      rates:[25,85,60,40],concept:"Third time through the order, change speeds to disrupt hitter timing",anim:"strike"},
    {id:"p10", conceptTag:"pitch-sequencing",title:"In the Zone",diff:1,cat:"approach",ageMin:6,ageMax:99,
      description:"Scoreless game, 4th inning. You're rolling — 8 straight outs. #3 hitter up. Count 1-0.",
      situation:{inning:"Bot 4",outs:2,count:"1-0",runners:[],score:[0,0]},
      options:["Fastball for a strike","Waste a pitch","Best breaking ball","Same sequence as last at-bat"],
      best:0,explanations:["You're dealing and it's only 1-0 — get the strike and keep attacking.","Wasting pitches when you're in a groove is overthinking.","Your fastball in a groove is highest-percentage.","Good hitters remember what you threw — repeating the exact same sequence lets them predict your pitches and sit on them."],
      explSimple:["You're doing great! Keep throwing strikes and stay confident.","Don't waste pitches when everything is working — just keep attacking.","Your fastball is your best pitch right now because you're in a groove.","Good batters remember what you threw last time, so don't do the exact same thing."],
      rates:[80,35,55,40],concept:"When you're in a groove, stay aggressive — don't overthink",anim:"strike"},
    {id:"p11", conceptTag:"dp-positioning",title:"First and Third Jam",diff:3,cat:"pressure",ageMin:12,ageMax:99,
      description:"Runners on 1st and 3rd, nobody out, down by 1. Contact hitter up. You need a double play or strikeout.",
      situation:{inning:"Top 6",outs:0,count:"0-0",runners:[1,3],score:[2,3]},
      options:["Pitch for the strikeout","Sinker for a ground ball DP","Walk him to load bases","Fastball — challenge him"],
      best:1,explanations:["Strikeouts are great but you need TWO more outs, which means a DP gets both.","Exactly! A sinker down gets the ground ball you need, because dP erases the inning.","Loading bases makes any wild pitch or walk score a run.","A fastball challenge might get hit in the air, since you want the ball on the ground."],
      rates:[45,85,20,35],concept:"With runners on 1st and 3rd, pitch for the double play ground ball",anim:"groundout"},
    {id:"p12", conceptTag:"first-pitch-value",title:"Opening Day Jitters",diff:1,cat:"approach",ageMin:6,ageMax:99,
      description:"1st inning of the season. Your adrenaline is pumping. Fastball feels extra fast. Leadoff hitter up.",
      situation:{inning:"Top 1",outs:0,count:"0-0",runners:[],score:[0,0]},
      options:["Let it rip — throw your hardest","Start with off-speed to surprise","Fastball for strike — establish the zone","Pitch out of the zone to start"],
      best:2,explanations:["Adrenaline makes you overthrow and lose control — channel that energy into a well-placed fastball instead.","Surprise is not needed on the first pitch of the season — just throw a quality strike.","Smart! Establish the strike zone early — controlled aggression beats wild energy.","Nibbling pitch 1 of the season sets a bad tone."],
      explSimple:["When you're too excited, you throw too hard and lose control.","You don't need to surprise anyone — just throw a good pitch.","Great choice! Throw a nice fastball for a strike. Stay calm and in control even when you're excited.","Throwing outside the zone on your very first pitch starts the game off badly."],
      rates:[40,35,85,25],concept:"Channel adrenaline into controlled aggression — establish the strike zone early",anim:"strike"},
    {id:"p13",title:"Covering First Base",diff:1,cat:"defense",conceptTag:"backup-duties",ageMin:8,ageMax:99,
      description:"Ground ball hit to the first baseman. He fields it but he's too far from the bag to step on it himself. What do you do as the pitcher?",
      situation:{inning:"Bot 2",outs:0,count:"1-0",runners:[],score:[1,0]},
      options:["Stay on the mound — that's the first baseman's job","Sprint to first base to take the throw","Run toward home plate to back up","Watch and see what happens"],
      best:1,explanations:["Staying on the mound means nobody is at first to receive the throw, because the first baseman already fielded the ball away from the bag. If you don't sprint over, the runner reaches safely even though your teammate made a clean play — that's an out wasted.","Sprinting to first base to take the throw is the right play, because on any ground ball to the right side the pitcher must cover first. The key is to run a banana path — angle toward foul territory first, then turn up the line — so you hit the bag running in a straight line. That way you can catch the toss and touch the base in one smooth motion without colliding with the runner.","Backing up home plate only makes sense if there's a runner threatening to score on an overthrow. Since this is a routine grounder with no runners on, the ball isn't going near home — which means running there leaves first base uncovered and the batter reaches safely.","Watching and waiting wastes the time you need to get to first base. Since the first baseman is too far from the bag, every second you hesitate makes it harder to beat the runner, otherwise you're giving away an easy out that your team earned."],
      explSimple:["It IS your job! When the first baseman fields the ball, the pitcher has to run to first base.","Yes! Sprint to first base and catch the throw. This is one of the most important things a pitcher does besides pitching.","Backing up home plate isn't needed here — you need to cover first base.","Don't just stand and watch! Run to the base so your teammate can throw it to you."],
      rates:[15,85,30,20],concept:"Pitchers must cover 1st base on ground balls to the right side — sprint to the bag!",anim:"groundout"},
    // Batch 1 — Pitch Selection by Count
    {id:"p14", conceptTag:"first-pitch-value",title:"First Pitch Strike",diff:1,cat:"counts",ageMin:6,ageMax:99,
      description:"Top of the 3rd, score is 1-0. The leadoff hitter steps in — he's a patient batter who likes to work counts. 0-0, nobody on, nobody out. Do you go after him or nibble?",
      situation:{inning:"Top 3",outs:0,count:"0-0",runners:[],score:[1,0]},
      options:["Fastball right down the middle for a strike","Curveball on the corner — nibble at the edges","Changeup low to start with something soft","Fastball high and tight to set a tone"],
      best:0,explanations:["Yes! First-pitch strikes put pitchers in control, which means hitters bat about .160 after falling behind 0-1, compared to .340 when ahead 1-0. Attack the zone early.","Nibbling against a patient hitter is his dream — because he'll take close pitches and work the count to 1-0, exactly what he wants.","Starting with offspeed gives away your advantage, because you want to get ahead, then use the changeup later.","High and tight misses are ball one, since against a patient hitter, you just gave him what he wanted — a free ball."],
      explSimple:["Yes! Throwing a strike first puts you in charge. The batter has to start swinging now.","Throwing tricky pitches on the corners is exactly what a patient batter wants — he'll just wait for a ball.","Save your slower pitches for later. Start with a fastball strike to get ahead.","Throwing up and inside might miss for a ball, and now the batter is winning the count."],
      rates:[85,40,35,30],concept:"First-pitch strikes are a pitcher's best weapon — hitters bat .160 after falling behind 0-1",anim:"strike"},
    {id:"p15", conceptTag:"count-leverage",title:"Ahead 0-2 — Now What?",diff:1,cat:"counts",ageMin:6,ageMax:99,
      description:"Bottom of the 4th, 1 out, nobody on. You've got the #6 hitter in an 0-2 hole. He's an aggressive swinger who's been chasing pitches all day. Score is 3-2.",
      situation:{inning:"Bot 4",outs:1,count:"0-2",runners:[],score:[3,2]},
      options:["Curveball in the dirt — make him chase","Fastball right down the middle — blow it by him","Slider on the black — paint the corner","Fastball up and in to push him off the plate"],
      best:0,explanations:["Perfect! With 0-2, you can afford to waste a pitch, because an aggressive hitter chasing all day is almost guaranteed to swing at a curveball in the dirt. The strikeout rate on 0-2 buried breaking balls is over 40%.","Throwing down the middle on 0-2 is giving away your advantage, since even weak hitters can hit a fastball with no movement over the plate.","The slider on the corner is a solid option, but against a chaser, the curveball in the dirt is even more effective, since as make him swing at something he can't hit.","Up and in on 0-2 is okay for backing him off, but you're wasting the count advantage, which means you want a swing-and-miss, not just a foul ball."],
      rates:[85,20,60,45],concept:"On 0-2, use the advantage — waste a pitch out of the zone and make the hitter chase",explSimple:["Perfect! With 0-2, you can afford to waste a pitch.","Not the best move. Throwing down the middle on 0-2 is giving away your advantage.","Not the best move. The slider on the corner is a solid option, but against a chaser, the curveball.","Not the best move. Up and in on 0-2 is okay for backing him off, but you're wasting."], anim:"strikeout"},
    {id:"p16", conceptTag:"count-leverage",title:"Must-Throw-a-Strike Count",diff:1,cat:"counts",ageMin:6,ageMax:99,
      description:"Top of the 5th, runner on second, 1 out. Count is 3-1 on the #9 hitter. Your catcher sets up on the outside corner. Score tied 2-2.",
      situation:{inning:"Top 5",outs:1,count:"3-1",runners:[2],score:[2,2]},
      options:["Fastball on the outside corner — hit the glove","Curveball and hope he swings","Changeup to surprise him","Fastball down the middle — just get it in the zone"],
      best:0,explanations:["Great choice! On 3-1 you need a strike, and the fastball is your most controllable pitch, because you throwing it to the outside corner gives you the best chance to get a called strike or weak contact instead of a walk.","A curveball on 3-1 is risky — if it bounces, you walk him. Breaking balls on hitter's counts only work if you can absolutely locate them.","A changeup that misses the zone is ball four and puts runners on first and second, since too risky in this count.","Down the middle works if you must, but the outside corner is smarter — you still get the strike while avoiding the hitter's power zone."],
      rates:[85,30,35,55],concept:"On 3-1 counts, throw your most controllable pitch — a strike is more important than a strikeout",explSimple:["Great choice! On 3-1 you need a strike, and the fastball is your most controllable pitch.","Not the best move. A curveball on 3-1 is risky — if it bounces, you walk him.","Not the best move. A changeup that misses the zone is ball four and puts runners on first and second.","Not the best move. Down the middle works if you must, but the outside corner is smarter — you."], anim:"strike"},
    {id:"p17", conceptTag:"count-leverage",title:"Even Count Power Threat",diff:2,cat:"counts",ageMin:9,ageMax:99,
      description:"Bot 5th, nobody on, 2 outs. The count is 1-1 against their cleanup hitter — a power-hitting righty who crushes fastballs. He hit a double off your heater last time. Score 4-3 your lead.",
      situation:{inning:"Bot 5",outs:2,count:"1-1",runners:[],score:[4,3]},
      options:["Fastball — challenge him again","Changeup low in the zone","Slider backdoor on the outside corner","Curveball up in the zone to freeze him"],
      best:1,explanations:["He already doubled off your fastball, because power hitters sit on fastballs in even counts. Throwing what he's looking for is playing his game.","Smart! The changeup looks like a fastball out of your hand but arrives 8-10 mph slower — power hitters who gear up for fastballs are most vulnerable to speed changes. Ground ball rate on changeups is over 50%.","The backdoor slider is a good pitch, but it needs perfect location, which means if it leaks over the plate, a power hitter will crush it.","Curveballs up in the zone hang and get hammered, because curveballs need to be down to be effective."],
      rates:[25,80,55,20],concept:"Against power hitters looking fastball, the changeup is your best friend — same arm speed, different velocity",explSimple:["He already doubled off your fastball.","The changeup looks like a fastball out of your hand but arrives 8-10 mph slower.","The backdoor slider is a good pitch, but it needs perfect location.","Curveballs up in the zone hang and get hammered."],anim:"groundout"},
    {id:"p18", conceptTag:"pitch-sequencing",title:"Two-Two Tightrope",diff:2,cat:"counts",ageMin:9,ageMax:99,
      description:"Top 7th, runner on third, 1 out, you're up 5-4. The count is 2-2 on a contact hitter. Your catcher wants a strikeout so the runner can't score on a ground ball.",
      situation:{inning:"Top 7",outs:1,count:"2-2",runners:[3],score:[5,4]},
      options:["Slider low and away — try for the strikeout","Fastball at the knees — pitch to contact","Curveball in the dirt — make him chase","Changeup on the outside corner"],
      best:0,explanations:["Yes! With a runner on third and 1 out, a strikeout avoids any chance of a run scoring on contact, since the slider low-away has a 30% whiff rate and is the best strikeout pitch in this spot.","Pitching to contact with a runner on third and 1 out is dangerous — given that even a routine ground ball can score the tying run.","The curveball in the dirt on 2-2 is risky — since if it bounces too far, the catcher might not block it and the runner on third scores on a wild pitch.","The changeup is a solid pitch, but the slider gives you a better chance at a swing-and-miss, which is what you really want here — that's why this approach matters in this situation."],
      rates:[70,27,35,43],concept:"With a runner on third, strikeouts are more valuable than outs on contact",explSimple:["With a runner on third and 1 out, a strikeout avoids any chance of a run scoring on contact.","Pitching to contact with a runner on third and 1 out is dangerous — even a routine ground ball can score the tying run.","The curveball in the dirt on 2-2 is risky — if it bounces too far, the catcher might not block it and the runner on third scores on a wild pitch.","The changeup is a solid pitch, but the slider gives you a better chance at a swing-and-miss, which is what you really want here."],anim:"strikeout"},
    {id:"p19", conceptTag:"pitch-sequencing",title:"Expand or Attack?",diff:2,cat:"counts",ageMin:9,ageMax:99,
      description:"Bot 3rd, bases empty, nobody out. Count is 0-1 after a called strike on the outside corner. The batter fouled off a fastball last at-bat. Score 1-0 your lead.",
      situation:{inning:"Bot 3",outs:0,count:"0-1",runners:[],score:[1,0]},
      options:["Slider just off the outside corner — expand the zone","Fastball inside — change his eye level","Curveball right down the middle — surprise him","Same pitch same spot — the outside fastball again"],
      best:0,explanations:["Perfect! After getting strike one on the outside corner, expanding just off that edge is textbook. The hitter's eye is calibrated to that spot — a pitch 2 inches further off the plate looks like the same pitch. Hitters chase expanded-zone pitches 35% more after seeing a strike in the same area.","Changing eye level is a good strategy, but going inside after establishing outside should come later in the sequence — because you haven't fully exploited the outside yet.","A curveball down the middle on 0-1 is hittable, because you're giving up your count advantage for a surprise that isn't necessary.","The same pitch same spot can work, but smart hitters adjust, since you expanding just off the edge is better than repeating the exact same location."],
      rates:[85,50,30,45],concept:"After getting a strike on the corner, expand the zone 2 inches further — the hitter's eye will follow",explSimple:["After getting strike one on the outside corner, expanding just off that edge is the right way to do it.","Changing eye level is a good strategy, but going inside after establishing outside should come later in the sequence — you haven't fully exploited the outside yet.","A curveball down the middle on 0-1 is hittable.","The same pitch same spot can work, but smart hitters adjust."],anim:"strike"},
    {id:"p20", conceptTag:"count-leverage",title:"Behind 2-0 to a Weak Hitter",diff:2,cat:"counts",ageMin:9,ageMax:99,
      description:"Top 4th, nobody on, 2 outs. You fell behind 2-0 to the #8 hitter after two close pitches were called balls. He's batting .210 on the season. Score 3-1 your lead.",
      situation:{inning:"Top 4",outs:2,count:"2-0",runners:[],score:[3,1]},
      options:["Groove a fastball down the middle — just get a strike","Fastball on the outside corner — work the edge","Curveball for a strike — change his timing","Walk him and face the pitcher next"],
      best:1,explanations:["Groving one down the middle to a .210 hitter sounds safe, but even weak hitters hit .310+ on pitches middle-middle, which means don't give away free contact.","Right! Work the outside corner — you need a strike, but you don't need to give in, because the outside corner fastball gets called strikes 65% of the time and generates weak contact even when hit. It's a competitive strike without being a meatball.","A curveball on 2-0 is too risky with this ump squeezing you, since if it's called a ball, you're at 3-0 to a weak hitter — embarrassing.","Walking the #8 hitter to face the pitcher seems clever, but you're putting a free baserunner on with a 2-run lead, because you trust your stuff and make a pitch."],
      rates:[45,80,30,25],concept:"Behind in the count, throw competitive strikes on the corners — don't groove one down the middle",explSimple:["Groving one down the middle to a .210 hitter sounds safe, but even weak hitters hit .310+ on pitches middle-middle.","Work the outside corner — you need a strike, but you don't need to give in.","A curveball on 2-0 is too risky with this ump squeezing you.","Walking the #8 hitter to face the pitcher seems clever, but you're putting a free baserunner on with a 2-run lead."],anim:"strike"},
    {id:"p21", conceptTag:"count-leverage",title:"Full Count, Bases Juiced",diff:3,cat:"counts",ageMin:12,ageMax:99,
      description:"Bot 8th, bases loaded, 2 outs, tie game 4-4. Full count 3-2 on the #5 hitter. He's a good breaking ball hitter but has struggled with high heat today. The crowd is going crazy.",
      situation:{inning:"Bot 8",outs:2,count:"3-2",runners:[1,2,3],score:[4,4]},
      options:["Your best pitch — a curveball","Fastball up in the zone — attack his weakness today","Slider low — make him chase","Changeup — keep him off balance"],
      best:1,explanations:["Your curveball is normally your best pitch, but he's a good breaking ball hitter — throwing his strength in this moment is playing his game, not yours.","Exactly! In the biggest moments, attack what's NOT working for the hitter, not what's best for you, which means he's struggled with high heat all day — that's the pitch to throw. MLB data shows targeting a hitter's cold zone raises strikeout probability by 25% regardless of the pitcher's preferred pitch.","Slider low on 3-2 with bases loaded — if it misses, you just walked in the tying run, because too much risk on a pitch that's designed to be out of the zone.","Changeup on a full count is risky — if you hang it, it's a grand slam. If you miss, it's a walk-off walk. The margin is too thin."],
      rates:[40,85,35,30],concept:"In big spots, throw what the hitter can't hit today — not just your best pitch",anim:"strikeout"},
    {id:"p22", conceptTag:"count-leverage",title:"Runner Stealing on 3-2",diff:3,cat:"counts",ageMin:12,ageMax:99,
      description:"Top 6th, runner on first, 2 outs. Count is 3-2. The runner will be going on the pitch — he has to with 2 outs. He's a pull hitter. Score 2-1 your lead.",
      situation:{inning:"Top 6",outs:2,count:"3-2",runners:[1],score:[1,2]},
      options:["Fastball for a strike — forget the runner","Slider low — hope he chases for strike three","Pitch out to let the catcher throw out the runner","Slide-step fastball on the outside corner"],
      best:3,explanations:["You can't just forget the runner, since a regular windup gives the base stealer an easy jump to second, and if the batter fouls it off or takes, the runner is in scoring position.","A slider on 3-2 with a runner going is dangerous — if it's a ball, it's a walk AND the runner advances, because plus the low slider is harder for the catcher to handle and throw from.","A pitchout on 3-2 is ball four — you walk the batter! After all, never pitchout on a full count.","Smart! The slide-step cuts your delivery time by 0.3 seconds, giving your catcher a real chance to throw out the runner — the outside corner location makes it easy for the catcher to receive and throw. You compete for the strike AND control the running game."],
      rates:[40,30,10,85],concept:"On 3-2 with a runner stealing, use a slide-step to give your catcher the best chance",anim:"strike"},
    {id:"p23", conceptTag:"pitch-sequencing",title:"0-2 to a Fastball Crusher",diff:3,cat:"counts",ageMin:12,ageMax:99,
      description:"Bot 7th, nobody on, 1 out. You're ahead 0-2 on a hitter who's batting .380 against fastballs this season but only .180 against breaking stuff. He's their best hitter. Score 3-3 tie game.",
      situation:{inning:"Bot 7",outs:1,count:"0-2",runners:[],score:[3,3]},
      options:["Fastball up — challenge him with your best","Curveball in the dirt — classic 0-2 waste pitch","Slider backdoor — try for the punchout right now","Changeup low — look fastball, get changeup"],
      best:1,explanations:["He bats .380 against fastballs! Even up in the zone, you're throwing his favorite pitch, which means an 0-2 count is too valuable to waste by giving him what he hits best.","Perfect! The 0-2 curveball in the dirt is the textbook play here, and doubly so against a fastball hitter. He's gearing up for heat — the curveball in the dirt looks like a strike out of the hand, then drops below the zone. Even if he doesn't chase, you're only at 1-2 and still ahead. Never rush to finish a hitter when you're dominating the count.","Going for the punchout on 0-2 is aggressive but unnecessary, because you have TWO strikes to work with. A backdoor slider that catches too much plate gets hit 400 feet by this guy.","The changeup low is a decent idea but the curveball has more break and is harder to lay off when a hitter is geared up for fastball speed, since save the changeup for 1-2 if he takes the curve."],
      rates:[15,85,45,55],concept:"Against fastball hitters, use 0-2 to show breaking balls — never throw what they crush",anim:"strikeout"},
    // Batch 2 — Pitching With Runners On Base
    {id:"p24", conceptTag:"pickoff-mechanics",title:"Runner on First — Stay Focused",diff:1,cat:"baserunners",ageMin:6,ageMax:99,
      description:"Top of the 2nd, runner on first, nobody out. He's a right-handed contact hitter. Count is 0-0. Score is 0-0. You notice the runner taking a normal lead. Do you focus on the batter or the runner?",
      situation:{inning:"Top 2",outs:0,count:"0-0",runners:[1],score:[0,0]},
      options:["Focus on the batter — the runner isn't your problem","Throw over to first a few times to keep him close","Focus on the batter but be quick to the plate","Call a pitchout to catch him leaning"],
      best:2,explanations:["Completely ignoring the runner is a mistake, because if he gets a big secondary lead or steals easily, you've given the other team a free base.","Throwing over multiple times before your first pitch slows the game, drives up your stress, and doesn't help you get the batter out, since one quick look is enough.","Smart! Your #1 job is always getting the batter out, which means but being quick to the plate — a compact delivery around 1.3 seconds — keeps the runner honest without changing your approach. You can do both at once.","A pitchout on the very first pitch is wasteful — the runner is taking a normal lead, not showing steal signs. Falling behind 1-0 for no reason hurts you more than it helps."],
      rates:[30,35,85,20],concept:"With a runner on first, your priority is the batter — but stay quick to the plate to keep the runner honest",explSimple:["Not the best move. Completely ignoring the runner is a mistake.","Not the best move. Throwing over multiple times before your first pitch slows the game, drives up your stress,.","Smart! Your #1 job is always getting the batter out.","Not the best move. A pitchout on the very first pitch is wasteful — the runner is taking a normal lead, not showing steal signs."], anim:"pickoff"},
    {id:"p25", conceptTag:"pickoff-mechanics",title:"Windup or Stretch?",diff:1,cat:"baserunners",ageMin:6,ageMax:99,
      description:"Bot 3rd, runner just reached first on a single. Nobody out, 0-0 count on the next batter. Score 2-1. You've been pitching from the windup all game. Your coach yells something from the dugout.",
      situation:{inning:"Bot 3",outs:0,count:"0-0",runners:[1],score:[2,1]},
      options:["Stay in the windup — it's working fine","Switch to the stretch since there's a runner on","Pitch from the windup but speed it up","Ask your catcher what to do"],
      best:1,explanations:["The windup takes longer and you can't see the runner, because with a man on first, the windup gives base stealers an easy jump — they'll take second for free.","Correct! Any time a runner is on base, you pitch from the stretch. The stretch lets you see the runner, hold him with a quick look or pickoff, and deliver the ball faster. It cuts your delivery time from about 1.5 seconds to 1.2 seconds. This is one of the first things every pitcher learns.","You can't really speed up a windup without losing mechanics, since the stretch exists specifically for this situation — use it.","Your catcher will give you pitch signs, but windup vs stretch is the pitcher's basic responsibility, because every pitcher should know: runners on base = stretch."],
      rates:[15,85,25,20],concept:"Always pitch from the stretch with runners on base — it lets you control the running game",explSimple:["Not the best move. The windup takes longer and you can't see the runner.","Great choice! Correct! Any time a runner is on base, you pitch from the stretch.","Not the best move. You can't really speed up a windup without losing mechanics.","Not the best move. Your catcher will give you pitch signs, but windup vs stretch is the pitcher's basic responsibility."], anim:"pickoff"},
    {id:"p26", conceptTag:"count-leverage",title:"Runner in Scoring Position",diff:1,cat:"baserunners",ageMin:6,ageMax:99,
      description:"Top 5th, runner on second, nobody out. A single will score him. He's their #7 hitter — not a great hitter but capable. Count 0-0. Score 3-2 your lead.",
      situation:{inning:"Top 5",outs:0,count:"0-0",runners:[2],score:[3,2]},
      options:["Pitch the same as with nobody on — don't overthink it","Be extra careful — don't give him anything to hit","Attack the zone — get ahead and get outs","Walk him intentionally to set up a double play"],
      best:2,explanations:["Pitching the exact same way ignores the situation, since you need to be aware that a run is 90 feet away, but that doesn't mean you change everything — just be smart.","Being too careful with a weak hitter is how you walk him and put TWO runners on, which means now a single scores one and puts a man on third. You made things worse.","Yes! With a runner on second and nobody out, the best strategy is to attack the zone aggressively. Get ahead in the count and force the weak hitter to put the ball in play. Pitchers who attack the zone with RISP give up fewer runs than pitchers who nibble — walks just add more runners.","Walking the #7 hitter to face the #8 hitter puts TWO men on with nobody out, because you're not afraid of a .230 hitter. Intentional walks should be saved for their best hitters."],
      rates:[40,25,85,20],concept:"With runners in scoring position, attack the zone — walks are more dangerous than hits",explSimple:["Not the best move. Pitching the exact same way ignores the situation.","Not the best move. Being too careful with a weak hitter is how you walk him and put.","Yes! With a runner on second and nobody out, the best strategy is to attack the zone hard.","Not the best move. Walking the #7 hitter to face the #8 hitter puts TWO men on with nobody out."], anim:"strike"},
    {id:"p27", conceptTag:"steal-breakeven",title:"Speed Demon on First",diff:2,cat:"baserunners",ageMin:9,ageMax:99,
      description:"Top 4th, their fastest player is on first with a stolen base in the 1st inning already. Count is 1-1, nobody out. He's dancing off the bag taking a big lead. Score 1-1.",
      situation:{inning:"Top 4",outs:0,count:"1-1",runners:[1],score:[1,1]},
      options:["Throw over to first to keep him close","Slide-step fastball to the plate — be quick","Forget the runner and just pitch normally","Pitch out so your catcher can throw him out"],
      best:1,explanations:["Throwing over is fine as a look, but this runner already stole a base — he's not scared of pickoff throws, since you're just delaying the inevitable and falling behind the hitter mentally.","Perfect! The slide step is your best weapon against speedsters. It shaves 0.3 seconds off your delivery — the difference between safe and out. By staying quick to the plate, you neutralize his speed advantage without losing focus on the batter. MLB pitchers who use the slide step cut stolen base attempts by 40%.","Pitching normally with a full delivery against a guy who already stole on you? He'll take second standing up, because you must adjust your timing.","A pitchout on 1-1 makes it 2-1, since you're behind in the count and you might not even get him — pitchouts work best when you're certain the runner is going."],
      rates:[40,85,20,30],concept:"Against fast runners, the slide step is your best friend — it cuts delivery time and steal success rates",explSimple:["Throwing over is fine as a look, but this runner already stole a base — he's not scared of pickoff throws.","The slide step is your best weapon against speedsters.","Pitching normally with a full delivery against a guy who already stole on you?","A pitchout on 1-1 makes it 2-1 — you're behind in the count and you might not even get him."],anim:"strike"},
    {id:"p28",title:"First and Third Groundball",diff:2,cat:"baserunners",conceptTag:"first-third",ageMin:11,ageMax:99,
      description:"Bot 6th, runners on first and third, 1 out. Tie game 3-3. Contact hitter up, count 0-1. Your infield is at double play depth. A ground ball could turn two and end the inning — but it could also score the run from third.",
      situation:{inning:"Bot 6",outs:1,count:"0-1",runners:[1,3],score:[3,3]},
      options:["Fastball up — try for a strikeout instead","Sinker down — pitch for the double play ground ball","Curveball — get him to pop up","Pitch carefully around him — don't give in"],
      best:1,explanations:["Strikeouts are nice, but on 0-1 to a contact hitter, you're unlikely to get one. And if you walk him trying for K's, you've loaded the bases.","Exactly! The sinker down in the zone is the double play pitch. Yes, the runner on third might score on a ground ball, but a 6-4-3 double play ends the inning and limits the damage to just one run. Giving up one to get two outs is a great trade. Sinkers generate ground balls at twice the rate of four-seamers.","A popup would be great, but you can't really pitch for a popup — as curveballs are meant to get swings and misses or ground balls, not lazy fly balls.","Pitching carefully with first and third and one out is how you load the bases, which means a walk here brings the tying run home from third AND loads the bases. Be aggressive and get the double play."],
      rates:[40,85,35,20],concept:"With first and third, pitch for the double play — giving up one run to get two outs is a smart trade",explSimple:["Strikeouts are nice, but on 0-1 to a contact hitter, you're unlikely to get one.","The sinker down in the zone is the double play pitch.","A popup would be great, but you can't really pitch for a popup — curveballs are meant to get swings and misses or ground balls, not lazy fly balls.","Pitching carefully with first and third and one out is how you load the bases."],anim:"doubleplay"},
    {id:"p29", conceptTag:"pitch-sequencing",title:"Scoring Position Strategy",diff:2,cat:"baserunners",ageMin:9,ageMax:99,
      description:"Top 7th, runner on second, 1 out. He's their #3 hitter — dangerous. Count is 1-0. First base is open. Score 4-3 your lead. Your catcher puts down the sign for a fastball away.",
      situation:{inning:"Top 7",outs:1,count:"1-0",runners:[2],score:[4,3]},
      options:["Shake off the catcher — throw inside to jam him","Follow the sign — fastball away","Walk him intentionally to set up the double play","Throw a changeup to keep him off balance"],
      best:1,explanations:["Shaking off to go inside on 1-0 to a dangerous hitter is risky. If you miss inside, it's 2-0. If you miss over the plate, he crushes it. Trust your catcher's read.","Smart! The fastball away is the right call. With a runner on second, pitching to the outside part of the plate does two things: it keeps the ball away from the hitter's power zone, and if he makes contact, it's more likely to be hit to the right side — away from the runner at second. Your catcher has a great view of the whole field. Trust the sign.","Walking their #3 hitter puts the go-ahead run on base too. Now first and second with 1 out — any hit scores at least one. Only walk him if you're certain the next hitter is much weaker.","A changeup on 1-0 that misses is 2-0, and you're in a hitter's count against their best hitter. Save the changeup for when you're ahead."],
      rates:[30,80,45,35],concept:"With a runner on second, pitch to the outside — it limits damage and directs contact away from the runner",explSimple:["Shaking off to go inside on 1-0 to a dangerous hitter is risky.","The fastball away is the right call.","Walking their #3 hitter puts the go-ahead run on base too.","A changeup on 1-0 that misses is 2-0, and you're in a hitter's count against their best hitter."],anim:"strike"},
    {id:"p30", conceptTag:"pickoff-mechanics",title:"Slide Step Timing",diff:2,cat:"baserunners",ageMin:9,ageMax:99,
      description:"Bot 4th, runner on first, 1 out. The runner is average speed. Count is 0-0. You've been using your full stretch delivery all game and throwing well. Your catcher signals for a slide step. Score 2-0 your lead.",
      situation:{inning:"Bot 4",outs:1,count:"0-0",runners:[1],score:[2,0]},
      options:["Use the slide step like the catcher wants","Stick with your full stretch — it's been working","Throw over to first instead","Slide step on every pitch from now on"],
      best:0,explanations:["Right! Trust your catcher, because he can see the runner's lead and timing better than you can. If he's calling for a slide step, the runner is probably getting a big secondary lead or showing steal signs. One slide step delivery keeps the runner honest without disrupting your rhythm.","Your full stretch has been great, but the catcher sees something you can't — the runner is getting too aggressive, since ignoring your catcher's read on the running game is a mistake.","Throwing over is an option, but the catcher specifically asked for a slide step on the pitch, because he wants you to deliver the ball AND control the runner at the same time.","Using the slide step on EVERY pitch sacrifices some velocity and command for no reason — use it strategically when the runner is a threat, not as your default delivery. The slide step is a weapon, not a permanent change."],
      rates:[80,35,40,30],concept:"Use the slide step strategically when your catcher calls for it — he can read the runner's intentions",explSimple:["He can see the runner's lead and timing better than you can.","Your full stretch has been great, but the catcher sees something you can't — the runner is getting too aggressive.","Throwing over is an option, but the catcher specifically asked for a slide step on the pitch.","Using the slide step on EVERY pitch sacrifices some velocity and command for no reason."],anim:"pickoff"},
    {id:"p31", conceptTag:"pitch-sequencing",title:"Runner on Third, Infield In",diff:3,cat:"baserunners",ageMin:12,ageMax:99,
      description:"Top 8th, runner on third, nobody out. Score 5-4 your lead. Infield is playing in to cut off the run. He's a left-handed contact hitter who puts the ball in play. Count 0-0. A ground ball on the drawn-in infield could sneak through.",
      situation:{inning:"Top 8",outs:0,count:"0-0",runners:[3],score:[5,4]},
      options:["Pitch for a strikeout — don't let him put it in play","Pitch for a fly ball — let the outfield handle it","Sinker for a ground ball — trust the infield","Pitch for a popup — something up in the zone"],
      best:1,explanations:["Trying for a strikeout sounds great but forcing it often means falling behind in the count. If you walk him, you've put the tying run on AND the go-ahead run in scoring position.","Yes! With the infield in and nobody out, a fly ball is your best friend. A medium-deep fly ball is an out — and even if the runner tags and scores from third, you now have 1 out and nobody on instead of 0 outs with a runner on third. An elevated fastball or a pitch up in the zone generates fly balls. Giving up the one run for an out is smart here.","Ground balls with the infield in are risky. The fielders are closer so they have less range, and the drawn-in infield creates holes. A grounder that normally is an out might sneak through for an RBI single.","Pitching for a popup specifically isn't really controllable. You can pitch up to get fly balls, but you can't aim for a popup — and if you leave a pitch up and over the plate, it gets hit hard."],
      rates:[35,85,40,30],concept:"With infield in and runner on third, pitch for fly balls — sacrifice the run for the out",anim:"flyout"},
    {id:"p32", conceptTag:"pickoff-mechanics",title:"Pickoff or Finish Him?",diff:3,cat:"baserunners",ageMin:12,ageMax:99,
      description:"Bot 5th, runner on first taking a huge lead — he's been inching further each pitch. But he's in an 0-2 hole and has been fooled twice. Score 2-1. 1 out. The runner is daring you to throw over.",
      situation:{inning:"Bot 5",outs:1,count:"0-2",runners:[1],score:[2,1]},
      options:["Throw over to first — that lead is too big","Pitch straight to the plate — deal with the batter first","Quick look, then your best 0-2 pitch to the batter","Call a pitchout to nail the runner"],
      best:2,explanations:["The runner WANTS you to throw over, because he's baiting you into losing focus on the batter who's in an 0-2 hole. Experienced runners do this — they take a big lead specifically to distract you from a hitter you're dominating. If you throw over and the batter resets mentally, you may have lost your advantage.","Pitching without acknowledging the runner at all lets him steal freely, because if he steals second, a single ties the game. You need to at least show him you're aware of his presence — even a quick glance freezes his lead and keeps the steal attempt honest.","Perfect! A quick look acknowledges the runner and keeps him honest, but your focus stays on finishing the 0-2 at-bat. The batter is in trouble — don't bail him out by getting distracted. One glance, then your best put-away pitch. The 0-2 count is more valuable than catching a runner. A strikeout here is worth more than a pickoff.","A pitchout turns your dominant 0-2 count into 1-2 and wastes a pitch, because you had the batter on the ropes with two strikes. Why bail him out to deal with a runner who may not even go? The count advantage is more valuable than a pitchout."],
      rates:[30,25,85,35],concept:"Don't let an aggressive runner distract you from finishing a hitter in an 0-2 count — quick look, then attack",anim:"strikeout"},
    {id:"p33", conceptTag:"pitch-sequencing",title:"Bases Loaded Jam",diff:3,cat:"baserunners",ageMin:12,ageMax:99,
      description:"Top 6th, bases loaded, 1 out, tie game 4-4. The #4 hitter steps up — he's 2-for-3 today with a homer. First pitch. Your catcher comes out to talk. He suggests pitching to him because the next guy up hits just as well.",
      situation:{inning:"Top 6",outs:1,count:"0-0",runners:[1,2,3],score:[4,4]},
      options:["Throw your hardest fastball and challenge him","Pitch to him — your catcher is right","Pitch around him — nothing in the zone but don't walk him","Ask the coach to come get you"],
      best:2,explanations:["Challenging a hot hitter with your hardest fastball is reckless when the bases are loaded. He’s 2-for-3 with a homer today and timing everything. One mistake could mean a grand slam.","Your catcher is right that you have to face someone, but pitching right to a guy who's 2-for-3 with a homer is too aggressive. Because he's locked in today, throwing strikes in the zone gives him pitches to drive. Since the bases are loaded, one mistake could mean a grand slam.","Exactly! Pitching around him means throwing competitive pitches just off the zone, because you want him to chase and get himself out. Since you're not giving him anything to crush, he either swings at a tough pitch or takes borderline calls. You accept a walk as the worst outcome, because walking in one run is better than grooving a pitch that gets hit for a grand slam — bend but don't break.","Asking to come out is the manager's call, not yours, and it shows the hitter you're rattled. Because confidence matters on the mound, competing — even carefully — keeps your team in a better position than giving up."],
      rates:[10,35,80,20],concept:"Bases loaded vs a hot hitter — pitch around him carefully, don't walk in the run and don't groove one",anim:"strike"},
    // Batch 3 — Game Situation Pitching
    {id:"p34", conceptTag:"pitch-count-mgmt",title:"Big Lead Comfort Zone",diff:1,cat:"approach",ageMin:6,ageMax:99,
      description:"Top of the 6th, you're up 7-2. Five-run lead. The #7 hitter steps to the plate. You've been cruising all game. Count is 0-0.",
      situation:{inning:"Top 6",outs:0,count:"0-0",runners:[],score:[7,2]},
      options:["Keep attacking — don't let up","Cruise — throw it down the middle and save energy","Work the corners — make them earn every hit","Experiment with new pitches you've been working on"],
      best:0,explanations:["With a big lead, keep attacking the zone with your best stuff. You do not need to overthrow or be perfect, but stay aggressive — big leads disappear when pitchers get lazy.","Grooving pitches down the middle even against weak hitters is asking for trouble — stay competitive and pitch to spots.","Working the corners sounds smart, but with a big lead it leads to walks and long innings. Attack the zone and let them get themselves out.","A game is never a practice session — save the experiments for bullpen sessions between games."],
      rates:[85,25,35,15],concept:"With a big lead, stay aggressive but don't overthrow — attack the zone and let hitters get themselves out",explSimple:["Great choice! With a big lead, keep attacking the zone with your best stuff.","Not the best move. Grooving pitches down the middle even against weak hitters is asking for trouble.","Not the best move. Pitching too carefully with a big lead leads to walks and long innings.","Not the best move. A game is never a practice session."], anim:"strike"},
    {id:"p35", conceptTag:"first-pitch-value",title:"Opening At-Bat of the Game",diff:1,cat:"approach",ageMin:6,ageMax:99,
      description:"Top of the 1st, very first batter of the game. You're on the mound, nervous and excited. The leadoff hitter steps in. What's your plan?",
      situation:{inning:"Top 1",outs:0,count:"0-0",runners:[],score:[0,0]},
      options:["First-pitch fastball strike — set the tone","Start with your best breaking ball to surprise him","Throw a changeup to mess with his timing","Nibble the corners — don't give in"],
      best:0,explanations:["Get strike one! Starting the game with a first-pitch strike tells the whole lineup you're in command — pitchers who throw first-pitch strikes have ERAs nearly 2 runs lower. Set the tone for the day.","Breaking balls first pitch of the game are risky — your feel for them isn't established yet, which means start with what you can control.","A changeup works best when the hitter expects something faster, because first pitch of the game, he doesn't know what to expect yet.","Nibbling against the leadoff hitter puts you behind in the count immediately, since you attack the zone."],
      rates:[85,30,35,20],concept:"Start the game with a first-pitch strike — set the tone and take command early",explSimple:["Great choice! Get strike one! Starting the game with a first-pitch strike tells the whole lineup you're in command.","Not the best move. Breaking balls first pitch of the game are risky — your feel for them.","Not the best move. A changeup works best when the hitter expects something faster.","Not the best move. Nibbling against the leadoff hitter puts you behind in the count right away."], anim:"strike"},
    {id:"p36", conceptTag:"pitch-count-mgmt",title:"Your Team Just Scored Big",diff:1,cat:"approach",ageMin:6,ageMax:99,
      description:"Your team just scored 4 runs in the bottom of the 4th to take a 6-1 lead. Now it's the top of the 5th and you're heading back to the mound with a big cushion. Top of the order is coming up.",
      situation:{inning:"Top 5",outs:0,count:"0-0",runners:[],score:[1,6]},
      options:["Attack the zone — put up a quick inning","Take it easy — you have a big lead now","Try to strike everyone out — dominate","Pitch carefully — don't give the lead back"],
      best:0,explanations:["After your team scores big, the best thing you can do is put up a quick, efficient inning, because you throw strikes, get ground balls, and get your team back to the plate fast. Momentum is real — keep it going.","Taking it easy leads to walks and long innings — stay engaged.","Trying to strike everyone out drives up your pitch count, which means you want quick outs.","Being too careful after a big scoring inning kills the momentum your offense just built, which means the outcome won't be what you need."],
      rates:[85,20,35,30],concept:"After your team scores big, put up a quick inning — keep the momentum going",explSimple:["Great choice! After your team scores big, the best thing you can do is put up a quick, efficient inning.","Not the best move. Taking it easy leads to walks and long innings.","Trying to strike everyone out drives up your pitch count.","Not the best move. Being too careful after a big scoring inning kills the momentum your offense just built."], anim:"strike"},
    {id:"p37", conceptTag:"count-leverage",title:"Tie Game, Deep in the Count",diff:2,cat:"situational",ageMin:9,ageMax:99,
      description:"Bot 7th, tied 3-3, you've thrown 85 pitches. You feel strong but the top of the order is coming. 0 outs. Do you keep attacking or conserve energy?",
      situation:{inning:"Bot 7",outs:0,count:"0-0",runners:[],score:[3,3]},
      options:["Keep attacking — you feel good, stay aggressive","Mix in more off-speed to save your arm","Pitch to contact — let your defense work","Throw everything you have — empty the tank"],
      best:2,explanations:["Attacking is good but being smart about it is better, because at 85 pitches, you need efficiency.","Throwing more off-speed just to save your arm changes your approach and hitters notice.","At 85 pitches in a tie game, pitching to contact is the smartest approach, since you throw strikes, let your defense field ground balls and fly balls. Quick outs keep your pitch count down and keep you in the game longer. Trust your fielders.","Emptying the tank in the 7th means you won't make it to the 8th, because pace yourself."],
      rates:[40,35,85,20],concept:"Deep in games, pitch to contact — trust your defense and stay efficient",explSimple:["Attacking is good but being smart about it is better.","Throwing more off-speed just to save your arm changes your approach and hitters notice.","At 85 pitches in a tie game, pitching to contact is the smartest approach.","Emptying the tank in the 7th means you won't make it to the 8th."],anim:"groundout"},
    {id:"p38", conceptTag:"times-through-order",title:"Third Time Through — Adjust",diff:2,cat:"adjustments",ageMin:9,ageMax:99,
      description:"Top of the 6th, you're facing the #3 hitter for the third time. He singled off your fastball in the 2nd and doubled off it in the 4th. Score 4-3 your lead.",
      situation:{inning:"Top 6",outs:1,count:"0-0",runners:[],score:[4,3]},
      options:["Throw the fastball again — you're a fastball pitcher","Lead with a changeup — disrupt his timing","Start with a curveball — something completely different","Pitch inside — he's been hitting outside pitches"],
      best:1,explanations:["He's 2-for-2 on your fastball — definition of insanity: doing the same thing and expecting different results.","The changeup is the perfect pitch here, which means he's timed your fastball twice. The changeup looks like a fastball coming out of your hand but arrives 8-10 mph slower. His timing will be completely off. Third time through, you MUST adjust.","A curveball is a speed change too, but the changeup better mimics the fastball arm action — given that harder for him to recognize.","Pitching inside helps, but if the speed is the same, he can still time it, because change the speed, not just the location."],
      rates:[15,85,55,35],concept:"Third time through, you MUST change something — if your fastball's been hit, lead with off-speed",explSimple:["He's 2-for-2 on your fastball.","The changeup is the perfect pitch here.","A curveball is a speed change too, but the changeup better mimics the fastball arm action — harder for him to recognize.","Pitching inside helps, but if the speed is the same, he can still time it."],anim:"strike"},
    {id:"p39", conceptTag:"pitch-count-mgmt",title:"They Just Took You Deep — Keep Your Cool",diff:2,cat:"approach",ageMin:9,ageMax:99,
      description:"Top of the 5th, the batter before this one crushed a solo homer off your fastball. 3-2, still your lead. You're angry. Next batter steps in.",
      situation:{inning:"Top 5",outs:1,count:"0-0",runners:[],score:[3,2]},
      options:["Throw harder — show this next guy you're still in charge","Take a deep breath and reset — pitch your game","Pitch inside to send a message","Change your whole approach — switch to off-speed only"],
      best:1,explanations:["Overthrowing after giving up a homer leads to more mistakes, since anger makes you lose mechanics.","The best pitchers have short memories, because that homer is done — you can't un-throw it. Take a breath, reset your focus, and pitch to THIS batter. Your game plan worked for 4.1 innings. One homer doesn't mean your plan is broken.","Pitching inside to 'send a message' can hit a batter and put another runner on — that hurts YOU, not the other team.","Abandoning your fastball after one homer takes away your best weapon, which means the next batter is a different hitter — stick to your game plan."],
      rates:[20,85,15,35],concept:"After giving up a homer, reset mentally — short memory, stay with your game plan",explSimple:["Overthrowing after giving up a homer leads to more mistakes.","The best pitchers have short memories.","Pitching inside to 'send a message' can hit a batter and put another runner on.","Being too careful leads to walks and more baserunners."],anim:"strike"},
    {id:"p40", conceptTag:"pitch-sequencing",title:"Walking Batters — What's Wrong?",diff:2,cat:"adjustments",ageMin:9,ageMax:99,
      description:"Bot 3rd, you just walked two batters in a row. Runners on 1st and 2nd, nobody out. Your catcher comes out. Score 2-0 your lead.",
      situation:{inning:"Bot 3",outs:0,count:"0-0",runners:[1,2],score:[2,0]},
      options:["Throw harder — overpower the next guy","Slow down — take a deep breath between pitches","Simplify — throw fastball strikes, forget about off-speed","Mix more off-speed to change the batter's eye level"],
      best:2,explanations:["Throwing harder when you're already losing control makes control even worse, because velocity isn't your problem — location is.","Slowing down helps mentally, but you also need an action plan for what to throw.","When you're walking batters, your mechanics are off, since simplify! Throw fastballs and aim for the middle of the zone. Don't try to be perfect — just throw strikes. A single is better than another walk. Once you find your rhythm again, you can add in off-speed.","Adding more off-speed when you can't throw your fastball for strikes makes things worse, not better."],
      rates:[15,45,85,25],concept:"When you're walking batters, simplify — throw fastball strikes until you find your rhythm",explSimple:["Throwing harder when you're already losing control makes control even worse.","Slowing down helps mentally, but you also need an action plan for what to throw.","When you're walking batters, your mechanics are off.","Adding more off-speed when you can't throw your fastball for strikes makes things worse, not better."],anim:"strike"},
    {id:"p41", conceptTag:"pitch-type-value",title:"Cold Weather Breaking Ball",diff:3,cat:"adjustments",ageMin:12,ageMax:99,
      description:"Top of the 3rd, it's 45 degrees and your curveball has no bite today. Usually it drops 6 inches — today it's flat. Tied 1-1.",
      situation:{inning:"Top 3",outs:0,count:"0-0",runners:[],score:[1,1]},
      options:["Keep throwing the curveball — it'll come around","Stop throwing the curveball entirely — all fastball","Use the changeup instead — it doesn't need spin like the curve","Switch between curveball and more fastball/changeup"],
      best:2,explanations:["A flat curveball in cold weather won't suddenly start biting, because it's a batting practice pitch waiting to get crushed. Cold fingers mean poor spin, and poor spin means the ball stays flat in the zone where hitters can drive it.","Going all-fastball makes you predictable, since you hitters will time your velocity. Without an off-speed option, batters can sit on the fastball and lock in on one speed. You need some kind of change-of-pace to keep them honest.","In cold weather, the curveball often loses its bite because your fingers are cold and can't grip the seams as well. The changeup doesn't rely on spin as much — it's a grip-based pitch that works in any weather. Replace your dead curveball with the changeup and you still have a speed-change weapon.","Mixing in a flat curve occasionally still risks hanging one. After all, even thrown sparingly, a flat curveball sitting in the zone is dangerous. Commit fully to the changeup as your off-speed pitch when cold conditions take away your breaking ball."],
      rates:[15,30,85,40],concept:"In cold weather, replace your curveball with the changeup — it doesn't rely on finger spin",anim:"strike"},
    {id:"p42", conceptTag:"times-through-order",title:"Top of the Order in the 8th",diff:3,cat:"late-game",ageMin:12,ageMax:99,
      description:"Top of the 8th, 1-run lead. You've thrown 95 pitches. The top of their order — 1-2-3 hitters — is coming up. They've seen you twice each.",
      situation:{inning:"Top 8",outs:0,count:"0-0",runners:[],score:[4,3]},
      options:["Stay in and compete — you've got this","Ask the coach for a reliever — the bullpen is fresh","Change your pitch mix completely — surprise them","Keep the same approach — it's worked for 7 innings"],
      best:0,explanations:["Stay in and compete — at 95 pitches with a 1-run lead, you can pitch another inning IF you're efficient. The key is adjusting your approach since they've seen you twice. Change sequences, add more off-speed, and pitch to contact. Don't try to overpower — outsmart.","Asking for a reliever is the manager's call. Your job is to compete until told otherwise.","Completely changing your approach is too drastic, which means adjust, don't reinvent.","The same approach won't work as well the third time through, because you hitters improve 40+ points in BA third time through the order. You must adjust."],
      rates:[85,40,35,25],concept:"Third time through, adjust your sequences — same pitcher, different approach beats the hitters' adjustments",anim:"strike"},
    {id:"p43", conceptTag:"pitch-sequencing",title:"Fastball's Not Working Today",diff:3,cat:"adjustments",ageMin:12,ageMax:99,
      description:"Bot of the 4th, your fastball keeps missing arm-side. You've thrown 3 wild fastballs already. But your slider has been sharp. Tied 2-2.",
      situation:{inning:"Bot 4",outs:0,count:"0-0",runners:[],score:[2,2]},
      options:["Keep throwing fastballs until they start going where you want","Make the slider your primary pitch today","Only throw fastballs in fastball counts to get strikes","Mix everything and hope the fastball comes around"],
      best:1,explanations:["Forcing a pitch that is not working leads to walks and meatballs — great pitchers adapt instead of being stubborn.","When your primary pitch is not working, make your best pitch your primary. If the slider is sharp, throw it 60-70% of the time and use the fastball sparingly. Great pitchers adapt in real time — they do not stubbornly force a pitch that is misbehaving.","Only throwing fastballs in fastball counts makes you predictable in those counts, and hitters will sit on it.","Hoping the fastball comes around is not a strategy — use what you have today and compete with your best stuff."],
      rates:[20,85,35,30],concept:"When your primary pitch isn't working, adapt — make your best pitch today your primary pitch",anim:"strike"},
    // Batch 4 — Holding Runners & Pickoffs
    {id:"p44", conceptTag:"pickoff-mechanics",title:"Big Lead — Throw a Pickoff?",diff:1,cat:"baserunners",ageMin:6,ageMax:99,
      description:"Top of the 4th, runner on 1st, nobody out, tied 2-2. The runner is taking a huge lead — three big steps off the bag. Your first baseman holds him on.",
      situation:{inning:"Top 4",outs:0,count:"0-0",runners:[1],score:[2,2]},
      options:["Throw to first — pick him off","Vary your hold time — mix up when you deliver","Quick-pitch to home","Ignore him and use your full windup"],
      best:0,explanations:["A runner taking a huge lead is begging to be picked off. Throw to first! Even if you don't get him out, you'll shorten his lead and make him respect your move. A shorter lead means a harder steal.","Varying your hold time is a good habit, but with a huge lead right now, you need to challenge him directly, which means he'll keep inching farther until you throw over.","Quick-pitching to home doesn't address the lead, because he's still got a great jump.","Ignoring a huge lead and using your full windup gives the runner a free stolen base, since the windup takes too long and he will get a great jump."],
      rates:[85,15,35,45],concept:"When a runner takes a big lead, throw over to first — shorten his lead and keep him honest",explSimple:["Great choice! A runner taking a huge lead is begging to be picked off.","Not the best move. Ignoring a massive lead invites a steal.","Not the best move. Quick-pitching to home doesn't address the lead.","Not the best move. Ignoring a huge lead and using your full windup gives the runner a free stolen base."], anim:"pickoff"},
    {id:"p45", conceptTag:"pickoff-mechanics",title:"Known Base Stealer — Adjust Timing",diff:1,cat:"baserunners",ageMin:6,ageMax:99,
      description:"Bot 5th, the fastest runner in the league is on 1st, 1 out. He steals 80% of the time. Your catcher has an average arm. Count is 1-0.",
      situation:{inning:"Bot 5",outs:1,count:"1-0",runners:[1],score:[3,2]},
      options:["Throw over to first three times before pitching","Vary your timing — hold the ball different amounts","Quick-pitch every time","Mix in quick-pitch deliveries to disrupt his timing"],
      best:1,explanations:["Three pickoff attempts in a row frustrates everyone and still doesn't solve the problem if he's fast enough.","Base stealers time your delivery. They count seconds: 'one-Mississippi, two-Mississippi, throw.' If you vary your hold time — sometimes 1 second, sometimes 3 seconds, sometimes 2.5 — they can't get a good jump because they can't predict when you'll pitch. This is the best weapon against speedsters.","Quick-pitching every time becomes predictable — the runner adjusts.","Giving up means he steals easily. You can disrupt his timing even if you can't stop him completely."],
      rates:[30,85,25,10],concept:"Against base stealers, vary your hold time — unpredictable timing ruins their jump",explSimple:["Not the best move. Three pickoff attempts in a row frustrates everyone and still doesn't solve the problem.","Great choice! Base stealers time your delivery.","Not the best move. Quick-pitching every time becomes predictable — the runner adjusts.","Not the best move. Giving up means he steals easily."], anim:"pickoff"},
    {id:"p46", conceptTag:"pickoff-mechanics",title:"Runner on Second — Big Secondary Lead",diff:2,cat:"baserunners",ageMin:9,ageMax:99,
      description:"Top of the 6th, runner on 2nd, 1 out, tied 3-3. The runner keeps taking a huge secondary lead after you deliver to home — drifting almost to the shortstop.",
      situation:{inning:"Top 6",outs:1,count:"1-1",runners:[2],score:[3,3]},
      options:["Vary your hold time before delivering home","Deliver quickly to home — limit his jump time","Have the shortstop sneak behind him after the pitch","Spin and throw to second"],
      best:2,explanations:["Stepping off before you pitch doesn't address the SECONDARY lead — that happens after you throw.","Quick-pitching to home means the runner's secondary lead goes unchecked.","The daylight play! Have the shortstop or second baseman sneak behind the runner after you pitch, because your catcher throws back to second immediately after receiving the pitch, and the fielder is waiting for the tag. This catches aggressive secondary leads.","Spinning to throw to second from the stretch is a balk if you don't step off first."],
      rates:[35,20,85,25],concept:"For aggressive secondary leads, use the daylight play — the catcher throws behind the runner after the pitch",explSimple:["Stepping off before you pitch doesn't address the SECONDARY lead — that happens after you throw.","Quick-pitching to home means the runner's secondary lead goes unchecked.","Have the shortstop or second baseman sneak behind the runner after you pitch.","Spinning to throw to second from the stretch is a balk if you don't step off first."],anim:"catch"},
    {id:"p47", conceptTag:"pickoff-mechanics",title:"Two Pickoffs Already — Try Again?",diff:2,cat:"baserunners",ageMin:9,ageMax:99,
      description:"Bot 3rd, runner on 1st, nobody out. You've thrown to first twice already and the runner is still taking the same lead. He's not intimidated. Count is 0-1.",
      situation:{inning:"Bot 3",outs:0,count:"0-1",runners:[1],score:[1,1]},
      options:["Throw over again — third time's the charm","Focus on the batter — you've shown him your move","Vary your timing and pitch to home","Step off and hold the ball extra long"],
      best:2,explanations:["A third pickoff attempt after two failures wastes time and annoys your defense, because the runner has timed your move — he's not going to get picked off. After two throws you've shown your move and gained whatever benefit the threat provides.","Focusing only on the batter lets the runner relax and take an even bigger lead, because you need a compromise between holding the runner and attacking the hitter. Abandoning one for the other gives the opponent a free advantage.","You've established the pickoff threat — the runner knows you'll throw over. Now use that to your advantage, because varying your timing to home means he can't time his jump. The pickoff threat plus unpredictable timing is the best combination for controlling the running game.","Holding the ball extra long can be called for delay by the umpire, because there are time limits on pitching. The runner is not going to get more nervous the longer you wait — he's already comfortable with his lead, which means stalling accomplishes nothing."],
      rates:[20,35,85,30],concept:"After establishing the pickoff threat, vary your delivery timing — the combination controls runners",explSimple:["A third pickoff attempt after two failures wastes time and annoys your defense.","Focusing only on the batter lets the runner relax.","You've established the pickoff threat — the runner knows you'll throw over.","Holding the ball extra long can be called for delay."],anim:"strike"},
    {id:"p48", conceptTag:"pickoff-mechanics",title:"Lefty Advantage — Pickoff Move",diff:2,cat:"baserunners",ageMin:9,ageMax:99,
      description:"Top of the 7th, fast runner on 1st, nobody out, up 4-3. You're a left-handed pitcher — you face the runner naturally when pitching from the stretch.",
      situation:{inning:"Top 7",outs:0,count:"0-0",runners:[1],score:[4,3]},
      options:["Use your pickoff move — lefties have the best angle","Slide step to home — shorten your delivery time","Quick-pitch to surprise the runner","Hold the ball and stare him down"],
      best:0,explanations:["Left-handed pitchers have the best pickoff move in baseball because they face first base while pitching. Your kick leg goes toward both home and first — the runner can't tell which way you're going until the last moment. Use this advantage! A good lefty pickoff move picks off runners who would steal easily on righties.","A slide step shortens your delivery, but as a lefty, your pickoff move is even more effective — your natural advantage facing first base lets you catch runners that slide steps alone can't.","Quick-pitching is a gimmick, which means your natural pickoff advantage is better.","Staring at the runner without throwing doesn't accomplish anything."],
      rates:[85,20,30,15],concept:"Left-handed pitchers have a natural pickoff advantage — your body faces first base. Use it!",explSimple:["Left-handed pitchers have the best pickoff move in baseball because they face first base while pitching.","As a lefty with a fast runner on first, ignoring your biggest advantage is wasteful.","Quick-pitching is a gimmick.","Staring at the runner without throwing doesn't accomplish anything."],anim:"pickoff"},
    {id:"p49", conceptTag:"pickoff-mechanics",title:"Runner Faking — Stay Composed",diff:3,cat:"baserunners",ageMin:12,ageMax:99,
      description:"Bot 6th, runner on 1st, 1 out, tied 5-5. The runner keeps faking like he's going to steal — bluffing secondary leads, dancing off first. He's trying to distract you.",
      situation:{inning:"Bot 6",outs:1,count:"1-1",runners:[1],score:[5,5]},
      options:["Throw over every time he fakes — teach him a lesson","Ignore his fakes — focus completely on the batter","Acknowledge the fake with a look, then deliver to home","Step off and throw to first when he fakes"],
      best:2,explanations:["Throwing over repeatedly is exactly what the runner wants — each throw resets your rhythm and tires your arm, because pickoff throws also raise your pitch count without recording outs, and the batter gets extra time to study your delivery.","Ignoring the runner completely is dangerous because you lose awareness of timing changes. If he suddenly breaks for real, your catcher gets no warning and the stolen base becomes almost automatic.","The runner is in your head — that's his goal. Acknowledge him with a quick glance so he knows you're aware, then deliver to the plate. A glance says 'I see you' without disrupting your pitch. This keeps your rhythm steady, lets the catcher stay in receiving position, and tells the runner his bluffs aren't working.","Stepping off the rubber every time he fakes is a tempo killer — it slows the pace, frustrates your defense, and gives the opposing hitters extra time to get comfortable in the box, since a quick look accomplishes the same awareness without the disruption."],
      rates:[20,35,85,30],concept:"When runners try to distract you, acknowledge with a look but stay focused on the batter",anim:"strike"},
    {id:"p50", conceptTag:"steal-window",title:"Pitchout — When to Agree",diff:3,cat:"baserunners",ageMin:12,ageMax:99,
      description:"Top of the 8th, fast runner on 1st, nobody out, up 3-2. Your catcher signals for a pitchout — he thinks the runner is stealing on the next pitch. Count is 1-1.",
      situation:{inning:"Top 8",outs:0,count:"1-1",runners:[1],score:[3,2]},
      options:["Agree to the pitchout — trust your catcher","Shake it off — you don't want to fall behind 2-1","Wait until the next pitch — one more look first","Throw a fastball up and in instead"],
      best:0,explanations:["Your catcher has the best view of the runner's movements. If he thinks the runner is going, trust him. A pitchout (an intentional ball thrown high and outside) lets the catcher receive the ball standing up and throw to second quickly. If the runner IS stealing, it's almost a guaranteed out.","Falling behind 2-1 is a concern, but catching a runner stealing is worth more than the count, because the catcher reads body language you can't see.","Waiting until the next pitch sounds cautious, but your catcher is reading the runner RIGHT NOW, since the steal window may only be open for one pitch — hesitate and you lose the opportunity.","A fastball up and in doesn't give the catcher the same clean receiving position as a pitchout."],
      rates:[85,35,30,40],concept:"Trust your catcher's pitchout call — he reads the runner's body language better than anyone",anim:"catch"},
    {id:"p51", conceptTag:"pickoff-mechanics",title:"Daylight Play at Second",diff:3,cat:"baserunners",ageMin:12,ageMax:99,
      description:"Bot 7th, runner on 2nd, nobody out, tied 4-4. The shortstop flashes his glove — the signal for the daylight play. He's going to sneak behind the runner on 2nd.",
      situation:{inning:"Bot 7",outs:0,count:"0-0",runners:[2],score:[4,4]},
      options:["Throw to second after the signal — pick him off","Pitch to the batter — let the catcher handle the runner","Look at the runner, step off, then throw when the SS gets there","Step off, wait for the shortstop to get in position, then throw"],
      best:3,explanations:["Throwing immediately after the signal might beat the shortstop — he needs time to get to the bag.","Pitching home and letting the catcher handle it wastes this strategic opportunity your shortstop just set up.","Looking at the runner tips him off — the whole point is to catch him off guard while the shortstop sneaks in behind him.","Step off the rubber (so it's not a balk), wait for the shortstop to reach the bag behind the runner, then throw. The timing has to be coordinated — the runner doesn't know the SS is sneaking behind him. This play picks off runners who get complacent at second base."],
      rates:[30,15,40,85],concept:"On the daylight play, step off and wait for the fielder to reach the bag — timing and coordination are key",anim:"catch"},
    // Batch 5 — Intentional Walks & Pitching Around
    {id:"p52", conceptTag:"pitch-sequencing",title:"Their Best Hitter — First Base Open",diff:2,cat:"strategy",ageMin:9,ageMax:99,
      description:"Top of the 8th, runner on 2nd, 2 outs, up 4-3. Their best hitter (.340 avg) is at the plate. First base is open. The #5 hitter (.230) is on deck.",
      situation:{inning:"Top 8",outs:2,count:"0-0",runners:[2],score:[4,3]},
      options:["Walk him intentionally — face the .230 hitter","Pitch to him competitively — don't put the go-ahead run on base","Pitch around him carefully — nothing hittable but no free pass","Walk only if you fall behind 2-0"],
      best:1,explanations:["Old-school thinking says walk the dangerous hitter, but analytics show intentional walks almost always increase the other team's run scoring, because you're putting the go-ahead run on base for free. With 2 outs, one more strike and the inning is over — make him earn it.","With 2 outs, you're one pitch away from ending the inning. Walking him gives a free baserunner and puts the go-ahead run on first. The Book by Tom Tango shows IBBs increase expected runs in almost every situation. Pitch competitively — even a .340 hitter makes an out 66% of the time.","Pitching around him is cautious but risky. If you fall behind, you've wasted pitches and may end up walking him anyway on a bad count. Either pitch to him or don't — the in-between approach often backfires.","Waiting until 2-0 means you've thrown two careful pitches and put yourself behind in the count, since now you're pitching from weakness. It's better to attack from pitch one."],
      rates:[20,85,50,30],concept:"Don't put the go-ahead run on base. Even elite hitters make outs 65%+ of the time — make them earn it.",explSimple:["Walking him sounds safe, but you're giving the other team a free runner. That's the go-ahead run on first base for free!","With 2 outs you only need one more out. Even great hitters fail most of the time. Pitch to him and make him earn it!","Pitching around him might work, but if you miss too much you walk him anyway. Be decisive.","Waiting until 2-0 to decide means you already fell behind. Attack the hitter from the start."],anim:"strike"},
    {id:"p53", conceptTag:"force-vs-tag",title:"Force Play Setup — Runner on 3rd, 1 Out",diff:2,cat:"strategy",ageMin:9,ageMax:99,
      description:"Bot 5th, runners on 2nd and 3rd, 1 out, up 5-3. First base is open. A decent hitter steps to the plate. Walking him loads the bases and creates a force at every base including home.",
      situation:{inning:"Bot 5",outs:1,count:"0-0",runners:[2,3],score:[3,5]},
      options:["Walk him — load the bases for force at home","Pitch to him — don't put the tying run on first","Walk only if the next batter is weaker","Bring in a relief pitcher from the bullpen"],
      best:0,explanations:["Loading the bases with 1 out creates a force at home plate. A ground ball to any infielder can get the lead runner at home — no tag needed. With runners on 2nd and 3rd, a ground ball through the infield scores both runners. Loading the bases also opens the door for a double play.","Without the force at home, you need a tag on any play at the plate, which is harder to execute, because a ground ball could score a run on a fielder's choice. Tag plays give the runner a chance to evade or slide around the catcher — force outs are much cleaner and more reliable.","The next batter matters, but the real value is the force at home and double play possibility with 1 out, because loading the bases creates defensive options that don't exist with runners on 2nd and 3rd alone.","Changing pitchers now puts a cold arm in a high-pressure spot, because a reliever needs time to warm up and adjust to the game situation. Your current pitcher knows the hitters and has been working effectively — stick with your plan and execute the intentional walk."],
      rates:[82,35,40,30],concept:"With 2nd and 3rd occupied and 1 out, loading the bases creates a force at home and a double play opportunity",explSimple:["Walking him loads the bases. Now you can get the out at home on any ground ball — no tag needed! Plus you might get a double play.","Without the bases loaded, you have to tag runners at home. Tags are harder than force outs.","The next batter matters, but the force at home and double play chance are the real reasons to walk him.","Bringing in a new pitcher now puts a cold arm in a high-pressure situation. Stick with your plan."],anim:"walk"},
    {id:"p54",title:"Lefty-Righty Walk Advantage",diff:2,cat:"strategy",conceptTag:"platoon-advantage",ageMin:11,ageMax:99,
      description:"Top of the 6th, runner on 1st, 1 out, tied 4-4. A tough left-handed hitter (.320 avg) is at the plate. The next guy up hits right-handed (.210 avg). You're a right-handed pitcher.",
      situation:{inning:"Top 6",outs:1,count:"1-0",runners:[1],score:[4,4]},
      options:["Walk the lefty to face the righty — platoon advantage","Pitch to the lefty — don't put another runner on","Pitch carefully to the lefty — don't give him anything good","Only walk him if he gets ahead in the count"],
      best:0,explanations:["As a righty, you have a natural advantage against right-handed hitters — your breaking balls move AWAY from them, which is harder to hit — walking the lefty to face the righty gives you the platoon advantage AND sets up a double play.","Pitching to a tough lefty as a righty means your breaking balls move INTO his hitting zone — toward him, not away, which means that's dangerous.","Pitching carefully often leads to walks anyway, but on a 3-2 count with a full count battle, because you just walk him cleanly.","Waiting to decide until the count develops wastes pitches and risks giving up a hit, because the downside outweighs the potential gain."],
      rates:[85,30,40,25],concept:"Walk a tough opposite-hand hitter to face a same-hand hitter — use the platoon advantage",explSimple:["As a righty, you have a natural advantage against right-handed hitters — your breaking balls move AWAY from them, which is harder to hit.","Pitching to a tough lefty as a righty means your breaking balls move INTO his hitting zone — toward him, not away.","Pitching carefully often leads to walks anyway, but on a 3-2 count with a full count battle.","Waiting to decide until the count develops wastes pitches and risks giving up a hit."],anim:"walk"},
    {id:"p55", conceptTag:"ibb-strategy",title:"3-for-3 Against You — Walk Him?",diff:3,cat:"strategy",ageMin:12,ageMax:99,
      description:"Bot 8th, runners on 1st and 2nd, 1 out, up 6-4. Their cleanup hitter has gone 3-for-3 against you today with a double and a homer. First base is NOT open — walking him loads the bases.",
      situation:{inning:"Bot 8",outs:1,count:"0-0",runners:[1,2],score:[4,6]},
      options:["Walk him anyway — he owns you today","Pitch to him — don't load the bases","Pitch around him very carefully — nothing hittable","Bring in a new pitcher to face him"],
      best:2,explanations:["Walking him loads the bases — now a walk, HBP, or wild pitch scores a run, since that's too dangerous.","Pitching to a guy who's 3-for-3 with extra-base hits is also dangerous, because he's got your timing.","Pitch around him — throw competitive pitches just off the zone — if he chases, great. If he doesn't, you walk him but at least you made him earn it. This is the middle ground between challenging a hot hitter and loading the bases intentionally.","A new pitcher with runners on in the 8th is high-pressure, which means sometimes you have to compete with what you've got."],
      rates:[30,20,85,40],concept:"When a hitter owns you, pitch around him carefully — don't groove one but don't load the bases free",anim:"strike"},
    {id:"p56", conceptTag:"force-vs-tag",title:"Walk to Load Bases — Force at Home",diff:3,cat:"strategy",ageMin:12,ageMax:99,
      description:"Top of the 9th, runners on 2nd and 3rd, 2 outs, up 5-3. First base is open. Walking the batter loads the bases but gives you a force at home.",
      situation:{inning:"Top 9",outs:2,count:"0-0",runners:[2,3],score:[5,3]},
      options:["Walk him — force at home on any ground ball","Pitch to him — don't load the bases","Walk only if this batter is better than the next one","Bring in a reliever instead"],
      best:0,explanations:["With a 2-run lead and 2 outs, loading the bases gives you a force at EVERY base, including home. Any ground ball, the catcher steps on home for the force out — no tag needed. A tag play at home on a close play is much harder. The force at home is a huge defensive advantage.","Pitching to him without the force at home means a ground ball through the infield scores a run, and a tag play at the plate might not get the runner. After all, and that's why this approach matters in this situation.","The force at home is valuable regardless of who's batting next, because it's about defensive positioning, not matchups.","Bringing in a reliever doesn't address the defensive advantage of the force at home."],
      rates:[85,30,35,25],concept:"Loading the bases for a force at home can be smart — force outs at the plate are much easier than tags",anim:"walk"},
    {id:"p57", conceptTag:"ibb-strategy",title:"IBB Backfires — Surprise Pinch Hitter",diff:3,cat:"strategy",ageMin:12,ageMax:99,
      description:"Bot 8th, you just intentionally walked their #4 hitter to face the weaker #5 hitter. But the opposing manager sends up a pinch hitter — a left-handed veteran with a .290 average.",
      situation:{inning:"Bot 8",outs:1,count:"0-0",runners:[1,2],score:[4,3]},
      options:["Stick with your game plan — pitch to the pinch hitter","Ask your manager for help — this changes things","Be extra careful — this guy is better than expected","Attack the zone — don't pitch scared"],
      best:3,explanations:["Sticking with the plan is fine, but you need to adjust your approach for a different hitter.","Your manager already made the call, since you adapt and compete. Think about what gives your team the best result here.","Being 'extra careful' leads to walks and more runners, because you already have runners on 1st and 2nd.","A surprise pinch hitter means you expected a weaker batter — don't panic — attack the zone. The pinch hitter is cold (hasn't batted all game), and you're warm. Throw strikes and make him beat you. Cold pinch hitters struggle with the first few pitches. Use that."],
      rates:[35,20,30,85],concept:"When a pinch hitter surprises you, attack — they're cold and you're warm. Throw strikes",anim:"strike"},
    {id:"p58", conceptTag:"ibb-strategy",title:"Walk the 8th Hitter?",diff:3,cat:"strategy",ageMin:12,ageMax:99,
      description:"Top of the 7th, runner on 3rd, 2 outs, up 3-2. The #8 hitter (.200) is up. The pitcher (.100) bats next. Should you walk the 8 hitter to face the pitcher?",
      situation:{inning:"Top 7",outs:2,count:"0-0",runners:[3],score:[3,2]},
      options:["Walk the .200 hitter to face the .100 pitcher","Pitch to the .200 hitter — he's weak enough","Pitch around the .200 hitter — nothing good","Only walk if you fall behind in the count"],
      best:0,explanations:["Walking the .200 hitter to face the pitcher (.100) is a massive upgrade, which means you're going from a 1-in-5 chance of a hit to a 1-in-10 chance. Plus, pitchers are terrible hitters. With the tying run on third, take every advantage you can.","A .200 hitter can still get a hit, because a .100 pitcher is almost a guaranteed out. Take the sure thing.","Pitching around him wastes pitches when you could just walk him and face the pitcher fresh.","Waiting to fall behind wastes pitches and risks giving up a hit in the process, because the downside outweighs the potential gain."],
      rates:[85,40,45,30],concept:"Walk a weak hitter to face an even weaker one — pitchers batting are almost automatic outs",anim:"walk"},
    {id:"f22", conceptTag:"bunt-defense",title:"Bunt With Runners — Get the Lead Runner",diff:3,cat:"infield",ageMin:12,ageMax:99,
      description:"Bot 3rd, runners on 1st and 2nd, nobody out, tied 1-1. The batter bunts — decent bunt rolling toward the mound. You're the pitcher. Where do you throw?",
      situation:{inning:"Bot 3",outs:0,count:"0-0",runners:[1,2],score:[1,1]},
      options:["Throw to third — get the lead runner","Throw to second — start a double play","Throw to first — get the sure out","Hold it and eat the ball"],
      best:0,explanations:["Getting the lead runner at third is the best play on a bunt with runners on 1st and 2nd! The runner from second is forced to third — it's a force out, so the third baseman just catches it on the bag. Getting the lead runner prevents him from reaching scoring position.","There's no double play on a bunt — since everyone is moving forward and he's fast out of the box.","Throwing to first is easy but advances both runners into scoring position (2nd and 3rd), since you getting the lead runner is worth the effort.","Eating the ball with nobody out loads the bases, because you make a play!"],
      rates:[85,15,40,5],concept:"On a bunt with runners on 1st and 2nd, get the lead runner at third — it's a force out",anim:"bunt"},
    {id:"p59",title:"Cover First on the Wild Strikeout",diff:2,cat:"pitcher",ageMin:9,ageMax:99,
      description:"You're the pitcher. Your curveball bounces in the dirt for strike three! The catcher dives left, but the ball rolls toward the first base dugout. Bases are empty with no outs and a 1-run lead in the top of the 7th. The batter takes off running toward first.",
      situation:{inning:"Top 7",outs:0,count:"0-2",runners:[],score:[2,1]},
      options:["Sprint to cover first base immediately","Back up home plate in case the catcher overthrows first","Stay near the mound — that's the catcher's play","Run to third base in case the runner tries to advance"],
      best:0,explanations:["Perfect reaction! On a dropped third strike with first base empty, it becomes a footrace — the catcher is scrambling for the ball, so YOU need to cover first base. Sprint there immediately and be ready for the throw.","Backing up home isn't needed — there's nobody on base to score, which means the urgent play is getting to first base before the batter-runner. The catcher needs a target at first!","Never just stand and watch! On a dropped third strike, the pitcher MUST sprint to first base, because the first baseman may be off the bag, and the catcher needs someone covering the base to throw to.","There's nobody on base — why would you go to third? The only play is at first base, since you sprint there and receive the throw from the catcher!"],
      rates:[90,40,25,15],concept:"On a dropped third strike, the pitcher MUST sprint to cover first base — it becomes a footrace between the pitcher and the batter-runner.",explSimple:["Great job! When the catcher drops strike three, you need to run to first base really fast so you can catch the throw and get the batter out.","Nobody is on base, so backing up home doesn't help. Run to first base instead!","Don't just stand there! When the ball gets away, run to first base as fast as you can.","Nobody is on base, so there's no reason to go to third. First base is where the play is!"],anim:"groundout",conceptTag:"dropped-third-strike"},
    {id:"p62",title:"The 2-0 Danger Zone",diff:2,cat:"strategy",conceptTag:"count-leverage",ageMin:9,ageMax:99,
      description:"You're the pitcher in a 2-0 count against a .280 hitter. Runner on 1st, 1 out, Bot 6th, you're up 4-2. Your catcher sets up for a fastball down the middle to get back in the count. You've thrown 72 pitches and feel strong. What's your approach?",
      situation:{inning:"Bot 6",outs:1,count:"2-0",runners:[1],score:[2,4]},
      options:["Throw the fastball down the middle — you need a strike","Throw a changeup — surprise him in a hitter's count","Try to paint the corner with a fastball","Throw a sinker low in the zone — get a ground ball for a DP"],
      best:3,explanations:["A fastball down the middle in a 2-0 count is what the hitter is sitting on, because batters hit .400 in 2-0 counts — they're looking for exactly this pitch. You're throwing batting practice.","A changeup in 2-0 is high-risk, since if it misses, you're 3-0 and basically walking him. The element of surprise doesn't outweigh the risk of falling further behind.","Painting the corner sounds smart, but in 2-0 you NEED a strike, which means trying to paint often results in ball three. The margin for error is too thin.","A sinker low in the zone is the best play. With a runner on 1st and 1 out, a ground ball could turn a double play. The sinker's natural downward movement makes it hard to elevate even when hitters are sitting fastball. You get your strike AND your best chance at a DP."],
      rates:[25,15,40,85],concept:"In a 2-0 hitter's count, pitch to contact on YOUR terms — a sinker for a ground ball DP is better than a fastball down the middle",explSimple:["A fastball down the middle in 2-0 is what the hitter is looking for — that's batting practice.","A changeup in 2-0 is risky — if it misses, you're 3-0 and almost walking him.","Painting the corner sounds smart, but trying to be too fine often results in ball three.","A sinker low in the zone gets you a strike AND a chance at a double play — best of both worlds!"],anim:"doubleplay"},
    {id:"p63", conceptTag:"pitch-sequencing",title:"Coors Field — Change Your Game Plan",diff:3,cat:"strategy",ageMin:12,ageMax:99,
      description:"You're a visiting pitcher at Coors Field in Denver (altitude ~5,280 ft). Top 1st, nobody on, no outs. You're a breaking ball pitcher — your slider and curveball are your best weapons at sea level. But you know the thin air at altitude reduces breaking ball movement by about 15%. The leadoff hitter bats .275 who struggles with fastballs up. How do you approach this at-bat?",
      situation:{inning:"Top 1",outs:0,count:"0-0",runners:[],score:[0,0]},
      options:["Lean on your fastball command — breaking balls lose movement at altitude","Throw your normal game — your breaking balls are still your best pitches","Throw only changeups — they rely on speed difference, not spin movement","Throw harder than usual — the thin air means less drag on your fastball"],
      best:0,explanations:["At Coors Field, the thin air reduces spin-induced movement by ~15%. Your slider that breaks 6 inches at sea level only breaks 5 inches here. Your curveball drops less. But your fastball command doesn't change with altitude. Since this hitter struggles with fastballs up, use your fastball as the primary pitch and mix in breaking balls as secondary — don't rely on them for put-aways.","Your breaking balls ARE still good pitches, but they're diminished at altitude, because a slider that looks like a strike but doesn't break as much stays over the plate — hittable. You must adjust your pitch mix to account for the 15% movement loss.","Changeups lose effectiveness too — the speed difference is the same, but the ball carries more at altitude, since a hanging changeup at Coors becomes a home run. You need fastball command as your base.","You can't just 'throw harder' — that's not how pitching works, because your velocity is what it is. The thin air does slightly reduce drag, adding ~1-2 mph, but the benefit is offset by the ball carrying farther if hit. Focus on location, not velocity."],
      rates:[85,30,15,20],concept:"At altitude (Coors Field), breaking balls lose ~15% movement — adjust your pitch mix to rely more on fastball command and less on spin-based movement",anim:"strike"},
    {id:"p64",conceptTag:"first-pitch-strike",title:"First Pitch Strike After a Leadoff Double",diff:2,cat:"pitching",ageMin:9,ageMax:99,
      description:"You're the pitcher. The leadoff batter just doubled to start the inning. Nobody out, runner on second, no outs. The next batter steps in. After giving up the double, you feel rattled. What's your first pitch approach?",
      situation:{inning:"Top 4",outs:0,count:"0-0",runners:[2],score:[3,2]},
      options:["Paint the corners — make him chase a perfect pitch","Attack with a first-pitch strike — get ahead immediately","Pitch around this batter to set up a double play at first","Throw a breaking ball to change the look after the double"],
      best:1,explanations:["Being careful after giving up a hit is the natural instinct, but it's a trap, since nibbling leads to walks, and a walk with a runner on second puts runners on first and second with nobody out — a disaster. Attack the zone.","After giving up a leadoff double, the WORST thing you can do is walk the next batter. Throw a strike. Getting ahead 0-1 lets you control the at-bat and work for a ground ball or strikeout. Pitchers who throw first-pitch strikes after extra-base hits limit the damage far more often than pitchers who nibble.","Pitching around this batter puts a free runner on first with nobody out, which means now you have runners on first and second and still need three outs. The double play is nice in theory, but the walk to set it up costs you more than it gains.","A breaking ball for a first pitch after a double is fine IF it's a strike. But the key is throwing a STRIKE, not the pitch type. Too many pitchers throw a first-pitch breaking ball that misses and fall behind 1-0, making everything harder."],
      rates:[25,85,20,40],concept:"After a leadoff extra-base hit, throw a first-pitch strike to the next batter — walks compound damage far worse than hits",explSimple:["Being too careful after a hit leads to walks, which makes things worse.","Throw a strike! Getting ahead 0-1 helps you limit the damage.","Pitching around the batter puts another free runner on base. Bad idea.","A breaking ball is fine if it's a strike, but the key is throwing a STRIKE."],anim:"strike"},
    {id:"p65",conceptTag:"eye-level-change",title:"What Is Changing Eye Level?",diff:1,cat:"pitching",ageMin:6,ageMax:99,
      description:"You're the pitcher. You've thrown two fastballs at the batter's belt for strikes. The count is 0-2. What should your next pitch do?",
      situation:{inning:"Top 3",outs:1,count:"0-2",runners:[],score:[1,0]},
      options:["Throw another fastball in the same spot — if it's working, keep doing it","Throw a pitch in a different location — up high or down low — to change the batter's eye level","Throw the hardest pitch you can right down the middle","Lob a slow pitch to mess up timing"],
      best:1,explanations:["Throwing the same pitch in the same spot three times in a row is predictable, because good hitters adjust — they'll be sitting on a belt-high fastball now. Change something.","When you throw two pitches at the same height, the batter's eyes get comfortable there. Changing eye level — going up near the letters or down near the knees — forces the batter to re-adjust his swing path. This makes it much harder to hit the ball. Even young pitchers can learn to go high then low.","Throwing your hardest pitch down the middle on 0-2 is wasteful and dangerous, since you're ahead in the count — make the batter chase something off the plate or at a different height.","Lobbing a slow pitch with no purpose is easy to hit, because changing speeds works, but you need to change location too, not just throw slower."],
      rates:[25,85,15,20],concept:"Changing eye level means moving pitches from high to low or low to high — this makes batters re-adjust their swing and is harder to hit",explSimple:["Throwing three pitches in the same spot is predictable. Change something!","Go up high or down low to change the batter's eye level. This makes it much harder to hit!","Throwing down the middle on 0-2 wastes your advantage.","Lobbing a slow pitch with no plan is easy to hit."],anim:"strikeout"},
    {id:"p66",conceptTag:"eye-level-change",title:"Setting Up the High Fastball",diff:2,cat:"pitching",ageMin:9,ageMax:99,
      description:"You're the pitcher. You've thrown two changeups low in the zone this at-bat. The count is 1-1. The batter has been gearing up for another low pitch — you can see him starting his swing low. What do you throw next?",
      situation:{inning:"Bot 5",outs:0,count:"1-1",runners:[1],score:[2,2]},
      options:["Another changeup low — he keeps swinging over it","Fastball up at the letters — change his eye level completely","Curveball in the dirt — go even lower","Fastball at the belt — split the difference"],
      best:1,explanations:["He's been adjusting to low pitches and starting his swing there — another low pitch plays into what he's already looking for. Change the look.","After two low pitches, the batter's eyes and swing path are geared downward. An elevated fastball at the letters forces him to completely re-adjust. The ball looks like it's rising because his timing is set for a lower pitch. This high-low sequence is one of the most effective pitch tunneling strategies in baseball — the eye level change makes both pitches harder to hit.","Going even lower when he's already gearing up for low pitches gives him a chance to adjust and scoop it, which means you want to move his eyes, not confirm where they're already looking.","A fastball at the belt is a bigger change than another low pitch, but it's not enough of an eye level shift to really disrupt him, because the biggest change — from knees to letters — creates the most confusion."],
      rates:[30,85,25,40],concept:"After low pitches, elevate the fastball at the letters — the eye level change makes the batter re-adjust his entire swing path",explSimple:["He's already looking low. Another low pitch plays into what he expects.","A fastball up at the letters changes his eye level and makes him re-adjust completely!","Going even lower confirms where he's already looking. Change it up.","A belt-high fastball isn't enough of a change to really disrupt him."],anim:"strike"},
    {id:"p67",conceptTag:"eye-level-change",title:"Pitch Tunneling — Same Look, Different Finish",diff:3,cat:"pitching",ageMin:13,ageMax:99,
      description:"You're a pitcher who throws a 90 mph four-seam fastball and a 78 mph curveball. Your catcher signals for a strikeout setup. In the previous at-bat, you struck this batter out on a curveball in the dirt after two fastballs up. He's back for his second at-bat. How do you use eye level change to get him again?",
      situation:{inning:"Bot 6",outs:1,count:"1-2",runners:[2],score:[3,3]},
      options:["Same sequence as last time — fastball up, fastball up, curveball down","Curveball first to surprise him, then fastball up","Fastball up, then curveball that starts at the same height as the fastball but drops out of the zone","All fastballs — he'll be looking for the curveball this time"],
      best:2,explanations:["Repeating the exact same sequence against the same hitter is predictable, since good hitters remember what they saw last at-bat and adjust. He'll be sitting on the curveball in the dirt this time.","Leading with a curveball removes the setup, because the curveball is most effective when the batter's eyes are calibrated to a fastball. Without the eye level shift, the curveball is just a slow pitch.","This is pitch tunneling combined with eye level change. When your curveball starts at the same release point and trajectory as your fastball but then drops 12\u201318 inches, the batter's brain sees 'fastball up' and commits — then the bottom falls out. The key is making both pitches look identical for the first 20 feet out of your hand. So a big eye level gap (high fastball to low curveball) creates so many swings and misses.","All fastballs ignores your best weapon — he struck out on the curveball last time, so yes, he might look for it — but the SETUP matters more than the pitch selection. A well-tunneled curveball beats a hitter even when he knows it's coming."],
      rates:[30,25,85,35],concept:"Pitch tunneling uses eye level change — throw pitches that start at the same trajectory but finish at different heights to fool the batter's brain",explSimple:["Repeating the exact same sequence is predictable. He'll be ready this time.","Leading with a curveball removes the setup. You need the fastball first.","Make your curveball start at the same height as your fastball, then let it drop. The batter's brain sees 'fastball' and then the bottom falls out!","All fastballs ignores your best weapon. The setup matters more than the pitch."],anim:"strikeout"},
    {id:"p68",conceptTag:"pitch-type-value",title:"Pitch Type Run Values — Fastball vs. Changeup",diff:2,cat:"strategy",ageMin:13,ageMax:99,
      description:"You're reviewing your pitch data after a start. Your four-seam fastball allowed a .310 batting average against, while your changeup allowed .190. Your catcher suggests discussing your pitch mix for the next start. Right now you throw 65% fastballs and 20% changeups.",
      situation:{inning:"Top 1",outs:0,count:"0-0",runners:[],score:[0,0]},
      options:["Keep the same mix — fastballs set up everything else","Throw more changeups since batters hit worse against them","Use your changeup more often, but keep enough fastballs to make the changeup effective","Switch to mostly curveballs to surprise hitters"],
      best:2,explanations:["Sticking with 65% fastballs when batters hit .310 against them means you're giving hitters too many pitches they can handle. Your pitch mix should evolve based on what works — because you run values tell you which pitches are actually preventing damage.","Simply maximizing your best pitch sounds logical, but changeups are effective BECAUSE batters expect fastballs. If you throw 60% changeups, hitters will adjust and sit on the slower pitch, which means your changeup run value will get worse over time.","This is the smart approach. Your changeup has a better run value (.190 vs .310 BAA), so increasing its usage from 20% to around 30-35% will prevent more runs. The key is keeping enough fastballs in the mix so batters can't eliminate the changeup speed. Pitch type value is about finding the optimal mix, not just throwing your best pitch every time.","Introducing a pitch you haven't been using heavily based on changeup data makes no sense. Since your changeup is already working well, the adjustment should be between fastball and changeup percentages, not adding an unproven third option."],
      rates:[35,40,80,20],concept:"Pitch type run values help you optimize your pitch mix — throw more of what works, but keep enough variety so hitters can't sit on one pitch",anim:"strike"},
    {id:"p69",conceptTag:"pitch-type-value",title:"Pitch Effectiveness by Count",diff:3,cat:"strategy",ageMin:13,ageMax:99,
      description:"You throw a fastball, slider, and changeup. Your data shows: fastball run value is best in 0-0 and 0-1 counts, slider run value is best in 0-2 and 1-2 counts, and changeup run value is best in 1-0 and 2-1 counts. It's a 1-2 count and you need a strikeout to end the inning with a runner on 3rd.",
      situation:{inning:"Top 7",outs:2,count:"1-2",runners:[3],score:[2,3]},
      options:["Fastball — your most powerful pitch","Slider — your best pitch in this count","Changeup — it has the best overall run value","Throw whatever feels right in the moment"],
      best:1,explanations:["Your fastball has its best run value in 0-0 and 0-1 counts, not 1-2. Since run values change by count, throwing your fastball here means you're using a pitch in the count where it's least effective as a put-away pitch. Hitters are geared up to protect against fastballs with two strikes.","Your slider has its best run value in 0-2 and 1-2 counts, which means it generates the most whiffs and weakest contact in exactly this situation. Because hitters with two strikes are protecting the plate and shortening their swing, a late-breaking slider that starts in the zone and dives out is the hardest pitch to lay off. Matching your pitch to its highest-value count is what elite pitching is about.","Your changeup is most effective in 1-0 and 2-1 counts — counts that favor the batter, where he's aggressive and looking to drive the ball. In a 1-2 count, the batter isn't swinging freely, so the changeup's speed differential is less deceptive. The key is using each pitch in the count where its run value is highest.","'Going with your gut' ignores the data that tells you exactly which pitch works best in this count. Since run values vary significantly by count, pitching based on feel alone means you'll sometimes choose a pitch that's statistically weaker in that situation."],
      rates:[30,85,40,15],concept:"Pitch effectiveness changes by count — use run values to pick the right pitch for each situation, not just your overall best pitch",anim:"strikeout"},
    {id:"p_mg1",conceptTag:"composure-pressure",title:"Resetting After a Home Run",diff:1,cat:"mental-game",ageMin:8,ageMax:99,
      description:"You just gave up a home run and the other team is celebrating. Runners are cleared. The next batter is stepping in. What do you do?",
      situation:{inning:"Top 4",outs:1,count:"0-0",runners:[],score:[3,2]},
      options:["Throw harder to show you're not rattled","Take a moment on the mound, gather yourself, then focus on this batter","Rush through the next pitch to move on quickly","Ask your coach to take you out"],
      best:1,explanations:["Throwing harder because you're frustrated leads to rushing your mechanics, which means you lose control and end up walking batters or leaving pitches over the plate. Velocity doesn't fix emotions.","Taking a moment to gather yourself is what every great pitcher does after giving up a big hit. Walk behind the mound, take a breath, and remind yourself that the home run is over — this is a brand new at-bat. By resetting your focus, you give yourself the best mechanics and the best chance to get this batter out.","Rushing through the next pitch carries your frustration into the next at-bat, since your body hasn't had time to reset. Quick pitches after mistakes usually miss their spots because your mind is still on the last play.","Asking to come out after one home run shows a lack of confidence and toughness. Every pitcher gives up home runs — the ones who succeed are the ones who can reset and compete with the next batter."],
      explSimple:["Throwing harder when you're upset usually means you lose control.","Walk behind the mound, take a breath, and focus on the next batter. The home run is over!","Rushing the next pitch means your body hasn't calmed down yet.","Every pitcher gives up home runs. The best ones reset and get the next batter out."],
      rates:[30,80,35,20],concept:"After giving up a big hit, take a moment to reset on the mound — a calm pitcher with good mechanics beats a frustrated pitcher throwing hard",anim:"strike"},
    {id:"p_ppr1",conceptTag:"pre-pitch-routine",title:"Your Routine Between Pitches",diff:1,cat:"mental-game",ageMin:8,ageMax:99,
      description:"You're on the mound with a 2-1 count. You got the ball back from the catcher. Before your next pitch, what should you do?",
      situation:{inning:"Top 5",outs:1,count:"2-1",runners:[],score:[1,1]},
      options:["Hurry up and throw — don't give the batter time to think","Step off the rubber, take a breath, decide what pitch you want to throw, then get back on","Stand on the rubber and stare at the batter to intimidate him","Look around at the crowd to stay loose"],
      best:1,explanations:["Hurrying your delivery doesn't give YOUR brain time to decide on the right pitch and location, since rushing leads to mistakes in a hitter's count where you can't afford to miss.","Stepping off the rubber between pitches lets you breathe, clear your head, and decide exactly what pitch you want to throw and where. This routine — breathe, decide, execute — keeps you in control of the pace and your mechanics. Every pitch starts with a plan, and your between-pitch routine is where that plan is made.","Staring at the batter wastes time without helping your preparation. The batter doesn't care about eye contact — he cares about the pitch you throw. Use your time to decide on your pitch and location instead.","Looking around at the crowd takes your focus away from the only thing that matters: the next pitch. Your between-pitch routine should be focused and purposeful, not casual."],
      explSimple:["Hurrying doesn't give you time to plan your next pitch. Slow down!","Step off, take a breath, and decide what you're throwing. Every pitch starts with a plan!","Staring at the batter doesn't help you throw a better pitch.","Looking at the crowd takes your focus off the next pitch."],
      rates:[35,80,40,20],concept:"A consistent between-pitch routine — breathe, decide, execute — keeps you in control of the game's pace and your own mechanics",anim:"strike"},
    {id:"p_lf1",conceptTag:"learning-from-failure",title:"Three Hits in a Row — What Do You Change?",diff:2,cat:"adjustments",ageMin:10,ageMax:99,
      description:"You've given up three straight hits: a line drive single on a fastball up, a double on a changeup that stayed over the plate, and a single on a hanging curveball. Your catcher calls time and comes to the mound. What adjustment should you make?",
      situation:{inning:"Top 5",outs:0,count:"0-0",runners:[1,3],score:[3,1]},
      options:["Throw everything harder — overpower the next hitter","Look at what went wrong — all three pitches were up in the zone, so focus on keeping the ball down","Switch to pitches you haven't thrown yet to surprise them","Tell your catcher you're fine and don't change anything"],
      best:1,explanations:["Throwing harder doesn't fix location problems, since all three hits came on pitches that missed their spots high in the zone. More velocity on a pitch that's belt-high just means a harder-hit ball.","All three hits had something in common — your fastball was up, your changeup stayed over the plate, and your curveball hung. The pattern is that you're not finishing your pitches down in the zone. Focus on staying on top of the ball and driving it down. One mechanical adjustment — staying tall and finishing through — can fix all three pitch types at once.","Switching pitch types doesn't fix the real problem, because if your mechanics are leaving everything up, new pitches will end up in the same spot. Fix the location issue first, then your whole arsenal improves.","Ignoring three straight hits means you'll keep making the same mistake. The best pitchers are honest about what's going wrong and make adjustments between batters, not after the inning."],
      explSimple:["Throwing harder doesn't fix the problem. Your pitches were too high, not too slow.","All three hits were on pitches that were up. Focus on keeping the ball down!","New pitches won't help if they end up in the same spot. Fix your location first.","Three straight hits means something is wrong. The best pitchers adjust right away."],
      rates:[35,80,35,25],concept:"When you're getting hit hard, find the pattern — if all your pitches are up, one mechanical adjustment to stay on top can fix everything",anim:"strike"},
    {id:"p_ba1",conceptTag:"backup-awareness",title:"Backing Up Home on a Tag-Up",diff:1,cat:"defense",ageMin:8,ageMax:99,
      description:"You're the pitcher. Fly ball to center field with a runner on 3rd tagging up. The center fielder catches it and throws home. Where should you go?",
      situation:{inning:"Bot 6",outs:1,count:"0-0",runners:[3],score:[2,3]},
      options:["Stay on the mound and watch the play","Run to back up home plate in case the throw gets past the catcher","Run to cover first base","Move toward third base to cover"],
      best:1,explanations:["Staying on the mound makes you a spectator. If the throw from center field gets past the catcher, the ball rolls to the backstop and nobody is there to stop it. You have a job on every play — and this one is at home.","On a tag-up throw to home, the pitcher's job is to sprint behind the catcher to back up the plate. If the throw bounces away or the catcher can't handle it, you're there to keep the ball in front of you and prevent extra bases. Backing up is one of the most important things a pitcher does on defense.","First base doesn't matter on this play, since the action is at home plate. The runner on third is the one scoring, and that's where you need to be backing up.","Third base is already empty and the runner has left, so there's no play there. Home plate is where the throw is going, and that's where you need to back up."],
      explSimple:["Don't just watch! If the throw gets past the catcher, you need to be there.","Sprint behind the catcher to back up home plate. If the throw gets away, you stop the ball!","First base isn't involved in this play. The action is at home plate.","The runner already left third. Back up home plate where the throw is going!"],
      rates:[25,80,40,25],concept:"On tag-up throws to home, the pitcher backs up the catcher — sprint behind home plate to prevent overthrows from becoming extra bases",anim:"throwHome"},
    // PITCH-MIX-STRATEGY scenarios
    {id:"p_pm1",title:"Lefty Can't Touch Your Changeup",diff:3,cat:"strategy",conceptTag:"pitch-mix-strategy",ageMin:13,ageMax:99,
      description:"You're facing a left-handed hitter who crushes fastballs (.380 AVG) but can't hit your changeup (.120 AVG). He's 1-for-2 today with a double off your fastball. Runner on 1st, 1 out. What's your pitch mix plan?",
      situation:{inning:"Top 5",outs:1,count:"0-0",runners:[1],score:[3,2]},
      options:["Throw all changeups — he can't hit them","Lead with changeups but mix in enough fastballs to keep him honest","Challenge him with fastballs — show him you're not afraid","Throw mostly sliders since he hasn't seen many today"],
      best:1,explanations:["Throwing all changeups sounds logical based on the data, but hitters adjust. After two or three consecutive changeups, he'll sit on the slower speed and time it. Even a .120 hitter against changeups can square one up when he knows nothing else is coming. Predictability kills even your best pitch.","Your changeup is your weapon against this hitter — use it heavily, but not exclusively. Start with a changeup to steal strike one, mix in a fastball to disrupt his timing, then go back to the changeup as your put-away pitch. The fastball serves a specific purpose: it keeps him from sitting on one speed. If he gears up for the changeup and gets a fastball, he's late. If he cheats for heat and gets the changeup, he's early. The mix makes both pitches more effective.","He's already hit .380 against your fastball and doubled off one today. Challenging him with what he crushes is not competing — it's stubbornness. Compete with the pitch that gives you the best chance to get him out. Using data to select your approach is how smart pitchers win matchups.","Introducing a pitch he hasn't seen today sounds creative, but your changeup has a proven track record against him (.120 AVG). The slider is an unknown in this matchup — you might get lucky, or he might hammer it. Go with the pitch that has the data behind it and use your slider only as a surprise change of look."],
      explSimple:["Throwing all changeups lets him sit on the speed. Even your best pitch gets hit when it's predictable.","Lead with changeups since he can't hit them, but throw enough fastballs to keep him guessing about the speed.","He already hit .380 against your fastball and doubled today. Use your changeup — the pitch that works.","Your changeup has real data behind it. Use your proven weapon instead of guessing with the slider."],
      rates:[30,85,25,25],concept:"Use your best pitch against a hitter's weakness, but mix in enough variety to prevent him from sitting on one speed",anim:"strikeout"},
    {id:"p_pm2",title:"Third At-Bat — He's 0-for-8 on Your Slider",diff:3,cat:"strategy",conceptTag:"pitch-mix-strategy",ageMin:13,ageMax:99,
      description:"You have 4 pitches: fastball, slider, changeup, and curve. This hitter is 0-for-8 lifetime against your slider. It's his 3rd AB today — you got him on sliders both previous times. He steps in looking determined. Count is 0-0.",
      situation:{inning:"Bot 6",outs:0,count:"0-0",runners:[],score:[4,2]},
      options:["Slider first pitch — it's worked all day and all career","Start with a fastball to change his eye level, then go to the slider","Throw three straight sliders — get this over with quickly","Mix in your curve early — he's never seen it from you today"],
      best:1,explanations:["He's 0-for-8 on your slider, but he also just went back to the dugout twice after seeing nothing but sliders. A smart hitter adjusts his approach the third time — he's coming up ready for the slider. Leading with it plays right into his adjustment. The element of surprise is gone.","After getting him twice on sliders, the hitter is going to sit slider this time. Starting with a fastball disrupts his plan — he's geared for the slider's speed and break, and a fastball arrives faster and on a different plane. Once you've changed his eye level with the heater, his timing is off for the slider. Now your slider in the second or third pitch of the AB becomes even more devastating, because he just recalibrated for fastball speed.","Three straight sliders against a hitter who's been studying your slider for two at-bats is overconfidence disguised as strategy. Even 0-for-8 hitters will time a pitch they see exclusively. By the third slider, he's locked in on the speed and break — and one mistake slider stays over the plate.","The curve is a reasonable change of pace, but you're introducing an unproven pitch in this matchup when you already have a proven slider and a logical fastball setup. Save the curve for a surprise later in the AB if you need it — don't lead with your fourth-best option against a hitter you've dominated with your second-best."],
      explSimple:["He's seen nothing but sliders from you today. The third time up, he'll be ready for it. Change the look.","Start with a fastball to mess up his timing — he's expecting your slider. Then go to the slider when he's off balance.","Three straight sliders gives him too many chances to time it. Mix it up even when one pitch is dominant.","Your slider works against him. Set it up with a fastball first instead of introducing a pitch you haven't tested."],
      rates:[30,80,15,40],concept:"When a hitter has seen your best pitch multiple times, set it up differently — change the sequencing, not the weapon",anim:"strike"},
    {id:"p_pm3",title:"Catcher Wants Fastballs, Data Says Changeup",diff:3,cat:"strategy",conceptTag:"pitch-mix-strategy",ageMin:13,ageMax:99,
      description:"Your catcher keeps calling for fastballs, but your season data shows your changeup is your most effective pitch — it has the lowest batting average against (.180) and highest whiff rate (32%). Your fastball BAA is .270. You shake off the fastball sign. Your catcher looks frustrated and calls fastball again.",
      situation:{inning:"Top 4",outs:1,count:"1-1",runners:[2],score:[2,2]},
      options:["Throw the fastball — trust your catcher, he sees things you don't from back there","Shake off again and throw the changeup — the data supports it","Call time and have a mound visit to discuss the disagreement","Just throw whatever you want without shaking off — surprise everyone"],
      best:2,explanations:["Blindly deferring to your catcher ignores the data advantage you have. Your catcher may be calling fastballs based on feel or a hunch, but your changeup has a .180 BAA versus .270 for the fastball. Trust and respect your catcher, but when the numbers clearly favor a different approach, you need to communicate — not just comply.","Shaking off repeatedly without communication creates frustration and mistrust. Your catcher might have a reason for calling fastballs — maybe the hitter is sitting changeup, maybe your changeup has been flat today, maybe there's a timing issue. Throwing the changeup without understanding his perspective could work, but it damages the pitcher-catcher relationship over time.","Calling time to talk is the mature play. Walk your catcher through your thinking: your changeup has been your best pitch with a .180 BAA and 32% whiff rate. Why fastballs here? Maybe he has information you lack — the hitter choked up, the runner is going, or your changeup has looked different today. Or maybe he agrees once he hears your reasoning. Either way, you make a better decision together than in a shake-off standoff.","Throwing a pitch your catcher isn't expecting is dangerous. If you throw a changeup and he's set up for a fastball, the pitch location will look wrong, his framing will be off, and a ball in the dirt could get past him with a runner on 2nd. The battery has to be on the same page."],
      explSimple:["Throwing the fastball just because the catcher wants it ignores what your data tells you.","Shaking off without talking creates frustration. Your catcher might have a good reason for calling fastballs.","Call time and talk about it. Share your data, hear his reasons — make the decision together.","Throwing a pitch your catcher doesn't expect is dangerous, especially with a runner on 2nd."],
      rates:[25,35,85,20],concept:"When you and your catcher disagree on pitch selection, communicate on the mound — share your reasoning and listen to his perspective before deciding",anim:"strike"},
    // PITCHER-FATIGUE-READS scenarios
    {id:"p_fr1",title:"Velocity Drop — 3 MPH Gone",diff:2,cat:"strategy",conceptTag:"pitcher-fatigue-reads",ageMin:12,ageMax:99,
      description:"You're 85 pitches into the game. Your fastball was sitting 88 mph in the first three innings, but now it's 85 mph. The hitters are starting to foul off pitches they were swinging through earlier. Runner on 1st, nobody out, up by 2.",
      situation:{inning:"Top 6",outs:0,count:"0-0",runners:[1],score:[4,2]},
      options:["Keep throwing fastballs — 85 mph is still enough to get outs","Lean on your off-speed pitches more — use the changeup and breaking ball to compensate","Try to overthrow to get your velocity back up to 88","Tell the coach your arm is dead and ask to come out"],
      best:1,explanations:["Pitching at 85 mph with a fastball that used to be 88 means hitters have an extra fraction of a second to see the ball. Pitches they were missing early in the game are now getting fouled off — the next step is hard contact. Continuing to rely on a diminished fastball is how tired pitchers give up late-inning runs.","When velocity drops, your off-speed becomes your best friend. A changeup at 76 mph off an 85 mph fastball still has a 9 mph speed differential — enough to disrupt timing. Your breaking ball still has its movement. The key is changing the hitter's eye level and speed expectations. Leaning on off-speed pitches conserves your arm for when you need a fastball in a key spot, and it keeps hitters from sitting on a pitch they can now time.","Trying to overthrow when fatigued leads to two problems: your mechanics break down (which causes the ball to flatten out or miss badly), and you accelerate the fatigue. Overthrowing trades command for velocity you can't sustain, and wild pitches or meatballs follow. Pitch smarter, not harder.","Your arm is not dead — you've lost 3 mph, which is normal fatigue. Asking to come out at 85 pitches with a 2-run lead sells your team short. You can still compete effectively by adjusting your approach — save the bullpen and pitch through the fatigue with your off-speed arsenal."],
      explSimple:["Your fastball lost speed, so hitters are catching up to it. You need to change something.","Use more off-speed pitches! Your changeup and breaking ball still have their movement, and the speed difference keeps hitters off balance.","Trying to throw harder when you're tired usually backfires — you'll lose control and throw bad pitches.","You don't need to come out. Losing 3 mph is normal. Adjust your pitch selection and keep competing."],
      rates:[25,85,20,35],concept:"When your fastball velocity drops from fatigue, lean on your off-speed arsenal — maintain the speed differential to keep hitters guessing",anim:"strike"},
    {id:"p_fr2",title:"Breaking Ball Losing Its Bite",diff:2,cat:"strategy",conceptTag:"pitcher-fatigue-reads",ageMin:12,ageMax:99,
      description:"Your curveball had great 12-to-6 break in the first three innings — hitters were chasing it in the dirt. Now in the 6th, your curve is hanging up in the zone and the last two were hit hard. Your fastball still feels decent. 1 out, nobody on.",
      situation:{inning:"Top 6",outs:1,count:"0-0",runners:[],score:[3,1]},
      options:["Keep throwing the curve — it'll come back if you focus on your mechanics","Shelve the curveball for now and rely on your fastball and changeup","Throw the curve harder to get more spin on it","Start aiming the curve lower to compensate for the reduced break"],
      best:1,explanations:["When a breaking ball loses its break, it's usually a fatigue signal — your wrist snap and arm speed are declining. Hoping it 'comes back' while throwing it in games means you're giving hitters hittable pitches in the zone. A hanging curveball is one of the easiest pitches to hit in baseball.","Your curveball is hanging because your arm is losing the snap it needs to generate that 12-to-6 break. Rather than throwing a pitch that's become hittable, remove it from your arsenal for the rest of the game and compete with what still works — your fastball and changeup. Two quality pitches are better than three mediocre ones. Your fastball still has its velocity, and your changeup speed differential is enough to keep hitters off balance.","Throwing the curve harder when your arm is fatigued is a recipe for injury. The wrist snap that creates curveball spin requires fine motor control, which deteriorates with fatigue. Adding effort to a tired arm produces inconsistent release points and flat breaking balls — or worse, arm strain.","Aiming the curve lower doesn't fix the mechanical issue. If the ball isn't breaking as much, starting it lower means it bounces in the dirt (ball) or starts in the zone and stays in the zone (hanging curve). You need break, not aim — and when you've lost the break, it's time to use other pitches."],
      explSimple:["When your curve stops breaking, throwing more of it just gives hitters easy pitches to hit.","Stop throwing the curveball and use your fastball and changeup instead. Two good pitches beat one bad one.","Throwing the curve harder when you're tired can hurt your arm and won't fix the problem.","Aiming lower doesn't add break to the pitch. If it's not breaking, use a different pitch."],
      rates:[25,80,20,40],concept:"When your breaking ball loses its bite from fatigue, shelve it and compete with your remaining pitches rather than throwing a hittable version",anim:"strike"},
    {id:"p_fr3",title:"Back-to-Back Walks After 5 Scoreless",diff:3,cat:"strategy",conceptTag:"pitcher-fatigue-reads",ageMin:13,ageMax:99,
      description:"You just walked 2 batters in a row after throwing 5 scoreless innings. Your pitch count is 92. You feel fine physically, but your last 8 pitches included 6 balls. Runners on 1st and 2nd, nobody out. Your coach visits the mound and asks how you feel.",
      situation:{inning:"Top 6",outs:0,count:"0-0",runners:[1,2],score:[3,0]},
      options:["Tell him you feel great and want to stay in — you've been dominant all game","Be honest — you feel okay physically, but your command has slipped and you might be losing focus from fatigue","Ask for one more batter to prove you can get out of it","Tell him to take you out — you're done"],
      best:1,explanations:["Saying you feel 'great' when you just walked two straight batters is denial. Your results are telling you something your body might not feel yet: your command is deteriorating. Pitchers often lose command before they lose velocity, and back-to-back walks after 5 scoreless is a classic fatigue signal. Being dishonest with your coach hurts the team.","Fatigue doesn't always show up as a tired arm. Mental fatigue — losing concentration on your release point, rushing your delivery, falling out of your mechanics — is just as real and just as damaging. Walking two batters after 5 scoreless at 92 pitches suggests your focus is fading even if your arm feels fine. Being honest with your coach lets him make the best decision for the team. He might leave you in with a shorter leash, or he might bring in a fresh arm. Either way, honesty gives the team the best chance.","Asking for 'one more batter' when you've already shown command problems puts the team in a worse position if that batter reaches base. Now you have bases loaded with nobody out, and the coach still has to make a pitching change from a worse situation. Trust the coaching staff to make the right call with honest information.","Volunteering to come out after 5 scoreless sells yourself short without giving the coach the full picture. You might have another inning in you with a mechanical adjustment. Let your coach make the decision based on honest feedback — he might keep you in, and that's his call to make."],
      explSimple:["Saying you feel great after two walks isn't honest. Your results show something is off even if your arm feels fine.","Be honest with your coach. You might be losing focus even if your arm is okay, and back-to-back walks prove something changed. Let him decide.","Asking for one more batter could make things worse if you walk him too. Trust your coach with honest info.","You might still have something left. Give your coach the truth and let him decide — don't make the decision for him."],
      rates:[25,80,35,25],concept:"Back-to-back walks after sustained success signal mental fatigue — command deteriorates before velocity, and honest self-assessment helps the team more than false confidence",anim:"walk"},
    // HITTER-TENDENCY-READS scenarios
    {id:"p_ht1",title:"Crowding the Plate — What It Tells You",diff:3,cat:"strategy",conceptTag:"hitter-tendency-reads",ageMin:13,ageMax:99,
      description:"The batter steps in and you notice he's crowding the plate and has choked up on the bat. He's a pull hitter with power, but right now he's set up differently than his first at-bat. Count is 0-0, runner on 2nd, 1 out.",
      situation:{inning:"Bot 4",outs:1,count:"0-0",runners:[2],score:[2,2]},
      options:["Throw inside — he's too close to the plate, jam him","Pitch away — he choked up to go the other way with the runner on 2nd","Start with a fastball middle-in to test if he's cheating inside","Throw a first-pitch breaking ball to catch him off guard"],
      best:1,explanations:["Throwing inside to a hitter who is crowding the plate seems logical, but consider WHY he moved closer. He may be trying to cover the outside corner — and now an inside pitch is right in his wheelhouse. Crowding the plate can be bait to get you to come inside where a pull hitter can turn on it. Falling for the bait is how you give up extra-base hits.","A pull hitter who chokes up and crowds the plate is signaling a situational adjustment. With a runner on 2nd and 1 out, he's trying to hit the ball to the right side to advance the runner to 3rd. Choking up shortens his swing for better contact, and crowding the plate helps him cover the outside corner. Pitching away takes the ball to the part of the zone where his shortened swing produces weak contact or ground balls to the left side — away from his pull power. You read his body language and adjusted.","Testing middle-in against a hitter who moved closer to the plate is risky with a runner on 2nd. If you miss even slightly over the plate, a pull hitter with power can drive it for extra bases. The situation calls for safe execution — work away and let him prove he can drive the ball the other way with his adjusted swing.","A first-pitch breaking ball might work occasionally, but it ignores the information his stance is giving you. Reading hitter adjustments is more valuable than pitch-type surprise. Pitch to the advantage his body language revealed — work the outside part of the zone."],
      explSimple:["Throwing inside to a hitter who crowded the plate might be exactly what he wants — he could be baiting you.","He choked up and moved closer to cover the outside pitch. Pitch away and make him prove he can hit it the other way with a shorter swing.","Going middle-in against a pull hitter who moved closer is risky — he's looking for something to pull.","Reading what his stance tells you is more useful than trying to surprise him with a breaking ball."],
      rates:[30,85,25,25],concept:"When a pull hitter chokes up and crowds the plate with a runner on 2nd, he's trying to go opposite field — pitch away and deny him the inside pitch he's abandoned",anim:"groundout"},
    {id:"p_ht2",title:"Open Front Foot — Exploiting the Tell",diff:3,cat:"strategy",conceptTag:"hitter-tendency-reads",ageMin:13,ageMax:99,
      description:"You noticed the hitter opens his front foot early during his stride — his toe points toward third base (for a right-handed hitter) before the ball arrives. He pulled a double off you last at-bat on an inside fastball. Count is 0-1, nobody on, 2 outs.",
      situation:{inning:"Top 5",outs:2,count:"0-1",runners:[],score:[2,3]},
      options:["Throw inside again — challenge him, he just got lucky","Throw a changeup or breaking ball away — his open foot commits him to pulling","Throw a high fastball — make him chase up in the zone","Throw at the same speed but move the ball to the other side of the plate"],
      best:1,explanations:["He already doubled on an inside fastball, and his open front foot means he's committed to turning on inside pitches. Throwing inside again plays directly into his strength — his body is already geared to rotate and pull. Challenging a hitter where he's strongest is stubbornness, not toughness.","When a hitter opens his front foot early, his hips and shoulders are already rotating toward the pull side before the pitch arrives. An off-speed pitch on the outer half exploits this perfectly: his body is committed to pulling, but the ball is going the opposite direction. The changeup's speed differential makes it even harder — he's out front AND reaching. His open foot turned him into a pull-only hitter, and you're pitching to the part of the zone he can't reach with that swing path.","A high fastball can work against some hitters, but an open-foot hitter is already generating lift in his swing from the early rotation. High fastballs and upward swing paths are a dangerous combination — it's how pull hitters hit home runs. Work low and away instead of high.","Moving to the other side of the plate with the same speed doesn't maximize the advantage. The speed differential is what makes the off-speed pitch devastating against an early-committing hitter. Same speed on the other side is better than inside, but the changeup or breaking ball creates a timing mismatch on top of the location mismatch."],
      explSimple:["He already hit an inside pitch for a double, and his front foot says he's looking to pull. Don't go inside again.","His open foot means his body is committed to pulling. A slower pitch on the outside half makes him reach and roll over weakly.","High fastballs to a hitter who's already rotating can end up as home runs. Go low and away instead.","Changing location is good, but changing speed AND location is even better against a hitter who's committing early."],
      rates:[20,85,30,35],concept:"When a hitter opens his front foot early, he's committed to pulling — off-speed pitches away exploit his inability to adjust mid-swing",anim:"groundout"},
    {id:"p_ht3",title:"3-for-3, All Opposite Field",diff:3,cat:"strategy",conceptTag:"hitter-tendency-reads",ageMin:13,ageMax:99,
      description:"This hitter is 3-for-3 today — all hits to the opposite field. He singled away, doubled away, and lined out to the opposite-field corner. He's clearly sitting on outside pitches and driving them. 4th AB, count is 0-0, runner on 1st, 1 out.",
      situation:{inning:"Bot 7",outs:1,count:"0-0",runners:[1],score:[3,4]},
      options:["Keep pitching away — make him prove he can keep doing it","Come inside with hard stuff — take away the outside pitch he's been crushing","Throw a breaking ball down and away — see if he chases below the zone","Mix locations randomly to keep him guessing"],
      best:1,explanations:["Pitching away to a hitter who is 3-for-3 going the other way is the definition of doing the same thing and expecting different results. He's proven three times today that he can handle outside pitches and drive them with authority. Continuing the same approach expects different results from a hitter who has already solved your plan.","Three opposite-field hits means this hitter has committed to staying back and driving the ball the other way. His approach is tuned to handle pitches on the outer half. Coming inside disrupts that plan completely — to hit an inside pitch, he has to pull his hands in and rotate, which is the opposite of the stay-back, go-with-it approach he's been using all day. An inside fastball forces him to change his swing entirely. Even if he fouls it off, you've planted doubt about going back to his opposite-field plan.","A breaking ball down and away is exactly the pitch an opposite-field hitter wants to see. He's staying back and going with pitches on the outer half — a breaking ball away with a slower speed gives him even MORE time to extend his arms and drive the ball. You'd be playing into his strength with an easier pitch to handle.","Random mixing without a strategic reason wastes your ability to exploit his tendency. You know he's committed to opposite field — randomness doesn't target that. Have a plan: attack inside to disrupt his approach, then use away as a surprise only after you've established the inside game."],
      explSimple:["He's 3-for-3 going the other way — pitching away is giving him what he wants.","Come inside! He's been staying back to hit outside pitches all day. An inside fastball forces a completely different swing.","A slow breaking ball away is the easiest pitch for an opposite-field hitter to handle. Don't go there.","Random pitching wastes the information his 3 hits gave you. Use that info — attack inside."],
      rates:[20,85,30,30],concept:"When a hitter is locked into an opposite-field approach, attack inside to force him to change his swing path and abandon his plan",anim:"strike"},
  ],
  batter: [
    {id:"b1", conceptTag:"situational-hitting",title:"RBI Opportunity",diff:1,cat:"situational",ageMin:6,ageMax:99,
      description:"Runner on 3rd, 1 out, down 2-1 in the 7th. He throws mostly fastballs. Infield at normal depth.",
      situation:{inning:"Bot 7",outs:1,count:"1-1",runners:[3],score:[1,2]},
      options:["Swing for the fences","Fly ball — sacrifice fly","Ground ball to the right side","Work a walk"],
      best:1,explanations:["Swinging for a homer is selfish here, which means you just need 1 run to tie.","A fly ball to the outfield scores the runner even if you're out, because with less than 2 outs the runner on 3rd can tag up and cross home plate after the catch. That ties the game — a productive out is just as valuable as a hit here.","Ground ball with infield at normal depth might get the runner thrown out at home.","Walking doesn't help with the tying run 90 feet away."],
      explSimple:["You don't need a home run — you just need to get the runner home to tie it up.","A fly ball lets the runner on third tag up and score. Even if you're out, the run counts!","A ground ball might let the other team throw the runner out at home.","A walk doesn't help because the runner on third still can't score from a walk."],
      rates:[25,85,45,30],concept:"With runner on 3rd, less than 2 outs: a fly ball is a productive out",anim:"flyout"},
    {id:"b2", conceptTag:"two-strike-approach",title:"Two-Strike Approach",diff:2,cat:"counts",ageMin:9,ageMax:99,
      description:"0-2 count, runner on 2nd, 2 outs. The pitcher's slider has been devastating today.",
      situation:{inning:"Bot 5",outs:2,count:"0-2",runners:[2],score:[3,4]},
      options:["Sit on the slider","Choke up and battle — protect the plate","Look fastball, react to off-speed","Surprise bunt"],
      best:1,explanations:["Guessing one pitch on 0-2 is a gamble.","Perfect! Choke up for bat control and a shorter swing, because fight off tough pitches until you get something hittable.","Sitting fastball when the slider is dominant means you'll chase.","Foul bunt with 2 strikes = strikeout, since game over."],
      explSimple:["Guessing one pitch with two strikes is too risky — you might guess wrong and strike out.","Great! Choke up on the bat and just try to make contact. Fight off tough pitches until you get a good one.","If the pitcher keeps throwing sliders, just looking for fastballs means you'll swing at bad pitches.","Be careful — if you try to bunt and it goes foul with two strikes, you're out!"],
      rates:[35,80,45,10],concept:"With 2 strikes, shorten your swing and focus on putting the ball in play",anim:"hit"},
    {id:"b3",title:"Hit and Run",diff:1,cat:"plays",conceptTag:"hit-and-run",ageMin:11,ageMax:99,
      description:"Coach gives the hit-and-run sign. Runner on 1st, 1 out, count 1-1.",
      situation:{inning:"Top 3",outs:1,count:"1-1",runners:[1],score:[1,1]},
      options:["Swing no matter what","Only swing if it's good","Bunt instead","Swing and pull for power"],
      best:0,explanations:["On a hit-and-run, the runner goes on the pitch, because you MUST swing to protect him.","You can't be selective — the runner is committed and will be thrown out.","The sign was hit-and-run, not bunt — don't change the play.","On hit-and-run, just make solid contact — pulling for power risks strikeouts and leaves the runner exposed for a caught stealing."],
      explSimple:["On a hit-and-run, you HAVE to swing because the runner is already running. If you don't swing, he could get thrown out.","You can't wait for a good pitch — the runner is counting on you to swing!","The coach said hit-and-run, not bunt. Do what the coach says.","Just try to hit the ball — you don't need to hit it hard, just make contact."],
      rates:[85,30,40,20],concept:"On a hit-and-run, your job is to swing and make contact — protect the runner",anim:"hit"},
    {id:"b4", conceptTag:"situational-hitting",title:"Smart Aggression",diff:2,cat:"approach",ageMin:9,ageMax:99,
      description:"It's your first at-bat and you're feeling out the pitcher. First pitch is a fastball right down the middle.",
      situation:{inning:"Top 1",outs:0,count:"0-0",runners:[],score:[0,0]},
      options:["Take it — see what he has","Swing — be aggressive on strikes","Bunt for a hit","Take until you get a strike"],
      best:1,explanations:["Seeing pitches is nice, but a meatball down the middle is the most hittable pitch you'll see, which means being patient doesn't mean taking every pitch — it means being ready when you get your pitch.","Smart aggression! MLB hitters who swing at first-pitch strikes bat .340+, because being selectively aggressive means pouncing on hittable pitches in the zone.","Bunting a meatball wastes a gift, since you think about what gives your team the best result here.","That IS a strike, because you're already in trouble at 0-1. Being patient means waiting for YOUR pitch, not watching strikes go by."],
      explSimple:["Watching pitches is fine, but if the ball is right down the middle, you should swing!","Yes! If the pitch is right there to hit, go for it. A good hitter swings at good pitches.","Bunting a pitch that's easy to hit is a waste. Swing away!","That pitch was already a strike. Now you're behind in the count."],
      rates:[45,85,30,35],concept:"Be selectively aggressive — attack hittable pitches in the zone",anim:"hit"},
    {id:"b5", conceptTag:"situational-hitting",title:"Advancing the Runner",diff:1,cat:"situational",ageMin:6,ageMax:99,
      description:"Runner on 2nd, nobody out, tie game in the 7th. You're a #2 hitter with good contact.",
      situation:{inning:"Bot 7",outs:0,count:"0-0",runners:[2],score:[3,3]},
      options:["Pull for extra bases","Hit to the right side","Bunt him to 3rd","Swing for the fences"],
      best:1,explanations:["Pulling doesn't reliably advance the runner — a smarter approach at the plate would give you a better chance of helping your team.","Hitting right side moves him to 3rd, which means from there he scores on a sac fly, wild pitch, or groundout.","Bunting is okay but a hit to the right side moves him AND potentially gets you on base, since it gives you the best chance of success.","Ignores the situation entirely, because you think about what gives your team the best result here."],
      explSimple:["Pulling the ball to the left side doesn't help the runner move to third.","Hit the ball to the right side! That moves the runner to third, where he can score really easily.","A bunt is okay, but hitting to the right side is even better because you might get on base too.","Swinging for the fences ignores the runner — your job is to help the team score."],
      rates:[30,85,60,15],concept:"Moving runners to 3rd with 0 outs creates multiple ways to score",anim:"hit"},
    {id:"b6", conceptTag:"count-leverage",title:"Hitter's Count",diff:2,cat:"counts",ageMin:9,ageMax:99,
      description:"Bases loaded, 2 outs, down by 1. Count is 3-1. Pitcher has been wild.",
      situation:{inning:"Bot 8",outs:2,count:"3-1",runners:[1,2,3],score:[4,5]},
      options:["Take — a walk ties the game","Swing only at YOUR pitch","Swing at anything close","Grand slam swing"],
      best:1,explanations:["What if it's a perfect strike? Now you're 3-2 and defending instead of attacking.","3-1 is the best hitter's count — only swing at YOUR pitch, and if it's not perfect, take ball four.","Swinging at mediocre pitches throws away the 3-1 advantage — wait for your pitch or force a walk.","Grand slam swings change your mechanics and lead to whiffs — just trust your normal swing."],
      explSimple:["What if it's a great pitch to hit? You'd miss your chance by just watching.","This is YOUR count! Only swing if the pitch is perfect for you. If it's not great, take ball four and walk.","Swinging at anything wastes the advantage — be patient and wait for your pitch.","Trying to crush it changes your swing. Just swing normal and hit it hard."],
      rates:[50,85,35,20],concept:"3-1 is a hitter's count — swing only at YOUR pitch",anim:"hit"},
    {id:"b7", conceptTag:"situational-hitting",title:"Going Opposite Field",diff:2,cat:"adjustments",ageMin:9,ageMax:99,
      description:"Pitcher keeps throwing outside. You've fouled off 3 pitches. Count 1-2. Runner on 1st.",
      situation:{inning:"Top 5",outs:1,count:"1-2",runners:[1],score:[2,2]},
      options:["Normal swing — he'll come inside","Go with the pitch — opposite field","Step closer to the plate","Bunt"],
      best:1,explanations:["If it's working, he won't change — you need to adjust your approach.","Smart! When the pitcher works outside, drive it the other way. The best hitters go with the pitch instead of fighting it.","Moving in the box doesn't fix your swing approach.","Bunting with 2 strikes risks a foul-bunt strikeout — a foul bunt on strike two is an automatic out."],
      explSimple:["The pitcher keeps throwing outside because it's working. You need to change, not him.","Smart! If the pitch is on the outside, hit it the other way. Don't fight it — go with it.","Moving closer to the plate doesn't help if you're still swinging the same way.","Bunting with two strikes is dangerous because a foul bunt means you're out."],
      rates:[25,85,50,20],concept:"When the pitcher works away, go with it to the opposite field",anim:"hit"},
    {id:"b8", conceptTag:"situational-hitting",title:"Cold Off the Bench",diff:3,cat:"pressure",ageMin:12,ageMax:99,
      description:"Pinch hitting, bottom 9th, runner on 2nd, 2 outs, down by 1. You haven't batted all game. He throws 95.",
      situation:{inning:"Bot 9",outs:2,count:"0-0",runners:[2],score:[4,3]},
      options:["Take the first pitch to time his speed","Swing if it's hittable","Ambush a specific pitch","Bunt"],
      best:0,explanations:["Coming in cold against 95mph, you need to time him, because taking one pitch gives you a read on his velocity and movement. But stay ready — if he grooves one, be prepared to adjust.","Your timing will be off against 95mph without any at-bats, since it's a close call, but seeing one pitch helps more than it hurts.","Ambushing requires locked-in timing you don't have yet, because you think about what gives your team the best result here.","Bunting with 2 outs and a runner on 2nd makes no sense — think about what gives your team the best result here."],
      rates:[70,60,45,5],concept:"As a pinch hitter, taking the first pitch to time the pitcher's velocity is usually smart — but stay ready",anim:"strike"},
    {id:"b9", conceptTag:"situational-hitting",title:"Infield Playing In",diff:2,cat:"situational",ageMin:9,ageMax:99,
      description:"Runner on 3rd, 1 out. Infield drawn in. Count 2-2.",
      situation:{inning:"Bot 6",outs:1,count:"2-2",runners:[3],score:[2,3]},
      options:["Fly ball to score the runner","Hard grounder","Hit over the infield","Ground ball anywhere"],
      best:0,explanations:["With infield in, ground balls are more likely fielded, which means a fly ball scores the runner on a tag-up.","Infield in means they're positioned to throw the runner out at home.","Trying to hit over them changes your swing.","Ground ball contact is what the drawn-in defense wants."],
      explSimple:["A fly ball is great because the runner can tag up from third and score!","The infield is playing close, so a grounder lets them throw the runner out at home.","Trying to hit it over their heads changes your swing and makes it harder to hit.","A ground ball is exactly what the defense wants when they're playing in close."],
      rates:[80,35,40,30],concept:"When the infield plays in, fly balls are more valuable than ground balls",anim:"flyout"},
    {id:"b10", conceptTag:"situational-hitting",title:"After a Teammate's Homer",diff:1,cat:"approach",ageMin:6,ageMax:99,
      description:"Teammate just went deep. Pitcher walked the last batter on 4 pitches. He's rattled. Stadium is rocking.",
      situation:{inning:"Bot 5",outs:1,count:"0-0",runners:[1],score:[5,3]},
      options:["Swing first pitch — keep pressure","Take pitches — let him struggle","Look for YOUR pitch","Pull for another homer"],
      best:2,explanations:["Swinging at anything can bail him out with a cheap out.","Too patient — lets the pitcher reset and breathe, which means the outcome won't be what you need.","When a pitcher is rattled, wait for your pitch and drive it.","Trying to hit homers changes your swing mechanics, causing strikeouts — just hit your pitch hard naturally."],
      explSimple:["Swinging at everything helps the pitcher because you might get out on a bad pitch.","Being too patient gives the pitcher time to calm down and get back on track.","The pitcher looks nervous! Wait for a good pitch and hit it hard.","Trying to hit a home run changes how you swing. Just hit the ball well."],
      rates:[45,30,85,25],concept:"When a pitcher is struggling, look for YOUR pitch — don't bail him out",anim:"hit"},
    {id:"b11", conceptTag:"pitch-sequencing",title:"First At-Bat Data",diff:2,cat:"adjustments",ageMin:9,ageMax:99,
      description:"2nd at-bat against this pitcher. First time he struck you out on 3 straight sliders. What's different now?",
      situation:{inning:"Top 4",outs:0,count:"0-0",runners:[],score:[1,2]},
      options:["Sit slider — he'll start with it again","Look fastball, react to slider","Swing at the first pitch before he sets up","Crowd the plate"],
      best:1,explanations:["He knows you saw 3 sliders, so a smart pitcher will mix it up the 2nd time and start with something different.","Right! Look for the fastball but stay ready for the slider — if he goes back to the slider, your first at-bat prepared you to recognize it. This two-pitch plan covers both scenarios.","You learned he throws sliders from that first at-bat — use that info to prepare your approach, not throw it away by hacking at pitch one.","Crowding the plate does not help you hit sliders — they break away from you regardless of where you stand in the box."],
      explSimple:["He threw you sliders last time, so he might throw something different now. Don't just look for one pitch.","Smart! Look for a fastball but be ready for the slider too. You learned from last time!","Swinging at the first pitch doesn't use what you learned from your first at-bat.","Moving closer to the plate doesn't help you hit better."],
      rates:[40,85,35,30],concept:"Use your first at-bat to gather data — adjust in the second at-bat",anim:"hit"},
    {id:"b12", conceptTag:"two-strike-approach",title:"Down to the Last Strike",diff:3,cat:"pressure",ageMin:12,ageMax:99,
      description:"Bottom 9th, 2 outs, down by 2. Runners on 1st and 2nd. Count is 2-2. You represent the tying run at the plate.",
      situation:{inning:"Bot 9",outs:2,count:"2-2",runners:[1,2],score:[3,5]},
      options:["Swing hard — need a big hit","Shorten up and put the ball in play","Sit on one pitch and guess right","Take — pray for a walk"],
      best:1,explanations:["Overswinging with 2 strikes leads to strikeouts, and a strikeout here ends the game.","In elimination situations, shorten your swing and find a way to keep the at-bat alive — contact creates chaos, and anything can happen once the ball is in play.","Guessing wrong on one pitch ends your season — with 2 strikes, you cannot afford to commit to a single pitch type.","A walk only loads the bases, and you still need a hit to actually score the runs. Put the ball in play."],
      rates:[25,80,35,30],concept:"With your back against the wall, shorten up and make contact — keep the line moving",anim:"hit"},
    {id:"b13", conceptTag:"situational-hitting",title:"Which Pitch to Expect",diff:1,cat:"basic",ageMin:6,ageMax:99,
      description:"You're a young batter stepping up to the plate for the first time in the game. You don't know anything about this pitcher yet. What should you look for?",
      situation:{inning:"Top 1",outs:0,count:"0-0",runners:[],score:[0,0]},
      options:["Look for a fastball — most pitchers throw fastballs first","Close your eyes and swing hard","Wait for a slow pitch — they're easier to hit","Guess curveball"],
      best:0,explanations:["Most pitchers throw fastballs 60%+ of the time, so until you see what a pitcher has, look for the most common pitch — the fastball. Be ready to hit it!","Never close your eyes! Watch the ball all the way from the pitcher's hand to the plate.","You cannot control what the pitcher throws, so be ready for the most likely pitch instead of hoping for a specific one.","Guessing curveball on the first pitch you ever see from a pitcher is too specific — you have no idea what this guy throws yet."],
      rates:[85,20,40,25],concept:"Look fastball first — it's the most common pitch. React to everything else",explSimple:["Great choice! Most pitchers throw fastballs early in the count — look for it first and react to everything else.","Not the best move. Never close your eyes! Watch the ball all the way.","Not the best move. You can't control what the pitcher throws.","Not the best move. Guessing curveball on the first pitch you ever see from a pitcher is too specific."], anim:"hit"},
    // Batch 1 — Situational Hitting
    {id:"b14", conceptTag:"situational-hitting",title:"Runner on Third — Make Contact",diff:1,cat:"situational",ageMin:6,ageMax:99,
      description:"Top of the 5th, runner on 3rd, 1 out. Score tied 2-2. Count is 1-0. He throws mostly fastballs and the infield is at normal depth.",
      situation:{inning:"Top 5",outs:1,count:"1-0",runners:[3],score:[2,2]},
      options:["Hit a fly ball to the outfield","Swing for a home run","Bunt the runner home","Strike out looking — don't risk a double play"],
      best:0,explanations:["With a runner on 3rd and less than 2 outs, a fly ball to the outfield scores the run even if you make an out. That's called a sacrifice fly — one of the most productive outs in baseball.","Swinging for the fences changes your mechanics and often leads to strikeouts — you just need to get the run home.","Bunting with the infield at normal depth is risky — because the catcher or pitcher could throw the runner out at home.","Striking out helps nobody, which means you have a chance to drive in the tying run!"],
      rates:[85,25,35,10],concept:"With a runner on 3rd and less than 2 outs, a fly ball is the most productive play",explSimple:["Great choice! With a runner on 3rd and less than 2 outs, a fly ball scores the run on a sacrifice fly.","Not the best move. Swinging for the fences changes your mechanics and often leads to strikeouts.","Not the best move. Bunting with the infield at normal depth is risky — the catcher or pitcher could.","Not the best move. Striking out helps nobody."], anim:"flyout"},
    {id:"b15", conceptTag:"situational-hitting",title:"Move the Runner Over",diff:1,cat:"situational",ageMin:6,ageMax:99,
      description:"Bottom of the 6th, runner on 2nd, nobody out, your team is up 3-2. You're the #2 hitter and a good contact guy. Count is 0-0.",
      situation:{inning:"Bot 6",outs:0,count:"0-0",runners:[2],score:[3,2]},
      options:["Hit to the right side to move the runner to 3rd","Pull the ball to left field for extra bases","Bunt the runner to 3rd","Swing hard — try to drive him in right now"],
      best:0,explanations:["Hitting to the right side moves the runner to 3rd with one out, because from 3rd, he can score on a sac fly, wild pitch, passed ball, or groundout. You create many ways to score!","Pulling the ball doesn't reliably advance the runner, and ground balls to the left side can leave him stranded at 2nd, since that's why this approach matters in this situation.","Bunting is decent, but a ground ball to the right side moves the runner AND gives you a chance to reach base safely, since as two for one!","Swinging hard often leads to strikeouts or pop-ups, since you play the percentages and move the runner."],
      rates:[85,30,50,25],concept:"With a runner on 2nd and nobody out, hitting to the right side advances him to 3rd",explSimple:["Great choice! Hitting to the right side moves the runner to 3rd with one out.","Not the best move. Pulling the ball doesn't reliably advance the runner, and ground balls to the left side.","Not the best move. Bunting is decent, but a ground ball to the right side moves the runner.","Not the best move. Swinging hard often leads to strikeouts or pop-ups."], anim:"hit"},
    {id:"b16", conceptTag:"situational-hitting",title:"Leading Off an Inning",diff:1,cat:"situational",ageMin:6,ageMax:99,
      description:"Top of the 3rd, score is 0-1 — you're trailing. You're the leadoff hitter starting the inning. Nobody on, nobody out. The pitcher's been sharp — only 1 hit so far.",
      situation:{inning:"Top 3",outs:0,count:"0-0",runners:[],score:[0,1]},
      options:["Work the count — see pitches and get on base","Swing at the first pitch to catch him off guard","Bunt for a hit to get something started","Swing for the fences — a homer ties it"],
      best:0,explanations:["As a leadoff hitter, your #1 job is getting on base. See some pitches, work the count, and look for a walk or a good pitch to hit. Getting on base starts rallies! Working the count doesn't mean taking every pitch — it means being patient but ready when you get your pitch.","First-pitch swinging can work, especially if you spot a pitch in your zone. Against a sharp pitcher though, seeing a pitch or two first helps you find his patterns.","Bunting when the defense isn't expecting it can work, but it's low-percentage as a first choice, because you working the count gives you more options.","Swinging for the fences as the leadoff hitter is selfish, since you get on base and let your teammates drive you in."],
      rates:[75,60,35,15],concept:"Leadoff hitters start rallies — get on base any way you can",explSimple:["Great choice! As a leadoff hitter, your #1 job is getting on base.","Not the best move. First-pitch swinging can work, especially if you spot a pitch in your zone.","Not the best move. Bunting when the defense isn't expecting it can work, but it's low-percentage as a first choice.","Not the best move. Swinging for the fences as the leadoff hitter is selfish."], anim:"walk"},
    {id:"b17", conceptTag:"situational-hitting",title:"Infield In — Fly or Ground?",diff:2,cat:"situational",ageMin:9,ageMax:99,
      description:"Bot 7th, runner on 3rd, 1 out, tied 4-4. Infield is playing in to cut off the run at home. Count is 1-1 against a sinkerball pitcher.",
      situation:{inning:"Bot 7",outs:1,count:"1-1",runners:[3],score:[4,4]},
      options:["Try to lift a fly ball to the outfield","Hit a hard grounder through the drawn-in infield","Bunt — surprise the defense","Swing for the fences to win it with a homer"],
      best:0,explanations:["When the infield plays in, a fly ball to the outfield scores the runner on a sacrifice fly — even if you're out. It's the highest-percentage play with 1 out.","The infield is drawn in specifically to throw the runner out on grounders, which means even hard grounders give them a play at home.","A bunt against a drawn-in infield is dangerous — given that the fielders are already close and can throw the runner out at home.","Swinging for the fences changes your swing and often leads to strikeouts, because a simple fly ball wins here."],
      rates:[85,35,20,15],concept:"Against a drawn-in infield, fly balls beat ground balls — the runner scores on a sac fly",explSimple:["When the infield plays in, a fly ball to the outfield scores the runner on a sacrifice fly — even if you're out.","The infield is drawn in specifically to throw the runner out on grounders.","A bunt against a drawn-in infield is dangerous — the fielders are already close and can throw the runner out at home.","Swinging for the fences changes your swing and often leads to strikeouts."],anim:"flyout"},
    {id:"b18", conceptTag:"hit-and-run",title:"First and Third — Hit and Run?",diff:2,cat:"situational",ageMin:9,ageMax:99,
      description:"Top of the 4th, runners on 1st and 3rd, 1 out. Score is 3-1 you're winning. Count is 1-0. Coach flashes the hit-and-run sign. The runner on 1st will be going.",
      situation:{inning:"Top 4",outs:1,count:"1-0",runners:[1,3],score:[1,3]},
      options:["Swing at anything — protect the runner","Only swing if it's a strike","Try to hit behind the runner to the right side","Pull for a double to score both runners"],
      best:0,explanations:["On a hit-and-run, the runner on first is sprinting toward second as the pitch is thrown. If you don't swing, the catcher catches the ball cleanly and has an easy throw to nail the runner — he's a sitting duck halfway between bases. You MUST swing to protect him, even if the pitch is bad, because contact of any kind disrupts the throw.","Being selective defeats the purpose of the hit-and-run. The whole play is designed so the runner goes, the shortstop or second baseman moves to cover the bag (opening a hole in the infield), and your swing puts the ball through that gap. If you take the pitch, you get none of those benefits and the runner gets thrown out.","Hitting to the right side is a bonus if the pitch allows it, but the first priority is making contact — any contact. Even a foul ball keeps the runner safe because the catcher can't throw on a foul. The runner is already committed, so contact is your #1 job, and location is secondary.","Pulling for power means taking a bigger swing, which increases your chance of a strikeout. On a hit-and-run, a strikeout is the worst possible outcome — you miss the ball AND the runner gets thrown out for a double play. Shorten your swing and put the ball in play."],
      rates:[85,20,55,25],concept:"On a hit-and-run, swing at anything — the runner is committed and needs your protection",explSimple:["On a hit-and-run, the runner is committed.","Being selective defeats the purpose.","Hitting to the right side is nice if you can, but the priority is making contact — any contact.","Pulling for power changes your mechanics and increases strikeout risk."],anim:"hit"},
    {id:"b19", conceptTag:"count-leverage",title:"Trailing by One, Runner in Scoring Position",diff:2,cat:"situational",ageMin:9,ageMax:99,
      description:"Bot 8th, runner on 2nd, 2 outs, down 5-4. You're facing a reliever who throws hard but has been missing his spots. Count is 2-1.",
      situation:{inning:"Bot 8",outs:2,count:"2-1",runners:[2],score:[4,5]},
      options:["Look for YOUR pitch — be patient but ready","Swing at the next pitch — be aggressive","Take all the way — work toward a walk","Choke up and just make contact"],
      best:0,explanations:["With a 2-1 count against a wild reliever, you're in the driver's seat, since you wait for your pitch — a fastball in your zone — and drive it. Don't chase his mistakes, but be ready to attack a hittable pitch.","Being too aggressive on 2-1 can bail him out, because he's struggling with control — let him come to you.","A walk puts runners on 1st and 2nd, but you still need a hit — with 2 outs, looking for your pitch to drive in the run is better than a walk.","Choking up isn't necessary on 2-1, which means you have the count advantage — use it to look for a pitch you can drive."],
      rates:[85,40,45,35],concept:"With a hitter's count against a wild pitcher, be patient — wait for your pitch and drive it",explSimple:["With a 2-1 count against a wild reliever, you're in the driver's seat.","Being too aggressive on 2-1 can bail him out.","A walk puts runners on 1st and 2nd, but you still need a hit.","Choking up isn't necessary on 2-1."],anim:"hit"},
    {id:"b20", conceptTag:"situational-hitting",title:"Bunt or Swing — Tie Game",diff:2,cat:"situational",ageMin:9,ageMax:99,
      description:"Bot 6th, runner on 2nd, nobody out, tied 3-3. You're the #7 hitter, decent contact but not much power. The pitcher has been tough all day. Count 0-0.",
      situation:{inning:"Bot 6",outs:0,count:"0-0",runners:[2],score:[3,3]},
      options:["Bunt him to 3rd — play for one run","Hit to the right side — advance him and maybe reach base","Swing away — try to drive him in yourself","Take pitches and hope for a walk"],
      best:1,explanations:["Bunting is okay, but it gives away an out for free, because there's a better option that moves the runner AND keeps you alive.","Hitting to the right side moves the runner to 3rd AND gives you a chance to reach base, since it's the best of both worlds — you advance the runner without giving up an out automatically.","Swinging away against a tough pitcher with no power isn't the highest-percentage play, because you play smart baseball.","Taking pitches is too passive — with nobody out and a runner on 2nd, you want to be aggressive with a purpose."],
      rates:[55,85,30,25],concept:"Hit to the right side — advance the runner without giving up an out for free",explSimple:["Bunting is okay, but it gives away an out for free.","Hitting to the right side moves the runner to 3rd AND gives you a chance to reach base.","Swinging away against a tough pitcher with no power isn't the highest-smart play.","Taking pitches is too passive."],anim:"hit"},
    {id:"b21", conceptTag:"situational-hitting",title:"Down by One in the 9th",diff:3,cat:"situational",ageMin:12,ageMax:99,
      description:"Bot 9th, runner on 3rd, 1 out, down 6-5. Their closer is on the mound throwing 96. Count is 0-1. A fly ball ties it. A hit wins it.",
      situation:{inning:"Bot 9",outs:1,count:"0-1",runners:[3],score:[5,6]},
      options:["Fly ball approach — just tie the game","Look for a pitch to drive — win the game","Take pitches — work the count back","Squeeze bunt — surprise the closer"],
      best:0,explanations:["A fly ball to the outfield ties the game on a sacrifice fly, which means you take the pressure off and give your team extra innings to win. That's the smart play because tying the game first eliminates the risk of losing. If you go for a hero swing, a strikeout or weak grounder wastes the runner on third.","Trying to drive a 96-mph closer is tempting, but swinging hard against elite velocity often leads to swings and misses because the margin for error is so tiny. A fly ball approach has a much higher success rate since even routine contact can score the runner from third.","Taking pitches to work the count sounds patient, but at 0-1 against a closer who throws 96, getting deeper into the count gives him more chances to blow you away. Since you only need a fly ball to tie it, being too passive risks falling behind 0-2 where you have almost no chance.","Squeeze bunting against a 96-mph closer is extremely risky because the pitch arrives so fast that timing the bunt is nearly impossible. If you miss or foul it off, the runner is hung out to dry — otherwise a simple fly ball ties it with much less risk."],
      rates:[85,40,25,15],concept:"Tie the game first — a sacrifice fly is worth more than a hero swing in the 9th",anim:"flyout"},
    {id:"b22", conceptTag:"situational-hitting",title:"Bases Loaded, Nobody Out",diff:3,cat:"situational",ageMin:12,ageMax:99,
      description:"Top of the 3rd, bases loaded, nobody out. Your team is up 2-0. Count is 1-0. The pitcher looks rattled — he just walked the last two batters.",
      situation:{inning:"Top 3",outs:0,count:"1-0",runners:[1,2,3],score:[0,2]},
      options:["Swing for a grand slam — blow the game open","Put the ball in play — any hit scores runs","Be patient — another walk forces a run in","Look for your pitch — something you can drive hard"],
      best:3,explanations:["Swinging for the fences changes your mechanics and often leads to pop-ups or strikeouts, which means you don't need a grand slam — any solid contact scores runs.","Just putting the ball in play is okay, but you can be smarter, because with 1-0 against a rattled pitcher, you'll likely get a hittable pitch.","Waiting for a walk is too passive, since you're ahead 1-0 and he's rattled — he's likely to throw a strike to avoid another free pass. Be ready for it!","With bases loaded, 1-0 count, and a rattled pitcher, you'll see a hittable pitch, because you look for YOUR pitch — a fastball in your zone — and drive it into the gap. Hard contact with the bases loaded is devastating."],
      rates:[20,50,40,85],concept:"Bases loaded with a rattled pitcher — look for your pitch and drive it. Don't try to do too much",anim:"hit"},
    {id:"b23", conceptTag:"count-leverage",title:"Wild Pitcher — Be Patient",diff:3,cat:"situational",ageMin:12,ageMax:99,
      description:"Bot 4th, runner on 1st, nobody out, tied 1-1. The pitcher has walked 3 batters already and just threw 2 balls to start your at-bat. Count 2-0.",
      situation:{inning:"Bot 4",outs:0,count:"2-0",runners:[1],score:[1,1]},
      options:["Take pitches — let the runner steal while he walks you","Swing at the next pitch — crush a mistake","Look for your pitch — if it's perfect, drive it","Bunt the runner to 2nd"],
      best:2,explanations:["Being completely passive wastes a great count — if he throws a 2-0 fastball right down the middle, you want to be ready for it. But you also don't need to chase bad pitches.","Swinging at anything on 2-0 is too aggressive, which means what if it's another ball? Then you're 3-0 and practically on base.","Smart! On 2-0, look for one specific pitch — a fastball in your happy zone. If you get it, drive it. If not, take it to 3-0 and you're almost guaranteed to reach base. This combines patience with aggression.","Bunting on 2-0 against a wild pitcher gives away all your advantage, because he might walk you without you lifting the bat!"],
      rates:[45,30,85,10],concept:"Against a wild pitcher, be selectively aggressive — wait for YOUR pitch on hitter's counts",anim:"hit"},
    // Batch 2 — Count Management
    {id:"b24", conceptTag:"count-leverage",title:"The 3-0 Take",diff:1,cat:"counts",ageMin:6,ageMax:99,
      description:"Bot 3rd, nobody on, 1 out, score is 2-1. Count is 3-0. The pitcher has been wild — you haven't swung once this at-bat.",
      situation:{inning:"Bot 3",outs:1,count:"3-0",runners:[],score:[2,1]},
      options:["Take the pitch — a walk is almost guaranteed","Swing if it's a fastball down the middle","Swing hard — he has to throw a strike","Foul one off to get your timing down"],
      best:0,explanations:["At 3-0, the pitcher must throw a strike or walk you, since the best play for most hitters is to take the pitch. If it's a ball, you walk. If it's a strike, you're still ahead 3-1 — the best hitter's count in baseball.","Only elite hitters with the coach's green light should swing 3-0, because for most young players, taking is the smart play.","Swinging hard at 3-0 is selfish — you're one ball away from a free base. Don't bail the pitcher out.","Intentionally fouling a pitch on 3-0 wastes a free base opportunity — the walk is more valuable than getting comfortable."],
      rates:[85,45,20,10],concept:"At 3-0, take the pitch — a walk is almost certain and you're ahead no matter what",explSimple:["Great choice! At 3-0, the pitcher must throw a strike or walk you.","Not the best move. Only elite hitters with the coach's green light should swing 3-0.","Not the best move. Swinging hard at 3-0 is selfish.","Not the best move. Fouling a pitch on 3-0 wastes a free base opportunity."], anim:"walk"},
    {id:"b25", conceptTag:"two-strike-approach",title:"Behind 0-2 — Survival Mode",diff:1,cat:"counts",ageMin:6,ageMax:99,
      description:"Top of the 4th, nobody on, 0 outs. The pitcher just threw two perfect strikes and you're behind 0-2. He's got a nasty slider.",
      situation:{inning:"Top 4",outs:0,count:"0-2",runners:[],score:[1,1]},
      options:["Choke up and protect the plate — foul off tough pitches","Sit on the slider and crush it","Swing hard — show him you're not scared","Take the next pitch and hope it's a ball"],
      best:0,explanations:["Down 0-2, your job changes from hitting to surviving, because choke up, shorten your swing, and fight off anything close. Foul off tough pitches until you get something you can handle. Hitters who battle back from 0-2 earn respect.","Guessing one pitch on 0-2 is risky, since if he throws a fastball instead, you're frozen for strike three.","Swinging hard with 2 strikes leads to big swings and misses, because shorten up and make contact.","Just watching a pitch on 0-2 is dangerous — if it catches the corner, you're out looking — be ready to fight."],
      rates:[85,30,15,40],concept:"With 2 strikes, shorten your swing, protect the plate, and battle — make the pitcher work",explSimple:["Great choice! Down 0-2, your job changes from hitting to surviving.","Not the best move. Guessing one pitch on 0-2 is risky.","Not the best move. Swinging hard with 2 strikes leads to big swings and misses.","Not the best move. Just watching a pitch on 0-2 is dangerous — if it catches the corner, you're out."], anim:"strike"},
    {id:"b26", conceptTag:"count-leverage",title:"Ahead 2-0 — Your Count",diff:1,cat:"counts",ageMin:6,ageMax:99,
      description:"Bot 5th, runner on 2nd, 1 out, up 4-2. Count is 2-0. The pitcher threw two fastballs that missed. What are you looking for?",
      situation:{inning:"Bot 5",outs:1,count:"2-0",runners:[2],score:[4,2]},
      options:["Look for a fastball in your zone — be ready to drive it","Take the pitch — get to 3-0","Swing at anything — he has to throw strikes","Bunt to advance the runner"],
      best:0,explanations:["2-0 is a great hitter's count! The pitcher must throw a strike, and fastballs are the most common pitch on 2-0, which means zone in on a fastball in your happy zone and be ready to drive it. If it's not there, take it.","Taking to 3-0 isn't bad, but 2-0 is actually a better count to hit in because pitchers throw more hittable pitches. Don't waste it!","Swinging at anything wastes your count advantage, because be selective — only swing at YOUR pitch.","Bunting on 2-0 gives away a huge advantage, since the pitcher is behind and you're in control."],
      rates:[85,50,30,10],concept:"On 2-0, look for a fastball in your zone — it's one of the best counts to hit in",explSimple:["Great choice! 2-0 is a great hitter's count! The pitcher needs to throw a strike, and fastballs.","Not the best move. Taking to 3-0 isn't bad, but 2-0 is actually a better count to hit.","Not the best move. Swinging at anything wastes your count advantage.","Not the best move. Bunting on 2-0 gives away a huge advantage."], anim:"hit"},
    {id:"b27", conceptTag:"situational-hitting",title:"First Pitch — Swing or Take?",diff:2,cat:"counts",ageMin:9,ageMax:99,
      description:"Top of the 2nd, nobody on, 0 outs. First pitch of your at-bat. You've watched this pitcher from the bench — he throws a first-pitch fastball 80% of the time.",
      situation:{inning:"Top 2",outs:0,count:"0-0",runners:[],score:[0,0]},
      options:["Take the first pitch — see his stuff up close","Swing if it's a fastball in your zone","Swing at the first pitch no matter what","Fake bunt to see how the defense reacts"],
      best:1,explanations:["Taking isn't bad for your first at-bat, but you know he throws first-pitch fastballs 80% of the time, because that's valuable info you're wasting.","You did your homework! If he throws a first-pitch fastball 80% of the time, be ready for it — if it's in your zone, drive it. If not, take it. Using data makes you a smart hitter.","Swinging at anything regardless of location is reckless, which means be aggressive but selective.","Fake bunting on the first pitch gives away information about yourself without gaining much."],
      rates:[45,85,25,15],concept:"Use what you learn from the bench — if you know what's coming, be ready for it",explSimple:["Taking isn't bad for your first at-bat, but you know he throws first-pitch fastballs 80% of the time.","You did your homework!","Swinging at anything regardless of location is reckless.","Fake bunting on the first pitch gives away information about yourself without gaining much."],anim:"hit"},
    {id:"b28", conceptTag:"count-leverage",title:"1-0 After a Close Call",diff:2,cat:"counts",ageMin:9,ageMax:99,
      description:"Bot 6th, runner on 1st, nobody out, tied 3-3. The pitcher just missed with a fastball on the corner — ump called it ball one. Count is 1-0.",
      situation:{inning:"Bot 6",outs:0,count:"1-0",runners:[1],score:[3,3]},
      options:["Get aggressive — jump on the next pitch","Stay patient — work the count deeper","Look for your pitch — if it's perfect, drive it","Take the next pitch to see if the ump's zone is small"],
      best:2,explanations:["Being too aggressive on 1-0 can lead to weak contact, because the count is slightly in your favor, but you don't need to chase.","Being too patient wastes your slight advantage, since the pitcher just barely missed — he's going to come back with a strike.","At 1-0, you have the luxury of being selective. Look for one pitch in one location — your best zone. If you get it, drive it. If not, take it to 2-0 and you're in great shape either way.","The ump's zone doesn't matter to your approach, because you focus on YOUR zone — the pitches you can drive."],
      rates:[40,35,85,30],concept:"At 1-0, you're slightly ahead — look for your pitch. If it's there, attack. If not, take it",explSimple:["Being too aggressive on 1-0 can lead to weak contact.","Being too patient wastes your slight advantage.","At 1-0, you have the luxury of being selective.","The ump's zone doesn't matter to your approach."],anim:"hit"},
    {id:"b29", conceptTag:"situational-hitting",title:"3-1 Double Play Danger",diff:2,cat:"counts",ageMin:9,ageMax:99,
      description:"Top of the 5th, runner on 1st, 1 out, up 2-1. Count is 3-1. This is your pitch to hit — but a ground ball could be a double play.",
      situation:{inning:"Top 5",outs:1,count:"3-1",runners:[1],score:[1,2]},
      options:["Swing only at a pitch you can lift — avoid grounders","Take the pitch — walk to first and avoid the DP","Swing at anything — 3-1 is your count","Hit and run — the runner goes with the pitch"],
      best:0,explanations:["Smart! On 3-1 with a runner on first, you want to swing at a pitch you can elevate — ground balls into double plays kill innings. Look for something up in the zone you can drive in the air.","Walking isn't bad, but 3-1 is a premium hitting count, which means pitchers throw their most hittable pitches here. Don't waste it completely.","Swinging at anything is reckless, because you still need to be selective — look for a pitch you can lift, not ground into a DP.","A hit and run on 3-1 is possible, but it forces you to swing at anything, since better to be selective and look for a ball you can drive in the air."],
      rates:[85,50,25,40],concept:"On 3-1 with a runner on 1st, look for a pitch you can lift — avoid the double play grounder",explSimple:["On 3-1 with a runner on first, you want to swing at a pitch you can elevate.","Walking isn't bad, but 3-1 is a premium hitting count.","Swinging at anything is reckless.","A hit and run on 3-1 is possible, but it forces you to swing at anything."],anim:"hit"},
    {id:"b30", conceptTag:"two-strike-approach",title:"2-2 — Protect or Attack?",diff:2,cat:"counts",ageMin:9,ageMax:99,
      description:"Bot 7th, runner on 2nd, 2 outs, down 3-2. Count is 2-2. The pitcher has mixed fastballs and changeups all day. You're the tying run.",
      situation:{inning:"Bot 7",outs:2,count:"2-2",runners:[2],score:[2,3]},
      options:["Protect the plate — swing at anything close","Sit on the changeup — he's thrown 3 in a row","Look for a fastball, react to everything else","Take the pitch — hope for a walk"],
      best:2,explanations:["Swinging at anything close leads to weak contact on bad pitches, because you can be more strategic than that.","Guessing changeup is risky — what if he switches to a fastball? You'd be way behind it, because the downside outweighs the potential gain.","On 2-2, you can't afford to be completely passive or completely aggressive — the best approach is to look for the pitch you hit best (usually a fastball) and react to anything else. If it's off the plate, fight it off.","Taking on 2-2 with 2 outs is too passive, which means a called strike three means your team doesn't score."],
      rates:[35,30,85,20],concept:"On 2-2, look for a fastball and react to off-speed — balance aggression with discipline",explSimple:["Swinging at anything close leads to weak contact on bad pitches.","Guessing changeup is risky — what if he switches to a fastball?","On 2-2, you can't afford to be completely passive or completely aggressive.","Taking on 2-2 with 2 outs is too passive."],anim:"hit"},
    {id:"b31", conceptTag:"count-leverage",title:"Full Count Battle — 2 Outs, RISP",diff:3,cat:"counts",ageMin:12,ageMax:99,
      description:"Top of the 8th, runners on 2nd and 3rd, 2 outs, tied 5-5. Full count 3-2. The pitcher just threw two nasty sliders you fouled off. You're exhausted.",
      situation:{inning:"Top 8",outs:2,count:"3-2",runners:[2,3],score:[5,5]},
      options:["Battle — foul off anything close until you get your pitch","Sit slider — he's going back to it","Swing hard — end the at-bat one way or another","Take the pitch — a walk loads the bases"],
      best:0,explanations:["This is what great hitters do — they battle, because foul off tough pitches, extend the at-bat, wear down the pitcher, and wait for a mistake. Every foul ball is a small victory that brings you closer to a hittable pitch.","Sitting on one pitch on a full count is risky, since what if he throws a fastball for strike three?","Swinging hard often leads to a strikeout in these situations, because shorten up and fight.","Taking on 3-2 with 2 outs is dangerous — since if it catches the corner, you're out looking and the runners are stranded."],
      rates:[85,35,20,40],concept:"On a full count with 2 outs, battle — foul off tough pitches and wait for your mistake pitch",anim:"hit"},
    {id:"b32", conceptTag:"count-leverage",title:"3-0 Green Light",diff:3,cat:"counts",ageMin:12,ageMax:99,
      description:"Bot 9th, runner on 3rd, 1 out, down 7-6. Count is 3-0. Your coach gives you the green light — meaning you CAN swing if you want. The pitcher needs a strike badly.",
      situation:{inning:"Bot 9",outs:1,count:"3-0",runners:[3],score:[6,7]},
      options:["Take the pitch — a walk puts another runner on","Swing only if it's a perfect fastball right down the middle","Swing at any strike — you have the green light","Squeeze bunt — the runner on 3rd scores"],
      best:1,explanations:["A walk helps, but it doesn't tie the game — the runner on 3rd is the tying run — you want to drive him in if possible.","The green light doesn't mean swing at everything — it means swing at a PERFECT pitch, which means on 3-0, the pitcher must throw a strike. If it's a meatball fastball right in your wheelhouse, crush it. If it's not absolutely perfect, take it to 3-1.","Swinging at any strike wastes the green light's purpose, because you only swing at a pitch you can CRUSH.","A squeeze bunt on 3-0 wastes an incredible count advantage, since you think about what gives your team the best result here."],
      rates:[40,85,30,15],concept:"A green light on 3-0 means swing at a PERFECT pitch — not any pitch, THE pitch",anim:"hit"},
    {id:"b33",title:"0-2 Same Pitch Twice",diff:3,cat:"counts",conceptTag:"two-strike-approach",ageMin:9,ageMax:99,
      description:"Top of the 6th, runner on 1st, 1 out, down 3-2. Count is 0-2. The pitcher has thrown you two changeups in a row — both for strikes. Is he coming back with a third?",
      situation:{inning:"Top 6",outs:1,count:"0-2",runners:[1],score:[3,2]},
      options:["Sit on the changeup — he'll throw it again","Look fastball, react to changeup","Crowd the plate to take away the outside changeup","Just try to foul everything off"],
      best:1,explanations:["Sitting changeup on 0-2 is tempting, but good pitchers rarely throw the same pitch three times in a row, because he knows you've seen two changeups — he might come with heat.","Even though he threw two changeups, look fastball and react to off-speed, since if the changeup comes, your hands will adjust. But if a fastball comes while you're sitting changeup, you'll be way late. It's easier to slow down than speed up.","Crowding the plate on 0-2 just gives the pitcher more inside options, which means it doesn't solve the sequencing problem.","Fouling off everything is survival mode, which is fine, but having a plan (look fastball, react to off-speed) gives you a better chance of getting a hit, which is why this approach matters in this situation."],
      rates:[30,85,25,45],concept:"Look fastball, react to off-speed — it's easier to slow down your swing than speed it up",anim:"hit"},
    // Batch 3 — Bunting Decisions
    {id:"b34", conceptTag:"bunt-re24",title:"Sacrifice Bunt — 9-Hole Hitter",diff:1,cat:"plays",ageMin:6,ageMax:99,
      description:"Top of the 5th, runner on 1st, nobody out, tied 2-2. You're the #9 hitter — weakest bat in the lineup. The leadoff hitter waits on deck. Coach gives the bunt sign.",
      situation:{inning:"Top 5",outs:0,count:"0-0",runners:[1],score:[2,2]},
      options:["Bunt the runner to 2nd — do your job","Swing away — surprise the defense","Fake the bunt and swing","Take pitches and hope for a walk"],
      best:0,explanations:["As the #9 hitter with nobody out, the sacrifice bunt is your job. While bunting statistically lowers your scoring chances, the tradeoff is worth it here — move the runner to 2nd where a single from the leadoff hitter scores him. You're trading your out for a runner in scoring position. That's a good trade when you're the weakest hitter.","Swinging away as the #9 hitter ignores the team's best strategy, because the leadoff hitter behind you is more likely to drive in the run. Your batting average is the lowest in the lineup, so trading your out for a runner in scoring position gives your team a higher chance of scoring.","Fake bunt and swing goes against the coach's sign, since the coach called a sacrifice bunt for a strategic reason — he wants the runner at second for the stronger hitters behind you. Executing the play as called builds team trust and discipline.","Hoping for a walk is too passive when the coach gave a bunt sign, because you can't control whether the pitcher walks you, but you CAN control whether you advance the runner. Take action rather than hoping for the best."],
      rates:[85,25,20,30],concept:"As the weakest hitter, the sacrifice bunt trades your out for a runner in scoring position — a good trade",explSimple:["Great choice! As the #9 hitter with nobody out, the give-up bunt is your job.","Not the best move. Swinging away as the #9 hitter ignores the team's best strategy.","Not the best move. Fake bunt and swing goes against the coach's sign.","Not the best move. Hoping for a walk wastes the bunt opportunity."], anim:"bunt"},
    {id:"b35",title:"Bunt Him to Third",diff:1,cat:"plays",conceptTag:"situational-hitting",ageMin:11,ageMax:99,
      description:"Bot 7th, runner on 2nd, nobody out, down 3-2. You're a decent contact hitter but not a power guy. The tying run is at second.",
      situation:{inning:"Bot 7",outs:0,count:"0-0",runners:[2],score:[2,3]},
      options:["Bunt the runner to 3rd","Hit to the right side — advance him and reach base","Swing away — drive the run in yourself","Take a pitch first to see what the pitcher has"],
      best:1,explanations:["Bunting the runner to third is okay, but it gives away an out when there's a better option — a sacrifice bunt gives you 3rd-and-1-out — you've given up an out without maximizing the situation.","Hitting to the right side moves the runner to 3rd AND gives you a chance to reach base, because From third with less than 2 outs, the runner can score on a sac fly, ground ball, wild pitch, or passed ball. You've created all those options WITHOUT giving away an out.","Swinging away is fine if you have power, but as a contact hitter you should play smart, because your strength is putting the ball in play, not swinging for the fences. Use that strength to place the ball to the right side and manufacture the run.","Taking a pitch doesn't advance the runner or get you closer to a productive at-bat, because in the 7th inning down a run, you need to be proactive and make something happen with your swing right away."],
      rates:[55,85,30,20],concept:"Hit to the right side to advance the runner — it's like a bunt but you might also reach base",explSimple:["Not the best move. Bunting the runner to third is okay, but it gives away an out.","Great choice! Hitting to the right side moves the runner to 3rd AND gives you a chance.","Not the best move. Swinging away is fine if you have power, but a contact hitter should play smart.","Not the best move. Taking a pitch doesn't advance the runner or get you closer to a productive at-bat."], anim:"hit"},
    {id:"b36", conceptTag:"situational-hitting",title:"Bunt for a Hit — Speed Advantage",diff:2,cat:"plays",ageMin:9,ageMax:99,
      description:"Top of the 3rd, nobody on, 1 out, tied 1-1. You're fast — really fast. The third baseman plays deep. You've noticed he's been slow to react to grounders.",
      situation:{inning:"Top 3",outs:1,count:"0-0",runners:[],score:[1,1]},
      options:["Bunt for a hit down the third base line","Swing away — bunting with nobody on is weird","Fake bunt to pull the 3B in, then bunt next pitch","Bunt toward first base instead"],
      best:0,explanations:["A bunt down the third base line when the third baseman is playing deep forces him to charge 30+ feet, barehand a rolling ball, plant his feet, and make a long throw across the diamond — all while you sprint at full speed. Each step in that chain takes time, and for a fast runner, that math works in your favor almost every time.","Bunting for a hit is NOT a sacrifice bunt — you're not giving yourself up. It's an offensive weapon that uses your speed to beat the defense, which means you're forcing the fielder into a tough play rather than giving up an out. Many of baseball's all-time greats (Ichiro, Rickey Henderson) used the bunt-for-a-hit regularly, even with nobody on base. Speed is a tool just like power.","Faking the bunt first tips off the defense and eliminates your biggest advantage: surprise, which means once the third baseman sees you show bunt, he'll creep in and be ready for it next pitch. The element of surprise is what makes this play work — don't waste it.","Bunting toward first base can work against a deep first baseman, but look at the field: the third baseman is playing deep AND he's slow to react, which means the third base side has the bigger gap right now. Always read the defense and bunt toward the weakest spot, not just a default direction, since exploiting the biggest opening gives you the best chance of beating the throw."],
      rates:[85,30,35,45],concept:"Fast runners can bunt for hits when the corner infielders play deep — use your speed as a weapon",explSimple:["A drag bunt or push bunt down the third base line when the 3B is playing deep is a great play for fast runners.","Bunting for a hit isn't a sacrifice — it's using your speed as a weapon.","Faking the bunt gives away the element of surprise.","Bunting toward first can work too, but with the third baseman playing deep, the third base side is the bigger opening."],anim:"bunt"},
    {id:"b37", conceptTag:"situational-hitting",title:"Good Hitter — Sacrifice or Swing?",diff:2,cat:"plays",ageMin:9,ageMax:99,
      description:"Bot 6th, runner on 1st, nobody out, tied 4-4. You're the #3 hitter — one of the best bats in the lineup. The coach hasn't given a sign. Do you bunt?",
      situation:{inning:"Bot 6",outs:0,count:"0-0",runners:[1],score:[4,4]},
      options:["Sacrifice bunt — move the runner","Swing away — you're the #3 hitter for a reason","Bunt for a hit — surprise the defense","Hit and run — put the runner in motion"],
      best:1,explanations:["Sacrifice bunting with your #3 hitter wastes one of your best at-bats, because that's like trading a dollar for a quarter.","You're batting third because you're one of the team's best hitters. A sacrifice bunt trades your quality at-bat for one base advancement. A single does the same thing while also getting you on base. A double scores the run. Swing your bat — good hitters should hit.","Bunting for a hit as the #3 hitter is unexpected, but you're giving up the chance to drive in the run with real power. And that's why this approach matters in this situation.","A hit and run is possible but constrains your swing, since as the #3 hitter, you should get your full swing."],
      rates:[25,85,40,45],concept:"Don't sacrifice bunt with your best hitters — their swings are too valuable to give away",explSimple:["Sacrifice bunting with your #3 hitter wastes one of your best at-bats.","You're batting third because you're one of the team's best hitters.","Bunting for a hit as the #3 hitter is unexpected, but you're giving up the chance to drive in the run with real power.","A hit and run is possible but constrains your swing."],anim:"hit"},
    {id:"b38", conceptTag:"squeeze-recognition",title:"Squeeze Play with Runner on Third",diff:2,cat:"plays",ageMin:9,ageMax:99,
      description:"Bot 8th, runner on 3rd, 1 out, tied 3-3. The coach calls the squeeze play — the runner will break for home when the pitcher starts his motion. You MUST bunt.",
      situation:{inning:"Bot 8",outs:1,count:"1-0",runners:[3],score:[3,3]},
      options:["Bunt the ball on the ground — anywhere fair","Only bunt if it's a good pitch","Pull back if the pitch is bad","Square early to let the defense see the bunt coming"],
      best:0,explanations:["On a squeeze play, you MUST bunt the ball. The runner from 3rd is committed — he's sprinting home the moment the pitcher starts his delivery. If you miss the bunt, he's a dead duck. Get the bat on the ball and put it on the ground, anywhere fair. That's all you need to do.","On a squeeze, you can't be selective, because the runner is committed. You bunt no matter what.","Pulling back means the runner is caught between third and home with nowhere to go — never pull back on a squeeze.","Squaring early tips off the defense and they might pitch out, which means stay in your batting stance as long as possible, then square to bunt late."],
      rates:[90,40,15,25],concept:"On a squeeze play, bunt the ball no matter what — the runner is committed and needs you to make contact",explSimple:["On a squeeze play, you MUST bunt the ball.","On a squeeze, you can't be selective.","Pulling back means the runner is caught between third and home with nowhere to go.","Squaring early tips off the defense and they might pitch out."],anim:"squeeze"},
    {id:"b39", conceptTag:"squeeze-recognition",title:"Suicide Squeeze — Bad Pitch",diff:3,cat:"plays",ageMin:12,ageMax:99,
      description:"Top of the 9th, runner on 3rd, 1 out, down 5-4. Suicide squeeze is on. He throws a fastball HIGH AND INSIDE — almost at your face. The runner is already running.",
      situation:{inning:"Top 9",outs:1,count:"1-0",runners:[3],score:[5,4]},
      options:["Bunt it anyway — the runner needs you","Bail out — protect yourself from the pitch","Swing at it — maybe you can hit it","Duck and hope the pitch goes to the backstop"],
      best:0,explanations:["Bunt it anyway, because on a suicide squeeze, you bunt NO MATTER WHAT. Even a pitch up and in — get your bat on it. The runner needs you. Stick the bat head up high, angle it toward the ground, and deaden the ball. Even a foul ball keeps the play alive. This pitch is high and inside but still buntable — get the bat on it.","Bailing out doesn't protect yourself or the runner — it leaves him completely exposed between 3rd and home. He's already sprinting and will be tagged out easily. The whole play depends on you making contact with the ball.","Swinging at a high-and-in pitch on a squeeze defeats the purpose, because you need the ball on the ground, not hit in the air. A pop-up or line drive could turn into a double play.","Ducking means the runner is dead, because on a squeeze, the batter MUST attempt to bunt no matter what. The runner committed on the pitch, and your job is to protect him by getting any piece of the ball."],
      rates:[90,25,40,15],concept:"On a suicide squeeze, bunt the ball no matter where it's thrown — your teammate's safety depends on you",anim:"squeeze"},
    {id:"b40", conceptTag:"situational-hitting",title:"Power Hitter Asked to Bunt",diff:3,cat:"plays",ageMin:12,ageMax:99,
      description:"Bot 5th, runner on 2nd, nobody out, tied 2-2. You're the #4 hitter — cleanup — with 15 home runs. The coach shockingly calls for a sacrifice bunt. What do you think?",
      situation:{inning:"Bot 5",outs:0,count:"0-0",runners:[2],score:[2,2]},
      options:["Bunt — follow the coach's sign no matter what","Ask the coach to reconsider — you can drive the run in","Swing away — the coach must have made a mistake","Fake bunt and slash — compromise"],
      best:0,explanations:["Even if you disagree, you execute the coach's sign. The coach has information you might not — maybe the pitcher owns you, maybe the hitters behind you are better in this spot, maybe there's a strategic reason. While the bunt statistically costs run expectancy, the coach sees a tradeoff worth taking. Trust the process and bunt.","Asking the coach to reconsider mid-at-bat disrupts the flow of the game, because strategy discussions belong before or after the game, not during a live at-bat when your teammates are watching and the pitcher is waiting.","Ignoring the coach's sign destroys team trust. Even if you think you know better, execute the play.","Going rogue with a slash play when the bunt is specifically called breaks team discipline, since even if you think it's a better play, ignoring signs destroys trust. Save your strategic suggestions for the dugout between innings."],
      rates:[85,30,10,20],concept:"Execute the coach's sign even if you disagree — trust, teamwork, and discipline win games",anim:"bunt"},
    {id:"b41", conceptTag:"situational-hitting",title:"Fake Bunt and Slash",diff:3,cat:"plays",ageMin:12,ageMax:99,
      description:"Top of the 4th, runner on 2nd, nobody out, up 3-1. The coach calls a fake bunt-and-slash play. You show bunt early, the infield charges, then you pull back and swing.",
      situation:{inning:"Top 4",outs:0,count:"1-0",runners:[2],score:[1,3]},
      options:["Show bunt, then slash away at whatever pitch comes","Show bunt, pull back, and only swing at a good pitch","Fake the bunt but don't commit — read the pitch first","Lay down a real bunt instead of slashing"],
      best:1,explanations:["Slashing at whatever comes defeats the purpose, because if the pitch is bad, take it for a ball. The bunt fake already pulled the infield in.","The slash play is an aggressive two-part trick at no real cost: First, show bunt to pull the infield in. Second, pull back and ONLY swing at a hittable pitch. With the infield charging, there are huge gaps behind them. A sharp ground ball or line drive goes right through the holes. But don't swing at a bad pitch — the fake already helped you.","Not committing to either the fake or the swing makes you do neither well. The slash play requires full commitment to each phase — a half-hearted fake won't draw the infield in, and a hesitant swing won't find the gaps.","The coach called a slash, not a bunt, so execute the play that was called. Changing the play on your own takes away the advantage the coach designed. Trust the call and execute your role."],
      rates:[35,85,30,15],concept:"The slash play exploits a charging infield — show bunt, then swing at a good pitch through the gaps",anim:"hit"},
    // Batch 4 — Two-Strike Approach
    {id:"b42",title:"Two Strikes — Change Your Swing",diff:1,cat:"counts",conceptTag:"two-strike-approach",ageMin:9,ageMax:99,
      description:"Bot 4th, nobody on, 1 out, tied 2-2. You fell behind 0-2 quickly. The pitcher has been pounding the outside corner. What do you do with your swing?",
      situation:{inning:"Bot 4",outs:1,count:"0-2",runners:[],score:[2,2]},
      options:["Shorten your swing — choke up and make contact","Keep swinging the same — don't change for anyone","Swing harder — you need to catch up to the fastball","Open your stance to see the ball better"],
      best:0,explanations:["With 2 strikes, shorten your swing. Choke up an inch on the bat, widen your stance slightly, and focus on putting the ball in play. A shorter swing gives you more time to see the pitch and better bat control. The goal changes from driving the ball to making contact.","Keeping the same big swing with 2 strikes leads to more strikeouts, since the best hitters in the world adjust with 2 strikes.","Swinging harder with 2 strikes is the opposite of what you should do, which means you need more control, not more power.","Opening your stance is a drastic change mid-at-bat, because choking up is simpler and more effective."],
      rates:[85,20,10,30],concept:"With 2 strikes, choke up and shorten your swing — contact is more important than power",explSimple:["Great choice! With 2 strikes, shorten your swing.","Not the best move. Keeping the same big swing with 2 strikes leads to more strikeouts.","Not the best move. Swinging harder with 2 strikes is the opposite of what you should do.","Not the best move. Opening your stance is a drastic change mid-at-bat."], anim:"hit"},
    {id:"b43", conceptTag:"two-strike-approach",title:"Protecting the Plate with Runners On",diff:1,cat:"counts",ageMin:6,ageMax:99,
      description:"Top of the 6th, runner on 3rd, 1 out, down 3-2. Count is 1-2. A borderline pitch comes — it might be a ball, might be a strike.",
      situation:{inning:"Top 6",outs:1,count:"1-2",runners:[3],score:[2,3]},
      options:["Swing at it — can't take a called strike three","Take it — trust the umpire to call it a ball","Foul it off — protect the plate","Swing for the fences — go for the big hit"],
      best:2,explanations:["Swinging at a borderline pitch with a full swing often leads to weak contact or a swing-and-miss.","Taking a borderline pitch with 2 strikes and a runner on 3rd is risky — because if the ump calls it a strike, you struck out looking with the tying run at third.","Fouling off borderline pitches is elite hitting. You're not giving in (striking out), and you're not swinging hard at a tough pitch. You're keeping the at-bat alive until you get something you can drive. With a runner on 3rd, every extra pitch is another chance to get a hittable ball.","Swinging for the fences with 2 strikes is how you strike out."],
      rates:[35,25,85,10],concept:"With 2 strikes and runners on, foul off borderline pitches — keep the at-bat alive",explSimple:["Not the best move. Swinging at a borderline pitch with a full swing often leads to weak contact.","Not the best move. Taking a borderline pitch with 2 strikes is risky — the umpire might ring you up.","Great choice! Fouling off borderline pitches is elite hitting.","Not the best move. Swinging for the fences with 2 strikes is how you strike out."], anim:"hit"},
    {id:"b44",title:"Two Strikes — Breaking Ball Barrage",diff:2,cat:"counts",conceptTag:"two-strike-approach",ageMin:9,ageMax:99,
      description:"Bot 5th, nobody on, 2 outs, up 4-3. Count is 1-2. The pitcher has been throwing you nothing but curveballs. You've fouled off two of them.",
      situation:{inning:"Bot 5",outs:2,count:"1-2",runners:[],score:[4,3]},
      options:["Sit on the curveball and crush it","Look for the fastball — he might switch","Stay ready for anything — react to what comes","Take the next pitch — it'll probably be a ball"],
      best:2,explanations:["Sitting on the curveball means if he throws a fastball, you're frozen, since he knows you've seen three curves.","Looking fastball only leaves you vulnerable to another curveball, because after three curves, he might throw a fourth OR switch.","After seeing multiple breaking balls, stay reactive — don't commit to guessing one pitch. See the ball, react to the ball. If it's a curve, your eyes have adjusted to the spin. If it's a fastball, your hands can react. Trust your eyes and your training.","Taking with 2 strikes and 2 outs is dangerous — a called strike three is game over, because the downside outweighs the potential gain."],
      rates:[35,30,85,20],concept:"After a breaking ball barrage, stay reactive — don't guess, let your eyes and hands adjust",explSimple:["Sitting on the curveball means if he throws a fastball, you're frozen.","Looking fastball only leaves you vulnerable to another curveball.","After seeing multiple breaking balls, stay reactive.","Taking with 2 strikes and 2 outs is dangerous — a called strike three is game over."],anim:"hit"},
    {id:"b45", conceptTag:"situational-hitting",title:"Choking Up — Why and When",diff:2,cat:"counts",ageMin:9,ageMax:99,
      description:"Top of the 7th, runner on 2nd, 2 outs, tied 3-3. Count is 0-2. He throws 95 mph and has been blowing you away. You're late on every fastball.",
      situation:{inning:"Top 7",outs:2,count:"0-2",runners:[2],score:[3,3]},
      options:["Choke up 2 inches — shorten the bat for quicker hands","Keep your normal grip — don't change mid-game","Move up in the batter's box — catch the fastball earlier","Swing earlier in your load"],
      best:0,explanations:["Choking up 2 inches on the bat makes it lighter and gives you quicker hands through the zone. When you're late on a fastball, the bat speed is the problem. A shorter bat is a faster bat. You lose a little power but gain bat speed and contact ability. With 2 strikes, that trade is worth it.","Keeping your normal grip when you're consistently late means you'll keep being late — if something is not working, make an adjustment.","Moving up in the box can help, but choking up is a more natural adjustment that keeps your timing the same while giving you quicker hands.","Swinging earlier changes your whole timing mechanism, which means choking up is simpler and more effective."],
      rates:[85,15,35,30],concept:"When you're late on fastballs, choke up — a shorter bat is a faster bat. Trade power for contact",explSimple:["Choking up 2 inches on the bat makes it lighter and gives you quicker hands through the zone.","Keeping your normal grip when you're consistently late means you'll keep being late.","Moving up in the box can help, but choking up is a more natural adjustment that doesn't change your timing.","Swinging earlier changes your whole timing mechanism."],anim:"hit"},
    {id:"b46", conceptTag:"two-strike-approach",title:"Fouling Off — Battle Mode",diff:2,cat:"counts",ageMin:9,ageMax:99,
      description:"Bot 8th, runner on 1st, 1 out, down 4-3. Count is 2-2. You've fouled off the last 5 pitches. The pitcher looks frustrated. The at-bat is at 10 pitches.",
      situation:{inning:"Bot 8",outs:1,count:"2-2",runners:[1],score:[3,4]},
      options:["Keep fouling — wear him down until he makes a mistake","Swing for a hit — enough battling","Take the next pitch — you've earned a ball","Change your approach — try something different"],
      best:0,explanations:["You're winning this battle, because every foul ball costs the pitcher a pitch and energy. He's getting frustrated, which means he's more likely to make a mistake — a hanging curve, a fastball over the plate, or a walk. The longer this at-bat goes, the better your chances. Keep battling.","Changing from battle mode to power swing mode throws away everything you've built. You've worn the pitcher down for 10 pitches, and he's frustrated. Switching to a big swing means more swing-and-miss. Stay alive and wait for his mistake.","Taking on 2-2 after a long battle risks a called strike three, because the umpire may ring you up on a borderline pitch. Keep your bat ready and keep fouling off pitches you can't drive. A walk is just as good as a hit here.","Your approach IS working — you're still alive after 10 pitches, which means you shouldn't fix what isn't broken. Changing strategy mid-battle gives the pitcher exactly the reset he needs when he's already frustrated."],
      rates:[85,25,30,20],concept:"Long at-bats wear down pitchers — keep fouling off tough pitches until they make a mistake",explSimple:["You're winning this battle!","Changing from battle mode to power swing mode throws away everything you've built.","Taking on 2-2 after a long battle risks a called strike three.","Your approach IS working — you're still alive after 10 pitches."],anim:"hit"},
    {id:"b47", conceptTag:"two-strike-approach",title:"Two Strikes — Expand the Zone?",diff:2,cat:"counts",ageMin:9,ageMax:99,
      description:"Top of the 3rd, nobody on, nobody out, tied 1-1. Count is 1-2. The pitcher has been nibbling the corners all day — he barely throws anything over the plate.",
      situation:{inning:"Top 3",outs:0,count:"1-2",runners:[],score:[1,1]},
      options:["Expand your zone — swing at anything close","Keep your normal zone — if it's not a strike, don't swing","Expand slightly — protect the plate on borderline pitches","Swing at everything — can't strike out looking"],
      best:2,explanations:["Swinging at anything close leads to bad contact on pitcher's pitches, because you'll ground out weakly.","Keeping your exact normal zone with 2 strikes means called strike threes on borderline pitches, since umps expand their zone late in counts.","Expand your zone slightly — about one ball-width in each direction, because if a pitch catches the black (the edge of the plate), fight it off. If it's clearly off the plate, lay off. This keeps you from striking out on borderline calls without chasing bad pitches.","Swinging at everything is just hacking — have a plan — expand slightly, not completely."],
      rates:[25,35,85,15],concept:"With 2 strikes, expand your zone slightly — protect the plate without chasing bad pitches",explSimple:["Swinging at anything close leads to bad contact on pitcher's pitches.","Keeping your exact normal zone with 2 strikes means called strike threes on borderline pitches.","Expand your zone slightly — about one ball-width in each direction.","Swinging at everything is just hacking."],anim:"hit"},
    {id:"b48", conceptTag:"two-strike-approach",title:"Two Strikes, Runner on Third — Contact At All Costs?",diff:3,cat:"counts",ageMin:12,ageMax:99,
      description:"Bot 9th, runner on 3rd, 1 out, tied 6-6. Count is 0-2. A fly ball wins the game. A strikeout kills the rally. The pitcher has been throwing his best stuff.",
      situation:{inning:"Bot 9",outs:1,count:"0-2",runners:[3],score:[6,6]},
      options:["Shorten up — put the ball in play at all costs","Wait for your pitch — don't swing at junk","Swing for a fly ball — that wins the game","Bunt for a squeeze play to surprise them"],
      best:0,explanations:["With a runner on 3rd, 1 out, and the game on the line, PUT THE BALL IN PLAY. A fly ball scores the run. A ground ball might score the run. Even weak contact creates a chance. A strikeout creates nothing. Shorten your swing, protect the plate, and make contact — any contact is better than a strikeout in this spot.","Waiting for your pitch on 0-2 against a pitcher's best stuff means you'll be waiting for a long time. Fight, which is why this approach matters in this situation.","Swinging for a fly ball specifically changes your mechanics, which means just make contact — fly balls happen naturally.","A squeeze bunt on 0-2 is extremely risky — one foul ball and you're out, because with two strikes you need to protect the plate and put a normal swing on the ball."],
      rates:[85,25,35,20],concept:"With the winning run on 3rd and 2 strikes, make contact — any contact is better than a strikeout",anim:"hit"},
    {id:"b49", conceptTag:"two-strike-approach",title:"0-2 Curveball Incoming?",diff:3,cat:"counts",ageMin:12,ageMax:99,
      description:"Top of the 8th, runner on 2nd, 2 outs, tied 4-4. Count is 0-2. The pitcher has thrown you an 0-2 curveball in every at-bat today — you've chased it all three times.",
      situation:{inning:"Top 8",outs:2,count:"0-2",runners:[2],score:[4,4]},
      options:["Sit on the curveball — you know it's coming","Look fastball but be ready for the curve","Lay off everything low — the curve will be in the dirt","Swing early to catch the curve before it breaks"],
      best:2,explanations:["Sitting on the curve means if he throws a fastball, you're frozen for strike three.","Looking fastball and reacting to the curve is the standard approach, but you KNOW the 0-2 curve is coming — as use that knowledge.","You've chased the 0-2 curveball three times today. The curve will be low — probably in or near the dirt. The fix is simple: lay off anything below the belt. If the curve is a strike, fight it off. If it's in the dirt (which it usually is on 0-2), you've taken ball one and the count is 1-2. You just turned the tables.","Swinging early at a curveball makes the timing even worse, since the curve is designed to fool your timing."],
      rates:[30,40,85,10],concept:"If you keep chasing 0-2 curveballs, lay off everything low — the 0-2 curve is almost always in the dirt",anim:"strike"},
    // Batch 5 — Hitting Strategy by Game Situation
    {id:"b50", conceptTag:"situational-hitting",title:"Winning Big — Still Compete",diff:1,cat:"approach",ageMin:6,ageMax:99,
      description:"Top of the 7th, your team is crushing it — up 10-2. You're at the plate with nobody on, 2 outs. Do you change your approach?",
      situation:{inning:"Top 7",outs:2,count:"0-0",runners:[],score:[2,10]},
      options:["Swing normally — compete every at-bat","Swing for the fences — might as well go big","Take every pitch — end the game faster","Bunt for a hit — take advantage of relaxed fielders"],
      best:0,explanations:["Compete every at-bat the same way regardless of the score, because don't showboat (swinging for homers in a blowout is disrespectful), but don't stop trying either. Swing at good pitches, take bad ones. Play the game the right way.","Swinging for the fences in a blowout is considered showing up the other team — it's bad sportsmanship.","Deliberately making outs disrespects the game and your own teammates, which means always compete.","Bunting in a blowout to mess around is unsportsmanlike, because you think about what gives your team the best result here."],
      rates:[90,25,40,15],concept:"Compete the same way in every at-bat — don't showboat in a blowout or give up in a loss",explSimple:["Great choice! Compete every at-bat the same way regardless of the score.","Not the best move. Swinging for the fences in a blowout is considered showing up the other team.","Not the best move. Deliberately making outs disrespects the game and your own teammates.","Not the best move. Bunting in a blowout to mess around is unsportsmanlike."], anim:"hit"},
    {id:"b51", conceptTag:"count-leverage",title:"First At-Bat — Gather Intel",diff:1,cat:"approach",ageMin:6,ageMax:99,
      description:"Top of the 1st, your first at-bat of the game. You've never faced this pitcher before. Your teammates haven't given you any intel.",
      situation:{inning:"Top 1",outs:0,count:"0-0",runners:[],score:[0,0]},
      options:["Take the first pitch — see what he has","Look for a fastball and be ready to swing","Swing at the first pitch — surprise him","Watch from the dugout first, then adjust"],
      best:0,explanations:["Your first at-bat against an unknown pitcher is a scouting mission. Take the first pitch to see his velocity, movement, and arm slot. This information makes your NEXT at-bat much more dangerous. Working the count doesn't mean taking every pitch — it means being patient but ready when you get your pitch.","Looking fastball first isn't bad — if you spot a hittable pitch, being ready to swing is smart hitting. But against a total unknown, seeing one pitch first helps.","Swinging at the first pitch against an unknown pitcher is guessing blind, since you get some data first.","You can't watch from the dugout during your own at-bat, because you ARE the first data point."],
      rates:[75,60,25,10],concept:"First at-bat against an unknown pitcher, take a pitch — gather data for your next at-bat",explSimple:["Great choice! Your first at-bat against an unknown pitcher is a scouting mission.","Not the best move. Looking fastball first isn't bad — if you spot a hittable pitch, being ready.","Not the best move. Swinging at the first pitch against an unknown pitcher is guessing blind.","Not the best move. You can't watch from the dugout during your own at-bat."], anim:"strike"},
    {id:"b52", conceptTag:"two-strike-approach",title:"In a Slump — What to Adjust",diff:2,cat:"adjustments",ageMin:9,ageMax:99,
      description:"Bot 6th, you're 0-for-your-last-12 over three games and your confidence is low. Runner on 1st, 1 out. The count runs to 1-2. You've been popping up and grounding out weakly all week. How do you adjust your approach with two strikes during this slump?",
      situation:{inning:"Bot 6",outs:1,count:"1-2",runners:[1],score:[2,2]},
      options:["Swing harder to force your way out of the slump — rip the next pitch","Shorten up and look for one pitch in one zone — just put the ball in play","Go back to basics — take a few pitches and reset your timing","Expand your zone and swing at anything close since you're behind in the count"],
      best:1,explanations:["Swinging harder with two strikes during a slump makes things worse, because you get tense, your swing gets longer, and you chase more pitches out of the zone. Since you're already struggling with weak contact, adding effort creates more pop-ups and strikeouts.","With two strikes during a slump, you shorten your swing and simplify your plan. Pick one zone — like middle-away — and just put the ball in play, because shorter swings make better contact and reduce strikeouts. Since your confidence is low, a line drive single rebuilds your feel at the plate, which is worth more than swinging for the fences.","Changing everything with two strikes creates confusion, because your muscle memory can't adjust mid-at-bat. Since your mechanics got you to this level, the fix is narrowing your focus — not rebuilding your entire swing with two strikes on you.","Expanding your zone with two strikes is a common mistake, because you swinging at bad pitches leads to even weaker contact. Since pitchers are trying to get you to chase with two strikes, having discipline to only swing at your pitch gives you a much better chance of making solid contact."],
      rates:[15,85,10,40],concept:"With two strikes during a slump, shorten up and simplify — pick one pitch in one zone and put the ball in play to rebuild confidence.",explSimple:["Swinging harder with two strikes during a slump makes things worse.","Shorten your swing and simplify — pick one zone and put the ball in play.","Changing everything with two strikes creates confusion.","Expanding your zone with two strikes means swinging at bad pitches."],anim:"hit"},
    {id:"b53", conceptTag:"situational-hitting",title:"Pitcher Hit Your Teammate — Stay Focused",diff:2,cat:"approach",ageMin:9,ageMax:99,
      description:"Top of the 5th, the pitcher just hit your teammate with a pitch. The benches are chirping. Now it's your turn to bat. Emotions are high.",
      situation:{inning:"Top 5",outs:1,count:"0-0",runners:[1],score:[2,3]},
      options:["Step in angry — punish the pitcher","Stay calm and focused — don't let emotions affect your at-bat","Take every pitch — show the pitcher you're not intimidated","Crowd the plate — dare him to throw inside"],
      best:1,explanations:["Anger changes your swing, your timing, and your pitch selection, since you'll chase bad pitches and try to hit the ball 500 feet.","After a teammate gets hit, the best thing you can do is get a hit. And the best way to get a hit is to stay calm, see the ball clearly, and stick to your approach. Don't let the pitcher live rent-free in your head. Channel any emotion into focus, not rage.","Taking every pitch lets the pitcher off the hook, which means get a hit — that hurts him more than a walk.","Crowding the plate after an HBP is asking to get hit yourself, because you stay in your normal position."],
      rates:[20,85,25,15],concept:"After a teammate gets hit, the best revenge is a base hit — stay calm and focused",explSimple:["Anger changes your swing, your timing, and your pitch selection.","After a teammate gets hit, the best thing you can do is get a hit.","Taking every pitch lets the pitcher off the hook.","Crowding the plate after an HBP is asking to get hit yourself."],anim:"hitByPitch"},
    {id:"b54", conceptTag:"situational-hitting",title:"Cold Weather — Adjust for Power",diff:2,cat:"adjustments",ageMin:9,ageMax:99,
      description:"Bot 3rd, nobody on, 1 out, tied 0-0. It's 42 degrees — the coldest game of the year. The ball isn't carrying at all. Your hands hurt.",
      situation:{inning:"Bot 3",outs:1,count:"0-0",runners:[],score:[0,0]},
      options:["Swing for the fences anyway — trust your power","Adjust to a line-drive approach — hit the gaps","Bunt more — the cold makes everyone less athletic","Swing easier to protect your hands"],
      best:1,explanations:["In cold weather, fly balls die, since what would be a home run in July is a fly out in March. Swinging for the fences wastes effort.","In cold weather, switch to a line-drive approach. Hit the ball hard on a line into the gaps. Line drives aren't affected by cold air as much as fly balls because they don't have to fight gravity as long. Focus on hard contact through the middle and to the gaps.","Bunting more because of cold weather is an overreaction. The cold affects everyone, but good hitters adjust.","Swinging easier reduces bat speed, making it even harder to generate the power you need in cold air."],
      rates:[15,85,25,30],concept:"In cold weather, switch to a line-drive approach — fly balls die but line drives travel in any temperature",explSimple:["In cold weather, fly balls die.","In cold weather, switch to a line-drive approach.","Bunting more because of cold weather is an overreaction.","Swinging easier reduces bat speed, making it even harder to generate the power you need in cold air."],anim:"hit"},
    {id:"b55", conceptTag:"pitch-sequencing",title:"Pitcher Tips His Curveball",diff:2,cat:"adjustments",ageMin:9,ageMax:99,
      description:"Top of the 4th, you notice the pitcher changes his glove position before throwing a curveball — he lifts it higher. This is called 'tipping pitches.' Nobody out, tied 1-1.",
      situation:{inning:"Top 4",outs:0,count:"0-0",runners:[],score:[1,1]},
      options:["Wait for the curveball tell, then crush it","Look for the tell but don't be obvious — use it subtly","Tell your whole team — let everyone benefit","Ignore it — it might be a decoy"],
      best:1,explanations:["Waiting only for curveballs means ignoring fastballs in your zone. Use the tell as a bonus, not as your entire approach. If you only hunt curves, hittable fastballs sail past you.","Use the tell to CONFIRM what's coming, but don't change your entire approach. If you see the high glove, you know a curve is coming — sit on it. If you don't see it, look fastball. This gives you an edge without being obvious. If you're too obvious (staring at his glove), the catcher will tell him and he'll fix it.","Telling your whole team is helpful, but do it quietly in the dugout — not during your at-bat, because and it needs to be subtle or the pitcher will fix his mechanics immediately.","Tipping pitches is a real thing and ignoring it wastes free information. If you see a consistent tell multiple times, use it wisely — but be subtle so the advantage lasts the whole game."],
      rates:[40,85,55,15],concept:"If you spot a pitch-tipping tell, use it subtly — don't be obvious or the pitcher will fix it",explSimple:["Waiting only for the curveball means ignoring fastballs that might be in your zone.","Use the tell to CONFIRM what's coming, but don't change your entire approach.","Telling your whole team is helpful, but do it quietly in the dugout — not during your at-bat.","Tipping pitches is a real thing."],anim:"hit"},
    {id:"b56", conceptTag:"situational-hitting",title:"Bases Loaded, Cleanup Spot — Smart Approach",diff:3,cat:"approach",ageMin:12,ageMax:99,
      description:"Bot 7th, bases loaded, nobody out, up 5-3. You're the cleanup hitter. Everyone in the stadium expects a grand slam. The pitcher looks nervous.",
      situation:{inning:"Bot 7",outs:0,count:"0-0",runners:[1,2,3],score:[5,3]},
      options:["Swing for the grand slam — give the fans what they want","Put the ball in play hard — any solid contact scores runs","Be patient — the pitcher might walk you for a free run","Bunt — nobody would ever expect it"],
      best:1,explanations:["Swinging for the grand slam changes your mechanics and usually leads to pop-ups or strikeouts, since you're trying to do too much.","With bases loaded and nobody out, solid contact is devastating. A single scores 1-2 runs. A double scores 2-3 runs. A hard ground ball might score a run. You don't need a grand slam — you need hard contact. The bases being loaded means EVERYTHING good is amplified. Just drive the ball.","Being too patient with nobody out and bases loaded wastes the pressure on a nervous pitcher, which means if he grooves one, crush it.","Bunting with bases loaded as the cleanup hitter is insane, because you drive the ball."],
      rates:[25,85,40,5],concept:"Bases loaded, don't swing for the grand slam — hard contact with the bases loaded is devastating enough",anim:"hit"},
    {id:"b57", conceptTag:"situational-hitting",title:"Go-Ahead Run in the 9th — Nervous Pitcher",diff:3,cat:"approach",ageMin:12,ageMax:99,
      description:"Bot 9th, runner on 2nd, 1 out, tied 7-7. You can see the pitcher sweating. He's bounced two curveballs. His fastball has been up. He's clearly nervous.",
      situation:{inning:"Bot 9",outs:1,count:"0-0",runners:[2],score:[7,7]},
      options:["Be aggressive — he's going to groove a fastball","Be patient — let him walk you","Look for one specific pitch — his fastball up in the zone","Jump on the first hittable pitch you see"],
      best:3,explanations:["Being overly aggressive might mean swinging at a curveball in the dirt as he tries to settle down.","Being too patient lets him recover, since nervous pitchers sometimes settle down after a few pitches.","Looking for one specific pitch is too narrow, because he's wild — you don't know what's coming.","A nervous pitcher will make a mistake — a fastball that drifts over the plate, a hanging curve, a changeup that stays up. Jump on the FIRST hittable pitch you see. Don't give him time to settle in. The longer the at-bat goes, the more comfortable he gets. Strike early while he's shaking."],
      rates:[40,30,35,85],concept:"Against a nervous pitcher, jump on the first hittable pitch — don't let him settle in",anim:"hit"},
    {id:"b58", conceptTag:"pitch-sequencing",title:"Third At-Bat — You've Seen Everything",diff:3,cat:"adjustments",ageMin:12,ageMax:99,
      description:"Top of the 7th, runner on 1st, 2 outs, down 4-3. Third at-bat against this pitcher. He struck you out on a slider in the 2nd and got you on a changeup in the 5th.",
      situation:{inning:"Top 7",outs:2,count:"0-0",runners:[1],score:[4,3]},
      options:["Sit on the slider — he got you with it once","Look for the changeup — it worked last time","Expect fastball early, then adjust to off-speed","Look for the pitch you HAVEN'T seen — he might go there"],
      best:2,explanations:["Sitting on the slider alone is risky, because he can throw the changeup and you're lost again. Guessing one pitch against a pitcher with three weapons leaves you vulnerable to the other two pitches in his arsenal.","Sitting changeup alone means the slider gets you, because You can't guess one pitch against a pitcher with multiple weapons — you need a plan that covers his whole arsenal, not just one part of it.","Third time through, you KNOW his arsenal. He has a fastball, slider, and changeup, which means you should expect fastball early in the count (most pitchers go back to the fastball to get ahead), then be ready to react to the off-speed. Your previous at-bats taught you what the slider and changeup LOOK like — use that knowledge to recognize them earlier.","Trying to guess a new pitch is overthinking the situation. Use what you've learned from your first two at-bats — you already know what his slider and changeup look like out of his hand. That recognition is more valuable than guessing."],
      rates:[30,25,85,35],concept:"Third at-bat, use your data — expect fastball early, react to off-speed with what you've learned",anim:"hit"},
    {id:"b_hr1",title:"Hit and Run — Where Should You Hit It?",diff:2,cat:"situational",conceptTag:"hit-and-run",ageMin:11,ageMax:99,
      description:"Runner on 1st, 1 out, tie game. The coach puts the hit-and-run on. The pitcher winds up and throws a fastball middle-away. Where should you try to hit this ball?",
      situation:{inning:"Bot 5",outs:1,count:"1-0",runners:[1],score:[3,3]},
      options:["Pull it to left field for a double","Hit it on the ground to the right side — behind the runner","Hit a fly ball to the outfield","Bunt it down the third base line"],
      best:1,explanations:["Pulling the ball on a hit-and-run is risky — a pulled grounder to the shortstop or third baseman is an easy double play — the runner is already going and can't get back. Pulling a line drive might double off the runner at first.","Correct! On the hit-and-run, your job is to put the ball on the ground to the RIGHT side. Why? The runner is going to first-to-second. The second baseman or shortstop has to cover second base for the steal, which opens a hole on the right side. A groundball through that hole advances the runner to third (or even scores him) and you reach first safely. The pitch is away, which naturally sets up a right-side groundball. Go with the pitch.","A fly ball on the hit-and-run is dangerous, which means if it's caught, the runner is way off first base and easily doubled off. The whole point of the hit-and-run is to put the ball on the ground.","Bunting defeats the purpose of the hit-and-run. The coach called hit-and-run specifically because they want you to swing and protect the runner. A bunt is a different play — and a foul bunt with 1 strike puts you behind in the count."],
      rates:[40,90,15,25],concept:"On the hit-and-run, hit the ball on the ground to the right side — the middle infielder covering second leaves a hole",explSimple:["Pulling the ball on a hit-and-run is risky.","On the hit-and-run, your job is to put the ball on the ground to the RIGHT side.","A fly ball on the hit-and-run is dangerous.","Bunting defeats the purpose of the hit-and-run."],anim:"hit"},
    {id:"b_mg1",conceptTag:"composure-pressure",title:"Bouncing Back After a Called Strike Three",diff:1,cat:"mental-game",ageMin:8,ageMax:99,
      description:"You just struck out looking on a close pitch. You're angry. You're up again next inning. What's your approach?",
      situation:{inning:"Bot 4",outs:1,count:"0-0",runners:[],score:[2,3]},
      options:["Swing at everything to make up for it","Take a deep breath, reset, and look for your pitch","Try extra hard to hit a home run","Complain to the umpire about the last call"],
      best:1,explanations:["Swinging at everything because you're angry leads to chasing pitches out of the zone, since frustration makes your strike zone bigger and your swing less controlled.","Taking a deep breath resets your mind and body. The last at-bat is over — you can't change it. By calming down and looking for your pitch, you give yourself the best chance to make solid contact, because a clear head sees pitches better than an angry one.","Trying to crush a home run when you're emotional changes your swing mechanics and usually leads to pop-ups or strikeouts, since you're swinging harder instead of smarter.","Complaining to the umpire wastes your mental energy and can get you in trouble. The call is already made, and arguing won't change it — but it will distract you from preparing for your next at-bat."],
      explSimple:["Swinging at everything because you're mad means you'll chase bad pitches.","Take a deep breath and forget about the last at-bat. A calm mind sees pitches better!","Trying to hit a home run when you're angry usually means you'll swing too hard and miss.","Complaining to the umpire won't change the call and just makes you more upset."],
      rates:[30,80,35,20],concept:"After a tough at-bat, reset your emotions — a deep breath and a clear mind give you the best chance next time up",anim:"strike"},
    {id:"b_ppr1",conceptTag:"pre-pitch-routine",title:"Getting Ready in the On-Deck Circle",diff:1,cat:"mental-game",ageMin:8,ageMax:99,
      description:"You're in the on-deck circle about to hit. The pitcher is throwing hard and mixing in a slider. What should you be doing to prepare?",
      situation:{inning:"Top 3",outs:0,count:"0-0",runners:[1],score:[1,1]},
      options:["Just take some hard practice swings to warm up your muscles","Watch the pitcher's release point and time his pitches while taking controlled swings","Talk to your teammates in the dugout until it's your turn","Stare at the scoreboard to check the count"],
      best:1,explanations:["Taking hard practice swings warms your muscles, but that's only half the job. You're missing the chance to study the pitcher's timing, arm slot, and pitch movement before you step in the box.","Watching the pitcher from the on-deck circle is your biggest advantage. You can time his fastball, see how his slider breaks, and pick up his release point — all before your at-bat even starts. Combine that with controlled practice swings that match his timing, and you step into the box already prepared.","Chatting with teammates wastes your most valuable scouting time. The on-deck circle gives you a front-row view of the pitcher's stuff, and ignoring that means you walk to the plate blind.","Checking the scoreboard doesn't help you hit. Your job in the on-deck circle is to study the pitcher and get your timing ready, since those are the things that directly help your at-bat."],
      explSimple:["Practice swings help your body, but you also need to watch the pitcher!","Watch the pitcher's arm and time his throws while you swing. You'll be ready when it's your turn!","Talking to teammates wastes your chance to study the pitcher before you bat.","The scoreboard doesn't help you hit. Watch the pitcher instead!"],
      rates:[40,80,25,25],concept:"Use the on-deck circle to study the pitcher's timing, release point, and pitch movement — step into the box prepared, not surprised",anim:"strike"},
    {id:"b_lf1",conceptTag:"learning-from-failure",title:"0-for-3 — What Do You Change?",diff:2,cat:"adjustments",ageMin:10,ageMax:99,
      description:"You're 0-for-3 today. First AB you popped up a high fastball. Second AB you grounded out on a low changeup. Third AB you swung through an outside slider. You're coming up for your 4th at-bat. What adjustment should you make?",
      situation:{inning:"Bot 7",outs:0,count:"0-0",runners:[2],score:[3,4]},
      options:["Change everything — completely different stance and swing","Look for the pattern in your outs and make one small adjustment","Swing harder — you just need to barrel one up","Don't change anything — you're due for a hit"],
      best:1,explanations:["Changing everything at once creates more problems than it solves, since overhauling your stance and swing mid-game means you're using mechanics you haven't practiced. Small adjustments are how good hitters adapt.","You popped up a high pitch, grounded out on a low pitch, and missed an outside pitch — the pattern is that you're chasing pitches outside your zone. The smart adjustment is to shrink your zone and be more selective: look for a pitch middle-in that you can drive, and lay off the edges. One focused adjustment is all you need.","Swinging harder when you're already having timing problems makes things worse, because your outs came from chasing — not from weak contact. More effort usually means less control.","Hoping you're 'due' ignores the fact that you've been fooled three different ways. Each at-bat is independent, and the pitcher will keep attacking your weaknesses unless you adjust."],
      explSimple:["Changing everything at once is too much. Make one small fix instead.","Look at your outs — you chased high, low, and outside. Be more patient and wait for your pitch!","Swinging harder won't help if you're swinging at the wrong pitches.","You're not 'due' for a hit. You need to adjust to what the pitcher is doing."],
      rates:[20,80,35,30],concept:"After multiple outs, find the pattern and make one small adjustment — don't overhaul everything, just fix what's getting you out",anim:"hit"},
    {id:"b_ss1",title:"Sign Systems — Hit-and-Run on 0-2",diff:2,cat:"situational",conceptTag:"sign-systems",ageMin:11,ageMax:99,
      description:"You're the batter with a runner on first base and 1 out. Your coach gives you the hit-and-run sign, but the count is 0-2. You're in a tough spot — the pitcher has you behind. What do you do?",
      situation:{inning:"Bot 5",outs:1,count:"0-2",runners:[1],score:[2,3]},
      options:["Execute the hit-and-run sign — your coach called the play and you trust the system","Ignore the sign — 0-2 is too risky for a hit-and-run, your coach must have missed the count","Foul the next pitch off on purpose to protect the runner","Step out of the box and look at the coach for confirmation"],
      best:3,explanations:["Blindly executing the hit-and-run on 0-2 puts the runner in extreme danger. On 0-2, the pitcher can waste pitches out of the zone, throw breaking balls in the dirt, or go for a strikeout pitch. If you swing and miss, the runner is a dead duck stealing. A hit-and-run at 0-2 is almost never intentional — it's more likely a sign mix-up.","Ignoring a coach's sign is never the right call. If you think there's an error, the correct response is to step out of the box and confirm. Ignoring the sign breaks trust and might get you benched. Maybe your coach has a reason you don't see.","Intentionally fouling a pitch off on 0-2 is a nice idea but incredibly hard to execute. You can't control where foul balls go, and an attempt to 'just foul it off' often results in a swing-and-miss strikeout. This isn't a reliable plan.","Stepping out of the box to confirm the sign is the smart, mature play. On 0-2, a hit-and-run is extremely unusual. Your coach may have given the sign before the count changed, or you may have misread the sequence. A quick look at the third base coach to re-check the sign costs you nothing and could save the runner from a caught stealing. Good players confirm when something feels wrong."],
      rates:[25,20,35,85],concept:"When a sign feels wrong for the situation — like a hit-and-run on 0-2 — step out and confirm with your coach before executing",explSimple:["A hit-and-run on 0-2 is almost never intentional. Confirm before you execute.","Never ignore a sign — step out and check with the coach instead.","Trying to foul a pitch off on purpose is extremely hard. Don't count on it.","Step out of the box and confirm! It costs nothing and could save the play."],anim:"hit"},
    // APPROACH-ADJUSTMENT scenarios
    {id:"b_aa1",title:"Fastball Pattern — Time to Adjust",diff:2,cat:"adjustments",conceptTag:"approach-adjustment",ageMin:11,ageMax:99,
      description:"The pitcher threw you 3 fastballs in a row — two inside and one up. You fouled off two and took a ball. Count is 2-1. What do you look for next?",
      situation:{inning:"Top 4",outs:1,count:"2-1",runners:[],score:[2,1]},
      options:["Sit on the fastball again — he's been throwing nothing else","Look off-speed — after 3 straight fastballs, a changeup or breaking ball is coming","Stay ready for fastball but don't commit — react to whatever comes","Step out of the box and reset your timing completely"],
      best:1,explanations:["After throwing 3 straight fastballs, most pitchers and catchers recognize the pattern and switch to something different. Sitting fastball again ignores the adjustment the battery is likely making — you need to stay one step ahead, not one step behind.","Smart adjustment! After 3 consecutive fastballs, the pitcher and catcher know you've timed the heater. A good battery changes the look — a changeup at 12 mph slower will freeze you if you're geared up for heat. On 2-1, the pitcher still needs a strike, so the off-speed will be in the zone. Anticipating the change of speed while staying ready to react keeps you ahead of the chess match.","Not committing to anything sounds safe, but being 'ready for everything' often means being ready for nothing. Great hitters have a plan each pitch — adjust your plan based on what you've seen, then commit. Reacting without a plan leads to late swings and weak contact.","Stepping out disrupts YOUR rhythm more than the pitcher's. You've already gathered three pitches of data — use it. Stepping out resets your timing advantage and gives the pitcher a free mental break."],
      explSimple:["After 3 fastballs, the pitcher will probably change it up. Sitting fastball again means you're not adjusting.","After 3 fastballs in a row, the pitcher knows you've timed his speed. Look for something slower — you'll be ready for the change.","Being ready for 'anything' really means being ready for nothing. Have a plan based on what you've seen.","Stepping out of the box wastes the information you already gathered from those 3 pitches."],
      rates:[35,80,40,15],concept:"After seeing multiple fastballs in a row, adjust your approach — anticipate the off-speed change",anim:"hit"},
    {id:"b_aa2",title:"Off-Speed Overload — Make an Adjustment",diff:2,cat:"adjustments",conceptTag:"approach-adjustment",ageMin:11,ageMax:99,
      description:"You fouled off 4 pitches in a row — all off-speed (two changeups, a slider, and a curve). You keep being just a little bit early. Count is 2-2. What adjustment do you make?",
      situation:{inning:"Bot 3",outs:0,count:"2-2",runners:[1],score:[1,1]},
      options:["Speed up your swing — you need to catch up to the off-speed","Slow down your load and stay back longer — let the ball travel deeper","Move up in the batter's box to hit the ball before it breaks","Sit fastball — he has to throw one eventually"],
      best:1,explanations:["Speeding up your swing is the opposite of what you need. You're already too early on off-speed — a faster swing makes the timing problem worse. When you're fooled by slow pitches, the fix is in your lower half, not your hands.","If you're consistently early on off-speed, your front foot is landing too soon. Slowing down your load and staying back keeps your weight on your back leg longer, giving you time to read the pitch and let it travel deeper into the zone. On 2-2, this approach also helps you lay off breaking balls that start in the zone and dive out — you see the full pitch path before committing.","Moving up in the box is a common misconception. While you would hit the ball before it breaks as much, you also reduce your reaction time on fastballs. With 2 strikes, you need to handle both speeds — moving up sacrifices your ability to catch up to heat.","Sitting fastball on 2-2 after seeing 4 straight off-speed pitches is a gamble. If the pitcher has thrown nothing but off-speed and it's working, he has no reason to change. You're hoping for a pitch that might never come — meanwhile, one more off-speed offering and you're out."],
      explSimple:["Speeding up your swing makes it worse — you're already swinging too early on slow pitches.","Stay back longer! Keep your weight on your back leg so you have more time to see the slower pitches before you swing.","Moving up in the box makes it harder to hit fastballs, and with 2 strikes you need to handle everything.","Sitting fastball when he keeps throwing off-speed is a gamble — he might never throw one."],
      rates:[15,80,35,40],concept:"When you're consistently early on off-speed, slow your load and stay back — let the ball travel deeper before committing",anim:"hit"},
    {id:"b_aa3",title:"Second At-Bat — He Got You on a Slider",diff:3,cat:"adjustments",conceptTag:"approach-adjustment",ageMin:13,ageMax:99,
      description:"Second at-bat against the same pitcher. He struck you out on a backdoor slider in the first inning — you froze on it because it looked like a ball off the hand, then caught the corner. Runner on 2nd, 1 out, down 3-2.",
      situation:{inning:"Bot 5",outs:1,count:"0-0",runners:[2],score:[2,3]},
      options:["Sit slider all the way — don't let him beat you with it again","Look fastball but widen your zone on the outer half to cover the slider","Choke up and shorten your swing — just try to make contact on everything","Crowd the plate so the slider can't catch the outside corner"],
      best:1,explanations:["Sitting slider leaves you completely vulnerable to the fastball. He struck you out on the slider in the first AB, so he knows you're thinking about it — a smart pitcher will use that fear against you by pumping fastballs. Guessing one pitch gives him three others to beat you with.","In your first at-bat, the slider froze you because you read it as a ball off the hand. Now you know it starts off the plate and bends back over the corner. Look fastball as your base plan, but expand your zone awareness on the outer half — if you see spin heading toward the outside corner, you stay ready to fight it off. Your first at-bat gave you data. Use it without abandoning your fastball timing.","Choking up and shortening your swing is a two-strike adjustment, not a first-pitch plan. Starting an at-bat in survival mode gives away your chance to drive a mistake pitch. With a runner on 2nd and 1 out, you want to be aggressive on hittable pitches, not defensive from the start.","Crowding the plate takes away the outside corner but opens you up to inside pitches. A smart pitcher sees you crowding and switches inside with hard stuff — now you're jammed. Plate positioning changes are extreme adjustments that create new vulnerabilities."],
      explSimple:["Sitting only on the slider means the fastball will blow right by you.","Smart! Look for the fastball but keep your eyes wider on the outside half so the slider won't freeze you again.","Starting in survival mode gives away your chance to drive a good pitch early in the count.","Crowding the plate takes away outside pitches but leaves you wide open to inside pitches."],
      rates:[30,80,25,35],concept:"Second time facing a pitcher, adjust your zone awareness based on what beat you — do not abandon your base approach",anim:"hit"},
    // PITCH-RECOGNITION scenarios
    {id:"b_pr1",title:"Fastball or Breaking Ball? Read the Drop",diff:2,cat:"adjustments",conceptTag:"pitch-recognition",ageMin:11,ageMax:99,
      description:"The pitch looks like a fastball out of the pitcher's hand but it starts dropping sharply about halfway to the plate. You haven't started your swing yet. Count is 1-1, nobody on.",
      situation:{inning:"Top 3",outs:1,count:"1-1",runners:[],score:[0,0]},
      options:["Swing — it looked like a fastball, so attack it","Hold up and take it — the drop means it's a breaking ball heading out of the zone","Start your swing but try to adjust mid-swing to hit where the ball is going","Bail out of the box — it might hit you"],
      best:1,explanations:["A pitch that drops sharply after looking like a fastball is a breaking ball with late movement. Swinging at your original read — the fastball plane — means your bat path will be above the ball. You'll either whiff completely or top it weakly into the ground. Recognizing the spin change early saves you from a bad swing.","When the ball drops sharply after a fastball look out of the hand, your eyes are telling you the pitch has breaking ball spin. Holding up on 1-1 is a smart play — you have a count where you can afford to take a ball. A sharp-dropping pitch is likely heading below the zone, and taking it keeps the count even at 2-1 or puts you at 1-2 with information. Your pitch recognition just saved you from chasing.","Adjusting mid-swing almost never works. Once your swing is committed, your bat path is set — trying to redirect a swing that's already in motion produces weak, off-balance contact at best. Good hitters make a go or no-go decision before the swing starts, not during it.","A pitch dropping down is not coming toward you — bailing out wastes an opportunity to gather information. A curveball or slider drops away from you, not into you. Recognizing pitch movement direction is part of reading the pitch."],
      explSimple:["A pitch that drops sharply is a breaking ball — swinging at the fastball height means you'll miss.","If the ball starts dropping, it's a breaking ball heading out of the zone. Take it and stay even in the count.","You can't really change your swing once it starts — decide before you swing, not during.","The ball is dropping down, not coming at you — no need to bail out."],
      rates:[25,80,40,20],concept:"When a pitch drops sharply after a fastball look, recognize the breaking ball spin and hold your swing",anim:"strike"},
    {id:"b_pr2",title:"Deciding to Swing — Before It Arrives",diff:2,cat:"adjustments",conceptTag:"pitch-recognition",ageMin:11,ageMax:99,
      description:"Your coach tells you that you have about 4/10 of a second to decide whether to swing once the pitcher releases the ball. The opposing pitcher throws 80 mph fastballs and has a big curveball. How do you decide whether to swing before the ball reaches you?",
      situation:{inning:"Top 1",outs:0,count:"0-0",runners:[],score:[0,0]},
      options:["Watch the ball all the way to the plate, then decide","Read the pitcher's arm speed and release point in the first 10 feet","Wait to see if it curves before deciding","Guess before each pitch and commit to swinging or not"],
      best:1,explanations:["Waiting until the ball is at the plate leaves zero time to decide and swing. A pitch traveling 80 mph reaches you in about 0.47 seconds. Your brain needs roughly 0.20 seconds to process and your swing takes about 0.15 seconds — there is no margin left if you wait until the ball arrives. The decision has to happen early.","Your decision starts the moment the ball leaves the pitcher's hand. In the first 10 feet of flight, you can read two critical clues: arm speed (fastball arm speed is faster than curveball arm speed) and release point (a curveball often has a slightly higher release with visible topspin). These early reads give your brain the head start it needs to decide swing or take before it's too late.","Waiting to see if it curves means you've already used up most of your decision time. By the time a curveball shows its break (about 20-25 feet from the plate), you have less than 0.2 seconds left — not enough time to commit to a quality swing. You need earlier information.","Guessing eliminates pitch recognition entirely. On days your guess is right, you look great. On days it's wrong, you look lost. Building real pitch recognition — reading arm speed and spin — gives you an edge every pitch, not just when you guess correctly."],
      explSimple:["You don't have time to wait until the ball is at the plate — you need to decide much earlier.","Read the pitcher's arm speed and how the ball looks coming out of his hand. That early info helps you decide fast enough.","Waiting to see the ball curve uses up too much time — by then it's too late to swing well.","Guessing works sometimes, but reading the pitch out of the hand works every time."],
      rates:[20,85,35,30],concept:"Read arm speed and release point in the first 10 feet of ball flight — that early information drives your swing decision",anim:"hit"},
    {id:"b_pr3",title:"Reading the Spin — Swing or Take?",diff:3,cat:"adjustments",conceptTag:"pitch-recognition",ageMin:13,ageMax:99,
      description:"You're locked in at the plate, and you've trained yourself to pick up spin. The pitcher releases and you see tight backspin with a red dot on the ball. Count is 2-0, runner on 1st and 3rd, 1 out.",
      situation:{inning:"Bot 6",outs:1,count:"2-0",runners:[1,3],score:[3,4]},
      options:["Swing — tight backspin with a red dot means slider, and you can drive it if it stays up","Take — the red dot means curveball heading out of the zone","Swing — tight backspin means four-seam fastball in the zone","Take — wait for 3-0 to make the pitcher come to you"],
      best:2,explanations:["A red dot can appear on sliders, but the key word here is 'tight backspin.' Sliders have side spin or gyro spin, not backspin. Confusing fastball spin for slider spin leads to taking hittable pitches, and on 2-0 you would waste a prime hitting count.","Curveballs have topspin, which looks like the ball is tumbling forward — the opposite of backspin. A red dot can appear on both sliders and curveballs, but tight backspin eliminates the curveball. Misreading this spin signature would have you taking a fastball right down the middle.","Tight backspin is the signature of a four-seam fastball. The ball appears to hold its plane because backspin creates lift. On 2-0 — a premium hitter's count — recognizing four-seam spin in the first few feet of flight tells you to attack. The red dot can appear on a fastball when the seams blur, and the backspin confirms it. With runners on 1st and 3rd and 1 out, driving a fastball here can break the game open.","Taking on 2-0 to get to 3-0 throws away one of the best pitches you'll see all at-bat. Hitters who swing at strikes on 2-0 have significantly higher slugging percentages than hitters who automatically take. You identified the fastball spin — attack it."],
      explSimple:["Sliders spin sideways, not backward — this backspin means fastball, not slider.","Curveballs tumble forward with topspin. Tight backspin means fastball, not curve.","Tight backspin means four-seam fastball! On 2-0, attack it — this is your pitch to drive.","Taking a fastball right down the middle on 2-0 just to get to 3-0 wastes a great opportunity."],
      rates:[30,25,80,35],concept:"Tight backspin identifies a four-seam fastball — in a hitter's count, recognizing that spin early lets you attack with confidence",anim:"hit"},
    // HOT-ZONE-AWARENESS scenarios
    {id:"b_hz1",title:"Your Hot Zone Says Swing — Count Agrees",diff:3,cat:"approach",conceptTag:"hot-zone-awareness",ageMin:13,ageMax:99,
      description:"You know from your stats that you hit .400 on pitches middle-in but only .100 on pitches away. The count is 2-1 — a hitter's count. The pitcher winds up and delivers inside.",
      situation:{inning:"Bot 5",outs:1,count:"2-1",runners:[2],score:[2,3]},
      options:["Take it — 2-1 means you can be patient and wait for 3-1","Swing hard — the pitch is in your hot zone AND it's a hitter's count","Look to go opposite field to show the pitcher you can hit anywhere","Pull back and try to bunt the runner over"],
      best:1,explanations:["Being patient on 2-1 is normally fine, but this pitch is middle-in — your .400 zone. You hit four out of ten pitches here for hits. Letting a pitch in your best zone go by in a hitter's count means you're ignoring two advantages stacked in your favor. The count will get better if it's a ball, but the pitch might never get better than this.","Two advantages are aligned: the count favors you (2-1 means the pitcher needs a strike) and the location is in your hot zone (.400 average middle-in). When count leverage and zone strength line up, elite hitters attack. With a runner on 2nd and 1 out, driving an inside pitch could score the tying run. You are not guessing — you are hunting a pitch you crush, and it arrived.","Going opposite field on an inside pitch works against your natural swing path. Middle-in pitches are designed to be pulled — trying to fight them the other way produces weak contact or foul balls. Play to your strength: turn on the inside pitch and drive it to your pull side.","Bunting with 1 out and a runner on 2nd in a hitter's count wastes your best opportunity to drive in a run. A bunt advances the runner to 3rd with 2 outs, but a base hit in your hot zone scores him. The expected value of swinging at a pitch you crush far exceeds the value of a sacrifice bunt."],
      explSimple:["Letting a pitch in your best zone go by wastes the advantage — you hit .400 on inside pitches!","Two things are in your favor: the count AND the location. When both line up, attack.","Fighting an inside pitch the other way produces weak contact — pull it where you're strong.","Bunting wastes your chance to drive in a run when you're getting a pitch in your hot zone."],
      rates:[30,80,25,30],concept:"When the count and your hot zone align, attack — stacked advantages are rare and valuable",anim:"hit"},
    {id:"b_hz2",title:"They Keep Attacking Your Weakness",diff:3,cat:"adjustments",conceptTag:"hot-zone-awareness",ageMin:13,ageMax:99,
      description:"The pitcher keeps throwing to your weak zone — low and away. You're 0-for-2 today with two weak groundouts on pitches in that area. He's clearly scouted you. Third at-bat, count is 1-0.",
      situation:{inning:"Bot 6",outs:0,count:"1-0",runners:[],score:[1,1]},
      options:["Move closer to the plate so 'away' becomes 'middle'","Shorten your swing and try to poke the ball the other way into the gap","Stay with your normal approach and wait for a pitch in your zone","Sit on a mistake — he might miss over the plate eventually"],
      best:1,explanations:["Moving closer to the plate is a big adjustment that creates a new vulnerability. Now inside pitches — which are normally in your comfort zone — become pitches that jam you. A smart pitcher sees you crowding and switches inside, turning your strength into a weakness. Plate positioning changes are high-risk and usually overcorrect.","The pitcher has a game plan: attack your .100 zone low-and-away. Rather than hoping he stops, adjust your swing to handle that location. Shortening up and trying to poke the ball to the opposite field turns a weakness into something manageable — even if you don't drive it, you can fight it into play and move baserunners. Adjusting your swing mechanics to cover your weak zone is smarter than moving in the box or waiting for a pitch that might never come.","Waiting for a pitch in your zone sounds patient, but the pitcher just got you out twice by staying away. He has no reason to come to your hot zone. Waiting for a pitch the pitcher will not throw is patience without purpose — you'll watch hittable strikes on the outside corner while looking for inside pitches that never arrive.","Sitting on a mistake requires the pitcher to mess up. He's located well enough to get you out twice already, and his catcher will keep calling pitches away. Banking on an error in execution when the pitcher is executing well is hoping, not hitting. Take control by adjusting your own mechanics."],
      explSimple:["Moving closer to the plate opens you up to getting jammed inside — it creates a new problem.","Shorten your swing and try to poke the outside pitch the other way. Turn your weakness into something you can handle.","The pitcher already got you out twice going away — he won't throw to your hot zone on purpose.","Hoping the pitcher makes a mistake is not a plan. Adjust your swing so you can handle the pitch he keeps throwing."],
      rates:[30,80,35,25],concept:"When the pitcher attacks your weak zone repeatedly, adjust your mechanics to cover it rather than hoping for a pitch in your strength",anim:"hit"},
    {id:"b_hz3",title:"Scouting Report — The Slider Whiffs Everyone",diff:3,cat:"approach",conceptTag:"hot-zone-awareness",ageMin:13,ageMax:99,
      description:"The scouting report says this pitcher's slider has a 40% whiff rate — hitters swing and miss on it nearly half the time. You're stepping in for your first at-bat. Count is 0-0. What's your plan?",
      situation:{inning:"Top 2",outs:0,count:"0-0",runners:[],score:[0,0]},
      options:["Sit slider first pitch — if you know it's coming, you can hit it","Eliminate the slider from your swing zone and hunt fastball","Take every slider and only swing at fastballs the entire at-bat","Swing at everything early to avoid getting to a 2-strike count where the slider dominates"],
      best:1,explanations:["A 40% whiff rate means even hitters who are looking for the slider miss it 40% of the time. Sitting on it does not neutralize it — the pitch breaks too late and too sharply for most hitters to square up even when they expect it. Planning to hit the unhittable pitch is not a smart use of scouting information.","A 40% whiff rate tells you the slider is nearly unhittable for most batters. The smart adjustment is to eliminate it from your plan — mentally take the slider off your swing list and focus on hunting the fastball or changeup. If the slider catches the zone for a called strike, accept it. Getting to an 0-1 count is better than chasing a slider for strike one AND losing your timing for the next pitch. Force the pitcher to beat you with his other pitches.","Taking every slider removes your ability to adjust if the slider catches the zone. Some sliders that start as strikes stay in the zone — if you've committed to never swinging at one, you'll watch called strikes and fall behind. The key is eliminating the slider from your SWING zone (pitches you chase), not from pitches you can recognize as strikes.","Swinging early to avoid deep counts is undisciplined. Aggressive hacking at early-count pitches leads to weak contact on pitches outside your zone. The goal is to make the pitcher throw pitches you can handle, not to panic-swing before the count gets tough."],
      explSimple:["Even when hitters know the slider is coming, they miss it 40% of the time. You can't just plan to hit it.","Eliminate the slider from your plan. Hunt the fastball instead and let the slider go — force him to beat you with other pitches.","Taking every slider no matter what means you'll watch called strikes. Be smart about which ones to take.","Swinging at everything just to avoid a 2-strike count leads to bad at-bats and weak contact."],
      rates:[25,85,30,25],concept:"When a pitcher has an elite swing-and-miss pitch, eliminate it from your plan and hunt his secondary offerings",anim:"strike"},
  ],
  secondBase: [
    {id:"f1", conceptTag:"double-play-turn",title:"Double Play Chance",diff:1,cat:"infield",ageMin:6,ageMax:99,
      description:"You're at 2nd base. Runner on 1st, 0 outs. Ground ball right at you. Runner isn't fast.",
      situation:{inning:"Top 5",outs:0,count:"0-0",runners:[1],score:[3,2]},
      options:["Tag 2nd, throw to 1st — double play","Throw to 1st for the sure out","Flip to SS covering 2nd","Hold and check the runner"],
      best:0,explanations:["Ball came right to you — tag 2nd (force out) and throw to 1st for the double play, because two outs!","One out is okay but you're leaving a free out on the field.","The flip adds an extra throw, since you're right there — do it yourself.","Holding the ball gives the runner time to advance — you need to make the play immediately!."],
      explSimple:["The ball came right to you! Step on second base, then throw to first to get two outs.","Throwing to first only gets one out. You could have gotten two!","You're standing right there at second — just step on the base yourself instead of flipping it.","Don't hold the ball! You need to make a throw and get someone out."],
      rates:[85,55,50,10],concept:"When a ground ball comes right to you, turn the double play yourself",anim:"doubleplay"},
    {id:"f12",title:"Relay Position",diff:2,cat:"outfield",conceptTag:"relay-double-cut",ageMin:11,ageMax:99,
      description:"Deep fly ball to the corner in right. Runner trying to score from 1st. You're the 2nd baseman going out for the relay.",
      situation:{inning:"Bot 5",outs:1,count:"0-0",runners:[1],score:[2,3]},
      options:["Line up between outfielder and home plate","Line up between outfielder and 3rd","Go to shallow right field","Stay near 2nd base"],
      best:0,explanations:["Perfect relay positioning! Remember, you get in a straight line between the outfielder and home plate.","The throw needs to go HOME, not 3rd — line up between the outfielder and home plate so the throw stays on a straight path.","Too close to the outfielder — you need distance for a relay so your throw has enough momentum to reach home.","Staying at 2nd means no relay — the throw bounces in."],
      explSimple:["Stand in a straight line between the outfielder and home plate so you can catch and throw it home quickly.","The runner is going home, so line up toward home plate — not third base.","Don't go too close to the outfielder. You need to be in the middle to make a good relay throw.","If you stay at second base, nobody catches the throw and it bounces all the way in."],
      rates:[85,35,25,15],concept:"On relay throws, line up directly between the outfielder and the target base",anim:"relay"},
    {id:"f14",title:"Bases Empty — Routine Grounder",diff:1,cat:"infield",conceptTag:"infield-positioning",ageMin:6,ageMax:99,
      description:"Bot 4th, nobody on, 1 out, tied 3-3. You're at second base. Routine ground ball hit right to you.",
      situation:{inning:"Bot 4",outs:1,count:"0-0",runners:[],score:[3,3]},
      options:["Throw to first base","Throw to second base","Hold the ball — no rush","Tag the base you're standing near"],
      best:0,explanations:["With nobody on base, throw to first! There's no force play anywhere else, which means field the ball cleanly, set your feet, and make a strong throw to first base for the out. Simple, fundamental baseball.","There's no runner going to second — nobody is on base! Throwing there accomplishes nothing.","Holding the ball lets the batter reach first safely — field it and throw, make the play!","Tagging second base does not create an out here — there is no force play at second, and the batter is running to first."],
      rates:[85,25,40,15],concept:"With nobody on base, every ground ball goes to first — know where to throw before the ball is hit",explSimple:["Great choice! With nobody on base, throw to first! There's no force play anywhere else.","Not the best move. There's no runner going to second — nobody's on base! Throwing there accomplishes nothing.","Not the best move. Holding the ball lets the batter reach first safely.","Not the best move. Tagging second base doesn't create an out — there's no force play."], anim:"groundout"},
    {id:"f17", conceptTag:"force-vs-tag",title:"Bases Loaded — Throw Home",diff:2,cat:"infield",ageMin:9,ageMax:99,
      description:"Top of the 3rd, bases loaded, 1 out, up 5-4. You're the second baseman. Hard ground ball hit right at you.",
      situation:{inning:"Top 3",outs:1,count:"0-0",runners:[1,2,3],score:[5,4]},
      options:["Throw home for the force out","Step on second and throw to first — double play","Tag the runner coming down the line","Flip to the shortstop covering second base"],
      best:0,explanations:["With bases loaded and 1 out, throwing home gets the force out AND prevents a run, because after the catcher catches it, he can throw to first for the double play. Protecting the plate is priority #1 with a 1-run lead.","The double play at second-first gets two outs but lets the runner on third score — that ties the game — with a 1-run lead, you can't give up that run.","Tagging a runner while others are advancing leaves bases occupied and a run scores from third.","Flipping to second gets one force out but lets the runner from third score, which means with bases loaded and a 1-run lead, throw home first to prevent the tying run."],
      rates:[85,50,20,40],concept:"With bases loaded, throw home first — prevent the run and set up the double play",explSimple:["With bases loaded and 1 out, throwing home gets the force out AND prevents a run.","The double play at second-first gets two outs but lets the runner on third score — that ties the game.","Tagging a runner only gets one out and lets a run score from third.","Flipping to second gets a force out but lets the run score."],anim:"throwHome"},
    {id:"f20", conceptTag:"double-play-turn",title:"Fast Runner — Can You Turn Two?",diff:3,cat:"infield",ageMin:12,ageMax:99,
      description:"Bot 5th, runner on 1st, nobody out, tied 3-3. The runner is their fastest player. Ground ball to second — you flip to short to start the DP.",
      situation:{inning:"Bot 5",outs:0,count:"0-0",runners:[1],score:[3,3]},
      options:["Turn the double play — every millisecond counts","Get the force at second and hold — don't rush the relay","Make the flip and let the shortstop decide","Skip the flip — throw directly to first"],
      best:1,explanations:["Trying to turn a DP against the fastest runner might result in a rushed wild throw, because two men on, nobody out is much worse.","When the runner is extremely fast, get the sure out at second, since a force out is guaranteed — but the relay throw to first might not beat the fastest runner. Take the sure out and avoid the error.","The shortstop will try to turn it, but a rushed throw against a blazing runner could be wild.","Throwing to first only gets one out and doesn't address the runner, because the force at second is better."],
      rates:[30,85,40,25],concept:"Against very fast runners, get the sure out at second — don't force a double play and risk an error",anim:"groundout"},
    {id:"f47", conceptTag:"infield-positioning",title:"Runner on Second — Hold or Play Back?",diff:1,cat:"positioning",ageMin:6,ageMax:99,
      description:"Bot 3rd, runner on 2nd, nobody out, tied 1-1. You're the second baseman. Should you play at double play depth even though there's no runner on first?",
      situation:{inning:"Bot 3",outs:0,count:"1-1",runners:[2],score:[1,1]},
      options:["Double play depth — try to get the runner heading to third","Normal depth — maximize your range","Play in — cut off the run at home","Split the difference — shade toward 2nd a bit"],
      best:1,explanations:["With only a runner on 2nd, you'd have to tag the runner at third, since you can't just step on the bag. Without a runner on first there's no conventional double play, so playing at DP depth wastes your range for an unlikely tag play.","With a runner on 2nd and nobody out, play at normal depth — your job is to get outs. If the ball is hit to you, throw to first for the out. Glance at the runner on second, but he's not your primary concern — getting the batter out is.","Playing in with a runner on 2nd and nobody out is too aggressive — you give up too much range and let ground balls get through.","Shading toward 2nd is not needed without a runner on first — play normal depth and focus on getting outs."],
      rates:[20,85,30,35],concept:"With only a runner on 2nd, play normal depth — no conventional DP is available without a runner on first",explSimple:["No conventional double play is available with only a runner on 2nd — there's no.","Great choice! With a runner on 2nd and nobody out, play at normal depth.","Not the best move. Playing in with a runner on 2nd and nobody out is too aggressive — you.","Not the best move. Shading toward 2nd isn't needed without a runner on first."], anim:"groundout"},
    {id:"f60", conceptTag:"rundown-mechanics",title:"Rundown — How Many Throws?",diff:1,cat:"communication",ageMin:6,ageMax:99,
      description:"Top of the 6th, runner caught in a rundown between first and second. You're the second baseman with the ball. The first baseman covers first. How do you handle this?",
      situation:{inning:"Top 6",outs:0,count:"0-0",runners:[1],score:[3,3]},
      options:["Chase him toward first and throw to the first baseman — one throw","Run at him full speed and tag him yourself","Pump fake a few times to freeze him, then tag","Throw the ball back and forth until he makes a mistake"],
      best:0,explanations:["A rundown should take ONE throw, maximum two, because fewer throws mean fewer chances for errors. Run hard at the runner, driving him back toward first base. When you get close enough that the first baseman can tag him, make a firm throw. The first baseman catches and tags. One throw, one out. The more throws you make, the more chances for an error.","Running at him yourself works if you're fast enough, but a throw to the first baseman is more reliable and gives a better angle for the tag. You also risk a collision if the runner reverses direction suddenly.","Pump fakes waste time and give the runner a chance to reverse direction and escape. In a rundown you want to be aggressive and decisive — run hard, throw once, and get the out quickly before other runners advance.","Throwing back and forth is the worst rundown technique because every throw is a chance for an error. The ball could sail, get bobbled, or arrive late. Keep it simple — one throw, one out."],
      rates:[85,40,30,10],concept:"Rundowns should take one throw — run hard at the runner, drive him back, make one firm throw for the tag",explSimple:["Great choice! A rundown should take ONE throw, maximum two.","Not the best move. Running at him yourself works if you're fast enough, but a throw is more reliable.","Not the best move. Pump fakes waste time and give the runner a chance to reverse direction.","Not the best move. Throwing back and forth is the worst rundown technique."], anim:"catch"},
    {id:"2b1", conceptTag:"double-play-turn",title:"Turning Two at the Pivot",diff:1,cat:"fielder",ageMin:6,ageMax:99,
      description:"You're the second baseman. Runner on first, one out, and the batter hits a ground ball to the shortstop. Your SS fields it cleanly and fires to you at second base. You catch the ball on the bag — what do you do next?",
      situation:{inning:"Top 4",outs:1,count:"1-0",runners:[1],score:[3,2]},
      options:["Catch the ball, drag your foot across the bag, and make a quick throw to first","Hold the ball at second and settle for just the force out","Catch it and run toward first base before throwing","Catch the ball and immediately throw to third base"],
      best:0,explanations:["Perfect double play pivot! You catch the throw, touch second base with your foot, and fire to first in one smooth motion, because quick hands and footwork turn two outs — that's textbook.","Getting one out is okay, but with a runner on first and a ground ball, this is a golden double play chance, since you always want to try to complete the turn unless the runner is right on top of you.","Running toward first wastes precious time, because the batter is sprinting down the line. You need to get rid of the ball quickly from second base — your arm is strong enough to make the throw from there.","Throwing to third makes no sense here — there's no force play at third and no runner heading there — the double play goes to first base. Always know where the next out needs to be."],
      rates:[88,35,15,20],concept:"On a double play pivot, catch the ball, touch the bag, and make a quick accurate throw to first — footwork and fast hands are everything.",explSimple:["Perfect double play pivot! You catch the throw, touch second base with your foot,.","Not the best move. Getting one out is okay, but with a runner on first and a ground ball,.","Not the best move. Running toward first wastes precious time.","Not the best move. Throwing to third makes no sense — there's no force play there and no runner heading that way."], anim:"doubleplay"},
    {id:"2b2", conceptTag:"infield-positioning",title:"Ball Up the Middle",diff:2,cat:"fielder",ageMin:9,ageMax:99,
      description:"You're the second baseman. Runner on first, one out, and the batter smacks a hard ground ball up the middle, just to the right of second base. You were shading toward first for the double play. How should you position and play this ball?",
      situation:{inning:"Bot 5",outs:1,count:"2-1",runners:[1],score:[1,1]},
      options:["Cheat toward second base before the pitch so you can range to your left, backhand the ball, and start the double play at second","Stay near first base since you're in DP depth — let the ball go through to center field","Dive for the ball and flip it from your knees to the shortstop covering second","Range to your left, field it, then spin all the way around to throw to second for the force"],
      best:0,explanations:["Great positioning! Because there's a runner on first with one out, you shade toward second base before the pitch, which gives you better range on balls up the middle. Backhanding the ball and feeding it to the shortstop at second starts the double play, since you getting the lead runner is the priority in a DP situation.","Letting the ball go through gives up an easy single, which means runners on first and second with one out instead of a potential double play. Since you have a DP opportunity, you need to make every effort to reach that ball because you turning two ends the inning.","Diving and flipping from your knees is a desperation play, because the flip will be weak and inaccurate. Since you need a strong, quick feed to start the double play, staying on your feet gives your shortstop a much better chance to complete the turn.","Spinning all the way around wastes too much time, which means the runner from first is already at second before you release the ball. Since the DP relay needs to be quick — catch, pivot, throw — the spin kills any chance of getting two outs."],
      rates:[85,15,25,25],concept:"With a runner on first and less than two outs, shade toward second base before the pitch — better positioning means better range on balls up the middle and a chance to start the double play.",explSimple:["Shade toward second before the pitch so you can range left and start the DP.","Letting the ball through gives up a single instead of a potential double play.","Diving and flipping from your knees is a desperation play.","Spinning all the way around wastes too much time for the DP relay."],anim:"groundout"},
    {id:"2b3",title:"Covering First on the Bunt",diff:1,cat:"fielder",conceptTag:"bunt-defense",ageMin:10,ageMax:99,
      description:"You're the second baseman. Runner on first, no outs, and the other team is bunting. Your first baseman charges toward home plate to field the bunt. The bunt rolls toward the pitcher. Who covers first base?",
      situation:{inning:"Top 3",outs:0,count:"1-1",runners:[1],score:[0,0]},
      options:["Sprint to first base to cover the bag — you're the one who takes over when the 1B charges","Charge toward the bunt to help field it","Run to second base instead in case the lead runner goes there","Wait and see what happens before you move"],
      best:0,explanations:["Exactly right! When the first baseman charges a bunt, the second baseman MUST hustle over to cover first base, which means this is your responsibility on every bunt play — get there fast and give the fielder a target!","Charging toward the bunt takes you in the wrong direction — the pitcher and third baseman handle the ball, because your job is to get to first base so there's someone to receive the throw.","The shortstop covers second base on this play, not you. Your job is first base. If you both go to second, nobody covers first and the batter gets a free base.","Waiting and watching is the worst thing you can do on a bunt play, since everything happens fast — you need to be sprinting toward first the instant you see the bunt go down. Hesitation means the runner is safe."],
      rates:[90,25,40,15],concept:"On a bunt play when the first baseman charges, the second baseman must sprint over to cover first base — hesitation means a free base.",explSimple:["Great choice! Exactly right! When the first baseman charges a bunt, the second baseman MUST hustle over.","Not the best move. Charging toward the bunt takes you away from first base — someone needs to be there.","Not the best move. The shortstop covers second base on this play, not you.","Not the best move. Waiting and watching is the worst thing you can do on a bunt play."], anim:"bunt"},
    {id:"2b4", conceptTag:"relay-double-cut",title:"Relay From Right Field",diff:1,cat:"fielder",ageMin:6,ageMax:99,
      description:"You're the second baseman. Runner on first, one out, and the batter hits a line drive into the right field gap. The ball rolls to the wall. The runner from first is rounding second and heading to third — and he looks like he might keep going. You're the relay man — where do you position yourself?",
      situation:{inning:"Bot 6",outs:1,count:"0-0",runners:[1],score:[4,3]},
      options:["Line yourself up between the right fielder and third base, arms up, calling for the ball","Line up between the right fielder and home plate","Stay near second base and let the shortstop handle the relay","Run out toward right field to get as close to the outfielder as possible"],
      best:1,explanations:["Lining up to third can work if the runner clearly stops there, but your default should always be toward home, because preventing runs is the priority, and your teammates can yell to redirect you if needed.","Perfect relay positioning! Your default is always to line up between the outfielder and home plate. Preventing the run is the #1 priority. Put your arms up high so the outfielder can see you, and listen for your teammates — they'll tell you where to throw. If the runner stops at third, you can cut it and hold.","The second baseman IS the relay man on balls hit to right field. The shortstop covers second base. If you don't go out for the relay, the outfielder has to make a long throw all by himself.","Going too far toward the outfielder defeats the purpose. You want to be about halfway so you can catch the throw and quickly relay it. If you're too deep, you're just an extra step that slows things down."],
      rates:[55,85,15,20],concept:"On a relay from right field, the second baseman lines up between the outfielder and home plate — preventing runs is always the default priority.",explSimple:["Not the best move. Lining up to third can work if the runner clearly stops there, but your default.","Perfect relay positioning! Your default is always to line up between the outfielder and home plate.","Not the best move. The second baseman IS the relay man on balls hit to right field.","Not the best move. Going too far toward the outfielder defeats the purpose."], anim:"advance"},
    {id:"2b5", conceptTag:"steal-window",title:"Tag Play at Second Base",diff:2,cat:"fielder",ageMin:9,ageMax:99,
      description:"You're the second baseman covering second base on a steal attempt. The runner on first takes off for second, and the catcher fires a strong throw. The ball is coming to you on the shortstop side of the bag. How do you apply the tag?",
      situation:{inning:"Top 2",outs:0,count:"1-2",runners:[1],score:[0,0]},
      options:["Straddle the bag, catch the ball, and sweep your glove down in front of the base to tag the runner's feet as he slides in","Catch the ball and chase the runner to tag him","Stand behind the bag and wait for the runner to slide into your glove","Catch the ball and slap the tag on the runner's head or shoulders"],
      best:0,explanations:["Textbook tag! You straddle the bag so you're in a strong position, catch the throw, and sweep your glove down right in front of the base — the runner slides right into your tag. Quick and clean — that's how you get the out.","Never chase a runner when you're already at the base! You have the ball and you're at second — let the runner come to you, which means chasing wastes time and might cause a collision.","Standing behind the bag means the runner touches the base before your tag gets there, because you need to put the tag in FRONT of the base so the runner slides into it. Position is everything on a tag play.","Tagging up high is dangerous and can hurt the runner. Always tag low, near the feet or legs, as the runner slides in. It's safer and more effective because that's what reaches the base first."],
      rates:[85,15,25,20],concept:"On a steal tag play, straddle the bag and sweep the glove tag down in front of the base — let the runner slide right into it.",explSimple:["You straddle the bag so you're in a strong position, catch the throw, and sweep your glove down right in front of the base.","Never chase a runner when you're already at the base!","Standing behind the bag means the runner touches the base before your tag gets there.","Tagging up high is dangerous and can hurt the runner."],anim:"tag"},
    {id:"2b6", conceptTag:"fly-ball-priority",title:"Pop Fly in Shallow Right",diff:1,cat:"fielder",ageMin:6,ageMax:99,
      description:"You're the second baseman. Runner on third, one out, tie game. The batter pops the ball up in shallow right field — it's a tweener between you, the first baseman, and the right fielder. All three of you are converging. What should you do?",
      situation:{inning:"Bot 7",outs:1,count:"0-2",runners:[3],score:[5,5]},
      options:["Call for it yourself — you're coming out on the ball","Peel off and let the right fielder take it — he's charging in with momentum toward the infield","Let the first baseman take it since he's closer to home plate","Stop running and duck so nobody crashes into each other"],
      best:1,explanations:["You're going back on this ball, which is the hardest catch in baseball — the ball drifts away from you and you're running blind. The right fielder charging in can see the ball in front of him the entire way. Plus, with a runner on third and one out, the RF's forward momentum gives him a better throwing position for the tag-up play at home.","Correct! Outfielders coming in always have priority over infielders going back. The right fielder has the ball in front of him, better depth perception, and forward momentum. With a runner on third tagging up, the RF is also in a much better position to catch and throw home — his momentum is already heading toward the infield. Two reasons to let the outfielder take it!","The first baseman going back has the same problem you do — he's running away from the ball, since plus, with a runner on third, the first baseman needs to get back to his position in case of a play. Let the outfielder handle it.","Stopping and ducking might avoid a collision, but it also means nobody catches the ball! After all, someone has to take charge — and on tweeners between infield and outfield, the outfielder coming in is always the priority fielder."],
      rates:[40,85,20,10],concept:"Outfielders coming in have priority over infielders going back — with a runner on third, the outfielder's forward momentum also sets up a better throw home on a tag-up.",explSimple:["Not the best move. You're going back on this ball, which is the hardest catch in baseball —.","Great choice! Correct! Outfielders coming in always have priority over infielders going back.","Not the best move. The first baseman going back has the same problem you do — he's running.","Not the best move. Stopping and ducking might avoid a collision, but it also means nobody catches the ball!"], anim:"catch"},
    {id:"2b7", conceptTag:"infield-positioning",title:"Holding the Runner at Second",diff:3,cat:"fielder",ageMin:12,ageMax:99,
      description:"You're the second baseman in a close game. There's a speedy runner on second base with a big lead. The pitcher works from the stretch. Your coach wants you to keep that runner close to second so he can't score easily on a single. What's your move?",
      situation:{inning:"Top 7",outs:1,count:"0-0",runners:[2],score:[3,3]},
      options:["Fake like you're going to cover second to keep the runner honest, then get back to your fielding position before the pitch","Stay at your normal fielding position and let the pitcher hold him","Stand right on second base the entire at-bat to guard the runner","Call for a pickoff play with the pitcher"],
      best:0,explanations:["Smart play! By faking toward the bag, you freeze the runner and keep his lead short, because then you hustle back to your fielding position before the pitch so you're ready for a ground ball. This cat-and-mouse game keeps the runner close without hurting your defense.","Ignoring the runner lets him take a huge secondary lead — if a single is hit, he'll score easily from second. Part of your job as a middle infielder is to control the running game.","Standing on the bag the whole time leaves a massive hole in the defense on the right side, which means the batter could hit a ground ball through your empty position. You have to balance holding the runner AND being ready to field.","A pickoff play requires pitcher coordination and takes time to set up, because your positioning and movement fakes give you quicker, more effective control of the runner without needing to call a special play."],
      rates:[90,40,25,15],concept:"Hold runners close by faking toward the bag, then hustle back to fielding position before the pitch — balance runner control with defensive positioning.",anim:"freeze"},
    {id:"2b8", conceptTag:"hit-and-run",title:"Hit and Run Coverage",diff:3,cat:"fielder",ageMin:12,ageMax:99,
      description:"You're the second baseman. Runner on first, one out, and you suspect the other team is running a hit-and-run play. As the pitcher delivers, you see the runner take off from first. The batter swings and hits a ground ball toward the hole between first and second. Where should you be?",
      situation:{inning:"Bot 4",outs:1,count:"1-1",runners:[1],score:[2,1]},
      options:["Stay near your normal position to field the ground ball — since you didn't break to cover second, you're perfectly placed to make the play","Sprint to the outfield grass to back up the play","Charge toward home plate to cut off the ground ball","Move toward first base to help the first baseman"],
      best:0,explanations:["On a hit-and-run, the shortstop usually covers second. Your job as the second baseman is to stay home and cover the right side of the infield. Because you held your position, you're right there to field the ground ball and get the out. Smart baseball!","Sprinting to the outfield grass takes you completely out of the play, because the ground ball is coming right through your zone, and running away from it gives up an easy single. Stay home and make the play!","There's no reason to charge toward home plate on a ground ball hit to your area, since you stay in your zone and make the play. Charging in takes you away from the ball.","The first baseman can handle his own position, because your job is to cover the area between first and second. Moving toward first creates a gap in the defense right where the ball is heading."],
      rates:[90,40,15,25],concept:"On a hit-and-run, the second baseman holds position to cover the right side while the shortstop covers second — don't leave your zone empty.",anim:"groundout"},

    {id:"2b9", conceptTag:"infield-positioning",title:"Slow Roller Up the Middle",diff:1,cat:"fielder",ageMin:6,ageMax:99,
      description:"You're the second baseman. Nobody on base, two outs, and the batter chops a slow ground ball up the middle toward second base. The ball is trickling through the grass and losing speed fast. You charge in to field it. What's your play?",
      situation:{inning:"Top 5",outs:2,count:"1-2",runners:[],score:[2,1]},
      options:["Charge hard, field the ball out in front of you, and make a strong throw to first while your momentum carries you forward","Wait at your position and let the ball roll to you, then tag the runner passing by","Field the ball and run it toward first base before throwing","Charge in, pick it up with your bare hand, and flip underhand to the pitcher covering first"],
      best:0,explanations:["Great play! On a slow roller, you have to attack the ball — don't let it play you. Since the ball is losing speed fast, charging forward gives you two advantages: you get to the ball faster while it still has some hop to it, and your forward momentum adds power to your throw. Field it out in front, transfer quickly, and fire to first.","Waiting for a slow roller to come to you is a recipe for an infield single — the ball is dying in the grass, and there's no runner near you to tag. You have to charge aggressively and throw to first to have any chance at the out.","Running the ball toward first wastes precious time, which means your arm is faster than your legs! Field it and throw — that's always quicker than trying to hand-deliver the ball. The batter will beat you in a foot race.","A bare-hand flip to the pitcher covering first sounds fancy, but it's risky and unnecessary here because the ball is up the middle, not on the first base line. You have time to field it in your glove and make a normal throw. Save the bare hand for the really tough slow rollers close to the line, since those are the only plays where the time saved justifies the risk."],
      rates:[85,15,30,40],concept:"On a slow roller, charge the ball aggressively — your forward momentum helps you field it cleanly and adds power to your throw to first.",explSimple:["Great play! On a slow roller, you have to attack the ball — don't let it play you.","Not the best move. Waiting for the ball and trying to tag someone? There's no runner near you to tag!","Not the best move. Running the ball toward first wastes precious time.","Not the best move. A bare-hand flip to the pitcher covering first sounds fancy, but it's risky and unnecessary here."], anim:"groundout"},
    {id:"2b10", conceptTag:"double-play-turn",title:"Double Play Feed From the Pitcher",diff:2,cat:"fielder",ageMin:9,ageMax:99,
      description:"You're the second baseman. Runner on first, nobody out. The batter hits a come-backer to the pitcher, who fields it and turns to throw to you at second base to start the double play. The throw is coming — how do you handle the feed and make the turn?",
      situation:{inning:"Bot 3",outs:0,count:"0-1",runners:[1],score:[1,1]},
      options:["Catch the ball at the bag, touch second with your left foot, and use the pitcher's throw momentum to redirect a quick sidearm throw to first","Field it, step on the bag with your right foot, then turn and throw to third base","Secure it and hold — the force out at second is enough with nobody out","Catch it, but jump high in the air to avoid the sliding runner before throwing"],
      best:0,explanations:["Textbook pivot on a feed from the pitcher! You catch the ball, touch the bag with your left foot as you step across the base, and redirect a quick sidearm throw to first, because using the momentum of the incoming throw helps you get the ball to first faster. Smooth footwork turns two!","Stepping on second and throwing to third makes no sense — there’s no force play at third on this play. The double play goes second to first, not second to third. Always know where the outs are.","Just taking the force out at second wastes a golden double play opportunity, because with nobody out, getting two outs on one play changes the whole inning. Always try to complete the double play when you can.","Jumping high makes your throw inaccurate and costs you time in the air, because a small step across the bag to the infield side is all you need to clear the runner. Stay low, stay quick, and get the ball to first."],
      rates:[85,35,20,25],concept:"On a double play feed from the pitcher, touch second with your left foot and redirect a quick sidearm throw to first — footwork and momentum are the keys.",explSimple:["the right way to do it pivot on a feed from the pitcher!","Not the best move. Throwing to third makes no sense — the double play goes second to first.","Just taking the force out at second wastes a golden double play opportunity.","Jumping high makes your throw inaccurate and costs you time in the air."],anim:"doubleplay"},
    {id:"2b11",title:"Bunt Play — Cover First!",diff:2,cat:"fielder",conceptTag:"bunt-defense",ageMin:10,ageMax:99,
      description:"You're the second baseman. Runner on first, no outs, and the batter squares to bunt. The first baseman charges hard toward home plate, the pitcher breaks toward the third base line, and the third baseman charges too. The bunt is down — a decent one rolling toward the pitcher. Where do you need to be?",
      situation:{inning:"Top 6",outs:0,count:"1-0",runners:[1],score:[3,2]},
      options:["Sprint to cover first base — the first baseman left it empty when he charged the bunt","Back up the pitcher in case the throw to first is wild","Stay in your normal position and watch the play develop","Move toward the mound area to back up the pitcher's throw"],
      best:0,explanations:["You nailed it! When the first baseman charges a bunt, first base is wide open and someone MUST cover it — the cost of missing this coverage is a free base. That's YOUR job as the second baseman. Sprint to the bag, get there before the throw, and give the fielder a clear target. If nobody covers first, the batter gets a free base even on a great defensive play.","The shortstop covers second base on a bunt play, not you, since your responsibility is first base. If both middle infielders go to second, nobody is at first and the defense falls apart — the fielder has nobody to throw to.","Standing and watching is never the answer on a bunt play. Every fielder has a job, and yours is to cover first base the instant you see the bunt go down. If you hesitate even a second, you won't get there in time.","Backing up the throw sounds helpful but leaves first base uncovered, because the catcher is the one who backs up throws in the infield. Your job is to get to that first base bag — there's nobody else who can do it."],
      rates:[90,40,15,25],concept:"On a sacrifice bunt, the second baseman must sprint to cover first base when the first baseman charges — every fielder has a specific bunt responsibility.",explSimple:["When the first baseman charges a bunt, first base is wide open and someone MUST cover it.","Not the best move. Charging toward the bunt puts three fielders on the ball and leaves first base empty.","Standing and watching is never the answer on a bunt play.","Backing up the throw sounds helpful but leaves first base uncovered."],anim:"bunt"},
    {id:"2b12",title:"Pop Fly — You or the Right Fielder?",diff:1,cat:"fielder",conceptTag:"fly-ball-priority",ageMin:6,ageMax:99,
      description:"You're the second baseman. Runner on third, one out, close game. The batter pops the ball up into shallow right field. You're drifting back for it and the right fielder charges in hard. The ball is hanging up there — who should catch it?",
      situation:{inning:"Bot 6",outs:1,count:"1-1",runners:[3],score:[4,5]},
      options:["Let the right fielder take it — he's coming in and can see the ball better","Call for it loudly and catch it yourself since you're closer","Let the first baseman take it since he's on that side of the field","Stay quiet and just get out of the way so nobody collides"],
      best:0,explanations:["Smart decision! The right fielder charging in has the ball in front of him the entire time — much easier to track and catch. Running in always beats running back — outfielders have priority on any ball they can reach while running in. You give way and peel off when RF calls it. This is the same principle throughout the outfield: center field has priority because they're always running IN — corner outfielders back off when CF calls it. You do the same for the RF here.","You're drifting back, which means the ball is moving away from you — that's one of the hardest catches in baseball. The right fielder running in can see the ball clearly in front of him the whole way. Outfielders coming in always have priority over infielders going back.","The first baseman would have to range far from his position and he'd be going back on the ball too — this is between you and the right fielder, and the right fielder has the better angle every time.","Never stay quiet on a fly ball! Someone MUST call for it or you risk a collision and a dropped ball, which means communication saves games — and prevents injuries. The right fielder should call for it, and you should peel off."],
      rates:[85,40,15,10],concept:"Outfielders charging in always have priority over infielders going back — the ball is easier to catch running forward, and with a runner on third, the outfielder has better throwing momentum toward home.",explSimple:["Smart decision! The right fielder charging in has the ball in front of him.","Not the best move. You're drifting back, which means the ball is moving away from you — that's one.","Not the best move. The first baseman would have to range far from his position and he'd be going.","Not the best move. Never stay quiet on a fly ball! Someone MUST call for it or you risk."], anim:"catch"},
    {id:"2b13", conceptTag:"steal-window",title:"Tag at Second on the Steal",diff:2,cat:"fielder",ageMin:9,ageMax:99,
      description:"You're the second baseman and you're covering second base on a steal attempt. Runner on first takes off, and the catcher guns a throw to you. The throw is a little to the first base side of the bag. The runner is sliding in hard from the right. How do you apply the tag?",
      situation:{inning:"Top 4",outs:1,count:"0-2",runners:[1],score:[1,0]},
      options:["Catch the ball, bring your glove down quickly in front of the bag on the runner's path, and let him slide into the tag","Catch the ball and then chase the tag toward the runner's body","Catch it, but hold the tag up high waiting for the runner to pop up","Move your whole body in front of the runner to block the bag, then tag him"],
      best:0,explanations:["Perfect tag technique! Catch the throw, then sweep your glove down right in front of the base where the runner's feet are heading. You don't chase the runner — you put the tag in his path and let him slide into it. Quick hands and good positioning make this an easy out.","Chasing the tag toward the runner means extra movement and wasted time, because the runner is already coming to you at full speed — just put the glove in his path. Let his momentum do the work. Chasing the tag also risks the ball getting knocked loose.","Holding the tag up high while the runner slides in low means you miss the tag entirely. The runner's feet or hands arrive at the base first, so that's where the tag needs to be — down low, right in front of the bag.","Blocking the bag without the ball is obstruction, and even with the ball, putting your whole body in the runner's path is dangerous, since you could get hurt badly on a hard slide. Straddle the bag, stay to the side, and apply a quick sweep tag — safe and effective."],
      rates:[85,30,20,15],concept:"On a steal tag, catch the throw and sweep the glove down in front of the base — let the runner slide into your tag instead of chasing him.",explSimple:["Perfect tag technique!","Chasing the tag toward the runner means extra movement and wasted time.","Holding the tag up high while the runner slides in low means you miss the tag entirely.","Blocking the bag without the ball is obstruction, and even with the ball, putting your whole body in the runner's path is dangerous."],anim:"steal"},
    {id:"2b14", conceptTag:"infield-positioning",title:"Positioning vs. a Lefty Pull Hitter",diff:3,cat:"fielder",ageMin:12,ageMax:99,
      description:"You're the second baseman. Runner on first, one out, and a powerful left-handed pull hitter steps to the plate. Your coach calls for a defensive shift. Left-handed pull hitters crush the ball to the right side of the field. Where should you position yourself, and what are you thinking about?",
      situation:{inning:"Top 7",outs:1,count:"0-0",runners:[1],score:[5,4]},
      options:["Shade several steps toward first base into the hole between first and second — that's where a lefty pull hitter is most likely to hit ground balls, while still being ready to cover second on a steal or double play","Move to your normal position — shifts are only for the pros","Shade toward second base to be ready for the double play since there's a runner on first","Move all the way to the left side of the infield with the shortstop and third baseman"],
      best:0,explanations:["Excellent positioning! Left-handed pull hitters tend to drive the ball toward the right side of the field. By shading several steps toward the first base hole, you're putting yourself where the ball is most likely to go. But you're also smart enough to stay close enough to second that you can still get there for a steal or double play. It's about playing the percentages while staying responsible.","Shifts aren't just for the pros — they work at every level! If you know a batter tends to hit to one side, moving a few steps in that direction gives you a much better chance of making the play. Good defense is about being in the right spot BEFORE the pitch.","Moving toward second base takes you away from where this hitter is most likely to hit the ball, which means you're giving up range on the plays you'll see most often. Yes, there's a runner on first, but you can still turn a double play from a shifted position — you just take a slightly different angle to the bag. Don't sacrifice your best positioning just for the DP.","Moving all the way to the left side is way too extreme because that leaves the entire right side of the infield completely empty — the batter could just bunt or poke a ball the other way for an easy hit. A shift means adjusting a few steps, not abandoning your side of the field entirely."],
      rates:[82,20,35,15],concept:"Against left-handed pull hitters, shade toward first base where they're most likely to hit — play the percentages but stay close enough to second for steal and double play coverage.",anim:"groundout"},
    {id:"2b_new1",title:"DP Pivot — Feed to Shortstop",diff:2,cat:"defense",conceptTag:"double-play-turn",ageMin:9,ageMax:99,
      description:"Runner on 1st, 1 out. Ground ball hit right at you. You need to feed the shortstop covering second. What's the fastest, safest feed?",
      situation:{inning:"Top 5",outs:1,count:"1-1",runners:[1],score:[2,2]},
      options:["Underhand flip if close, overhand throw if deep","Always throw overhand — more accurate","Shovel it backhand regardless","Wait for SS to get set before throwing"],
      best:0,explanations:["Correct. The feed choice depends on distance from the bag. If you field the ball within 15 feet of 2nd, the underhand flip is faster and more accurate — no wasted arm action. Beyond 15 feet, overhand gives you the carry needed. Matching the throw to the distance is the mark of a skilled pivot man.","Always throwing overhand adds unnecessary arm movement on close plays, because within 15 feet, the underhand flip reaches SS in half the time with more control. Overhand at close range creates looping throws that arrive late.","The backhand shovel is a desperation move for balls hit to your glove side when you're off-balance — on a ball hit right at you, use the standard flip or overhand based on distance.","Waiting for SS to set defeats the purpose of the DP, which means the timing is choreographed — SS starts moving to the bag as you field the ball. Your job is to deliver immediately so he arrives just as the throw does."],
      rates:[90,40,25,15],concept:"DP feed to SS: underhand flip close in, overhand throw from deep",explSimple:["The feed choice depends on distance from the bag.","Always throwing overhand adds unnecessary arm movement on close plays.","The backhand shovel is a desperation move for balls hit to your glove side when you're off-balance.","Waiting for SS to set defeats the purpose of the DP."],anim:"groundout"},
    {id:"2b_new2",title:"The Bunt — Who Takes First?",diff:2,cat:"defense",conceptTag:"bunt-defense",ageMin:10,ageMax:99,
      description:"Runner on 1st, nobody out. Batter squares to bunt. First baseman charges hard. Where do you go?",
      situation:{inning:"Top 3",outs:0,count:"0-0",runners:[1],score:[1,1]},
      options:["Cover first base — 1B is charging, you take the bag","Stay at your position and let first handle it","Charge toward the ball to help field the bunt","Back up the catcher"],
      best:0,explanations:["Correct. When first base charges a bunt, second base covers first. This is the standard bunt defense rule — it's in every level's defensive coverage scheme. You sprint to the bag, receive the throw from the charging 1B or pitcher, and record the out. If you don't cover, first base is a ghost bag.","'Let first handle it' works only if first base isn't charging, because on a hard charge play, 1B physically cannot get back to the bag. Second base must fill it — this is a non-negotiable coverage assignment.","Running toward the ball puts three fielders chasing the bunt and leaves first base uncovered. The shortstop handles second base — your job is first.","Backing up the catcher on a bunt? The catcher fields the ball or directs traffic, since you are needed at first base. Backup catcher duty on bunts belongs to the pitcher on certain coverage schemes."],
      rates:[90,25,40,15],concept:"On bunt defense: 2B covers first when 1B charges",explSimple:["When first base charges a bunt, second base covers first.","'Let first handle it' works only if first base isn't charging.","Running toward the ball puts three fielders chasing the bunt and leaves first base uncovered.","Backing up the catcher on a bunt?"],anim:"groundout"},
    {id:"2b_new3",title:"Hit and Run — Your Read",diff:3,cat:"defense",conceptTag:"hit-and-run",ageMin:11,ageMax:99,
      description:"Runner on 1st takes off on the pitch. It's a hit and run. Ball is hit sharply up the middle. What do you do?",
      situation:{inning:"Top 6",outs:0,count:"2-1",runners:[1],score:[3,3]},
      options:["Abandon covering 2nd — field the ball up the middle","Keep going to cover 2nd — SS will field the ball","Stop and let SS take everything up the middle","Wave the runner through and focus on the next hitter"],
      best:0,explanations:["Correct. A sharply hit ball up the middle on a hit-and-run is YOUR ball if it's in your range. The offense is trying to exploit the hole created when you leave for 2B — recognize this and attack the ball. Fielding the sharp grounder prevents the hit, possibly catches the runner off base, and kills the hit-and-run play. If you can reach it, get it.","Going to cover 2nd when a ball is hit sharply in your zone is exactly what the offense wants, because the hit-and-run is designed to exploit the hole your movement creates. Read the batted ball and react.","Stopping mid-coverage to let SS handle everything up the middle is indecisive — the read is simple: if the ball is in your zone (right side of middle), take it. If it's to SS's side, cover 2nd.","'Wave the runner through' makes no sense on defense, which means your job is to field the ball or cover the base — not signal anything to baserunners."],
      rates:[90,25,40,15],concept:"Hit and run: 2B must read the ball — field if in range, cover if not",anim:"groundout"},
    {id:"2b_new4",title:"Relay from Right Field — Who Takes It?",diff:2,cat:"defense",conceptTag:"cutoff-roles",ageMin:11,ageMax:99,
      description:"Runner on 1st, fly ball drops in right field for a double. Deep in the RF corner. Who takes the relay and where do you go?",
      situation:{inning:"Top 4",outs:1,count:"0-0",runners:[1],score:[1,2]},
      options:["SS takes the relay — you back up second base","You take the relay — SS covers second","Both you and SS go out for a double-cut","You cover third — SS takes relay, 2B covers second"],
      best:0,explanations:["Correct. On balls to right field, the shortstop is the primary relay man because his arm angle to third base is optimal. Second base backs up the SS and covers second base. If SS's relay throw is cut, you're in position to relay to second. This is the standard RF relay assignment at every level.","On RF balls, second base is NOT the primary relay man, because your arm angle to third base is awkward — you'd have to turn completely around. SS handles this relay; your role is backup and bag coverage.","Double-cut relay (both 2B and SS going out) is used on extra-base hits to the outfield gaps — not a standard RF corner double, since double-cuts add personnel but create a hole at second base if misused.","Covering third on a RF ball makes no sense for second base, because third base covers third. Your responsibilities are: back up SS relay, cover second base."],
      rates:[90,25,40,15],concept:"RF relay: SS is primary relay man, 2B backs up and covers second",explSimple:["On balls to right field, the shortstop is the primary relay man because his arm angle to third base is best.","On RF balls, second base is NOT the primary relay man.","Double-cut relay (both 2B and SS going out) is used on extra-base hits to the outfield gaps — not a standard RF corner double.","Covering third on a RF ball makes no sense for second base."],anim:"groundout"},
    {id:"2b_new5",title:"First and Third — Your Role",diff:3,cat:"defense",conceptTag:"first-third",ageMin:11,ageMax:99,
      description:"Runners on 1st and 3rd, 1 out. The runner on 1st breaks for 2nd. The catcher fires down. You're the fielder covering 2nd. What's your read as the throw comes in?",
      situation:{inning:"Bot 7",outs:1,count:"1-1",runners:[1,3],score:[4,4]},
      options:["Fake a tag, then check the runner at 3rd before throwing home","Always apply the tag and throw home immediately","Let the runner have 2nd — don't tag, hold the ball","Fire to third base to trap the runner"],
      best:0,explanations:["Correct. The fake tag (or bluff tag) on a 1st-and-3rd steal is a classic defender's tool. Show the tag to stop the runner at 2B from reversing, then immediately read the runner at 3rd. If he hasn't committed to home, hold the ball — you've just stopped the run-scoring threat. If he goes, fire home. Blind throws home give up free bases and often wild pitch situations.","Always throwing home gives the offense exactly what they want — many 1st-and-3rd steals are designed to get the catcher to throw so the 3rd-base runner can score. Make the runner earn it — read first, throw second.","Letting the runner have 2nd with no contest is too passive in a tie game in the 7th, which means use the fake tag to control the baserunner — you get information for free.","Throwing to 3rd makes no sense — the runner is already standing there, because you'd be giving up 2nd base and making a cross-diamond throw with a runner baiting you at home."],
      rates:[90,40,25,15],concept:"1st and 3rd: fake the tag at 2nd, read the runner at 3rd before throwing",anim:"strike"},
    {id:"2b_tc1",conceptTag:"team-communication",title:"Steal Coverage — Who Takes the Bag?",diff:1,cat:"defense",ageMin:9,ageMax:99,
      description:"Runner on first, one out. Before the pitch, you and the shortstop need to decide who covers second base if the runner steals. How do you communicate this?",
      situation:{inning:"Top 3",outs:1,count:"1-0",runners:[1],score:[1,0]},
      options:["Don't communicate — just react when the runner goes","Use a pre-pitch signal with your shortstop — open glove means you cover, closed glove means he covers","Yell across the infield who's covering so everyone knows","Both run to second and whoever gets there first takes the throw"],
      best:1,explanations:["Reacting without a plan means both of you might run to the bag or both might stay, which leaves second base uncovered or creates a collision. Communication before the pitch prevents this.","Before the pitch, you and the shortstop use a glove signal hidden behind your gloves. Open glove means you're covering, closed glove means the shortstop covers. The coverage depends on the batter — against a right-handed pull hitter, the shortstop covers so you can shade toward first. Against a lefty, you might cover so the shortstop can shade toward the hole. This silent communication happens on every single pitch.","Yelling across the infield tips off the batter and the baserunner about your defensive alignment, since they can adjust their approach based on who's covering. Use quiet hand signals to keep the element of surprise.","Both running to second is a recipe for a collision or a missed bag. One player covers, one player stays in position — and the pre-pitch signal decides who does what."],
      explSimple:["You need a plan before the runner goes. If you don't talk, both of you might mess up!","Use a glove signal with your shortstop before each pitch. Open means you cover, closed means he covers!","Yelling tells the batter and runner what you're doing. Use quiet hand signals instead.","Both running to second means you might crash into each other. Decide before the pitch!"],
      rates:[20,80,40,30],concept:"Use pre-pitch glove signals with your shortstop to decide steal coverage — silent communication prevents confusion and keeps the defense aligned",anim:"steal"},
  ],
  shortstop: [
    {id:"f2", conceptTag:"cutoff-roles",title:"Cutoff Decision",diff:2,cat:"outfield",ageMin:9,ageMax:99,
      description:"You're the SS cutoff. Deep hit to left-center, runner from 1st trying to score. Throw coming to you.",
      situation:{inning:"Bot 6",outs:1,count:"0-0",runners:[1],score:[2,2]},
      options:["Cut it off and throw home","Let the throw go through","Cut and hold","Cut and throw to 3rd"],
      best:0,explanations:["Your relay is faster and more accurate than a bouncing outfield throw — catch it, pivot, and fire home in one smooth motion.","Letting throws through only works on perfect one-hoppers, and those are rare from deep left-center. Your relay gives the catcher a better throw.","Holding the ball lets the tying run score without even making a play.","The runner scoring is the main threat — throw home because that's where the action is."],
      explSimple:["Catch the ball and make a strong throw home. Your throw will be faster and better than letting the outfield throw bounce all the way.","Letting the throw go past you only works if it's a perfect throw, and that's rare.","If you just hold the ball, the runner scores and you didn't even try to get him.","The runner is going home, so that's where you need to throw — not third base."],
      rates:[80,35,25,40],concept:"The cutoff man relays accurate throws home — catch and throw, don't let it go",anim:"throwHome"},
    {id:"f13", conceptTag:"double-play-turn",title:"Ground Ball to Short — Runner on First",diff:1,cat:"infield",ageMin:6,ageMax:99,
      description:"Top of the 3rd, runner on 1st, nobody out. You're at shortstop. Ground ball hit right at you. The runner isn't very fast.",
      situation:{inning:"Top 3",outs:0,count:"0-0",runners:[1],score:[2,1]},
      options:["Throw to second to start the double play","Throw to first for one out","Tag the runner yourself","Throw to first for the sure out if the DP isn't there"],
      best:0,explanations:["With a runner on first and nobody out, the double play is the best outcome, since you flip to second base, the middle infielder turns it, and you get two outs on one play. That's how you get out of innings fast!","Throwing to first gets one out but advances the runner to second — now he's in scoring position, because the double play clears the bases.","Tagging the runner as a shortstop would require chasing him — throw to second for the force.","Flipping to the pitcher on the mound doesn't get an out — he's not standing on a base, which means throw to second base for the double play!"],
      explSimple:["Throw to second base to get the first out, and then your teammate throws to first for the second out. Two outs on one play!","Throwing to first gets one out, but the runner moves to second base where he can score more easily.","You can't chase the runner — just throw to second base for the easy force out.","Don't flip to the pitcher — he's not on a base! Throw to second to start the double play."],
      rates:[85,45,10,15],concept:"With a runner on first and nobody out, the double play is always the first thought",anim:"doubleplay"},
    {id:"f16", conceptTag:"double-play-turn",title:"First and Second — Start the DP",diff:2,cat:"infield",ageMin:9,ageMax:99,
      description:"Bot 6th, runners on 1st and 2nd, nobody out, tied 4-4. You're at shortstop. Hard ground ball right at you. Both runners are going.",
      situation:{inning:"Bot 6",outs:0,count:"0-0",runners:[1,2],score:[4,4]},
      options:["Step on second and throw to first — double play","Throw to third for the force out","Throw home to cut down the lead runner","Tag the runner coming from first"],
      best:0,explanations:["With runners on 1st and 2nd, stepping on second starts the double play — the runner from first is forced at second, then a quick throw to first gets the batter. Two outs on one play!","Throwing to third gets one out but lets the batter reach first — the double play is worth two outs on one play.","Throwing home sounds aggressive, but there's no force play at the plate with runners on 1st and 2nd. The catcher would need to tag the runner, and the double play is worth more.","Tagging one runner still leaves the other runners advancing, because the double play is the best play."],
      rates:[85,45,30,15],concept:"With runners on 1st and 2nd, step on second and throw to first for the double play",explSimple:["With runners on 1st and 2nd, stepping on second starts the double play — the runner from first is forced at second, then a quick throw to first gets the batter.","Throwing to third gets one out but lets the batter reach first.","Throwing home doesn't work here — there's no force at the plate with runners on 1st and 2nd.","Tagging one runner still leaves the other runners advancing."],anim:"doubleplay"},
    {id:"f18", conceptTag:"infield-positioning",title:"Runner Breaks from Third",diff:1,cat:"infield",ageMin:6,ageMax:99,
      description:"Bot 7th, runner on 3rd, 1 out, down 3-4. You're at shortstop playing normal depth. Slow ground ball to your left — you field it, but the runner on 3rd breaks for home!",
      situation:{inning:"Bot 7",outs:1,count:"0-0",runners:[3],score:[4,3]},
      options:["Throw home to get the runner","Throw to first — get the sure out","Hold the ball — check if the runner commits","Throw to third — maybe he'll go back"],
      best:1,explanations:["On a slow roller from normal depth, you had to range to your left and take time to field it. The runner broke on contact — by now he's almost home. A long throw across your body to the plate will likely be late or wild. Know when you don't have the play.","This is the smart play, since on a slow grounder from normal depth, the runner breaking on contact will beat your throw home. Take the sure out at first — don't let the batter reach base too. Give up the run you can't stop, get the out you can.","While reading the runner is good instinct, on a slow roller you took too long to field it, which means the runner is already committed and almost home. Holding the ball means no out anywhere — now you've given up the run AND the out.","The runner already committed to home — throwing to an empty third base is a wasted throw, because you need to get an out somewhere."],
      rates:[40,90,25,15],concept:"On a slow roller from normal depth, the runner from third will beat your throw home — take the sure out at first",explSimple:["Not the best move. On a slow roller from normal depth, you had to range to your left.","Great choice! This is the smart play.","Not the best move. While reading the runner is good instinct, on a slow roller you took too.","Not the best move. The runner already committed to home — throwing to an empty third base is."], anim:"groundout"},
    {id:"f31",title:"Cutoff Man Position on a Relay",diff:3,cat:"outfield",conceptTag:"cutoff-roles",ageMin:9,ageMax:99,
      description:"Top of the 6th, runner on 1st, nobody out. Double to left-center gap. You're the shortstop going out as the relay man. Where do you position yourself?",
      situation:{inning:"Top 6",outs:0,count:"0-0",runners:[1],score:[2,2]},
      options:["In a straight line between the outfielder and home plate","In a straight line between the outfielder and third base","Halfway between the outfielder and the infield","As close to the outfielder as possible"],
      best:0,explanations:["Line yourself up directly between the outfielder and home plate. Raise your arms so the outfielder can see you and has a target. The throw from the outfielder should come to you chest-high, and you catch-and-fire to home in one motion. The relay man is always an infielder — the pitcher is sprinting to back up a base, not cut off a throw.","Lining up toward third only works if you know the throw is going to third. Default to home — you can always redirect to third after catching it.","Halfway is too vague, since you need to be in the optimal relay distance — close enough to receive a strong throw but far enough to get momentum on your throw home.","Being too close to the outfielder makes your relay throw longer, because position yourself about 100-130 feet from home."],
      rates:[85,35,30,15],concept:"As the relay man, line up between the outfielder and home plate — give the outfielder a clear target",anim:"relay"},
    {id:"f44", conceptTag:"double-play-turn",title:"Double Play Depth",diff:1,cat:"positioning",ageMin:6,ageMax:99,
      description:"Top of the 4th, runner on 1st, nobody out, tied 2-2. You're the shortstop. Where should you position yourself?",
      situation:{inning:"Top 4",outs:0,count:"0-0",runners:[1],score:[2,2]},
      options:["Double play depth — a few steps closer to 2nd base","Normal depth — play your regular spot","Deep in the hole — maximize range","Shift toward the pull side"],
      best:0,explanations:["With a runner on first and nobody out, move to double play depth. This means moving a few steps toward second base and a step or two in (closer to home). This shorter path to second base lets you start the double play faster. You sacrifice a little range in the hole, but the DP is worth it.","Normal depth makes the double play harder — you have to cover more ground to get to second.","Deep in the hole maximizes your range but makes the throw to second for the DP much longer.","Shifting without knowing the hitter's tendencies is guessing."],
      rates:[85,30,20,25],concept:"Double play depth means a few steps toward 2nd and a step in — shorter path to start the DP",explSimple:["Great choice! With a runner on first and nobody out, move to double play depth.","Normal depth makes the double play harder — you have to cover more ground to get to second.","Not the best move. Deep in the hole maximizes your range but makes the throw to second for.","Not the best move. Shifting without knowing the hitter's tendencies is guessing."], anim:"doubleplay"},
    {id:"f48", conceptTag:"infield-positioning",title:"Fast Runner at the Plate — Adjust Depth",diff:1,cat:"positioning",ageMin:6,ageMax:99,
      description:"Top of the 8th, nobody on, 1 out, up 3-2. Their fastest player steps in — he can beat out routine ground balls if you play too deep. You're the shortstop.",
      situation:{inning:"Top 8",outs:1,count:"0-0",runners:[],score:[3,2]},
      options:["Play a step or two in — shorten the throw to first","Play normal depth — don't change for one batter","Play deep — get more range","Shade toward the hole — fast guys pull the ball"],
      best:0,explanations:["Against fast runners, cheat in a step or two. A shorter throw to first means the ball gets there faster. You're trading a tiny bit of range for a quicker throw — which matters against speed. The difference between safe and out against a fast runner is often 0.1 seconds.","Normal depth against a speedster means routine grounders become infield singles. After all, you should adjust. And that's why this approach matters in this situation.","Playing deep gives you more range but a longer throw, since against a fast runner, the long throw means he beats it out.","There's no evidence this fast player is a pull hitter, which means don't guess — adjust your depth."],
      rates:[85,30,15,25],concept:"Against fast runners, play a step in — a shorter throw to first compensates for their speed",explSimple:["Great choice! Against fast runners, cheat in a step or two.","Normal depth against a speedster means routine grounders become infield singles.","Not the best move. Playing deep gives you more range but a longer throw.","Not the best move. There's no evidence this fast player is a pull hitter."], anim:"groundout"},
    {id:"f61", conceptTag:"cutoff-roles",title:"Relay from Deep Center — Who Goes Where?",diff:3,cat:"outfield",ageMin:12,ageMax:99,
      description:"Bot 8th, runner on 1st, nobody out. Ball hit to deep center — it's a triple. The center fielder chases it to the wall. Who goes out for the relay?",
      situation:{inning:"Bot 8",outs:0,count:"0-0",runners:[1],score:[4,5]},
      options:["Shortstop goes out for the relay, second baseman covers second","Let the left fielder handle it — no relay needed on a ball to center","Both middle infielders go out — one for each possible target","The third baseman goes out as the relay man"],
      best:0,explanations:["On balls to center and left-center, the shortstop goes out as the relay man, because he lines up between the outfielder and home plate, arms raised as a target. The second baseman stays and covers second base. This is the standard relay alignment.","Skipping the relay leaves the outfielder making a 300-foot throw alone, since on extra-base hits to the gaps, a relay man is essential to get the ball home quickly and accurately.","Having both go out leaves second base uncovered, because one goes, one stays.","The third baseman stays at third to take a possible throw — the shortstop is the relay man on balls to center."],
      rates:[90,40,25,15],concept:"On balls to center/left, the shortstop is the relay man — the second baseman covers second base",anim:"relay"},
    {id:"ss1", conceptTag:"infield-positioning",title:"Deep in the Hole",diff:2,cat:"fielder",ageMin:9,ageMax:99,
      description:"You're the shortstop. No outs, nobody on base. The batter hits a sharp ground ball deep in the hole between short and third. You range far to your right, backhand the ball, and now you're deep behind third base. What's the play?",
      situation:{inning:"Top 3",outs:0,count:"1-1",runners:[],score:[1,0]},
      options:["Plant your back foot hard, set your feet, and make a strong overhand throw across the diamond to first","Flip the ball to the third baseman and let him throw to first","Lob a high rainbow throw to make sure it gets there","Run toward first base to shorten the throw before letting it go"],
      best:0,explanations:["This is the signature shortstop play! After a deep backhand, you plant your back foot hard to stop your momentum, set your feet, and fire a strong throw across the diamond, which means it takes a cannon arm and great footwork — that's why shortstop is a premium position.","The third baseman isn't expecting a flip, and by the time he catches it and throws, the runner is safe, because you have to make this throw yourself — it's one of the most important plays a shortstop makes.","A high rainbow throw from deep in the hole will never beat the runner, since you're far from first base and the batter is sprinting. You need a hard, low throw to get the out in time.","Running toward first eats up valuable time, because he's faster than you running toward first, so every step you take closer costs you. Plant and throw — your arm strength is what gets this out."],
      rates:[85,20,15,25],concept:"On a deep backhand in the hole, plant hard, set your feet, and make a strong throw across the diamond — this is the shortstop's signature play.",explSimple:["This is the signature shortstop play!","The third baseman isn't expecting a flip, and by the time he catches it and throws, the runner is safe.","A lob throw from deep in the hole will never beat the runner.","Running toward first eats up valuable time."],anim:"groundout"},
    {id:"ss2", conceptTag:"double-play-turn",title:"Starting the Double Play",diff:1,cat:"fielder",ageMin:6,ageMax:99,
      description:"You're the shortstop. Runner on first, one out, and the batter hits a ground ball right at you. You field it cleanly. You need to start the double play by getting the ball to second base. What's the best way to feed the second baseman?",
      situation:{inning:"Bot 5",outs:1,count:"0-1",runners:[1],score:[2,3]},
      options:["Make a quick, chest-high throw to the second baseman at the bag — firm but easy to handle","Shovel a hard underhand flip right at his feet","Throw the ball as hard as you possibly can to save time","Run the ball over to second base yourself and then throw to first"],
      best:0,explanations:["A firm, chest-high throw right to the second baseman's glove is the perfect double play feed — it gives him a clean catch and lets him turn the play quickly. Accuracy matters more than speed on the feed — help your teammate make the turn!","An underhand flip at his feet is hard to handle and slows down the turn, which means the second baseman has to reach down, adjust, and then throw — that extra time lets the runner reach first safely.","Throwing as hard as you can might be wild or hard for the second baseman to catch, because a firm, accurate throw is much better than a bullet that sails into center field. Control your throw!","Running the ball to second wastes way too much time, since by the time you get there, the runner from first is already at second, and the batter is almost to first. Use your arm — that's what it's for!"],
      rates:[90,40,25,15],concept:"On a double play feed to second, make a firm chest-high throw the second baseman can handle — accuracy beats raw speed every time.",explSimple:["Great choice! A firm, chest-high throw right to the second baseman's glove is the perfect double play feed.","Not the best move. An underhand flip at his feet is hard to handle and slows down the turn.","Not the best move. Throwing as hard as you can might be wild or hard for the second.","Not the best move. Running the ball to second wastes way too much time."], anim:"doubleplay"},
    {id:"ss3",title:"Covering on the Steal",diff:2,cat:"fielder",conceptTag:"steal-window",ageMin:11,ageMax:99,
      description:"You're the shortstop. Runner on first with good speed, and you suspect he's going to steal second. The pitcher delivers, and the runner takes off! The catcher pops up and fires to second. You're covering the bag. How should you set up?",
      situation:{inning:"Top 1",outs:0,count:"2-1",runners:[1],score:[0,0]},
      options:["Get to the bag early, straddle it with your left foot on the outfield side, and give the catcher a clear target with your glove","Stand in front of the bag blocking the base path so the runner can't reach it","Get to the bag and jump out of the way as the throw arrives to avoid getting hit by the runner","Wait at your normal position until you see the throw, then run to the bag"],
      best:0,explanations:["Perfect steal coverage! Getting to the bag early gives the catcher a clear target, because straddling with your left foot on the outfield side keeps you out of the runner's path while letting you sweep a tag down in front of the base. Quick glove, quick tag, out!","Blocking the base path without the ball is obstruction — the umpire will award the runner the base! Since you need to straddle the bag and leave a lane for the runner to slide, then apply the tag.","Jumping out of the way means you won't be in position to make the tag — yes, the runner is coming hard, but you need to be strong at the bag. Straddle it so you can apply the tag and let the runner slide past you on the other side.","Waiting at your normal position means the catcher has no target and you won't get to the bag in time, which means you need to anticipate the steal and get to the bag as the pitch is delivered, not after the throw."],
      rates:[85,15,20,25],concept:"On steal coverage, get to the bag early, straddle it to give the catcher a target, and sweep the tag down in front of the base.",explSimple:["Perfect steal coverage!","Blocking the base path without the ball is obstruction — the umpire will award the runner the base!","Jumping out of the way means you won't be in position to make the tag.","Waiting at your normal position means the catcher has no target and you won't get to the bag in time."],anim:"steal"},
    {id:"ss4", conceptTag:"popup-priority",title:"Pop-Up Between Short and Third",diff:1,cat:"fielder",ageMin:6,ageMax:99,
      description:"You're the shortstop. Bases empty, two outs. The batter pops the ball straight up — a high popup right between you and the third baseman in the infield dirt. You're both moving toward it. Who takes this ball?",
      situation:{inning:"Bot 3",outs:2,count:"1-2",runners:[],score:[0,2]},
      options:["Call for it loud and clear — as the shortstop, you have priority on this popup","Let the third baseman take it since he's on that side of the infield","Nobody calls it — whoever gets there first just catches it","Wait to see if the pitcher wants it"],
      best:0,explanations:["Correct! On popups between infielders, the shortstop has priority over the third baseman, because you're moving to your right (toward the ball) and can see it clearly. Call 'I got it!' loud and early so everyone knows it's yours. Communication prevents collisions.","The shortstop has priority over the third baseman on popups in this area, since the third baseman should defer unless you can't get there. The popup priority order goes: SS first, then 2B, then 1B/3B, then pitcher/catcher.","Never leave a popup uncalled! When nobody calls it, players crash into each other or the ball drops between them, because someone MUST take charge — and the shortstop has priority over the third baseman on balls in this zone.","The pitcher should only take popups that are right near the mound and no other fielder can reach — on a ball between short and third, the shortstop takes charge over the third baseman."],
      rates:[88,35,10,15],concept:"On infield popups, the shortstop has priority over the third baseman. Call for the ball loud and early to prevent collisions.",explSimple:["Great choice! The shortstop has priority over the third baseman on popups in this area.","Not the best move. The shortstop has priority over the third baseman on popups between them.","Not the best move. Never leave a popup uncalled! Someone MUST call for it.","Not the best move. The pitcher should only take popups right near the mound."], anim:"popup"},
    {id:"ss5",title:"Relay Man to Left-Center",diff:1,cat:"fielder",conceptTag:"relay-double-cut",ageMin:11,ageMax:99,
      description:"You're the shortstop. Runner on first, one out. The batter hits a deep fly ball to left-center field that drops and rolls to the wall. The runner from first is rounding second and heading for third — and he might keep going. You need to be the relay man. Where do you go?",
      situation:{inning:"Top 6",outs:1,count:"0-0",runners:[1],score:[3,4]},
      options:["Run out to line up between the left-center fielder and third base, arms up high so the outfielder can see you","Line up between the outfielder and home plate, arms up","Stay at shortstop position and let the third baseman handle it","Go to second base in case the batter tries to stretch it to a double"],
      best:1,explanations:["Lining up to third can work if the runner clearly stops, but your default should always be toward home, which means preventing runs is the priority, and your teammates can yell to redirect you if needed.","Perfect relay positioning! Your default is always to line up between the outfielder and home plate — preventing runs is the #1 priority. Put your arms up high so the outfielder has a target, and listen to your teammates. They'll tell you where to throw. If the runner stops at third, you can cut it and hold.","The third baseman needs to be at third base to receive the throw! He can't be out doing the relay, because the shortstop is always the relay man on balls hit to the left side of the outfield.","The second baseman or another infielder can cover second, since your priority as shortstop on a deep left-center hit is to get out there as the relay man. Without a relay, the outfielder has to make an impossible long throw."],
      rates:[55,85,15,20],concept:"On relay plays, the default alignment is toward home plate — preventing runs is always the priority.",explSimple:["Not the best move. Lining up to third can work if the runner clearly stops, but your default should.","Perfect relay positioning! Your default is always to line up between the outfielder and home.","Not the best move. The third baseman needs to be at third base to receive the throw! He can't.","Not the best move. The second baseman or another infielder can cover second."], anim:"relay"},
    {id:"ss6", conceptTag:"infield-positioning",title:"Do-Or-Die With Runner on Third",diff:3,cat:"fielder",ageMin:12,ageMax:99,
      description:"You're the shortstop. Runner on third, one out, tie game in the bottom of the last inning. The batter hits a slow chopper toward you — not hit hard, and the runner on third is breaking for home the moment the ball is hit. This is a do-or-die play. What do you do?",
      situation:{inning:"Bot 7",outs:1,count:"0-0",runners:[3],score:[4,4]},
      options:["Charge the ball hard, field it with your bare hand if needed, and fire home to try to get the runner","Play it safe — field the ball cleanly and throw to first for the sure out","Wait for the ball to come to you, then decide where to throw","Let the third baseman field it since he's closer to home"],
      best:0,explanations:["This is the do-or-die play! With the game on the line and the runner going home, you MUST charge hard and throw home. Even a bare-hand pickup and throw gives you a chance to save the game. If you throw to first, the runner scores and the game is over.","Throwing to first gets an out, but the runner from third scores and the game is over — you lose! In a tie game with a runner breaking from third, you have to try to get the runner at home. The out at first doesn't matter if the winning run scores.","Waiting for the ball to come to you wastes precious time, because the runner is sprinting home — every fraction of a second matters. You have to charge aggressively and make a quick play. There's no time to be patient here.","The ball is hit toward you, not the third baseman, since even if the third baseman could get it, he'd have to field it and then spin to throw home. You're already facing home plate as you charge in — it's your play to make."],
      rates:[90,40,15,25],concept:"On a do-or-die play with a runner scoring from third, charge hard and throw home — the out at first doesn't matter if the winning run scores.",anim:"throwHome"},
    {id:"ss7", conceptTag:"infield-positioning",title:"Positioning for a Pull Hitter",diff:1,cat:"fielder",ageMin:6,ageMax:99,
      description:"You're the shortstop. Nobody on base, two outs. A big right-handed pull hitter steps up to bat. Your coach tells you to shade toward the third base side. Where should you position yourself?",
      situation:{inning:"Top 5",outs:2,count:"0-0",runners:[],score:[1,0]},
      options:["Move a few steps toward third base from your normal position — right-handed pull hitters tend to hit toward the left side of the infield","Stay in your normal shortstop position because you don't want to leave gaps","Move a few steps toward second base to cover the middle","Move way over right next to the third baseman"],
      best:0,explanations:["Smart positioning! Right-handed pull hitters hit the ball to the left side of the field most of the time. By shading a few steps toward third, you put yourself right where the ball is most likely to be hit. Good defense is about being in the right spot BEFORE the ball is hit.","Your normal position is designed for an average hitter, which means but this is a known pull hitter, so the ball is more likely to be hit toward third. Adjusting your position a few steps gives you a much better chance at making the play.","Moving toward second takes you AWAY from where a pull hitter is most likely to hit the ball, because that's the opposite of what you want. You'd be leaving the hot zone unprotected.","Moving right next to the third baseman is too extreme, since you'd leave a huge gap between you and second base. A few steps toward third is enough — you still need to cover your zone. Subtle adjustments make a big difference."],
      rates:[85,30,15,20],concept:"Against pull hitters, shade a few steps toward the side they tend to hit — positioning yourself where the ball is most likely to go is smart defense.",explSimple:["Smart positioning! Right-handed pull hitters hit the ball to the left side of the field.","Not the best move. Your normal position is designed for an average hitter.","Not the best move. Moving toward second takes you AWAY from where a pull hitter is most likely.","Not the best move. Moving right next to the third baseman is too extreme."], anim:"groundout"},
    {id:"ss8", conceptTag:"bunt-defense",title:"Bare-Hand the Swinging Bunt",diff:3,cat:"fielder",ageMin:12,ageMax:99,
      description:"You're the shortstop. Runner on second, two outs, one-run game. The batter barely makes contact — a weak dribbler rolling slowly up the third base line. It's dying in the grass between the mound and third. The third baseman plays deep. Can you make the play?",
      situation:{inning:"Top 7",outs:2,count:"2-2",runners:[2],score:[3,2]},
      options:["Charge full speed, bare-hand the ball on the run, and make a quick throw to first in one motion","Let the third baseman come in for it since it's on his side","Wait for the ball to stop rolling, then pick it up with your glove and throw","Charge in but field it with your glove first, then transfer and throw"],
      best:0,explanations:["This is the ultimate athletic play! The ball is dying in the grass, so you have to charge full speed. Bare-handing lets you grab it and throw in one motion — no glove transfer needed. It's risky but it's the only way to get the runner at first in time. Elite shortstop play!","The third baseman is playing deep and has to cover more ground than you, because plus, he'd be running in and to his left, which is a harder angle. You can charge straight in — you have the better path to this ball.","If you wait for the ball to stop, the batter is safe at first by a mile. On a slow dribbler like this, every millisecond counts. You can't play it safe — you have to be aggressive and make a bang-bang play.","Fielding with your glove means you have to transfer the ball to your throwing hand, and that extra step takes too long on a slow roller, since the bare-hand scoop-and-throw is one motion. When the ball is rolling that slowly, you need the bare hand."],
      rates:[90,25,15,40],concept:"On a dying swinging bunt, charge hard and bare-hand it — the scoop-and-throw in one motion is the only way to beat the runner on a slow roller.",anim:"groundout"},

    {id:"ss9", conceptTag:"infield-positioning",title:"Ranging Deep in the Hole",diff:2,cat:"fielder",ageMin:9,ageMax:99,
      description:"You're the shortstop. Runner on first, two outs. The batter hits a hard ground ball deep in the hole between short and third. You range far to your right, backhand the ball cleanly, and now you're almost behind third base. The runner on first is moving. What's your best play?",
      situation:{inning:"Bot 5",outs:2,count:"2-1",runners:[1],score:[3,2]},
      options:["Plant your back foot hard, set up, and fire a strong overhand throw across the diamond to first base","Flip the ball to the third baseman and let him make the throw to first","Lob a high, arching rainbow to make sure it reaches the bag","Spin toward second base and try to get the force out on the lead runner"],
      best:0,explanations:["This is the shortstop's money play! After ranging deep into the hole and backhanding the ball, you plant your back foot hard to stop your momentum, get your feet set, and fire across the diamond. It takes a strong arm and great footwork — you're throwing from far away, so you need everything behind it. This is the play that separates great shortstops from good ones.","The third baseman isn't positioned to receive your flip — he's not expecting it and may not even be near third base, which means by the time he catches your flip, adjusts, and throws, the runner is safe at first. You have to make this throw yourself.","A lob from deep in the hole will never beat the runner. You're already far from first, and a slow, arching throw gives the batter extra time. You need a hard, low throw — a line drive to the first baseman's glove. Lobs are for Sunday catch, not game situations.","Spinning toward second takes time and the throw to second is awkward from this angle, because with two outs, you don't need the force at second — just get the batter at first. One out ends the inning. Keep it simple."],
      rates:[85,20,15,25],concept:"On a deep backhand in the hole, plant hard and fire across the diamond — your arm strength and footwork are what make this signature shortstop play possible.",explSimple:["This is the shortstop's money play!","The third baseman isn't positioned to receive your flip — he's not expecting it and may not even be near third base.","A lob from deep in the hole will never beat the runner.","Spinning toward second takes time and the throw to second is awkward from this angle."],anim:"groundout"},
    {id:"ss10", conceptTag:"cutoff-roles",title:"Relay on a Left-Center Gap Shot",diff:2,cat:"fielder",ageMin:9,ageMax:99,
      description:"You're the shortstop. Runner on first, nobody out, and the batter rips a ball into the left-center field gap. It rolls all the way to the warning track. The runner from first is rounding second and heading for third — he might try to score. You need to get out as the relay man. How do you set up?",
      situation:{inning:"Top 7",outs:0,count:"1-0",runners:[1],score:[2,3]},
      options:["Sprint out and line up between the outfielder and home plate, hands raised high so the outfielder can see you — listen to your teammates for where to throw","Line up between the outfielder and third base since that's where the lead runner is heading","Stay at shortstop position and let the outfielder make the throw himself","Sprint all the way to the outfielder to shorten his throw as much as possible"],
      best:0,explanations:["Perfect relay setup! On balls to left-center, the shortstop is the relay man. Your default alignment is always toward home plate because preventing runs is the #1 priority. Put your hands up high so the outfielder has a clear target. Your teammates behind you will yell directions — if they say 'cut three!' you cut it and throw to third. If they say 'let it go!' the throw is on line to home. Trust your ears.","Lining up toward third can work if the runner clearly stops, but your default should always be home plate. If you line up to third and the runner keeps going, you've already lost. Start with home as your target — you can always redirect to third after you catch the ball.","The outfielder cannot make a 250-foot throw to home plate on the fly — that's nearly impossible. The relay man exists to break that long throw into two shorter, faster throws. Without you out there, the runner scores easily.","Going too far toward the outfielder defeats the purpose of a relay. You want to position yourself so you can catch the outfielder's throw and make a strong relay throw home. If you're too deep in the outfield, your throw home is still really long. Find the sweet spot — roughly in line with the edge of the outfield grass."],
      rates:[85,45,10,20],concept:"On relay plays to left-center, the shortstop lines up between the outfielder and home plate — preventing runs is always the default priority. Hands up, ears open.",explSimple:["On balls to left-center, the shortstop is the relay man.","Lining up toward third can work if the runner clearly stops, but your default should always be home plate.","The outfielder cannot make a 250-foot throw to home plate on the fly — that's nearly impossible.","Going too far toward the outfielder defeats the purpose of a relay."],anim:"relay"},
    {id:"ss11", conceptTag:"steal-window",title:"Steal Coverage With a Righty Batting",diff:1,cat:"fielder",ageMin:6,ageMax:99,
      description:"You're the shortstop. Runner on first with speed, and a right-handed batter steps to the plate. The runner takes off for second on the pitch. The catcher fires the throw. On this play, who covers second base — you or the second baseman?",
      situation:{inning:"Top 2",outs:0,count:"1-1",runners:[1],score:[0,0]},
      options:["You cover second base — with a right-handed batter up, the ball is more likely hit to the left side, so the second baseman stays in his fielding position","The second baseman covers — he's closer to the bag","Both of you run to the bag so someone is definitely there","Neither of you — the pitcher covers second on a steal"],
      best:0,explanations:["Exactly right! With a right-handed batter, the ball is more likely to be pulled to the left side of the field. That means the second baseman needs to stay in his position to field a possible ground ball hit to the right side. So the shortstop covers second on the steal. It's all about protecting the side of the field where the ball is most likely NOT to go.","The second baseman might be physically closer, but with a right-handed batter up, he needs to stay in his fielding position. If he breaks toward second to cover the steal and the batter hits a ground ball to the right side, there's nobody there. The coverage depends on the batter, not the distance.","If both of you run to the bag, you leave the entire middle of the infield wide open. What if the batter swings and hits a ground ball? It rolls through for an easy hit because nobody is in position. Only one middle infielder covers — the other stays home.","The pitcher has to deliver the pitch and then be ready to field a batted ball, since he can't cover second base on a steal — that's the middle infielders' job. The shortstop and second baseman divide this responsibility based on the handedness of the batter."],
      rates:[85,35,10,15],concept:"With a right-handed batter, the shortstop covers second on a steal because the second baseman needs to protect the right side where a righty is more likely to hit.",explSimple:["Great choice! Exactly right! With a right-handed batter, the ball is more likely to be pulled.","Not the best move. The second baseman might be physically closer, but with a right-handed batter up, he needs.","Not the best move. If both of you run to the bag, you leave the entire middle of.","Not the best move. The pitcher has to deliver the pitch and then be ready to field a batted ball."], anim:"steal"},
    {id:"ss12",title:"Double Play Depth or Normal Depth?",diff:2,cat:"fielder",conceptTag:"dp-positioning",ageMin:11,ageMax:99,
      description:"You're the shortstop. It's a tie game in the 6th inning. Runner on first, nobody out. Your coach tells you to get into double play depth. What does that mean, and why does it matter?",
      situation:{inning:"Top 6",outs:0,count:"0-0",runners:[1],score:[3,3]},
      options:["Move a few steps toward second base and a step or two closer to home plate — shorter distance to second base means you can start the double play faster","Move several steps toward third to increase your range in the hole","Stay at your normal depth but move closer to second base only","Move way in on the grass, almost behind the pitcher's mound"],
      best:0,explanations:["That's double play depth! You move a couple of steps toward second base (shorter throw or quicker feed to start the DP) and a step or two in toward home (so the ball gets to you faster and you have more time to turn two). You sacrifice a little range deep in the hole, but the double play is worth it — two outs changes the whole inning.","Moving toward third gives you more range in the hole, but it makes the double play much harder, because you're farther from second base, so the feed takes longer. With a runner on first and nobody out, the double play is your priority — position for it.","Moving laterally toward second without coming in a step means the ball takes longer to reach you, since coming in slightly means you get the ball a fraction of a second sooner, and on a double play, every fraction counts. Both adjustments matter.","Moving way in on the grass is too aggressive. You'd be so close to home that hard ground balls get through before you can react. Double play depth is a subtle adjustment — a few steps, not a radical change. You still need to be able to field normal ground balls."],
      rates:[85,20,35,15],concept:"Double play depth means a few steps toward second base and a step in toward home — shorter distance to the bag and quicker reactions make turning two possible.",explSimple:["That's double play depth!","Moving toward third gives you more range in the hole, but it makes the double play much harder.","Moving laterally toward second without coming in a step means the ball takes longer to reach you.","Moving way in on the grass is too aggressive."],anim:"doubleplay"},
    {id:"ss13", conceptTag:"fly-ball-priority",title:"Pop Fly in Shallow Left",diff:1,cat:"fielder",ageMin:6,ageMax:99,
      description:"You're the shortstop. Runners on first and third, one out. The batter pops the ball up into shallow left field. You're going back on the ball and the left fielder charges in. The third baseman has pulled off to cover his base. Who should catch this?",
      situation:{inning:"Bot 5",outs:1,count:"0-2",runners:[1,3],score:[2,3]},
      options:["Let the left fielder take it — he's charging in and can see the ball in front of him the whole way","Call for it yourself — you're the shortstop and you're closer","Let the third baseman come over since it's on the left side","Nobody calls for it — just see who gets there first"],
      best:0,explanations:["Smart play! The left fielder charging in has the ball in front of him the entire way — that's a much easier catch than you going back over your shoulder. Outfielders coming in always have priority over infielders going back. Plus, with a runner on third, the left fielder's forward momentum gives him a better position to throw home if the runner tags up. Let the outfielder have it!","Going back on a fly ball is the hardest catch in baseball — the ball drifts away from you and you're running almost blind. The left fielder running forward can track the ball the whole way and make a much easier catch. Don't let pride get in the way of good defense.","The third baseman has to cover third base with a runner there, which means he can't leave the bag to chase a pop fly. This is between you and the left fielder, and the left fielder wins that priority battle every time.","Never leave a fly ball uncalled! When nobody communicates, players crash into each other or the ball drops, because the left fielder should call for it loudly, and you should peel off. Communication prevents disasters."],
      rates:[90,40,15,25],concept:"Outfielders running in always have priority over infielders going back — the ball is easier to see and catch when it's in front of you, not over your shoulder.",explSimple:["Smart play! The left fielder charging in has the ball in front of him.","Not the best move. Going back on a fly ball is the hardest catch in baseball — the ball.","Not the best move. The third baseman has to cover third base with a runner there.","Not the best move. Never leave a fly ball uncalled! When nobody communicates, players crash into each other."], anim:"popup"},
    {id:"ss14", conceptTag:"infield-positioning",title:"Throwing on the Run — Backhand Side",diff:3,cat:"fielder",ageMin:12,ageMax:99,
      description:"You're the shortstop in a one-run game. Runner on second, two outs. The batter hits a ground ball to your backhand side — not deep in the hole, but far enough that you have to range to your right and field it on the move. You don't have time to plant and set your feet. How do you make this throw?",
      situation:{inning:"Top 7",outs:2,count:"1-2",runners:[2],score:[4,3]},
      options:["Field it on the run, skip the plant, and throw sidearm to first using your momentum — your body is already going that direction so let it work for you","Stop completely, set your feet, then make a perfect overhand throw to first","Hold the ball — the runner on second isn't going anywhere on a groundout with two outs, so take your time","Flip to the second baseman covering the bag for the force at second instead of throwing to first"],
      best:0,explanations:["Elite play! When you're ranging to your backhand side and don't have time to plant, you throw on the run with a sidearm or three-quarter arm slot. Because your momentum is already carrying you toward the first base side, you use that energy in your throw. It's not as strong as a planted throw, but it's fast — and fast is what you need since the batter is sprinting down the line.","Stopping to set your feet is ideal in most situations, but here you don't have time. Because the ball was hit hard enough to your right, stopping to plant and throw overhand means the batter beats it out. Since the runner is flying, you have to sacrifice a little accuracy for speed.","Holding the ball with two outs means the inning continues and the runner on second stays in scoring position. Because you need this out to end the inning and protect your one-run lead, eating the ball gives the other team another chance to score — make the throw.","There's no force at second on this play, since the only runner is on second base — not first. Because there's no runner being forced at second, flipping it there accomplishes nothing. The only play that gets an out is the throw to first."],
      rates:[82,35,15,20],concept:"When ranging to the backhand side without time to plant, throw sidearm on the run — use your momentum toward first base to power the throw instead of fighting it.",anim:"groundout"},
    {id:"ss_new1",title:"Double Play Pivot — Inside or Outside?",diff:2,cat:"defense",conceptTag:"double-play-turn",ageMin:9,ageMax:99,
      description:"Runner on 1st, 1 out. Ground ball to second. You're covering 2nd for the pivot. The throw is coming to your left. Do you take it inside the bag or outside?",
      situation:{inning:"Top 4",outs:1,count:"1-1",runners:[1],score:[1,1]},
      options:["Take it inside the bag — step across","Take it outside the bag — drag the back foot","Camp on the bag and wait for the throw","Cut it off and flip to first directly"],
      best:0,explanations:["Correct. Inside pivot: you catch on the infield side, step across the bag, and release toward first in one fluid motion. You clear the runner's path and gain arm angle. MLB second-to-first DP conversion rate is 72% using the inside pivot. So this approach matters in this situation.","The outside pivot (dragging the back foot on the outfield side) works on throws to your right, not your left, since on a throw to your left, going outside puts your arm behind your body — you lose 15+ feet of carry.","Camping on the bag and waiting kills your momentum. The pivot is a catch-and-release movement — dwelling costs you the DP because the runner reaches first before your throw does.","Cutting it off only makes sense if the throw is badly offline and a DP is already dead, because on a catchable throw, always complete the relay to first."],
      rates:[82,35,28,20],concept:"Double play pivot: inside vs. outside depends on throw direction",explSimple:["Inside pivot: you catch on the infield side, step across the bag, and release toward first in one fluid motion.","The outside pivot (dragging the back foot on the outfield side) works on throws to your right, not your left.","Camping on the bag and waiting kills your momentum.","Cutting it off only makes sense if the throw is badly offline and a DP is already dead."],anim:"groundout"},
    {id:"ss_new2",title:"Relay Positioning — Where Do You Line Up?",diff:2,cat:"defense",conceptTag:"relay-double-cut",ageMin:11,ageMax:99,
      description:"Runner on 1st, nobody out. Deep single to right-center. Where do you set up as the relay man?",
      situation:{inning:"Top 5",outs:0,count:"0-0",runners:[1],score:[0,2]},
      options:["Shallow outfield grass, inline between CF and 3rd base","Deep in the outfield to save the outfielder a long throw","On the outfield side of 2nd base","At the pitching mound — split the distance"],
      best:0,explanations:["Correct. The SS relay man sets up on the shallow outfield grass, directly in line between the outfielder and the base being targeted. 'Shallow' means 30-40 feet into the outfield — not so deep you can't re-relay, not so shallow the outfielder's throw dies before reaching you. Inline alignment is the #1 priority: any angle creates carry loss.","Deep setups waste the relay's purpose, since you're absorbing a long throw only to make another long throw. Proper depth is 30-40 feet past the infield — close enough to fire quickly to any base.","Setting up at 2nd base means you're too close — the outfielder's throw sails over you, which means the relay man must be out in the grass to take cut-down throws.","The mound is a common youth mistake, because it's too shallow for deep singles — the outfielder's throw lands before it reaches you. Relay depth scales with the depth of the hit."],
      rates:[84,18,22,25],concept:"Relay positioning: shallow outfield grass, inline with target base",explSimple:["The SS relay man sets up on the shallow outfield grass, directly in line between the outfielder and the base being targeted.","Deep setups waste the relay's purpose.","Setting up at 2nd base means you're too close — the outfielder's throw sails over you.","The mound is a common youth mistake."],anim:"groundout"},
    {id:"ss_new3",title:"Steal Coverage — Who Has Second?",diff:1,cat:"defense",conceptTag:"dp-positioning",ageMin:11,ageMax:99,
      description:"Runner on 1st. Left-handed batter at the plate. Runner breaks for 2nd. Who covers the bag?",
      situation:{inning:"Top 3",outs:1,count:"1-0",runners:[1],score:[0,0]},
      options:["Second baseman covers — SS stays in position","Shortstop covers — 2B stays in position","Whoever gets there first","Both break for the bag and the first one there takes it"],
      best:1,explanations:["With a left-handed batter, the ball tends to be pulled to the right side, since the second baseman needs to stay in position to field those pulled grounders — so the shortstop covers 2nd on the steal, not the second baseman.","Correct! Against a left-handed batter, the second baseman must guard the pull side (right side of the infield), because that means the shortstop breaks to cover second base on the steal attempt. This is the standard steal coverage rule: SS covers on LHB, 2B covers on RHB.","'Whoever gets there first' creates communication breakdowns — the classic 'I've got it'/'you've got it' collision scenario — stolen base coverage is pre-determined by batter handedness, every time.","Two players breaking for the bag creates a hole on both sides of the infield, which means pre-set communication rules prevent this — one player covers, the other holds position."],
      rates:[25,90,40,15],concept:"Stolen base coverage: SS covers on LHB, 2B covers on RHB — the non-pull-side middle infielder covers the bag",explSimple:["Not the best move. The second baseman needs to guard the pull side against a lefty batter.","Great choice! The shortstop covers second base when a left-handed batter is up.","Not the best move. 'Whoever gets there first' creates communication breakdowns.","Not the best move. Two players breaking for the bag creates a hole on both sides of the infield."], anim:"strike"},
    {id:"ss_new4",title:"Communication on the Pop-Up",diff:1,cat:"defense",conceptTag:"fly-ball-priority",ageMin:6,ageMax:99,
      description:"Short popup between you and the third baseman. Both of you break for it. You're calling for it. What do you do?",
      situation:{inning:"Bot 2",outs:1,count:"1-2",runners:[],score:[2,1]},
      options:["Call loudly 'I got it! I got it!' and take the ball","Wave off the third baseman and back off","Let third base take it — he has better angle","Yell for center field to come take it"],
      best:0,explanations:["Correct. The shortstop has priority over third base on short pops in this zone. When you call loudly and early, third base must yield — verbal communication wins. Early, loud, repeated calls ('I got it! I got it!') eliminate collisions. SS is moving toward the ball, which improves catch probability vs. standing still.","Waving off and backing away contradicts taking responsibility. If you call it, take it. Backing off after calling creates hesitation from third base and increases drop probability.","Third base has a harder angle on balls drifting toward SS territory, because the SS moving forward has better momentum and a cleaner look than 3B backpedaling.","Center field handles deep flies, since a short pop between SS and 3B is never a CF ball — calling CF creates confusion and leaves the other zones uncovered."],
      rates:[90,25,40,15],concept:"Shortstop has priority over third base on shared popup zone",explSimple:["Great choice! Correct.","Not the best move. Waving off and backing away contradicts taking responsibility.","Not the best move. Third base has a harder angle on balls drifting toward SS territory.","Not the best move. Center field handles deep flies."], anim:"flyout"},
    {id:"ss_new5",title:"The 5-4-3 Double Play — Your Throw",diff:3,cat:"defense",conceptTag:"double-play-turn",ageMin:9,ageMax:99,
      description:"Bases loaded, 1 out. Hard grounder to third. Third fires to you at second for the force. You catch it, step, and see the runner from first is trucking. Do you hurry the throw?",
      situation:{inning:"Bot 6",outs:1,count:"0-0",runners:[1,2,3],score:[3,4]},
      options:["Take the extra half-second to set your feet — accuracy beats speed","Rush the throw — the runner is close","Eat the ball — just get the out at second","Lob it to avoid throwing into the runner"],
      best:0,explanations:["Correct. A half-second to set your feet is almost always worth it at the pro level. An offline throw to first in this spot scores two runs and puts runners on the corners. MLB data: rushed pivot throws are 3x more likely to be wild. Get the out at second, set your feet, and deliver a strike to first. Runner contact is part of the pivot — absorb it and throw.","Rushing the relay when you have time is the #1 cause of DP-killing wild throws, because the 'hurry up and miss' play is a baserunner's best friend. Take your half-second.","Eating the ball gets one out when you might get two — with the force, you always complete the relay unless the throw to 2nd was truly off-line and you bobbled it.","Lobbing is never the answer on a double play relay, which means you lose velocity, the throw becomes hittable for the runner, and you almost certainly won't beat the batter to first."],
      rates:[90,25,40,15],concept:"On the DP pivot, accuracy beats speed — set your feet",anim:"groundout"},
  ],
  centerField: [
    {id:"f3", conceptTag:"fly-ball-priority",title:"Pop Fly Priority",diff:1,cat:"communication",ageMin:6,ageMax:99,
      description:"You're center field. High pop between you, the right fielder, and the 2nd baseman.",
      situation:{inning:"Top 2",outs:1,count:"0-0",runners:[2],score:[0,1]},
      options:["Call 'I got it!' and wave off others","Let the infielder take it","Stay quiet and see who gets there","Back off for the right fielder"],
      best:0,explanations:["As center fielder, you have priority on ALL fly balls you can reach because you're running in toward the ball, which gives you a better angle and easier catch than an infielder running back. Call early and loud so the right fielder and second baseman know to clear out.","The infielder is running back, which is harder than running forward. Since you're the center fielder coming in, you have the better angle, which means you should take charge — not defer to the second baseman.","Staying quiet is dangerous because collisions happen when nobody communicates. If you, the right fielder, and the second baseman all go for it without calling, someone gets hurt. The key is calling early and loud.","You ARE the center fielder, so you don't need to back off for anyone. Since center field has priority over all other positions on fly balls, the right fielder should back off for YOU once you call it."],
      explSimple:["You're the center fielder — you're the boss of fly balls! Yell 'I got it!' nice and loud because you have the best angle.","You're running in which is easier than running back, so the outfielder should take it over the infielder.","Never stay quiet! If nobody calls it, players crash into each other because they don't know who's going for it.","You ARE the center fielder! You don't back off — everyone else backs off for you since you're the boss of fly balls."],
      rates:[90,30,5,35],concept:"Center fielder has priority on all fly balls — call it early and loud!",anim:"catch"},
    {id:"f10", conceptTag:"of-depth-arm-value",title:"Do-or-Die Play",diff:3,cat:"pressure",ageMin:12,ageMax:99,
      description:"Bottom 9th, tie game, runner on 2nd, 2 outs. Single to you in center. Runner going home.",
      situation:{inning:"Bot 9",outs:2,count:"0-0",runners:[2],score:[3,3]},
      options:["Field cleanly, set feet, strong throw home","Charge and throw on the run","Field and hit cutoff","Dive for the ball"],
      best:0,explanations:["This is it. Accuracy beats speed. Set your feet and make your best throw — that's why this approach matters in this situation.","Throwing on the run sacrifices accuracy in the biggest moment.","Cutoff adds time on a game-ending throw.","Diving forces you to get up slowly, losing time to throw, because clean field beats risky diving here."],
      rates:[85,40,45,20],concept:"In do-or-die plays: field cleanly, set your feet, throw accurately",anim:"throwHome"},
    {id:"f24", conceptTag:"tag-up",title:"Fly Ball Caught — Throw Home or Cutoff?",diff:1,cat:"outfield",ageMin:6,ageMax:99,
      description:"Bot 6th, runner on 3rd, 1 out, tied 3-3. Fly ball caught by you in center field — medium depth. The runner is tagging up.",
      situation:{inning:"Bot 6",outs:1,count:"0-0",runners:[3],score:[3,3]},
      options:["Throw directly home — gun him down","Hit the cutoff man with a strong throw","Throw to second — the batter isn't going anywhere","Hold the ball — save your arm"],
      best:0,explanations:["On a tag-up play from center field at medium depth, you have a realistic chance to throw the runner out at home, since crow-hop, set your feet, and fire a strong throw home. This is one of the few times you throw through the cutoff.","The cutoff man is great on base hits, but on a tag play you need the ball home as fast as possible, because a relay adds time.","Throwing to second ignores the run scoring — the runner on third is the priority.","Holding the ball lets the tying run score, which means make a play! Think about what gives your team the best result here."],
      rates:[85,50,10,5],concept:"On tag-up plays, throw directly home — speed matters more than accuracy on this play",explSimple:["Great choice! On a tag-up play from center field at medium depth, you have a realistic chance.","Not the best move. The cutoff man is great on base hits, but on a tag play you need.","Not the best move. Throwing to second ignores the run scoring.","Not the best move. Holding the ball lets the tying run score."], anim:"throwHome"},
    {id:"f27", conceptTag:"relay-double-cut",title:"Extra Base Hit to the Gap",diff:2,cat:"outfield",ageMin:9,ageMax:99,
      description:"Top of the 7th, runner on 1st, 1 out, tied 4-4. Ball hit into the right-center gap. Runner is sprinting for home. You're the center fielder — you get to the ball first.",
      situation:{inning:"Top 7",outs:1,count:"0-0",runners:[1],score:[4,4]},
      options:["Throw home — try to get the runner at the plate","Hit the relay man between you and home","Throw to third to stop the batter","Hold the ball and run it in"],
      best:1,explanations:["Throwing home from the gap is 300+ feet — way too far for an accurate throw, because it'll bounce multiple times and the batter will advance.","On extra-base hits to the gap, the relay throw is essential. Hit the relay man (usually the shortstop or second baseman) who is positioned in a straight line between you and home plate. He catches your throw and fires home in one motion. Two short throws beat one long throw.","Throwing to third ignores the scoring runner, since you stop the run first.","Running the ball in is way too slow, because the runner scores easily and the batter takes an extra base."],
      rates:[25,90,40,15],concept:"On balls in the gap, use the relay man — two short throws beat one long throw",explSimple:["Throwing home from the gap is 300+ feet — way too far for an accurate throw.","On extra-base hits to the gap, the relay throw is essential.","Throwing to third ignores the scoring runner.","Running the ball in is way too slow."],anim:"throwHome"},
    {id:"f30", conceptTag:"cutoff-roles",title:"Two Runners Going — Which Throw?",diff:3,cat:"outfield",ageMin:12,ageMax:99,
      description:"Bot 9th, runners on 1st and 2nd, 1 out, down 5-4. Single to center field. Runner from 2nd is scoring. Runner from 1st is trying for third. You're the center fielder.",
      situation:{inning:"Bot 9",outs:1,count:"0-0",runners:[1,2],score:[5,4]},
      options:["Throw home — stop the tying run","Throw to third — get the batter trying to advance","Hit the cutoff and let him decide","Throw to second — hold the batter to a single"],
      best:0,explanations:["With a runner scoring the tying run in the 9th, preventing that run is everything. The runner from second to home is the throw you must make. If you get him, the game stays in your favor.","Getting the runner at third is nice, but the tying run scoring from second is far more important — stop the lead runner first.","The cutoff is usually smart, but in a do-or-die situation where the tying run is scoring, you throw home, which means the cutoff can catch the throw if the runner stops.","Throwing to second is the lowest-priority play, because the tying run is about to score!"],
      rates:[85,35,50,10],concept:"When the tying or go-ahead run is scoring, throw home — stop the most important runner first",anim:"throwHome"},
    {id:"f51", conceptTag:"fly-ball-priority",title:"Routine Fly — Catch It Right",diff:1,cat:"outfield",ageMin:6,ageMax:99,
      description:"Bot 3rd, nobody on, 1 out, tied 1-1. Fly ball hit right to you in center field. It's a routine catch. How should you catch it?",
      situation:{inning:"Bot 3",outs:1,count:"0-0",runners:[],score:[1,1]},
      options:["Catch it above your head with both hands — the right way","Basket catch at your waist — it looks cool","One-hand snag — show off your skills","Catch it on the run — charge in"],
      best:0,explanations:["Catch fly balls above your head with two hands, since your glove hand catches the ball and your throwing hand covers it immediately. This is the safest, most reliable way to catch a fly ball. You can also transition to a throw quickly from this position.","Basket catches look cool but are much riskier. If you misjudge the ball, it hits you in the face. There's no margin for error at your waist.","One-handed catches increase the chance of the ball popping out of your glove, because you use two hands.","The ball is coming to you — don't charge in on a routine fly — get under it and make the catch."],
      rates:[85,25,20,15],concept:"Catch fly balls above your head with two hands — safe, reliable, and ready to throw",explSimple:["Great choice! Catch fly balls above your head with two hands.","Not the best move. Basket catches look cool but are much riskier.","Not the best move. One-handed catches increase the chance of the ball popping out of your glove.","Not the best move. The ball is coming to you — don't charge in on a routine fly."], anim:"catch"},
    {id:"f52", conceptTag:"fly-ball-priority",title:"Ball Between Two Outfielders — Who Gets It?",diff:1,cat:"communication",ageMin:6,ageMax:99,
      description:"Top of the 5th, nobody on, 2 outs. Fly ball hit to left-center — both the left fielder and center fielder are running for it. Who calls it?",
      situation:{inning:"Top 5",outs:2,count:"0-0",runners:[],score:[2,2]},
      options:["Center fielder calls it — he has priority","Left fielder calls it — he called it first","Whoever is closer calls it","They should both try to catch it"],
      best:0,explanations:["The center fielder is the captain of the outfield. On any ball between two outfielders, the center fielder has priority. He calls 'I got it!' or 'Mine!' and the other fielder peels off. This prevents collisions and dropped balls. The CF has priority because he's running toward the ball and has a better angle.","The left fielder should defer to the center fielder even if he called it first. The CF has priority on balls between outfielders because he's coming in toward the play and has a better angle on the catch.","Whoever is closer is a recipe for collisions because without a clear priority system, both players converge at full speed. Outfield collisions cause serious injuries.","Both going for the ball is how outfielders get hurt. One person catches it, the other backs up. Without that rule, two players crash into each other at full sprint and the ball drops anyway."],
      rates:[85,25,30,5],concept:"The center fielder has priority on fly balls between outfielders — he calls it and everyone else defers",explSimple:["Great choice! The center fielder is the captain of the outfield.","Not the best move. The left fielder should defer to the center fielder even if he called it first.","Not the best move. Whoever is closer is a recipe for collisions.","Not the best move. Both going for the ball is how outfielders get hurt."], anim:"catch"},
    {id:"f53", conceptTag:"of-depth-arm-value",title:"Ball Deep to the Warning Track",diff:2,cat:"outfield",ageMin:9,ageMax:99,
      description:"Bot 6th, runner on 2nd, 1 out, tied 3-3. Deep fly ball hit toward the warning track in right-center. You're the center fielder — it's going over your head.",
      situation:{inning:"Bot 6",outs:1,count:"0-0",runners:[2],score:[3,3]},
      options:["Sprint back, turn your back to the infield, and run to the spot","Drift back while keeping your eyes on the ball","Sprint to the wall and wait for it","Take an angle route — the banana route to the ball"],
      best:3,explanations:["Sprinting straight back while watching over your shoulder is the old-school method but it's inefficient, because you lose speed looking backward and take a longer path to the ball. The angle route gets you there faster with better body positioning for the catch.","Drifting back is too slow for a ball going over your head, because you won't cover enough ground in time. When a ball is hit deep, you need to turn and sprint immediately, since drifting only works on balls that hang high and land nearby.","Sprinting to the wall and waiting doesn't work because the ball might land short of the wall and you'll be out of position. You need to track the ball and run to the landing spot, not to a fixed point like the fence.","Take an angle route (the 'banana route') — turn and run at an angle to where the ball will land, then curve back to catch it, because this is faster than running straight back since you run in a more efficient path. You also end up facing the right direction to make a throw after the catch. Elite outfielders always use angle routes on deep fly balls."],
      rates:[35,15,20,85],concept:"On deep fly balls, use an angle route — turn and run to the spot, don't drift back or run straight",explSimple:["Sprinting straight back while watching over your shoulder is the old-school method but it's inefficient.","Drifting back is too slow for a ball going over your head, because","Sprinting to the wall and waiting doesn't work — the ball might land short of the wall.","Take an angle route (the 'banana route') — turn and run at an angle to where the ball will land, then curve back to catch it."],anim:"catch"},
    {id:"cf1",title:"Take Charge on the Pop Fly",diff:1,cat:"fielder",conceptTag:"fly-ball-priority",ageMin:6,ageMax:99,
      description:"You're the center fielder. A high pop fly is hit to short left-center field. The left fielder runs over and the shortstop drifts back. You have a clear path to the ball and can get there easily.",
      situation:{inning:"Top 3",outs:1,count:"0-1",runners:[],score:[2,2]},
      options:["Call 'I got it!' loudly and wave off both players","Let the left fielder take it since it's closer to his side","Stay quiet and just run to the ball","Yell for the shortstop to catch it"],
      best:0,explanations:["As the center fielder you're the outfield captain, which means you have priority over corner outfielders and infielders on fly balls, and calling loudly prevents collisions.","The left fielder can catch it, but center fielders have priority on balls they can reach because you're coming in and can see the whole field better.","Running to the ball without calling it is dangerous, because two players could collide at full speed trying to make the same catch.","The shortstop is running with his back to the infield, making it a harder catch, since outfielders have priority over infielders on fly balls."],
      rates:[90,35,15,25],concept:"The center fielder is the outfield captain and has priority on any fly ball they can reach.",explSimple:["Great choice! As the center fielder you're the outfield captain.","Not the best move. The left fielder can catch it, but center fielders have priority on balls they can.","Not the best move. Running to the ball without calling it is dangerous.","Not the best move. The shortstop is running with his back to the infield, making it a harder catch."], anim:"catch"},
    {id:"cf2", conceptTag:"of-communication",title:"Shade the Gap",diff:2,cat:"fielder",ageMin:9,ageMax:99,
      description:"You're in center field. A left-handed pull hitter steps up with nobody on base and one out. Your coach taught you to watch the batter's stance. This batter has an open stance and likes to drive the ball to right-center.",
      situation:{inning:"Bot 4",outs:1,count:"0-0",runners:[],score:[1,3]},
      options:["Shade a few steps toward right-center field","Shade a few steps toward left-center field","Stay in straightaway center","Move way over to the right field line"],
      best:0,explanations:["Shade toward right-center field — a left-handed pull hitter with an open stance tends to drive the ball that way, because taking a few steps in that direction puts you in the best spot to cut off a gap hit.","Left-center is the opposite of where this batter likes to hit, since you'd be leaving the right-center gap wide open for a double.","Staying in straightaway center is okay, but you're giving up a step or two toward where this hitter is most likely to drive the ball, which is why this approach matters in this situation.","Moving all the way to the right field line is way too extreme, which means you'd leave a huge gap in left-center and couldn't recover on an opposite-field hit."],
      rates:[85,20,45,10],concept:"Study the batter's stance and tendencies to shade your position toward where they're most likely to hit.",explSimple:["A left-handed pull hitter with an open stance tends to drive the ball to right-center.","Left-center is the opposite of where this batter likes to hit.","Staying in straightaway center is okay, but you're giving up a step or two toward where this hitter is most likely to drive the ball.","Moving all the way to the right field line is way too extreme."],anim:"catch"},
    {id:"cf3", conceptTag:"cutoff-roles",title:"Hit the Right Base",diff:2,cat:"fielder",ageMin:9,ageMax:99,
      description:"You're the center fielder. A line drive single is hit to you on one hop. There's a runner on first who was running on the pitch and is already rounding second base heading for third. No other runners are on base with one out.",
      situation:{inning:"Top 6",outs:1,count:"2-1",runners:[1],score:[4,3]},
      options:["Throw to third base to try to get the lead runner","Fire to second base to hold the batter at first","Launch a throw home just in case the runner tries to score","Throw to first base to keep the batter honest"],
      best:0,explanations:["The lead runner is the most dangerous baserunner. If you can gun him down at third, you get the second out and take away a scoring threat. That's the high-value play.","The batter already has a single and is unlikely to try for second on a ball hit right at you, because you throwing to second base wastes time while the lead runner takes third easily.","The runner is only going to third, not home, since you throwing home lets the batter move up to second and gives nobody a chance at an out.","Throwing to first makes no sense since the batter is already safe on the hit. You'd be ignoring the advancing lead runner completely."],
      rates:[80,40,15,10],concept:"Always target the lead runner — getting the out on the most advanced baserunner takes away the biggest scoring threat.",explSimple:["The lead runner is the most dangerous baserunner.","The batter already has a single and is unlikely to try for second on a ball hit right at you.","The runner is only going to third, not home.","Throwing to first makes no sense since the batter is already safe on the hit."],anim:"catch"},
    {id:"cf4",title:"Back Up the Play",diff:1,cat:"fielder",conceptTag:"backup-duties",ageMin:8,ageMax:99,
      description:"You're the center fielder. Runner on first, one out. A ground ball is hit to the shortstop. He fields it and throws to first base. Where should you be moving during this play?",
      situation:{inning:"Bot 2",outs:1,count:"1-1",runners:[1],score:[0,0]},
      options:["Sprint toward right field to back up a possible overthrow at first base","Stay in center field and watch the play unfold","Run toward second base to back up in case the runner advances","Jog toward the infield to be ready for the next play"],
      best:0,explanations:["Great hustle! Because the throw is going to first base, an overthrow would send the ball into right field territory. Since the runner on first could advance to second or even third on an overthrow, you sprint toward the right field side to back up the first baseman — that way if the ball gets past him, you're there to keep the runner from taking extra bases.","Standing still in center field means if the throw gets past the first baseman, the ball rolls to the fence and nobody is there to stop it. Because great outfielders are always moving to back up throws, staying put leaves a dangerous gap behind first base.","Running to second base doesn't help on this play, because the throw is going to first, not second. Since the ball will end up near the first base side if anything goes wrong, backing up second base puts you in the wrong spot entirely.","Never jog during a live play! Because the ball is still in play and runners are moving, you need to be sprinting to your backup position. Since hustling to back up is how great center fielders prevent extra bases, jogging means you won't get there in time if something goes wrong."],
      rates:[85,30,20,10],concept:"Great center fielders are always moving to back up throws, even on routine plays — sprint toward where the ball might end up if something goes wrong.",explSimple:["Sprint toward right field to back up a possible overthrow at first.","Standing still leaves a dangerous gap behind first base.","The throw is going to first, not second — back up in the right direction.","Never jog during a live play — hustle to your backup spot."], anim:"advance"},
    {id:"cf5", conceptTag:"of-depth-arm-value",title:"Go Back on the Deep Ball",diff:2,cat:"fielder",ageMin:9,ageMax:99,
      description:"You're in center field playing at normal depth. The batter crushes a towering fly ball that's hit well over your head toward the warning track. You need to turn and run. The ball is drifting slightly to your right.",
      situation:{inning:"Top 7",outs:2,count:"3-2",runners:[1,2],score:[5,5]},
      options:["Turn your body to the right, sprint back at an angle, and look for the ball over your right shoulder","Backpedal straight back while keeping your eyes on the ball the whole time","Turn completely around and sprint straight back, then look up at the last second","Drift back slowly while watching the ball so you don't lose it"],
      best:0,explanations:["Turning to the side the ball is drifting and sprinting at an angle is the fastest way to cover ground while still tracking the ball over your shoulder, because this is textbook deep-ball technique.","Backpedaling is the slowest way to move backward — on a ball hit well over your head, you'll never catch up by going backward — you need to turn and run.","Sprinting straight back without looking risks running to the wrong spot, which means you need to peek over your shoulder to track the ball's flight and adjust your path.","Drifting slowly won't get you to a ball that's over your head, because you need full speed immediately or the ball lands behind you for extra bases."],
      rates:[85,15,40,20],concept:"On balls over your head, drop-step to the side the ball is drifting, sprint at an angle, and track it over your shoulder.",explSimple:["Turning to the side the ball is drifting and sprinting at an angle is the fastest way to cover ground while still tracking the ball over your shoulder.","Backpedaling is the slowest way to move backward.","Sprinting straight back without looking risks running to the wrong spot.","Drifting slowly won't get you to a ball that's over your head."],anim:"catch"},
    {id:"cf6", conceptTag:"of-communication",title:"Direct the Outfield",diff:3,cat:"fielder",ageMin:12,ageMax:99,
      description:"You're the center fielder and the outfield captain. A pinch hitter comes up that nobody on your team has seen before. He's a right-handed batter in a tie game. Your left fielder shades toward the line and your right fielder plays straightaway. The scouting report on your lineup card says he pulls everything dead.",
      situation:{inning:"Bot 8",outs:0,count:"0-0",runners:[2],score:[3,3]},
      options:["Wave the right fielder to shade toward the right field line and have the left fielder move toward center","Tell both outfielders to stay where they are since you don't know the hitter","Wave the left fielder closer to the left field line to protect against a hit down the line","Move yourself toward right-center but don't direct the other outfielders"],
      best:0,explanations:["A dead pull right-handed hitter drives the ball to left field and left-center, since moving RF toward the line and LF toward center creates an outfield shift that puts all three fielders where the ball is most likely to go. Great captainship!","Doing nothing wastes the scouting report you were given, because the center fielder's job is to use information and position the outfield before each batter.","Moving LF toward the left field line leaves the biggest gap in left-center, exactly where a right-handed pull hitter drives the ball most — that's the opposite of what you want.","Moving yourself is good, but part of being outfield captain is directing all three outfielders, which means the team defense is only as good as its positioning."],
      rates:[85,30,10,45],concept:"The center fielder uses scouting reports and batter tendencies to position the entire outfield before each pitch.",anim:"catch"},
    {id:"cf7", conceptTag:"cutoff-roles",title:"Relay Throw From the Gap",diff:3,cat:"fielder",ageMin:12,ageMax:99,
      description:"You're in center field. A line drive is hit into the left-center gap and rolls to the wall. The left fielder reaches the ball first. You see a runner from first base rounding third and heading home. The shortstop runs out to be the relay man.",
      situation:{inning:"Top 8",outs:1,count:"1-0",runners:[1],score:[6,5]},
      options:["Line up behind the shortstop and yell directions — 'Home! Home!' — so the relay throw goes to the plate","Run to the ball to help the left fielder field it","Stand at second base to take a throw from the left fielder","Run toward home plate to help the catcher"],
      best:0,explanations:["On relay plays, the center fielder lines up behind the relay man and yells where to throw, because your voice and positioning help the shortstop make an accurate relay throw home. This is your most important job on gap hits.","The left fielder already has the ball, since two outfielders at the wall means nobody is directing the relay, and the throw home will be late and inaccurate.","Standing at second base doesn't help when the play is at the plate, because the batter's base doesn't matter right now — the run scoring does.","The catcher handles home plate — your job is behind the relay man, giving directions and backing up in case the relay throw is off-line."],
      rates:[90,25,40,15],concept:"On relay plays, the center fielder lines up behind the cutoff man and calls out where to throw — you're the eyes of the relay.",anim:"relay"},
    {id:"cf8", conceptTag:"of-depth-arm-value",title:"Shallow or Deep?",diff:1,cat:"fielder",ageMin:6,ageMax:99,
      description:"You're the center fielder. It's the bottom of the last inning and your team leads by one run. There's a runner on third with one out. A fly ball to you would tie the game on a sacrifice fly. The batter hits for contact who rarely hits deep fly balls.",
      situation:{inning:"Bot 7",outs:1,count:"0-0",runners:[3],score:[3,4]},
      options:["Play shallow to have a better chance of throwing the runner out at home on a sac fly","Play extra deep to make sure nothing gets over your head","Stay at normal depth since you don't want to change anything","Move to left-center because the runner is on third"],
      best:0,explanations:["Playing shallow gives you momentum going forward and a shorter throw home, which means with a contact hitter who doesn't hit deep, you can afford to come in. A strong throw might nail the runner at the plate and save the game.","Playing extra deep makes your throw home longer, almost guaranteeing the runner scores, because against a contact hitter who doesn't hit deep, there's no reason to play back.","Normal depth is okay, but with the game on the line and a runner on third, you should adjust, since good fielders change their positioning based on the situation.","Moving left or right doesn't help you throw the runner out at home, because the issue is depth — how close or far from home plate you are."],
      rates:[80,20,40,15],concept:"In late-game situations with a runner on third, play shallow to give yourself a shorter throw home and a chance to save the run.",explSimple:["Great choice! Playing shallow gives you momentum going forward and a shorter throw home.","Not the best move. Playing extra deep makes your throw home longer, almost guaranteeing the runner scores.","Normal depth is okay, but with the game on the line and a runner.","Not the best move. Moving left or right doesn't help you throw the runner out at home."], anim:"throwHome"},

    {id:"cf9", conceptTag:"of-depth-arm-value",title:"Line Drive Read",diff:1,cat:"fielder",ageMin:6,ageMax:99,
      description:"The batter swings hard and the ball jumps off the bat heading your way. It's coming fast and you need to decide instantly — is this a line drive that's going to sink or a fly ball that will carry?",
      situation:{inning:"Top 3",outs:1,count:"0-0",runners:[1],score:[2,1]},
      options:["Take a step back first, then adjust forward if needed","Charge in aggressively right away","Stay frozen and wait to see what happens","Turn and run straight back to the wall"],
      best:0,explanations:["Taking a drop step back first is the golden rule of outfield reads. It's much easier to come forward on a ball than to recover after charging in on a line drive that carries over your head. This protects against the worst outcome — a ball getting behind you for extra bases.","Charging in is tempting, but if this ball has any carry at all, it sails over your head and rolls to the wall, since a single becomes a triple. Only charge when you're 100% sure it's a short fly.","Staying frozen wastes your most precious resource — reaction time, which means every fraction of a second matters on a hard-hit ball. You need to move immediately, and your first step should be back.","Turning and sprinting to the wall only makes sense on an obvious deep fly, because on a ball you're still reading, you'll lose sight of it completely and have no chance to adjust."],
      rates:[85,25,15,20],concept:"On a hard-hit ball, your first step should always be back — it's easier to come in than go back.",explSimple:["Great choice! Taking a drop step back first is the golden rule of outfield reads.","Not the best move. Charging in is tempting, but if this ball has any carry at all, it sails.","Not the best move. Staying frozen wastes your most precious resource — reaction time.","Not the best move. Turning and sprinting to the wall only makes sense on an obvious deep fly."], anim:"catch"},
    {id:"cf10", conceptTag:"backup-duties",title:"Backing Up Second",diff:2,cat:"fielder",ageMin:9,ageMax:99,
      description:"Runner on first takes off stealing. The catcher fires a strong throw to second base. You're in center field about 150 feet behind the bag. The shortstop covers the base.",
      situation:{inning:"Bot 4",outs:0,count:"1-1",runners:[1],score:[3,3]},
      options:["Sprint in behind second base in a direct line with the catcher's throw","Stay in your normal center field position and watch","Move toward second but angle toward the right field side","Drift slowly toward the bag, staying shallow"],
      best:0,explanations:["This is your job on every steal attempt, since you sprint directly behind second base, lined up with the catcher's throw. If the ball gets past the shortstop or bounces away, you're right there to keep the runner from advancing to third. Great center fielders do this automatically.","Staying put is a missed responsibility, because if the throw skips past the infielder, the runner jogs to third with nobody backing up. That turns a stolen base into a runner 90 feet from scoring.","Angling toward right field takes you off the line of the throw. A backup should always be directly behind the base in line with the throw — that way a missed ball comes right to you instead of past you at an angle.","Drifting slowly won't get you close enough — you need to sprint hard to get within 30-40 feet of the bag. A lazy backup is almost as bad as no backup at all."],
      rates:[88,15,30,35],concept:"Center fielders back up second base on every steal attempt and infield throw — sprint in directly behind the bag, in line with the throw.",explSimple:["This is your job on every steal attempt.","Staying put is a missed responsibility.","Angling toward right field takes you off the line of the throw.","Drifting slowly won't get you close enough."],anim:"steal"},
    {id:"cf11", conceptTag:"of-depth-arm-value",title:"Ball Off the Wall",diff:2,cat:"fielder",ageMin:9,ageMax:99,
      description:"Deep fly ball to center field — you turn and chase it but it's going to reach the wall. The ball hits the padded wall about 8 feet high and bounces back. Runner on first is sprinting hard around second. You need to play this carom cleanly.",
      situation:{inning:"Top 6",outs:1,count:"0-0",runners:[1],score:[4,5]},
      options:["Set up a few feet off the wall and field the carom with two hands, then hit your cutoff man","Run to the wall, grab the ball, and throw it as hard as you can to third base","Let the ball bounce to you wherever you end up, then look for a play","Go to the wall and try to catch it on the rebound before it hits the ground"],
      best:0,explanations:["Setting up off the wall is the smart play. Position yourself 5-8 feet from the wall so the ball bounces to you at a playable height. Field it with two hands, turn, and hit your cutoff man. This is the fastest, most reliable way to keep the runner from taking an extra base.","Reaching the wall first and trying to throw from there puts you in a terrible position, which means your body is facing the wall, you have no momentum toward the infield, and a wild throw from deep center with no cutoff man means the runner might score.","Letting the ball come to you passively means it might bounce past you or die at the base of the wall, because you need to be aggressive and set up in the right spot — not just react to wherever the ball ends up.","Trying to catch the carom before it hits the ground is flashy but risky. The ball bounces unpredictably off the wall. If you miss the snag, the ball rolls away and the runner scores easily. Play it safe with a controlled two-hand pickup."],
      rates:[82,25,20,30],concept:"On balls off the wall, set up a few feet away from the wall to play the carom cleanly — don't chase the ball to the wall.",explSimple:["Setting up off the wall is the smart play.","Reaching the wall first and trying to throw from there puts you in a terrible position.","Letting the ball come to you passively means it might bounce past you or die at the base of the wall.","Trying to catch the carom before it hits the ground is flashy but risky."],anim:"hit"},
    {id:"cf12", conceptTag:"of-communication",title:"Gap Communication",diff:1,cat:"fielder",ageMin:6,ageMax:99,
      description:"A fly ball is hit into the right-center gap. Both you and the right fielder are running hard toward the same ball. You're the center fielder and you can see you'll get there at about the same time. Nobody has called for it yet.",
      situation:{inning:"Bot 2",outs:2,count:"0-0",runners:[2],score:[1,0]},
      options:["Call 'I got it! I got it!' loudly and wave off the right fielder","Stay quiet and let the right fielder take it since it's closer to right","Both go for it and whoever gets there first catches it","Slow down and point at the right fielder to take it"],
      best:0,explanations:["The center fielder is the captain of the outfield. On any ball you can reach, you have priority and should call for it loudly and clearly — at least twice. The right fielder is trained to peel off when they hear you call. This prevents collisions and dropped balls.","Staying quiet is the worst thing you can do, since silence causes collisions. Two outfielders running full speed into each other can cause serious injuries. Someone must communicate, and center field has the priority.","'Whoever gets there first' is how collisions happen, because in youth baseball and the pros alike, this is exactly the kind of play that leads to injuries. There must be one clear call and one player backing off.","Slowing down and pointing gives up the play — hand signals are hard to see when both players are sprinting and focused on the ball. Use your voice — it's louder and clearer than a gesture."],
      rates:[90,25,15,40],concept:"The center fielder is the captain of the outfield — call for every ball you can reach, loudly and more than once.",explSimple:["Great choice! The center fielder is the captain of the outfield.","Not the best move. Staying quiet is the worst thing you can do.","Not the best move. 'Whoever gets there first' is how collisions happen.","Not the best move. Slowing down and pointing gives up the play."], anim:"catch"},
    {id:"cf13", conceptTag:"of-depth-arm-value",title:"Dive or Play the Hop",diff:3,cat:"fielder",ageMin:12,ageMax:99,
      description:"Tie game, bottom of the 8th. Runner on second, one out. A sinking line drive is hit to your right in center field. You're sprinting and the ball is dropping fast. If you dive, you might catch it — or it might skip past you to the wall. If you play it on a hop, the runner scores but you keep the batter to a single.",
      situation:{inning:"Bot 8",outs:1,count:"0-0",runners:[2],score:[3,3]},
      options:["Play it on a hop — keep the ball in front of you and limit the damage","Dive for the catch — a spectacular play ends the threat","Slide feet-first to knock the ball down","Pull up and let it bounce to you, then throw home"],
      best:0,explanations:["With one out in a tie game, the risk of diving and missing is too high. If the ball gets past you, both the runner on second AND the batter score — you go from a tie to down two. Playing it on a hop to limit the damage gives up one run but keeps the ball in front of you with two outs coming.","A spectacular catch would end the threat, but the math is brutal. If you miss the dive, the ball rolls to the wall and two runs score instead of one. In a tie game with one out, you can't afford to gamble. Diving is the right call with two outs or a bigger lead — not here.","Feet-first slides in the outfield are dangerous and unpredictable, which means you can't control where the ball goes, and you're likely to kick it past you. This technique doesn't belong in an outfielder's toolbox.","Pulling up and letting it bounce is too passive — the ball may scoot past you or take a bad hop, because you still need to charge and play it aggressively on the short hop, just without leaving your feet."],
      rates:[85,35,10,40],concept:"In a close game with less than two outs, don't dive unless you're sure — a ball past the center fielder is a disaster.",anim:"hit"},
    {id:"cf14", conceptTag:"cutoff-roles",title:"Crow-Hop and Throw",diff:2,cat:"fielder",ageMin:9,ageMax:99,
      description:"Fly ball hit to medium-depth center field. You camp under it and make the catch. Runner on third is tagging up to score. Runner on first is holding. Your arm is decent but the throw home is about 250 feet. The cutoff man is lined up at the mound area.",
      situation:{inning:"Top 5",outs:0,count:"0-0",runners:[1,3],score:[2,3]},
      options:["Crow-hop and throw a strong one-hopper to the cutoff man, letting him decide to cut or let it go","Throw directly home on the fly, skipping the cutoff man","Lob it to second base to keep the runner on first from advancing","Hold the ball since the runner will score easily anyway"],
      best:0,explanations:["The crow-hop gives your throw power and accuracy. Hitting the cutoff man lets him make the final decision — if the runner at third left early or stumbles, the cutoff lets the throw through. If the run is going to score, the cutoff can redirect to keep the runner on first from advancing. Two plays for the price of one.","A 250-foot throw on the fly from medium center is extremely difficult, since if the throw sails or bounces wide without a cutoff, the runner on first moves up to second or third. You've given up an extra base trying to be a hero. Trust your cutoff man.","Throwing to second base completely ignores the runner scoring, because your primary job is to give your team a chance at the plate. Even if the runner is likely to score, you have to make the throw home through the cutoff — that's the play that matters.","Holding the ball gives away the play and lets the runner on first advance for free — even if the run will likely score, your throw through the cutoff man keeps the other runner honest at first base."],
      rates:[85,25,15,20],concept:"Always hit your cutoff man with a crow-hop throw — it gives your team two chances to make a play instead of one.",explSimple:["The crow-hop gives your throw power and accuracy.","A 250-foot throw on the fly from medium center is extremely difficult.","Throwing to second base completely ignores the runner scoring.","Holding the ball gives away the play and lets the runner on first advance for free."],anim:"throwHome"},
    {id:"cf60",title:"Wind Out — How Deep Do You Play?",diff:2,cat:"fielder",conceptTag:"of-depth-arm-value",ageMin:11,ageMax:99,
      description:"You're playing center field. Top 3rd, nobody on, tied 1-1. The wind is blowing straight out at about 15 mph — you've already seen two fly balls carry farther than expected in the first two innings. The cleanup hitter steps up with a 1-0 count. Where do you set up?",
      situation:{inning:"Top 3",outs:1,count:"1-0",runners:[],score:[1,1]},
      options:["Play 10-15 feet deeper than normal — the wind is carrying everything","Play normal depth — adjust on each ball as it comes","Play a few steps shallower — the wind will push the ball back toward you","Stay where you are but shade toward the pull side"],
      best:0,explanations:["With 15 mph wind blowing out, fly balls carry 10-15 feet farther than normal. You've already seen evidence of this in innings 1-2. Playing deeper gives you the cushion to run in on short flies, but prevents balls from sailing over your head. Against the cleanup hitter in a hitter's count, depth is critical.","Adjusting 'on each ball' means you're constantly reacting late, which means set your depth BEFORE the pitch based on known conditions. Two innings of evidence tells you the wind is real.","Shallower is exactly backwards, because wind OUT means balls carry FARTHER, not closer. Playing shallow means routine fly balls become extra-base hits over your head.","Shading to the pull side is a reasonable secondary adjustment, but it doesn't address the primary issue — you need to be DEEPER, since wind direction trumps pull tendency when the wind is this strong."],
      rates:[85,30,10,45],concept:"When the wind blows out at 10+ mph, play 7-15 feet deeper than normal — fly balls carry farther and you need the extra cushion",explSimple:["With 15 mph wind blowing out, fly balls carry 10-15 feet farther than normal.","Adjusting 'on each ball' means you're constantly reacting late.","Shallower is exactly backwards.","Shading to the pull side is a reasonable secondary adjustment, but it doesn't address the primary issue — you need to be DEEPER."],anim:"catch"},
    // ============================================================================
    // OUTFIELD EXPANSION — Center Field advanced scenarios
    // ============================================================================
    {id:"cf15", conceptTag:"of-communication",title:"Reading the Swing — Bat Angle Predicts Direction",diff:3,cat:"fielder",ageMin:12,ageMax:99,
      description:"You're in center field. The batter hits left-handed with a slightly uppercut swing. The pitcher delivers a fastball up in the zone. You see the batter's bat angle as he starts his swing — the bat is tilting upward and his hands are rolling over early. Where is this ball most likely going?",
      situation:{inning:"Top 2",outs:0,count:"1-1",runners:[],score:[0,0]},
      options:["Dead pull to right field — rolled hands on a high fastball = pull side","Straight to center — lefty hitters hit center on fastballs","Opposite field to left — the uppercut creates loft the other way","Foul ball — that bat angle means he's late on the pitch"],
      best:0,explanations:["Correct! When a left-handed hitter rolls his hands over early on a high fastball, the bat angle is closing. This produces a pulled ball to the right side. The uppercut swing combined with early hand roll creates topspin pull-side contact. As a center fielder, you should be shading a step toward right-center as soon as you read the hand roll. Elite outfielders read the swing in the first milliseconds of contact to get a jump.","Straight to center would require the bat to be square at contact, because rolled hands and an uppercut on a high pitch produce pull-side contact, not center.","Opposite field from a lefty rolling his hands over is extremely unlikely — opposite-field hits come from staying inside the ball with hands back — the opposite of what you're seeing.","The bat angle you described is consistent with contact, not a foul ball, which means early hand roll on a high fastball produces a hard pull-side hit, likely in the air."],
      rates:[90,40,15,25],concept:"Read the bat angle at contact — rolled hands and an uppercut on high fastballs produce pull-side fly balls. Shade early for a jump.",anim:"catch"},
    {id:"cf16", conceptTag:"fly-ball-priority",title:"Catchable or Uncatchable — The Split-Second Decision",diff:3,cat:"fielder",ageMin:12,ageMax:99,
      description:"You're in center field. A deep fly ball is hit to right-center gap. You're sprinting at full speed and the ball is drifting farther away. You have about 2 seconds to decide: you MIGHT catch it at full extension with a dive, or you can pull up and play the carom off the wall. Runner on first, 1 out, close game. What's your decision framework?",
      situation:{inning:"Bot 6",outs:1,count:"0-0",runners:[1],score:[3,4]},
      options:["Always dive — making the catch ends the threat","Pull up and play the carom — a missed dive means the ball rolls to the wall and both runners score","Dive only if you're 80%+ sure you can catch it — below that, play the carom","Sprint to the wall and try to play it off the bounce, don't dive at all"],
      best:2,explanations:["'Always dive' ignores risk, because a missed dive with a runner on first and 1 out turns a double into an inside-the-park home run. The ball rolls past you, both runners score, and the batter ends up at third. The risk is catastrophic.","'Never dive' is too conservative. If you're 90% sure you can catch it, the expected value of the dive is much higher than conceding a double. You need a threshold, not a blanket rule.","Correct! The 80% rule: if you're 80% or more confident you can make the catch, dive. Below that, pull up and play the carom. Here's why — with a runner on first and 1 out, a catch ends the at-bat and keeps the runner at first (2 outs now). A missed dive lets both runners score and the batter reaches third. The downside of missing is 3x worse than the upside of catching. So you need high confidence before committing. Game situation matters: if it's 2 outs, lower your threshold because a catch ends the inning.","Sprinting to the wall without attempting the catch concedes extra bases, since if the ball is catchable at full extension, you should at least evaluate the catch probability before giving up on it."],
      rates:[25,35,82,30],concept:"Use the 80% rule on dive decisions: dive if you're 80%+ confident, play the carom below that. The threshold changes with outs and game situation.",anim:"catch"},
    {id:"cf17", conceptTag:"of-depth-arm-value",title:"Getting Behind the Ball — Never Let It Go Over Your Head",diff:1,cat:"fielder",ageMin:8,ageMax:99,
      description:"You're in center field. A fly ball is hit right at you — medium depth, not deep. It's a routine catch. But you notice you're drifting forward toward the ball as it rises. By the time it starts coming down, you realize it's going farther than you thought. What's the fundamental mistake?",
      situation:{inning:"Top 4",outs:1,count:"0-0",runners:[],score:[2,1]},
      options:["Charging hard to catch it earlier would have been better","You should have taken your first step BACK, then come forward if needed","Standing still and waiting to read the ball's full arc was the right call","You should have called for help from the corner outfielders"],
      best:1,explanations:["You should not have charged hard to catch it earlier — that is the opposite of what you need, because you already misjudged the ball as shorter than it was. Charging forward when the ball is deeper makes the problem worse.","Correct! The golden rule of fly ball reads: your first step should always be BACK. Take a drop step backward, read the ball's trajectory, then come forward if it's short. It's much easier to run forward to a ball in front of you than to turn and sprint backward for a ball over your head. A ball over your head is a triple. A ball you run in on is a routine catch. Always give yourself the cushion first, then adjust forward.","Standing still wastes your reaction time — by the time you read the full arc, you've lost 1-2 seconds of running time. The drop step back gives you a head start while you read.","You should not have called for help from the corner outfielders on a ball hit right at you — that means you've already made a positioning error, which means the fix is your first step, not communication."],
      rates:[25,90,40,15],concept:"First step back on every fly ball — it's easier to run forward than to turn and chase a ball over your head",explSimple:["Not the best move. Charging hard is the opposite of what you need.","Great choice! Correct! The golden rule of fly ball reads: your first step should always be BACK.","Not the best move. Standing still wastes your reaction time.","Not the best move. Calling for help on a ball hit right at you means you've already made."], anim:"catch"},
    {id:"cf18",title:"Directing the Outfield — You're the Captain",diff:2,cat:"fielder",conceptTag:"of-communication",ageMin:11,ageMax:99,
      description:"You're the center fielder. Between innings, you notice the left fielder plays too shallow for the power hitter coming up, and the right fielder shades too far toward the line against a hitter who goes opposite field. What do you do?",
      situation:{inning:"Top 3",outs:0,count:"0-0",runners:[],score:[1,1]},
      options:["Mind your own business — each outfielder positions himself","Wave the left fielder back and the right fielder toward the gap — you're the captain","Yell instructions but stay in your own position","Tell the coach between innings and let him fix it"],
      best:1,explanations:["'Mind your own business' ignores the center fielder's primary leadership role. CF is the captain of the outfield because you can see both corners and the whole field. Staying silent when you see a positioning error costs your team.","Correct! The center fielder is the outfield captain. You can see both corners, you know the hitter's tendencies, and you're responsible for the whole outfield alignment. Wave the LF back to prevent extra-base hits over his head, and wave the RF toward the gap to cover the opposite-field hitter's likely spray direction. Do this BEFORE the pitch. Good communication prevents runs before they happen.","Yelling without moving them into position is half the job, because you use hand signals and direct them to specific spots — don't just shout general instructions.","Waiting for the coach wastes an at-bat of poor positioning, since the center fielder has the authority and the view to adjust positioning in real time. The coach may not see the same angles you do from center field."],
      rates:[10,82,40,30],concept:"Center fielder is the outfield captain — direct both corner outfielders into position before every pitch based on the hitter and situation",explSimple:["'Mind your own business' ignores the center fielder's primary leadership role.","The center fielder is the outfield captain.","Yelling without moving them into position is half the job.","Waiting for the coach wastes an at-bat of poor positioning."],anim:"freeze"},
    {id:"cf19",conceptTag:"backup-duties",title:"Backing Up Second on a Steal",diff:1,cat:"fielder",ageMin:6,ageMax:99,
      description:"You're the center fielder. Runner on first, one out. The runner takes off stealing second base. The catcher fires to second and the shortstop catches it. Where should you be right now?",
      situation:{inning:"Top 4",outs:1,count:"1-1",runners:[1],score:[2,1]},
      options:["Behind second base in case the throw gets past the shortstop","Stay in your normal position — the infielders handle steal plays","Run toward the pitcher's mound to help","Move toward right field to cover the gap"],
      best:0,explanations:["As center fielder, you should always sprint toward second base on any steal attempt. If the throw gets past the shortstop or second baseman, you're the last line of defense. Without you backing up, a wild throw rolls to the outfield wall and the runner goes all the way to third or scores.","Staying in your normal position means a throw that gets past the infielders rolls to the wall with nobody behind it, because you must back up second on every steal play.","The pitcher's mound isn't where you're needed, since your backup position is behind the base the throw is going to.","Moving toward right field leaves the area behind second base completely uncovered, which means the backup position for a throw to second is always center field's job."],
      rates:[90,40,15,25],concept:"Center fielders must back up second base on every steal attempt — you're the last line of defense if the throw gets through.",explSimple:["Run behind second base to catch any ball that gets past the infielders.","Staying in your spot means nobody is behind second base if the ball gets away.","The pitcher's mound isn't where you're needed right now.","Moving toward right field means nobody backs up the throw."],anim:"steal"},
    {id:"cf20",conceptTag:"tag-up",title:"Deep Fly to Center — Tag-Up Relay",diff:2,cat:"fielder",ageMin:9,ageMax:99,
      description:"You're the center fielder. Runner on third, one out. Deep fly ball hit to straightaway center. You catch it easily near the warning track. The runner on third tags up and is heading home. You're 320 feet from home plate. Where do you throw?",
      situation:{inning:"Bot 5",outs:1,count:"0-0",runners:[3],score:[3,3]},
      options:["Throw directly home — skip the cutoff and try to nail the runner","Hit the cutoff man with a strong low throw so he can relay it home","Hold the ball — the runner will score anyway from that distance","Throw to second base to keep the batter from advancing"],
      best:1,explanations:["From 320 feet, even the strongest arms can't consistently reach home accurately on a fly, because a throw that bounces multiple times loses speed and accuracy. The cutoff man relay is faster and more accurate.","Hitting the cutoff man is the right play, since your throw travels 150 feet accurately to the cutoff, and his relay goes another 150 feet to home. Two accurate throws beat one wild one. The cutoff man can also redirect or hold if the runner stops.","Never give up on a play with the game tied, because the cutoff relay system gives you a real chance to get the runner.","With the tying run heading home, throwing to second ignores the priority — stop the run first, worry about the batter later."],
      rates:[40,90,15,25],concept:"On tag-up plays from deep outfield, always hit the cutoff man — the relay system is faster and more accurate than a 300+ foot throw.",explSimple:["Throwing that far usually bounces too many times and goes offline.","Hitting the cutoff man is the smartest play — he relays it home fast and accurate.","Never give up on a play with the game tied. Make the throw!","The runner going home is more important than the batter right now."],anim:"throwHome"},
    {id:"cf21",conceptTag:"of-communication",title:"Ball in the Left-Center Gap",diff:1,cat:"fielder",ageMin:6,ageMax:99,
      description:"You're the center fielder. A fly ball is hit into the gap between you and the left fielder. You're both running hard toward the ball. You can get there, but so can the left fielder. Nobody has called for it yet. What do you do?",
      situation:{inning:"Top 2",outs:1,count:"0-0",runners:[],score:[0,0]},
      options:["Call 'I got it!' loudly — center fielder has priority in the gaps","Stay quiet and let the left fielder take it since it's closer to his area","Both go for it and whoever gets there first catches it","Stop running and wave the left fielder over to take it"],
      best:0,explanations:["The center fielder is the outfield captain and has priority on any ball they can reach, which means in the gaps between outfielders, CF always calls for the ball. You're running toward the infield which gives you a better angle. Call it loud and early!","Staying quiet is dangerous — two fielders converging without communication is how collisions happen, because as center fielder, it's YOUR job to take charge in the gaps.","Going for a fly ball without communicating is the most dangerous play in baseball, since always communicate — call it or get out of the way.","Stopping and waving wastes precious time. If you can get to it, call for it and catch it. The center fielder has priority in the gaps."],
      rates:[90,25,15,40],concept:"The center fielder is the outfield captain — you have priority on any ball in the gaps. Call it loud and early.",explSimple:["The center fielder is the boss in the outfield. Call for the ball!","Staying quiet means you might crash into the left fielder.","Running to the same spot without talking can cause a bad collision.","Stopping and waving wastes time. Just call for the ball!"],anim:"catch"},
    {id:"cf22",conceptTag:"of-depth-arm-value",title:"Ball Off the Center Field Wall",diff:3,cat:"fielder",ageMin:12,ageMax:99,
      description:"You're the center fielder. Runner on first, nobody out, tie game. A hard line drive hits the center field wall on one hop and ricochets straight back toward you. You're 10 feet from the wall. The runner from first is being waved to third. How do you play this?",
      situation:{inning:"Bot 7",outs:0,count:"0-0",runners:[1],score:[2,2]},
      options:["Field the carom cleanly, spin, and hit the relay man between you and third","Let the ball bounce to you, pick it up, and throw directly to third base","Charge the ball hard, bare-hand it, and fire home","Catch the carom and hold the ball — the runner will make third anyway"],
      best:0,explanations:["On wall caroms, the key is fielding cleanly and getting the ball to the relay man quickly. The relay man sets up between you and the target base, giving you a shorter accurate throw. Two quick throws beat one long one.","Throwing directly to third from the warning track is a 200+ foot throw, because even with a clean carom, the accuracy drops significantly. The relay system exists for exactly this situation.","Bare-handing a carom off the wall is extremely risky — the ball comes off unpredictably. Field it with your glove first, then transfer and find the relay man.","Holding the ball concedes third base and possibly lets the batter take second, which means in a tie game, get the ball to the relay man."],
      rates:[82,30,15,20],concept:"On wall caroms, field cleanly with your glove and hit the relay man quickly. The relay system is faster and more accurate than long throws from the wall.",explSimple:["Field the ball cleanly and throw to the relay man. Two quick throws beat one long one.","Throwing all the way to third from the wall is too far and inaccurate.","Bare-handing a wall carom is risky — use your glove and find the relay man.","Holding the ball gives up extra bases. Get it to the relay man!"],anim:"throwHome"},
    {id:"cf23",conceptTag:"fly-ball-priority",title:"Shallow Pop-Up — You or the Shortstop?",diff:1,cat:"fielder",ageMin:6,ageMax:99,
      description:"You're the center fielder. A short pop-up is hit to shallow center field. The shortstop drifts back and you're charging in. You can both reach the ball. Who should catch it?",
      situation:{inning:"Top 5",outs:2,count:"2-2",runners:[1],score:[1,0]},
      options:["Call for it and take charge — the outfielder running in has a better angle","Let the shortstop take it since infielders have priority on pop flies","Both go for it and the faster player catches it","Pull up and point at the shortstop to take it"],
      best:0,explanations:["You have the ball in front of you the entire way as you run in. The shortstop is running backwards, which is much harder. Outfielders always have priority over infielders on balls they can reach because you running forward is easier and safer than running backward.","Infielders have priority on infield pop-ups, but NOT on balls in the outfield, because when the ball is in the shallow outfield, the outfielder running in has a better angle and should take it.","Running to the same spot without communicating is dangerous, since two players colliding at full speed causes injuries. One player must call for it — and on this play, it should be you.","Pulling up wastes your advantage, because you have the better angle running in. Take charge, call it loud, and make the catch."],
      rates:[90,40,15,25],concept:"Outfielders have priority over infielders on shallow fly balls because you running in is easier and safer than running out.",explSimple:["You're running forward and can see the ball the whole time. Call for it!","Infielders have priority on infield pop-ups, but not balls in the outfield.","Running to the same spot without talking is dangerous.","Don't pull up — you have the better angle. Call for the ball and catch it."],anim:"catch"},
    {id:"cf_tc1",conceptTag:"team-communication",title:"Fly Ball in the Gap — Calling the Ball",diff:1,cat:"communication",ageMin:9,ageMax:99,
      description:"You're the center fielder. A fly ball is hit into the right-center gap. Both you and the right fielder are running toward it. You can both reach it. How do you handle this?",
      situation:{inning:"Top 6",outs:1,count:"0-0",runners:[1],score:[2,1]},
      options:["Call 'I got it!' loudly and repeatedly while running toward the ball","Stay quiet and let the right fielder call for it since it's closer to his side","Both go for it and whoever gets there first catches it","Wave your arm but don't say anything"],
      best:0,explanations:["As the center fielder, you have priority over all other outfielders on any fly ball you can reach. Call loudly and early — 'I got it! I got it!' — so the right fielder hears you and peels off. Your voice is the most important tool in the outfield, and calling the ball prevents collisions.","Staying quiet is the most dangerous thing you can do on a gap fly ball. If neither player calls it, both arrive at the same spot at full speed and collide. Center field has priority over corner outfielders, so it's YOUR job to call for the ball.","Going for the ball without communicating leads to collisions that cause injuries. Two outfielders reaching for the same ball is how players get hurt. One player calls, the other backs off — every time.","Waving without yelling doesn't work because the right fielder is watching the ball, not you. Your voice carries across the outfield, and that's how you communicate. Call it loud and call it early."],
      explSimple:["You're the center fielder, so you're the boss! Call 'I got it!' loud so the right fielder knows to stop.","Don't stay quiet! If nobody calls it, you might crash into each other.","Both going for it without talking is how outfielders get hurt. One person calls it!","Waving your arm doesn't work because the right fielder is watching the ball. Use your voice!"],
      rates:[80,35,15,35],concept:"Center fielders have priority on all fly balls they can reach — call loudly and early to prevent collisions in the gaps",anim:"catch"},
    {id:"cf_wl1",title:"Wall Play — Carom Off Dead Center",diff:2,cat:"outfield",conceptTag:"of-wall-play",ageMin:11,ageMax:99,
      description:"You're the center fielder. A ball is hit hard off the wall in dead center field and caroms straight back toward you. You're about 10 feet from the wall. The batter-runner is rounding first hard and the runner from first is heading for third. What do you do with the ball?",
      situation:{inning:"Top 4",outs:0,count:"0-0",runners:[1],score:[1,1]},
      options:["Field the carom cleanly and hit the relay man lined up between you and third","Bare-hand the ball and throw directly to third base","Let the ball roll to you and then throw home to cut off the lead runner","Hold the ball and keep both runners from advancing further"],
      best:0,explanations:["On a carom straight back off the center field wall, your first job is to field the ball cleanly with your glove. Then find the relay man — he should be lined up between you and third base. Two quick, accurate throws beat one long throw from the warning track every time. The relay system is built for exactly this play, and your job is to get the ball into it as fast as possible.","Bare-handing a carom off the wall is a high-risk play. Wall caroms come back at unpredictable speeds and angles, and fumbling a bare-hand attempt turns a single into a triple. Use your glove, secure the ball, and make a strong throw to the relay man.","Letting the ball roll to you wastes time — every second the ball is on the ground, runners are advancing. Charge the carom, field it on the move, and get the ball to the relay man. A throw home from deep center is 350+ feet and almost never accurate enough.","Holding the ball concedes extra bases for free. In a tie game with a runner heading for third and the batter heading for second, you need to make a play. Get the ball to the relay man and let the infield make the decision."],
      rates:[82,20,30,33],concept:"On wall caroms in center, field the ball cleanly with your glove and hit the relay man — the relay system is faster than any direct throw from the wall",explSimple:["Field the carom and hit the relay man. Two quick throws beat one long one!","Bare-handing a wall carom is too risky. Use your glove!","Letting the ball roll wastes time. Charge it and throw to the relay man.","Holding the ball gives up extra bases. Get it to the relay man!"],anim:"throwHome"},
  ],
  leftField: [
    {id:"f9", conceptTag:"of-depth-arm-value",title:"Ball in the Sun",diff:1,cat:"outfield",ageMin:6,ageMax:99,
      description:"High fly ball headed right into the sun. You lose sight of it.",
      situation:{inning:"Top 7",outs:2,count:"1-1",runners:[1],score:[3,2]},
      options:["Glove up to shade your eyes","Keep running where you think it's going","Stop and call for help","Drop to one knee"],
      best:0,explanations:["The glove-up technique is standard sun defense — practice it every spring.","Running blind is how you misplay balls badly.","By the time help arrives, the ball has landed.","Dropping to one knee blocks even less sun — hold your glove high to actually block the glare."],
      explSimple:["Hold your glove up to block the sun from your eyes. That way you can still see the ball!","Running without seeing where the ball is means you'll probably miss it.","If you stop and call for help, the ball will land before anyone gets there.","Dropping to your knee doesn't block the sun — you need your glove up high."],
      rates:[85,25,35,30],concept:"Use your glove to shade the sun — fundamental outfield technique",anim:"catch"},
    {id:"f28", conceptTag:"cutoff-roles",title:"Runner Trying to Score from First on a Double",diff:2,cat:"outfield",ageMin:9,ageMax:99,
      description:"Bot 5th, runner on 1st, nobody out, down 3-2. Ball bounces off the left field wall — it's a double. Runner from first is trying to score all the way from first base.",
      situation:{inning:"Bot 5",outs:0,count:"0-0",runners:[1],score:[3,2]},
      options:["Throw home — he started from first, it's a long run","Hit the relay man lined up between you and home","Throw to third — stop the batter from getting to third","Hold the ball — the runner will score anyway"],
      best:1,explanations:["A throw from the left field wall to home is 350+ feet. Even if you have a cannon arm, that throw bounces 3 times and arrives too late.","The relay man is your best friend on balls off the wall. He should be positioned between you and home. Fire a strong, chest-high throw to him. He catches and fires home. This is how runners get thrown out from the outfield — through relay throws, not one long heave.","The run scoring is more important than holding the batter at second, which means stop the run first.","Never give up on a play, because even if the runner probably scores, a strong relay throw can save a run."],
      rates:[40,90,25,15],concept:"On doubles off the wall, the relay throw is essential — no arm is strong enough to throw 350 feet accurately",explSimple:["A throw from the left field wall to home is 350+ feet.","The relay man is your best friend on balls off the wall.","The run scoring is more important than holding the batter at second.","Never give up on a play."],anim:"throwHome"},
    {id:"f29", conceptTag:"of-depth-arm-value",title:"Ball Off the Wall — Play It Quick",diff:2,cat:"outfield",ageMin:9,ageMax:99,
      description:"Top of the 8th, nobody on, 1 out, up 5-4. Ball slices toward the left field corner and hits the wall. You're the left fielder — the ball caroms off at an angle.",
      situation:{inning:"Top 8",outs:1,count:"0-0",runners:[],score:[5,4]},
      options:["Chase the ball and play the carom off the wall","Wait for the ball to settle on the ground","Sprint to the ball but be cautious of the wall","Let the center fielder back you up and play it"],
      best:0,explanations:["Play the carom! When a ball hits the wall, read the angle it bounces and position yourself to field it quickly, since you getting the ball back to the infield fast is the difference between holding the batter to a double or letting him reach third.","Waiting for the ball to settle lets the runner take an extra base, because every second counts.","Being cautious of the wall is important for safety, but you should know where the wall is before the ball is hit — attack the carom.","Waiting for backup wastes time, which means you're the closest player — play it yourself and get the ball back in."],
      rates:[85,15,55,25],concept:"Play the carom off the wall quickly — reading the angle and fielding fast prevents extra bases",explSimple:["When a ball hits the wall, read the angle it bounces and position yourself to field it quickly.","Waiting for the ball to settle lets the runner take an extra base.","Being cautious of the wall is important for safety, but you should know where the wall is before the ball is hit.","Waiting for backup wastes time."],anim:"hit"},
    {id:"f54", conceptTag:"fly-ball-priority",title:"Line Drive Sinking — Dive or Play It Safe?",diff:2,cat:"outfield",ageMin:9,ageMax:99,
      description:"Top of the 7th, runner on 1st, 2 outs, up 4-3. Line drive sinking in front of you in left field. If you dive and catch it, the inning is over. If you miss, the ball rolls past you.",
      situation:{inning:"Top 7",outs:2,count:"0-0",runners:[1],score:[4,3]},
      options:["Dive for it — catch it and end the inning","Play it on a hop — keep the damage to a single","Slide feet-first to catch it low","Let it bounce and field it quickly"],
      best:0,explanations:["With 2 outs and a lead, dive for it! If you catch it, the inning is over. If you miss, the worst case is the ball gets past you and the tying run scores. But with 2 outs, you want to end the inning NOW. The risk of diving is worth the reward of ending the threat.","Playing it on a hop concedes a single and keeps the inning alive with the tying run at the plate — you want to end this inning now, not extend it.","Sliding feet-first in the outfield is not a standard technique for catching a sinking liner.","Letting it bounce guarantees a base hit and extends the inning — with 2 outs and a lead, go for the catch and end it."],
      rates:[85,40,15,25],concept:"With 2 outs and a lead, dive for sinking liners — ending the inning is worth the risk",explSimple:["With 2 outs and a lead, dive for it!","Playing it on a hop concedes a single and keeps the inning alive with the tying run at the plate.","Sliding feet-first in the outfield is not a standard technique for catching a sinking liner.","Letting it bounce guarantees a base hit and extends the inning."],anim:"catch"},
    {id:"f57", conceptTag:"of-depth-arm-value",title:"Wind Blowing Out — Play Deeper",diff:3,cat:"outfield",ageMin:12,ageMax:99,
      description:"Bot 5th, nobody on, tied 2-2. The wind is blowing hard toward the outfield today — straight out. A routine fly ball in the 2nd inning carried 20 feet farther than expected.",
      situation:{inning:"Bot 5",outs:0,count:"0-0",runners:[],score:[2,2]},
      options:["Play deeper than normal — give yourself more room","Play normal depth — adjust on each ball","Play shallow — the wind won't affect line drives","It doesn't matter — just react to each ball"],
      best:0,explanations:["When the wind is blowing out, play 10-15 feet deeper than normal. Fly balls will carry farther, and balls that would normally be warning track fly outs become home runs or extra-base hits if you're playing too shallow. Depth is your friend with the wind at your back.","Adjusting on each ball means you're constantly behind, since you set your depth before the pitch.","Playing shallow is the OPPOSITE of what you should do, because wind blowing out means balls carry — give yourself room.","It absolutely matters. A ball you would normally catch at the warning track now sails over the fence if you're too shallow."],
      rates:[85,35,10,20],concept:"When the wind blows out, play deeper — fly balls carry farther and you need the extra room",anim:"catch"},
    {id:"lf1",title:"Hit the Cutoff",diff:1,cat:"fielder",conceptTag:"cutoff-roles",ageMin:9,ageMax:99,
      description:"You're the left fielder. Bottom of the 4th, runner on second, one out. The batter singles to your left. You field it cleanly about 20 feet from the foul line. The runner is rounding third and heading home. Your third baseman has lined up as the cutoff man.",
      situation:{inning:"Bot 4",outs:1,count:"0-2",runners:[2],score:[3,1]},
      options:["Throw a strong one-hopper to the cutoff man's chest","Throw it directly to home plate, skipping the cutoff","Throw it to third base to keep the batter from advancing","Hold the ball and jog it in"],
      best:0,explanations:["Hitting the cutoff man gives your team options — he can let it go through to the plate or redirect it — a one-hopper to his chest is a throw he can handle cleanly.","Trying to skip the cutoff from deep left field often leads to wild throws that miss everyone, which means even strong arms should use the relay to keep throws accurate.","Throwing to third ignores the runner scoring, because the priority is always the lead runner, and right now he's heading home.","Holding the ball lets the runner score easily and the batter take extra bases, since you must get the ball in quickly."],
      rates:[90,40,25,15],concept:"Always hit the cutoff man — it keeps your throw accurate and gives your team options on where to send the ball.",explSimple:["Great choice! Hitting the cutoff man gives your team options — he can let it go through.","Trying to skip the cutoff from deep left field often leads to wild throws that miss everyone.","Not the best move. Throwing to third ignores the runner scoring.","Not the best move. Holding the ball lets the runner score easily and the batter take extra bases."], anim:"throwHome"},
    {id:"lf2", conceptTag:"of-depth-arm-value",title:"Ball Off the Wall",diff:2,cat:"fielder",ageMin:9,ageMax:99,
      description:"You're in left field. Top of the 6th, runner on first, no outs. The batter drives a ball to the left field corner. It hits the wall and caroms back at a sharp angle toward center field. You're running toward the corner to play the bounce.",
      situation:{inning:"Top 6",outs:0,count:"1-0",runners:[1],score:[2,2]},
      options:["Round the ball so your momentum carries toward the infield as you field it","Run straight to the ball, pick it up, then spin and throw","Let the ball come to you off the wall and wait for it to settle","Call for the center fielder to get it since it bounced toward him"],
      best:0,explanations:["Rounding the ball lets you field it with your momentum already going toward the infield, because you save a full second compared to fielding and spinning, which can be the difference between the runner being safe or out.","Running straight at the ball means you have to stop, field, spin 180 degrees, then throw — that wasted motion gives runners extra bases.","Waiting for the ball to settle is way too passive, which means every second you wait, runners are advancing. Attack the ball off the wall.","The ball is in your territory — calling off to the center fielder creates confusion and delays, because you're closer and it's your wall to play."],
      rates:[85,40,15,20],concept:"Round the ball off the wall so your momentum is already heading toward the infield — never field and spin.",explSimple:["Rounding the ball lets you field it with your momentum already going toward the infield.","Running straight at the ball means you have to stop, field, spin 180 degrees, then throw.","Waiting for the ball to settle is way too passive.","The ball is in your territory — calling off to the center fielder creates confusion and delays."],anim:"catch"},
    {id:"lf3",title:"Shallow Fly Communication",diff:1,cat:"fielder",conceptTag:"fly-ball-priority",ageMin:6,ageMax:99,
      description:"You're the left fielder. Bottom of the 3rd, nobody on, two outs. The batter hits a soft fly ball that's dropping into short left field. You're running in hard, and you can see the shortstop backpedaling toward the same spot. You're going to get there at the same moment.",
      situation:{inning:"Bot 3",outs:2,count:"0-0",runners:[],score:[1,0]},
      options:["Call 'I got it!' loudly and early so the shortstop peels off","Stay quiet and let the shortstop take it since he's an infielder","Both go for it and whoever gets there first catches it","Pull up and let the shortstop have it — infielders have priority on shallow flies"],
      best:0,explanations:["As the outfielder coming in, you have the ball in front of you the whole way, since you have the better angle and can see it clearly. Call it loud and early so the shortstop knows to peel off.","Wrong — outfielders have priority over infielders on balls in front of them. You're running IN with the ball in front of you the whole way. The shortstop is running BACK and can't see the ball as well. Priority goes to the player running toward the ball. Center field has priority because they're always running IN — corner outfielders back off when CF calls it. Call it loud, call it early.","Both going for it without talking is how players get hurt, because collisions between fielders are one of the most dangerous plays in baseball.","Actually, on balls in between, the outfielder has priority because they're running in and can see the ball better. The shortstop is running with his back to the infield, making it a harder catch."],
      rates:[88,15,10,40],concept:"Outfielders have priority on shallow flies because they're running forward with the ball in front of them — call it loud and early.",explSimple:["Great choice! As the outfielder coming in, you have the ball in front of you the whole way.","Not the best move. Wrong — outfielders have priority over infielders on balls in front of them.","Not the best move. Both going for it without talking is how players get hurt.","Not the best move. Actually, on balls in between, the outfielder has priority because they're running in and can."], anim:"catch"},
    {id:"lf4",title:"Back Up Third",diff:1,cat:"fielder",conceptTag:"backup-duties",ageMin:8,ageMax:99,
      description:"You're in left field. Top of the 5th, runner on first, no outs. The batter hits a ground ball to second base. The second baseman fields it and throws to the shortstop at second for the force out. The shortstop now throws to first for the double play. Where should you be?",
      situation:{inning:"Top 5",outs:0,count:"1-1",runners:[1],score:[3,3]},
      options:["Backing up third base in case of an overthrow from the outfield later","Stay in your normal left field position — the play is on the infield","Move toward the infield to back up any throw to third base","Back up second base in case the throw from the shortstop is wild"],
      best:2,explanations:["You're thinking ahead, but the immediate play might involve a throw to third if the double play doesn't turn — moving toward third to back up is the smart positioning right now.","Standing in your normal spot means you're too far away to help if a throw gets away, which means left fielders should always be moving toward a backup position on ground balls.","Correct! On ground balls with a runner on first, the left fielder backs up third base, because if the throw from second goes wild, or if a runner advances to third, you're there to prevent extra bases.","Second base is the center fielder's backup responsibility, not yours, since as the left fielder, third base is your backup assignment."],
      rates:[55,10,85,20],concept:"On ground balls, the left fielder always moves to back up third base — every throw needs a backup behind it.",explSimple:["Not the best move. You're thinking ahead, but the immediate play might involve a throw to third if.","Not the best move. Standing in your normal spot means you're too far away to help if.","Great choice! Correct! On ground balls with a runner on first, the left fielder backs up third base.","Not the best move. Second base is the center fielder's backup responsibility, not yours."], anim:"groundout"},
    {id:"lf5", conceptTag:"cutoff-roles",title:"Two Runners Moving",diff:3,cat:"fielder",ageMin:12,ageMax:99,
      description:"You're the left fielder. Bottom of the 7th, runners on first and second, one out, tie game. The batter singles hard into left field. The runner from second is scoring easily. The runner from first is rounding second and heading to third. The batter takes a wide turn at first.",
      situation:{inning:"Bot 7",outs:1,count:"2-0",runners:[1,2],score:[3,3]},
      options:["Throw to third base to try to get the runner coming from first","Throw home to try to get the runner scoring from second","Hit the cutoff man and let him decide where to throw","Throw to second base to get the batter trying to stretch it"],
      best:2,explanations:["The runner from first has a huge head start to third, because by the time you field and throw, he's likely safe. You might also throw it away and let the batter advance.","The runner from second is scoring easily — there's no play at home — throwing there wastes your time and lets other runners advance.","With multiple runners moving, hitting the cutoff man is the smartest play. He can see all the runners and redirect the throw to wherever the best play is. This prevents wild throws.","The batter is just rounding first, which means throwing behind him to second is a low-value play when you have a runner going to third. Get the ball to the cutoff."],
      rates:[30,10,85,20],concept:"With multiple runners moving, always hit the cutoff man — he can see the whole field and redirect to the best play.",anim:"throwHome"},
    {id:"lf6", conceptTag:"of-depth-arm-value",title:"Reading Off the Bat",diff:2,cat:"fielder",ageMin:9,ageMax:99,
      description:"You're in left field. Top of the 1st, nobody on, no outs. A right-handed batter swings and you hear a loud crack. The ball comes off the bat high in the air, hooking toward you. Your first step will determine if you catch it or it drops.",
      situation:{inning:"Top 1",outs:0,count:"2-1",runners:[],score:[0,0]},
      options:["Take a drop step back and to your right, then read the ball in the air","Take a step forward to charge the ball","Stand still and watch the trajectory for a moment before moving","Break hard toward center field since right-handed hitters usually pull"],
      best:0,explanations:["A drop step back opens your hips and lets you cover ground quickly, because a high fly ball hooking toward left from a right-hander usually carries more than you think. Getting back first is safer — you can always come in.","Charging forward on a high fly ball is dangerous, since if it carries over your head, you can't recover. It's much easier to come in on a ball than to go back.","Standing still wastes your best reaction time, because your first step in the first half-second determines whether you reach the ball. Read and react immediately.","Breaking toward center ignores where the ball actually is — it's hooking toward you in left, not going to center — react to the ball, not a guess about the hitter."],
      rates:[85,20,30,15],concept:"On fly balls, your first step determines everything — a drop step back gives you time to read the carry and adjust.",explSimple:["A drop step back opens your hips and lets you cover ground quickly.","Charging forward on a high fly ball is dangerous.","Standing still wastes your best reaction time.","Breaking toward center ignores where the ball actually is — it's hooking toward you in left, not going to center."],anim:"flyout"},
    {id:"lf7", conceptTag:"of-depth-arm-value",title:"Sun in Your Eyes",diff:3,cat:"fielder",ageMin:12,ageMax:99,
      description:"You're the left fielder. Bottom of the 2nd in an afternoon game. The sun is low and directly in your eyes when you look toward home plate. A high fly ball is hit your way and you immediately lose it in the sun. You know it's somewhere above you.",
      situation:{inning:"Bot 2",outs:0,count:"1-0",runners:[],score:[0,0]},
      options:["Use your glove to shade the sun while tracking the ball","Turn your head sideways and try to pick up the ball's shadow on the grass","Put your sunglasses down, shift your head to find the ball out of the sun's glare, and get under it","Close your eyes and put your glove up where you think it will land"],
      best:2,explanations:["Using your glove to shade works and is a solid backup technique. Every outfielder should know the glove-shield method — raise your glove to block the sun while tracking the ball. If you don't have sunglasses, this is your go-to move.","Looking for the ball's shadow is creative but unreliable — since shadows shift depending on the sun angle and the grass, and it doesn't help you judge the ball's height.","Dropping your sunglasses, shifting your angle to find the ball outside the sun's glare, and repositioning is the best technique when you have sunglasses, which means but the glove-shield is a strong backup — use both together if needed.","Closing your eyes and guessing is never a good idea, because the ball could hit you in the face. You need to find a way to track it."],
      rates:[55,15,85,10],concept:"In the sun, use sunglasses AND the glove-shield technique — sunglasses are primary, glove-up is your always-available backup.",anim:"flyout"},
    {id:"lf8", conceptTag:"of-depth-arm-value",title:"Dive or Play Safe",diff:3,cat:"fielder",ageMin:12,ageMax:99,
      description:"You're in left field. Top of the 8th, your team leads 6-3. Runner on first, two outs. The batter hits a sinking line drive to your left. You can probably catch it with a full dive, but if you miss, the ball rolls to the wall and at least one run scores — maybe two.",
      situation:{inning:"Top 8",outs:2,count:"0-1",runners:[1],score:[6,3]},
      options:["Play it safe on a hop — keep the ball in front of you and hold the runner to second","Dive for the catch — with two outs, the inning is over if you catch it","Sprint and try a sliding catch to stay in control","Dive but angle your body so if you miss, the ball stays in front of you"],
      best:0,explanations:["With a 3-run lead in the 8th and two outs, playing it safe is the percentage play. If the ball gets past you, you turn a 3-run lead into a 1-run game. Keeping it in front means runners on first and second with two outs — your pitcher can get the next guy.","A diving catch ends the inning, but if you miss, the ball rolls to the wall and suddenly it's a one-run game. The risk isn't worth the reward when you're protecting a lead.","A sliding catch sounds controlled, but on a sinking liner to your side, a slide is hard to execute. If you misjudge it, you're on the ground and the ball is rolling away.","Angling your dive is good in theory, but it's very hard to control where your body goes mid-dive. If you're going to play it safe, commit to playing it safe."],
      rates:[82,30,35,40],concept:"With a comfortable lead and two outs, play it safe — keeping the ball in front of you protects your lead better than a risky dive.",anim:"catch"},

    {id:"lf9", conceptTag:"of-depth-arm-value",title:"Charging a Ground Single",diff:2,cat:"fielder",ageMin:9,ageMax:99,
      description:"Ground ball single slices through the left side of the infield. Runner on first is rounding second and heading for third. The ball is rolling on the grass toward you in left field. You've got a chance to throw the runner out if you charge hard and field it cleanly.",
      situation:{inning:"Bot 3",outs:1,count:"0-0",runners:[1],score:[1,2]},
      options:["Charge hard, field the ball outside your glove foot, and throw to third in one motion","Charge, pick it up, set your feet, and make a strong throw to third","Jog in, field it safely, and hold the runner at third with the threat of a throw","Run hard to the ball, barehand it, and fire to third"],
      best:0,explanations:["Charging hard and fielding outside your glove-side foot puts your body in perfect throwing position. You can field and throw in one fluid motion without wasting time setting your feet. This is the outfielder's version of a shortstop's charging play — momentum toward the target creates a fast, accurate throw.","Stopping to set your feet costs you a full second, and that's the difference between out and safe, since by the time you plant and throw, the runner has already slid into third. The charge-and-throw in one motion is what separates great outfielders from average ones.","Jogging in concedes the base. If you don't challenge the runner, they take third every time. With one out, a runner on third scores on a fly ball, a wild pitch, or a passed ball. You have to at least try to get them.","Barehanding a ground ball in the outfield is extremely risky. If you bobble it, the ball rolls behind you and the runner might score. Use your glove — that's what it's there for. Barehand plays are for infielders on slow rollers, not outfielders."],
      rates:[82,40,25,20],concept:"Charge ground balls aggressively and field outside your glove foot — this lets you throw in one smooth motion without stopping.",explSimple:["Charging hard and fielding outside your glove-side foot puts your body in perfect throwing position.","Stopping to set your feet costs you a full second, and that's the difference between out and safe.","Jogging in concedes the base.","Barehanding a ground ball in the outfield is extremely risky."],anim:"groundout"},
    {id:"lf10", conceptTag:"backup-duties",title:"Backing Up Third Base",diff:1,cat:"fielder",ageMin:6,ageMax:99,
      description:"Runner on second base tries to steal third. The catcher jumps up and fires a throw to the third baseman. You're the left fielder standing in your normal position. The throw looks a little high and might get past the third baseman.",
      situation:{inning:"Top 5",outs:1,count:"2-1",runners:[2],score:[3,2]},
      options:["Sprint toward the area behind third base in line with the catcher's throw","Stay in your position — that's the third baseman's play","Run toward the foul line to back up any ball that goes into the stands","Move toward shortstop position to help relay"],
      best:0,explanations:["This is left field's responsibility on every throw to third. Sprint to a spot about 30 feet behind third base, directly in line with the catcher's throw. If the ball gets past the third baseman, you're right there to grab it and keep the runner from scoring. This is a fundamental play that youth coaches love to see.","Staying put is a mistake, because if that high throw gets past the third baseman and nobody is backing up, the runner scores on what should have been a simple steal attempt. Left fielders who don't back up third base cost their team runs.","Running to the foul line takes you out of the line of the throw, since a backup should always be directly behind the base in line with the throw. The ball won't bounce sideways toward the stands — it'll skip straight back.","Moving to shortstop position doesn't help on this play at all, which means the throw is going from the catcher to third base, and you need to be behind third base, not beside it."],
      rates:[90,25,40,15],concept:"The left fielder always backs up third base on throws from the catcher — sprint behind the bag, in line with the throw.",explSimple:["Great choice! This is left field's responsibility on every throw to third.","Not the best move. Staying put is a mistake.","Not the best move. Running to the foul line takes you out of the line of the throw.","Not the best move. Moving to shortstop position doesn't help on this play at all."], anim:"steal"},
    {id:"lf11", conceptTag:"of-communication",title:"Lost in the Sun",diff:2,cat:"fielder",ageMin:9,ageMax:99,
      description:"Afternoon game and the sun is brutal in left field. A high fly ball is hit your way and as you look up, you lose the ball completely in the blinding sun. You had a read on it for a second — it's coming down somewhere near you. The crowd is yelling.",
      situation:{inning:"Bot 4",outs:0,count:"0-0",runners:[1],score:[0,1]},
      options:["Use your glove to shade the sun, shift your angle slightly, and try to pick the ball back up","Keep staring straight up into the sun — you'll find it eventually","Turn away from the sun and listen for your teammates to guide you to the ball","Drop to one knee and let the ball bounce in front of you to play it safe"],
      best:0,explanations:["Using your glove as a sun shield is the textbook move. Hold it up above your eyes to block the sun while shifting your angle a step or two to either side. This often lets you reacquire the ball against a different part of the sky. Sunglasses help, but the glove shade is every outfielder's best friend on sun-field plays.","Staring directly into the sun is dangerous for your eyes and won't help you find the ball, because the longer you stare, the worse the spots in your vision become. You need to shade your eyes and change your viewing angle.","Turning away from the ball completely means you have zero chance of catching it, since your teammates can yell, but they can't guide you precisely enough in the 2-3 seconds a fly ball is in the air. You need to keep your eyes in the general area of the ball.","Dropping to a knee is giving up on the play, because the ball could land anywhere, and if it bounces over you, runners advance freely. You should always try to track the ball — shade your eyes and fight to find it."],
      rates:[82,10,30,25],concept:"When you lose a ball in the sun, use your glove to shade your eyes and shift your angle — never stare directly into the sun.",explSimple:["Using your glove as a sun shield is the the right way to do it move.","Staring directly into the sun is dangerous for your eyes and won't help you find the ball.","Turning away from the ball completely means you have zero chance of catching it.","Dropping to a knee is giving up on the play."],anim:"flyout"},
    {id:"lf13", conceptTag:"relay-double-cut",title:"Reading the Wall Carom",diff:3,cat:"fielder",ageMin:12,ageMax:99,
      description:"Scoreless game, runner on first, one out. A screaming line drive hooks toward the left field corner and hits the angled wall where the foul line meets the outfield fence. The ball ricochets hard and shoots back toward center field. You chased it to the corner and now the carom is bouncing away from you.",
      situation:{inning:"Top 7",outs:1,count:"0-0",runners:[1],score:[0,0]},
      options:["Let the center fielder grab the carom — redirect and become the relay man between CF and the infield","Chase the ball down yourself even though it's moving away from you","Run to the wall where the ball hit and wait for it to come back","Yell for the third baseman to come get it"],
      best:0,explanations:["This is elite-level awareness. When the carom shoots away from you toward center, the center fielder is in a better position to field it. Your job now changes — become the relay man. Position yourself between the center fielder and the infield so the throw gets home as fast as possible. This team play can save a run.","Chasing a ball that's bouncing away from you toward center field is a losing race, since you're moving in the wrong direction relative to the infield, and every second you chase, the runners advance. Let the center fielder take the shorter path to the ball.","Going back to the wall where the ball originally hit makes no sense — the ball isn't there anymore, which means it's already bouncing toward center. You need to react to where the ball IS, not where it WAS. In a scoreless game, every second matters.","The third baseman should be covering third base for a possible play on the lead runner, because asking them to leave their position to chase a ball in the outfield leaves third base empty and gives the runners a free base."],
      rates:[90,40,15,25],concept:"When a carom takes the ball away from you, let a teammate field it and switch to being the relay man — smart positioning beats foot speed.",anim:"hit"},
    {id:"lf14", conceptTag:"of-depth-arm-value",title:"Sac Fly Positioning",diff:2,cat:"fielder",ageMin:9,ageMax:99,
      description:"Runner on third, 1 out. The batter hits right-handed and pulls the ball who likes to lift the ball. Your coach signals for you to adjust your positioning. A sacrifice fly will score the run, but if the ball drops for a hit, it's even worse.",
      situation:{inning:"Bot 7",outs:1,count:"0-0",runners:[3],score:[5,4]},
      options:["Move in a few steps from normal depth — catch the fly and give yourself a shorter throw home","Play extra deep to make sure nothing gets over your head","Move to your normal depth but shade toward the line since he's a pull hitter","Charge in very shallow, almost to the dirt, to have the shortest possible throw"],
      best:0,explanations:["Moving in a few steps shortens your throw home by 20-30 feet, which could be the difference between the runner being safe or out. You're still deep enough to catch most fly balls, but now your throw has a real chance. This is the smart compromise — you give yourself a chance at both the catch AND the throw.","Playing extra deep guarantees the runner scores easily on any fly ball. Sure, nothing gets over your head, but the run scores on any catchable fly ball because your throw is too long. In a one-run game, you need to give yourself a chance to throw the runner out.","Shading toward the line is a reasonable idea, but depth matters more than angle here, since the main issue isn't where the ball is hit laterally — it's how long your throw to the plate will be. Moving in a few steps helps more than moving sideways.","Playing extremely shallow is too aggressive, because a ball hit over your head in this situation scores the runner AND gives the batter extra bases. You'd turn a sacrifice fly into a run-scoring double or triple. Move in a few steps, not halfway to the infield."],
      rates:[82,20,45,15],concept:"With a runner on third and fewer than two outs, move in a few steps — shorten your throw home without giving up catchable fly balls.",explSimple:["Moving in a few steps shortens your throw home by 20-30 feet, which could be the difference between the runner being safe or out.","Playing extra deep guarantees the runner scores easily on any fly ball.","Shading toward the line is a reasonable idea, but depth matters more than angle here.","Playing extremely shallow is too aggressive."],anim:"throwHome"},
    // ============================================================================
    // OUTFIELD EXPANSION — Left Field advanced scenarios
    // ============================================================================
    {id:"lf15", conceptTag:"of-communication",title:"Reading the Bat Angle — Pull or Opposite",diff:2,cat:"fielder",ageMin:11,ageMax:99,
      description:"You're in left field. A right-handed power hitter steps up with a 2-0 count. He's a dead-pull hitter — 70% of his balls in play go to left field. But you notice he's opened his stance slightly and moved his hands lower. Where do you position?",
      situation:{inning:"Top 4",outs:1,count:"2-0",runners:[],score:[2,1]},
      options:["Shade toward the line — he's a pull hitter, play the tendency","Stay in your normal gap position — one stance change doesn't override 70% pull rate","Move a step toward center — the open stance and low hands suggest opposite field","Charge in shallow — 2-0 count means he's swinging hard, expect a line drive"],
      best:0,explanations:["Correct! A 70% pull rate is a strong tendency. One slight stance adjustment doesn't override a season of data. The 2-0 count is a hitter's count — pull hitters are MOST likely to pull on counts where they can sit on a fastball. Shade toward the line and play his tendency.","Normal gap position ignores a 70% pull rate, since that's a massive tendency — you should be shading to take advantage of it.","One stance change can suggest an opposite-field approach, but 70% pull rate means his muscle memory will win, which means moving toward center leaves the line wide open.","Charging in shallow on a power hitter in a hitter's count is dangerous, because a 2-0 fastball from a pull hitter can be a home run or a deep fly — you need depth, not shallow positioning."],
      rates:[82,40,25,15],concept:"Trust pull-rate data over single at-bat stance changes — a 70% pull hitter pulls even more on hitter's counts",explSimple:["A 70% pull rate is a strong tendency.","Normal gap position ignores a 70% pull rate.","One stance change can suggest an opposite-field approach, but 70% pull rate means his muscle memory will win.","Charging in shallow on a power hitter in a hitter's count is dangerous."],anim:"catch"},
    {id:"lf16", conceptTag:"of-depth-arm-value",title:"Hard Carom Off the Wall — Line Drive",diff:3,cat:"fielder",ageMin:12,ageMax:99,
      description:"You're in left field. A screaming line drive hits the wall 8 feet up on the fly and caroms straight back toward you at chest height. The batter-runner is sprinting for second. A runner on first is rounding second heading for third. How do you handle the carom?",
      situation:{inning:"Top 6",outs:0,count:"0-0",runners:[1],score:[3,2]},
      options:["Catch the carom on the fly and throw directly to third to get the lead runner","Field the carom off the ground after it bounces, then hit the cutoff man","Set up off the wall — let the ball come to you, field it cleanly, and hit the cutoff at shortstop","Turn and chase the ball to the wall, then relay to the infield"],
      best:2,explanations:["Trying to catch a hard carom on the fly is risky — line drive caroms are unpredictable and can change direction off the wall padding or seams. If you miss it, both runners advance.","Waiting for the ball to bounce off the ground after the carom adds time, since a hard line drive off the wall comes back fast — you should be set up to field it in the air or on a short hop.","Correct! On hard caroms, set up 10-15 feet off the wall so the ball comes to YOU rather than you running to the wall. A line drive that hits 8 feet up will come back hard and fast — you need space to read the angle. Field it cleanly, then hit the cutoff man at shortstop who can redirect to third or home.","The ball is coming BACK toward you, not away from you, because you turning to chase it to the wall means you're running away from a ball that's already coming your way."],
      rates:[25,35,82,10],concept:"On hard wall caroms, set up 10-15 feet off the wall — let the ball come to you, field it cleanly, and use the cutoff system",anim:"hit"},
    {id:"lf17",title:"Do-or-Die — Runner Tagging from Third",diff:3,cat:"fielder",conceptTag:"of-depth-arm-value",ageMin:12,ageMax:99,
      description:"Bottom of the 9th, runner on 3rd, 1 out, tied game. Fly ball hit to medium-depth left field — catchable but not routine. If you catch it, the runner will tag and try to score the winning run. Your arm is average. The throw home is about 200 feet. What's your plan BEFORE the ball arrives?",
      situation:{inning:"Bot 9",outs:1,count:"0-0",runners:[3],score:[4,4]},
      options:["Catch the ball and throw home as hard as you can — it's do or die","Catch on the move with momentum toward home, crow-hop, and hit the cutoff","Let the ball drop — if it's a single, the runner scores but you don't risk a bad throw","Position yourself so you catch moving toward the infield, then hit the cutoff man at third-base side"],
      best:3,explanations:["'As hard as you can' without a plan leads to wild throws, since an average arm from 200 feet is unlikely to reach home on a line. A wild throw lets the batter-runner advance.","Crow-hopping to the cutoff is close, but you need to catch the ball moving TOWARD the infield so your momentum is already going the right direction. After all, so this approach matters in this situation.","Letting a catchable fly drop concedes the run AND puts the batter on base, which means never voluntarily give up outs.","Correct! With an average arm and a 200-foot throw, position yourself so you catch the ball moving toward the infield. Set up slightly behind the ball's landing spot so your momentum carries you toward home. Then hit the cutoff man at third-base side, who redirects to home. The relay system turns your average arm into an effective throw home. Pre-positioning is the key."],
      rates:[20,50,10,82],concept:"With an average arm on a do-or-die play, pre-position to catch moving toward the infield and use the cutoff relay",anim:"throwHome"},
    {id:"lf18", conceptTag:"of-depth-arm-value",title:"Sprint-to-Throw Transition — The Crow Hop",diff:2,cat:"fielder",ageMin:9,ageMax:99,
      description:"You're in left field. A single hits the gap between you and center field. You sprint to your right to cut it off. You field the ball on the run while moving away from the infield. A runner is trying to go from first to third. How do you transition from sprinting to throwing?",
      situation:{inning:"Top 3",outs:0,count:"0-0",runners:[1],score:[1,0]},
      options:["Plant your back foot hard, spin, and throw to third as fast as possible","Round the ball — take a curved path so your momentum points toward the infield when you field it","Field it and throw on the run without stopping — save time by not setting your feet","Stop completely, set your feet square to third base, then throw"],
      best:1,explanations:["Planting hard and spinning while your momentum is going the wrong direction leads to off-balance throws, because your body is moving away from the infield — a hard plant and spin fights your own momentum.","Correct! Rounding the ball means taking a banana-route path so that by the time you field it, your body is facing the infield. This converts your sprinting momentum into throwing momentum. The curve route adds 1-2 steps but gains 10-15 mph on your throw.","Throwing on the run without setting your feet is inaccurate at distances over 100 feet, since you lose half your arm strength when your lower body isn't involved.","Stopping completely kills all your momentum, because you've just sprinted 30 feet — that energy should transfer into your throw. A crow-hop from momentum beats a dead-stop throw."],
      rates:[20,82,30,25],concept:"Round the ball on gap hits — curve your path so your momentum faces the infield when you field it, then crow-hop for a strong, accurate throw",explSimple:["Planting hard and spinning while your momentum is going the wrong direction leads to off-balance throws.","Rounding the ball means taking a banana-route path so that by the time you field it, your body is facing the infield.","Throwing on the run without setting your feet is inaccurate at distances over 100 feet.","Stopping completely kills all your momentum."],anim:"hit"},
    {id:"lf19",conceptTag:"backup-duties",title:"Backing Up Third on a Grounder",diff:1,cat:"fielder",ageMin:6,ageMax:99,
      description:"You're the left fielder. Runner on first, one out. The batter hits a ground ball to the shortstop. The shortstop fires to second for the force out, and the second baseman relays to first for the double play attempt. Where should you be during this play?",
      situation:{inning:"Top 3",outs:1,count:"0-0",runners:[1],score:[0,0]},
      options:["Running toward third base to back up any throw that goes there","Standing in your normal position watching the double play","Running toward second base to help the infielders","Moving toward the foul line in case the ball gets past the third baseman"],
      best:0,explanations:["As the left fielder, your primary backup responsibility is third base. On every ground ball hit to the infield, you should be sprinting toward third base. If a throw goes wild or a runner tries to advance, you're the safety net. This is one of your most important routine jobs.","Watching from your normal position means nobody is behind third base, since if any throw goes wild — even an overthrow to first that bounces into foul territory near third — there's nobody to prevent extra bases.","The center fielder backs up second base, not you, which means your job is third base. Each outfielder has specific backup responsibilities based on position.","While covering the foul line is important on hits, during a grounder to the infield you should be backing up third base, not hugging the line, since that's why this approach matters in this situation."],
      rates:[85,15,20,25],concept:"Left fielders back up third base on every ground ball to the infield — it's one of your most important routine responsibilities.",explSimple:["Run toward third base to be the backup! That's your most important routine job.","Standing still means nobody is behind third base if a throw goes wild.","The center fielder backs up second base, not you. Your job is third.","During a grounder, back up third base instead of covering the foul line."],anim:"groundout"},
    {id:"lf20",conceptTag:"tag-up",title:"Tag-Up Play — Runner on Third",diff:2,cat:"fielder",ageMin:9,ageMax:99,
      description:"You're the left fielder. Runner on third, one out, down by one. A medium-depth fly ball is hit to left field. You catch it about 250 feet from home plate. The runner on third tags up. Where do you throw?",
      situation:{inning:"Bot 6",outs:1,count:"0-0",runners:[3],score:[4,3]},
      options:["Throw to third base to catch the runner before he leaves","Hit the cutoff man (third baseman or shortstop) lined up between you and home","Throw directly home — it's only 250 feet","Hold the ball — medium-depth fly means the runner scores easily"],
      best:1,explanations:["The runner tags up AFTER the catch, because you throwing to third makes no sense — he's already left the base and is running home. You'd be throwing behind him.","The cutoff man gives your team the best chance, since he can let the throw go through if it's on line, cut it off and throw home if it's off target, or hold it if the runner already scored. The relay system works.","250 feet is borderline for a direct throw, because unless you have an elite arm, the throw may bounce multiple times and arrive too late. The cutoff relay is more reliable.","Never give up on a play when you're down by one — the cutoff relay gives you a legitimate chance to get the tying run at the plate."],
      rates:[15,82,40,10],concept:"On tag-up plays, hit the cutoff man — he can relay home, cut it off, or hold depending on the play.",explSimple:["Throwing to third makes no sense — the runner already left and is heading home.","Hit the cutoff man! He decides if the throw should go home or not.","250 feet is a long throw. The cutoff relay is more reliable.","Never give up on a play when your team is losing. Make the throw!"],anim:"throwHome"},
    {id:"lf21",conceptTag:"of-communication",title:"Fly Ball in the LF-CF Gap",diff:2,cat:"fielder",ageMin:9,ageMax:99,
      description:"You're the left fielder. A fly ball is sliced into the left-center gap. Both you and the center fielder are sprinting toward it. The center fielder calls 'I got it!' What do you do?",
      situation:{inning:"Top 4",outs:0,count:"1-2",runners:[2],score:[1,0]},
      options:["Peel off and let the center fielder take it — CF has priority in the gaps","Keep going — you're closer and can make a better catch","Call 'No, I got it!' to override the center fielder","Slow down but stay close in case the center fielder drops it"],
      best:0,explanations:["The center fielder is the outfield captain and has priority on any ball they can reach, especially in the gaps. When CF calls for it, you peel off immediately. This prevents collisions and ensures the player with the best angle makes the catch.","Even if you think you're closer, the center fielder has priority in the gaps. CF can see the whole field and is usually running in a better direction. Trust your teammate's call and peel off.","Never override the center fielder's call in the gaps, which means cF has priority by rule and by positioning. Overriding causes confusion and potential collisions — the most dangerous plays in baseball.","Staying close 'just in case' creates a collision risk, because when CF calls for it, get completely out of the way. Trust your center fielder. If the ball drops, you'll have time to react from a safe distance."],
      rates:[85,25,10,35],concept:"When the center fielder calls for a ball in the gap, peel off immediately — CF has priority and collisions are the most dangerous plays in baseball.",explSimple:["When the center fielder calls for it, get out of the way! CF is the boss.","Even if you're closer, the center fielder has priority in the gaps.","Never override the center fielder's call. That can cause crashes.","Don't hover close by. Get completely out of the way when CF calls for it."],anim:"catch"},
    {id:"lf22",conceptTag:"of-depth-arm-value",title:"Ball Down the Left Field Line",diff:2,cat:"fielder",ageMin:9,ageMax:99,
      description:"You're the left fielder. A line drive hooks down the left field line and hits the wall in the corner. The ball caroms off the angled wall and bounces toward center field. Runner on first is being sent to third. How do you play the carom?",
      situation:{inning:"Top 5",outs:0,count:"0-0",runners:[1],score:[2,1]},
      options:["Get your body between the ball and center field, field it, and throw to the relay man","Chase the ball toward center field and throw to third when you pick it up","Let the center fielder pick up the carom since it bounced toward him","Turn and throw to third base without fielding — save time"],
      best:0,explanations:["Position your body to cut off the carom and prevent it from rolling further away, since you getting between the ball and center field is fundamental wall play — you contain the ball, field it cleanly, and hit the relay man for a quick throw to third.","Chasing the ball toward center field means you're running AWAY from the infield, because by the time you pick it up and turn, you've lost seconds and your throw angle is terrible. Cut the ball off before it gets away.","It's YOUR ball in the left field corner, not the center fielder's — cF should be backing you up, not fielding your ball. You're closer and know the wall angles better.","You can't throw accurately without fielding the ball first, which means trying to make a play without control is how errors happen. Field it cleanly, then throw."],
      rates:[90,40,25,15],concept:"On wall caroms in the corner, get your body between the ball and center field to contain it, then hit the relay man.",explSimple:["Cut off the carom and throw to the relay man. Don't let the ball get away!","Chasing toward center field means you're running away from the infield.","It's your ball in the left field corner, not the center fielder's.","You can't throw accurately without fielding the ball first."],anim:"throwHome"},
    {id:"lf23",conceptTag:"fly-ball-priority",title:"Shallow Fly — Coming In on the Ball",diff:1,cat:"fielder",ageMin:6,ageMax:99,
      description:"You're the left fielder. A soft fly ball is hit into shallow left field. The third baseman drifts back toward the ball. You're charging in. You'll both get there at the same time. What do you do?",
      situation:{inning:"Top 1",outs:0,count:"0-0",runners:[],score:[0,0]},
      options:["Call 'I got it!' loud and early — you have the better angle running in","Let the third baseman take it since he's an infielder","Stay quiet and go for it — whoever gets there first catches it","Stop and let the third baseman decide"],
      best:0,explanations:["You're running forward with the ball in front of you the entire time. The third baseman is drifting backward, which is much harder. Outfielders always have priority on balls they can reach because you running in is easier and safer than running back. Call it loud and early!","Infielders have priority on infield pop-ups, not shallow outfield flies, because when the ball is in the outfield, the outfielder running forward has the better angle and should take charge.","Never go for a ball without communicating. Staying quiet while whoever gets there first catches it is how collisions happen, since two players running to the same spot without talking is dangerous. Call for it or get out of the way.","Don't stop and let the third baseman decide — that gives away your advantage, because you're running in with the ball in front of you — that's the best angle on the field. Call for it and catch it."],
      rates:[90,40,15,25],concept:"Outfielders have priority over infielders on shallow fly balls because you running in is always easier and safer than running back.",explSimple:["You're running forward and can see the ball the whole time. Call for it!","Infielders have priority on infield pop-ups, but not outfield flies.","Never go for a ball without talking first. You could crash into someone!","Don't stop — you have the best angle. Call for the ball!"],anim:"catch"},
    {id:"lf_wl1",title:"Wall Play — Tracking a Deep Ball in Left-Center",diff:2,cat:"outfield",conceptTag:"of-wall-play",ageMin:11,ageMax:99,
      description:"You're the left fielder. A ball is hit deep to left-center and you're tracking it on the run toward the wall. You can feel yourself getting close to the warning track but you haven't looked back yet. How do you play it?",
      situation:{inning:"Top 6",outs:1,count:"0-0",runners:[1],score:[3,2]},
      options:["Glance back at the wall as you run to find your distance, then look back up at the ball","Keep your eyes on the ball the entire time — never take your eyes off it","Stop running and wait for the ball to come to you","Turn around completely to find the wall, then turn back to the ball"],
      best:0,explanations:["Near the wall, the most dangerous thing is a collision you didn't see coming. A quick glance back tells you exactly how far you are from the wall, so you can keep running without fear. Good outfielders practice the timing of this glance — a half-second look back, then eyes up to relocate the ball. The warning track under your feet is your first signal, but a glance confirms exactly how much room you have left.","Keeping your eyes on the ball sounds right, but running full speed at a wall you can't see is how serious injuries happen. Every outfielder needs to know where the wall is before committing to a catch at the fence. One quick glance keeps you safe and gives you confidence to keep going.","Stopping and waiting gives up on any ball you could catch at the wall. A ball hit to the warning track might be catchable if you keep running — stopping turns a potential out into a guaranteed extra-base hit.","Turning around completely takes too long and you'll lose track of the ball entirely. A quick glance over your shoulder is all you need — just enough to judge distance, then eyes back on the ball to make the catch."],
      rates:[82,35,20,28],concept:"Near the wall, take a quick glance back to find your distance — the warning track is your first cue, but a glance confirms how much room you have",explSimple:["A quick glance at the wall tells you how much room you have. Then look up!","Running full speed at a wall you can't see is dangerous. Glance back!","Stopping gives up on any ball you could catch at the wall.","Turning completely around takes too long. A quick glance is all you need."],anim:"catch"},
  ],
  firstBase: [
    {id:"f5", conceptTag:"infield-positioning",title:"First Base Fundamentals",diff:1,cat:"infield",ageMin:6,ageMax:99,
      description:"You're at 1st. Grounder to the shortstop, nobody on. What do you do BEFORE the throw?",
      situation:{inning:"Bot 4",outs:0,count:"0-0",runners:[],score:[1,0]},
      options:["Get to the bag and give a target","Move toward the ball","Stay back from the bag","Cover home"],
      best:0,explanations:["Get to the bag, give the thrower a target, and stretch toward the ball — that is textbook first baseman play.","The shortstop has it — your job is to be at the bag ready to receive the throw, not chase the ball.","Staying back means you can't stretch for offline throws.","Nobody on base — no need to cover home."],
      explSimple:["Get to the base, look at the person throwing, and stretch toward the ball. That's how first basemen do it!","The shortstop has the ball — your job is to be at the base ready to catch the throw.","If you stand too far from the base, you can't stretch to catch bad throws.","There's no one on base, so you don't need to go to home plate."],
      rates:[85,20,40,5],concept:"First baseman: get to the bag early, face the thrower, stretch toward the throw",anim:"catch"},
    {id:"f21", conceptTag:"double-play-turn",title:"First Baseman's DP — Bases Loaded",diff:3,cat:"infield",ageMin:12,ageMax:99,
      description:"Top of the 4th, bases loaded, 1 out, down 4-2. You're the first baseman. Hard ground ball hit right at you, 15 feet from the bag.",
      situation:{inning:"Top 4",outs:1,count:"0-0",runners:[1,2,3],score:[2,4]},
      options:["Step on first, then fire to second for the relay","Step on first, throw to second for the double play","Throw home first to keep the force, then get back to first for the return throw","Step on first — one out is enough"],
      best:2,explanations:["Stepping on first retires the batter, but it REMOVES the force at home — the runner from 3rd is no longer forced and must be tagged. The relay to second is meaningless because the damage is already done — a run scores.","Stepping on first removes ALL force plays, which means the throw to second now requires a tag, and the runner from 3rd scores. This gets two outs but gives up the run.","With bases loaded, throw home FIRST — the force is still on at home plate. The catcher catches and steps on the plate (out #2), then fires back to you covering first (out #3). This is the 3-2-3 double play — two outs AND you prevent the run from scoring.","One out is never enough when you can get two, because with bases loaded and you near the bag, the double play is right there — but you have to throw home first to keep the force."],
      rates:[35,30,85,20],concept:"Bases loaded, ball hit near first — throw home FIRST to keep the force, then get the out at first",anim:"doubleplay"},
    {id:"f32", conceptTag:"cutoff-roles",title:"Let It Through or Cut It Off?",diff:3,cat:"outfield",ageMin:12,ageMax:99,
      description:"Bot 8th, runner on 2nd, 1 out, up 6-5. Single to right field. Runner from 2nd is heading home. You're the first baseman — the cutoff man on throws from right field to home. The throw is coming and the runner is going to be close at the plate.",
      situation:{inning:"Bot 8",outs:1,count:"0-0",runners:[2],score:[5,6]},
      options:["Let the throw go through to home — it's on line","Cut it off — the throw is off-line and won't get there","Listen for the catcher's call — he can see the play","Catch it and throw to third to get the batter"],
      best:2,explanations:["Deciding on your own to let it through is risky, because you're facing the outfield and can't see the runner behind you. If the throw is actually off-line, it sails past the catcher and the tying run scores. The key is that the catcher has the full picture — you don't.","Cutting it off on your own is just as dangerous, because if the throw is on-line and would have nailed the runner, you've killed the play. Since you can't see both the throw and the runner at the same time, you need the catcher's read before deciding.","Correct! As the first baseman, you're the cutoff on throws from right and center field to home. Your job is to line up between the outfielder and home plate, then listen for the catcher's call. The catcher can see both the throw and the runner, which means he knows whether the throw will beat the runner. He yells 'Cut!' if it's off-line, or 'Let it go!' if it's on target. Trusting the catcher is what makes the cutoff system work.","Throwing to third to get the batter-runner is secondary, because the tying run heading home is the priority. You only redirect to another base after the catcher tells you to cut it, and only when the run has already scored or there's a better play available."],
      rates:[30,30,85,20],concept:"As the first baseman cutoff on RF/CF throws home, listen to the catcher — he sees the full play and tells you to cut or let it go",anim:"throwHome"},
    {id:"f46", conceptTag:"infield-positioning",title:"Pull Hitter — Shade or Stay?",diff:2,cat:"positioning",ageMin:9,ageMax:99,
      description:"Top of the 6th, nobody on, 2 outs, up 4-2. A left-handed pull hitter steps in. He's hit every ball to the right side today — 3 ground balls to second and first.",
      situation:{inning:"Top 6",outs:2,count:"0-0",runners:[],score:[4,2]},
      options:["Shade the whole infield toward the right side","Play straight up — he might adjust","Only shade the second baseman","Shift the shortstop all the way to the right side"],
      best:0,explanations:["When a hitter pulls everything, shade your infield toward the pull side, since you move the second baseman toward first, the shortstop toward second, and the first baseman closer to the line. You're positioning where the ball is most likely to go based on the data you have.","Playing straight up ignores three at-bats of evidence, because he's pulled every ball to the right side today. Use the information the hitter is giving you and position your defense where the ball is most likely to go — good defenders always adjust based on observable tendencies.","Only shading one player is a half-measure that leaves gaps in your defense, because moving just one fielder creates uneven spacing. Move the whole infield together so the coverage is consistent and there are no holes between fielders on the pull side.","A full shift with the shortstop on the right side is too extreme for most situations because shading is enough. If he adjusts and hits the other way, a full shift leaves the entire left side of the infield open."],
      rates:[85,25,35,30],concept:"Against pull hitters, shade the infield toward the pull side — position where the ball is going",explSimple:["When a hitter pulls everything, shade your infield toward the pull side.","Playing straight up ignores three at-bats of evidence, because","Only shading one player is a half-measure, because","A full shift with the shortstop on the right side is too extreme for most situations."],anim:"groundout"},
    {id:"f59", conceptTag:"fly-ball-priority",title:"Pop-Up Between Three Players",diff:1,cat:"communication",ageMin:6,ageMax:99,
      description:"You're the first baseman. Bot 3rd, nobody on, 1 out. A pop-up is hit near home plate between you, the pitcher, and the catcher. All three of you are drifting toward it. Nobody has called it yet.",
      situation:{inning:"Bot 3",outs:1,count:"0-0",runners:[],score:[2,1]},
      options:["Call for it loudly — you have priority as the first baseman","Let the pitcher catch it — he's closest","Let the catcher take it — he has priority on pop-ups near home","Wait and see who gets there first"],
      best:2,explanations:["The first baseman has priority over the pitcher on pop-ups, but near home plate the catcher takes charge. The catcher practices pop-ups constantly and knows how the ball spins off the bat. Defer to the catcher here.","The pitcher should defer to both the catcher and the first baseman — pitchers have the lowest priority on pop-ups.","On pop-ups near home plate, the catcher has priority over both the pitcher and infielders. Pop-ups near home spin back toward the backstop, and the catcher is trained to flip his mask, find the ball, and make the catch. Someone MUST call 'I got it!' — the worst outcome is nobody calling it. Let the catcher take charge here.","Waiting is how easy pop-ups drop for hits, because someone must take charge immediately."],
      rates:[45,15,85,10],concept:"On pop-ups near home plate, the catcher has priority — he's trained for them and knows the spin. CALL IT!",explSimple:["Not the best move. Near home plate, the catcher has priority over infielders on pop-ups.","Not the best move. The pitcher has the lowest priority on pop-ups — defer to other fielders.","Great choice! On pop-ups near home plate, the catcher has priority. He practices these constantly.","Not the best move. Waiting is how easy pop-ups drop for hits."], anim:"catch"},
    {id:"f62", conceptTag:"bunt-defense",title:"Bunt Defense — Who Covers What?",diff:3,cat:"communication",ageMin:12,ageMax:99,
      description:"Top of the 3rd, runners on 1st and 2nd, nobody out. Bunt is expected. Your team calls the bunt defense. Who covers what?",
      situation:{inning:"Top 3",outs:0,count:"0-0",runners:[1,2],score:[1,1]},
      options:["1B and 3B charge, SS covers 3rd, 2B covers 1st, pitcher fields near the mound","Everyone holds their position and reacts","1B charges, 3B holds, pitcher covers the bunt area","Only the pitcher and catcher handle the bunt"],
      best:0,explanations:["Standard bunt defense with runners on 1st and 2nd: the first baseman and third baseman charge toward home as the pitch is delivered. The shortstop breaks to cover third base. The second baseman breaks to cover first base. The pitcher is ready to field the bunt and throw to the base where the lead runner is going. Everyone has a job.","Holding position means slow reaction time — the bunt dies before anyone gets to it. A sacrifice bunt against a static defense almost always succeeds because nobody is close enough to make a play on the lead runner.","Only the 1B charging leaves the third base line bunt uncovered if the 3B holds. The batter can push a bunt down the third base line for an easy single since nobody is charging from that side to field it.","The pitcher and catcher alone can't cover all the bases, which means the whole infield must shift together. Somebody has to cover first and third while the corners charge, and that's why the middle infielders rotate into those positions."],
      rates:[90,15,40,25],concept:"Bunt defense is a team play — corners charge, SS covers 3rd, 2B covers 1st, pitcher fields",anim:"bunt"},
    {id:"1b1", conceptTag:"pickoff-mechanics",title:"Holding the Runner On",diff:1,cat:"fielder",ageMin:6,ageMax:99,
      description:"You're the first baseman. There's a speedy runner on first with one out. The pitcher works from the stretch and looking back at the runner. The runner is taking a big lead — almost four steps off the bag.",
      situation:{inning:"Top 5",outs:1,count:"1-0",runners:[1],score:[2,1]},
      options:["Stay on the bag with your foot touching it and give the pitcher a target with your glove for the pickoff throw","Play behind the runner in case the batter hits a ground ball to the right side","Cheat toward second base to get a head start on covering the hole between first and second","Bluff like you're going to the bag, then back off to play deep for a ground ball"],
      best:0,explanations:["Exactly right! With a fast runner taking a big lead, you need to hold him on the bag. Keep your foot on first and show the pitcher your glove as a target — this keeps the runner honest and close to the base.","Playing behind the runner means he can extend his lead even more, making a stolen base almost automatic. Your job right now is to keep that runner close to first base.","Cheating toward second leaves first base uncovered. If the pitcher tries a pickoff throw, no one is there to catch it and the runner advances easily — or even scores.","Bluffing can work sometimes, but with an aggressive runner already taking four steps, you need to be ON the bag. A bluff will not hold this runner — only your physical presence on the base will."],
      rates:[85,25,20,35],concept:"With a fast runner on first, the first baseman's primary job is to hold the runner on by staying on the bag and giving the pitcher a pickoff target.",explSimple:["Great choice! Exactly right! With a fast runner taking a big lead, you need to hold him on the bag.","Not the best move. Playing behind the runner means he can extend his lead even more, making.","Not the best move. Cheating toward second leaves first base uncovered.","Not the best move. Bluffing can work sometimes, but with an aggressive runner already taking four steps, you need."], anim:"safe"},
    {id:"1b2", conceptTag:"force-vs-tag",title:"Scooping a Short-Hop Throw",diff:2,cat:"fielder",ageMin:9,ageMax:99,
      description:"You're the first baseman. Routine ground ball to shortstop, runner sprinting down the line. The shortstop's throw is low — it's going to bounce about three feet in front of you. The runner is fast and it'll be close.",
      situation:{inning:"Top 3",outs:0,count:"0-0",runners:[],score:[1,1]},
      options:["Keep your foot on the bag, stretch toward the throw, and scoop it by keeping your glove low with the pocket facing up","Pull your foot off the bag and catch the ball cleanly with two hands, then try to tag the runner","Stay upright on the bag and try to catch the ball chest-high after it bounces up","Move off the bag entirely to block the ball like a hockey goalie"],
      best:0,explanations:["Textbook first baseman play! Keep your foot on the base for the force out, stretch toward the throw to catch it sooner, and scoop with your glove low and open, which means great first basemen save errors by picking these short hops every day.","If you pull your foot off the bag, it's not a force out anymore. You'd have to tag the runner, and he's already sprinting past you. Keep your foot on the bag — that's the whole point of a force play at first.","Short-hop throws don't bounce up to chest height at first base — they stay low, because you waiting for a big hop means the ball scoots under your glove or past you. Staying upright waiting for it to bounce chest-high is a recipe for an error.","Leaving the bag means no out even if you stop the ball. First base is all about keeping your foot on the bag while making the catch. Blocking like a hockey goalie entirely defeats the purpose."],
      rates:[88,30,20,15],concept:"First basemen save infielders' errors by scooping short hops — keep your foot on the bag, stretch toward the throw, and get your glove down low.",explSimple:["the right way to do it first baseman play!","If you pull your foot off the bag, it's not a force out anymore.","Short-hop throws don't bounce up to chest height at first base — they stay low.","Leaving the bag means no out even if you stop the ball."],anim:"groundout"},
    {id:"1b3", conceptTag:"bunt-defense",title:"Fielding a Bunt as the First Baseman",diff:1,cat:"fielder",ageMin:6,ageMax:99,
      description:"You're at first base. Runner on first, no outs, and the batter squares to bunt. The pitch is bunted hard right at you, about 20 feet down the first base line. The second baseman sprints to cover first.",
      situation:{inning:"Bot 4",outs:0,count:"1-0",runners:[1],score:[0,0]},
      options:["Charge the ball, field it, and throw to second base to get the lead runner if you have time","Charge the ball, field it, and flip to the second baseman covering first for the sure out","Let the pitcher field it since you bunts are always the pitcher's job","Field the ball and run to first base yourself to get the easy out"],
      best:1,explanations:["Going to second for the lead runner sounds great, but the ball was bunted hard right at you — by the time you field it, the runner from first has already gotten a good jump, since the safe play is to get the sure out at first.","Smart play! The ball is right in front of you, so you can field it quickly, because the second baseman is covering first, so flip it to him for the guaranteed out. Getting the sure out prevents a big inning.","Bunts are NOT always the pitcher's job — when a bunt comes right at the first baseman, you field it. The pitcher covers his zone, and you cover yours. This one is yours all the way.","Running to first yourself takes too long and you might not beat the batter, which means the second baseman is already sprinting to cover first — flip it to him for a much faster out."],
      rates:[40,85,10,25],concept:"On bunt plays, the first baseman fields balls in his zone and flips to the second baseman covering first for the sure out.",explSimple:["Not the best move. Going to second for the lead runner sounds great, but the ball was bunted hard.","Smart play! The ball is right in front of you, so you can field it quickly.","Not the best move. Bunts are NOT always the pitcher's job.","Not the best move. Running to first yourself takes too long and you might not beat the batter."], anim:"bunt"},
    {id:"1b4", conceptTag:"infield-positioning",title:"Cover First or Play the Ball?",diff:3,cat:"fielder",ageMin:12,ageMax:99,
      description:"You're the first baseman. Runner on second, one out. The batter hits a sharp ground ball right in the hole between you and second base — about 15 feet to your right. The pitcher breaks toward first base to cover. The second baseman also moves toward the ball.",
      situation:{inning:"Top 6",outs:1,count:"0-0",runners:[2],score:[3,2]},
      options:["Let the second baseman field it — sprint back to first base so someone is there to take the throw","Go after the ball yourself since you're closer, and let the pitcher cover first","Freeze and see what happens — wait to see if the second baseman or pitcher gets to it first","Go after the ball and then try to beat the runner back to first base yourself"],
      best:0,explanations:["This is the right call! When the ball is in the hole, the second baseman has a better angle to field it and throw to first. Your job is to get back to the bag so there's someone to receive the throw. If nobody's on first, the out is impossible.","You might be closer, but the second baseman has a much better throwing angle to first base from that position. If you field it, you have to spin and throw across your body or run to the bag yourself — both are harder plays.","Freezing is the worst thing a first baseman can do, because every ground ball requires an instant decision — either go get the ball or get back to the bag. Hesitation means nobody covers first and the runner is safe.","You cannot field a ball 15 feet to your right and then beat a sprinting batter back to first base, since even the fastest first baseman can't outrun a thrown ball. Get to the bag and let your teammate make the throw."],
      rates:[88,40,10,20],concept:"First basemen must decide instantly: go after the ball or get back to the bag. When the second baseman has a better angle, get to first and be the target.",anim:"groundout"},
    {id:"1b5", conceptTag:"cutoff-roles",title:"Cutoff Positioning on a Single to Right",diff:1,cat:"fielder",ageMin:6,ageMax:99,
      description:"You're the first baseman. Runner on second base, and the batter singles to right field. The runner is rounding third and heading home. The right fielder picks up the ball and is ready to throw. You need to get in the cutoff position.",
      situation:{inning:"Bot 5",outs:1,count:"0-0",runners:[2],score:[2,3]},
      options:["Line up between the right fielder and home plate, about 45 feet from home, with your arms up so the fielder can see you","Run to home plate to back up the catcher in case the throw gets past him","Stay at first base in case the batter tries to stretch his single into a double","Move halfway between first and second base to cover the cutoff from right-center field"],
      best:0,explanations:["Perfect cutoff positioning! Line up between the outfielder and home plate so the throw comes right through you, because arms up so the fielder can see your target. You can cut the throw and redirect it or let it go through to the catcher.","Backing up the catcher sounds helpful, but who's going to cut the throw off? If the throw is offline or the catcher has no play, nobody is there to redirect the ball — the cutoff man is the most important player on this play.","Staying at first base ignores the bigger play — a run is about to score! The batter advancing to second doesn't matter as much as cutting down the runner at home, which means cutoff plays save runs.","The cutoff position for a throw from right field to home plate is between the fielder and home, not between first and second, because you need to be in a straight line from the right fielder to the catcher."],
      rates:[85,25,20,15],concept:"On throws to home from right field, the first baseman is the cutoff man — line up between the fielder and home plate with your arms raised.",explSimple:["Perfect cutoff positioning! Line up between the outfielder and home plate so the throw comes right through you.","Not the best move. Backing up the catcher sounds helpful, but who's going to cut the throw off? If.","Not the best move. Staying at first base ignores the bigger play — a run is about to score!","Not the best move. The cutoff position for a throw from right field to home plate is between."], anim:"throwHome"},
    {id:"1b6",title:"Turning the 3-6-3 Double Play",diff:3,cat:"fielder",conceptTag:"double-play-turn",ageMin:9,ageMax:99,
      description:"You're the first baseman. Runner on first, one out, ground ball hit right at you. The runner is going on the pitch. You field the ball cleanly about eight feet in front of the bag. The shortstop covers second base.",
      situation:{inning:"Top 7",outs:1,count:"0-1",runners:[1],score:[4,4]},
      options:["Throw to the shortstop at second base for the force out, then sprint back to first and get ready for the return throw","Tag first base yourself first, then throw to second to try to get the runner","Hold the ball and just tag first base for the one sure out","Throw to second base and let the pitcher cover first for the return throw"],
      best:0,explanations:["That's the 3-6-3 double play! Throw to the shortstop at second for the first out, then hustle back to the bag for the return throw from the shortstop, since it's one of the hardest double plays in baseball, but it ends the inning in a tie game.","Tagging first base first removes the force at second — without the force, it becomes a TAG play, which is fundamentally harder, because the shortstop now has to tag the runner instead of just touching the base. Get the lead runner first while the force is still on.","One out is okay, but in a tie game in the 7th inning, a double play ends the inning and keeps the score tied — you have a chance for two outs — take it.","The pitcher covering first is less reliable than you getting back to the bag yourself, which means the 3-6-3 is your play to make — you know where the bag is and you're the best at receiving throws at first base."],
      rates:[85,30,40,35],concept:"The 3-6-3 double play requires quick feet — throw to the shortstop at second, then sprint back to first for the return throw.",anim:"doubleplay"},
    {id:"1b7", conceptTag:"fly-ball-priority",title:"Foul Ball Communication Near First",diff:1,cat:"fielder",ageMin:6,ageMax:99,
      description:"You're at first base. The batter pops a foul ball high in the air between first base and the dugout on the home team side. The second baseman runs over, the pitcher drifts toward the area, and the ball is drifting toward the stands.",
      situation:{inning:"Top 2",outs:0,count:"1-2",runners:[],score:[0,0]},
      options:["Call 'I got it! I got it!' loudly and wave off your teammates since you have the best angle as the first baseman","Let the second baseman take it since he's running toward the ball","Wait to see who gets there first and then the closest player catches it","Stay quiet and just try to catch it without saying anything"],
      best:0,explanations:["Take charge! Foul balls on the first base side are your territory, because you're closest to the stands, you know how much room you have, and you face these pop-ups all the time. Call it loud and clear so nobody crashes into each other.","The second baseman is running a longer distance and doesn't know how close the stands are, since the first baseman plays near the dugout every day and knows exactly how much room is available. This is your ball.","Waiting to see who gets there first causes collisions, because somebody has to call for the ball EARLY so the other players can get out of the way. Hesitation leads to dropped balls and banged-up teammates.","Never try to catch a fly ball silently! Without calling it, two or three players might converge on the same spot — collisions cause injuries and dropped balls. Always communicate — be loud and be early."],
      rates:[90,35,15,10],concept:"On foul balls near your position, call it loudly and early — communication prevents collisions and dropped balls.",explSimple:["Great choice! Take charge! Foul balls on the first base side are your territory.","Not the best move. The second baseman is running a longer distance and doesn't know how close the stands are.","Not the best move. Waiting to see who gets there first causes collisions.","Not the best move. Never try to catch a fly ball silently! Without calling it, two or three players."], anim:"catch"},
    {id:"1b8",title:"First-and-Third Pickoff Play",diff:3,cat:"fielder",conceptTag:"first-third",ageMin:11,ageMax:99,
      description:"You're the first baseman. Runners on first and third, one out. The runner on first takes off for second base on the pitch. Your catcher catches the ball and fires a throw to second base — but it's actually a designed play where the shortstop cuts the throw and look at third.",
      situation:{inning:"Top 8",outs:1,count:"1-1",runners:[1,3],score:[5,4]},
      options:["Sprint to cover home plate in case the runner on third tries to score during the chaos of the play","Stay near first base in case the throw from the shortstop comes back to you for a pickoff on the runner retreating","Get behind the mound to back up any throw that goes to second base or back to the pitcher","Run toward the runner going to second to get in a rundown between first and second"],
      best:1,explanations:["The catcher covers home plate — that's his position. If you leave first base to go home, nobody is covering first and you create a gap the offense can exploit. Stay at your position and trust your catcher.","Smart positioning! In a first-and-third situation, the shortstop might cut the throw and fire back to first if the runner on first hesitates or retreats. If you're on the bag, you can catch the throw and get a surprise out.","Backing up behind the mound takes you away from first base, which is your responsibility, which means every player has a specific job on this play, and yours is to stay at first base ready for a possible return throw.","Running toward the baserunner creates confusion and leaves first base completely uncovered, because you rundowns are for when the ball is already in play between two fielders — let the middle infielders handle this."],
      rates:[20,88,25,15],concept:"In first-and-third pickoff plays, the first baseman must stay on the bag — the throw might come right back to you for a surprise out.",anim:"safe"},
    {id:"1b9", conceptTag:"pickoff-mechanics",title:"Hold Runner, Lefty Batter",diff:2,cat:"fielder",ageMin:9,ageMax:99,
      description:"You're the first baseman. Tie game, runner on first with decent speed. A left-handed batter steps in — his swing naturally pulls toward right field, right where you normally stand. The pitcher looks back at the runner, who has a three-step lead.",
      situation:{inning:"Bot 6",outs:1,count:"1-0",runners:[1],score:[3,3]},
      options:["Stay glued to the bag the entire at-bat with your foot on first","Play behind the runner in your normal defensive position since lefties pull the ball to you","Cheat halfway — stand two steps off the bag toward your regular position to split the difference","Peel off to your defensive position as the pitcher delivers home"],
      best:3,explanations:["Staying glued to the bag the entire at-bat is solid defense against the steal, but with a left-handed pull hitter it leaves a massive hole on the right side — a pulled ground ball goes right through where you should be standing.","Playing full depth behind the runner gives him a huge lead and a free stolen base. In a tie game, letting a runner reach scoring position for free is a gift to the other team.","Splitting the difference means you're too far off the bag to hold the runner AND too close to the bag to field a pulled grounder — you end up bad at both jobs.","This is the advanced first baseman move — hold the runner until the pitcher commits home, then quickly release to your fielding position. You keep the runner honest AND cover the hole against the lefty pull hitter."],
      rates:[45,25,30,82],concept:"Against left-handed hitters, hold the runner until the pitcher delivers, then peel off to cover the right side — you need to do both jobs.",explSimple:["Holding the runner on the bag is solid, but with a left-handed pull hitter, staying glued to the bag leaves a massive hole on the right side.","Playing full depth behind the runner gives him a huge lead and a free stolen base.","Splitting the difference means you're too far off the bag to hold the runner AND too close to the bag to field a pulled grounder.","This is the advanced first baseman move."],anim:"safe"},
    {id:"1b10",title:"Bunt in Front of the Mound",diff:1,cat:"fielder",conceptTag:"bunt-defense",ageMin:10,ageMax:99,
      description:"You're the first baseman. Runner on first, no outs. The batter bunts the ball and it dribbles to a stop about 30 feet in front of home plate — right between the mound and the first base line. The pitcher, catcher, and you are all looking at it. Nobody has called for it yet.",
      situation:{inning:"Top 3",outs:0,count:"0-0",runners:[1],score:[1,0]},
      options:["Sprint toward the ball and call 'I got it!' — the first baseman should take charge on bunts","Hang back and let the pitcher or catcher field it since they're closer to the ball","Charge toward the ball but stay quiet and see who gets there first","Sprint toward the ball and call 'I got it!' while pointing at where you want the pitcher to go cover first"],
      best:3,explanations:["Charging and calling for it is great, but if you field the ball, who covers first base? You need someone there to throw to. Communication is everything on bunt plays.","Hanging back means nobody takes charge, because the bunt sits there while three players stare at each other and the runners advance. Somebody has to go get the ball.","Charging silently is a recipe for a collision, since the pitcher and catcher are also moving toward the ball. Without calling it, two players might crash into each other.","This is the complete play! You call for the ball — the first baseman owns bunts in his zone on bunt defense — AND you direct the pitcher to cover first base. On a bunt, the pitcher covers first when the 1B charges — he sprints to the bag to receive the throw. Call it loud, field it clean, direct your teammates."],
      rates:[50,15,20,85],concept:"On bunts, call for the ball AND direct your teammates — tell the pitcher to cover first so you have someone to throw to.",explSimple:["Not the best move. Charging and calling for it is great, but if you field the ball, who covers.","Not the best move. Hanging back means nobody takes charge.","Not the best move. Charging silently is a recipe for a collision.","Great choice! This is the complete play! You call for the ball — the first baseman owns."], anim:"bunt"},
    {id:"1b11", conceptTag:"force-vs-tag",title:"Scoop the Short-Hop From Third",diff:2,cat:"fielder",ageMin:9,ageMax:99,
      description:"You're the first baseman. Two outs, runner on second. The batter hits a sharp grounder to the third baseman who backhands it deep behind the bag. He throws hard across the diamond but the ball is going to short-hop you about two feet in front of first base. This is a tougher scoop than a throw from shortstop because the ball has more velocity and a different angle.",
      situation:{inning:"Top 5",outs:2,count:"1-2",runners:[2],score:[2,1]},
      options:["Keep your foot on the bag, stretch toward the throw, and turn your glove to get a forehand scoop on the ball","Stretch out but keep your glove in the backhand position since the ball is coming from the left side","Pull your foot off the bag and use two hands to block the ball and keep it in front of you","Stay upright on the bag and try to short-hop it with your glove at waist height"],
      best:0,explanations:["Textbook! On throws from third base, stretch toward the throw and turn your glove for a forehand scoop, because the forehand position keeps your glove pocket open and facing the ball, giving you the best chance to pick the short hop cleanly.","A backhand scoop is harder to control and the ball can kick off the back of your glove — on throws from the left side, rotating to a forehand position gives you a much bigger scooping surface.","Pulling your foot off the bag means even if you catch it, the runner is safe. With two outs you need this out — keep your foot on the base and make the scoop.","Short hops don't bounce up to waist height from two feet away, which means the ball stays low. You need to get your glove down to the dirt to scoop it, not wait for it to come up to you."],
      rates:[82,40,30,15],concept:"On short-hop throws from third base, stretch and rotate your glove to the forehand position — the bigger scooping surface gives you the best chance.",explSimple:["On throws from third base, stretch toward the throw and turn your glove for a forehand scoop.","A backhand scoop is harder to control and the ball can kick off the back of your glove.","Pulling your foot off the bag means even if you catch it, the runner is safe.","Short hops don't bounce up to waist height from two feet away."],anim:"groundout"},
    {id:"1b12", conceptTag:"double-play-turn",title:"3-6-3 Double Play — Quick Feet",diff:3,cat:"fielder",ageMin:12,ageMax:99,
      description:"You're the first baseman in a tied game. Runner on first, no outs. The batter hits a hard grounder right at you. You field it cleanly just in front of the bag. The shortstop already breaks for second base to cover. The runner from first has only taken two steps — he got a bad jump. You have time, but you need to execute perfectly.",
      situation:{inning:"Bot 5",outs:0,count:"0-0",runners:[1],score:[2,2]},
      options:["Throw to the shortstop covering second, then sprint back to first base for the return throw","Step on first base to get the batter out, then throw to second for the runner","Hold the ball, tag first base, and let the team settle for one out","Flip to the pitcher covering first, then let the pitcher throw to second"],
      best:0,explanations:["This is the 3-6-3 double play executed perfectly! Throw to the shortstop for the force at second, then hustle back to first for the return throw, because you getting the lead runner first keeps the force play alive at both bases. Two outs, inning over.","Stepping on first REMOVES the force at second base, since now instead of the shortstop just touching second, he has to tag the runner — which is much harder and slower. Always get the lead runner first when turning two.","Settling for one out when you have a chance to end the inning with a double play wastes an opportunity, because in a tie game with no outs, a double play completely changes the momentum.","The pitcher covering first adds an unnecessary relay — you're RIGHT THERE at first base — you can get back to the bag faster than the pitcher can get there. The 3-6-3 is your play."],
      rates:[85,30,35,20],concept:"On the 3-6-3 double play, always throw to second FIRST to keep the force play alive — stepping on first first kills the force at second.",anim:"doubleplay"},
    {id:"1b13", conceptTag:"infield-positioning",title:"Play Back or Hold — Tie Game",diff:2,cat:"fielder",ageMin:9,ageMax:99,
      description:"You're the first baseman. Bottom of the 7th in a tie game. Runner on first, no outs, and it's the opposing team's best power hitter. The runner on first is slow — a catcher who's only stolen two bases all season. Your pitcher has a good pickoff move.",
      situation:{inning:"Bot 7",outs:0,count:"0-0",runners:[1],score:[3,3]},
      options:["Hold the runner on the bag like you always do when there's a runner on first","Play behind the runner at your normal depth — the power hitter is the bigger threat","Play in closer to home plate to cut off a ground ball through the right side","Shade toward the foul line to prevent an extra-base hit down the line"],
      best:1,explanations:["With a slow runner who almost never steals and a pitcher with a good pickoff move, holding the runner on the bag sacrifices your defensive range for nothing, which means the runner isn't going anywhere.","Smart! A slow runner with only two steals isn't a threat, because you playing at your normal depth gives you much better range to field ground balls from the power hitter. Your pitcher's pickoff move keeps the runner honest without your help.","Playing in makes sense for bunt defense, but a power hitter isn't bunting, since moving in just makes hard ground balls reach you faster, giving you less reaction time.","Shading the line could work late in a game, but with no outs and a runner on first, taking away the right-side hole is more valuable. A ground ball through the right side advances the runner to third — a single down the line does too, but it's less likely."],
      rates:[40,82,25,35],concept:"When the runner on first is slow and not a stolen base threat, play at normal depth to maximize your defensive range against the batter.",explSimple:["With a slow runner who almost never steals and a pitcher with a good pickoff move, holding the runner on the bag sacrifices your defensive range for nothing.","A slow runner with only two steals isn't a threat.","Playing in makes sense for bunt defense, but a power hitter isn't bunting.","Shading the line could work late in a game, but with no outs and a runner on first, taking away the right-side hole is more valuable."],anim:"groundout"},
    {id:"1b14", conceptTag:"force-vs-tag",title:"Picking the Ball in the Dirt",diff:1,cat:"fielder",ageMin:6,ageMax:99,
      description:"You're the first baseman. Routine ground ball to the second baseman with a runner on first and one out. The second baseman makes the throw but it bounces in the dirt about five feet in front of you — a classic short hop. You can see the ball clearly and he's still a few steps from first base.",
      situation:{inning:"Top 4",outs:1,count:"0-0",runners:[1],score:[0,2]},
      options:["Keep your foot on the bag, stretch toward the throw, bend your knees, and scoop your glove along the ground like you're sweeping the dirt","Stay upright and try to catch the ball after it bounces up to you","Pull your foot off the bag so you can move freely to block the ball","Close your eyes and stab at where you think the ball will be"],
      best:0,explanations:["Perfect form! Keeping your foot on the bag maintains the force out, because stretching toward the throw catches the ball sooner, before the hop gets unpredictable. Bending low and sweeping the glove along the ground gives you the best chance to scoop it cleanly.","Staying upright means the ball could bounce under your glove or skip past you — short hops stay low — you need to get down to the ball's level, not wait for it to come up to yours.","Pulling your foot off the bag means there's no force out even if you catch the ball perfectly. The whole point of first base is keeping your foot on the bag while making the catch.","Never close your eyes! You need to watch the ball all the way into your glove, which means closing your eyes and guessing leads to errors and potential injuries from getting hit by the ball."],
      rates:[88,30,20,10],concept:"Scooping throws in the dirt is a first baseman's signature skill — keep your foot on the bag, stretch toward the throw, and sweep your glove low along the ground.",explSimple:["Perfect form! Keeping your foot on the bag maintains the force out.","Not the best move. Staying upright means the ball could bounce under your glove or skip past you.","Not the best move. Pulling your foot off the bag means there's no force out even if you.","Not the best move. Never close your eyes! You need to watch the ball all the way into your glove."], anim:"groundout"},
    {id:"1b_new1",title:"The Cutoff — RF to Home",diff:2,cat:"defense",conceptTag:"cutoff-roles",ageMin:9,ageMax:99,
      description:"Runner on 2nd, nobody out. Single to right field. RF is throwing home. You're first base. What's your job?",
      situation:{inning:"Top 5",outs:0,count:"0-0",runners:[2],score:[1,1]},
      options:["Line up as the cutoff between RF and home plate","Stay at first base — this isn't your cutoff","Become the relay to second base","Back up third base on the throw"],
      best:0,explanations:["Correct. First base is the cutoff man on throws from right field to home plate. You position yourself in a direct line between the RF and home, approximately 45 feet in front of the plate. The catcher reads the play and either calls 'cut' (redirect to another base) or says nothing (let it go through). Without you, a bad RF throw has no second chance.","Staying at first base on an RF throw home leaves a critical gap, because the cutoff man's job is to give the catcher a redirect option and cut off throws that can't reach home in time. First base owns this responsibility.","The relay to second on RF-to-home throws belongs to the shortstop or second baseman, not first base, since first base's lane is the direct RF-to-home line.","Backing up third base on this play belongs to the pitcher, because your lane is RF-to-home as cutoff. Leave third base backup to the pitcher."],
      rates:[90,25,40,15],concept:"First base is the cutoff man on throws from right field to home",explSimple:["First base is the helper in the middle on throws from right field to home plate.","Staying at first base on an RF throw home leaves a critical gap.","The relay to second on RF-to-home throws belongs to the shortstop or second baseman, not first base.","Backing up third base on this play belongs to the pitcher."],anim:"groundout"},
    {id:"1b_new2",title:"Scooping the Short-Hop",diff:1,cat:"defense",conceptTag:"infield-positioning",ageMin:8,ageMax:99,
      description:"Runner on first, two outs. Ground ball to shortstop — he fields it and fires to you at first for the force, but the throw is in the dirt, bouncing 3 feet in front of the bag. What's your technique?",
      situation:{inning:"Top 2",outs:2,count:"1-2",runners:[1],score:[0,0]},
      options:["Keep your foot on the bag, drop your glove to the dirt, scoop up through the ball","Jump off the bag and block it like a catcher","Pull your foot off the bag early and catch it on the short-hop","Leave the bag and backhand it — worry about the out after"],
      best:0,explanations:["Correct! Because you maintain bag contact with your foot while dropping your glove below the ball, you scoop up through the bounce and complete the force out. Since the runner on first is being forced at your bag, keeping your foot on the base while making the catch is what gets the third out and ends the inning.","Jumping off the bag turns a force out into a safe runner, because you lose the out the moment your foot leaves the base before catching the ball. Since there's a runner on first being forced, you need bag contact to record the out.","Pulling your foot early is the most common first-base mistake at youth level, because umpires watch the foot, not the glove. Since the force play requires you to have possession of the ball while touching the base, an early foot means the runner is safe even if you catch it cleanly.","Knocking it down gives up the force out, because without a clean catch you can't record the third out. Since there's a runner on first who would be forced at your bag, any chance to scoop it cleanly is worth taking — a knockdown just keeps the inning going."],
      rates:[86,20,25,15],concept:"Short-hop scoop at first base: keep your foot on the bag, drop glove to the dirt, and scoop up through the ball to complete the force out.",explSimple:["Keep your foot on the bag and scoop through the ball to complete the force out.","Jumping off the bag loses the force out.","Pulling your foot early means the runner is safe even if you catch it.","Knocking it down gives up the force out."], anim:"groundout"},
    {id:"1b_new3",title:"Pickoff Tag — Swipe or Sweep?",diff:2,cat:"defense",conceptTag:"pickoff-mechanics",ageMin:8,ageMax:99,
      description:"Runner takes a big lead at first. Pitcher fires over for a pickoff. The throw is on time. Do you swipe tag or sweep tag?",
      situation:{inning:"Top 4",outs:1,count:"2-1",runners:[1],score:[2,1]},
      options:["Swipe tag — apply quickly at the front corner of the bag where the runner dives","Sweep tag — bring the glove across the runner's body in a wide arc","Block the bag with your body and let him run into the tag","Catch and hold — wait for the umpire to look"],
      best:0,explanations:["Correct. The swipe tag at the front corner of the bag is the fastest and safest technique. Your glove meets the runner's hand or foot at the earliest contact point — the front edge of the bag where he dives back. Place the back of the glove down so the ball doesn't get knocked loose on contact. MLB first basemen apply this tag in under 0.15 seconds from catch to tag completion.","The sweep tag (wide arc across the body) takes 3-4x longer than the swipe tag and exposes the ball to being knocked loose — on a close pickoff, the sweep will be too slow. Reserve the sweep for runners already committed past the bag.","Blocking the bag creates obstruction risk, which means you must present the tag, not your body. Letting a runner run into you is Type A obstruction — automatic safe, possibly advancing other runners.","Catching and holding confuses the umpire and delays the tag, because apply it immediately upon catching — don't wait. Delayed tags are never called out."],
      rates:[90,40,25,15],concept:"Pickoff tag: swipe at front bag corner, back of glove down",explSimple:["The swipe tag at the front corner of the bag is the fastest and safest technique.","The sweep tag (wide arc across the body) takes 3-4x longer than the swipe tag and exposes the ball to being knocked loose.","Blocking the bag creates obstruction risk.","Catching and holding confuses the umpire and delays the tag."],anim:"strike"},
    {id:"1b_new4",title:"Bunt Defense — Your Crash",diff:2,cat:"defense",conceptTag:"bunt-defense",ageMin:10,ageMax:99,
      description:"Runner on 1st, nobody out. Batter shows bunt early. You're playing at normal depth. When do you break for the bunt?",
      situation:{inning:"Top 2",outs:0,count:"0-0",runners:[1],score:[0,0]},
      options:["Break hard on the pitch — commit to the bunt as the pitcher delivers","Wait until you see the ball hit the ground","Creep forward but don't commit until contact","Stay back — let the pitcher handle bunts down the line"],
      best:0,explanations:["Correct. On a bunt defense, first base crashes hard on the pitch — an aggressive commitment that accepts the risk of leaving first uncovered. The timing key is 'go when the pitcher's arm comes forward.' Committing on delivery gives you the speed to field a bunt and still have a play. Hesitation — waiting to see where the ball goes — means arriving late and having no play anywhere. Hard crash = options. Hesitation = no play.","Waiting until the ball hits the ground means you arrive 1-2 seconds late, since by then, the batter is halfway to first and you have no throw. Reaction-based charging kills all bunt defense plays.","Creeping forward is half-charging — you're slow to the ball and you've already left first base uncovered without gaining the speed to field it effectively, because commit fully or hold your position.","Letting the pitcher handle first-base-side bunts alone is too passive — pitchers field bunts down the first base line, but you crash to give a second fielder option and to take a quick throw back from the catcher."],
      rates:[90,25,40,15],concept:"Bunt defense: 1B crashes hard on the pitch, not after contact",explSimple:["On a bunt defense, first base crashes hard on the pitch.","Waiting until the ball hits the ground means you arrive 1-2 seconds late.","Creeping forward is half-charging — you're slow to the ball and you've already left first base uncovered without gaining the speed to field it effectively.","Letting the pitcher handle first-base-side bunts alone is too passive."],anim:"groundout"},
    {id:"1b_new5",title:"Runner on Second — Hold or Play Back?",diff:3,cat:"defense",conceptTag:"infield-positioning",ageMin:11,ageMax:99,
      description:"Runner on 2nd base only, 1 out, tie game in the 7th. Do you hold the runner at second or play at normal depth?",
      situation:{inning:"Top 7",outs:1,count:"0-0",runners:[2],score:[3,3]},
      options:["Play at normal depth — no need to hold a runner on second","Hold the runner tight at second base","Play halfway — between hold and normal depth","Shade toward the line to guard against the double"],
      best:0,explanations:["Correct. There is never a standard reason to hold a runner at second base. Holding a runner at second gains you almost nothing — the runner can score from second on a single regardless of his lead. Normal depth at first base keeps you in the play for grounders, gives you better range, and maintains your ability to cover first on bunts. Holding at second base is textbook positional waste.","Holding at second base is one of the most common strategic mistakes in youth baseball, which means the runner scores from second on a hit anyway — your two extra feet of lead inhibition buys nothing. You surrender your range and your coverage duty at first.","'Halfway' positioning combines the weaknesses of both — you're not covering first effectively and you're not helping at second, because position yourself for your primary job: fielding ground balls and receiving throws at first.","Shading toward the line in a 1-out, tie game is reasonable late-game positioning — guarding against an extra-base hit, since but the core answer is: play normal depth. No hold at second base."],
      rates:[75,15,32,35],concept:"Never hold a runner at second base — no strategic value",anim:"groundout"},
    {id:"1b15", conceptTag:"relay-double-cut",title:"Relay Position on Extra-Base Hit to Right",diff:2,cat:"fielder",ageMin:9,ageMax:99,
      description:"You're the first baseman. A ball is hit to the right-center gap and it's rolling to the wall. Runner on first is rounding second and heading for third. Where do you position yourself?",
      situation:{inning:"Bot 4",outs:1,count:"0-0",runners:[1],score:[1,2]},
      options:["Line up between the outfielder and home plate as the cutoff man","Line up between the outfielder and third base","Stay at first base in case the batter tries to stretch to a double","Run to back up the throw at third base"],
      best:0,explanations:["On extra-base hits to right-center, the first baseman is the cutoff man, because line up in a direct line between where the outfielder fields the ball and home plate, about 45 feet in front of home. Listen for the catcher's call to cut it or let it through.","Lining up toward third is the shortstop's or second baseman's job on relay plays — the first baseman's lane is always toward home plate on throws from the right side of the outfield.","Staying at first base takes you out of the most important play happening on the field, which means nobody is going back to first — the action is at home. Get into cutoff position.","Backing up third is the pitcher's responsibility, because your job as first baseman is the cutoff lane between the outfield and home plate."],
      rates:[85,30,15,20],concept:"On extra-base hits to right field, the first baseman is the cutoff man between the outfielder and home plate",explSimple:["On extra-base hits to right-center, the first baseman is the helper in the middle.","Lining up toward third is the shortstop's or second baseman's job on relay plays.","Staying at first base takes you out of the most important play happening on the field.","Backing up third is the pitcher's responsibility."],anim:"throwHome"},
    {id:"1b16", conceptTag:"bunt-defense",title:"Bunt With Runner on Second — Where to Throw?",diff:1,cat:"fielder",ageMin:6,ageMax:99,
      description:"You're the first baseman. Runner on 2nd, nobody out. The batter drops a sacrifice bunt right in front of you. You charge and field it cleanly. The runner on second is going to third. Where do you throw?",
      situation:{inning:"Bot 3",outs:0,count:"0-1",runners:[2],score:[1,1]},
      options:["Throw to first — get the easy out on the batter","Throw to third — try to get the lead runner","Hold the ball and look at both runners","Throw home — the runner might try to score"],
      best:0,explanations:["Get the sure out at first! When you charge a bunt with a runner on second, the lead runner usually gets a great jump to third. Trying to throw behind a runner going to third is risky and often results in nobody being out. Take the guaranteed out at first base.","The runner on second had a big head start, since you throwing to third is a bang-bang play where an error means everyone is safe and the batter reaches first. The safe play is the out you can get.","Holding and looking takes time, and now both runners are safe, because on bunt plays, you have to decide quickly. In this situation, take the out at first.","The runner on second is going to third, not home, since there's no play at home plate on a sacrifice bunt from second to third."],
      rates:[90,40,25,15],concept:"On sacrifice bunts, take the sure out — don't try to be a hero by getting the lead runner when the throw is risky",explSimple:["Great choice! Get the sure out at first. The runner going to third had a big head start.","Not the best move. The runner on second had a big head start to third.","Not the best move. Holding and looking takes time, and now both runners are safe.","Not the best move. The runner is going to third, not home."],anim:"bunt"},
    {id:"1b17", conceptTag:"force-vs-tag",title:"3-1 Putout — Unassisted",diff:1,cat:"fielder",ageMin:6,ageMax:99,
      description:"You're the first baseman. Ground ball hit right to you. Nobody on base, 1 out. You field it cleanly. The pitcher isn't covering first yet. What do you do?",
      situation:{inning:"Top 2",outs:1,count:"1-0",runners:[],score:[0,0]},
      options:["Take it to the bag yourself — step on first for the unassisted putout","Throw to the pitcher covering first","Hold the ball and wait for the pitcher to get there","Throw to second base"],
      best:0,explanations:["If you're close enough to the bag, take it yourself! A 3-1 unassisted putout (first baseman to first base) is the safest play when the pitcher hasn't gotten over yet. No throw means no chance of a throwing error.","The pitcher isn't covering first yet. Waiting for him and then throwing adds time and risk. If you can reach the bag yourself, that's always the safer play.","Holding and waiting lets the batter get closer to first. If you're near the bag, just go step on it yourself.","Nobody is running to second base. First base is where the out is — take the ball there."],
      rates:[85,30,20,10],concept:"When you field the ball near first base and can reach the bag, take the unassisted putout — no throw means no error",explSimple:["Great choice! If you're close to the bag, just step on it yourself. No throw means no error!","Not the best move. The pitcher isn't covering first yet, so waiting adds time and risk.","Not the best move. Holding and waiting lets the batter get closer to first.","Not the best move. Nobody is running to second base — the out is at first."],anim:"groundout"},
    {id:"1b18", conceptTag:"fly-ball-priority",title:"Pop-Up Near the Dugout",diff:2,cat:"fielder",ageMin:9,ageMax:99,
      description:"You're the first baseman. Foul ball popped up high on the first base side, drifting toward the dugout. The second baseman also runs over. Who takes it?",
      situation:{inning:"Top 3",outs:1,count:"0-2",runners:[1],score:[2,1]},
      options:["You take it — call everyone off and track the ball","Let the second baseman take it since he's running toward the ball","Let whoever gets there first catch it","Back off and let the catcher handle it"],
      best:0,explanations:["Foul pop-ups on the first base side are your ball as the first baseman, which means you're closer, you have a better angle, and the second baseman would be running away from the play. Call 'I got it!' loudly and repeatedly, track the ball, and watch for the dugout railing.","The second baseman would be running toward the dugout — away from the infield and toward an obstacle, because you're already facing the right direction and are closer to the play. Take charge.","Letting whoever gets there first is how collisions happen, since someone must call for the ball, and on the first base side, that's the first baseman. Take charge and call everyone off.","The catcher handles pop-ups directly behind home plate, because this one is on the first base side — it's your territory as the first baseman."],
      rates:[85,30,15,20],concept:"Pop-ups on the first base side belong to the first baseman — call for the ball and watch for the dugout railing",explSimple:["Foul pop-ups on the first base side are your ball as the first baseman.","The second baseman would be running toward the dugout — away from the infield and toward an obstacle.","Letting whoever gets there first is how collisions happen.","The catcher handles pop-ups directly behind home plate."],anim:"catch"},
    {id:"1b19", conceptTag:"force-vs-tag",title:"Wide Throw From the Shortstop",diff:2,cat:"fielder",ageMin:9,ageMax:99,
      description:"You're the first baseman. Routine grounder to shortstop, but his throw is pulling you off the bag toward the home plate side. The batter-runner is about three steps from first. What do you do?",
      situation:{inning:"Top 5",outs:0,count:"0-0",runners:[],score:[1,0]},
      options:["Stretch toward the throw with your glove foot on the bag — reach as far as you can while maintaining contact","Come off the bag entirely and catch the ball cleanly — you can tag the runner","Switch feet and stretch with your throwing-side foot on the bag","Stay flat-footed on the bag and wait for the ball to come to you"],
      best:0,explanations:["Stretching with your glove foot on the bag gives you maximum reach toward the throw while keeping the force play alive — this is the fundamental first baseman stretch — every inch of reach can be the difference between safe and out.","Coming off the bag gives up the force play, which means now you need to tag the runner, which is much harder on a bang-bang play. Keep your foot on the bag whenever possible.","Switching feet reduces your reach toward the throw, because the glove-side foot on the bag keeps your body oriented toward the throw and gives you the longest stretch.","Staying flat-footed gives you no extra reach, since the whole point of the stretch is to catch the ball as early as possible — every split second matters on a close play at first."],
      rates:[85,30,25,20],concept:"Stretch with your glove foot on the bag to maximize reach — keeping the force play alive is almost always better than coming off the bag to tag",explSimple:["Stretching with your glove foot on the bag gives you maximum reach toward the throw while keeping the force play alive.","Coming off the bag gives up the force play.","Switching feet reduces your reach toward the throw.","Staying flat-footed gives you no extra reach."],anim:"groundout"},
    {id:"1b20", conceptTag:"pickoff-mechanics",title:"Holding the Runner With a Left-Handed Pitcher",diff:3,cat:"fielder",ageMin:12,ageMax:99,
      description:"You're the first baseman. Fast runner on first with a left-handed pitcher on the mound. The runner has been getting big secondary leads. How do you and the lefty work together to keep him close?",
      situation:{inning:"Top 6",outs:0,count:"0-0",runners:[1],score:[3,2]},
      options:["Hold your position at first — the lefty can see the runner and pick him off without your help","Give the pitcher a target with your glove, stay tight to the bag, and time the pickoff together with a pre-arranged signal","Cheat toward the bag early so the runner sees you're ready","Play behind the runner to take away the big lead"],
      best:1,explanations:["A left-handed pitcher has a natural advantage seeing the runner at first, but the first baseman is still critical, because without a target and a pre-arranged timing signal, pickoff throws are less accurate and less effective. Teamwork makes pickoffs work.","The first baseman and lefty pitcher work as a unit. Hold your glove up as a target near the bag, stay tight so you can receive the throw and apply the tag quickly, and use a pre-arranged count or signal so you both time the move together. Left-handed pickoffs are devastating when the first baseman and pitcher are in sync.","Cheating toward the bag too early tips off the runner — a good base stealer will see you moving early and shorten his lead. Stay relaxed until the signal, then move to the bag.","Playing behind the runner means you can't receive the pickoff throw at first base, which means if the pitcher fires over, there's nobody to catch it. Stay close to the bag where you can receive throws and apply tags."],
      rates:[25,85,30,15],concept:"First baseman and lefty pitcher work as a unit on pickoffs — pre-arranged signals and a visible target make the timing devastating",anim:"safe"},
  ],
  rightField: [
    {id:"f7", conceptTag:"tag-up",title:"Shallow Fly Tag-Up",diff:2,cat:"outfield",ageMin:9,ageMax:99,
      description:"You're in right. Runner on 3rd, 1 out. Shallow fly — you catch it. Runner tags up.",
      situation:{inning:"Bot 8",outs:1,count:"0-0",runners:[3],score:[2,3]},
      options:["Throw home immediately","Throw to cutoff","Hold — too shallow","Throw to 2nd"],
      best:0,explanations:["Since you caught the ball shallow, you're much closer to home plate than on a deep fly ball, which means your throw has less distance to travel and arrives faster. Throw directly home because the short distance gives you a realistic chance to beat the runner — otherwise he scores the go-ahead run.","Using a cutoff relay adds an extra catch-and-throw, which wastes precious time. Since you're already shallow and close to home, the direct throw is faster because the ball only has to travel one distance instead of two.","Holding the ball because the fly is shallow is backwards thinking. The key is that shallow means you're CLOSER to home, not farther. That way your throw has less distance to cover, which gives you your best chance to nail the runner at the plate.","Throwing to second base ignores the runner scoring from third, which is the entire reason this play matters. Since the tying run is tagging up from third, home plate is the only base that matters — if you throw to second, the runner scores the go-ahead run unopposed."],
      explSimple:["You caught the ball close to home plate, which means your throw gets there faster — fire it home!","Using a cutoff man wastes time because you're already close enough to throw home yourself.","Being shallow means you're CLOSER to home — that way you have a great chance to throw the runner out.","The runner is going home from third, so throwing to second doesn't help because it lets the run score."],
      rates:[85,50,20,10],concept:"On shallow fly balls, throw directly home — the short distance is your advantage",anim:"throwHome"},
    {id:"f11",title:"Backing Up Bases",diff:1,cat:"positioning",conceptTag:"backup-duties",ageMin:8,ageMax:99,
      description:"You're in right field. Grounder to shortstop, runner on 2nd going to 3rd. Where should you go?",
      situation:{inning:"Top 3",outs:1,count:"0-0",runners:[2],score:[1,1]},
      options:["Stay in position","Back up 1st base","Back up 3rd base","Back up home"],
      best:1,explanations:["Staying in position means you can't help if there's an overthrow.","Correct! The right fielder backs up throws to 1st — if the ball gets away, you are right there to keep the runner from advancing.","The left fielder backs up 3rd, not the right fielder. Each outfielder has their own backup assignment.","The catcher covers home — that is his responsibility, not yours. Your job is backing up first base."],
      explSimple:["Don't just stand there! Run to back up the throw in case someone misses it.","Right! Go stand behind first base in case the throw gets past the first baseman.","The left fielder backs up third base, not you. You back up first base.","The catcher is already at home plate — that's not where you need to go."],
      rates:[20,85,30,15],concept:"Always back up the base where the throw is going — anticipate overthrows",anim:"catch"},
    {id:"f25", conceptTag:"backup-duties",title:"Who Backs Up the Throw?",diff:1,cat:"outfield",ageMin:6,ageMax:99,
      description:"Top of the 3rd, runner on 1st, nobody out. Ground ball to the shortstop — he's throwing to first. You're the right fielder. What should you be doing?",
      situation:{inning:"Top 3",outs:0,count:"0-0",runners:[1],score:[1,0]},
      options:["Stand and watch — it's an infield play","Back up first base","Run toward the infield to help","Back up second base"],
      best:1,explanations:["Standing and watching is lazy outfield play — every outfielder has a backup responsibility on every play.","The right fielder backs up throws to first base. If the throw gets past the first baseman, you're there to keep the runner from advancing. This prevents one error from becoming two bases.","Running toward the infield gets you too close, which means you need to be behind first base at a distance.","The throw is going to first, not second, because back up the base where the throw is going."],
      rates:[15,90,25,40],concept:"Right fielders back up first base on infield grounders — prevent one error from becoming two bases",explSimple:["Not the best move. Standing and watching is lazy outfield play.","Great choice! The right fielder backs up throws to first base.","Not the best move. Running toward the infield gets you too close.","Not the best move. The throw is going to first, not second."], anim:"catch"},
    {id:"f26", conceptTag:"cutoff-roles",title:"Runner Rounding Second Hard",diff:2,cat:"outfield",ageMin:9,ageMax:99,
      description:"Bot 4th, runner on 1st, nobody out, down 2-1. Clean single to right field. The runner from first is rounding second hard — the first base coach is waving him to third.",
      situation:{inning:"Bot 4",outs:0,count:"0-0",runners:[1],score:[2,1]},
      options:["Throw to third — cut him down","Hit the cutoff man and let him redirect","Throw home in case he tries to score","Hold the ball — he's already at third"],
      best:1,explanations:["Throwing directly to third from right field is a long throw that's likely to sail, since if it gets past the third baseman, the runner scores.","Hit the cutoff man! On a single to right with a runner going first to third, your job is to throw a strong, low throw to the cutoff. He can redirect to third if there's a play, or hold it to prevent the batter from advancing. The cutoff creates options.","Throwing home when the runner is only going to third wastes a throw and lets the batter advance.","Holding the ball lets runners take extra bases for free, because always make a throw."],
      rates:[35,85,15,20],concept:"On singles to right with runners advancing, hit the cutoff — he can redirect to the right base",explSimple:["Throwing directly to third from right field is a long throw that's likely to sail.","On a single to right with a runner going first to third, your job is to throw a strong, low throw to the cutoff.","Throwing home when the runner is only going to third wastes a throw and lets the batter advance.","Holding the ball lets runners take extra bases for free."],anim:"throwHome"},
    {id:"f55", conceptTag:"of-depth-arm-value",title:"Fly Ball in the Sun",diff:1,cat:"outfield",ageMin:6,ageMax:99,
      description:"Bot 4th, nobody on, 1 out. Fly ball hit to right field — you look up and the sun is directly in your eyes. You lost the ball!",
      situation:{inning:"Bot 4",outs:1,count:"0-0",runners:[],score:[2,1]},
      options:["Use your glove as a sun shield — put it up to block the sun","Close your eyes and guess where it'll land","Call off and let someone else catch it","Drop your head and pick up the ball below the sun"],
      best:0,explanations:["Use your glove to shield the sun! Raise your glove above your eyes to block the sun while keeping your other eye on the ball, since this is the classic sun-fly technique that every outfielder learns. You can track the ball in the shadow your glove creates.","Never close your eyes in the outfield, because you'll get hit in the face or miss the ball entirely. You need to track the ball all the way into your glove, even when the sun is blinding.","Calling off wastes time when you have the tools to make the play yourself. Use the glove-shield technique, since by the time another fielder gets there, it may be too late.","Dropping your head means you lose the ball completely, because Keep your head up and use the glove above your eyes to block the sun. Once you lose sight of the ball in bright sunlight, it's nearly impossible to pick it up again."],
      rates:[85,5,30,25],concept:"On fly balls in the sun, use your glove as a sun shield — raise it to block the sun while tracking the ball",explSimple:["Great choice! Use your glove to shield the sun! Raise your glove above your eyes to block.","Not the best move. Never close your eyes in the outfield.","Not the best move. Calling off wastes time.","Not the best move. Dropping your head means you lose the ball completely."], anim:"catch"},
    {id:"f56", conceptTag:"of-communication",title:"Communication Between Outfielders",diff:2,cat:"communication",ageMin:9,ageMax:99,
      description:"Top of the 3rd, nobody on. Ball hit to the gap in right-center. Both you (RF) and the center fielder are sprinting for it. You're both close.",
      situation:{inning:"Top 3",outs:1,count:"0-0",runners:[],score:[1,0]},
      options:["Call 'I got it!' loudly and clearly","Don't call it — whoever gets there first catches it","Wave your glove so the CF sees you","Call 'Mine!' and keep running — he'll get out of the way"],
      best:0,explanations:["CALL IT! Yell 'I got it!' or 'Mine!' loudly and clearly, which means if the center fielder also calls it, defer to him — he has priority. If he doesn't call it, it's yours. Communication prevents collisions and dropped balls. The call must be LOUD — a stadium is noisy.","Not calling it guarantees confusion and possibly a collision. Always communicate on fly balls — silence is the most dangerous thing in the outfield because both players assume the other will stop.","Waving your glove takes your hand off the catch and makes it harder to make the play. Use your voice, not your glove — verbal calls are faster and let you keep both hands ready for the catch.","'Mine!' works, but you should also listen for the CF's call because he has priority. If he calls it, peel off immediately and let him take it. The center fielder outranks the corner outfielders on shared balls."],
      rates:[85,5,20,35],concept:"On fly balls between fielders, CALL IT loudly — communication prevents collisions and errors",explSimple:["Yell 'I got it!' or 'Mine!' loudly and clearly.","Not calling it guarantees confusion and possibly a collision.","Waving your glove takes your hand off the catch.","'Mine!' works, but you should also listen for the CF's call."],anim:"catch"},
    {id:"f58", conceptTag:"of-depth-arm-value",title:"Ball at the Wall — Make the Play or Protect Yourself?",diff:3,cat:"outfield",ageMin:12,ageMax:99,
      description:"Top of the 9th, runner on 1st, 2 outs, up 5-4. Deep fly ball to the warning track. You're sprinting back and feel the warning track under your feet. The ball is catchable but you'll hit the wall.",
      situation:{inning:"Top 9",outs:2,count:"0-0",runners:[1],score:[5,4]},
      options:["Make the catch — win the game, worry about the wall later","Pull up — your safety comes first","Reach up and try to time the catch before impact","Feel the wall with your hand, then make the catch"],
      best:3,explanations:["Crashing into the wall without awareness is how outfielders get seriously hurt because you have no way to brace for impact. If you run full speed into a padded wall while looking up, the collision can cause concussions or shoulder injuries, which means you might win this play but miss the rest of the season.","Pulling up lets the ball drop for a hit, which means the runner on first advances and the tying run could reach scoring position. Since there's a technique that lets you make the catch safely, pulling up gives away an out you could have gotten.","Reaching up blindly might work, but you could hit the wall face-first because you have no idea how close it is. That's dangerous since even padded walls deliver a serious jolt when you're sprinting full speed with your eyes on the ball.","Feel the warning track under your feet, then find the wall with your non-glove hand. Reach up with your glove hand for the catch while bracing yourself against the wall with your other hand. This works because your free hand absorbs the impact, which means you stay on your feet and make the catch safely — that's how all great outfielders handle the wall."],
      rates:[30,20,35,85],concept:"At the wall, use your free hand to find and brace against it while catching with your glove hand",anim:"catch"},
    {id:"rf1", conceptTag:"of-depth-arm-value",title:"Gun Down at Third",diff:2,cat:"fielder",ageMin:9,ageMax:99,
      description:"You're the right fielder. A sharp single is hit to right field. The runner on first base is rounding second hard and trying to advance to third. You field the ball cleanly on one hop. You have a strong arm and third base is open.",
      situation:{inning:"Top 4",outs:1,count:"2-2",runners:[1],score:[2,1]},
      options:["Fire a strong throw to third base on a line to try to nail the runner","Throw to second base to keep the batter from advancing","Hold the ball and jog it back in to the cutoff man","Throw home in case the runner doesn't stop at third"],
      best:0,explanations:["You have a clean field and a strong arm, because you throwing to third base to get the advancing runner is the high-value play. Getting an out here stops a runner from reaching scoring position.","Throwing to second lets the runner take third base for free, since the batter already has a single — the dangerous runner is the one heading to third.","Holding the ball and jogging it in is playing too safe, because you have a chance to get an out, and that's always worth taking when you field the ball cleanly.","The runner is going to third, not home — throwing home wastes your arm and lets the runner take third easily while accomplishing nothing."],
      rates:[85,40,30,15],concept:"Right fielders with strong arms can keep runners from going first-to-third — that throw takes away a scoring-position runner.",explSimple:["You have a clean field and a strong arm.","Throwing to second lets the runner take third base for free.","Holding the ball and jogging it in is playing too safe.","The runner is going to third, not home."],anim:"catch"},
    {id:"rf2", conceptTag:"of-depth-arm-value",title:"Stop First-to-Third",diff:1,cat:"fielder",ageMin:6,ageMax:99,
      description:"You're in right field. A ground ball single comes through the infield and rolls toward you. There's a runner on first base who is a fast runner. Your coach always says the right fielder's most important job is preventing first-to-third advances.",
      situation:{inning:"Bot 5",outs:0,count:"1-1",runners:[1],score:[3,3]},
      options:["Charge the ball aggressively to field it quickly and throw to third base","Hang back and wait for the ball to come to you, then throw to second","Let the ball roll to you while watching the runner","Throw to first base to make sure the batter doesn't take second"],
      best:0,explanations:["Charging the ball cuts down the time the runner has to advance, which means getting to the ball fast and making a quick throw to third gives you the best chance to cut down the runner or at least hold him at second.","Hanging back lets the runner round second and cruise into third easily, because every extra second the ball is on the ground is an extra step for the runner.","Watching the runner instead of attacking the ball is passive play, since by the time the ball reaches you, the runner is standing on third.","Throwing to first doesn't help since the batter already has a single. The critical play is stopping the lead runner from taking third."],
      rates:[90,40,25,15],concept:"Charge ground ball singles aggressively in right field — every second you save keeps runners from going first-to-third.",explSimple:["Great choice! Charging the ball cuts down the time the runner has to advance.","Not the best move. Hanging back lets the runner round second and cruise into third easily.","Watching the runner instead of attacking the ball is passive play.","Not the best move. Throwing to first doesn't help since the batter already has a single."], anim:"catch"},
    {id:"rf3", conceptTag:"cutoff-roles",title:"Hit the Cutoff Man",diff:1,cat:"fielder",ageMin:6,ageMax:99,
      description:"You're the right fielder. A deep fly ball drops in front of the warning track for a hit. A runner is scoring from second base. You pick up the ball 320 feet from home plate. The second baseman has set up as your cutoff man about 150 feet from you. Your arm can reach home on the fly from 250 feet but not from 320.",
      situation:{inning:"Top 6",outs:1,count:"0-2",runners:[2],score:[1,2]},
      options:["Throw a hard one-hop throw to the cutoff man so he can relay it home","Air-mail a throw toward home plate even though you can't reach it","Run the ball in closer before throwing so you can reach home","Throw to third base instead to keep the batter from advancing"],
      best:0,explanations:["Hitting the cutoff man with a strong throw gives your team the best chance, because the relay can reach home faster than you can throw it there, and the cutoff man can redirect the throw if needed.","Throwing a rainbow toward home that bounces multiple times gives the runner an easy score and lets the batter take extra bases — a throw you can't reach is a wasted throw.","Running the ball in takes too long, which means the runner scores easily while you're jogging forward, and now the batter advances too.","Throwing to third ignores the runner scoring, because the run matters more than the batter's position, and the cutoff man can redirect to third anyway if needed."],
      rates:[85,15,20,35],concept:"When you can't reach home on the fly, always hit your cutoff man — a good relay is faster than a bad long throw.",explSimple:["Great choice! Hitting the cutoff man with a strong throw gives your team the best chance.","Not the best move. Throwing a rainbow toward home that bounces multiple times gives the runner an easy score.","Not the best move. Running the ball in takes too long.","Not the best move. Throwing to third ignores the runner scoring."], anim:"throwHome"},
    {id:"rf4", conceptTag:"of-depth-arm-value",title:"Playing the Wall",diff:2,cat:"fielder",ageMin:9,ageMax:99,
      description:"You're the right fielder. A hard line drive is hit down the right field line toward the corner. The ball is going to hit the wall. You need to play the carom. Your coach taught you that balls hitting the wall straight-on bounce straight back, but balls hitting the corner angle toward center field.",
      situation:{inning:"Bot 3",outs:0,count:"1-0",runners:[1],score:[0,1]},
      options:["Angle your run toward center field side of the corner to play the carom off the wall","Run straight at where the ball will hit the wall and wait for it","Run to the corner and put your back against the wall to trap the ball","Stay where you are and let the ball bounce back to you"],
      best:0,explanations:["The ball hitting the corner will angle back toward center field, since by running to where the carom will end up instead of where the ball hits, you save precious seconds and field the ball much quicker.","Running straight at the wall means the carom bounces past you toward center field, because you'll have to spin around and chase it, giving the runners extra time to advance.","Putting your back against the wall is dangerous and the ball will bounce off the wall well before it reaches you, caroming away toward center field. After all, so this approach matters in this situation.","Staying where you are means the ball bounces around in the corner while runners circle the bases, since you need to attack the ball, not wait for it."],
      rates:[85,35,15,10],concept:"Learn how balls carom off the wall — corner hits angle toward center field, so position yourself where the bounce will go, not where the ball hits.",explSimple:["The ball hitting the corner will angle back toward center field.","Running straight at the wall means the carom bounces past you toward center field.","Putting your back against the wall is dangerous and the ball will bounce off the wall well before it reaches you, caroming away toward center field.","Staying where you are means the ball bounces around in the corner while runners circle the bases."],anim:"catch"},
    {id:"rf5", conceptTag:"of-communication",title:"Shallow Fly Communication",diff:1,cat:"fielder",ageMin:6,ageMax:99,
      description:"You're in right field. A soft fly ball is hit to shallow right field. The second baseman drifts back and you're charging in. You can see the second baseman faces an over-the-shoulder catch, while you're coming straight in with the ball in front of you.",
      situation:{inning:"Top 2",outs:0,count:"0-1",runners:[1,2],score:[1,0]},
      options:["Call 'I got it!' loudly and keep charging — the ball is in front of you for an easier catch","Stay quiet and let the second baseman take it since he's closer","Call off the second baseman but then slow down and let it drop","Call for the infielder to take it since infielders have priority on pop flies"],
      best:0,explanations:["An outfielder coming in has the ball in front of them and more momentum for a throw, which means outfielders have priority over infielders on balls they can reach. Call it loud and clear to avoid a collision!","Staying quiet with two fielders converging is how collisions happen, because someone must call for the ball, and the outfielder has the better angle coming forward.","Calling for the ball and then slowing down could cause the ball to drop for a hit with runners on base. If you call it, commit to making the catch.","Infielders have priority on infield pop-ups, but on balls in the shallow outfield, the outfielder has priority because they're running forward with the ball in front of them."],
      rates:[85,20,10,30],concept:"Outfielders have priority over infielders on fly balls because you running in is easier than running out with the ball over your shoulder.",explSimple:["Great choice! An outfielder coming in has the ball in front of them and more momentum for a throw.","Not the best move. Staying quiet with two fielders converging is how collisions happen.","Not the best move. Calling for the ball and then slowing down could cause the ball to drop.","Not the best move. Infielders have priority on infield pop-ups, but on balls in the shallow outfield, the outfielder."], anim:"catch"},
    {id:"rf6", conceptTag:"backup-duties",title:"Back Up First Base",diff:1,cat:"fielder",ageMin:6,ageMax:99,
      description:"You're the right fielder. A ground ball is hit to the shortstop with nobody on base and one out. The shortstop fields it and throws to first base. You know your coach always says right fielders should back up first base on infield grounders.",
      situation:{inning:"Bot 1",outs:1,count:"0-0",runners:[],score:[0,0]},
      options:["Sprint toward the area behind first base in foul territory to back up the throw","Stay in right field and watch the play since it's a routine grounder","Run toward second base to cover in case of an error","Move toward center field to back up a possible overthrow there"],
      best:0,explanations:["Backing up first base is one of the right fielder's most important responsibilities, since if the throw gets past the first baseman, you're there to keep the ball from rolling to the fence and the batter from taking extra bases.","Watching from right field means an overthrow rolls all the way to the fence, because that turns a routine out into a runner on second or third. Never stand and watch!","Second base doesn't need coverage on this play. The throw is going to first, so that's where the backup needs to be.","An overthrow at first goes into foul territory on the right side, not toward center field — you need to be behind first base, not in center."],
      rates:[90,40,25,15],concept:"The right fielder backs up first base on every infield grounder — it's a routine responsibility that prevents disaster on overthrows.",explSimple:["Great choice! Backing up first base is one of the right fielder's most important responsibilities.","Watching from right field means an overthrow rolls all the way to the fence.","Not the best move. Second base doesn't need coverage on this play.","Not the best move. An overthrow at first goes into foul territory on the right side, not toward center field."], anim:"advance"},
    {id:"rf7", conceptTag:"of-depth-arm-value",title:"Charge or Play It Safe",diff:2,cat:"fielder",ageMin:9,ageMax:99,
      description:"You're in right field. A hard ground ball single gets through the infield into right field. There's a runner on second base who's rounding third. The ball is bouncing toward you with good speed. If you charge hard, you might bobble it but will have a shorter throw. If you play it safe, you'll field it cleanly but the throw will be longer.",
      situation:{inning:"Top 7",outs:2,count:"1-2",runners:[2],score:[5,4]},
      options:["Charge hard and field the ball aggressively to make the shorter throw home","Hang back, field it cleanly, then hit the cutoff man","Charge hard but throw to second base instead of home","Let the ball come to you and throw to the cutoff man"],
      best:0,explanations:["With two outs in a one-run game, you need to be aggressive, which means charging the ball saves time and shortens the throw home. A clean aggressive play gives you the best chance to throw out the tying run at the plate.","Hanging back and hitting the cutoff man concedes the run at the plate, because in a close game with two outs, you need to charge aggressively and try to make the play at home yourself.","Throwing to second base concedes the run at home, since with two outs in a one-run game, the only throw that matters is to home plate.","Letting the ball come to you and throwing to the cutoff is fine when the run doesn't matter, but this is the tying run with two outs, because you need to be aggressive and try to make the play at the plate."],
      rates:[80,35,15,30],concept:"In close games with two outs, charge the ball aggressively — saving a half-second on your throw can be the difference between an out and a run scoring.",explSimple:["With two outs in a one-run game, you need to be aggressive.","Hanging back means the runner scores easily — you need to be aggressive with the tying run heading home.","Throwing to second base concedes the run at home.","Letting the ball come to you and throwing to the cutoff is fine when the run doesn't matter, but this is the tying run with two outs."],anim:"throwHome"},
    {id:"rf8", conceptTag:"cutoff-roles",title:"Throw Through or Hit Cutoff",diff:3,cat:"fielder",ageMin:12,ageMax:99,
      description:"You're the right fielder. A line drive single comes right at you and you field it on one clean hop. The runner on first is rounding second. You're playing at medium depth, about 280 feet from home. Your arm is decent but not elite — you can reach third on the fly from here but home would require a bounce. The first base coach is waving the runner to third.",
      situation:{inning:"Bot 5",outs:0,count:"2-1",runners:[1],score:[2,2]},
      options:["Hit the cutoff man with a strong throw so the relay can go to third or home","Try to throw all the way home on one bounce in case the runner goes","Throw directly to third base to try to get the runner","Hold the ball since the runner is going to make it to third anyway"],
      best:0,explanations:["Hitting the cutoff man gives your team options — the relay man can throw to third if the runner stops, or redirect home if the runner rounds too far. A good cutoff throw keeps all your options alive.","Throwing home on a bounce from 280 feet will be too slow and the ball could bounce away from the catcher, which means meanwhile, if the runner stops at third, your throw to home accomplishes nothing.","You might get the runner at third, but a throw that misses goes into the dugout and the runner scores, because you hitting the cutoff is safer and the relay can still get him at third.","Holding the ball gives the runner a free base and possibly lets him round third, since always make a strong throw to keep the pressure on the baserunner."],
      rates:[80,25,40,15],concept:"When in doubt, hit the cutoff man — it keeps every option alive and prevents the throw from becoming an error that gives up extra bases.",anim:"throwHome"},
    {id:"rf9", conceptTag:"of-depth-arm-value",title:"Ball Down the Right Field Line",diff:1,cat:"fielder",ageMin:6,ageMax:99,
      description:"You're the right fielder. The batter slashes a hard ground ball down the right field line. It's hugging the foul line and rolling fast toward the corner. There's a runner on first who is already sprinting toward second. You need to get to the ball quickly and make a smart play.",
      situation:{inning:"Bot 3",outs:1,count:"1-0",runners:[1],score:[1,2]},
      options:["Angle your run toward the foul line side so you can field the ball and already be facing the infield for your throw","Run straight at the ball and then spin around to throw after you pick it up","Let the ball roll and see if it goes foul — it's close to the line","Jog toward the ball to save energy for the throw"],
      best:0,explanations:["Angling toward the line puts your body in position to field the ball and make a throw in one fluid motion. You're already facing the infield when you pick it up, saving a full turn. That saved time can be the difference between a double and holding the runner at second.","Running straight at the ball means your momentum carries you away from the infield, because you have to stop, spin, and then throw — that extra time lets the runner take an extra base.","Hoping a ball goes foul is never a plan, since if it stays fair and you waited, the runner is rounding third. Always play the ball as if it's fair until it isn't.","Jogging to a live ball in play is unacceptable, which means the runner is sprinting — you need to match his urgency. Every step you jog is an extra base for the other team."],
      rates:[85,40,15,10],concept:"On balls down the right field line, angle your approach so you're already facing the infield when you field the ball — it saves a full turn on your throw.",explSimple:["Great choice! Angling toward the line puts your body in position to field the ball and make.","Not the best move. Running straight at the ball means your momentum carries you away from the infield.","Not the best move. Hoping a ball goes foul is never a plan.","Not the best move. Jogging to a live ball in play is unacceptable."], anim:"catch"},
    {id:"rf10", conceptTag:"backup-duties",title:"Backing Up First on a Throw From Third",diff:1,cat:"fielder",ageMin:6,ageMax:99,
      description:"You're the right fielder. The batter hits a slow roller to the third baseman, who bare-hands it and fires a long throw across the diamond to first base. Nobody else is on base. You're playing at normal depth and watching the play develop.",
      situation:{inning:"Top 5",outs:0,count:"0-0",runners:[],score:[2,2]},
      options:["Sprint toward the foul territory behind first base to back up the throw from third","Stay in right field and watch — it's a routine play","Run toward second base in case the batter tries to stretch for a double","Move toward center field to cover more ground"],
      best:0,explanations:["Long throws from third base are the most likely to pull the first baseman off the bag or skip past him, because backing up first base on throws from the left side of the infield is one of your most important responsibilities as a right fielder.","A throw from deep behind third base is 130+ feet across the diamond, since that's a long, hard throw that can sail or bounce. If nobody backs it up and it gets past the first baseman, the runner takes second or third for free.","The batter is trying to beat out a grounder to first — he's not going to second unless there's an error, because your job is to prevent the error from becoming a disaster by backing up first.","Moving toward center leaves first base completely unprotected — an overthrow rolls to the fence and turns a routine groundout into a runner on second or third."],
      rates:[90,25,40,15],concept:"The right fielder must back up first base on throws from the left side of the infield — long throws from third are the most likely to get past the first baseman.",explSimple:["Great choice! Long throws from third base are the most likely to pull the first baseman off.","Not the best move. A throw from deep behind third base is 130+ feet across the diamond.","Not the best move. The batter is trying to beat out a grounder to first — he's not going.","Not the best move. Moving toward center leaves first base completely unprotected."], anim:"advance"},
    {id:"rf11",title:"Cutoff Man or Throw Home Direct",diff:3,cat:"fielder",conceptTag:"cutoff-roles",ageMin:9,ageMax:99,
      description:"You're the right fielder. Bottom of the 8th, one-run game. Runner on second, one out. The batter singles sharply to right field and you charge in to field it cleanly on one hop. The runner from second is rounding third and heading home. You're about 250 feet from home plate. You have a strong arm — you can reach home on the fly from 250 feet, but it won't be your most accurate throw. The first baseman has lined up as the cutoff man at about 130 feet from you.",
      situation:{inning:"Bot 8",outs:1,count:"2-1",runners:[2],score:[4,3]},
      options:["Throw home directly — your arm is strong enough and this is a do-or-die situation","Hit the cutoff man with a chest-high throw so he can relay it home or redirect","Throw to second base to keep the batter from advancing into scoring position","Hold the ball and concede the run since the runner has too big a head start"],
      best:1,explanations:["Your arm CAN reach home, but a 250-foot throw under pressure is likely to tail, bounce, or miss the catcher entirely, which means if it gets past the catcher, the batter takes second or third. One bad throw costs you more than the run.","Hitting the cutoff man with a strong, accurate throw gives your team the best chance, because the relay can reach home faster and more accurately than your long throw, and the cutoff man can redirect if the play at home is too late. This keeps all options alive.","Throwing to second concedes the tying run without a fight, since in a one-run game with one out, you have to at least try to get the runner at home.","Conceding the run without making a throw lets the other team tie the game for free, because you fielded the ball cleanly — make a play. A throw to the cutoff man at least puts pressure on the runner."],
      rates:[35,82,20,15],concept:"In pressure situations, hitting the cutoff man is smarter than a hero throw — accurate relay throws beat long, risky heaves to the plate.",anim:"throwHome"},
    {id:"rf12", conceptTag:"of-depth-arm-value",title:"Fly Ball With Wind Blowing In",diff:2,cat:"fielder",ageMin:9,ageMax:99,
      description:"You're the right fielder. A high fly ball is hit to medium-deep right field. Before the game, your coach told you the wind is blowing straight in from right field at about 15 mph. The ball looks like a routine fly at first, but you can see it starting to hang in the air and slow down. There's a runner on third with one out.",
      situation:{inning:"Top 6",outs:1,count:"0-2",runners:[3],score:[3,2]},
      options:["Play it where you think it was hit and wait for the ball to come down to you","Take a few steps IN from where the ball was hit because the wind will knock it down short","Drift BACK a few steps because wind can be tricky and you don't want it over your head","Charge in hard and try to make a diving catch"],
      best:1,explanations:["Wind blowing in at 15 mph can knock 20-30 feet off a fly ball. If you stay where the ball was originally hit, it will drop in front of you for a hit. You have to adjust your positioning to where the ball will actually land.","Exactly right! Wind blowing in will hold the ball up and push it back toward the infield — take a few steps in so the ball comes down to you instead of dropping in front of you. Read the wind and adjust.","Drifting back when the wind is blowing IN is the worst adjustment, which means the wind pushes the ball TOWARD you, not away. Going back means the ball falls 30 feet in front of you.","Charging in hard and diving is reckless when you can simply take a few calm steps in and catch the ball at your chest, because diving creates a chance for the ball to get past you and the runner on third to score."],
      rates:[30,85,15,35],concept:"When the wind blows in, fly balls lose distance — adjust your positioning a few steps toward the infield to catch the ball where it actually lands.",explSimple:["Wind blowing in at 15 mph can knock 20-30 feet off a fly ball.","Wind blowing in will hold the ball up and push it back toward the infield.","Drifting back when the wind is blowing IN is the worst adjustment.","Charging in hard and diving is reckless when you can simply take a few calm steps in and catch the ball at your chest."],anim:"catch"},
    {id:"rf13", conceptTag:"cutoff-roles",title:"Cut Off the Extra Base to the Gap",diff:2,cat:"fielder",ageMin:9,ageMax:99,
      description:"You're the right fielder. The batter drives a hard line drive into the right-center field gap. The ball splits the gap and is rolling to the wall. A runner on first is sprinting hard. The center fielder also chases the ball but you're closer. If you get to the ball quickly, you might hold the runner to third instead of letting him score.",
      situation:{inning:"Top 4",outs:0,count:"1-1",runners:[1],score:[0,0]},
      options:["Sprint to the ball at full speed, pick it up, and fire to the cutoff man lined up between you and third base","Let the center fielder handle it since gap balls are usually the center fielder's responsibility","Jog to the ball since the extra base is already given up","Sprint to the ball, pick it up, and throw directly home to try to get the runner"],
      best:0,explanations:["Getting to the ball fast and hitting your cutoff man is the smart play, since the cutoff man can relay to third to hold the runner or redirect home. Your urgency to the ball saves the extra base — every second counts.","The ball is closer to you than the center fielder, because when you're closer, the ball is YOURS regardless of who normally covers the gap. Waiting for the center fielder wastes precious seconds.","Jogging to any ball in play is never acceptable. The runner is sprinting at full speed — if you jog, he scores standing up. Hustle to the ball and you might hold him at third.","Throwing directly home from deep right-center is an extremely long throw — even with a strong arm, the ball bounces multiple times and arrives too late. Hitting the cutoff man gets the ball to the right base faster."],
      rates:[82,25,10,30],concept:"On gap hits, the closest outfielder sprints to the ball and hits the cutoff man — urgency prevents extra bases and keeps runners from scoring.",explSimple:["Getting to the ball fast and hitting your helper in the middle is the smart play.","The ball is closer to you than the center fielder.","Jogging to any ball in play is never acceptable.","Throwing directly home from deep right-center is an extremely long throw."],anim:"throwHome"},
    {id:"rf14", conceptTag:"tag-up",title:"Charge the Shallow Fly for the Throw",diff:3,cat:"fielder",ageMin:12,ageMax:99,
      description:"You're the right fielder. Top of the 9th, runner on third, one out, tied game. The batter lofts a shallow fly ball to medium-right field — deep enough that the runner on third will tag up. You're charging in and you know this will be close. If you catch it, the runner will tag and try to score the winning run. You need to decide how to position your body WHILE catching the ball.",
      situation:{inning:"Top 9",outs:1,count:"1-1",runners:[3],score:[4,4]},
      options:["Catch the ball on your glove side while running in, crow-hop, and fire home in one motion","Drift under the ball and catch it standing still to make sure you don't drop it, then throw","Charge in and catch it on the run, but immediately throw to the cutoff man instead of home","Let the ball drop on purpose so the runner can't tag up — play it on the bounce instead"],
      best:0,explanations:["This is the elite outfield play! Catching on your glove side while moving forward gives you momentum toward home, which means the crow-hop transfers that momentum into your throw. You catch AND throw in one fluid motion, giving the runner the least possible time.","Stopping to catch the ball kills your momentum, because you'll be throwing from a standstill, which gives the runner an extra two seconds to tag and score. In a tie game with the winning run, those seconds are everything.","The cutoff man adds a relay step that eats precious time, since on a shallow fly ball, you're close enough to throw home directly. The relay is for deep flies when you can't reach home — not for shallow catches.","Letting a catchable fly ball drop intentionally is risky, because the ball could take a bad hop, roll past you, or you might bobble it. You also give up a guaranteed out. A caught fly ball with a throw home gives you two chances for an out."],
      rates:[82,40,30,15],concept:"On shallow sacrifice fly attempts, catch the ball on the move with momentum toward home — the crow-hop throw gives the runner the least time to tag and score.",anim:"throwHome"},
    // ============================================================================
    // OUTFIELD EXPANSION — Right Field advanced scenarios
    // ============================================================================
    {id:"rf15",title:"Throwing on the Run vs. Setting Your Feet",diff:2,cat:"fielder",conceptTag:"of-depth-arm-value",ageMin:10,ageMax:99,
      description:"You're the right fielder. Bottom of the 6th, runner on first, one out, you're up by one run. The batter slaps a clean single into right field. The runner on first is rounding second hard and trying to take third. You field the ball cleanly on your glove side while moving forward. Do you throw on the run or plant and set your feet?",
      situation:{inning:"Bot 6",outs:1,count:"2-1",runners:[1],score:[3,2]},
      options:["Field it and throw on the run to third — don't let the runner get there","Plant your back foot, crow-hop, and make a strong overhand throw to third","Throw to the cutoff man and let him decide whether to relay to third","Hold the ball — the runner will probably stop at second anyway"],
      best:1,explanations:["Throwing on the run from right field sacrifices accuracy — the throw to third is one of the longest in the outfield and requires precision. An offline throw lets the runner advance or even score.","Correct! From right field, the throw to third base is long and must be accurate, which means planting your back foot and crow-hopping generates maximum arm strength and accuracy. The extra half-second to set up is worth the accurate throw.","The cutoff is for deep flies when you can’t reach the base, because on a single fielded cleanly, you have a direct throw to third. Using the cutoff adds relay time the runner will exploit.","Never assume a runner will stop! Holding the ball with a runner in motion is how runs score, since always make the throw and force the runner to earn the base."],
      rates:[45,82,50,20],concept:"Right fielders must set their feet for the long throw to third — accuracy beats speed on this distance.",explSimple:["Throwing on the run from right field sacrifices accuracy.","From right field, the throw to third base is long and must be accurate.","The cutoff is for deep flies when you can\’t reach the base.","Never assume a runner will stop!"],anim:"throwHome"},
    {id:"rf16",title:"Corner Carom — Ball Off the Right-Field Wall",diff:3,cat:"fielder",conceptTag:"of-depth-arm-value",ageMin:12,ageMax:99,
      description:"You're the right fielder. Top of the 4th, no one on, nobody out. The batter drives a line drive that hits the right-field wall at an angle, about 15 feet from the corner. The ball is going to carom off the wall. You need to read the angle to position yourself for the fastest play.",
      situation:{inning:"Top 4",outs:0,count:"0-1",runners:[],score:[2,2]},
      options:["Run straight to where the ball hit the wall and wait for it to bounce back","Angle toward the foul line — the ball will kick toward the corner","Stay where you are and react after the ball bounces","Sprint to the wall and try to play it off the wall on the fly"],
      best:1,explanations:["Running straight to the impact point means you'll be behind the ball after it caroms, because a line drive hitting the wall at an angle kicks toward the foul line, not straight back. You'll have to chase it.","Correct! When a ball hits the outfield wall at an angle, it caroms toward the foul line like a billiard ball. By angling toward the corner, you meet the ball where it's going, not where it was. This saves two or three steps and keeps the batter to a double instead of a triple.","Waiting to react gives the batter extra bases, since wall caroms are predictable — angle of incidence equals angle of reflection. Read it early, move early, keep the damage to a double.","Playing a line drive off the wall on the fly is extremely risky. If you misjudge the timing, the ball gets past you and rolls to the corner for a triple or inside-the-park home run."],
      rates:[35,80,25,15],concept:"Read wall caroms like a billiard ball — the angle of incidence predicts where the ball will kick. Move to where it's going, not where it hit.",anim:"catch"},
    {id:"rf17",title:"Do-or-Die — Runner Tagging from Second on a Fly",diff:3,cat:"fielder",conceptTag:"of-depth-arm-value",ageMin:12,ageMax:99,
      description:"You're the right fielder. Bottom of the 8th, runner on second, one out, tied game. The batter hits a medium-depth fly ball to right-center. You're going to catch it, but the runner on second is going to tag up and try to advance to third. If he gets to third, a sacrifice fly scores the winning run. Your arm is above average. How do you play this?",
      situation:{inning:"Bot 8",outs:1,count:"1-2",runners:[2],score:[3,3]},
      options:["Catch it and throw to third to try to get the tagging runner","Secure it and relay to the cutoff man at shortstop","Catch it and immediately fire home to prevent the run","Hold the ball — don't risk an overthrow"],
      best:0,explanations:["Correct! With one out and a runner tagging from second, you MUST try to throw him out at third. If he reaches third, the next batter just needs a fly ball to win the game. This is a do-or-die moment — throw to third with everything you've got. Your above-average arm makes this play.","The cutoff relay adds time and the runner will beat the throw to third, which means on a medium-depth fly, you're close enough for a direct throw. Cutoffs are for deep flies.","The runner is going to third, not home, because you throwing home has no purpose here — you'd be throwing to a base where nothing is happening while the runner takes third for free. Firing home immediately won't prevent anything.","Holding the ball after the catch risks an overthrow of nothing and concedes third base, since with one out in a tie game, a runner on third scores on a fly ball, groundout, wild pitch, passed ball, or balk. You must try to keep him at second."],
      rates:[78,45,15,20],concept:"When a runner tags from second to third with one out in a close game, the right fielder MUST challenge the throw — third base with one out is nearly automatic scoring position.",anim:"throwHome"},
    {id:"rf18",title:"Reading the Runner's Commitment — Bluff or Go?",diff:2,cat:"fielder",conceptTag:"of-depth-arm-value",ageMin:10,ageMax:99,
      description:"You're the right fielder. Top of the 7th, runner on first, nobody out, up by two. The batter lines a single to right field. You field it cleanly and look up. The runner who was on first has rounded second base aggressively — he's about a third of the way to third. He could be bluffing to draw a throw, or he could be committed to taking third. How do you read this?",
      situation:{inning:"Top 7",outs:0,count:"1-0",runners:[1],score:[5,3]},
      options:["Throw to third immediately — he's going!","Throw to second base to keep the batter at first","Pump-fake toward third, then throw to second if the runner retreats","Hold the ball and run it toward the infield, watching the runner"],
      best:2,explanations:["If the runner is bluffing, you've thrown behind him and the ball could get past third base, letting him score, because a committed throw to a base where the runner isn't going is a free advance for everyone.","Throwing to second ignores the lead runner entirely — yes, it keeps the batter at first, but you've given the lead runner a free look at third without any consequences.","Smart play! The pump-fake forces the runner to commit, which means if he keeps going to third, you throw there. If he stops or retreats, you throw to second to keep the batter at first. You've used deception to read his intention without risking an error.","Walking the ball in is too passive, because the runner will read your hesitation and take third easily. Outfielders must be decisive — make the runner react to YOU, not the other way around."],
      rates:[40,45,80,25],concept:"Use the pump-fake to read a runner's commitment before throwing. Force THEM to react to you — a rushed throw to the wrong base is worse than no throw at all.",explSimple:["If the runner is bluffing, you've thrown behind him and the ball could get past third base, letting him score.","Throwing to second ignores the lead runner entirely.","The pump-fake forces the runner to commit.","Walking the ball in is too passive."],anim:"throwHome"},
    {id:"rf19",conceptTag:"relay-double-cut",title:"Trail Man on a Right-Side Double Relay",diff:2,cat:"fielder",ageMin:9,ageMax:99,
      description:"You're the right fielder. A ball is hit deep into the right-center gap. The center fielder chases it down near the wall. The second baseman runs out as the lead relay man. Where should you position yourself?",
      situation:{inning:"Top 6",outs:0,count:"0-0",runners:[1],score:[1,2]},
      options:["Line up behind the second baseman as the trail man in the double relay","Run to back up the center fielder at the wall","Stay in your normal right field position","Run toward first base to cover it"],
      best:0,explanations:["On deep hits to right-center, the right fielder becomes the trail man in the double relay. The second baseman goes out as the lead relay man, and you line up behind him. If the lead relay man's throw is off-target, you catch it and redirect. Two relay men give you backup and better accuracy on long throws.","Backing up the center fielder at the wall means two outfielders are in the same spot and nobody is positioned for the relay, since the CF will field it — your job is to be part of the relay chain.","Staying in your normal position leaves the relay system short-handed, because on deep hits to the gap, the outfield relay requires TWO relay men for the long throw home.","First base is the first baseman's responsibility, since your job on a deep gap hit is the double relay. Cover positions in the relay chain, not infield positions."],
      rates:[90,40,15,25],concept:"On deep hits to right-center, the right fielder becomes the trail man in the double relay — line up behind the lead relay man for backup.",explSimple:["Line up behind the relay man. You're the backup in the double relay!","Two outfielders at the wall is bad — you need to be in the relay chain.","Staying in your spot leaves the relay system short-handed.","First base is the first baseman's job. Your job is the double relay."],anim:"throwHome"},
    {id:"rf20",conceptTag:"fly-ball-priority",title:"Shallow Fly — Charging In",diff:1,cat:"fielder",ageMin:6,ageMax:99,
      description:"You're the right fielder. A soft fly ball is dropping into shallow right field. The second baseman runs back toward the ball, but you're charging in and can see the ball clearly in front of you. What do you do?",
      situation:{inning:"Top 3",outs:1,count:"0-0",runners:[],score:[0,0]},
      options:["Call 'I got it!' loud and early — you have the better angle coming in","Let the second baseman take it since he's closer to the infield","Stay quiet and let whoever gets there first catch it","Pull up and wave the second baseman to take it"],
      best:0,explanations:["You're running forward with the ball in front of you the whole way. The second baseman is running backward and can barely see the ball over his shoulder. Outfielders have priority on shallow flies because coming in is always easier than running out — your better angle makes this your play. Call it loud and early!","The second baseman is running with his back to the ball, which makes catching much harder, which means even though he's 'closer to the infield,' your forward momentum gives you a much better angle and a safer catch.","Staying quiet while whoever gets there first tries to catch it is the most dangerous play in baseball, because collisions between converging fielders cause serious injuries. Always call for it.","Your forward angle is a big advantage, since don't give it up by pulling back. Call for the ball and make the catch."],
      rates:[90,40,15,25],concept:"Outfielders running in always have priority over infielders running out — call it loud and early.",explSimple:["You're running forward and can see the ball easily. Call for it!","The second baseman is running backwards, which is way harder.","Never go for a ball without calling for it. You might crash!","Don't pull up — your angle is better. Call for the ball!"],anim:"catch"},
    {id:"rf21",conceptTag:"of-communication",title:"Ball in the Right-Center Gap",diff:2,cat:"fielder",ageMin:9,ageMax:99,
      description:"You're the right fielder. A deep fly ball is hit into the right-center gap. You and the center fielder are both running hard. The center fielder calls 'Mine!' What should you do?",
      situation:{inning:"Bot 3",outs:1,count:"0-0",runners:[1],score:[2,2]},
      options:["Peel off and get into backup position behind the center fielder","Keep running — you might be able to catch it if CF can't","Call 'No, mine!' — you're closer and have a better angle","Slow down but stay right next to the center fielder in case he drops it"],
      best:0,explanations:["When the center fielder calls for a ball, you peel off immediately and get into backup position. CF is the outfield captain and has priority in the gaps. Your new job is to be behind CF in case the ball gets past — this prevents a triple or inside-the-park home run.","Keep running and you might catch it, but you also create a collision risk, because when CF calls for it, trust your teammate and get out of the way. CF has the better angle and the authority to make this call.","Never override the center fielder in the gaps. Even if you think you're closer with a better angle, CF has priority by positioning and by the communication rules of outfield play. Overriding creates confusion and collisions.","Staying right next to CF is just as dangerous as both going for it — peel off and get BEHIND CF in backup position, not beside him."],
      rates:[90,40,15,25],concept:"When the center fielder calls for a ball in the gap, peel off and get into backup position behind CF to prevent extra bases.",explSimple:["Peel off and back up the center fielder. CF is the boss in the gaps!","Keep running and you might crash into the center fielder.","Never override the center fielder's call in the gaps.","Don't stay next to CF — get behind him for backup."],anim:"catch"},
    {id:"rf22",conceptTag:"of-depth-arm-value",title:"Corner Carom Off the Right Field Wall",diff:2,cat:"fielder",ageMin:9,ageMax:99,
      description:"You're the right fielder. A ball hits the wall in the right field corner and caroms off at a sharp angle toward center field. Runner on first is trying to go to third. You're 15 feet from the wall chasing the ball. What's your play?",
      situation:{inning:"Top 4",outs:1,count:"0-0",runners:[1],score:[0,1]},
      options:["Cut off the carom — get your body between the ball and center field, then hit the relay man","Let it bounce and chase it toward center field","Wait for the center fielder to back you up and field it","Throw the ball quickly to third base bare-handed"],
      best:0,explanations:["Cutting off the carom is the right play. Get your body between the ball and the direction it's bouncing to contain it. Then field it cleanly and hit the relay man (usually the second baseman or shortstop) for a quick throw to third. Wall play is about containment first, then the relay.","Chasing the ball toward center field means you're running away from the infield, which means you'll lose precious time, and your throwing angle gets worse with every step toward center.","Waiting for the center fielder costs time, because it's YOUR ball in the right field corner. The center fielder should be in backup position behind you, not fielding for you.","Bare-handing a carom is unreliable — wall caroms are unpredictable and hard to handle cleanly, since you use your glove, field it properly, then make an accurate throw to the relay man."],
      rates:[90,40,25,15],concept:"On wall caroms in the corner, contain the ball by getting your body between it and center field, then hit the relay man.",explSimple:["Cut off the carom and throw to the relay man. Don't let the ball get further away!","Chasing toward center means you're running away from the infield.","It's your ball in the corner. Don't wait for the center fielder.","Bare-handing a wall carom is too risky. Use your glove!"],anim:"throwHome"},
    {id:"rf23",conceptTag:"tag-up",title:"Deep Sacrifice Fly — Relay Home",diff:3,cat:"fielder",ageMin:12,ageMax:99,
      description:"You're the right fielder. Runner on third, one out, tie game in the 8th. A deep fly ball is hit down the right field line. You catch it at the warning track, 330 feet from home. The runner tags and is flying home. Your cutoff man (first baseman) is lined up. Do you throw through the cutoff or hit him?",
      situation:{inning:"Bot 8",outs:1,count:"0-0",runners:[3],score:[4,4]},
      options:["Throw directly home — the game is on the line","Hit the cutoff man with a strong throw and let him relay home","Pump-fake to freeze the runner, then throw home","Hold the ball — you can't throw 330 feet accurately"],
      best:1,explanations:["From 330 feet down the right field line, a direct throw home is almost impossible to get there accurately, because even MLB right fielders use the relay from this distance. An offline throw bounces past the catcher and lets the batter advance to second or third.","Hitting the cutoff man is the right call even with the game on the line. The first baseman is set up 150 feet from you and 150 feet from home. Two strong, accurate throws beat one wild one. The cutoff man can let it through if it's perfect or redirect if needed.","The runner on a tag-up is already committed, since pump-faking wastes a full second of throwing time — on a deep sac fly, every fraction of a second matters. Get the ball to the relay immediately.","The game is tied in the 8th — you can never just hold the ball, which means the cutoff relay system gives you a real chance. Hit the cutoff man and let the relay do its job."],
      rates:[25,85,30,10],concept:"Even in critical moments, hit the cutoff man from deep in the corner — the relay system is more reliable than a 330-foot throw.",explSimple:["330 feet is too far for an accurate throw. Use the cutoff man!","Hit the cutoff man with a strong throw. Two accurate throws beat one wild one.","Don't pump-fake on a tag-up — the runner is already going. Throw now!","The game is tied. You can't hold the ball. Hit the cutoff man!"],anim:"throwHome"},
    {id:"rf_ba1",conceptTag:"backup-awareness",title:"Backing Up First Base on a Grounder",diff:1,cat:"positioning",ageMin:8,ageMax:99,
      description:"You're the right fielder. The batter hits a ground ball to the shortstop, who fields it cleanly and throws to first base. Where should you be?",
      situation:{inning:"Top 2",outs:0,count:"0-0",runners:[],score:[0,0]},
      options:["Stay in your normal right field position and watch the play","Sprint toward first base to back up the throw from shortstop","Run toward second base in case the runner tries to advance","Move toward the right field line"],
      best:1,explanations:["Staying in right field during an infield grounder means nobody is backing up first base. If the throw from shortstop sails past the first baseman, the ball rolls into foul territory and the batter ends up on second or third.","On every ground ball to the infield, the right fielder sprints toward foul territory behind first base. If the throw is accurate, you just jog back to position. If it's wild, you're there to stop the ball and prevent extra bases. This is one of the most important habits in the outfield — back up first on every single grounder.","Second base isn't your responsibility on a routine grounder to shortstop. The middle infielders handle second base coverage. Your backup duty is at first base.","The right field line has nothing to do with this play. The throw is going to first base, and that's where you need to back up."],
      explSimple:["Staying in right field means nobody is behind first base if the throw is bad.","Run behind first base on every grounder! If the throw is wild, you stop the ball!","Second base isn't your job on this play. Back up first base instead.","The right field line doesn't matter here. Back up first base!"],
      rates:[25,80,40,25],concept:"Right fielders back up first base on every infield grounder — if the throw gets past the first baseman, you're the last line of defense",anim:"groundout"},
    {id:"rf_wl1",title:"Wall Play — Warning Track Fly Ball in Right",diff:2,cat:"outfield",conceptTag:"of-wall-play",ageMin:11,ageMax:99,
      description:"You're the right fielder. A deep fly ball is hit down the right field line. As you track the ball on the run, you feel the warning track dirt under your feet. The ball is still in the air and catchable, but you're close to the wall. How do you handle it?",
      situation:{inning:"Bot 5",outs:2,count:"1-2",runners:[1,3],score:[3,3]},
      options:["Reach your glove hand up to find the wall, then look back at the ball and make the catch","Keep running full speed and try to catch the ball before you hit the wall","Stop on the warning track and wait for the ball to come down to you","Turn your back to the ball and run to the wall first, then turn around"],
      best:0,explanations:["When you feel the warning track, reach your non-glove hand back to find the wall while keeping your eyes on the ball. Your hand tells you exactly how far the wall is so you can position yourself safely. Once you've located the wall, you can set your feet and make the catch with confidence. The warning track is your alarm clock — it tells you to find the wall with your hand, not your body.","Running full speed into the wall is how outfielders get hurt. The warning track exists specifically to tell you the wall is close. When you feel the dirt, your priority shifts from tracking the ball to knowing where the wall is. A collision at full speed can end your season.","Stopping on the warning track might work on some balls, but if this one is still drifting toward the wall, you'll watch it go over your head for a home run or bounce off the wall behind you. Keep moving, but use your hand to find the wall so you can adjust your position safely.","Turning your back to the ball means you lose track of it completely. Relocating a fly ball after looking away is extremely difficult, and you'll likely misjudge the catch. Keep your eyes on the ball and use your hand to find the wall."],
      rates:[82,20,35,28],concept:"On the warning track, reach your non-glove hand back to find the wall while keeping your eyes on the ball — let your hand tell you where the wall is, not your body",explSimple:["Feel the warning track? Reach your hand back to find the wall. Eyes stay on the ball!","Running full speed into the wall is dangerous. Use the warning track to slow down.","Stopping might let the ball drift over your head. Keep moving, but find the wall.","Turning your back to the ball means you'll lose it. Keep your eyes up!"],anim:"catch"},
  ],
  thirdBase: [
    {id:"f6", conceptTag:"bunt-defense",title:"Bunt Against the Shift",diff:3,cat:"positioning",ageMin:12,ageMax:99,
      description:"You're 3B, shifted right vs a lefty pull hitter. He squares to bunt down the 3B line!",
      situation:{inning:"Top 3",outs:0,count:"1-0",runners:[1],score:[0,0]},
      options:["Sprint back to 3B position","Stay in the shift","Yell for the pitcher","Charge from where you are"],
      best:0,explanations:["React and get back! Remember, don't let a bunt beat the shift.","Staying in the shift with a bunt coming gives a free base hit.","The pitcher has limited range on bunts down the line — you need to get there yourself.","Charging from the wrong side — you won't get there."],
      rates:[80,10,30,25],concept:"Always adjust positioning when the batter shows bunt",anim:"catch"},
    {id:"f8", conceptTag:"bunt-defense",title:"Wheel Play",diff:3,cat:"plays",ageMin:12,ageMax:99,
      description:"You're 3B. Runner on 1st, 0 outs. Batter bunts. Coach called a wheel play — SS covers 3rd.",
      situation:{inning:"Top 4",outs:0,count:"0-0",runners:[1],score:[1,0]},
      options:["Charge hard (no plan)","Hold position","Charge, throw to 1st","Charge, spin-throw to 3rd"],
      best:3,explanations:["Charging without a throw target wastes time — at third base on a wheel play, you need to know where you are throwing before you pick up the ball.","Holding lets the bunt die and gives the batter a free base — you have to charge on bunt defense.","1st gets 1 out but lead runner advances to scoring position.","On a wheel play, charge and throw to 3rd — getting the lead runner is worth more."],
      rates:[20,15,50,85],concept:"On bunt defense, getting the lead runner is more valuable than the sure out",anim:"throwHome"},
    {id:"f15", conceptTag:"force-vs-tag",title:"Runner on Second — Check Before Throwing",diff:1,cat:"infield",ageMin:6,ageMax:99,
      description:"Top of the 5th, runner on 2nd, 1 out, down 2-1. You're the third baseman. Ground ball hit to you. But the runner on 2nd is edging toward third.",
      situation:{inning:"Top 5",outs:1,count:"0-0",runners:[2],score:[1,2]},
      options:["Fire across the diamond without checking the runners","Throw to third to tag the runner","Glance at the runner, then throw to first for the out","Hold the ball and chase the runner"],
      best:2,explanations:["Firing across the diamond without checking the runner could let him advance to third — then he scores on anything.","With only a runner on 2nd, third base is a tag play — someone has to catch the ball and tag the runner. If the runner isn't fully committed, he can retreat to 2nd and you've thrown to an empty bag while the batter reaches first safely.","Smart! Glance at the runner first, which means if he's going, throw to the shortstop covering third. If he's staying, throw to first. This quick look takes half a second but prevents a free base.","Chasing a runner starts a rundown that gives the batter time to reach base, because you make a throw instead."],
      rates:[50,25,85,10],concept:"With a runner on 2nd, look him back before throwing to first — don't give a free base",explSimple:["Not the best move. Throwing to first without checking the runner could let him advance to third — then.","Not the best move. There's no force at third, so you'd need to tag him.","Smart! Glance at the runner first.","Not the best move. Chasing a runner starts a rundown that gives the batter time to reach base."], anim:"groundout"},
    {id:"f19", conceptTag:"infield-positioning",title:"Slow Roller — Eat It or Throw?",diff:1,cat:"infield",ageMin:8,ageMax:99,
      description:"Top of the 8th, nobody on, 2 outs, up 2-1. You're the third baseman. Slow roller — you charge in and barehand it, but he's fast and almost to first.",
      situation:{inning:"Top 8",outs:2,count:"0-0",runners:[],score:[2,1]},
      options:["Throw it anyway — you might get him","Eat the ball — don't risk an overthrow","Flip it underhand to first","Sprint toward first and throw on the run"],
      best:1,explanations:["A rushed throw from deep in the grass is risky because you're off-balance after charging in, which means the throw is likely to sail or bounce. If the batter is almost at first, a wild throw puts him in scoring position and suddenly the tying run is at second or third.","Smart! If you don't have a clean throw, hold the ball because an error with 2 outs and a 1-run lead could let the tying run reach scoring position. A single is much less dangerous than a runner on 2nd or 3rd from an overthrow, since the next batter still has to get a hit to score him.","An underhand flip can work from close range, but from deep in the grass you're too far from first base for it to arrive in time. The flip doesn't have enough velocity to beat the runner, which means you've given up your best option — eating the ball — for a play that's too slow to get the out.","Throwing on the run from deep grass is one of the hardest throws in baseball because your body isn't set and your feet aren't underneath you. If the batter is almost there, the risk isn't worth it since a wild throw turns a harmless single into a potential tying run in scoring position."],
      rates:[25,85,20,30],concept:"If you don't have a clean throw, eat the ball — an error is worse than a single",explSimple:["Not the best move. A rushed throw is risky because you're off-balance after charging in.","Smart! If you don't have a clean throw, hold the ball because an error is worse than a single.","Not the best move. An underhand flip from deep in the grass is too slow to beat the runner to first.","Not the best move. Throwing on the run from deep grass is one of the hardest throws because your feet aren't set."], anim:"safe"},
    {id:"f45", conceptTag:"bunt-defense",title:"Bunt Situation — Where to Move",diff:1,cat:"positioning",ageMin:6,ageMax:99,
      description:"Bot 5th, runner on 1st, nobody out, tied 3-3. The #8 hitter steps up — he's almost certainly going to bunt. You're the third baseman. Where should you play?",
      situation:{inning:"Bot 5",outs:0,count:"0-0",runners:[1],score:[3,3]},
      options:["Charge in aggressively — be ready to field the bunt","Play normal depth — react after the ball is bunted","Halfway in — compromise between bunt and swing","Stay deep and let the pitcher field it"],
      best:0,explanations:["When you KNOW a bunt is coming, charge aggressively as the pitcher delivers. The risk of being caught forward is a tradeoff worth taking when a bunt is certain — the third baseman crashing in on a bunt gives you the best angle to field it and throw to second for the force on the lead runner. Don't wait — attack the bunt.","Playing at normal depth means the bunt dies in the grass before you can reach it, since the runner advances for free and you've turned a potential out into a free base — exactly what the offense wants.","Halfway is better than deep but not as good as a full crash, because when you're confident of the bunt, commit.","The pitcher can field some bunts, but the third baseman crashing has a better angle for the throw to second — that's why this approach matters in this situation."],
      rates:[85,15,45,25],concept:"When you know a bunt is coming, crash in aggressively — field it and throw to second for the force",explSimple:["Great choice! When you KNOW a bunt is coming, charge hard as the pitcher delivers.","Normal depth means the bunt dies before you get to it.","Not the best move. Halfway is better than deep but not as good as a full crash.","Not the best move. The pitcher can field some bunts, but the third baseman crashing has a better angle."], anim:"bunt"},
    {id:"f49", conceptTag:"bunt-defense",title:"No Outs, Known Bunter — Stay or Crash?",diff:3,cat:"positioning",ageMin:12,ageMax:99,
      description:"Bot 4th, runner on 1st, nobody out, tied 2-2. A known bunter steps in. Your first baseman holds the runner. You're the third baseman. How do you play?",
      situation:{inning:"Bot 4",outs:0,count:"0-0",runners:[1],score:[2,2]},
      options:["Crash in on every pitch — be ready for the bunt","Play in but wait to see if he actually shows bunt","Play normal depth — he might slash instead","Crash in but only after the pitcher starts his motion"],
      best:3,explanations:["Crashing on every pitch means you're out of position if he swings away. Be smart about when you crash — timing it with the pitcher's delivery lets you be aggressive without committing too early and leaving a hole.","Waiting to see the bunt show before charging in means you're too late, because by the time you react and start running, the ball is already on the ground. You need to commit early and be in position to field it before the bunt dies in the grass.","Playing normal depth against a known bunter means the bunt dies before you can reach it, because the ball only travels 15-20 feet on a good bunt. You need to be much closer than normal to have any chance at fielding it and getting the lead runner at second.","Crash in as the pitcher starts his delivery, because if the batter shows bunt, you're already charging and can field it quickly to get the lead runner at second. If he pulls the bat back and swings, you're caught in no-man's land — but that's a risk worth taking against a known bunter. Time your crash with the pitch."],
      rates:[40,35,20,85],concept:"Against known bunters, crash in as the pitcher delivers — time your charge with the pitch",anim:"bunt"},
    {id:"f50", conceptTag:"line-guarding",title:"Power Hitter — Deep or Guard the Line?",diff:3,cat:"positioning",ageMin:12,ageMax:99,
      description:"Top of the 9th, nobody on, 2 outs, up 5-4. Their power hitter steps in — he's a right-handed pull hitter. You're the third baseman.",
      situation:{inning:"Top 9",outs:2,count:"0-0",runners:[],score:[5,4]},
      options:["Guard the line — a double down the line extends the inning","Play normal — he might go the other way","Shade toward the hole — most ground balls go to short","Play deep — give yourself more reaction time"],
      best:0,explanations:["In the 9th with a lead and 2 outs, guard the line. A double down the third base line puts the tying run in scoring position. A single through the normal hole keeps him at first — less dangerous. You'd rather give up a single than a double in this situation.","A power hitter who pulls the ball is not likely to go the other way, since you use the data.","Shading toward the hole ignores the line — a double down the line is the most dangerous hit, because the downside outweighs the potential gain.","Playing deep against a power hitter is fine for range, but the LINE is the priority in the 9th."],
      rates:[85,25,30,35],concept:"In the 9th with a lead, guard the line — a double is more dangerous than a single",anim:"catch"},
    {id:"3b1", conceptTag:"bunt-defense",title:"Bunt Charge",diff:1,cat:"fielder",ageMin:6,ageMax:99,
      description:"You're the third baseman. Bottom of the 6th, runner on first, one out. The batter squares to bunt and drops it about 15 feet in front of home plate. The ball is rolling slowly toward you on the grass.",
      situation:{inning:"Bot 6",outs:1,count:"1-0",runners:[1],score:[4,3]},
      options:["Charge hard, field with bare hand, throw to first","Wait for it to come to you and field it with your glove","Charge hard, field with glove, throw to second for the lead runner","Let the catcher handle it and cover third"],
      best:0,explanations:["Charging aggressively and bare-handing the slow roller lets you get rid of the ball quickly, because your momentum is already carrying you toward first base. This is the textbook third baseman play on a bunt since the throw to first is short and in line with your charge.","Waiting lets the batter reach safely because on slow rollers the ball dies in the grass. If you hang back at your normal depth, by the time you field it the runner is already past first.","Throwing to second for the lead runner sounds tempting, but it's risky because after charging forward on a bunt you've lost all momentum toward second base. The throw to second is longer and against your body, which means a higher chance of an error or a late throw that gets nobody out.","The catcher has to come too far out since the ball is 15 feet in front of the plate in the third baseman's zone. If you let it go, the batter reaches easily because nobody else can get there in time."],
      rates:[88,25,40,10],concept:"On bunts, the third baseman charges aggressively and bare-hands when needed to get the out at first.",explSimple:["Great choice! Charging hard and bare-handing the slow roller lets you throw quickly because your momentum is already going toward first.","Not the best move. Waiting lets the batter reach safely since the ball dies in the grass.","Not the best move. Throwing to second is risky because you've charged forward and lost your momentum toward second base.","Not the best move. The catcher has to come too far out — this is clearly in your zone since it's 15 feet from home."], anim:"bunt"},
    {id:"3b2", conceptTag:"infield-positioning",title:"Bare-Hand Roller",diff:2,cat:"fielder",ageMin:9,ageMax:99,
      description:"You're at third base. Top of the 3rd, nobody on, two outs. The batter chops a slow roller that dies on the infield grass about 20 feet from you. It's barely moving and he's fast — he's already halfway to first.",
      situation:{inning:"Top 3",outs:2,count:"0-1",runners:[],score:[1,1]},
      options:["Sprint in, bare-hand the ball, and make a strong throw across the diamond","Run in, field it with your glove, transfer to throwing hand, then throw","Charge in and try to backhand flip it to the shortstop covering","Hold your position and wait for the ball to reach you"],
      best:0,explanations:["With a fast runner and a dying roller, bare-handing lets you skip the glove transfer and fire to first in one motion, which means every split second counts on the long throw across the diamond.","Fielding with the glove adds a transfer step, because on a ball this slow with a fast runner, that extra half-second often means the runner beats the throw.","There's no reason for the shortstop to be involved — the play is to first base, since a flip to short just adds a relay and wastes time.","Waiting means the runner reaches first easily, because on slow rollers at third, you must come get it."],
      rates:[82,50,15,10],concept:"On dying rollers, bare-handing saves the glove transfer time needed to beat fast runners on the long throw to first.",explSimple:["With a fast runner and a dying roller, bare-handing lets you skip the glove transfer and fire to first in one motion.","Fielding with the glove adds a transfer step.","There's no reason for the shortstop to be involved — the play is to first base.","Waiting means the runner reaches first easily."],anim:"groundout"},
    {id:"3b3", conceptTag:"infield-positioning",title:"Long Throw Mechanics",diff:2,cat:"fielder",ageMin:9,ageMax:99,
      description:"You're the third baseman. Bottom of the 4th, one out, bases empty. A hard grounder is hit right at you and you field it cleanly. You're about 120 feet from first base — the longest infield throw on the diamond. The batter runs at average speed.",
      situation:{inning:"Bot 4",outs:1,count:"2-2",runners:[],score:[0,0]},
      options:["Crow-hop toward first to build momentum, then throw overhand with your body behind it","Stand still and rifle it from where you fielded it to save time","Throw sidearm to get it there faster","Lob it high so the first baseman has time to adjust"],
      best:0,explanations:["The crow-hop builds momentum for the long throw across the diamond — using your body and an overhand release gives you accuracy and carry. This is how third basemen are taught to make this throw.","Standing still means you're throwing with only arm strength from 120 feet, which means without body momentum, the throw tails or bounces, and you risk a throwing error.","Sidearm throws from third base tend to tail away from the first baseman, especially on long throws, because save sidearm for short-range plays.","A lob takes too long in the air and gives the runner extra steps, since even average runners will beat a rainbow throw from third."],
      rates:[85,35,30,15],concept:"The crow-hop builds momentum for the long throw across the diamond — your body generates the power, not just your arm.",explSimple:["The crow-hop builds momentum for the long throw across the diamond.","Standing still means you're throwing with only arm strength from 120 feet.","Sidearm throws from third base tend to tail away from the first baseman, especially on long throws.","A lob takes too long in the air and gives the runner extra steps."],anim:"groundout"},
    {id:"3b4",title:"Guard the Line",diff:1,cat:"fielder",conceptTag:"line-guarding",ageMin:9,ageMax:99,
      description:"You're at third base. Top of the 8th, your team leads 3-2. Runner on first, one out. The coach signals you to guard the line. The batter hits left-handed and pulls the ball who has hit two doubles down the line tonight.",
      situation:{inning:"Top 8",outs:1,count:"0-0",runners:[1],score:[3,2]},
      options:["Move two steps closer to the foul line and shade toward the bag","Stay in your normal position — you can react to anything","Cheat toward the shortstop hole to take away the ground ball up the middle","Move in closer to home plate for a potential bunt"],
      best:0,explanations:["In late innings with a lead, preventing extra-base hits is the priority, because shading the line takes away the double down the line from a known pull hitter. Move closer and shade toward the bag — a single through the hole hurts less than a double.","Your normal position leaves the line exposed against a proven pull hitter, since in a close late-inning game, a double could tie or win it for the other team.","Shading toward the middle leaves the line wide open for the left-handed pull hitter, which means you're giving him exactly what he wants.","Moving closer to home plate for a potential bunt makes no sense here, since there's no bunt situation with one out in a one-run game. The hitter is looking to drive the ball."],
      rates:[85,40,20,12],concept:"In late innings with a lead, guard the line to prevent extra-base hits — a single hurts less than a double.",explSimple:["Great choice! In late innings with a lead, preventing extra-base hits is the priority.","Not the best move. Your normal position leaves the line exposed against a proven pull hitter.","Not the best move. Shading toward the middle leaves the line wide open for the left-handed pull hitter.","Not the best move. There's no bunt situation here with one out and a runner on first."], anim:"catch"},
    {id:"3b5", conceptTag:"force-vs-tag",title:"Tag Play at Third",diff:1,cat:"fielder",ageMin:6,ageMax:99,
      description:"You're the third baseman. Bottom of the 5th, runner on second, no outs. The batter hits a single to right field. The runner rounds third hard but the right fielder comes up throwing. You receive the throw right as the runner is sliding back to the bag.",
      situation:{inning:"Bot 5",outs:0,count:"1-1",runners:[2],score:[2,5]},
      options:["Catch the ball and sweep a quick tag down low in front of the bag","Receive the ball and tag the runner on the chest as he slides","Secure the ball, hold it up to show the umpire, then tag","Catch the ball and block the bag with your foot"],
      best:0,explanations:["A quick sweep tag low and in front of the bag is the fastest way to apply the tag on a sliding runner, because you meet him before he reaches the base, giving the umpire a clear look.","Tagging the chest on a sliding runner is awkward — the runner is low to the ground and sliding feet-first, since you're more likely to miss or apply a slow tag.","Holding the ball up wastes precious time, because the runner is sliding NOW — tag first, celebrate later.","Blocking the bag with your foot without the ball in your glove isn't a tag — you could also get hurt in a collision. You need ball-in-glove touching the runner."],
      rates:[88,35,15,10],concept:"On tag plays, sweep the glove low in front of the bag to meet the sliding runner before he reaches the base.",explSimple:["Great choice! A quick sweep tag low and in front of the bag is the fastest way.","Not the best move. Tagging the chest on a sliding runner is awkward — the runner is low.","Not the best move. Holding the ball up wastes precious time.","Not the best move. Blocking the bag with your foot without the ball in your glove isn't a tag."], anim:"catch"},
    {id:"3b6", conceptTag:"force-vs-tag",title:"Hot Corner Rocket",diff:3,cat:"fielder",ageMin:12,ageMax:99,
      description:"You're the third baseman. Top of the 7th, tie game, runners on first and second, one out. The cleanup hitter smashes a one-hop rocket right at you. The ball is hit so hard you barely have time to react. You knock it down but it rolls a few feet to your right.",
      situation:{inning:"Top 7",outs:1,count:"3-1",runners:[1,2],score:[4,4]},
      options:["Pick it up and step on third for the force out","Pick it up and throw to second to start a double play","Pick it up and throw to first for the sure out","Hold the ball — with runners moving you might throw it away"],
      best:0,explanations:["Stepping on third base for the force out is the smart play, which means it's the closest base, you don't need a throw, and you get the lead runner. With two outs, it changes the whole at-bat for the next hitter.","After knocking a ball down and scrambling, a throw to second for a double play is extremely difficult, because you'll likely rush it and throw it into center field.","Throwing to first after a knockdown means a long throw while off-balance, since with runners moving, an error puts the go-ahead run in scoring position or worse.","Holding the ball with bases loaded and one out lets everyone advance safely, because the tying and go-ahead runs both move up. You need to get an out."],
      rates:[82,25,35,12],concept:"After knocking down a hard shot, look for the closest force out — stepping on the bag beats a risky throw every time.",anim:"groundout"},
    {id:"3b7", conceptTag:"fly-ball-priority",title:"Foul Ball Near Dugout",diff:1,cat:"fielder",ageMin:6,ageMax:99,
      description:"You're at third base. Bottom of the 2nd, nobody on, one out. The batter pops up a high foul ball drifting toward the third base dugout. You're tracking it well, but it's carrying closer to the dugout railing. The dugout steps are about three feet away.",
      situation:{inning:"Bot 2",outs:1,count:"1-2",runners:[],score:[0,1]},
      options:["Track the ball but pull up if you get within one step of the dugout — player safety comes first","Sprint full speed, reach over the railing, and try to make the spectacular catch","Call off your teammates and catch it, planting your feet well before the dugout edge","Ignore it and let the catcher handle all foul pops"],
      best:2,explanations:["Pulling up too early gives away a free out — you should know your surroundings and catch the ball as long as you can plant safely before the dugout.","Reaching over the railing is dangerous — you can tumble into the dugout and get seriously injured, which means no single out is worth an injury.","Calling the ball, tracking it, and planting your feet safely while still being far enough from the dugout is the smart play, because you get the out without risking injury.","Foul pops near third base are the third baseman's ball, since the catcher has to spin around and fight his mask. You have a much better angle."],
      rates:[45,15,85,10],concept:"On foul pops, know your surroundings — catch the ball confidently, but never blindly run into the dugout.",explSimple:["Not the best move. Pulling up too early gives away a free out.","Not the best move. Reaching over the railing is dangerous — you can tumble into the dugout.","Great choice! Calling the ball, tracking it, and planting your feet safely while still being far enough.","Not the best move. Foul pops near third base are the third baseman's ball."], anim:"popup"},
    {id:"3b8", conceptTag:"cutoff-roles",title:"Cutoff From Left",diff:3,cat:"fielder",ageMin:12,ageMax:99,
      description:"You're the third baseman. Top of the 9th, your team leads 5-4. Runner on second, one out. The batter singles to left field. The runner rounds third heading home. The left fielder fires it in, and you're the cutoff man positioned between third and home.",
      situation:{inning:"Top 9",outs:1,count:"2-1",runners:[2],score:[5,4]},
      options:["Let the throw go through to the catcher — the play is at home","Cut it off and throw home because the throw is offline","Cut it off and look to get the batter who rounded first too far","Check the runner at home, and if the throw is on line, let it go through; if not, cut and redirect"],
      best:3,explanations:["Automatically letting it go through is risky — if the throw is offline, it gets past the catcher and the tying run scores easily, because you need to read the throw first.","Automatically cutting every throw takes away plays at the plate when the outfielder's throw is right on target — you should read it first.","Looking to get the batter at first sounds smart, but with the tying run heading home in the 9th, the priority is always the lead runner. Letting the batter take second is fine if you get the out at home.","As the cutoff man, your job is to read the throw, which means if it's on line and has a chance, let it through. If it's off target, cut it and redirect to give the catcher a better throw or hold the ball. This is the most advanced cutoff decision."],
      rates:[35,40,20,85],concept:"The cutoff man reads the throw — let accurate throws go through, cut off bad ones and redirect to give your team the best chance.",anim:"throwHome"},
    {id:"3b9", conceptTag:"infield-positioning",title:"Bare-Hand the Slow Roller",diff:2,cat:"fielder",ageMin:9,ageMax:99,
      description:"You're the third baseman. Bottom of the 4th, runner on second, one out. The batter chops a slow roller down the third base line. The ball is dying on the grass about 25 feet from you and barely spinning. He's fast — he's already three steps out of the box. You need to decide how to field this ball and where to throw.",
      situation:{inning:"Bot 4",outs:1,count:"2-1",runners:[2],score:[1,2]},
      options:["Charge hard, bare-hand the ball, and fire to first base in one motion","Charge hard, field it with your glove, transfer to your throwing hand, then throw to first","Charge in but look the runner back to second before throwing to first","Hold your position and wait for the ball to roll closer to you"],
      best:0,explanations:["On a dying roller, bare-handing saves the split second of glove-to-hand transfer, because you scoop it with your throwing hand and fire to first in one seamless motion. With a fast runner, that saved time is the difference between out and safe.","Fielding with your glove is safer for catching, but the transfer from glove to hand takes too long, since on a slow roller with a fast runner, you need every millisecond. The bare hand is the play here.","Looking the runner back is a good instinct, but with one out and a fast batter, you don't have time to check the runner AND throw out the batter, because you get the sure out at first — the runner on second isn't going home on a slow roller to third.","Waiting for a dying roller is a death sentence — the ball is barely moving — it might stop completely before it reaches you. Meanwhile the batter is sprinting to first. Attack the ball!"],
      rates:[82,50,35,10],concept:"On slow rollers, bare-handing eliminates the glove transfer and lets you throw in one continuous motion — every split second counts.",explSimple:["On a dying roller, bare-handing saves the split second of glove-to-hand transfer.","Fielding with your glove is safer for catching, but the transfer from glove to hand takes too long.","Looking the runner back is a good instinct, but with one out and a fast batter, you don't have time to check the runner AND throw out the batter.","Waiting for a dying roller is a death sentence."],anim:"groundout"},
    {id:"3b10",title:"Tag the Runner at Third",diff:1,cat:"fielder",conceptTag:"force-vs-tag",ageMin:6,ageMax:99,
      description:"You're the third baseman. Runner on second, no outs. The batter singles to left field and the runner rounds third hard. The left fielder fires to you at third base and the runner decides to come back. He's sliding into the bag headfirst. You catch the throw and need to apply the tag.",
      situation:{inning:"Top 5",outs:0,count:"0-0",runners:[2],score:[2,3]},
      options:["Catch the ball and sweep your glove down low in front of the bag to tag the runner's hands before they reach the base","Catch the ball and try to tag the runner on the back as he slides","Catch the ball, hold it up for the umpire to see, then apply the tag","Stand on top of the bag and wait for the runner to slide into your feet"],
      best:0,explanations:["On a headfirst slide back to the bag, the runner's hands are reaching for the base, which means sweeping your glove low in front of the bag meets his hands BEFORE they touch the base. This is the textbook tag on a headfirst slide.","Tagging the runner's back on a headfirst slide is difficult because his hands reach the base before his back arrives at the tag point. You need to tag the part of his body that arrives first — his hands.","Showing the ball to the umpire before tagging is a waste of time, because the runner will be safe by the time you finish showing off. Tag first, appeal later if needed.","Standing on the bag blocks the runner's path and could cause a collision or interference call, since you need to let the runner access the base and apply a clean tag."],
      rates:[88,35,15,20],concept:"On headfirst slides, sweep the tag low in front of the bag — meet the runner's hands before they reach the base.",explSimple:["Great choice! On a headfirst slide back to the bag, the runner's hands are reaching for the base.","Not the best move. Tagging the runner's back on a headfirst slide is difficult because his hands reach.","Not the best move. Showing the ball to the umpire before tagging is a waste of time.","Not the best move. Standing on the bag blocks the runner's path and could cause a collision or interference call."], anim:"catch"},
    {id:"3b11",title:"Cut Off the Throw From Left",diff:2,cat:"fielder",conceptTag:"cutoff-roles",ageMin:9,ageMax:99,
      description:"You're the third baseman. Runner on first, one out. The batter doubles into the left field corner. The runner from first is rounding second and heading to third. The left fielder picks up the ball and fires toward home. The shortstop is out as the cutoff man, but the throw is angling toward you near third base. It's coming at you about head height, and you need to decide what to do.",
      situation:{inning:"Bot 6",outs:1,count:"1-2",runners:[1],score:[3,4]},
      options:["Let the throw go through to the catcher — the runner from first might try to score","Catch the throw and immediately tag the runner arriving at third","Cut the throw off and hold the ball — freeze everyone","Listen for the catcher's call — he'll yell 'cut' or 'let it go' based on what he sees"],
      best:3,explanations:["Automatically letting the throw go through could be wrong, because if the runner stops at third, the throw sails past the catcher for nothing and the batter advances.","Immediately tagging the runner at third could work, but you don't know where all the runners are while facing the outfield — you might miss a better play — like a throw home to get the lead runner.","Cutting it off and holding the ball is passive — you might freeze a runner, but you also give up the chance to throw someone out. Without listening for the catcher's direction, you don't know if there's a play at home or another base.","The catcher can see the entire field — he is watching every runner while you face the outfield. On any throw coming toward the infield, react to the catcher's call: 'CUT' means catch it and redirect, silence means let it through. The catcher commands all relay plays because he has the only unobstructed view of the whole field."],
      rates:[35,40,30,82],concept:"On cutoff plays, listen to your catcher — he sees the whole field and will tell you to cut or let it through based on where the runners are.",explSimple:["Automatically letting the throw go through could be wrong.","Tagging the runner at third could work, but you don't know where all the runners are while facing the outfield.","Cutting and holding is safe but passive — you give up the chance to make a play.","The catcher can see the entire field — he's watching every runner while you face the outfield."],anim:"throwHome"},
    {id:"3b12", conceptTag:"bunt-defense",title:"Bunt Defense — Charge and Throw",diff:1,cat:"fielder",ageMin:6,ageMax:99,
      description:"You're the third baseman. Bottom of the 3rd, runner on first, no outs. The batter squares to bunt and pushes it toward the left side — the ball rolls about 20 feet up the third base line. The ball has some pace on it and is rolling right toward you as you charge in. The second baseman covers first.",
      situation:{inning:"Bot 3",outs:0,count:"0-0",runners:[1],score:[0,1]},
      options:["Charge in, field it with your bare hand, and throw to first for the sure out","Charge in, field it with your bare hand, and throw to second to get the lead runner","Let the ball come to you at your normal depth, then decide your play","Charge in, pick it up, and run toward first base to make a shorter throw"],
      best:0,explanations:["Charge aggressively, bare-hand the rolling ball, and fire to first for the guaranteed out, because the bunt has pace on it so you'll be close enough for a strong throw. Getting the sure out is the smart play on bunt defense.","Throwing to second for the lead runner sounds great, but after charging forward on a bunt, your momentum is going the wrong way for a throw to second, since it's a much harder throw and you risk throwing it away.","Waiting at normal depth gives the batter too much time to reach base, because on bunt defense, you must charge in aggressively to have any chance of making the play.","Running toward first base wastes time and makes your throw awkward — a strong throw from where you field the ball is faster than jogging closer and then throwing. Use your arm, not your legs."],
      rates:[85,35,15,25],concept:"On bunt plays, charge aggressively and throw to first for the sure out — don't try for the lead runner when your momentum is going the wrong way.",explSimple:["Great choice! Charge hard, bare-hand the rolling ball, and fire to first for the guaranteed out.","Not the best move. Throwing to second for the lead runner sounds great, but after charging forward on.","Not the best move. Waiting for the ball at normal depth gives the batter too much time to reach first.","Not the best move. Running toward first base wastes time and makes your throw awkward."], anim:"bunt"},
    {id:"3b13", conceptTag:"infield-positioning",title:"Hot Corner Line Drive",diff:3,cat:"fielder",ageMin:12,ageMax:99,
      description:"You're the third baseman. Top of the 8th, one-run game. A right-handed power hitter smashes a screaming line drive right at you, about chest high. The ball is on you in less than a second — there's almost no time to think. You're playing at normal depth, about 90 feet from home plate. Your reflexes take over.",
      situation:{inning:"Top 8",outs:0,count:"1-0",runners:[1,2],score:[5,4]},
      options:["React with your glove — keep your glove open, centered on your body, and try to snare it","Duck out of the way — self-preservation comes first on a ball hit that hard","Knock the ball down with your body to keep it in front of you, then pick it up and throw","Try to backhand it since the ball is slightly to your glove side"],
      best:0,explanations:["On a screaming liner, keeping your glove centered and open gives you the biggest target, which means you react with soft hands and let the ball hit the glove rather than stabbing at it. At 90 feet, you have just enough time to react if your glove is ready.","Ducking gives the batter a free hit and runners advance, because third basemen are taught to keep their glove in front of their body on every pitch. The 'hot corner' requires courage — you'll face hard-hit balls regularly.","Intentionally using your body to block a line drive is painful and unnecessary when you can use your glove, since your glove is designed to catch the ball — your chest is not. Plus a body block might deflect the ball away and you can't make a throw.","A backhand on a ball coming at 100+ mph gives you less glove surface and less control, because center your glove in front of your body with the pocket open — maximum catching area for maximum reaction time."],
      rates:[80,10,40,30],concept:"At the hot corner, keep your glove centered and ready on every pitch — react with soft hands and let the ball hit the glove rather than stabbing at it.",anim:"catch"},
    {id:"3b14", conceptTag:"steal-window",title:"Cover Third on a Steal From Second",diff:2,cat:"fielder",ageMin:9,ageMax:99,
      description:"You're the third baseman. Runner on second, one out, and the runner has been taking aggressive leads all game. The pitcher works from the stretch. As the pitcher starts his delivery, you see the runner from second break toward third base — he's stealing! The shortstop yells 'He's going!' The catcher catches the pitch and fires a throw to third.",
      situation:{inning:"Top 7",outs:1,count:"1-1",runners:[2],score:[2,1]},
      options:["Sprint to third base, straddle the bag, and catch the throw with your glove ready to sweep a tag on the runner's feet","Stay in your fielding position because the shortstop should cover third on steals of third","Run toward the runner to cut down the throwing distance for the catcher","Move behind third base to back up the throw in case it's off target"],
      best:0,explanations:["When a runner steals third, the third baseman covers the bag — sprint to third, straddle it so the runner has access to the base, and catch the catcher's throw with your glove sweeping down to tag the runner's feet as he slides in.","The shortstop does NOT cover third on steals — that's the third baseman's responsibility, which means the shortstop covers second base on steal situations. Third base is your bag, and you need to be there when the ball arrives.","Running toward the runner leaves third base uncovered. The catcher is throwing to the BASE, not to you in the middle of the baseline. If you're not on the bag, the throw has nowhere to go.","Moving behind third means the catcher's throw has to go past the bag and reach you deeper, because that's a longer throw and gives the runner more time to reach the base safely. Be on the bag, not behind it."],
      rates:[85,20,40,25],concept:"On steals of third, the third baseman covers the bag — straddle it, catch the throw, and sweep the tag down on the runner's feet.",explSimple:["When a runner steals third, the third baseman covers the bag.","The shortstop does NOT cover third on steals — that's the third baseman's responsibility.","Running toward the runner leaves third base uncovered.","Moving behind third means the catcher's throw has to go past the bag and reach you deeper."],anim:"catch"},
    {id:"3b_new1",title:"The Slow Roller — Charge or Wait?",diff:2,cat:"defense",conceptTag:"infield-positioning",ageMin:8,ageMax:99,
      description:"Slow roller down the third base line. Spin on the ball — it might stay fair or go foul. What do you do?",
      situation:{inning:"Bot 4",outs:1,count:"2-2",runners:[],score:[2,1]},
      options:["Let it roll — if it goes foul, you avoid making a play on a foul ball","Charge hard and field it immediately while fair","Charge and knock it foul with your foot if it's rolling toward the line","Wait at the bag for the ball to decide its fate"],
      best:1,explanations:["Letting it roll won't help you avoid making the play — this passive approach backfires constantly, since the ball spinning toward fair territory often hugs the line or curves back fair. By waiting, you lose the chance to field it cleanly.","Correct. Charging hard and fielding it quickly while it is clearly in fair territory is almost always the right play. A rolling ball with spin is unpredictable — waiting is gambling. Charge, field it quickly, and make your throw from an off-balance athletic position. MLB third basemen make this play at 78% success rate when they commit early versus 41% when they hesitate.","Don't charge and knock it foul — deliberately kicking a fair ball rolling toward the foul line is interference — it's an automatic dead ball and the batter is awarded first base, because never use your foot to redirect a batted ball.","Waiting at the bag while a slow roller dies in front of you is the worst option — you have no throw angle, no momentum, and the batter is already halfway to first."],
      rates:[40,90,15,25],concept:"Slow roller: charge hard and field while clearly fair — never wait",explSimple:["Letting it roll hoping it goes foul is a passive play that backfires constantly.","Charging hard and fielding it quickly while it is clearly in fair territory is almost always the right play.","Deliberately kicking a fair ball foul is interference — it's an automatic dead ball and the batter is awarded first base.","Waiting at the bag while a slow roller dies in front of you is the worst option."],anim:"groundout"},
    {id:"3b_new2",title:"The Bunt Crash — Who Gets It?",diff:2,cat:"defense",conceptTag:"bunt-defense",ageMin:10,ageMax:99,
      description:"Runner on 1st and 2nd, nobody out. Batter squares to bunt. You're crashing hard from third. The pitcher and catcher also break. The bunt is right down the third base line. Who fields it?",
      situation:{inning:"Top 5",outs:0,count:"1-0",runners:[1,2],score:[1,2]},
      options:["You field it — you have the best angle and you called it","Let the pitcher have it — he has momentum toward the line","Catcher takes it — he sees the whole field","Whoever gets there first fields it"],
      best:0,explanations:["Correct. Third base owns the bunt down the third base line. You're crashing with momentum toward the ball and you call it loudly. The pitcher peeling toward that line creates collision risk — verbal communication wins. 'I got it!' called early gives pitcher and catcher time to redirect. On third-base-side bunts, third base has the clearest lane and the best throw angle to first.","The pitcher's momentum carries him toward first base, making him ideal for first-base-side bunts, which means on third-base-side bunts, the pitcher has to turn back across his momentum to field it — awkward angle, late throw. Third base takes these.","The catcher handles bunt plays in front of the plate and on the first-base side — not down the third-base line, because you catcher direction on bunts: 'Third! Third!' is communication, not a fielding assignment.","'Whoever gets there first' creates collisions and dropped balls, since you bunt defense coverage zones are pre-assigned. Verbal communication backs up the zone assignments."],
      rates:[90,40,25,15],concept:"Third-base-line bunts: 3B owns it — call it loudly and early",explSimple:["Third base owns the bunt down the third base line.","The pitcher's momentum carries him toward first base, making him ideal for first-base-side bunts.","The catcher handles bunt plays in front of the plate and on the first-base side — not down the third-base line.","'Whoever gets there first' creates collisions and dropped balls."],anim:"groundout"},
    {id:"3b_new3",title:"Guarding the Line — When?",diff:3,cat:"defense",conceptTag:"line-guarding",ageMin:11,ageMax:99,
      description:"Bottom of the 7th, you're leading by 1, runner on 1st, 1 out. Do you guard the third base line?",
      situation:{inning:"Bot 7",outs:1,count:"0-0",runners:[1],score:[3,4]},
      options:["Yes — guard the line in this late/close situation to prevent a double","No — play normal depth, doubles are less common than grounders","Shift toward second base to improve DP range","Play at the edge of the grass for the bunt"],
      best:0,explanations:["Correct. Guarding the third base line in innings 7-9 while leading by 1-2 runs is textbook late-game positioning. A double down the line scores the tying run easily — preventing 0.4 extra base hits per game is worth the 8% increase in singles through the hole. Per MLB defensive data, line-guarding in this exact scenario (late, 1-run lead, runner on) is the correct call. The run that ties or wins the game is your priority, not the average play.","Playing normal depth treats a late/close 1-run lead the same as a random inning, because the strategic context changes the optimal position. This is exactly the scenario where guarding the line is justified — a double ties the game, a single through the hole still gives the runner only first.","Shifting toward second base in a 1-run game abandons your line protection and gives the offense an extra base hit lane — dP range matters more with a runner on in neutral innings — here, preventing the go-ahead run is the priority.","Playing at the grass edge for a bunt makes sense with runners on 1st and 2nd with nobody out, which means with a runner on 1st and 1 out, a bunt is uncommon — guard the line."],
      rates:[90,40,15,25],concept:"Guard the third base line in innings 7-9 with a 1-2 run lead",anim:"groundout"},
    {id:"3b_new4",title:"The Tag Play at Third",diff:2,cat:"defense",conceptTag:"force-vs-tag",ageMin:6,ageMax:99,
      description:"Runner on 1st and 2nd. Ground ball to short. SS throws to second for the force. Runner from 2nd rounds third and the second baseman fires to you. Is this a force or a tag?",
      situation:{inning:"Top 6",outs:0,count:"1-1",runners:[1,2],score:[2,2]},
      options:["Tag play — the force at second removed the force at third","Force play — runners were on 1st and 2nd so all bases are forced","Either way — I'll just touch the bag to be safe","Tag play only if the runner stops — otherwise touch the bag"],
      best:0,explanations:["Correct. When the force out is recorded at second base, the force condition at third base is removed. The runner from second is no longer forced to advance — he could have stopped at third. Your throw from second base is now a TAG situation. You must apply the tag. Touching the bag without tagging a runner who isn't forced is not an out. This is one of the most common base-running rule errors in youth baseball.","The force at third existed when both 1st and 2nd were occupied — but the moment the 2nd base force out was recorded, the trailing runner no longer has a runner behind him pushing him forward, because you force removed = tag required.","'Touch the bag to be safe' will cost you this out. The umpire sees a runner who is not forced — they will call him safe if you touch the bag but don't tag him. Always know your force status.","The force/tag distinction has nothing to do with whether the runner stops, since it depends entirely on whether the runner behind him was retired. Force out at 2nd = force removed at 3rd, period."],
      rates:[89,25,43,18],concept:"Force at 2nd removed = tag play at third, not force",explSimple:["When the force out is recorded at second base, the force condition at third base is removed.","The force at third existed when both 1st and 2nd were occupied — but the moment the 2nd base force out was recorded, the trailing runner no longer has a runner behind him pushing him forward.","'Touch the bag to be safe' will cost you this out.","The force/tag distinction has nothing to do with whether the runner stops."],anim:"groundout"},
    {id:"3b_new5",title:"Deep Fly — Cover Third on the Tag-Up",diff:1,cat:"defense",conceptTag:"tag-up",ageMin:8,ageMax:99,
      description:"You're playing third base on defense. Runner on 2nd, 1 out. Deep fly ball to center field. The runner is tagging up at second, ready to advance to third. The outfielder catches the ball. What's your job?",
      situation:{inning:"Top 5",outs:1,count:"0-0",runners:[2],score:[1,2]},
      options:["Get to third base and be ready for a throw — the runner might try to tag up","Run toward the cutoff man to help catch the throw","Stay where you are and watch the play develop","Move toward the pitcher's mound to back up a throw"],
      best:0,explanations:["Correct! On a tag-up with a runner on 2nd, the third baseman's job is to get to third base and straddle the bag. If the outfielder or cutoff man throws to third, you need to be there to catch it and apply the tag. The runner is tagging up and heading your way — be ready for the play at your base.","The first baseman or shortstop handles the cutoff — not the third baseman. Your job is to cover your base so there's someone to receive a throw if the defense tries to get the runner at third.","Staying in your normal fielding position means nobody is covering third base. If the outfielder throws to third, the ball rolls into foul territory and the runner keeps going. Always cover your base on a tag-up play.","Backing up the pitcher's mound leaves third base uncovered. The most likely play is at your base — be there."],
      rates:[82,30,25,15],concept:"On a tag-up with a runner heading to third, the third baseman covers the bag and prepares for a possible throw",explSimple:["Great choice! Get to third base and be ready for the throw — the runner is heading your way.","Not the best move. The cutoff is handled by other infielders — your job is to cover third.","Not the best move. Staying in your normal spot leaves third base uncovered.","Not the best move. Backing up the mound leaves your base open."], anim:"flyout"},
    {id:"3b_new6",conceptTag:"line-guarding",title:"Guard the Line or Play Normal?",diff:1,cat:"defense",ageMin:6,ageMax:99,
      description:"You're the third baseman. It's the last inning and your team is winning by one run. There are 2 outs and nobody on base. The batter hits a lot of balls down the third base line. Where should you stand?",
      situation:{inning:"Bot 6",outs:2,count:"0-0",runners:[],score:[2,3]},
      options:["Move closer to the foul line — don't let a ball get past you down the line","Stay in your normal spot — that's where you always play","Move closer to the shortstop to cover more ground","Play way back on the grass to give yourself more time"],
      best:0,explanations:["In the last inning with a lead, guarding the line is the smart play. A ball that gets past you down the line could roll to the corner for a double or triple — and that puts the tying run in scoring position. A ground ball through the normal hole is just a single, which is less dangerous. Always protect against the extra-base hit when you're trying to hold a lead.","Your normal spot is fine most of the time, but the game situation matters! With a lead in the last inning, you need to take away the extra-base hit down the line, because a single is okay — a double could tie the game.","Moving toward the shortstop leaves the line wide open — a hard grounder down the line goes to the corner and the runner ends up on second or third. That's the most dangerous outcome.","Playing back gives you more reaction time, but it doesn't help if the ball goes down the line past you, which means position matters more than depth here."],
      rates:[85,30,20,25],concept:"In the last inning with a lead, guard the foul line — a double is much more dangerous than a single",explSimple:["Move closer to the foul line! A ball down the line could be a double or triple.","Your normal spot is fine usually, but with a lead in the last inning, guard the line.","Moving toward short leaves the line wide open for a double.","Playing back doesn't help if the ball goes past you down the line."],anim:"catch"},
    {id:"3b_ba1",conceptTag:"backup-awareness",title:"Backing Up the Throw to Second Base",diff:2,cat:"defense",ageMin:9,ageMax:99,
      description:"You're the third baseman. A single to center field and the runner from first is rounding second. The center fielder throws to the shortstop, who is the cutoff man lined up with second base. Where should you position yourself?",
      situation:{inning:"Top 3",outs:0,count:"0-0",runners:[1],score:[1,2]},
      options:["Stay at third base in case the runner tries to advance there","Move behind the shortstop to back up the throw to second base","Run toward the pitcher's mound to help relay","Go out to shallow left field to help the outfielder"],
      best:1,explanations:["Staying at third base sounds logical, but if the throw from center field gets past the shortstop, nobody is behind him and the ball rolls into left field. The runner advances and your defense breaks down. Back up the throw first — you can get back to third after.","On a throw from center field to second base, the third baseman shifts behind the shortstop to back up the throw. If the ball skips past the shortstop, you're there to cut it off and keep the runner from advancing extra bases. Once the ball is secured, you get back to third. Backing up is invisible until it saves a run.","The pitcher's mound isn't in the throwing lane and doesn't help the relay, since the cutoff system handles the relay. Your job is to back up the play at second base.","Going into the outfield leaves the entire left side of the infield uncovered, because the outfielder can handle his own throw — your job is to back up where the throw is going, not where it's coming from."],
      explSimple:["If the throw gets past the shortstop and nobody is there, the ball rolls away and the runner keeps going.","Move behind the shortstop to back up the throw. If it gets past him, you stop the ball!","The mound isn't in the way of the throw. Back up behind the shortstop instead.","Going to the outfield leaves the infield wide open. Stay where the throw is going!"],
      rates:[40,80,25,25],concept:"Third baseman backs up throws to second base — position yourself behind the shortstop so an overthrow doesn't turn into extra bases",anim:"groundout"},
  ],
  baserunner: [
    {id:"r1",title:"Stealing Second",diff:1,cat:"stealing",conceptTag:"steal-breakeven",ageMin:8,ageMax:99,
      youthNote:"In youth leagues where leading off is not permitted, apply this read only after the pitch crosses home plate — stay on the bag until ball is delivered.",
      description:"You're on 1st, 2-1 count. Pitcher delivers slowly to the plate, catcher has a weak arm. You've got speed.",
      situation:{inning:"Top 6",outs:0,count:"2-1",runners:[1],score:[2,3]},
      options:["Go! Steal on the next pitch","Wait for a better count","Stay — let the batter work","Take a bigger lead but don't go"],
      best:0,explanations:["Perfect conditions: slow pitcher, weak catcher, hitter's count. Since you need roughly a 72% success rate for stealing to be worth the risk, and MLB runners succeed 85%+ in this situation, the math strongly favors going now.","Waiting for a better count is tempting, but you might not get a better spot. The key is that all three steal conditions are already aligned — slow delivery, weak arm, hitter's count — which means your success rate is well above the ~72% breakeven threshold.","Letting the batter work sounds safe, but staying put wastes your biggest advantage. Stealing needs about a 72% success rate to be worth it, because you getting caught removes a baserunner and costs your team an out. Here your odds are 85%+, so the risk-reward math says GO.","Taking a bigger lead without committing is indecisive, because the pitcher will notice and throw over to first. If you're going to test the defense, commit fully — otherwise you just invite a pickoff attempt."],
      explSimple:["Everything is perfect — the pitcher is slow and the catcher can't throw well. Go steal that base!","This is the best time to steal. Don't wait for a better chance because this IS the best chance.","Just standing there wastes your speed. Everything says it's time to run!","Taking a bigger lead without running just makes the pitcher throw to first base."],
      rates:[85,45,25,35],concept:"Steal when conditions align: slow pitcher, weak catcher, hitter's count",anim:"steal"},
    {id:"r2",title:"Tag Up Deep Fly",diff:1,cat:"tagging",conceptTag:"tag-up",ageMin:8,ageMax:99,
      description:"You're on 3rd, 1 out. Deep fly to center. Routine catch. Tie game, 8th inning.",
      situation:{inning:"Bot 8",outs:1,count:"0-0",runners:[3],score:[3,3]},
      options:["Tag up and score after the catch","Go halfway","Stay on 3rd","Break for home immediately"],
      best:0,explanations:["Deep fly, 1 out — tag up and score after the catch, because the throw from deep center is long.","Halfway on a routine catch = can't score from there.","A deep fly with 1 out? That's your chance for the go-ahead run.","Leaving early = out on appeal, since you wait for the catch!"],
      explSimple:["Wait on third base until the outfielder catches it, then run home! The throw is really far so you'll make it.","Going only halfway means you can't score. You need to stay on the base and then run after the catch.","This is a great chance to score! Tag up and run home after the catch.","Don't leave the base early — wait for the catch first, or the other team can get you out."],
      rates:[90,40,25,15],concept:"Always tag up on deep fly balls from 3rd with less than 2 outs",anim:"score"},
    {id:"r3", conceptTag:"wild-pitch-coverage",title:"Ball in the Dirt",diff:1,cat:"baserunning",ageMin:6,ageMax:99,
      youthNote:"In youth leagues, your secondary lead begins the moment the pitch leaves the pitcher's hand — stay on the bag until then.",
      description:"You're on 1st, 2 outs. Batter swings and misses, pitch bounces away from catcher.",
      situation:{inning:"Top 5",outs:2,count:"2-2",runners:[1],score:[1,2]},
      options:["Sprint to 2nd!","Wait for the catcher","Stay at 1st","Only go if it hits backstop"],
      best:0,explanations:["Sprint! With 2 outs, go on anything in the dirt, because the catcher has to find, pick up, and throw.","Hesitation kills — by the time you decide, the catcher has recovered.","Having 2 outs makes advancing MORE important.","Any ball away from the catcher is your chance."],
      explSimple:["Run! The ball bounced away from the catcher, so go to second base right now!","If you wait too long, the catcher will pick up the ball and you'll miss your chance.","With two outs, moving to the next base is super important because any hit could score you.","Whenever the ball gets away from the catcher, that's your chance to run."],
      rates:[85,25,15,45],concept:"With 2 outs, always advance on balls in the dirt",anim:"steal"},
    {id:"r4", conceptTag:"baserunning-rates",title:"First-to-Third",diff:2,cat:"baserunning",ageMin:9,ageMax:99,
      description:"You're on 1st, 1 out. Clean single to right. Right fielder has a strong arm.",
      situation:{inning:"Bot 4",outs:1,count:"1-1",runners:[1],score:[2,2]},
      options:["Round 2nd and read the coach","Sprint to 3rd no matter what","Stop at 2nd","Watch the throw first"],
      best:0,explanations:["Round 2nd aggressively and trust your 3rd base coach, which means he sees everything.","Running blind into a strong arm gets you thrown out.","Too conservative, because at 3rd you score on a sac fly or wild pitch.","By the time you watch the throw, it's too late, which means the outcome won't be what you need."],
      explSimple:["Run hard around second and look at your third base coach. He'll tell you to keep going or stop!","Don't just run without looking — the right fielder has a strong arm and could throw you out.","Stopping at second is too safe. If you get to third, you can score way more easily.","Don't look at the ball yourself — by the time you see the throw, it's too late. Trust your coach!"],
      rates:[85,25,40,35],concept:"Round bases aggressively and trust your 3rd base coach",anim:"advance"},
    {id:"r5", conceptTag:"steal-window",title:"Delayed Steal",diff:3,cat:"stealing",ageMin:12,ageMax:99,
      youthNote:"In youth leagues where leads are prohibited, the delayed steal works differently — read the catcher's lob-back timing and go when the ball is in transit between fielders.",
      description:"You're on 2nd. Middle infielders aren't covering the bag. Catcher lazily throwing back to pitcher.",
      situation:{inning:"Top 3",outs:1,count:"1-1",runners:[2],score:[0,0]},
      options:["Go! Break when catcher throws back","Don't — stealing 3rd is too risky","Wait for a passed ball","Only go on the coach's signal"],
      best:0,explanations:["Nobody covers, catcher is not paying attention — baseball IQ beats speed here, and this is your window.","Normally stealing 3rd is risky, but nobody is covering the bag, so the risk drops dramatically.","Waiting for a passed ball is passive — this moment of sloppy defense is YOUR chance to steal third.","Smart runners see opportunities the coach might miss, and taking the initiative here is the right call."],
      rates:[85,30,25,45],concept:"The delayed steal exploits defensive inattention — awareness over pure speed",anim:"steal"},
    {id:"r6", conceptTag:"scoring-probability",title:"Two Outs, Run on Contact",diff:1,cat:"baserunning",ageMin:6,ageMax:99,
      description:"You're on 2nd, 2 outs. Sharp grounder to SS — tough play, he has to charge it.",
      situation:{inning:"Bot 6",outs:2,count:"1-1",runners:[2],score:[3,4]},
      options:["Sprint home!","Wait to see if SS fields it","Go halfway","Stay at 2nd"],
      best:0,explanations:["Sprint home! With 2 outs, always run on contact — the SS has a tough play AND has to throw to 1st.","With 2 outs, hesitating wastes the advantage — the pitcher can't force you at any base, so run!","Halfway with 2 outs makes no sense.","NEVER assume a routine play with 2 outs."],
      explSimple:["Run home as fast as you can! With two outs, you always run when the ball is hit on the ground.","Waiting to see what happens wastes time. Just go!","Going only halfway makes no sense with two outs — you need to run all the way.","Don't just stand there! With two outs, always run when the ball is hit."],
      rates:[90,20,30,10],concept:"With 2 outs, ALWAYS run on contact — nothing to lose",anim:"score"},
    {id:"r7", conceptTag:"steal-window",title:"Reading the Pitcher",diff:3,cat:"stealing",ageMin:12,ageMax:99,
      youthNote:"In youth leagues, reading the pitcher's tells applies once the pitcher is in the windup — all leads must be taken after pitch delivery.",
      description:"You notice the pitcher's shoulder dips before a pickoff but stays level when going home. You're on 1st.",
      situation:{inning:"Top 5",outs:0,count:"1-1",runners:[1],score:[1,1]},
      options:["Use the tell — go when shoulder stays level","Ignore it, might be a decoy","Share with dugout but don't go","Wait for the steal sign"],
      best:0,explanations:["Using the pitcher's tell — that shoulder dip — gives you a massive jump, which means the best base stealers read these exact patterns to know when to go.","Ignoring a consistent tell wastes valuable information, because if you've seen the same pattern multiple times, trust your eyes — decoys are rare at this level.","Good to share, but acting NOW helps your team right now, since it gives you the best chance of success.","You have better info than the coach here."],
      rates:[85,20,45,40],concept:"Reading the pitcher's tells gives a huge advantage on the basepaths",anim:"steal"},
    {id:"r8", conceptTag:"baserunning-rates",title:"Running Out a Double",diff:1,cat:"baserunning",ageMin:6,ageMax:99,
      description:"You hit one in the gap. Definite single. Ball is still rolling as you round 1st.",
      situation:{inning:"Top 3",outs:1,count:"1-1",runners:[],score:[0,1]},
      options:["Peek at the ball while running","Full sprint to 2nd, then look up","Round 1st and decide","Sprint all the way to 3rd"],
      best:1,explanations:["Peeking breaks your stride and momentum — sprint full speed and trust your coach to guide you.","Run full speed to 2nd, then read your 3rd base coach.","Deciding at 1st is too early and slows you down — get to second first, then read the situation from there.","Going to 3rd without reading is reckless."],
      explSimple:["Looking at the ball while running slows you down. Keep your head up and run fast!","Run as fast as you can to second base, then look at your coach to see if you should keep going.","You can't decide at first base — just run hard to second and then look up.","Running all the way to third without checking is dangerous. You could get thrown out."],
      rates:[40,85,30,25],concept:"On extra base hits, sprint full speed and let the coach guide you",anim:"advance"},
    {id:"r9", conceptTag:"baserunning-rates",title:"Freeze on a Line Drive",diff:2,cat:"baserunning",ageMin:9,ageMax:99,
      description:"You're on 2nd. Screaming line drive toward shortstop. It might be caught.",
      situation:{inning:"Bot 5",outs:0,count:"1-1",runners:[2],score:[2,1]},
      options:["FREEZE!","Sprint to 3rd","Go halfway","Break back to 2nd"],
      best:0,explanations:["On line drives, FREEZE, since if caught, you're safe at 2nd. If it drops, advance.","Sprinting on a line drive = doubled off, because the #1 baserunning mistake.","Even halfway is dangerous on a liner, because the downside outweighs the potential gain.","Breaking back means you can't advance if it's a hit."],
      explSimple:["Freeze! Don't move until you see if the ball is caught or drops. If it's caught, you're safe. If it drops, then run.","If you run and the fielder catches it, they can throw to your base and get you out too — that's a double play!","Even going halfway is risky because line drives get caught fast and you won't have time to get back.","Running back to second means you can't go to third if the ball drops for a hit."],
      rates:[85,10,30,40],concept:"FREEZE on line drives — running on a catch means an easy double play",anim:"freeze"},
    {id:"r10", conceptTag:"scoring-probability",title:"Scoring from 2nd",diff:2,cat:"baserunning",ageMin:9,ageMax:99,
      description:"You're on 2nd, 1 out. Single to left. LF fields it on one hop. Score or hold?",
      situation:{inning:"Bot 7",outs:1,count:"1-1",runners:[2],score:[3,4]},
      options:["Score!","Hold at 3rd","Round 3rd and read the coach","Hold at third and check how far the outfielder's throw went"],
      best:2,explanations:["Aggressive is good but running blind into a throw can end the rally, since it gives you the best chance of success.","Too conservative with 1 out in a close game, which means the outcome won't be what you need.","Round 3rd hard and read your coach — he sees the throw and catcher.","Checking the throw at third before deciding is smart instinct, but your coach already sees everything, which means round third hard and read his signals — he'll wave you home or hold you based on the throw's accuracy."],
      explSimple:["Running home without looking could get you thrown out. Be smart!","Staying at third is too safe when you might be able to score.","Run hard around third base and look at your coach! He can see the throw and will tell you to go or stop.","Don't just stop — round third and look at your coach. He'll tell you to go or stay!"],
      rates:[45,35,85,40],concept:"Round 3rd aggressively and read your coach — he sees the whole play",anim:"score"},
    {id:"r11", conceptTag:"wild-pitch-coverage",title:"Wild Pitch Awareness",diff:1,cat:"baserunning",ageMin:6,ageMax:99,
      description:"You're on 3rd, 2 outs. Pitcher uncorks a curveball that bounces 5 feet in front of the plate.",
      situation:{inning:"Bot 8",outs:2,count:"1-2",runners:[3],score:[2,3]},
      options:["Sprint home!","Wait — too risky with 2 outs","See where the ball goes first","Only go if it gets past the catcher"],
      best:0,explanations:["Sprint home — any ball that bounces well in front of the plate is your chance to score, so be aggressive from 3rd with 2 outs!","With 2 outs, the risk-reward heavily favors going — if you stay, you might not get another chance to score.","By the time you see, the catcher has recovered.","It bounced 5 feet in front of the plate, so it WILL get away from the catcher at least briefly. Go!"],
      explSimple:["The ball bounced way in front of the catcher — run home right now! This is your chance to score!","With two outs, you should try to score because your team really needs it.","If you wait to see where the ball goes, the catcher will pick it up and you'll miss your chance.","The ball bounced far from the catcher, so he can't catch it right away. Go!"],
      rates:[85,20,35,50],concept:"On wild pitches with a runner on 3rd, react immediately — don't wait and watch",anim:"score"},
    {id:"r12", conceptTag:"baserunning-rates",title:"Running Through First Base",diff:1,cat:"basic",ageMin:6,ageMax:99,
      youthNote:"In youth leagues, your secondary lead begins the moment the pitch leaves the pitcher's hand — stay on the bag until then.",
      description:"You hit a ground ball to shortstop. It's going to be close at first base. How should you run through the bag?",
      situation:{inning:"Top 2",outs:0,count:"0-0",runners:[],score:[0,0]},
      options:["Run full speed straight through the bag","Slow down before the bag to hit it perfectly","Dive headfirst into first base","Round the bag toward second"],
      best:0,explanations:["Run THROUGH first base at full speed! You're allowed to overrun 1st base without being tagged out (as long as you turn right/foul territory), since never slow down.","Slowing down loses time, because the difference between safe and out is often 0.1 seconds.","NEVER dive headfirst into 1st base — it's slower than running through — you lose momentum.","Only round the bag if the ball gets through to the outfield, which means on a ground ball, run straight through."],
      explSimple:["Run as fast as you can straight through first base! You're allowed to run past it without getting tagged out.","Slowing down means you might be out! Keep running full speed.","Never dive into first base — running through is faster and safer.","Only curve toward second if the ball goes to the outfield. On a ground ball, run straight through the base."],
      rates:[85,15,10,35],concept:"Run full speed through 1st base — you can overrun it safely in foul territory",anim:"advance"},
    // Batch 1 — Steal Decisions
    {id:"r13", conceptTag:"steal-breakeven",title:"Slow Pitcher, Big Lead",diff:1,cat:"stealing",ageMin:6,ageMax:99,
      youthNote:"In youth leagues where leading off is not permitted, apply this read only after the pitch crosses home plate — stay on the bag until ball is delivered.",
      description:"Bot 3rd, you're on 1st with nobody out. The pitcher takes forever to deliver — his time to the plate is 1.8 seconds (average is 1.4). Score is 2-1.",
      situation:{inning:"Bot 3",outs:0,count:"1-1",runners:[1],score:[2,1]},
      options:["Steal second — the pitcher is slow","Stay put — don't risk it","Wait for a better count to steal","Only go if the coach gives the sign"],
      best:0,explanations:["A pitcher with a 1.8-second delivery is a gift for baserunners — your success rate here is well above the break-even percentage needed to justify the risk, because most catchers need the ball in 2.0 seconds total to throw out a runner. If the pitcher takes 1.8 just to deliver, even an average runner can steal second easily.","Playing it safe with a slow pitcher wastes a golden opportunity, since this is exactly when aggressive baserunning wins games.","The count doesn't matter much when the pitcher is this slow. His delivery time gives you the advantage, not the count.","Waiting for a sign is good fundamentals, but any smart coach would give the steal sign against a pitcher this slow, which is why this approach matters in this situation."],
      rates:[85,25,40,50],concept:"A pitcher's delivery time is the key to stealing bases — slow deliveries mean easy steals",explSimple:["Great choice! A pitcher with a 1.8-second delivery is a gift for baserunners.","Not the best move. Playing it safe with a slow pitcher wastes a golden opportunity.","Not the best move. The count doesn't matter much when the pitcher is this slow.","Not the best move. Waiting for a sign is good fundamentals, but any smart coach would give the steal."], anim:"steal"},
    {id:"r14",title:"Fast but Strong-Armed Catcher",diff:1,cat:"stealing",conceptTag:"steal-breakeven",ageMin:11,ageMax:99,
      youthNote:"In youth leagues where leading off is not permitted, apply this read only after the pitch crosses home plate — stay on the bag until ball is delivered.",
      description:"Top of the 5th, you're on 1st, 1 out, tied 2-2. You're one of the fastest kids on the team, but their catcher has thrown out 3 runners today.",
      situation:{inning:"Top 5",outs:1,count:"0-0",runners:[1],score:[2,2]},
      options:["Steal anyway — you're fast enough","Stay put — the catcher is too good","Get a great jump — timing beats arm strength","Take a bigger lead to make up the difference"],
      best:2,explanations:["Speed alone doesn't beat a great arm, because plenty of fast runners get thrown out by strong catchers.","Staying put isn't wrong, but you're giving up on your speed advantage — there's a better approach.","Against a strong-armed catcher, your jump is everything. Study the pitcher's pickoff move, time his leg kick, and get a perfect first step. A great jump beats a great arm because the runner gains distance before the catcher even receives the ball.","A bigger lead just makes you more vulnerable to a pickoff, which means it's your JUMP that matters, not your lead."],
      rates:[35,40,85,20],concept:"Against a great throwing catcher, your jump is more important than your speed",explSimple:["Not the best move. Speed alone doesn't beat a great arm.","Not the best move. Staying put isn't wrong, but you're giving up on your speed advantage.","Great choice! Against a strong-armed catcher, your jump is everything.","Not the best move. A bigger lead just makes you more vulnerable to a pickoff."], anim:"steal"},
    {id:"r15", conceptTag:"scoring-probability",title:"Is Stealing Third Worth It?",diff:1,cat:"stealing",ageMin:6,ageMax:99,
      youthNote:"In youth leagues where leading off is not permitted, apply this read only after the pitch crosses home plate — stay on the bag until ball is delivered.",
      description:"Bot 6th, you're on 2nd, nobody out, up 3-2. You're fast and thinking about stealing 3rd. The pitcher works from the windup, focused on the batter.",
      situation:{inning:"Bot 6",outs:0,count:"1-0",runners:[2],score:[3,2]},
      options:["Steal third — you're already in scoring position","Stay at second — it's not worth the risk","Only steal if the pitcher isn't paying attention","Wait for a passed ball to advance"],
      best:1,explanations:["Stealing third with nobody out is one of the worst risks in baseball, because you're already in scoring position at 2nd! From 2nd, you can score on most singles. Getting thrown out takes you off the bases entirely.","Smart! You're already in scoring position, since from 2nd base, you score on most singles, doubles, sac flies, and many ground balls. Risking an out to gain one base when you're already in scoring position is bad math.","Even if the pitcher isn't paying attention, stealing third with nobody out is rarely worth it, because the only time to steal third is with 2 outs when a single might not score you from 2nd.","Waiting for a passed ball is fine, but the key lesson is that stealing 3rd with nobody out is almost never the right play. And that's why this approach matters in this situation."],
      rates:[20,85,35,45],concept:"Don't steal third with nobody out — you're already in scoring position at second base",explSimple:["Not the best move. Stealing third with nobody out is one of the worst risks in baseball.","Smart! You're already in scoring position.","Not the best move. Even if the pitcher isn't paying attention, stealing third with nobody out is rarely worth it.","Not the best move. Waiting for a passed ball is fine, but the key lesson is that stealing 3rd."], anim:"freeze"},
    {id:"r16", conceptTag:"count-leverage",title:"3-1 Count — Pitcher Must Throw a Strike",diff:2,cat:"stealing",ageMin:9,ageMax:99,
      youthNote:"In youth leagues where leading off is not permitted, apply this read only after the pitch crosses home plate — stay on the bag until ball is delivered.",
      description:"Top of the 4th, you're on 1st, nobody out, down 2-1. Count is 3-1. He almost certainly throws a fastball strike here or walks the batter.",
      situation:{inning:"Top 4",outs:0,count:"3-1",runners:[1],score:[2,1]},
      options:["Steal on this pitch — he'll throw a fastball","Stay and let the batter hit","Wait for a full count to steal","Take a bigger lead but don't go"],
      best:0,explanations:["On 3-1, the pitcher almost always throws a fastball for a strike. This aggressive play carries less risk than a normal steal and your success rate is well above the break-even threshold — fastballs are easier to steal on because they take longer to reach the catcher. Plus, the catcher is set up for a strike, not a pitchout. This is the best count to steal on!","Letting the batter hit is fine, but you're wasting a perfect stealing count where the pitcher is almost guaranteed to throw a fastball — the 3-1 fastball is coming.","Waiting for a full count means the runner goes anyway on ball four. The 3-1 count is actually better for stealing because you know a fastball is coming.","A bigger lead without going wastes the count advantage and makes you more vulnerable to a pickoff, which means the value isn't in the lead size but in the timing of your break."],
      rates:[85,40,30,25],concept:"3-1 counts are great for stealing — the pitcher must throw a fastball strike",explSimple:["On 3-1, the pitcher almost always throws a fastball for a strike.","Letting the batter hit is fine, but you're wasting a perfect stealing count.","Waiting for a full count means the runner goes anyway on ball four.","A bigger lead without going wastes the count advantage and makes you vulnerable to a pickoff."],anim:"steal"},
    {id:"r17", conceptTag:"baserunning-rates",title:"Down Big — Play It Safe?",diff:2,cat:"stealing",ageMin:9,ageMax:99,
      youthNote:"In youth leagues, reading the pitcher's tells applies once the pitcher is in the windup — all leads must be taken after pitch delivery.",
      description:"Bot 5th, you're on 1st, 1 out, down 7-2. Your team needs a big rally. You're fast.",
      situation:{inning:"Bot 5",outs:1,count:"0-1",runners:[1],score:[2,7]},
      options:["Steal — get into scoring position","Stay put — save your energy, it's a blowout","Only go if the pitcher is slow","Take a chance — you've got nothing to lose"],
      best:0,explanations:["When you're down big, you need baserunners in scoring position. This aggressive play is worth the risk because the break-even point shifts when you're trailing badly — stealing second puts you where a single can score you. Playing it safe when you're down 5 runs won't help you come back.","Playing it safe when you're down by 5 means you've already given up, because aggressive baserunning gives you the best chance at a rally.","Waiting to evaluate the pitcher is too cautious when you're down this much, since you take the risk.","The instinct is right but the reasoning should be smarter — you're going because you getting into scoring position is essential for a comeback."],
      rates:[85,15,40,55],concept:"When trailing big, aggressive baserunning gives your team the best chance at a rally",explSimple:["When you're down big, you need baserunners in scoring position.","Playing it safe when you're down by 5 means you've already given up.","Waiting to evaluate the pitcher is too cautious when you're down this much.","The instinct is right but the reasoning should be smarter — you're going because you getting into scoring position is essential for a comeback."],anim:"steal"},
    {id:"r18", conceptTag:"steal-breakeven",title:"Left-Handed Pitcher on the Mound",diff:2,cat:"stealing",ageMin:9,ageMax:99,
      youthNote:"In youth leagues where leading off is not permitted, apply this read only after the pitch crosses home plate — stay on the bag until ball is delivered.",
      description:"Top of the 3rd, you're on 1st, nobody out, tied 1-1. But there's a problem — the pitcher pitches left-handed, which means he's facing you while in the stretch.",
      situation:{inning:"Top 3",outs:0,count:"1-1",runners:[1],score:[1,1]},
      options:["Don't steal — lefties are impossible to steal on","Watch his front foot — if it crosses toward home, he's pitching","Take a huge lead to compensate","Wait until there are 2 outs to steal"],
      best:1,explanations:["Lefties are tougher to steal on, but not impossible, because many runners steal on lefties by reading their move correctly.","The key to stealing on a lefty is reading the front foot — if the front foot goes toward home plate (crossing an imaginary line from the rubber), he's delivering to the batter and you GO. If it goes toward first, he's picking off and you dive back.","A huge lead against a lefty who can see you is asking for a pickoff, which means lefties have the easiest pickoff move in baseball.","Waiting for 2 outs has nothing to do with the lefty problem, because learn to read the move."],
      rates:[20,85,15,30],concept:"Steal on lefties by reading the front foot — if it crosses toward home, GO!",explSimple:["Lefties are tougher to steal on, but not impossible.","The key to stealing on a lefty is reading the front foot.","A huge lead against a lefty who can see you is asking for a pickoff.","Waiting for 2 outs has nothing to do with the lefty problem."],anim:"steal"},
    {id:"r19", conceptTag:"steal-window",title:"The Delayed Steal",diff:2,cat:"stealing",ageMin:9,ageMax:99,
      youthNote:"In youth leagues where leads are prohibited, the delayed steal works differently — read the catcher's lob-back timing and go when the ball is in transit between fielders.",
      description:"Bot 4th, you're on 1st, 1 out, up 4-3. The catcher has been lazily lobbing the ball back to the pitcher after each pitch. He's not paying attention.",
      situation:{inning:"Bot 4",outs:1,count:"1-0",runners:[1],score:[4,3]},
      options:["Normal steal on the next pitch","Delayed steal — go when the catcher throws back to the pitcher","Stay at first — no need to risk it with a lead","Wait for the hit-and-run sign"],
      best:1,explanations:["A normal steal works, but you'd be ignoring the bigger opportunity the catcher is giving you.","The delayed steal is one of the smartest plays in baseball — an aggressive gamble with a high success rate that far exceeds the break-even threshold when the catcher is lazy, since instead of going when the pitcher delivers, you go when the catcher lazily lobs the ball back. The pitcher isn't expecting it, the catcher isn't ready, and nobody covers second.","You have a lead, but building a bigger lead with smart baserunning puts more pressure on the defense, because you getting into scoring position with an easy steal makes every at-bat more dangerous.","Waiting for a coach's sign is fine, but recognizing this opportunity yourself shows great baseball IQ — the best baserunners see chances that coaches might miss."],
      rates:[50,85,30,35],concept:"The delayed steal exploits a lazy catcher — go when they lob the ball back to the pitcher",explSimple:["A normal steal works, but you'd be ignoring the bigger opportunity the catcher is giving you.","The delayed steal is one of the smartest plays in baseball.","You have a lead, but building a bigger lead with smart baserunning puts more pressure on the defense.","Waiting for a coach's sign is fine, but recognizing this opportunity yourself shows great baseball IQ."],anim:"steal"},
    {id:"r20", conceptTag:"steal-breakeven",title:"Two Outs, Best Hitter Up",diff:3,cat:"stealing",ageMin:12,ageMax:99,
      youthNote:"In youth leagues where leading off is not permitted, apply this read only after the pitch crosses home plate — stay on the bag until ball is delivered.",
      description:"Top of the 7th, you're on 1st, 2 outs, tied 3-3. Your team's best hitter steps to the plate — he's 3-for-3 today with a double and a homer.",
      situation:{inning:"Top 7",outs:2,count:"1-0",runners:[1],score:[3,3]},
      options:["Steal second — get into scoring position","Stay and let the best hitter drive you in","Take a big lead but don't steal — distract the pitcher","Only steal if you get a great jump"],
      best:1,explanations:["Stealing here is risky because if you're thrown out, your best hitter — who's 3-for-3 — never gets to swing. That's a terrible trade.","Your best hitter is ON FIRE, which means he's 3-for-3 with extra-base hits. Let him hit! If he doubles, you score from first. If he homers, you both score. Getting thrown out stealing robs your team of its best chance to score.","Distracting the pitcher is okay, but the main point is: don't risk getting thrown out before your hottest hitter swings. So this approach matters in this situation.","Even a great jump isn't worth the risk. If you're thrown out, the inning is over and your best hitter goes back to the dugout."],
      rates:[25,85,45,35],concept:"Don't steal in front of a hot hitter — let your best players drive you in",anim:"safe"},
    {id:"r21", conceptTag:"first-third",title:"Double Steal — First and Third",diff:3,cat:"stealing",ageMin:12,ageMax:99,
      youthNote:"In youth leagues, coordinate with your coaches before attempting a double steal — league rules on lead-offs vary widely.",
      description:"Bot 6th, runners on 1st and 3rd, 1 out, down 4-3. You're the runner on 1st. Coach signals a double steal — if they throw to second, the runner on 3rd scores.",
      situation:{inning:"Bot 6",outs:1,count:"0-0",runners:[1,3],score:[3,4]},
      options:["Sprint to second — make them throw to you","Jog to second — get in a rundown to give the runner on 3rd time","Bluff the steal — take a big secondary lead but stay at first","Go halfway and stop — see what happens"],
      best:0,explanations:["On a double steal with 1st and 3rd, sprint to second to force the catcher to choose, because if he throws to second, the runner on 3rd breaks home. If he holds the ball, you're safe at second. Win-win.","Getting into a rundown on purpose wastes time and gives the defense a chance to make the play at both ends, since a clean steal attempt is better.","A bluff doesn't force the catcher to choose — he just holds the ball and nobody advances. The whole point of the double steal is to commit fully and make them throw.","Going halfway and stopping is the worst option — you're neither stealing nor safe, because commit fully or don't go."],
      rates:[85,40,10,15],concept:"On a double steal from 1st and 3rd, force the catcher to choose — throw to 2nd and the runner on 3rd scores",anim:"steal"},
    {id:"r22", conceptTag:"steal-window",title:"Reading the Pitcher's Move",diff:3,cat:"stealing",ageMin:12,ageMax:99,
      youthNote:"In youth leagues, reading the pitcher's tells applies once the pitcher is in the windup — all leads must be taken after pitch delivery.",
      description:"Top of the 8th, you're on 1st, nobody out, tied 5-5. The pitcher keeps looking over at you and throwing to first. He's picked off two runners today.",
      situation:{inning:"Top 8",outs:0,count:"1-1",runners:[1],score:[5,5]},
      options:["Steal anyway — don't let him intimidate you","Shorten your lead and be safe","Time his pickoff move — find the pattern, then go","Don't steal — he's too dangerous"],
      best:2,explanations:["Stealing blindly against a pitcher who's picked off two runners today is reckless, not brave — running without reading his move first is asking to be the third victim.","Shortening your lead too much takes away your steal threat entirely, which means the outcome won't be what you need.","Every pitcher has a pattern — maybe he always looks twice before throwing home, or his leg moves differently on a pickoff vs a pitch, which means watch, learn his tell, and exploit it. Great baserunners study the pitcher before they run.","Deciding not to steal at all lets the pitcher control you with his pickoff threat, because studying his move and finding the pattern gives you a window to go safely."],
      rates:[15,35,85,40],concept:"Study the pitcher's pickoff move — every pitcher has a tell. Find it, then exploit it",anim:"steal"},
    // Batch 2 — Tagging Up
    {id:"r23", conceptTag:"tag-up",title:"Deep Fly Ball — Tag and Score",diff:1,cat:"tagging",ageMin:6,ageMax:99,
      description:"Bot 5th, you're on 3rd, 1 out, up 3-2. The batter hits a deep fly ball to center field — the outfielder catches it near the warning track.",
      situation:{inning:"Bot 5",outs:1,count:"1-1",runners:[3],score:[3,2]},
      options:["Tag up and score after the catch","Run halfway and watch","Run on contact — don't wait for the catch","Stay on the base — don't risk it"],
      best:0,explanations:["A deep fly ball to center is the perfect tagging opportunity, since touch the base, and the moment the ball hits the glove, sprint home. The outfielder has a long throw, and you'll score easily.","Going halfway means you can't go back if it's caught and you don't get the full head start of a tag, because commit to one or the other.","Running on contact before the catch means you're out if the ball is caught, since as you can't get back to third in time.","Staying on third with a deep fly ball wastes a chance to score, since one out, deep fly — this is exactly what tagging up is for!"],
      rates:[85,30,10,25],concept:"On a deep fly ball with less than 2 outs, tag up — touch the base and go when the ball is caught",explSimple:["Great choice! A deep fly ball to center is the perfect tagging opportunity.","Not the best move. Going halfway means you can't go back if it's caught and you don't get.","Not the best move. Running on contact before the catch means you're out if the ball is caught —.","Not the best move. Staying on third with a deep fly ball wastes a chance to score."], anim:"score"},
    {id:"r24", conceptTag:"tag-up",title:"Shallow Fly — Too Risky?",diff:1,cat:"tagging",ageMin:6,ageMax:99,
      description:"Top of the 4th, you're on 3rd, 1 out, tied 1-1. The batter pops a short fly to left field — the outfielder jogs in to catch it about 200 feet from home.",
      situation:{inning:"Top 4",outs:1,count:"1-1",runners:[3],score:[1,1]},
      options:["Tag up and go — any fly ball scores from 3rd","Stay at third — the throw is too short","Go halfway and see what happens","Run on contact before the catch"],
      best:1,explanations:["A shallow fly at 200 feet means the outfielder is close enough to throw you out easily, which means bad idea.","Good read! A shallow fly means the left fielder's throw will be quick and accurate, because you stay at third and wait for a better opportunity — a deeper fly, a ground ball, or a hit.","Going halfway commits you to neither option, since either tag or stay — don't get caught in between.","Running before the catch means you're out if the ball is caught."],
      rates:[30,85,40,15],concept:"Not every fly ball is a good tag-up — shallow fly balls give the outfielder an easy throw home",explSimple:["Not the best move. A shallow fly at 200 feet means the outfielder is close enough to throw.","Good read! A shallow fly means the left fielder's throw will be quick and accurate.","Not the best move. Going halfway commits you to neither option.","Not the best move. Running before the catch means you're out if the ball is caught."], anim:"freeze"},
    {id:"r25", conceptTag:"tag-up",title:"Advancing from Second on a Fly",diff:1,cat:"tagging",ageMin:6,ageMax:99,
      description:"Bot 7th, you're on 2nd, 1 out, down 3-2. Deep fly ball to right field — the right fielder catches it near the warning track. Can you tag to third?",
      situation:{inning:"Bot 7",outs:1,count:"1-1",runners:[2],score:[2,3]},
      options:["Tag up and advance to third","Stay at second — too risky","Go halfway and see what happens","Sprint home — try to score"],
      best:0,explanations:["Tagging from 2nd to 3rd on a deep fly to right field is great! Right fielders have the longest throw to third base, because at third, you can score on a wild pitch, sac fly, or ground ball.","Staying at second is too conservative — deep fly to right means the right fielder has the farthest throw to third. Take the base!","Going halfway means you can't advance and might get doubled off, which means commit to tagging or staying.","Trying to score from second on a fly ball is way too aggressive — the throw is much shorter, which means the outcome won't be what you need."],
      rates:[90,40,25,15],concept:"Tag from 2nd to 3rd on deep flies to right field — the right fielder has the longest throw to 3rd",explSimple:["Great choice! Tagging from 2nd to 3rd on a deep fly to right field is great! Right.","Not the best move. Staying at second is too conservative.","Not the best move. Going halfway means you can't advance and might get doubled off.","Trying to score from second on a fly ball is way too aggressive —."], anim:"advance"},
    {id:"r26", conceptTag:"tag-up",title:"Strong Arm in Right — Tag or Hold?",diff:2,cat:"tagging",ageMin:9,ageMax:99,
      description:"Top of the 6th, you're on 3rd, 1 out, up 4-2. Medium-depth fly to right field. The right fielder has the strongest arm on their team — he threw out a runner at home last inning.",
      situation:{inning:"Top 6",outs:1,count:"1-1",runners:[3],score:[2,4]},
      options:["Tag up and go — you're fast enough","Stay at third — his arm is too strong","Read the catch — if he's off-balance, go. If he's set, stay","Bluff a few steps toward home to force a hurried throw"],
      best:2,explanations:["Going blindly against a strong arm without reading the catch is risky, because the downside outweighs the potential gain.","Staying at third is safe but you might be wasting a chance, because there's a smarter way to decide.","Reading the catch is the key! If the outfielder has to reach, run sideways, or catch off-balance, his throw will be weaker — GO, since if he's camped under it with his feet set, his throw will be strong — STAY. Great baserunners make this read in real time.","Bluffing toward home against a strong-armed outfielder is risky, because if his throw is accurate, you're caught off the bag. Read the catch instead of playing mind games."],
      rates:[35,40,85,30],concept:"Read the outfielder's catch — if he's off-balance, go. If he's set, stay",explSimple:["Going blindly against a strong arm without reading the catch is risky.","Staying at third is safe but you might be wasting a chance.","Reading the catch is the key!","Bluffing to force a bad throw can backfire."],anim:"score"},
    {id:"r27",title:"Line Drive — Freeze!",diff:2,cat:"tagging",conceptTag:"tag-up",ageMin:8,ageMax:99,
      description:"Bot 3rd, you're on 2nd, nobody out, tied 2-2. The batter hits a screaming line drive to left-center. You took a few steps toward third on contact.",
      situation:{inning:"Bot 3",outs:0,count:"1-1",runners:[2],score:[2,2]},
      options:["Keep going to third — it's a hit!","Freeze and get back to second immediately","Go halfway and see if it's caught","Sprint home — it's in the gap!"],
      best:1,explanations:["Line drives can be caught by diving outfielders. If you're off the base and it's caught, you're doubled off for an easy double play.","On line drives, FREEZE and get back to your base. Line drives are caught at a much higher rate than fly balls, and if you're off the base, you're doubled off. Wait until the ball gets past the fielders, THEN run.","Going halfway is for fly balls, not line drives — line drives are too fast — by the time you see if it's caught, it's too late to get back.","Sprinting home on a line drive is the fastest way to get doubled off."],
      rates:[25,90,40,15],concept:"On line drives, freeze and get back to your base — if it's caught, you can't get doubled off",explSimple:["Line drives can be caught by diving outfielders.","On line drives, FREEZE and get back to your base.","Going halfway is for fly balls, not line drives.","Sprinting home on a line drive is the fastest way to get doubled off."],anim:"freeze"},
    {id:"r28",title:"Sacrifice Fly Timing",diff:2,cat:"tagging",conceptTag:"tag-up",ageMin:8,ageMax:99,
      description:"Top of the 7th, you're on 3rd, 1 out, up 5-4. Deep fly ball to center. You're tagging up. When exactly do you leave?",
      situation:{inning:"Top 7",outs:1,count:"1-1",runners:[3],score:[5,4]},
      options:["Leave right when the ball is hit — get a head start","Leave right when the ball touches the glove","Leave a split second before the catch — anticipate it","Wait until the outfielder's throw is in the air"],
      best:1,explanations:["Leaving when the ball is hit means you haven't tagged up, because the rule requires you to be touching the base at the moment the catch is made. If you leave early, the defense can appeal at third and you'll be called out — which means your insurance run never scores.","The rule says you can leave the moment the ball is first touched by the fielder. Watch the ball into his glove, and the instant it touches leather, explode toward home. That way you get the maximum head start without risking an appeal, since your foot was on the bag when the catch happened.","Leaving a split second before the catch feels smart, but if you guess wrong you're off the base too early. Since the defense can appeal at third base, even being a fraction of a second early means you're out — otherwise you'd score easily on a deep fly.","Waiting until the throw is in the air wastes precious seconds, because the outfielder's momentum is already carrying the ball toward home. The key is to leave at the moment of the catch, since every extra second you wait gives the throw a better chance of beating you."],
      rates:[15,85,30,20],concept:"On a tag-up, leave the moment the ball touches the glove — not before, not after",explSimple:["Leaving when the ball is hit means you haven't tagged up.","The rule says you can leave the moment the ball is first touched by the fielder.","Leaving before the catch is illegal — if the defense appeals, you'll be called out.","Waiting until the throw is in the air wastes precious seconds."],anim:"score"},
    {id:"r29", conceptTag:"tag-up",title:"Two Runners Tagging",diff:3,cat:"tagging",ageMin:12,ageMax:99,
      youthNote:"In youth leagues, reading the pitcher's tells applies once the pitcher is in the windup — all leads must be taken after pitch delivery.",
      description:"Bot 8th, runners on 2nd and 3rd, 1 out, down 6-5. You're the runner on 3rd. Deep fly to center — your teammate on 2nd wants to tag to 3rd too.",
      situation:{inning:"Bot 8",outs:1,count:"1-1",runners:[2,3],score:[5,6]},
      options:["Both tag — score the tying run and advance your teammate","Only you tag — don't risk your teammate getting thrown out","Stay at third — let your teammate tag to 3rd instead","Run without tagging — get home as fast as possible"],
      best:0,explanations:["When two runners tag up, the lead runner goes first. If you score, your teammate advances to 3rd because the throw goes home. Both tagging creates maximum pressure on the defense.","Only you tagging is too conservative. If both of you tag, the defense has to choose — throw home or throw to 3rd. They cannot do both.","Staying while your teammate tags to 3rd would put two runners on the same base — automatic out!","Running without tagging means you will be called out on appeal — always touch the base after the catch before you run."],
      rates:[85,45,15,10],concept:"When two runners can tag, both should go — the defense can only make one throw",anim:"score"},
    {id:"r30",title:"Foul Ball Tag-Up",diff:3,cat:"tagging",conceptTag:"tag-up",ageMin:8,ageMax:99,
      description:"Top of the 9th, you're on 3rd, 1 out, tied 7-7. The batter pops up a foul ball deep down the first base line. The first baseman drifts toward the dugout and catches it.",
      situation:{inning:"Top 9",outs:1,count:"1-1",runners:[3],score:[7,7]},
      options:["Tag up and score — a catch is a catch, even in foul territory","Stay at third — you can't tag on foul balls","Go halfway and watch the play","Sprint home before the catch"],
      best:0,explanations:["You CAN tag up on foul ball catches! As long as the fielder catches it, you can tag and advance, since a catch near the dugout means the first baseman is far from home and in an awkward position to throw.","Common mistake — you absolutely CAN tag up on foul ball catches, because the rule only requires the ball to be caught.","Going halfway on a foul ball doesn't help — either tag or stay.","Sprinting before the catch means you haven't tagged up — you'll be called out on appeal."],
      rates:[90,40,25,15],concept:"You CAN tag up on foul ball catches — a catch is a catch, fair or foul",anim:"score"},
    {id:"r31", conceptTag:"tag-up",title:"Fly Ball to Shallow Right",diff:3,cat:"tagging",ageMin:12,ageMax:99,
      description:"Bot 6th, you're on 3rd, 1 out, down 3-2. Fly ball to shallow right — the right fielder charges in hard. He'll catch it about 230 feet from home, running toward you.",
      situation:{inning:"Bot 6",outs:1,count:"1-1",runners:[3],score:[2,3]},
      options:["Tag and go — his momentum makes the throw hard","Stay at third — he's too close","Go if he bobbles the catch","Tag up but read his body — go if he stumbles"],
      best:3,explanations:["Just because he's running in doesn't automatically mean you should go. If he catches cleanly while running forward, he might throw you out.","He might be close, but his momentum matters, which means if he has to stop and set his feet, his throw will be late.","Waiting for a bobble is too specific, because you read his overall body position.","Smart! When a fielder charges in, watch his body, since if he stumbles, slides, or reaches awkwardly, his throw will be weak — GO. If he catches it in stride with his feet under him, STAY."],
      rates:[40,30,25,85],concept:"When an outfielder charges in, read his body — stumble or reach means GO, clean catch means STAY",anim:"score"},
    {id:"r32", conceptTag:"tag-up",title:"Deep Fly to the Warning Track",diff:3,cat:"tagging",ageMin:12,ageMax:99,
      description:"Top of the 5th, you're on 3rd, 1 out, tied 4-4. Deep fly to left — the wind held it up but the left fielder catches it at the warning track, 320+ feet from home.",
      situation:{inning:"Top 5",outs:1,count:"1-1",runners:[3],score:[4,4]},
      options:["Tag and score — outfielder is at the track, throw will be long","Stay at third — the wind might help his throw","Tag but wait to see the throw before committing","Go halfway and watch"],
      best:0,explanations:["The left fielder caught it at the warning track — that's 320+ feet from home plate, because no outfielder can throw you out from that distance with only 90 feet to run. This is an automatic tag-up.","The wind might help slightly, but the distance matters way more — 320 feet is too far for any throw to beat you.","Waiting to see the throw wastes time, which means you need to be sprinting the moment the ball hits the glove. The decision to go happens BEFORE the throw.","Going halfway means you lose your head start and can't tag properly."],
      rates:[85,15,25,20],concept:"When the outfielder catches at the warning track, tag and score — the throw is too long to beat you",anim:"score"},
    // Batch 3 — Reading the Ball Off the Bat
    {id:"r33",title:"Ground Ball to the Left Side",diff:1,cat:"baserunning",conceptTag:"force-vs-tag",ageMin:6,ageMax:99,
      youthNote:"In youth leagues, the force play rule is the same — when the batter runs to first, you MUST advance to second on a ground ball. There is no choice.",
      description:"Bot 4th, you're on 1st, nobody out, tied 2-2. The batter hits a ground ball to the shortstop. Do you advance to second?",
      situation:{inning:"Bot 4",outs:0,count:"1-1",runners:[1],score:[2,2]},
      options:["Run to second — you have to go on a ground ball","Stay at first — the shortstop might throw to second","Sprint to second but slide to avoid the tag","Run only if the ball gets past the shortstop"],
      best:0,explanations:["Under the force play rule, when a batter hits a ground ball, the runner on first MUST advance — no choice. The batter is running to first, so you can't stay. This is a rule, not a suggestion: two runners can't occupy the same base when the trailing runner is forced forward. No lead = no choice = force play. Run hard and try to break up the double play.","You can't stay at first — the batter-runner is coming to first. The force play rule means you're forced to advance because the base behind you is occupied. Two runners can't be on the same base, and the force removes your option to stay. You must go.","You don't need to slide at second on a force play — just run hard through the base, because sliding actually slows you down.","Waiting to see if the ball gets past the fielder means you'll be too late, since on a ground ball, the runner on first always goes."],
      rates:[85,5,40,15],concept:"On a ground ball with a runner on first, you MUST advance — it's a force play",explSimple:["Great choice! Under the force play rule, when a batter hits a ground ball, the runner.","Not the best move. You can't stay at first — the batter-runner is coming to first.","Not the best move. You don't need to slide at second on a force play — just run.","Not the best move. Waiting to see if the ball gets past the fielder means you'll be too late."], anim:"advance"},
    {id:"r34", conceptTag:"baserunning-rates",title:"Line Drive at the Shortstop",diff:1,cat:"baserunning",ageMin:6,ageMax:99,
      description:"Top of the 5th, you're on 1st, 1 out, up 3-1. The batter smashes a line drive right at the shortstop. You took a few steps toward second on the crack of the bat.",
      situation:{inning:"Top 5",outs:1,count:"1-1",runners:[1],score:[1,3]},
      options:["Keep going — it's a hit!","Stop and get back to first immediately","Dive back headfirst","Go halfway and wait"],
      best:1,explanations:["A line drive right at the shortstop is likely caught. If you're off the base, you'll be doubled off at first for an easy double play.","Get back to first NOW! Line drives hit right at fielders are usually caught. If you're off the base, the fielder catches the ball and throws to first for a double play. Always freeze or retreat on line drives hit at fielders.","Diving back headfirst to first is actually slower than running back, because you turn and run back to the base.","Going halfway on a line drive is dangerous — they're hit too hard for you to react in time — either you're going or you're going back."],
      rates:[10,85,30,20],concept:"On line drives hit at fielders, get back to your base — don't get doubled off",explSimple:["Not the best move. A line drive right at the shortstop is likely caught.","Great choice! Get back to first NOW! Line drives hit right at fielders are usually caught.","Not the best move. Diving back headfirst to first is actually slower than running back.","Not the best move. Going halfway on a line drive is dangerous — they're hit too hard for you."], anim:"freeze"},
    {id:"r35", conceptTag:"tag-up",title:"Fly Ball to the Outfield — Go Halfway",diff:1,cat:"baserunning",ageMin:6,ageMax:99,
      description:"Bot 6th, you're on 1st, nobody out, down 3-2. The batter lofts a high fly ball to center field. It's not clear if it'll be caught or drop.",
      situation:{inning:"Bot 6",outs:0,count:"1-1",runners:[1],score:[2,3]},
      options:["Run to second — assume it drops","Go halfway between first and second and watch","Stay at first — it'll probably be caught","Sprint to third — be aggressive"],
      best:1,explanations:["Running to second assumes the ball drops, which means if it's caught, you can't get back to first in time — you're doubled off.","Go halfway! On fly balls, run to the midpoint between first and second and watch the outfielder, because if the ball drops, you can advance to second (or beyond). If it's caught, you can retreat safely to first. Halfway gives you the best of both options.","Staying at first is too conservative, since if the ball drops, you've only advanced one base when you could have reached second or third.","Sprinting to third on a fly ball means you'll be out at first on a double play if it's caught — that's why this approach matters in this situation."],
      rates:[40,90,25,15],concept:"On fly balls, go halfway — you can advance if it drops and retreat if it's caught",explSimple:["Not the best move. Running to second assumes the ball drops.","Great choice! Go halfway! On fly balls, run to the midpoint between first and second and watch the outfielder.","Not the best move. Staying at first is too conservative.","Not the best move. Sprinting to third on a fly ball means you'll be out at first on."], anim:"advance"},
    {id:"r36", conceptTag:"baserunning-rates",title:"Ground Ball to the Right Side — Second to Third",diff:2,cat:"baserunning",ageMin:9,ageMax:99,
      description:"Top of the 3rd, you're on 2nd, nobody out, tied 1-1. The batter hits a ground ball to the second baseman. The second baseman fields it on the right side.",
      situation:{inning:"Top 3",outs:0,count:"1-1",runners:[2],score:[1,1]},
      options:["Advance to third — he's throwing to first","Stay at second — it's too risky","Only go if he doesn't look at you","Sprint home — catch them off guard"],
      best:0,explanations:["When the ball is hit to the right side (first baseman or second baseman) and you're on second, advance to third! The fielder's back is to you as he throws to first. He can't throw to third and first at the same time. This is one of the easiest advances in baseball.","Staying at second when the ball is hit to the right side wastes a golden opportunity, because the fielder has to throw to first — he can't get you at third.","He's going to throw to first regardless, since he has to — don't wait for a look. Go!","Sprinting home from second on a ground ball to the second baseman is way too aggressive, which means third base is the right target."],
      rates:[85,20,40,5],concept:"On ground balls to the right side, advance from 2nd to 3rd — the fielder has to throw to first",explSimple:["When the ball is hit to the right side (first baseman or second baseman) and you're on second, advance to third!","Staying at second when the ball is hit to the right side wastes a golden opportunity.","He's going to throw to first regardless — he has to.","Sprinting home from second on a ground ball to the second baseman is way too aggressive."],anim:"advance"},
    {id:"r37", conceptTag:"baserunning-rates",title:"Ball in the Gap — First to Third?",diff:2,cat:"baserunning",ageMin:9,ageMax:99,
      description:"Bot 5th, you're on 1st, 1 out, down 4-3. The batter drives a ball into the right-center gap. It's going to the wall. Can you make it from first to third?",
      situation:{inning:"Bot 5",outs:1,count:"1-1",runners:[1],score:[3,4]},
      options:["Sprint to third — the ball is in the gap","Stop at second — don't risk getting thrown out at third","Round second hard and watch the third base coach","Sprint home — score the tying run"],
      best:2,explanations:["Sprinting to third without looking at the coach could get you thrown out if the outfielder plays it quickly.","Stopping at second is too conservative on a ball in the gap, because you should be looking to take the extra base.","Round second hard and look at your third base coach! He can see the outfielder, the ball, and the throw, since if he's waving you, go to third. If he's holding you up, stop at second. Trusting your third base coach is fundamental to smart baserunning.","Going home from first on a ball to the gap is risky unless the ball gets past the outfielder completely, which is why this approach matters in this situation."],
      rates:[45,30,85,20],concept:"On extra-base hits, round the base hard and watch your third base coach — he sees the whole play",explSimple:["Sprinting to third without looking at the coach could get you thrown out if the outfielder plays it quickly.","Stopping at second is too conservative on a ball in the gap.","Round second hard and look at your third base coach!","Going home from first on a ball to the gap is risky unless the ball gets past the outfielder completely."],anim:"advance"},
    {id:"r38", conceptTag:"baserunning-rates",title:"Chopper Over the Pitcher — Score?",diff:2,cat:"baserunning",ageMin:9,ageMax:99,
      description:"Top of the 7th, you're on 2nd, 1 out, up 3-2. The batter hits a high chopper that bounces over the pitcher's head toward second base. The shortstop ranges over to field it.",
      situation:{inning:"Top 7",outs:1,count:"1-1",runners:[2],score:[2,3]},
      options:["Sprint home — the shortstop has to throw to first","Advance to third only — don't overrun the play","Watch and read — go based on where the fielder throws","Hold at second — too risky"],
      best:0,explanations:["On a high chopper with the shortstop ranging to his right, his momentum carries him away from home plate. He HAS to throw to first to get the batter. By the time the ball reaches first and could be relayed home, you've already scored. This is aggressive but smart baserunning.","Third base is the safe choice, but with the shortstop moving away from you and the ball bouncing high (buying you time), you can actually score on this play if you read it right away.","Watching wastes the time advantage the chopper gave you — on a high chopper, you read it instantly and GO.","Holding at second on a ball that takes the shortstop away from you wastes a great opportunity to score."],
      rates:[85,50,35,15],concept:"On high choppers that take the fielder away from you, be aggressive — score if you can",explSimple:["On a high chopper with the shortstop ranging to his right, his momentum carries him away from home plate.","Third base is the safe choice, but with the shortstop moving away from you and the ball bouncing high (buying you time), you can score.","Watching wastes the time advantage the chopper gave you.","Holding at second on a ball that takes the shortstop away from you wastes a great opportunity."],anim:"score"},
    {id:"r39", conceptTag:"force-vs-tag",title:"Sharp Grounder to Third — Frozen at Second",diff:2,cat:"baserunning",ageMin:9,ageMax:99,
      description:"Bot 3rd, you're on 2nd, nobody out, tied 3-3. Sharp ground ball hit to the third baseman — he's standing right next to the bag. You're only 10 feet off second.",
      situation:{inning:"Bot 3",outs:0,count:"1-1",runners:[2],score:[3,3]},
      options:["Advance to third — the ground ball gets through","Stay at second — the third baseman can tag the bag","Bluff toward third to distract him","Get back to second immediately"],
      best:1,explanations:["The third baseman is standing next to the bag. If you run to third, he just steps on third for the force-out — wait, there's no force. But he can tag you easily since he's right there.","Smart! When the third baseman fields a ground ball right next to his bag, DO NOT advance — he can look at you, fake a throw, or tag you easily. Stay at second and let the play go to first. You'll advance later on the next at-bat.","Bluffing toward third when the fielder is right there is dangerous — he might tag you, because the downside outweighs the potential gain.","You don't need to get back to second — there's no force play, which means just stay where you are."],
      rates:[10,85,25,30],concept:"When the third baseman fields near his bag, stay at second — don't run into a tag",explSimple:["The third baseman is standing next to the bag.","When the third baseman fields a ground ball right next to his bag, DO NOT advance.","Bluffing toward third when the fielder is right there is dangerous — he might tag you.","You don't need to get back to second — there's no force play."],anim:"freeze"},
    {id:"r40", conceptTag:"scoring-probability",title:"Slow Roller — Go on Contact?",diff:3,cat:"baserunning",ageMin:12,ageMax:99,
      description:"Top of the 8th, you're on 3rd, 1 out, down 4-3. 'Go on contact' is the call — run home on anything hit on the ground. But the batter hits a slow roller right at the first baseman, 15 feet from home.",
      situation:{inning:"Top 8",outs:1,count:"2-1",runners:[3],score:[4,3]},
      options:["Go — the call was go on contact","Hold up — the ball is too close to home","Freeze and read the play — did the first baseman field it cleanly?","Sprint home and hope for the best"],
      best:2,explanations:["'Go on contact' is a guideline, not a suicide pact, because you still need to read the play. A slow roller right at the first baseman 15 feet from home is different from a ground ball to shortstop.","Holding up entirely ignores the 'go on contact' call, since you should at least read the play.","Even with 'go on contact,' you still have to read the ball. If the first baseman bobbles it or has to reach, GO — his throw home will be late. If he fields it cleanly and is close to home, HOLD — he can throw home or tag the batter and throw home easily. Smart baserunners read the play even on 'go on contact.'","Sprinting home blindly into a tag when the first baseman is 15 feet away is an easy out."],
      rates:[30,35,85,15],concept:"'Go on contact' still requires reading the play — a ball right at a fielder near home is an exception",anim:"freeze"},
    {id:"r41", conceptTag:"secondary-lead",title:"Blooper to Shallow Center",diff:3,cat:"baserunning",ageMin:12,ageMax:99,
      description:"Bot 6th, you're on 1st, 1 out, tied 5-5. Blooper hit to shallow center — the center fielder and shortstop are both running for it. If it drops, you might score. If caught, you're doubled off.",
      situation:{inning:"Bot 6",outs:1,count:"1-1",runners:[1],score:[5,5]},
      options:["Sprint to third — be aggressive","Go halfway and read the play","Stay at first — it's probably caught","Freeze and wait to see what happens"],
      best:1,explanations:["Sprinting to third on a blooper means you're out at first on a double play if it's caught, because way too risky.","Go halfway! On a blooper where you're unsure if it'll drop, get to the halfway point between first and second. If the ball drops, you can advance to second (or beyond). If it's caught, you can get back to first safely. Halfway is the smart baserunning play on any 'tweener' ball.","Staying at first is too conservative, since if the ball drops, you've only gone to second when you could have reached third from the halfway point.","Freezing at first base is the same as staying, which means be more proactive — go halfway."],
      rates:[15,85,35,30],concept:"On bloopers and tweeners, go halfway — you can advance if it drops and retreat if it's caught",anim:"advance"},
    {id:"r42", conceptTag:"baserunning-rates",title:"Hard Grounder Back to the Pitcher",diff:3,cat:"baserunning",ageMin:12,ageMax:99,
      description:"Top of the 9th, you're on 3rd, 1 out, tied 6-6. Hard one-hopper back to the pitcher. He fields it, fakes a throw home, and spins to look at you.",
      situation:{inning:"Top 9",outs:1,count:"1-1",runners:[3],score:[6,6]},
      options:["Sprint home — he faked, so he's throwing to first","Freeze — don't fall for the fake","Jog back to third — play it safe","Take a few steps and see what he does next"],
      best:1,explanations:["The fake throw home is designed to get you to commit so he can throw you out. If you sprint home, he simply throws to third or chases you down for the tag. Reacting to the fake is exactly what the pitcher wants you to do.","The fake throw is one of the oldest tricks in baseball. The pitcher fields the ball, fakes a throw home to get you to commit toward the plate, then throws to third (or chases you down) for the tag. FREEZE. Don't react to the fake. Stay at third. He still has to throw to first for the out.","Jogging back to third shows you're rattled, because retreating from a safe position is unnecessary. Just freeze in place — you're safe at third. There's no reason to retreat when standing still keeps you safe and ready for the next play.","Taking steps toward home after the fake is exactly what the pitcher wants, because any movement toward the plate gives him an angle to throw you out. Freeze and hold your ground — standing still at third keeps you safe while the pitcher has to deal with the batter."],
      rates:[10,85,25,30],concept:"When the pitcher fakes a throw home, freeze — don't fall for the oldest trick in the book",anim:"freeze"},
    // Batch 4 — Advancing & Game Situations
    {id:"r43", conceptTag:"wild-pitch-coverage",title:"Wild Pitch — Advance from Second",diff:1,cat:"baserunning",ageMin:6,ageMax:99,
      description:"Bot 5th, you're on 2nd, 1 out, tied 3-3. A curveball bounces off the catcher's glove and rolls a few feet away. Do you advance?",
      situation:{inning:"Bot 5",outs:1,count:"1-2",runners:[2],score:[3,3]},
      options:["Sprint to third — the ball got away","Stay at second — it didn't go far enough","Take a few steps and watch the catcher","Only go if the ball goes to the backstop"],
      best:0,explanations:["On a wild pitch or passed ball from 2nd base, advance to 3rd! Even if the ball only goes a few feet from the catcher, it takes him time to recover, pick it up, and throw to third. From 3rd, you can score on a sac fly, ground ball, or another wild pitch.","Staying at second wastes a free base, because any ball that gets away from the catcher is an opportunity.","Taking a few steps wastes the head start, since commit and go — hesitation costs you the base.","Waiting for the backstop means you only advance on really bad wild pitches, because aggressive runners go on ANY ball that gets away."],
      rates:[85,20,35,30],concept:"On wild pitches, advance immediately — don't wait for the ball to reach the backstop",explSimple:["Great choice! On a wild pitch or passed ball from 2nd base, advance to 3rd! Even if.","Not the best move. Staying at second wastes a free base.","Not the best move. Taking a few steps wastes the head start.","Not the best move. Waiting for the backstop means you only advance on really bad wild pitches."], anim:"wildPitch"},
    {id:"r44", conceptTag:"wild-pitch-coverage",title:"Passed Ball — Score from Third",diff:1,cat:"baserunning",ageMin:6,ageMax:99,
      description:"Top of the 7th, you're on 3rd, 2 outs, down 4-3. The pitcher's fastball gets past the catcher and rolls toward the backstop. You're 90 feet from tying the game.",
      situation:{inning:"Top 7",outs:2,count:"1-1",runners:[3],score:[4,3]},
      options:["Sprint home immediately — score the tying run","Wait to see how far the ball goes","Only go if the catcher turns his back","Freeze — it's too risky with 2 outs"],
      best:0,explanations:["On a passed ball from 3rd with 2 outs, GO HOME. The catcher has to turn around, find the ball, retrieve it, and throw or tag. By the time he does all that, you should be sliding into home. With 2 outs, this might be your last chance to score.","Waiting wastes your head start, since the second the ball gets past the catcher, sprint.","The catcher will always turn to get the ball, which means you don't need to wait for permission.","With 2 outs and the tying run at third, a passed ball is a gift. After all, take it!. So this approach matters in this situation."],
      rates:[85,25,30,10],concept:"On passed balls from 3rd base, sprint home — react instantly, don't watch and wait",explSimple:["Great choice! On a passed ball from 3rd with 2 outs, GO HOME.","Not the best move. Waiting wastes your head start.","Not the best move. The catcher will always turn to get the ball.","Not the best move. With 2 outs and the tying run at third, a passed ball is a gift."], anim:"wildPitch"},
    {id:"r45", conceptTag:"baserunning-rates",title:"Overthrow at First — How Far Do You Go?",diff:1,cat:"baserunning",ageMin:6,ageMax:99,
      description:"Bot 3rd, you hit a ground ball to third. The third baseman's throw to first is wild — it sails over the first baseman's head and rolls down the right field line.",
      situation:{inning:"Bot 3",outs:0,count:"1-1",runners:[],score:[1,1]},
      options:["Stop at first — you were safe already","Round first and sprint to second","Try for third — the ball is loose","Sprint for home — the ball is rolling away"],
      best:1,explanations:["Stopping at first ignores a free extra base, because the ball is in right field — take advantage!","When the throw goes past the first baseman, round first and go to second. Watch where the ball goes and listen to your first base coach. An overthrow at first is almost always a free base to second. Be aggressive but smart — if the ball stays near the line, go to second. If it rolls far away, keep going.","Third might be possible if the ball rolls really far, but second is the smart, safe advance, since it gives you the best chance of success.","Going home on a simple overthrow at first is too aggressive unless the ball goes completely out of play, which means the outcome won't be what you need."],
      rates:[15,85,45,20],concept:"On overthrows at first, take the extra base — round first and head to second immediately",explSimple:["Not the best move. Stopping at first ignores a free extra base.","Great choice! When the throw goes past the first baseman, round first and go to second.","Not the best move. Third might be possible if the ball rolls really far, but second is.","Not the best move. Going home on a simple overthrow at first is too aggressive unless the ball goes."], anim:"advance"},
    {id:"r46", conceptTag:"baserunning-rates",title:"Throw to Wrong Base — Keep Going?",diff:2,cat:"baserunning",ageMin:9,ageMax:99,
      description:"Top of the 6th, you're on 1st. The batter singles to right. You round second and see the right fielder throw to third — but nobody is going to third. The ball arrives at the bag with no one there.",
      situation:{inning:"Top 6",outs:1,count:"1-1",runners:[1],score:[2,3]},
      options:["Take third — the ball went to the wrong base","Stop at second — don't overrun the play","Watch the third baseman — if he's not there, go","Sprint home — total chaos"],
      best:0,explanations:["When the outfielder throws to the wrong base, TAKE THE EXTRA BASE, since the ball is at third with no one covering — by the time someone retrieves it, you're standing on third safely. Smart baserunners exploit defensive mistakes.","Stopping at second when the ball went to an unoccupied third base wastes a free base.","Watching takes too long. If you can see the ball is at an empty bag, go immediately.","Home is too far unless the ball gets away from third base too, which means the outcome won't be what you need."],
      rates:[85,25,45,15],concept:"When the defense throws to the wrong base, take the extra base — exploit their mistakes",explSimple:["When the outfielder throws to the wrong base, TAKE THE EXTRA BASE.","Stopping at second when the ball went to an unoccupied third base wastes a free base.","Watching takes too long.","Home is too far unless the ball gets away from third base too."],anim:"advance"},
    {id:"r47",title:"Hit and Run — Batter Misses",diff:2,cat:"baserunning",conceptTag:"hit-and-run",ageMin:11,ageMax:99,
      youthNote:"In youth leagues, your secondary lead begins the moment the pitch leaves the pitcher's hand — stay on the bag until then.",
      description:"Bot 4th, you're on 1st, 1 out. The hit-and-run is called — you take off running. But the batter swings and MISSES. You're now a sitting duck between first and second.",
      situation:{inning:"Bot 4",outs:1,count:"1-1",runners:[1],score:[2,2]},
      options:["Keep going — try to steal second","Stop and get back to first","Slide into second and hope the catcher's throw is bad","Get in a rundown to let the batter get set for the next pitch"],
      best:0,explanations:["When the batter misses on a hit-and-run, you're committed — keep going to second! The risk is worth it because your aggressive jump gives you a success rate above the break-even threshold. Don't stop, don't hesitate. You had a running start and the catcher still has to receive the pitch, then throw. Your jump might be good enough to be safe. Stopping or turning back almost guarantees you're out.","Stopping between bases is the worst option — you'll be caught in a rundown with nowhere to go, because your momentum is already carrying you toward second, and reversing direction puts you in no-man's land.","Sliding into second is what you should do at the end, but first you need to keep sprinting at full speed — the slide is just the finishing move — your legs do the real work.","Getting into a rundown on purpose wastes a precious out with 1 out already, which means your best chance is to keep going and try to be safe."],
      rates:[85,15,45,20],concept:"On a missed hit-and-run, keep going — you're committed. A good jump might still be safe",explSimple:["When the batter misses on a hit-and-run, you're committed — keep going to second!","Stopping between bases is the worst option — you'll be caught in a rundown with nowhere to go.","Sliding into second is what you should do — but you also need to keep sprinting there first.","Getting into a rundown on purpose wastes an out."],anim:"steal"},
    {id:"r48", conceptTag:"baserunning-rates",title:"First to Third on a Single",diff:2,cat:"baserunning",ageMin:9,ageMax:99,
      description:"Top of the 5th, you're on 1st, nobody out, tied 2-2. Clean single to left field. The left fielder takes his time fielding it. Can you go first to third?",
      situation:{inning:"Top 5",outs:0,count:"1-1",runners:[1],score:[2,2]},
      options:["Sprint to third — the left fielder is lazy","Stop at second — don't take risks with nobody out","Round second and read the third base coach","Only go if the ball gets past the left fielder"],
      best:2,explanations:["Sprinting to third without reading the play could get you thrown out if the fielder recovers quickly.","Second base is safe, but if the fielder is being lazy, you're leaving a free base on the table.","Round second hard and pick up your third base coach! He can see the left fielder and his throw. If the coach is waving, sprint to third. If he's holding you, stop at second. First to third on a single puts enormous pressure on the defense and puts you in scoring position with nobody out.","The left fielder doesn't need to miss the ball for you to take third, because a lazy fielding effort or a weak arm is enough."],
      rates:[40,30,85,25],concept:"Going first to third on a single requires reading — round second hard and watch your third base coach",explSimple:["Sprinting to third without reading the play could get you thrown out if the fielder recovers quickly.","Second base is safe, but if the fielder is being lazy, you're leaving a free base on the table.","Round second hard and pick up your third base coach!","The left fielder doesn't need to miss the ball for you to take third."],anim:"advance"},
    {id:"r49", conceptTag:"baserunning-rates",title:"Double Play in Progress — Advance?",diff:3,cat:"baserunning",ageMin:12,ageMax:99,
      description:"Bot 6th, runners on 1st and 2nd, nobody out, tied 4-4. Ground ball to short — the shortstop flips to second for the force. You're the runner on 2nd. While the DP is being turned, do you advance to 3rd?",
      situation:{inning:"Bot 6",outs:0,count:"1-1",runners:[1,2],score:[4,4]},
      options:["Sprint to third while they turn the DP","Stay at second — the DP ends the play","Advance to third only if the throw to first is late","Go halfway and watch the play"],
      best:0,explanations:["While the defense is turning a double play, the runner on second should advance to third! The middle infielder is focused on the flip and throw to first — nobody is covering third. Even if the DP is completed (2 outs), you're now on third with 2 outs. If the DP isn't completed, you're on third with 1 out. Win-win.","Staying at second wastes a free advance, since the defense is occupied with the DP and nobody is covering third base. This is a free base that aggressive runners take every time.","Waiting to see if the throw to first is late means you've already lost your head start. Go immediately — the defense can't turn the DP and throw to third at the same time.","Halfway gives up your advantage because you're not committed to either staying or going. Sprint to third — the defense can't throw to three places at once, and by the time the DP is complete you should already be standing on the bag."],
      rates:[85,15,35,30],concept:"During a double play, the runner on 2nd should advance to 3rd — the defense can't cover everywhere",anim:"advance"},
    {id:"r50", conceptTag:"balk-rule",title:"Balk — Free Base",diff:2,cat:"baserunning",ageMin:9,ageMax:99,
      description:"Top of the 4th, you're on 1st, nobody out. The pitcher starts his motion, stops, then restarts. The umpire calls BALK. What happens?",
      situation:{inning:"Top 4",outs:0,count:"1-0",runners:[1],score:[1,2]},
      options:["Advance to second — all runners advance one base on a balk","Stay at first — a balk is just a warning","Go to second only if the umpire tells you","Run as far as you can — it's a dead ball"],
      best:0,explanations:["On a balk, ALL runners advance one base, because you go from first to second for free. A balk is called when the pitcher makes an illegal motion — like starting and stopping his delivery. It's a free base for all runners, no exceptions.","A balk is not a warning — it's an immediate penalty — all runners advance one base.","You don't need to wait for the umpire to tell you, which means once a balk is called, it's automatic — advance one base.","You only advance one base on a balk, not as many as you want, because it's a dead ball."],
      rates:[90,15,40,25],concept:"On a balk, all runners advance one base — it's a free base when the pitcher makes an illegal motion",explSimple:["On a balk, ALL runners advance one base.","A balk is not a warning — it's an immediate penalty.","You don't need to wait for the umpire to tell you.","You only advance one base on a balk, not as many as you want."],anim:"advance"},
    {id:"r51",title:"Rundown — Make Them Throw",diff:3,cat:"baserunning",conceptTag:"rundown-mechanics",ageMin:8,ageMax:99,
      description:"Bot 8th, you're caught in a rundown between second and third. Two fielders are chasing you. You're probably going to be out, but how can you help your team?",
      situation:{inning:"Bot 8",outs:1,count:"1-1",runners:[1,2],score:[4,5]},
      options:["Sprint toward third — maybe you'll be safe","Make them throw as many times as possible — buy time","Stop and retreat to second — get back safely","Run toward the fielder with the ball to force a bad throw"],
      best:1,explanations:["Just sprinting to one base means you're out quickly with no benefit to your team. A quick rundown ends the play fast and gives your other runners no time to advance — you've wasted a chance to help.","In a rundown, make the defense throw as many times as possible. Every throw is a chance for an error. Every second in the rundown is time for OTHER runners to advance. If there's a runner on first, he might advance to second (or further) while the defense is focused on you. Even if you're out, you've helped your team.","Retreating to second ends the rundown quickly without helping your teammates advance, since every second you stay alive gives your other runners time to move up.","Running at the fielder is unpredictable but risky — given that you might run into an obstruction call or just get tagged easily. The smarter play is to make them chase you back and forth so they have to throw multiple times, increasing the chance of an error."],
      rates:[30,85,10,25],concept:"In a rundown, make them throw — every throw is a chance for an error and lets other runners advance",anim:"safe"},
    {id:"r52", conceptTag:"secondary-lead",title:"Overthrow on Pickoff — React!",diff:3,cat:"baserunning",ageMin:12,ageMax:99,
      description:"Top of the 7th, you're on 1st, nobody out, tied 5-5. A pickoff throw goes to first for a pickoff, but the first baseman drops the ball! It's rolling behind him toward right field.",
      situation:{inning:"Top 7",outs:0,count:"1-1",runners:[1],score:[5,5]},
      options:["Sprint to second — the ball is loose","Stay at first — it might be a trick","Go to second only if you see the ball on the ground","Sprint to third — take two bases on the error"],
      best:0,explanations:["When the pickoff throw gets away, sprint to second immediately! Don't wait, don't think, just react, because the ball is loose and the first baseman has to chase it. By the time he recovers, you should be safe at second. Aggressive baserunners turn defensive mistakes into scoring opportunities.","It's not a trick — the ball is clearly on the ground, which means you should react immediately and take the free base. Hesitating out of caution gives the defense time to recover and eliminates the opportunity their mistake created.","You should already be sprinting while verifying where the ball went, because every second you wait is a second the defense uses to recover. Don't stand and watch — start running the instant you see the ball loose and adjust as you go.","Third might be possible if the ball goes far, but second is the guaranteed safe advance. Take the sure base first — being greedy and getting thrown out at third wastes the free opportunity the defense just gave you."],
      rates:[85,10,40,35],concept:"On dropped pickoff throws, react immediately — sprint to the next base while the ball is loose",anim:"advance"},
    // Batch 5 — Special Situations
    {id:"r53",title:"Infield Fly Rule — What Do I Do?",diff:2,cat:"rules",conceptTag:"infield-fly",ageMin:9,ageMax:99,
      description:"Bot 3rd, runners on 1st and 2nd, 1 out. The batter pops up a high fly to the shortstop. The umpire yells 'INFIELD FLY — BATTER OUT!' What do you do as the runner on 2nd?",
      situation:{inning:"Bot 3",outs:1,count:"1-1",runners:[1,2],score:[2,2]},
      options:["Sprint to the nearest open base immediately","Return to your base and hold — the play is dead","Tag up and advance if the ball is caught","Stay near your base — advance at your own risk"],
      best:3,explanations:["Sprinting to the nearest open base is dangerous, because even though the batter is out, the ball is still live. If the shortstop catches it and you've left second base, he can throw to second to double you off — which means the infield fly rule that was supposed to protect you actually backfires into a double play.","Returning to your base and holding is too passive, because the infield fly rule doesn't freeze the runners. The batter is automatically out whether the ball is caught or dropped, but since the ball is still live, you're allowed to advance at your own risk. If you never move, you miss a chance to take third on a dropped ball.","Tagging up is part of the answer, but only covers one scenario, because if the fielder catches it, yes, you must tag up before advancing. But if he drops it, you don't need to tag up at all — you can just run. The key is understanding that the infield fly rule keeps the ball live, so you need to react to what actually happens.","Staying near your base and reacting is the smart play, because the infield fly rule makes the batter automatically out whether the ball is caught or not — but the ball is STILL LIVE. If the fielder catches it, you must tag up before advancing. If he drops it, you can try to advance without tagging. That way you're ready for either outcome, otherwise you risk getting doubled off or missing an opportunity."],
      rates:[10,25,35,85],concept:"On an infield fly, the batter is out but the ball is still live — stay near your base and react",explSimple:["You're NOT free to just run.","You don't HAVE to stay put, but you should be careful.","Tagging up is one option, but the key is understanding the rule first.","On an infield fly, the batter is automatically out whether or not the ball is caught."],anim:"freeze"},
    {id:"r54", conceptTag:"baserunning-rates",title:"Ground Rule Double — Where Do I Go?",diff:2,cat:"rules",ageMin:9,ageMax:99,
      description:"Top of the 5th, you're on 1st, nobody out. The batter ropes a line drive that bounces in fair territory and then hops over the outfield fence. The umpire signals ground rule double.",
      situation:{inning:"Top 5",outs:0,count:"1-1",runners:[1],score:[1,3]},
      options:["Sprint home — the ball went over the fence","Advance to third only","Advance to second only — you were on first","Stay at first base — the ground rule double only advances the batter"],
      best:1,explanations:["Sprinting home seems right because the ball left the field, but the ground rule double rule caps your advancement at exactly two bases. Unlike a live ball where you run as far as you can, a dead ball limits everyone to two bases from their starting position.","On a ground rule double, all runners advance exactly two bases from where they were when the ball was pitched. Since you started on first, you go to third (first to second = one base, second to third = two bases). The batter gets second base. The ball is dead once it bounces over the fence, so no extra advancement is possible.","You're thinking one base short — two bases from first lands you at third, not second. Count it out: first base plus one is second, plus two is third. That's the full two-base award the rule gives you.","The ground rule double isn't just about the batter — it awards ALL runners two bases. This matters because a ball bouncing over the fence takes the outfielder out of the play, so the rule gives runners a fair advancement without letting them circle the bases on a dead ball."],
      rates:[40,90,25,15],concept:"On a ground rule double, all runners advance exactly two bases from where they started",explSimple:["You can't score from first on a ground rule double.","On a ground rule double, all runners are awarded two bases from where they were when the ball was pitched.","Two bases from first is third, not second.","A ground rule double awards ALL runners two bases from where they were at the time of the pitch, not just the batter."],anim:"advance"},
    {id:"r55", conceptTag:"obstruction-interference",title:"Obstruction — Fielder in My Way",diff:3,cat:"rules",ageMin:12,ageMax:99,
      description:"Bot 7th, you're on 2nd, 1 out. The batter singles to left. You sprint toward third, but the third baseman stands in the baseline without the ball — blocking your path!",
      situation:{inning:"Bot 7",outs:1,count:"1-1",runners:[2],score:[3,3]},
      options:["Stop and go back — you can't go through him","Run through him — he's blocking you illegally","Avoid him and keep running — go around","Keep running toward the base — the umpire will call obstruction"],
      best:3,explanations:["Don't stop or retreat, because if you go back, you lose the base you're entitled to under the obstruction rule. A fielder can't legally block your path without the ball, which means the rules protect you — keep going toward the base and let the umpire make the call.","Running through the fielder could get you called for interference, because initiating deliberate contact — even against a player blocking you — can be turned against you by the umpire. Keep running toward the base without shoving, and let the official see the obstruction clearly.","Going around him costs you time and might prevent you from reaching the base you deserve, because every extra step you take is time the defense uses to complete a play. The fielder shouldn't benefit from blocking you — that's exactly what the obstruction rule is designed to prevent, which means the direct path is always the right choice.","Obstruction is when a fielder blocks the baseline without the ball, because the rules don't allow defenders to impede runners unless they're fielding the ball. Keep running toward the base and the umpire will call obstruction, which means he'll award you the base (or bases) you would have reached. Don't stop, don't go back — the rule protects you."],
      rates:[10,20,30,85],concept:"If a fielder blocks you without the ball, it's obstruction — keep running, the umpire will award the base",anim:"advance"},
    {id:"r56", conceptTag:"appeal-play",title:"Appeal Play — Missed a Base",diff:3,cat:"rules",ageMin:12,ageMax:99,
      description:"Top of the 8th, you're on 1st. The batter hits a double to deep right. You sprint around the bases — but in your excitement, you miss touching second base. You're standing on third, safe.",
      situation:{inning:"Top 8",outs:1,count:"1-1",runners:[2,3],score:[2,4]},
      options:["Go back and touch second before anyone notices","Stay at third — they probably didn't see it","Ask the umpire if you touched second","Signal to your third base coach and retrace in reverse order"],
      best:0,explanations:["Go back and touch second base now, because you're allowed to retrace your steps and touch a missed base as long as the defense hasn't appealed yet. The key is to do it in the correct order — go back from third to second, touch the bag, then return to third. If you fix it before the defense notices, the appeal can't get you out.","Staying at third and hoping is a gamble, because if the defense throws to second and appeals, the umpire will call you out. Since the defense can appeal at any time before the next pitch, you're one alert fielder away from losing your baserunner — which means gambling here could cost your team a run.","Asking the umpire won't help, because umpires are not allowed to tell you if you missed a base. That's the defense's responsibility to notice and appeal. If you ask, you're actually drawing attention to your mistake, which makes it more likely the defense figures it out.","Signaling your coach is smart communication, but the important thing is to retrace in the correct order — third to second, then back to third. Since you must touch the bases in reverse sequence, skipping straight to second from third without proper order could create confusion. The best play is to immediately go back and touch second yourself, because every second you wait gives the defense more time to appeal."],
      rates:[85,15,10,40],concept:"If you miss a base, go back and touch it before the defense appeals — fix your mistake yourself",anim:"advance"},
    {id:"r57", conceptTag:"force-vs-tag",title:"Force Removed — Am I Still Forced?",diff:3,cat:"rules",ageMin:12,ageMax:99,
      description:"Bot 6th, runners on 1st and 2nd, nobody out. Ground ball to short — the shortstop steps on second for the force out on the runner from first. You're the runner from 2nd heading to 3rd. Are you still forced?",
      situation:{inning:"Bot 6",outs:0,count:"1-1",runners:[1,2],score:[4,4]},
      options:["Keep going — I'm still forced to third","Go back to second — the force was removed when my teammate was out","Keep going but now I have to be tagged, not forced","The play is dead — stop where I am"],
      best:2,explanations:["The force on you was removed when the runner behind you was called out, since you can still advance, but you must be tagged.","Going back to second could actually be smart, but you're not required to — the force was removed, which means you can choose to advance.","When the runner behind you (on first) was forced out at second, there's no longer anyone behind you requiring you to advance. The force on you is REMOVED. You can still run to third, but now the defense must TAG you — they can't just step on third base. This changes the play significantly.","The play is definitely not dead, because the ball is still live and the game continues."],
      rates:[25,40,90,15],concept:"When the runner behind you is forced out, your force is removed — you must be tagged, not just forced",anim:"advance"},
    {id:"r59",title:"Touch Every Base!",diff:2,cat:"rules",conceptTag:"appeal-play",ageMin:9,ageMax:99,
      description:"Bot 8th, 2 outs, you're on 1st base, your team trails 4-3. Your teammate smashes a double off the wall in left-center! You're flying around the bases. As you round 2nd, you cut the corner wide and your foot barely misses the bag. You score easily. But the opposing catcher yells at his pitcher. What should you be worried about?",
      situation:{inning:"Bot 8",outs:2,count:"1-1",runners:[1],score:[3,4]},
      options:["Nothing — I scored, the run counts","The defense might appeal that I missed 2nd base","I should go back and re-touch 2nd base right now","The umpire would have called me out already if I missed it"],
      best:1,explanations:["The run does NOT automatically count just because you crossed home plate. If the defense appeals at 2nd base before the next pitch, you're out and the run is erased.","Exactly right. If you missed 2nd base, the defense can appeal by having the pitcher step off the rubber and throw to 2nd. If the umpire confirms you missed it, you're out — and since you'd be the 3rd out, your run does NOT count. This is a time play: a 3rd out on an appeal erases any run scored on the same play.","Going back to re-touch would be smart IF the ball is still live, but you'd need to touch bases in reverse order (home → 3rd → 2nd), since once you're in the dugout, it's too late.","Umpires do NOT automatically call missed bases — the defense must formally appeal, because that's exactly what the catcher is setting up."],
      rates:[15,85,50,10],concept:"Umpires don't call missed bases automatically — the defense must appeal before the next pitch, and a 3rd-out appeal erases any run scored on the play",explSimple:["The run does NOT automatically count just because you crossed home plate.","If you missed 2nd base, the defense can appeal by having the pitcher step off the rubber and throw to 2nd.","Going back to re-touch would be smart IF the ball is still live, but you'd need to touch bases in reverse order (home → 3rd → 2nd).","Umpires do NOT automatically call missed bases — the defense must formally appeal."],anim:"score"},
    {id:"r60", conceptTag:"steal-breakeven",title:"The Double Steal — Your Read",diff:2,cat:"baserunning",ageMin:9,ageMax:99,
      youthNote:"In youth leagues, coordinate with your coaches before attempting a double steal — league rules on lead-offs vary widely.",
      description:"You're on second base, runner on first. Tie game, 7th inning, 1 out. The manager gives the double steal sign. The pitch is delivered — you watch the catcher, not the runner at first. The catcher catches the pitch, transfers the ball... and his weight shifts toward second base. He's throwing.",
      situation:{inning:"Bot 7",outs:1,count:"1-1",runners:[1,2],score:[3,3]},
      options:["Break for home immediately — the catcher has committed to throwing to second","Wait to see if the runner at first makes it safely to second first","Hold at third — the catcher might fake the throw and fire home","Go only if the catcher actually releases the ball toward second"],
      best:0,explanations:["Correct! The moment the catcher's weight commits to throwing to second, you go — don't wait for the throw to be released. Since the ball takes nearly a full second to travel from the catcher to second base, you need to already be more than halfway home by the time it arrives. Waiting for the throw to leave his hand costs you a full second — that's the difference between safe and out.","Never wait for confirmation — the whole point of the double steal is that the catcher can't get both of you, which means you go the instant he commits to throwing to second. Waiting for the runner at first to reach second defeats the purpose because the catcher has already caught it and can throw home.","If the catcher is faking toward second to freeze you, he's already given up the stolen base at second. Either way you win — but you only win if you go. Staying at second on a double steal sign is not an option.","By the time the ball leaves his hand, it's too late — you need to be running before the release, reading the body commitment, not the ball. Half a second of hesitation is the difference between a walk-off run and an out at home."],
      rates:[75,40,35,25],concept:"On a double steal, the runner at second reads the catcher's body commitment — go the instant the catcher's weight shifts toward second, before the throw is released",explSimple:["The moment the catcher's weight commits to throwing to second, you go — don't wait for the throw to be released.","Never wait for confirmation — the whole point of the double steal is that the catcher can't get both of you.","If the catcher is faking toward second to freeze you, he's already given up the stolen base at second.","By the time the ball leaves his hand, it's too late."],anim:"score"},
    {id:"r61", conceptTag:"baserunning-rates",title:"First to Third — Do You Go?",diff:1,cat:"baserunning",ageMin:6,ageMax:99,
      description:"You're on first base. 2nd inning, nobody out. The batter hits a single to the right field corner — the ball rolls to the wall. The right fielder sprints toward the corner with his back to you. Your third base coach is windmilling his arm hard. What do you do?",
      situation:{inning:"Top 2",outs:0,count:"1-1",runners:[1],score:[0,0]},
      options:["Go full speed to third — ball in the corner, RF back to you, coach windmilling","Stop at second and play it safe — don't risk being thrown out","Round second, then stop and read the play","Go to third only if you're sure you can make it"],
      best:0,explanations:["Correct! Every factor says go: ball is in the corner (long way for RF to throw), the right fielder's back is to you (no momentum toward 3B), and your coach is windmilling, which means this is exactly the first-to-third opportunity. Sprint through second and get to third standing up.","This is a green light situation — ball in the RF corner with RF's back to you is the best first-to-third opportunity in baseball, because going to second and stopping gives up a free extra base. That extra base scores a run 85% of the time with 0 outs.","Do not slow down at second, since you made your read when the ball hit the corner — RF back to you means throw will be long. Your coach is windmilling. Rounding and stopping flat-footed kills your momentum and gets you thrown out. Run through the base.","You have all the information you need: RF corner, back to you, windmill from coach, because this is not a close call — it's a clear go. Trust your read and trust your coach. Run."],
      rates:[90,40,25,15],concept:"Ball in the RF corner with the outfielder's back to you and the coach windmilling is a go situation — sprint through second without hesitation",explSimple:["Great choice! Correct! Every factor says go: ball is in the corner , the right fielder's back.","Not the best move. This is a green light situation — ball in the RF corner with RF's back.","Not the best move. Do not slow down at second.","Not the best move. You have all the information you need: RF corner, back to you, windmill from coach."], anim:"advance"},
    {id:"r62", conceptTag:"scoring-probability",title:"The 3rd Out Rule",diff:2,cat:"baserunning",ageMin:9,ageMax:99,
      description:"You're on third base, 1 out, tie game in the 8th inning. The batter hits a sharp single to left field. The left fielder charges hard, fields it cleanly, and fires home. Your third base coach puts both hands up — stop sign. Do you respect the stop sign?",
      situation:{inning:"Bot 8",outs:1,count:"1-1",runners:[3],score:[4,4]},
      options:["Yes — respect the stop sign. Scoring from third on a close play with 1 out risks making the 3rd out at home","No — ignore it and go. You score more often than you're thrown out","Go only if you get a good jump off the pitch","Depends on how fast you are — elite runners should always go"],
      best:0,explanations:["Correct. This is the 3rd out rule: with less than 2 outs, never make the 3rd out at home on a close play. Your coach sees the LF fielded cleanly with momentum toward home — that's a strong, accurate throw coming. If you're thrown out, the inning ends with the tying run stranded. Instead, you're now on third with 1 out and the tying run still alive. That's a much better position than making the 3rd out.","The problem isn't your odds of scoring — it's what happens if you're out. Being thrown out at home with 1 out ENDS the inning. You kill the rally for every batter behind you. The RE24 cost of making the 3rd out at home with 1 out is catastrophic compared to standing on third and letting the next batter drive you in.","Your jump is irrelevant when the coach has a stop sign up — the coach sees the whole play — the fielder's angle, the arm, the throw trajectory. You can't see what he sees from third base. Trust the stop sign.","Speed is a factor in close plays, but the 3rd out rule applies to all runners, which means even elite runners get thrown out on strong throws from a cleanly-fielded ball. The expected value of stopping is higher than the expected value of risking the inning-ending out."],
      rates:[75,40,35,25],concept:"With less than 2 outs, never make the 3rd out at home on a close play — being out at home kills the inning and all runners behind you",explSimple:["This is the 3rd out rule: with less than 2 outs, never make the 3rd out at home on a close play.","The problem isn't your odds of scoring — it's what happens if you're out.","Your jump is irrelevant when the coach has a stop sign up.","Speed is a factor in close plays, but the 3rd out rule applies to all runners."],anim:"freeze"},
    {id:"r63",title:"Should I Try to Steal?",diff:1,cat:"baserunning",conceptTag:"steal-breakeven",ageMin:8,ageMax:11,
      youthNote:"In youth leagues where leading off is not permitted, apply this read only after the pitch crosses home plate — stay on the bag until ball is delivered.",
      description:"You're on first base. The pitcher sets up in the stretch. The catcher hasn't thrown anyone out all game — his throws keep bouncing in the dirt. Your coach gives you the steal sign. The pitcher starts his motion. What do you do?",
      situation:{inning:"Bot 3",outs:1,count:"1-1",runners:[1],score:[2,2]},
      options:["Go! The catcher can't throw — this is a great time to steal","Wait for a passed ball or wild pitch instead","Stay on first — stealing is too risky","Take a big lead but don't go"],
      best:0,explanations:["Go! At your level, catchers rarely throw out runners. If the catcher has been bouncing throws all game, your success rate is very high — way above the break-even percentage (around 67%) you need for a steal to be worth it. When your coach gives the steal sign and the catcher is struggling, this is the easiest steal you'll get all season. Note: In many youth leagues, you cannot leave the base until the pitch crosses home plate.","Waiting for a passed ball is safe, but you're wasting an opportunity. Your coach gave you the sign because he sees the catcher struggling. Trust your coach and go on the pitch.","Stealing is NOT too risky here — the catcher can't throw! At your level, you only need to be safe about half the time for a steal to help your team. With a catcher who's bouncing throws, you'll be safe way more than that.","A big lead without going wastes the opportunity. Your coach gave you the green light. If you don't go, you're ignoring the sign and missing a chance to get into scoring position."],
      rates:[85,35,15,25],concept:"At the youth level, steal when the catcher is struggling to throw — you only need about a 50% success rate for stealing to help your team",explSimple:["Great choice! Go! At your level, catchers rarely throw out runners.","Not the best move. Waiting for a passed ball is safe, but you're wasting an opportunity.","Not the best move. Stealing is NOT too risky here — the catcher can't throw! At your level, you.","Not the best move. A big lead without going wastes the opportunity."], anim:"steal"},
    {id:"r64",title:"Is This Steal Worth It? High School Math",diff:3,cat:"baserunning",conceptTag:"steal-breakeven",ageMin:14,ageMax:18,
      youthNote:"In youth leagues where leading off is not permitted, apply this read only after the pitch crosses home plate — stay on the bag until ball is delivered.",
      description:"You're on first base, 1 out, down 3-2 in the top of the 7th (last inning). The catcher has a 2.0 pop time and has thrown out 2 of 5 runners today (60% caught stealing rate). The pitcher's average delivery time is 1.4 seconds. Your personal stolen base rate this season is 70% (14 for 20). Should you attempt the steal?",
      situation:{inning:"Top 7",outs:1,count:"1-0",runners:[1],score:[3,2]},
      options:["Don't steal — your 70% rate is above break-even but this catcher is too good","Steal — your 70% rate is above the 65% high school break-even","Steal only on the next pitch if it's a breaking ball","Wait for a 2-strike count when the catcher has to focus on framing"],
      best:0,explanations:["Your season rate is 70%, but that's against ALL catchers. This catcher has a 2.0 pop time (elite) and has thrown out 60% of runners today. Against THIS catcher, your expected success rate drops well below 65%. The combined delivery+pop time is 1.4+2.0=3.4 seconds — that's right at the margin where steals become very difficult. The break-even at the high school level is 65%, and your adjusted rate against this arm is likely below that. Don't run into an out in the 7th when you're down by 1.","Your 70% season rate is above the 65% high school break-even — but break-even is the MINIMUM, not the target, because against a catcher throwing out 60% of runners with a 2.0 pop time, your actual success probability drops significantly. The math says hold.","Breaking balls give you slightly more time, but the 0.1-0.2 second advantage doesn't overcome a 2.0 pop time catcher, since you'd need the delivery+pop total above 3.4 seconds to be comfortable, and even with a curve you're at about 3.5 — barely marginal.","A 2-strike count doesn't help your steal, because the catcher still receives and throws the same way. Framing matters for borderline pitches, but it doesn't slow down his pop time or transfer."],
      rates:[82,40,30,20],concept:"Break-even is the MINIMUM, not the target — adjust your steal decision for the specific catcher's arm, not just your season average",anim:"steal"},
    // ============================================================================
    // VARIABLE MASTERY CLUSTER 2 — The Steal Decision
    // Same base situation, one variable changes the correct answer each time
    // ============================================================================
    {id:"r_vc2a",title:"Steal Decision — Green Light Situation",diff:3,cat:"baserunning",conceptTag:"steal-breakeven",ageMin:12,ageMax:99,
      description:"You're a fast runner on first base. The catcher has an average arm (2.1 pop time). The count is 2-0 on the hitter — a favorable hitter's count. Nobody out. Your team is tied. Your stolen base success rate is 78%. Should you steal second?",
      situation:{inning:"Bot 5",outs:0,count:"2-0",runners:[1],score:[3,3]},
      options:["Yes — fast runner, average catcher arm, 2-0 count, all systems go","No — 0 outs means a stolen base isn't worth the risk","Yes — but only on the next pitch regardless of count","Wait for a 3-1 count for an even better jump"],
      best:0,explanations:["Correct! This is a textbook green light situation. Your 78% success rate is well above the ~70% break-even threshold. The 2-0 count means the pitcher is more likely to throw a fastball (easier to read and get a jump on). The catcher's 2.1 pop time is average, not elite. With 0 outs in a tied game, getting into scoring position with a steal puts pressure on the defense and sets up a run on a single.","A stolen base with 0 outs and a 78% success rate is absolutely worth the risk. The break-even point for steals is around 70% — you're well above it. Getting to second with 0 outs raises your expected runs significantly.","'Regardless of count' ignores the advantage of a favorable count. The 2-0 count is part of what makes this a green light — don't throw that information away.","Waiting for 3-1 means waiting for a count that might never come. The 2-0 count is already favorable. If the next pitch is a strike, you're at 2-1 and the advantage shrinks. Take the green light when it's there."],
      rates:[85,20,40,30],concept:"Green light steal: success rate above break-even + favorable count + average catcher arm = go",anim:"steal"},
    {id:"r_vc2b",title:"Steal Decision — Bad Count Changes Everything",diff:3,cat:"baserunning",conceptTag:"steal-window",ageMin:12,ageMax:99,
      description:"Same situation — fast runner on first, average catcher, nobody out, tied game, 78% steal rate. But this time the count is 0-2. The hitter has a defensive count. Should you steal second?",
      situation:{inning:"Bot 5",outs:0,count:"0-2",runners:[1],score:[3,3]},
      options:["Yes — your steal rate is still above break-even regardless of count","No — on 0-2 the pitcher can waste pitches, making your jump harder","No — don't take the bat out of the hitter's hands when he needs to protect","Steal — the pitcher expects you to stay put on 0-2, so you'll surprise him"],
      best:2,explanations:["Your steal rate doesn't change, but the GAME CONTEXT does. On 0-2, the hitter needs to fight to survive. A pitch-out or breaking ball in the dirt becomes more likely, and the hitter can't protect you with a swing. You're taking the hitter's focus away from his at-bat when he needs it most.","The pitch selection argument is partially right, since the pitcher may throw off-speed or waste pitches — but the bigger reason is the hitter's situation, not just pitch predictability.","Correct! On 0-2, the hitter is in survival mode. He needs to shorten up, protect the plate, and battle. If you steal and get thrown out, you've removed a baserunner and the hitter's at-bat was wasted. If you stay, the hitter can fight back to a better count, and you still have the option to steal later in a more favorable situation. Don't take the bat out of a hitter's hands when he's behind.","Surprise value doesn't overcome bad game theory, which means even if the pitcher doesn't expect it, the hitter is compromised on 0-2 and losing the runner makes his at-bat less valuable."],
      rates:[30,50,82,25],concept:"On 0-2, don't steal — the hitter needs to battle back and you'd be taking the bat out of his hands",anim:"strikeout"},
    {id:"r_vc2c",title:"Steal Decision — Best Hitter Up Changes the Math",diff:3,cat:"baserunning",conceptTag:"steal-breakeven",ageMin:12,ageMax:99,
      description:"Same situation — fast runner on first, average catcher, nobody out, tied game, 78% steal rate, 2-0 count. But this time your team's best hitter steps to the plate — he's batting .380 with 12 extra-base hits. Should you steal second?",
      situation:{inning:"Bot 5",outs:0,count:"2-0",runners:[1],score:[3,3]},
      options:["Yes — all the green light factors are still there","No — your best hitter can drive you in from first, don't risk the out","Steal — but only if the hitter gives you a sign he's taking","Delayed steal to catch them off guard"],
      best:1,explanations:["The green light factors ARE there for the steal itself — but game context overrides. Your best hitter batting .380 with extra-base power can drive you in from first base without you needing to steal. An extra-base hit scores you from first. A single to the gap scores you from first with your speed. Risking an out removes a baserunner in front of your most dangerous hitter.","Correct! When your best hitter is up batting .380, he doesn't need you at second to drive you in. His extra-base power means a double or triple scores you from first. Getting thrown out stealing removes the baserunner and pressure from the at-bat. Trust your best hitter. He's your highest-probability scoring event regardless of your base.","Waiting for a take sign adds communication complexity for marginal gain, because the bigger point is that your best hitter doesn't need you at second.","A delayed steal is creative but unnecessary, since the best play is the simplest one: let your .380 hitter hit."],
      rates:[35,82,30,25],concept:"Don't steal in front of your best hitter — his bat is a higher-probability scoring event than your legs",anim:"hit"},
    {id:"r_vc2d",title:"Steal Decision — Double Steal with 1st and 3rd",diff:3,cat:"baserunning",conceptTag:"first-third",ageMin:12,ageMax:99,
      description:"Runners on 1st and 3rd, 1 out, your team is down by 1. The runner on first is fast. The count is 1-1. The catcher has an average arm. Your coach gives the double steal sign. When should the runner on first go?",
      situation:{inning:"Bot 6",outs:1,count:"1-1",runners:[1,3],score:[2,3]},
      options:["Go on the pitch — both runners break simultaneously","Runner on 1st goes on the pitch, runner on 3rd reads the catcher's throw","Runner on 1st goes on the pitch, runner on 3rd goes when the throw leaves the catcher's hand","Runner on 1st fakes a steal to draw the throw, runner on 3rd scores on the throw to second"],
      best:1,explanations:["Both runners breaking simultaneously tips off the defense too early, because the catcher sees the runner on third break and either throws home or fakes to second and throws home. You need the element of the catcher committing to second before the runner on third goes.","Correct! The classic 1st-and-3rd double steal: the runner on first breaks on the pitch like a normal steal. The runner on third reads the catcher. If the catcher throws to second, the runner on third breaks home. If the catcher fakes or throws home, the runner on third stays and the runner on first either steals second or gets back. The key is the READ — the runner on third decides based on the catcher's throw, not a predetermined break.","Going when the throw 'leaves the catcher's hand' is often too late — by the time you read the release, the throw is already at second and the middle infielder can redirect home. The read should happen when the catcher commits his body toward second — before the release.","The fake steal can work but is less reliable because the catcher may not bite. If the catcher holds the ball, you've achieved nothing. The straight steal with a read is a higher-percentage play."],
      rates:[25,82,40,45],concept:"On the 1st-and-3rd double steal, the runner on third READS the catcher's throw — never break on a predetermined signal",anim:"steal"},
    {id:"r_hr1",title:"Hit and Run — Batter Swings and Misses",diff:2,cat:"baserunning",conceptTag:"hit-and-run",ageMin:11,ageMax:99,
      description:"Runner on 1st, 1 out. The hit-and-run is on. You break on the pitch, but the batter swings and misses. The catcher catches the ball cleanly. What do you do?",
      situation:{inning:"Top 4",outs:1,count:"1-1",runners:[1],score:[2,2]},
      options:["Keep running — commit to the steal and hope you beat the throw","Stop and get back to first as quickly as possible","Stop halfway and get in a rundown to buy time","Slide headfirst into second — surprise them with aggression"],
      best:0,explanations:["Correct! Once the hit-and-run is on and you've broken, you're committed — the risk is already taken and your success rate from a running start often exceeds the break-even threshold. Stopping or hesitating is the worst thing you can do — you'll be in no-man's land between bases and an easy out. Your jump was timed to the pitch, so you have a full stride. Keep running hard to second. Even if the catcher catches it cleanly, you have a fighting chance if your jump was good. The hit-and-run gives you a better jump than a straight steal because you go on the pitch, not on the catcher's throw.","Trying to get back to first is almost always too late once the hit-and-run has been called and you've broken toward second, which means you're already several steps toward second. Reversing direction means you'll be tagged out in a rundown. You've lost your momentum and the catcher has a clear throw.","Getting in a rundown on purpose wastes time and energy, and with 1 out it just gives the defense an easy second out with no upside, because a rundown only helps if there's another runner who can advance — here there isn't.","Sliding headfirst doesn't change the physics of the play, because your speed and jump determine whether you're safe, not the slide technique you choose. A standard feet-first slide is actually safer and more practiced for most players. A headfirst slide can actually slow you down if you're not practiced at it."],
      rates:[72,15,20,55],concept:"On the hit-and-run, if the batter misses, keep running — you're committed and stopping makes it worse",explSimple:["Once the hit-and-run is on and you've broken, you're committed.","Trying to get back to first is almost always too late.","Getting in a rundown on purpose wastes time and energy, and with 1 out, it just gives the defense an easy second out.","Sliding headfirst doesn't change the physics."],anim:"steal"},
    {id:"r_sl1",title:"What Is a Secondary Lead?",diff:1,cat:"baserunning",conceptTag:"secondary-lead",ageMin:9,ageMax:99,
      description:"You're a runner on first base. The pitcher delivers the ball to the plate and the catcher catches it for a called strike. What should you do with your feet as the pitch is being thrown?",
      situation:{inning:"Bot 3",outs:1,count:"0-1",runners:[1],score:[1,1]},
      options:["Stay on first base — don't risk getting picked off","Take 2\u20133 shuffle steps toward second as the pitch is thrown — your secondary lead","Sprint toward second as soon as the pitcher throws home","Take a big step and then freeze to watch the play"],
      best:1,explanations:["Staying glued to the base means you can't react to passed balls, wild pitches, or base hits, since every runner should take a secondary lead on every pitch.","As the pitcher delivers home, shuffle 2\u20133 quick steps toward second base. This is your secondary lead — it puts you in a better position to advance on a wild pitch, passed ball, or hit. After the catcher catches the ball, shuffle back toward first. Every good baserunner does this on every single pitch.","Sprinting toward second is stealing, not a secondary lead, because without a steal sign, you'll be an easy out if the catcher throws down. A secondary lead is a controlled shuffle, not a sprint.","Freezing after one step defeats the purpose, since the secondary lead is a continuous shuffle that keeps you moving and ready to react. Standing still makes you flat-footed."],
      rates:[20,85,30,25],concept:"Take a secondary lead on every pitch — 2\u20133 shuffle steps toward the next base as the ball is delivered",explSimple:["Staying on the base means you can't react to anything. Always take a secondary lead!","Take 2\u20133 shuffle steps toward second as the pitch is thrown. This is your secondary lead.","Sprinting toward second is stealing, not a secondary lead. A secondary lead is a controlled shuffle.","Freezing after one step defeats the purpose. Keep shuffling!"],anim:"advance"},
    {id:"r_sl2",title:"Secondary Lead — Reading the Pitch Result",diff:2,cat:"baserunning",conceptTag:"secondary-lead",ageMin:9,ageMax:99,
      description:"You're on second base with one out. You take your secondary lead as the pitch is thrown. The pitch bounces in the dirt in front of the catcher and kicks off to his right. The catcher scrambles after it. What do you do?",
      situation:{inning:"Top 6",outs:1,count:"1-2",runners:[2],score:[2,3]},
      options:["Hold at second — the catcher might recover quickly","Advance to third — the ball got away and you had a good secondary lead","Go halfway and wait to see if the catcher picks it up","Sprint all the way home — the ball is loose"],
      best:1,explanations:["Holding when the ball gets away wastes the whole point of your secondary lead, which means you took those shuffle steps precisely so you could react to a ball in the dirt. If the catcher is scrambling, go!","Your secondary lead put you in perfect position. The ball kicked away from the catcher and he's scrambling to his right — his throw to third will be difficult. Advance aggressively to third base. This is exactly why good baserunners take a secondary lead on every pitch — it turns wild pitches into free bases.","Going halfway is hesitation, and hesitation gets you thrown out in no-man's land, because either commit to going or stay put. With the ball kicked away from the catcher, you should commit to third.","Trying to score from second on a ball that only kicked a few feet away is too aggressive, since the catcher will likely recover before you can reach home. Take the sure base at third and put yourself 90 feet from scoring."],
      rates:[20,85,30,15],concept:"A good secondary lead turns wild pitches and passed balls into free bases — react aggressively when the ball gets away",explSimple:["Holding when the ball gets away wastes your secondary lead. Go!","Your secondary lead put you in perfect position. The ball got away — advance to third!","Going halfway is hesitation. Commit to going or stay put.","Trying to score from second on a ball that only kicked a few feet away is too risky."],anim:"advance"},
    {id:"r_lf1",conceptTag:"learning-from-failure",title:"Picked Off Last Inning — Back on First",diff:2,cat:"baserunning",ageMin:10,ageMax:99,
      description:"Last inning you got picked off at first because you were taking too big a lead and not watching the pitcher's feet. Now you're back on first base with one out. The same left-handed pitcher is on the mound. What do you adjust?",
      situation:{inning:"Top 6",outs:1,count:"1-0",runners:[1],score:[3,4]},
      options:["Take an even bigger lead to prove you're not scared","Shorten your lead slightly and watch the pitcher's feet — if he steps toward home, you go; if he steps toward first, you get back","Stay glued to the base and don't lead off at all","Take the same lead as before — it was just bad luck"],
      best:1,explanations:["Taking a bigger lead after getting picked off is repeating the same mistake with more risk, since the pitcher already showed he'll throw over and he knows you're aggressive. A bigger lead makes the pickoff even easier.","Getting picked off taught you something: your lead was too long and you weren't reading the pitcher's move. The adjustment is simple — shorten your lead by one step so you can get back safely, and lock your eyes on the pitcher's front foot. A lefty who steps toward home is going to the plate; a lefty who steps toward first is picking. Reading the feet keeps you safe while still being an aggressive baserunner.","Staying on the base means you learned the wrong lesson. The goal isn't to stop leading off — it's to take a smarter lead. A shorter lead with better reads keeps you aggressive without the risk.","Calling it 'bad luck' ignores what actually happened, because you got picked off for a reason. Smart baserunners diagnose what went wrong and make a specific fix, not just hope for a different result."],
      explSimple:["A bigger lead is the same mistake but worse. The pitcher already picked you off once!","Shorten your lead a little and watch the pitcher's feet. You'll know when it's safe to go!","Staying on the base means you're too scared to run. Just take a shorter, smarter lead.","It wasn't bad luck. Figure out what went wrong and fix it!"],
      rates:[20,80,35,35],concept:"After getting picked off, shorten your lead and read the pitcher's feet — learn from the mistake instead of repeating it or overcompensating",anim:"safe"},
    {id:"r_ta1",title:"Two-Out Aggression — Bobble in Right",diff:2,cat:"baserunning",conceptTag:"two-out-aggression",ageMin:10,ageMax:99,
      description:"You're the runner on first base with 2 outs in the 5th inning. The batter lines a single to right field, but the right fielder bobbles the ball as he fields it. You're rounding second. Do you keep going to third?",
      situation:{inning:"Top 5",outs:2,count:"1-1",runners:[1],score:[2,3]},
      options:["Keep running hard to third — the bobble gives you the extra second you need","Stop at second — don't risk making the third out on the bases","Go halfway between second and third and read the throw","Retreat back to first — the ball is still in the outfield"],
      best:0,explanations:["With 2 outs, the only way you score is on a hit, so getting to third puts you 90 feet away where a wild pitch, passed ball, or single scores you. The right fielder bobbled the ball, which means his throw will be late and rushed. Aggressive baserunning with 2 outs wins games — a runner stuck at second needs a clean hit to score, but a runner at third can score on almost anything.","Stopping at second is safe, but with 2 outs you need to push for every extra base. The bobble gave you a window — if you don't take third now, you need a hit to score. Two-out aggression separates good baserunners from great ones.","Going halfway is the worst spot to be. You're not close enough to get back to second if the throw comes, and you've lost momentum toward third. With 2 outs, commit one way or the other — and the bobble says go.","Retreating to first makes no sense when the ball is in right field and the batter already singled. You should be at second at minimum, and the bobble opens third."],
      rates:[80,35,25,25],concept:"With 2 outs, push for every extra base — the only way you score is on a hit, so aggressive baserunning puts you closer to home",explSimple:["The bobble gives you the extra second you need. Take third!","Stopping at second with 2 outs means you need a clean hit to score.","Going halfway is the worst spot — commit one way or the other.","Retreating to first makes no sense when the batter singled."],anim:"advance"},
    {id:"r_ta2",title:"Two-Out Aggression — Single to Center",diff:2,cat:"baserunning",conceptTag:"two-out-aggression",ageMin:10,ageMax:99,
      description:"You're the runner on second base with 2 outs in a tie game. The batter hits a clean single to center field. The center fielder is playing at normal depth and has an average arm. The third base coach is waving you home. Do you try to score?",
      situation:{inning:"Bot 6",outs:2,count:"0-1",runners:[2],score:[4,4]},
      options:["Run hard and score — with 2 outs, you have to be aggressive on a single to center","Hold at third — don't risk making the third out at home","Score only if the center fielder bobbles it","Wait to see if the throw goes to second before you commit"],
      best:0,explanations:["With 2 outs and a tie game, you run on contact. A single to center with a normal-depth center fielder and an average arm means the throw home will be long and late. Your third base coach is waving you — he can see the play developing. Two-out scoring from second on a single to center is successful over 90% of the time in youth baseball. If you hold at third, you still need another hit to score.","Holding at third with 2 outs leaves the scoring up to the next batter. You had a great read, a clean single, and an average arm — all signs say go. With 2 outs, the risk of staying at third (needing another hit) is greater than the risk of running home on a single.","Waiting for a bobble costs you momentum and time. By the time you see the fielder handle the ball cleanly, it's too late to score. You have to commit early with 2 outs — your read starts before the ball reaches the outfielder.","The throw is going home, not to second — the center fielder sees you running. Waiting to see where the throw goes wastes the head start you got from your secondary lead and your jump on contact."],
      rates:[80,30,20,35],concept:"With 2 outs, score from second on a single to center — the coach is waving and the math says go",explSimple:["With 2 outs and a tie game, run hard and score on a single to center.","Holding at third with 2 outs means you still need another hit to score.","Waiting for a bobble costs you momentum. Commit early with 2 outs.","The throw is going home, not second. Don't wait — run on contact."],anim:"score"},
    {id:"r_ta3",title:"Two-Out Aggression — Running Hard on a Grounder",diff:2,cat:"baserunning",conceptTag:"two-out-aggression",ageMin:10,ageMax:99,
      description:"You're the runner on first with 2 outs in the 7th. The batter hits a routine ground ball to the shortstop. How hard do you run to second base?",
      situation:{inning:"Top 7",outs:2,count:"2-2",runners:[1],score:[1,3]},
      options:["Sprint as hard as you can — force the shortstop to make a perfect throw","Jog to second — the play is at first base, not second","Run at three-quarter speed to save energy for the next inning","Peel off and head to the dugout — it's a routine groundout"],
      best:0,explanations:["With 2 outs, every ground ball is a chance for an error. Sprinting hard to second forces the shortstop to rush the throw, and a rushed throw can sail, skip, or pull the first baseman off the bag. You also beat out more throws than you'd expect when you're running full speed from the crack of the bat. The inning isn't over until the out is recorded.","Jogging with 2 outs is giving up before the play is finished. Shortstops make throwing errors on routine grounders more often than you'd think, and if you're jogging, you can't take advantage. Full effort on every play, especially with 2 outs.","Three-quarter speed is three-quarter effort, and three-quarter effort with 2 outs is unacceptable. If the shortstop bobbles or throws wild, you need to be at second base, not between first and second. Sprint every time.","Never assume an out before it happens. Peeling off toward the dugout on a ground ball is the worst habit a baserunner can develop — you'll miss free bases all season when fielders make errors."],
      rates:[80,25,25,35],concept:"With 2 outs, sprint on every ground ball — errors happen, and you can only take advantage if you're running full speed",explSimple:["Sprint hard and force the shortstop to make a perfect throw.","Jogging with 2 outs is giving up before the play is over.","Three-quarter speed means you can't take advantage of errors.","Never assume an out. Sprint until the umpire calls it."],anim:"advance"},
    {id:"r_ga1",title:"Gap Awareness — Left-Center Opening",diff:2,cat:"baserunning",conceptTag:"gap-awareness",ageMin:11,ageMax:99,
      description:"You're the runner on first base with 1 out. Before the pitch, you notice the center fielder is shading toward right-center, leaving a bigger gap in left-center. The batter lines a drive into the left-center gap. How do you run the bases?",
      situation:{inning:"Bot 4",outs:1,count:"1-0",runners:[1],score:[1,2]},
      options:["Run hard all the way — you read the gap pre-pitch and know you can reach third","Stop at second — a single to left-center is only good for one base","Round second hard but come back — don't get greedy","Wait to see if the ball gets past the outfielders before committing to third"],
      best:0,explanations:["Your pre-pitch awareness pays off here. You noticed the center fielder shading toward right-center, so you knew the left-center gap was wide open. When the ball is hit into that gap, you already know the outfielders have a long run to get to the ball. Combine that knowledge with an aggressive first-to-third mindset and you reach third standing up. Smart baserunners do their homework before the pitch.","Stopping at second ignores the information you gathered before the pitch. The center fielder was shading right-center — the ball went left-center. A longer run for the outfielders means a delayed throw. You had a pre-pitch read that should have you thinking third from the crack of the bat.","Rounding second hard and coming back wastes a perfect read. You saw the gap pre-pitch — commit to third. Hesitation at second means you read the defense but didn't trust your own scouting. If you identified the gap, run like you mean it.","Waiting to see if the ball gets past the outfielders costs you the extra base. By the time you confirm the ball is in the gap, you've lost two full seconds of running time. Your pre-pitch read should trigger your decision — commit to third on contact."],
      rates:[80,30,25,30],concept:"Pre-pitch gap awareness gives you a head start — when you see the outfield shifting, you already know where the ball can land and how far you can go",explSimple:["You read the gap pre-pitch. Commit to third on contact!","Stopping at second wastes your pre-pitch read of the gap.","Rounding second and coming back means you didn't trust your own scouting.","Waiting to see the ball in the gap costs you two full seconds. Commit early!"],anim:"advance"},
    {id:"r_ga2",title:"Gap Awareness — Shortstop Up the Middle",diff:2,cat:"baserunning",conceptTag:"gap-awareness",ageMin:11,ageMax:99,
      description:"You're the runner on second base with 1 out. Before the pitch, you notice the shortstop is playing up the middle, closer to second base than normal. The batter singles to the right side, through the hole between first and second. How aggressively do you run?",
      situation:{inning:"Top 3",outs:1,count:"0-0",runners:[2],score:[0,0]},
      options:["Score easily — the shortstop playing up the middle means no one can cut off the throw from right field quickly","Score, but only because the ball got through — the shortstop position didn't matter","Hold at third — a single to right from second base is only a one-base advance","Round third hard, read the right fielder's arm, then decide"],
      best:0,explanations:["Your pre-pitch read of the shortstop pays off. With the shortstop shaded toward second, the hole on the right side was bigger, and more importantly, the cutoff alignment is disrupted. The shortstop has to cover more ground to get into cutoff position for a throw from right field, which means the relay home will be late. You knew before the pitch that a right-side hit would give you a clear path to score.","The ball getting through is only half the story. You can score easily because the shortstop is out of position for the cutoff throw. A right-side single with the shortstop playing up the middle means a slower relay to home — your pre-pitch awareness turns a close play into an easy score.","Holding at third with 1 out and a single to right ignores your positional advantage. You read the defense before the pitch and knew the right side was open. With the shortstop out of cutoff position, the throw home will be late. Score the run.","Rounding and reading wastes the advantage your pre-pitch awareness gave you. You already know the shortstop is out of position — commit to scoring on contact. By the time you stop to read the throw, you've lost your momentum."],
      rates:[80,40,20,25],concept:"When the shortstop plays up the middle, the cutoff relay on right-side hits is delayed — pre-pitch awareness of infield positioning helps you score from second",explSimple:["The shortstop is out of cutoff position. Score on the single!","The ball getting through is only half the story — the cutoff relay is delayed.","Holding at third wastes your pre-pitch defensive read.","Rounding and reading wastes time. You already know the relay will be late."],anim:"score"},
    {id:"r_ga3",title:"Gap Awareness — Double-Play Depth Grounder",diff:3,cat:"baserunning",conceptTag:"gap-awareness",ageMin:13,ageMax:99,
      description:"You're the runner on first base with 0 outs in a 1-run game. The infield is playing at double-play depth — slightly back and shading toward second. The batter hits a sharp ground ball to the right side. The second baseman fields it cleanly. What's your read?",
      situation:{inning:"Bot 5",outs:0,count:"1-1",runners:[1],score:[3,4]},
      options:["Slide hard into second to break up the double play — make the pivot man earn it","Run straight through the bag at second — don't slow down for a slide","Take a wide turn at second and read whether the throw goes to first","Peel off the baseline early — the double play is inevitable"],
      best:0,explanations:["When the infield is at double-play depth and a grounder goes to the right side, the double play is the defensive priority. Your job as the baserunner is to make the pivot man's job as hard as possible. A hard, legal slide into second base forces the shortstop or second baseman covering the bag to hurry the relay throw to first. A disrupted relay often sails wide or arrives late, saving the batter from the double play. You recognized the double-play depth pre-pitch and prepared mentally.","Running straight through the bag makes the pivot man's job easy — he has a clean lane to catch, touch, and throw without worrying about a slide. A legal, hard slide forces him to adjust his footwork and rush the throw. At double-play depth, every fraction of a second matters, and your slide creates that pressure.","Taking a wide turn only makes sense on extra-base hits, not on a ground ball to the right side with 0 outs. You should be focused on reaching second and breaking up the relay, not setting up for third base on a grounder.","Peeling off assumes the double play is guaranteed, and it never is. Rushed relay throws go wide, bad hops happen, and a hard slide can rattle the pivot man. Your job as a baserunner is to fight for every out — never concede the play."],
      rates:[80,30,25,30],concept:"At double-play depth, your job as the runner is to slide hard and legally into second — disrupting the relay can save the batter from the double play",explSimple:["Slide hard into second to force the pivot man to rush his throw.","Running straight through makes the pivot man's job too easy.","A wide turn only helps on extra-base hits, not on grounders.","Never concede the double play. Fight for every out."],anim:"doubleplay"},
    {id:"r_st1",title:"Slide Technique — Steal of Second",diff:1,cat:"baserunning",conceptTag:"slide-technique",ageMin:9,ageMax:99,
      description:"You're stealing second base. As you approach the bag, you see the shortstop is set up on the right-field side of the base, waiting for the throw from the catcher. The tag will come from the right. Which slide do you use?",
      situation:{inning:"Top 3",outs:0,count:"1-0",runners:[1],score:[0,0]},
      options:["Slide to the left side of the bag — away from the tag","Slide headfirst straight into the middle of the bag","Slide feet-first directly into the shortstop's glove","Pop-up slide so you can get to your feet quickly"],
      best:0,explanations:["When the tag is coming from the right side, you slide to the left side of the base — away from the tag. Your hand or foot reaches the far corner of the bag while the shortstop has to sweep his glove across to find you. This extra distance the tag has to travel can be the difference between safe and out. Smart baserunners always read where the fielder is set up before choosing their slide direction.","A headfirst slide straight into the middle of the bag puts your hands right into the tag zone. The shortstop is set up on the right side with the glove waiting — sliding into the center of the bag is sliding into the tag. Go to the opposite side of the fielder.","Sliding feet-first into the fielder's glove is the easiest tag in baseball. You want to make the fielder move his glove to find you, not deliver yourself right to him.","A pop-up slide is for when you need to immediately stand up — like advancing on an overthrow. On a straight steal attempt, your priority is avoiding the tag, not getting to your feet. Slide away from the tag first."],
      rates:[82,25,20,38],concept:"On a steal, read where the fielder is set up and slide to the opposite side of the bag — make the tag travel the longest distance possible",explSimple:["Slide to the left, away from the tag on the right. Make the fielder reach!","Sliding straight into the middle puts your hands right into the tag zone.","Sliding into the fielder's glove is the easiest tag in baseball.","A pop-up slide is for overthrows, not steal attempts. Avoid the tag first."],anim:"steal"},
    {id:"r_st2",title:"Slide Technique — Wild Pitch at Home",diff:1,cat:"baserunning",conceptTag:"slide-technique",ageMin:9,ageMax:99,
      description:"You're the runner on third base. The pitch bounces in the dirt and gets past the catcher, rolling about 15 feet behind home plate. Your coach waves you home. The catcher is scrambling to pick up the ball. Should you slide or run through home plate?",
      situation:{inning:"Bot 7",outs:1,count:"2-2",runners:[3],score:[3,4]},
      options:["Run through home plate standing up — there's no tag play","Slide into home plate — always slide when scoring","Slide wide to the back corner of the plate to avoid the catcher","Stop and wait to see if the catcher picks up the ball"],
      best:0,explanations:["When the catcher is scrambling 15 feet behind the plate, there is no tag play at home. Sliding actually slows you down — you lose 2-3 feet of speed when you hit the ground. Run through the plate at full speed and touch it with your foot. A slide only makes sense when there is a play at the plate and you need to avoid a tag. No tag, no slide.","Sliding when there's no tag play costs you speed for no benefit. You slide to avoid a tag or to stop your momentum at a base. Home plate is the end of the run — there's nowhere to overrun to. If the catcher is 15 feet from the plate, just touch it and score.","Sliding wide to the back corner is a technique for avoiding a tag at home, but the catcher is nowhere near the plate. A wide slide adds distance and slows you down when you should just run straight through.","Stopping to watch the catcher wastes the head start you have. The wild pitch already happened — commit to scoring. By the time you stop and evaluate, the catcher may recover and throw you out at the plate."],
      rates:[82,35,25,23],concept:"When there's no tag play, run through home plate at full speed — sliding only slows you down when the catcher isn't waiting for you",explSimple:["No tag play, no slide. Run through home plate at full speed!","Sliding when nobody is tagging you just slows you down.","Sliding wide adds distance when you should run straight through.","Don't stop to watch the catcher. Commit to scoring!"],anim:"score"},
    {id:"r_st3",title:"Slide Technique — Close Play at Third",diff:2,cat:"baserunning",conceptTag:"slide-technique",ageMin:11,ageMax:99,
      description:"You're trying to advance from second to third on a single to right field. It's going to be a close play. The throw is coming from the right fielder and the third baseman is straddling the baseline, waiting with his glove low. How do you slide?",
      situation:{inning:"Top 5",outs:1,count:"0-0",runners:[2],score:[2,1]},
      options:["Hook slide to the back corner of the bag — away from the throw and the fielder's glove","Slide straight into the bag headfirst","Slide feet-first directly into the third baseman","Stand up and try to jump over the tag"],
      best:0,explanations:["The throw is coming from right field, so the third baseman's glove will be on the infield side of the bag. A hook slide to the back corner (outfield side) of the base takes you away from the tag. Your foot hooks around the back of the bag while the third baseman has to sweep his glove all the way across to find you. On close plays, the hook slide to the far corner is the difference between safe and out.","A headfirst slide into the middle of the bag puts your hands right where the tag is. The third baseman is straddling the baseline with his glove low — you're sliding into the tag. Go around the glove, not through it.","Sliding directly into the third baseman invites a hard tag and gives him the easiest possible play. Your goal is to make the tag as difficult as possible by sliding away from the glove.","Jumping over the tag looks exciting but almost never works in a real game. You lose all your momentum in the air, you can't change direction, and if you miss the base you're out. A proper slide is faster and more reliable."],
      rates:[82,25,20,38],concept:"On a close play at third with the throw from right field, hook slide to the back corner of the bag — away from the tag and the glove",explSimple:["Hook slide to the back corner, away from the throw and the glove!","A headfirst slide puts your hands right where the tag is waiting.","Sliding into the fielder gives him the easiest tag possible.","Jumping over the tag almost never works. A proper slide is faster."],anim:"safe"},
    {id:"r_ss1",title:"Sign Systems — Reading the Indicator",diff:2,cat:"baserunning",conceptTag:"sign-systems",ageMin:11,ageMax:99,
      description:"You're the runner on first base. Your third base coach gives a sequence of signs: he touches his cap, then his right ear, then his belt, then his nose. Your team's indicator is the belt touch — the sign that counts is whatever comes right after the indicator. The nose touch means 'steal.' What do you do?",
      situation:{inning:"Top 4",outs:0,count:"1-1",runners:[1],score:[1,1]},
      options:["Steal on the next pitch — the nose touch after the belt indicator means steal","Stay put — the cap touch was the real sign","Stay put — you're not sure, so play it safe","Take a bigger lead but don't steal — you might have missed the sign"],
      best:0,explanations:["You read the signs correctly. The indicator system works like this: everything before the indicator is a decoy, and everything after the indicator is ignored except the very first sign following it. Cap, ear, belt (indicator), nose (steal). The nose touch came right after the belt indicator, so the sign is steal. Knowing your team's sign system and being confident in your read is what separates prepared players from hesitant ones.","The cap touch was the very first sign in the sequence — before the indicator. Signs before the indicator are decoys designed to confuse the other team. Only the sign immediately after the indicator counts.","Playing it safe when you've been given a steal sign means you missed the play your coach called. If you're unsure about signs, call time and check with your coach. But in this case, the sequence is clear: belt (indicator), nose (steal).","Taking a bigger lead without stealing ignores the sign your coach just gave you. The steal sign was clearly communicated — belt indicator followed by the nose touch for steal. Trust your read and execute the play."],
      rates:[82,25,28,30],concept:"In the indicator system, ignore everything before the indicator — the sign that counts is the first touch immediately after the indicator sign",explSimple:["Belt is the indicator, nose comes right after it. The sign is steal!","The cap touch was before the indicator — it's just a decoy.","If you're unsure, call time. But here, the sign is clear: steal.","A bigger lead without stealing ignores the coach's call. Execute the play!"],anim:"steal"},
  ],
  manager: [
    {id:"m1",title:"Intentional Walk",diff:2,cat:"late-game",conceptTag:"ibb-strategy",ageMin:6,ageMax:99,
      description:"Bottom 9th, runner on 2nd, 1 out, up by 1. The .310 hitter steps up. .220 hitter (8 HRs) on deck.",
      situation:{inning:"Bot 9",outs:1,count:"2-1",runners:[2],score:[5,4]},
      options:["Walk him — set up the DP","Pitch to him","Walk both — load bases","Bring in a new pitcher"],
      best:0,explanations:["Walking the .310 hitter sets up a force at every base + potential DP, because the .220 hitter on deck strikes out more.","Pitching to a .310 hitter in a 1-run 9th is risky, because the downside outweighs the potential gain.","Loading bases means any walk/HBP/error scores the tying run.","A cold reliever with runners on is worse."],
      explSimple:["Walk the better hitter on purpose! Then you can get a force out at any base, and the next batter isn't as good.","Pitching to their best hitter when the game is this close is really risky.","Walking both batters puts runners everywhere, and then even a little mistake ties the game.","Bringing in a new pitcher who hasn't warmed up with runners on base is a bad idea."],
      rates:[80,40,15,45],concept:"Intentional walks set up force plays and let you face a weaker hitter",anim:"walk"},
    {id:"m2", conceptTag:"leverage-index",title:"Pinch Hitter Timing",diff:1,cat:"substitutions",ageMin:6,ageMax:99,
      description:"Bottom 8th, down 2, bases loaded, 1 out. Your pitcher bats next. He's been great.",
      situation:{inning:"Bot 8",outs:1,count:"0-0",runners:[1,2,3],score:[2,4]},
      options:["Pinch hit — need runs NOW","Let pitcher hit — he's earned it","Only if a good reliever is ready","Have the pitcher bunt"],
      best:0,explanations:["Bases loaded, down 2 — you need runs — pitchers bat .120. A real hitter's odds are much better.","Loyalty is nice, but the job is winning.","Can't wait for ideal conditions, which means this IS the moment.","Bunting scores 1 max, because you need 2."],
      explSimple:["The bases are loaded and you need runs! Put in a real hitter because pitchers aren't good at hitting.","The pitcher did great on the mound, but you need someone who can hit right now.","This is the perfect time to use a pinch hitter — don't wait for a better moment.","A bunt can only score one run, and you need two to catch up."],
      rates:[85,15,60,20],concept:"Use pinch hitters in high-leverage spots — pitchers can't hit",anim:"hit"},
    {id:"m3", conceptTag:"leverage-index",title:"Defensive Replacement",diff:2,cat:"late-game",ageMin:9,ageMax:99,
      description:"Top 9th, up by 1. Your LF went 3-4 with a HR but plays below-average defense. Gold Glover on bench.",
      situation:{inning:"Top 9",outs:0,count:"0-0",runners:[],score:[5,4]},
      options:["Bring in the Gold Glover","Keep the hot bat","Wait for runners","Switch if first batter gets on"],
      best:0,explanations:["Bring in the Gold Glover — in a 1-run 9th, one misplayed fly ball ties the game. Prioritize defense when you are protecting a lead.","You are trying to win NOW, and defense matters more than having a hot bat on the bench for potential extra innings.","Waiting until runners are on is too late — a misplay is what puts them on in the first place.","That misplay could BE the first batter getting on."],
      explSimple:["Put in the better fielder! One dropped ball could tie the game. Defense matters most right now.","The hot bat doesn't matter if he drops a fly ball that lets them tie the game.","Don't wait for someone to get on base — by then it's too late to switch.","The mistake that lets a runner on base might be the one that costs you the game."],
      rates:[85,30,35,40],concept:"In close late innings, prioritize defense — one play decides the game",anim:"catch"},
    {id:"m4", conceptTag:"bunt-re24",title:"Sacrifice Bunt",diff:1,cat:"plays",ageMin:6,ageMax:99,
      description:"Bottom 7th, tie. Runner on 2nd, nobody out. #7 hitter (.220) is up.",
      situation:{inning:"Bot 7",outs:0,count:"0-0",runners:[2],score:[2,2]},
      options:["Bunt the runner to 3rd","Let him swing","Hit-and-run","Squeeze play"],
      best:0,explanations:["A .220 hitter with nobody out is the perfect time to bunt, even though bunting carries the risk of giving up an out — moving the runner to third gives your team lots of ways to score — a single, a fly ball, a ground ball, even a wild pitch. This weak hitter probably won't get a hit anyway, so using the out to advance the runner is a smart trade.","A .220 hitter is more likely to make an unproductive out that doesn't advance anyone, because his contact quality is too low to reliably drive the ball into play. The bunt at least makes the out productive by moving the runner.","Hit-and-run from 2nd is risky because if the batter misses the pitch, the runner is hung out to dry between bases with nobody to protect him.","A squeeze play only works when the runner is on 3rd base, not 2nd, because the runner needs to be only 90 feet from home to score on a bunt. From second base, a bunted ball doesn't give the runner enough time to cover 180 feet."],
      explSimple:["Have him bunt! That moves the runner to third base, where he can score really easily.","This batter isn't a great hitter, so he'll probably make an out anyway. A bunt at least moves the runner.","A hit-and-run is risky because if the batter misses, the runner could get thrown out.","You can only do a squeeze play when the runner is on third, not second."],
      rates:[80,35,40,10],concept:"Sacrifice bunts are smart with weak hitters and runners in scoring position",anim:"bunt"},
    {id:"m5", conceptTag:"platoon-advantage",title:"Lefty vs. Lefty",diff:2,cat:"matchups",ageMin:9,ageMax:99,
      description:"Top 8th, up 1, runners on 1st and 3rd, 2 outs. Dangerous lefty up. Lefty specialist available.",
      situation:{inning:"Top 8",outs:2,count:"0-0",runners:[1,3],score:[4,3]},
      options:["Bring in the lefty","Trust your current pitcher","Wait until 2-0 to decide","Walk the lefty"],
      best:0,explanations:["L-on-L matchups are huge — lefties bat 30-50 points lower vs lefty pitchers, and that edge matters in a close game.","Platoon advantage is real, and your specialist is in the bullpen for exactly this moment — use him.","Waiting until 2-0 means your pitcher is already losing.","Walking puts the go-ahead run on base."],
      explSimple:["Bring in the lefty pitcher! Left-handed batters have a much harder time hitting against left-handed pitchers.","The lefty specialist is there for exactly this situation. Use him!","If you wait too long, the batter might already be winning the at-bat.","Walking the batter puts another runner on base, and that makes things worse."],
      rates:[85,45,25,35],concept:"Lefty-on-lefty matchups give a significant platoon advantage",anim:"strikeout"},
    {id:"m6", conceptTag:"steal-breakeven",title:"Stolen Base Call",diff:2,cat:"plays",ageMin:9,ageMax:99,
      description:"Bottom 6th, down 1. Fastest guy on 1st, nobody out. Slow pitcher. #3 hitter batting 1-0.",
      situation:{inning:"Bot 6",outs:0,count:"1-0",runners:[1],score:[2,3]},
      options:["Send him","Don't — let #3 drive him in","Hit-and-run","Let the runner decide"],
      best:0,explanations:["Send him — fast runner + slow pitcher + hitter's count = green light, since you get into scoring position. The break-even rate for a stolen base is 72% at the MLB level — with this matchup (fast runner, slow pitcher, hitter's count), you're well above that threshold.","He can drive him in from 2nd too — getting into scoring position makes it even easier for the #3 hitter to knock him in.","Hit-and-run is fine but straight steal has better odds here.","Managers make the tactical calls — letting the runner decide on his own takes the strategy out of your hands."],
      explSimple:["Send the fast runner! The pitcher is slow, so your runner can easily steal second base.","The batter can still drive in the run from second base, so getting there first is great.","A hit-and-run is okay, but just stealing is simpler and the runner is really fast.","The manager decides when to steal — it's part of the job!"],
      rates:[85,40,55,30],concept:"Give the steal sign when the matchup heavily favors the runner",anim:"steal"},
    {id:"m7", conceptTag:"situational-hitting",title:"Lineup Construction",diff:1,cat:"pregame",ageMin:6,ageMax:99,
      description:"Setting your lineup. Leadoff: Player A (.320, speed, walks) vs Player B (.280, 20 HRs, speed).",
      situation:{inning:"Pre",outs:0,count:"0-0",runners:[],score:[0,0]},
      options:["Player A — OBP machine","Player B — power sets the tone","Alternate by pitcher","Best hitter leads off"],
      best:0,explanations:["Player A is the OBP machine you want leading off — get on base, which means .320 + walks = highest OBP.","Power at leadoff = lower OBP = fewer baserunners.","The leadoff spot needs baserunners first — only then can power hitters drive them in.","Best hitter usually bats 2nd or 3rd in modern lineups, since it gives you the best chance of success."],
      explSimple:["Player A gets on base a lot, and that's exactly what a leadoff hitter needs to do!","The power hitter is great, but the leadoff spot needs someone who gets on base, not someone who hits home runs.","The player who gets on base the most should always bat first.","Your best hitter usually bats second or third, not first."],
      rates:[85,40,50,35],concept:"The leadoff hitter's job is to get on base — OBP is king",anim:"hit"},
    {id:"m8", conceptTag:"leverage-index",title:"Challenge the Call",diff:2,cat:"game-management",ageMin:9,ageMax:99,
      description:"Top 7th, tie. Close play at 1st — ump calls your runner out. Replay looks favorable. 1 challenge left.",
      situation:{inning:"Top 7",outs:1,count:"0-0",runners:[],score:[3,3]},
      options:["Challenge it","Save for later","Ask the bench coach","Only if clearly wrong"],
      best:0,explanations:["Challenge it — tie game, 7th inning, every baserunner matters, because the replay looks favorable, so use it.","'Saving for later' often means never using it.","Getting input is good but you already think it's favorable, since don't overthink.","Too conservative, because if replay looks good, go."],
      explSimple:["The game is tied and it looks like the call was wrong. Challenge it now because every runner matters!","If you save it for later, you might never use it. Use it when it matters!","Don't think too hard about it — if the replay looks good, challenge the call.","Don't be afraid to challenge. If you think the umpire got it wrong, speak up!"],
      rates:[80,35,50,45],concept:"Use challenges when they matter most — don't save them hoping for a better spot",anim:"safe"},
    {id:"m9", conceptTag:"times-through-order",title:"Pitching Change Timing",diff:3,cat:"pitching",ageMin:12,ageMax:99,
      description:"Your starter has thrown 95 pitches through 6. He's been great but his velocity dropped 2mph last inning. Up 2.",
      situation:{inning:"Top 7",outs:0,count:"0-0",runners:[],score:[4,2]},
      options:["Pull him — velocity drop is a red flag","Let him start the 7th","Let him face one more batter","Go to the bullpen after he allows a baserunner"],
      best:3,explanations:["Pulling a dominant pitcher with no runners on base is premature — he has been great all game, so let him start the inning.","Letting him pitch without a plan is risky — that velocity drop means fatigue is setting in, and you need a trigger point.","One more batter is not a real plan. You need a clear line in the sand, like pulling him the moment a runner reaches base.","Smart! Let him start the inning but have someone ready — first baserunner means the bullpen gets the call. This balances his dominance with the fatigue signs."],
      rates:[40,30,35,85],concept:"Have a short leash plan: let dominant pitchers continue but act on the first sign of trouble",anim:"strike"},
    {id:"m10", conceptTag:"leverage-index",title:"Closer Usage",diff:2,cat:"pitching",ageMin:9,ageMax:99,
      description:"Top 9th, up by 3. Your closer hasn't pitched in 4 days. Use him or save him?",
      situation:{inning:"Top 9",outs:0,count:"0-0",runners:[],score:[6,3]},
      options:["Use the closer","Save him for a closer game","Use a setup man","Use whoever's freshest"],
      best:2,explanations:["A 3-run lead does not need your best arm — save him for when you really need him.","Smart thinking, but you still need a competent reliever to close out the game cleanly.","Correct! The setup man can handle a 3-run lead — save the closer for a 1-run game tomorrow.","Freshest is not always best in the 9th — use the setup man who is built for these situations and save the closer for tight games."],
      explSimple:["You're winning by three runs — you don't need your best pitcher. Save him for a closer game.","Saving him is smart, but you still need a good pitcher to finish the game.","Use your setup man! He can handle a big lead, and you'll need your closer when the game is tight.","Just because a pitcher is rested doesn't mean he's the right choice. Use the setup man."],
      rates:[15,40,85,25],concept:"Save your closer for tight games — setup men can handle comfortable leads",anim:"strike"},
    {id:"m11", conceptTag:"pitch-count-mgmt",title:"When to Call Timeout",diff:1,cat:"in-game",ageMin:6,ageMax:99,
      description:"Your pitcher just gave up back-to-back singles. He's shaking his head on the mound. The cleanup hitter steps up. What do you do?",
      situation:{inning:"Top 5",outs:0,count:"0-0",runners:[1,2],score:[4,2]},
      options:["Let him figure it out — he's a competitor","Visit the mound to slow things down and refocus him","Immediately pull him for a reliever","Yell encouragement from the dugout"],
      best:1,explanations:["Letting him figure it out alone sounds tough, but a pitcher shaking his head is showing frustration — and frustrated pitchers throw emotional pitches instead of smart ones, because the cleanup hitter will feast on that.","A mound visit does three things at once: it breaks the other team's momentum (they were rolling with back-to-back hits), it gives your pitcher a deep breath to reset his nerves, and it lets you remind him of the game plan for this dangerous hitter. Sometimes 30 seconds of calm changes everything.","Pulling him after just two singles is an overreaction. Save your bullpen arms for when they're really needed — back-to-back singles with no outs can still end with zero runs if you help him refocus.","Yelling from the dugout can't slow the game down or give specific guidance, since the other team's hitters stay in rhythm, and your pitcher can't hear strategy over the crowd. A face-to-face visit is worth much more."],
      explSimple:["Even tough pitchers need help sometimes. Don't just let him struggle alone.","Go visit the mound! It gives your pitcher a chance to take a deep breath and calm down. Sometimes that's all he needs.","Two hits don't mean the pitcher is done. Don't pull him yet — just go talk to him.","Yelling from far away doesn't really help. Go out to the mound and talk to him."],
      rates:[25,85,30,20],concept:"Mound visits break momentum and refocus your pitcher — use them strategically",anim:"strike"},
    {id:"m12", conceptTag:"situational-hitting",title:"Batting Order Basics",diff:1,cat:"lineup",ageMin:6,ageMax:99,
      description:"You're setting your lineup. Where should your fastest player who gets on base a lot bat?",
      situation:{inning:"Top 1",outs:0,count:"0-0",runners:[],score:[0,0]},
      options:["Leadoff (1st)","3rd in the order","Cleanup (4th)","9th (last)"],
      best:0,explanations:["Leadoff! Your fastest, highest-OBP player bats first, because their job is to get on base and score. The leadoff hitter gets the most at-bats over a season.","3rd is traditionally for your best all-around hitter, not necessarily the fastest — that spot needs someone who can hit for average and power.","Cleanup is for your power hitter — the one who drives in runs, not steals bases.","9th is usually your weakest hitter (or a second leadoff in NL before universal DH)."],
      rates:[85,35,20,15],concept:"Leadoff hitter = speed + on-base ability. They set the table for the whole lineup",explSimple:["Great choice! Leadoff! Your fastest, highest-OBP player bats first.","Not the best move. 3rd is traditionally for your best all-around hitter, not necessarily the fastest.","Not the best move. Cleanup is for your power hitter — the one who drives in runs, not steals bases.","Not the best move. 9th is usually your weakest hitter."], anim:"advance"},
    // Batch 1 — Pitching Changes
    {id:"m13", conceptTag:"pitch-count-mgmt",title:"Starter Getting Tired",diff:1,cat:"pitching",ageMin:6,ageMax:99,
      description:"Top of the 7th, your starter has thrown 90 pitches. He gave up a double last inning and his fastball is losing velocity. Score is 4-2 your lead.",
      situation:{inning:"Top 7",outs:0,count:"0-0",runners:[],score:[4,2]},
      options:["Pull him — go to your bullpen","Let him start the 7th and see how it goes","Leave him in — he's earned the right to finish","Ask him how he feels"],
      best:0,explanations:["At 90 pitches with declining velocity and a hit given up, it's time to go to the bullpen — pitchers' injury risk and hit rate both spike after 90 pitches. Protect the lead and protect your pitcher's arm.","Letting him 'see how it goes' often means watching a lead disappear, which means by the time he gives up a run, you're bringing in a reliever with runners on and pressure.","Earning the right to finish doesn't apply when his stuff is declining, because a fresh reliever protects the lead better than a tired starter.","Asking a pitcher how he feels always gets the same answer — 'I'm fine.' Pitchers never want to come out, since that's YOUR job as manager."],
      rates:[85,35,25,40],concept:"When a starter's velocity drops and pitch count is high, go to the bullpen — protect the lead and the arm",explSimple:["Great choice! At 90 pitches with declining velocity and a hit given up, it's time to go to the bullpen.","Not the best move. Letting him 'see how it goes' often means watching a lead disappear.","Not the best move. Earning the right to finish doesn't apply when his stuff is declining.","Not the best move. Asking a pitcher how he feels always gets the same answer — 'I'm fine.' Pitchers."], anim:"freeze"},
    {id:"m14", conceptTag:"pitch-count-mgmt",title:"Back-to-Back Hits",diff:1,cat:"pitching",ageMin:6,ageMax:99,
      description:"Bot 5th, your pitcher just gave up back-to-back singles. Runners on 1st and 2nd, nobody out. He looked sharp before that. Score tied 3-3.",
      situation:{inning:"Bot 5",outs:0,count:"0-0",runners:[1,2],score:[3,3]},
      options:["Go get him — it's falling apart","Send the pitching coach to settle him down","Leave him alone — two hits happen","Warm someone up but leave him in"],
      best:3,explanations:["Two hits don't necessarily mean it's falling apart, because good pitchers give up hits — it's how they respond that matters.","A mound visit now is premature — save your mound visits for when you really need them (you only get a limited number per game).","Leaving him alone AND not warming anyone up is risky, which means what if the next batter gets a hit too?","Smart! Warm up a reliever in the bullpen as insurance, but let your pitcher work through it, because two hits aren't a disaster — he's been sharp all game. If he gives up another hit or walks someone, your reliever is ready. This protects against both scenarios."],
      rates:[30,40,25,85],concept:"After back-to-back hits, warm up a reliever but let your pitcher try to work out of it",explSimple:["Not the best move. Two hits don't necessarily mean it's falling apart.","Not the best move. A mound visit now is premature.","Not the best move. Leaving him alone AND not warming anyone up is risky.","Smart! Warm up a reliever in the bullpen as insurance, but let your pitcher work through it."], anim:"freeze"},
    {id:"m15", conceptTag:"pitch-count-mgmt",title:"Shutout but High Pitch Count",diff:1,cat:"pitching",ageMin:6,ageMax:99,
      description:"Top of the 7th, your starter is throwing a shutout — 0 runs on 3 hits. But he's already at 105 pitches. Do you let him finish?",
      situation:{inning:"Top 7",outs:0,count:"0-0",runners:[],score:[5,0]},
      options:["Pull him — 105 pitches is enough","Let him go one more inning","Leave him in to finish the shutout","Let him face one more batter and decide"],
      best:0,explanations:["A shutout is special, but arm health is more important than stats, since at 105 pitches, injury risk increases significantly. Your bullpen can hold a 5-0 lead for three innings. Protect your pitcher for the future.","One more inning could mean 120+ pitches, because that's dangerous territory for any pitcher, especially a young one.","Finishing the shutout feels great today but a torn ligament hurts for a year or more — the win is what matters, not who throws the last pitch.","He's already at 105, which means the decision should already be made. Take him out and celebrate the great outing."],
      rates:[85,35,20,30],concept:"Pitch count matters more than stats — protect your pitcher's arm even during a shutout",explSimple:["Great choice! A shutout is special, but arm health is more important than stats.","Not the best move. One more inning could mean 120+ pitches.","Not the best move. Finishing the shutout feels great today but a torn ligament hurts for a year or more.","Not the best move. He's already at 105."], anim:"freeze"},
    {id:"m16", conceptTag:"platoon-advantage",title:"Lefty-Righty Matchup",diff:2,cat:"pitching",ageMin:9,ageMax:99,
      description:"Top of the 8th, your righty reliever is on the mound. He just got the first out. But now a tough left-handed hitter comes up next. You have a lefty specialist in the bullpen.",
      situation:{inning:"Top 8",outs:1,count:"0-0",runners:[],score:[4,3]},
      options:["Bring in the lefty specialist","Leave the righty in — he just got an out","Let the righty face the lefty, then bring in the lefty for the next hitter","Wait to see how the at-bat starts"],
      best:0,explanations:["The platoon advantage is real — left-handed pitchers get left-handed hitters out at a significantly higher rate than right-handed pitchers do, because this is exactly the situation your lefty specialist exists for.","Getting one out doesn't mean the righty will get this tough lefty out, since the matchup favors the hitter against a same-side disadvantage.","Waiting to use the lefty means the tough lefty gets to face a righty — that's backwards. Use the advantage NOW.","Waiting wastes the platoon advantage, because the time to make the switch is before the at-bat, not during it."],
      rates:[85,35,25,30],concept:"Use the platoon advantage — lefty specialists exist to get tough left-handed hitters out",explSimple:["The platoon advantage is real — left-handed pitchers get left-handed hitters out at a significantly higher rate than right-handed pitchers do.","Getting one out doesn't mean the righty will get this tough lefty out.","Waiting to use the lefty means the tough lefty gets to face a righty — that's backwards.","Waiting wastes the platoon advantage."],anim:"freeze"},
    {id:"m17", conceptTag:"pitch-count-mgmt",title:"Reliever Came Back — Send Him Out Again?",diff:2,cat:"pitching",ageMin:9,ageMax:99,
      description:"Top of the 8th, your reliever was lights out in the 7th — struck out the side. He's thrown 15 pitches. Do you send him back out for the 8th?",
      situation:{inning:"Top 8",outs:0,count:"0-0",runners:[],score:[5,3]},
      options:["Send him back out — he's dealing","Bring in a fresh arm for the 8th","Let him start the 8th but have someone warming","Only send him out if the closer isn't available"],
      best:2,explanations:["Sending him back out makes sense, but you need a backup plan — what if the top of their order gets to him the second time through?","A fresh arm isn't necessary when your guy struck out the side on just 15 pitches, which means don't fix what isn't broken.","Let him ride the wave but have insurance, because he's sharp and only threw 15 pitches, so he should start the 8th. But have someone warming in case the top of the order adjusts. This covers both scenarios without wasting an arm.","Closer availability shouldn't affect whether your setup man goes back out, since manage each inning independently."],
      rates:[50,25,85,35],concept:"If your reliever is sharp on a low pitch count, send him back out — but have someone warming just in case",explSimple:["Sending him back out makes sense, but you need a backup plan.","A fresh arm isn't necessary when your guy struck out the side on just 15 pitches.","Let him ride the wave but have insurance.","Closer availability shouldn't affect whether your setup man goes back out."],anim:"freeze"},
    {id:"m18", conceptTag:"pitch-count-mgmt",title:"Bases Loaded Jam — Pull or Stay?",diff:2,cat:"pitching",ageMin:9,ageMax:99,
      description:"Bot 6th, bases loaded, 1 out. Your pitcher walked the last batter to load the bases. He's thrown 80 pitches. Their #4 hitter steps up. Score 4-3 your lead.",
      situation:{inning:"Bot 6",outs:1,count:"0-0",runners:[1,2,3],score:[4,3]},
      options:["Pull him now — bring in a fresh arm","Leave him in — let him pitch out of his own mess","Send the pitching coach for a mound visit first","Pull him only if he falls behind in the count"],
      best:0,explanations:["Your pitcher just walked a batter to load the bases — he's struggling, because you bringing in a fresh reliever to face their cleanup hitter gives you the best chance of getting out of this jam. Don't let pride cost you the game.","Letting a struggling pitcher face the other team's best hitter with the bases loaded is a recipe for disaster — the walk showed he's losing it.","A mound visit delays the decision but doesn't change the reality — he just loaded the bases, which means make the move.","Waiting until he falls behind means you're already in deeper trouble, because the time to act is now."],
      rates:[85,25,35,30],concept:"In a bases-loaded jam after a walk, bring in a fresh arm — don't let a struggling pitcher face their best hitter",explSimple:["Your pitcher just walked a batter to load the bases — he's struggling.","Letting a struggling pitcher face the other team's best hitter with the bases loaded is a recipe for disaster.","A mound visit delays the decision but doesn't change the reality — he just loaded the bases.","Waiting until he falls behind means you're already in deeper trouble."],anim:"freeze"},
    {id:"m19", conceptTag:"pitch-count-mgmt",title:"Closer Pitched Two Days in a Row",diff:2,cat:"pitching",ageMin:9,ageMax:99,
      description:"Top of the 9th, you have a 3-run lead. Your closer has pitched the last 2 days (25 pitches total). It's a save situation. Do you use him?",
      situation:{inning:"Top 9",outs:0,count:"0-0",runners:[],score:[6,3]},
      options:["Use your closer — it's a save situation","Rest him — use your setup man to close","Use the closer only if the tying run gets to the plate","Bring in your closer but pull him early if he struggles"],
      best:1,explanations:["Using your closer three days in a row risks injury and burnout, since with a 3-run cushion, your setup man should be able to handle it.","Smart! A 3-run lead gives you a cushion, because your setup man or another reliever can close this game while your closer rests. If it was a 1-run lead, you might use the closer. But 3 runs gives you flexibility to protect his arm for tomorrow.","Waiting until the tying run reaches the plate means your closer enters in a higher-pressure spot — since worse for a tired arm.","Starting him and pulling him early wastes his availability for tomorrow without getting full value."],
      rates:[35,85,40,25],concept:"With a big lead, rest your closer — save him for closer games tomorrow",explSimple:["Using your closer three days in a row risks injury and burnout.","A 3-run lead gives you a cushion.","Waiting until the tying run reaches the plate means your closer enters in a higher-pressure spot — worse for a tired arm.","Starting him and pulling him early wastes his availability for tomorrow without getting full value."],anim:"freeze"},
    {id:"m20", conceptTag:"pitch-count-mgmt",title:"No-Hitter Through 6 — High Pitch Count",diff:3,cat:"pitching",ageMin:12,ageMax:99,
      description:"Top of the 7th, your starter has a no-hitter going through 6 innings. But he's thrown 105 pitches. He walked 4 batters. Score is 2-0.",
      situation:{inning:"Top 7",outs:0,count:"0-0",runners:[],score:[2,0]},
      options:["Pull him — 105 pitches with 4 walks means he's laboring","Let him try for the no-hitter — it's special","One more inning, then pull him regardless","Ask him if his arm feels okay"],
      best:0,explanations:["A no-hitter is exciting, but 105 pitches with 4 walks tells you he's not in control — he's working hard for every out. Adding 15-20 more pitches in the 7th risks his arm AND the lead. The smart move is to protect both.","No-hitters are magical, but arm health is permanent, which means plus, the 4 walks show he's been wild — a hit is likely eventually. Protect the lead and the arm.","One more inning could mean 125+ pitches, because at 105 with 4 walks, he's already past the safe zone.","Pitchers always say they feel fine, since the data (105 pitches, 4 walks) tells you more than his pride does."],
      rates:[85,20,30,25],concept:"Pitch count and control matter more than chasing a no-hitter — protect the arm and the win",anim:"freeze"},
    {id:"m21", conceptTag:"leverage-index",title:"Best Reliever — Use Now or Save?",diff:3,cat:"pitching",ageMin:12,ageMax:99,
      description:"Bot of the 6th, runners on 1st and 3rd, 1 out. Your best reliever is available, but it's only the 6th. Their best hitter steps to the plate. Score tied 3-3.",
      situation:{inning:"Bot 6",outs:1,count:"0-0",runners:[1,3],score:[3,3]},
      options:["Use him now — this is the highest-leverage moment","Save him for the 8th or 9th","Use your second-best reliever now","Bring in your best but only for this batter"],
      best:0,explanations:["This is the moment that decides the game — runners on the corners, their best hitter up, tie game, because your best reliever should face the highest-leverage situation, NOT the last three outs. Analytics prove that saves are overrated — leverage is what matters.","Saving him for a hypothetical future situation when a REAL crisis is happening right now is bad managing. What if you never have a lead to protect?","Your second-best reliever against their best hitter in the biggest moment is a mismatch — use your ace.","Using him for just one batter is possible, but if he gets this out, you might want him for the next batter too, which means let him work."],
      rates:[85,20,35,50],concept:"Use your best reliever in the highest-leverage situation — that's not always the 9th inning",anim:"freeze"},
    {id:"m22", conceptTag:"platoon-advantage",title:"Lefty-Righty vs Switch Hitter",diff:3,cat:"pitching",ageMin:12,ageMax:99,
      description:"Top of the 8th, 1 out, runner on 2nd, up 5-4. Their best hitter bats as a switch hitter. You have both a lefty and righty reliever available. Does the platoon advantage apply?",
      situation:{inning:"Top 8",outs:1,count:"0-0",runners:[2],score:[5,4]},
      options:["Bring in the lefty — force him to bat righty","Bring in the righty — force him to bat lefty","It doesn't matter — switch hitters negate the platoon","Bring in whoever has been pitching better lately"],
      best:3,explanations:["Bringing in the lefty forces a righty at-bat, but if the switch hitter is better from the right side, you've helped him — that's why this approach matters in this situation.","Bringing in the righty to force him to bat lefty has the same risk — you might be forcing him into his stronger side.","It matters a little, but not in the traditional platoon way, because switch hitters do often have a weaker side.","Smart! Bring in whoever has been pitching better lately. Against switch hitters, the traditional platoon advantage is reduced, since instead, use the reliever who has been the most effective recently, regardless of handedness. The pitcher's current form, stuff, and confidence matter more than which side the batter stands on."],
      rates:[30,30,35,85],concept:"Against switch hitters, use your most effective reliever — handedness matters less than performance",anim:"freeze"},
    // Batch 2 — Offensive Strategy Calls
    {id:"m23", conceptTag:"bunt-re24",title:"Sacrifice Bunt or Swing Away?",diff:1,cat:"plays",ageMin:6,ageMax:99,
      description:"Bot 7th, runner on 1st, nobody out, down 3-2. Your #8 hitter steps to the plate — he's batting .190 today. The tying run is on first.",
      situation:{inning:"Bot 7",outs:0,count:"0-0",runners:[1],score:[2,3]},
      options:["Bunt the runner to second","Let him swing away","Hit and run","Have him take pitches and hope for a walk"],
      best:0,explanations:["With a weak hitter up and the tying run on first, the sacrifice bunt is the smart play, because you move the runner to second (scoring position) so a single from your #9 or leadoff hitter ties the game. You're trading a weak at-bat for a runner in scoring position — the tradeoff statistically favors bunting with a .190 hitter.","A .190 hitter makes an out over 80% of the time — use that likely out productively by bunting — advancing the tying run to scoring position gives your better hitters a chance to drive him in.","A hit and run with a .190 hitter is risky — because if he misses, the runner gets thrown out stealing.","Hoping for a walk is too passive in a one-run game, which means think about what gives your team the best result here."],
      rates:[85,30,25,20],concept:"With a weak hitter and a runner to advance, the sacrifice bunt is a productive out",explSimple:["Great choice! With a weak hitter up and the tying run on first, the give-up bunt is the smart play.","Not the best move. A .190 hitter is more likely to make an out than get a hit.","Not the best move. A hit and run with a .190 hitter is risky — if he misses,.","Not the best move. Hoping for a walk is too passive in a one-run game."], anim:"bunt"},
    {id:"m24", conceptTag:"bunt-re24",title:"Down by One in the 9th — Bunt or Hit?",diff:1,cat:"plays",ageMin:6,ageMax:99,
      description:"Bot 9th, runner on 1st, nobody out, down 4-3. Your leadoff hitter just singled. Your #2 hitter steps to the plate — he's a good contact guy who's been hitting well.",
      situation:{inning:"Bot 9",outs:0,count:"0-0",runners:[1],score:[3,4]},
      options:["Sacrifice bunt — move the runner to scoring position","Let him hit — he's been hot","Hit and run — put pressure on the defense","Have him bunt for a hit — get two runners on"],
      best:1,explanations:["Bunting gives away an out when your #2 hitter has been hitting well, because you're turning your good hitter into a free out for the defense. Statistics show teams score fewer runs when they bunt with good hitters — let him swing and create multiple ways to score.","He's been hot — let him hit! He's your #2 hitter because he's one of your best bats. A single puts runners on 1st and 3rd with nobody out. A double ties or wins the game. Don't waste good at-bats on sacrifice bunts. When a good hitter bunts, your team actually scores fewer runs on average — a strong hitter swinging away is always worth more than giving away an out with a sacrifice.","A hit and run is aggressive but restricts the batter's approach, since when he's already hitting well, let him pick his pitch. When a batter is seeing the ball well, don't take the bat out of his hands with restrictions.","Bunting for a hit is lower percentage than just letting him swing normally. Even a great bunter only gets on base about 40% of the time bunting for a hit, while your hot hitter is likely to do better just swinging away."],
      rates:[40,85,50,30],concept:"Don't sacrifice bunt with your good hitters — let them swing and produce",explSimple:["Not the best move. Bunting gives away an out when your #2 hitter has been hitting well.","Great choice! Let your hot hitter swing! He's your #2 hitter because he's one of your best bats.","Not the best move. A hit and run is aggressive but restricts the batter's approach.","Not the best move. Bunting for a hit is lower percentage than just letting him swing normally."], anim:"hit"},
    {id:"m25", conceptTag:"squeeze-play",title:"Bases Loaded, Nobody Out — Squeeze?",diff:1,cat:"plays",ageMin:6,ageMax:99,
      description:"Top of the 4th, bases loaded, nobody out, up 2-0. Your #6 hitter steps to the plate. The pitcher has been wild.",
      situation:{inning:"Top 4",outs:0,count:"0-0",runners:[1,2,3],score:[2,0]},
      options:["Squeeze bunt — guarantee a run","Let him swing — bases loaded with a wild pitcher","Hit and run","Take all the way — walk forces a run"],
      best:1,explanations:["A squeeze bunt with bases loaded and nobody out limits you to one run, because with nobody out and a wild pitcher, you could score 3-4 runs this inning.","With bases loaded, nobody out, and a wild pitcher, let your hitter swing, since any hit scores runs. A walk forces a run in. An error scores runs. Everything good can happen — don't limit yourself to one run with a squeeze bunt.","A hit and run with bases loaded is unnecessary, since as the runners will be moving on contact with nobody out anyway.","Taking is okay if the pitcher is truly wild, but your hitter should be ready to drive a mistake pitch, which is why this approach matters in this situation."],
      rates:[30,85,20,45],concept:"Bases loaded with nobody out and a wild pitcher — don't squeeze for one run when you can score several",explSimple:["Not the best move. A squeeze bunt with bases loaded and nobody out limits you to one run.","Great choice! With bases loaded, nobody out, and a wild pitcher, let your hitter swing.","Not the best move. A hit and run with bases loaded is unnecessary — the runners will be moving.","Not the best move. Taking is okay if the pitcher is truly wild, but your hitter should be ready."], anim:"hit"},
    {id:"m26",title:"Steal or Hit and Run?",diff:2,cat:"plays",conceptTag:"steal-breakeven",ageMin:11,ageMax:99,
      description:"Bot 5th, runner on 1st, 1 out, tied 2-2. Your fastest player is on first. The pitcher delivers slowly. Count is 1-0.",
      situation:{inning:"Bot 5",outs:1,count:"1-0",runners:[1],score:[2,2]},
      options:["Straight steal — he's your fastest player","Hit and run — the batter must make contact","Let the batter hit naturally","Sacrifice bunt to move the runner"],
      best:0,explanations:["Your fastest player against a slow pitcher is a stolen base waiting to happen, which means a straight steal doesn't require the batter to do anything — the runner handles it himself. On 1-0 against a slow pitcher, this is high-percentage.","A hit and run makes the batter swing at whatever comes — it could be a bad pitch, because the straight steal is cleaner and doesn't restrict the batter.","Letting the batter hit naturally is fine but doesn't use your speed advantage against the slow pitcher.","A sacrifice bunt with 1 out gives away a precious out, since save bunts for 0-out situations."],
      rates:[85,50,35,20],concept:"With your fastest runner and a slow pitcher, the straight steal is cleaner than a hit and run",explSimple:["Your fastest player against a slow pitcher is a stolen base waiting to happen.","A hit and run makes the batter swing at whatever comes — it could be a bad pitch.","Letting the batter hit naturally is fine but doesn't use your speed advantage against the slow pitcher.","A sacrifice bunt with 1 out gives away a precious out."],anim:"steal"},
    {id:"m27", conceptTag:"steal-breakeven",title:"Down by Three — Steal?",diff:2,cat:"plays",ageMin:9,ageMax:99,
      description:"Top of the 6th, runner on 1st, nobody out, down 5-2. Your runner is fast. Is this a good time to steal?",
      situation:{inning:"Top 6",outs:0,count:"0-0",runners:[1],score:[2,5]},
      options:["Steal — get in scoring position for a rally","Don't steal — play for a big inning instead","Steal only if the pitcher is slow","Bunt the runner over instead"],
      best:1,explanations:["Down by 3, you need a big inning — multiple runs, because stealing one base doesn't create a big inning. If the runner is thrown out, you've lost a baserunner when you need everyone on base.","When trailing by 3+ runs, you need a rally — multiple baserunners and hits — stealing risks losing a baserunner for just one base. The math doesn't work: you need at least 3 runs, and each baserunner is precious. Play for the big inning.","The pitcher's speed doesn't change the strategic math, which means down by 3, you play for big innings, not small ball.","Bunting gives away an out when you need baserunners, because down by 3, every out is valuable."],
      rates:[30,85,35,15],concept:"Down by 3+, don't steal or bunt — play for a big inning. You need runners, not outs",explSimple:["Down by 3, you need a big inning — multiple runs.","When trailing by 3+ runs, you need a rally — multiple baserunners and hits.","The pitcher's speed doesn't change the strategic math.","Bunting gives away an out when you need baserunners."],anim:"safe"},
    {id:"m28", conceptTag:"hit-and-run",title:"Hit and Run Goes Wrong",diff:2,cat:"plays",ageMin:9,ageMax:99,
      description:"Bot 3rd, runner on 1st, 1 out, up 3-1. You call the hit and run. The batter swings and misses. The runner is caught stealing. Was it the right call?",
      situation:{inning:"Bot 3",outs:1,count:"1-1",runners:[1],score:[3,1]},
      options:["Bad call — should never have called it","Unlucky — the hit and run was the right play","Should have called a straight steal instead","Next time, consider the situation more carefully before calling plays"],
      best:1,explanations:["Just because it didn't work doesn't mean it was the wrong call. Baseball involves probability, not certainty.","Unlucky, but the hit and run was the right play — runner on first, 1 out, 1-1 count, your team has a lead, since the batter just didn't execute. In baseball, good decisions sometimes lead to bad results. That doesn't make the decision wrong. You'd call it again in the same spot.","A straight steal doesn't put pressure on the defense the same way, because the hit and run has more upside when it works.","Hindsight analysis is useful for learning, but judging a decision only by its result is outcome bias — good plays can fail — a batter missing a pitch doesn't mean the hit and run was wrong. The reasoning was sound."],
      rates:[20,85,35,25],concept:"Good strategy sometimes fails — judge decisions by the reasoning, not just the result",explSimple:["Just because it didn't work doesn't mean it was the wrong call.","The hit and run was a reasonable call — runner on first, 1 out, 1-1 count, your team has a lead.","A straight steal doesn't put pressure on the defense the same way.","Just because it didn't work doesn't mean it was a bad call — good decisions sometimes have bad results."],anim:"safe"},
    {id:"m_hr1",title:"Hit and Run — When to Call It Off",diff:3,cat:"plays",conceptTag:"hit-and-run",ageMin:12,ageMax:99,
      description:"Runner on 1st, 1 out, tie game in the 6th. You had the hit-and-run on the last pitch but the batter fouled it off. The count is now 0-2. The runner is average speed. Do you put the hit-and-run back on?",
      situation:{inning:"Bot 6",outs:1,count:"0-2",runners:[1],score:[4,4]},
      options:["Yes — the defense won't expect it on 0-2","No — take the hit-and-run off, let the batter fight the count","Yes — but only if the pitcher throws a fastball","Switch to a straight steal — the batter can't protect the runner in an 0-2 count"],
      best:1,explanations:["'They won't expect it' is gambling, not strategy. On 0-2, the pitcher has the advantage and will likely throw something off-speed or out of the zone. The batter MUST swing on a hit-and-run, and swinging at a 0-2 waste pitch means almost certain weak contact or a miss — leaving your runner hung out to dry.","Correct! The hit-and-run on 0-2 is one of the worst calls in baseball. Here's why: on 0-2, the pitcher throws waste pitches — balls out of the zone designed to get the batter to chase. The hit-and-run FORCES the batter to swing at whatever comes, turning a potential take into a chase. The batter can't protect the runner if the pitch is a slider in the dirt or a fastball at eye level. Take the play off, let the batter work the count back, and reassess if the count improves.","You can't condition the hit-and-run on pitch type — the runner has to go before the pitch arrives. There's no way to know it's a fastball until it's too late.","A straight steal on 0-2 is slightly better than a hit-and-run (because the batter doesn't have to swing), but with an average-speed runner, the risk of a caught stealing still outweighs the benefit. With 0-2, the catcher might call a pitchout or the pitcher might slide-step. Better to take everything off and let the batter fight."],
      rates:[25,82,25,42],concept:"Never run the hit-and-run on 0-2 — the batter can't protect the runner when the pitcher owns the count",anim:"safe"},
    {id:"m29", conceptTag:"platoon-advantage",title:"Slumping Cleanup Hitter",diff:2,cat:"lineup",ageMin:9,ageMax:99,
      description:"Your cleanup hitter has gone 0-for-15 over the last 4 games. He's frustrated but he's still your best power hitter. Today's game matters. Do you drop him in the order?",
      situation:{inning:"Top 1",outs:0,count:"0-2",runners:[],score:[0,0]},
      options:["Drop him to 6th — send a message","Keep him at 4th — trust his talent","Move him to 2nd — more at-bats might help","Bench him — give him a day off"],
      best:1,explanations:["Dropping him sends a message of no confidence. A slumping player needs support, not a public demotion that shakes his trust.","Slumps happen to every hitter. Your cleanup hitter is in the 4-hole because of his season-long performance, not one bad week. Moving him tells the whole team you panic when things go wrong. Trust your guys.","Moving him to 2nd changes the whole lineup dynamic and doesn't fix the slump.","Benching your best power hitter in an important game because of a slump is overreacting. Unless he's hurt, he plays."],
      rates:[25,85,30,20],concept:"Trust your best hitters through slumps — don't panic-move your lineup after a bad week",explSimple:["Dropping him sends a message of no confidence.","Slumps happen to every hitter.","Moving him to 2nd changes the whole lineup dynamic and doesn't fix the slump.","Benching your best power hitter in an important game because of a slump is overreacting."],anim:"freeze"},
    {id:"m30", conceptTag:"bunt-defense",title:"One Run Game, 8th Inning — Bunt to Third?",diff:3,cat:"plays",ageMin:12,ageMax:99,
      description:"Bot 8th, runner on 2nd, nobody out, tied 3-3. Your #3 hitter steps to the plate. Should you bunt the runner to third?",
      situation:{inning:"Bot 8",outs:0,count:"0-0",runners:[2],score:[3,3]},
      options:["Bunt to third — set up the sac fly","Let your #3 hitter swing — he can drive the run in","Hit and run — put pressure on the defense","Take a pitch first, then decide"],
      best:1,explanations:["Bunting your #3 hitter is giving away your best bat, because he can drive in the run himself with a hit.","Your #3 hitter is in that spot because he's one of your best bats. A hit scores the run. A sac fly scores the run. A ground ball to the right side scores the run. He can do all of these while swinging. Bunting him wastes your best opportunity to score.","A hit and run with a runner on second is unusual and risky, since you think about what gives your team the best result here.","Waiting a pitch doesn't help the strategic decision, because the question is bunt or hit, not what pitch to wait for."],
      rates:[30,85,35,25],concept:"Don't sacrifice your best hitters — they can drive in runs while swinging",anim:"hit"},
    {id:"m31", conceptTag:"ibb-strategy",title:"Intentional Walk to Load the Bases",diff:3,cat:"late-game",ageMin:12,ageMax:99,
      description:"Top of the 9th, runners on 2nd and 3rd, 1 out, up 5-4. Their #3 hitter steps to the plate (.320 avg). The #4 hitter on deck is a power hitter (.240 avg, 30 HRs). First base is open.",
      situation:{inning:"Top 9",outs:1,count:"0-0",runners:[2,3],score:[5,4]},
      options:["Walk him — load the bases for a force at every base","Pitch to him — .320 is scary but walking him loads the bases","Bring in a fresh reliever to face the .320 hitter","Bring in a new pitcher instead"],
      best:0,explanations:["Walking the .320 hitter to load the bases is smart here — you set up a force out at every base (including home), the possibility of a double play, and you face a .240 hitter instead. The .240 guy hits for power, but he also strikes out more.","Pitching to a .320 hitter with runners in scoring position is dangerous, which means he's more likely to drive in runs than the .240 hitter.","Bringing in a reliever changes the dynamic, but your current pitcher knows the situation, because the real question is WHO to face, not who throws — the walk to load bases and face the .240 hitter is the strongest strategic move regardless of the pitcher.","A new pitcher with the bases about to be loaded is high-pressure, since your current pitcher knows the situation."],
      rates:[85,30,35,25],concept:"Walk the better hitter to load the bases — set up forces at every base and face the weaker hitter",anim:"walk"},
    {id:"m32", conceptTag:"leverage-index",title:"Pinch Hitter — Now or Save?",diff:3,cat:"substitutions",ageMin:12,ageMax:99,
      description:"Bot 7th, runner on 2nd, 2 outs, tied 4-4. Your weakest hitter (.150) is due up. You have 2 pinch hitters on the bench — one is solid (.280) and one is your best (.310 but you might need him later).",
      situation:{inning:"Bot 7",outs:2,count:"0-0",runners:[2],score:[4,4]},
      options:["Use your best pinch hitter (.310) — this situation matters","Use the .280 hitter — save the .310 for later","Let the .150 hitter bat — save both for later","Use neither — call a different play"],
      best:0,explanations:["Use your best hitter NOW. The tying run is in scoring position with 2 outs in a tied game. There's no guarantee you'll get a better situation later. If you save your best bat and never get to use him, you wasted an advantage. The game is decided in moments like this.","The .280 hitter is solid, but this is a key moment, because if the .310 hitter can drive in the go-ahead run, the game changes. Don't save your best weapon for a situation that might not come.","Letting a .150 hitter bat in this spot is malpractice — you have better options — use them.","There's no play that replaces a good at-bat, which means use your pinch hitter."],
      rates:[85,55,10,15],concept:"Use your best pinch hitter in the current big moment — don't save him for a situation that may never come",anim:"hit"},
    // Batch 3 — Defensive Strategy
    {id:"m33", conceptTag:"leverage-index",title:"Late Game Defense — Sub in Glove Man?",diff:1,cat:"defense",ageMin:6,ageMax:99,
      description:"Top of the 9th, your team is up 3-2. Your left fielder has been great at the plate (2-for-3) but he's not a good defender. You have a great defensive outfielder on the bench.",
      situation:{inning:"Top 9",outs:0,count:"0-0",runners:[],score:[3,2]},
      options:["Sub in the defensive replacement","Leave the hitter in — his bat might be needed","Only sub if a runner gets on base","Sub in the defense for the last out only"],
      best:0,explanations:["In the 9th inning with a 1-run lead, defense is more important than offense. You're not going to bat again (you're winning). A defensive replacement in left field could be the difference between a routine catch and a ball dropping for a hit. Protect the lead with your best glove.","His bat doesn't matter — you're on defense protecting a lead, because you likely won't bat again unless the game goes to extras.","Waiting until a runner is on base is too late — given that the defensive mistake that put the runner on is exactly what you're trying to prevent.","You can't sub in 'for the last out only' — defensive substitutions last the rest of the game."],
      rates:[85,30,25,10],concept:"In late innings with a lead, defense matters more than offense — bring in your best glove",explSimple:["Great choice! In the 9th inning with a 1-run lead, defense is more important than offense.","Not the best move. His bat doesn't matter — you're on defense protecting a lead.","Not the best move. Waiting until a runner is on base is too late — the defensive mistake that.","Not the best move. You can't sub in 'for the last out only' — defensive substitutions last."], anim:"catch"},
    {id:"m34", conceptTag:"steal-window",title:"Steal Alert — Warn the Catcher",diff:1,cat:"defense",ageMin:6,ageMax:99,
      description:"Bot 6th, their fastest runner just reached first. He's stolen 25 bases this season. Your pitcher isn't paying attention. Score is 4-3 your lead.",
      situation:{inning:"Bot 6",outs:0,count:"0-0",runners:[1],score:[4,3]},
      options:["Call time and tell the catcher to watch for a steal","Tell the pitcher to use the slide step","Call a pitchout on the first pitch","Just let the battery handle it"],
      best:0,explanations:["As a manager, it's your job to recognize threats — a runner with 25 steals has a success rate well above the break-even point, making the steal threat very real, since you call timeout and remind your catcher that the fastest runner in the league is on first. Make sure the pitcher and catcher are ready for the steal attempt. Communication prevents easy stolen bases.","The slide step helps limit the runner's jump, but the whole team needs to be aware of the threat, because start with communication.","A pitchout on the first pitch is too predictable and puts your pitcher behind 1-0 in the count, giving the batter an advantage — save it for later.","Letting the battery handle it when they clearly aren't paying attention is negligent managing, which means your pitcher was oblivious to one of the league's fastest runners, and that's exactly when you need to step in and ensure everyone is alert."],
      rates:[85,55,25,15],concept:"When a dangerous basestealer reaches base, communicate — make sure your catcher and pitcher are ready",explSimple:["Great choice! As a manager, it's your job to recognize threats.","Not the best move. The slide step helps, but the whole team needs to be aware.","Not the best move. A pitchout on the first pitch is too predictable and puts your pitcher behind 1-0.","Not the best move. Letting the battery handle it when they clearly aren't paying attention is negligent managing."], anim:"freeze"},
    {id:"m35",title:"Pull Hitter at the Plate — Shift?",diff:2,cat:"defense",conceptTag:"infield-positioning",ageMin:11,ageMax:99,
      description:"Top of the 5th, nobody on, 2 outs, tied 2-2. Their left-handed cleanup hitter steps up — he's pulled every ball to the right side today. He's hit 2 hard ground balls to the right.",
      situation:{inning:"Top 5",outs:2,count:"0-0",runners:[],score:[2,2]},
      options:["Shift — move the shortstop to the right side","Play straight up — standard positioning","Shift slightly — shade toward the right but don't overshift","Only shift with the bases empty"],
      best:2,explanations:["A full shift with the shortstop on the right side is aggressive, because if he adjusts and hits the other way, there's nobody on the left side of the infield.","Playing straight up ignores the information you have, since he's pulled every ball today. Two hard ground balls to the right side is clear evidence that shading your defense makes sense.","Shade the infield toward the right side without going to an extreme shift. Move the shortstop a few steps toward second and the second baseman a few steps toward first. This takes away his pull zone while still covering the left side if he adjusts. Smart positioning uses data without overcommitting.","You can shift in any situation, because bases empty is actually the safest time to shift since no runners are on base. But the question is whether to shift fully or shade — shading is the smarter, less risky approach here."],
      rates:[40,25,85,20],concept:"Shade your defense based on the hitter's tendencies — use data but don't overcommit",explSimple:["A full shift with the shortstop on the right side is aggressive.","Playing straight up ignores the information you have.","Shade the infield toward the right side without going to an extreme shift.","You can shift in any situation."],anim:"groundout"},
    {id:"m36", conceptTag:"bunt-defense",title:"Bunt Defense — Runners on First and Second",diff:2,cat:"defense",ageMin:9,ageMax:99,
      description:"Bot 3rd, runners on 1st and 2nd, nobody out, tied 1-1. The opposing #8 hitter steps to the plate — he's likely going to bunt. What defense do you call?",
      situation:{inning:"Bot 3",outs:0,count:"0-0",runners:[1,2],score:[1,1]},
      options:["Crash the first and third basemen — charge the bunt","Have the third baseman crash, first baseman holds","Standard bunt defense — hold positions","Call the wheel play — rotation defense"],
      best:0,explanations:["With a bunt expected, crash both corner infielders. The first baseman and third baseman charge as the pitch is delivered, giving them the best chance to field the bunt and throw to third to get the lead runner. This is standard bunt defense and gives you the best chance at the out at third.","Having only the third baseman crash means the first baseman is too far back to field a bunt between the mound and first base, leaving a big gap on the right side.","Standard positioning lets the bunt drop and gives the defense less time to make a play — you have to charge it on bunt defense.","The wheel play is a more complex rotation that works best with practice — standard crash defense is more reliable unless your team has drilled the wheel play."],
      rates:[85,45,20,35],concept:"On bunt defense, crash the corners — the first and third basemen charge to field the bunt quickly",explSimple:["With a bunt expected, crash both corner infielders.","Having only the third baseman crash means the first baseman is too far back to field a bunt between the mound and first base.","Standard positioning lets the bunt drop and gives the defense less time to make a play.","The wheel play is a more complex rotation that works best with practice."],anim:"bunt"},
    {id:"m37", conceptTag:"infield-positioning",title:"Infield In or Back?",diff:2,cat:"defense",ageMin:9,ageMax:99,
      description:"Top of the 7th, runner on 3rd, 1 out, up 5-4. The hitter at the plate is a contact hitter with some pop. Do you bring the infield in?",
      situation:{inning:"Top 7",outs:1,count:"0-0",runners:[3],score:[5,4]},
      options:["Infield in — cut off the run at the plate","Infield back — play for the ground ball out","Infield halfway — compromise position","Corners in, middle back — split the difference"],
      best:3,explanations:["Full infield in gives up a lot of range — ground balls that are normally outs get through, because with a 1-run lead and 1 out, that's risky.","Infield back gives up the run on most ground balls, since the runner on 3rd scores easily on a grounder to short.","Halfway positioning doesn't give you the range of playing back or the throw home of playing in.","Corners in (1st and 3rd basemen play close) while the middle infielders play at normal depth, because the corners can throw home if the ball is hit to them, while the shortstop and second baseman maintain their range. This gives you the best of both worlds."],
      rates:[35,30,25,85],concept:"Corners in, middle back is the best compromise — you can cut off the run AND maintain range",explSimple:["Full infield in gives up a lot of range — ground balls that are normally outs get through.","Infield back gives up the run on most ground balls.","Halfway positioning doesn't give you the range of playing back or the throw home of playing in.","Corners in (1st and 3rd basemen play close) while the middle infielders play at normal depth."],anim:"groundout"},
    {id:"m38", conceptTag:"line-guarding",title:"Guard the Lines in the 9th",diff:3,cat:"defense",ageMin:12,ageMax:99,
      description:"Top of the 9th, nobody on, 2 outs, up 5-3. But the next guy up hits .340 and leads the team. A double down the line could start a rally.",
      situation:{inning:"Top 9",outs:2,count:"0-0",runners:[],score:[5,3]},
      options:["Guard the lines — move 1B and 3B closer to the foul lines","Play straight up — don't overadjust","Shift toward the pull side","Bring the outfield in to prevent extra bases"],
      best:0,explanations:["With 2 outs and a 2-run lead in the 9th, guard the lines! A double down the line keeps the inning alive and brings the tying run to the plate. A single through the normal hole is less dangerous. You'd rather give up a single up the middle than a double down the line in this situation.","Playing straight up risks a double down the line that extends the inning in the worst way — a single up the middle is less damaging than an extra-base hit.","Shifting ignores the extra-base hit risk on the non-pull side, and a double to the opposite gap is just as dangerous as one down the line.","Bringing the outfield in is for single-run situations, since with a 2-run lead, you can afford a single — you can't afford a double."],
      rates:[85,30,25,20],concept:"In the 9th with a lead, guard the foul lines — a double is more dangerous than a single",anim:"catch"},
    {id:"m39",title:"Power Hitter Up — DP or Guard Lines?",diff:3,cat:"defense",conceptTag:"dp-positioning",ageMin:11,ageMax:99,
      description:"Bot 8th, runner on 1st, nobody out, up 6-4. Their power hitter steps up — he's hit 2 homers today. But a double play ends the threat.",
      situation:{inning:"Bot 8",outs:0,count:"0-0",runners:[1],score:[6,4]},
      options:["Play for the double play — DP depth","Guard the lines — prevent extra bases","Play straight up — balanced approach","Bring the outfield way back to prevent a homer"],
      best:0,explanations:["With a runner on first and nobody out, the double play is your best friend. Move the middle infielders to DP depth. Yes, the hitter has power and hit 2 homers — but you can't prevent a homer with positioning. What you CAN control is turning a ground ball into two outs. The double play erases the threat completely.","Guarding the lines with a runner on first and nobody out gives up the double play opportunity.","Straight up is neutral but doesn't maximize the DP chance, which means think about what gives your team the best result here.","Outfield positioning doesn't prevent home runs — the ball goes over their heads regardless, because you play the infield for the DP."],
      rates:[85,30,40,15],concept:"With a runner on first and nobody out, play DP depth — a double play erases the threat",anim:"doubleplay"},
    {id:"m40", conceptTag:"of-depth-arm-value",title:"Outfielder Tired — Defensive Sub?",diff:3,cat:"defense",ageMin:12,ageMax:99,
      description:"Top of the 9th, up 4-3. Your center fielder has been struggling in the field the last few innings — he misjudged a fly ball in the 7th. You have a solid defensive CF on the bench, but only 2 bench players left.",
      situation:{inning:"Top 9",outs:0,count:"0-0",runners:[],score:[4,3]},
      options:["Sub in the defensive center fielder — protect the lead","Keep the current CF — save the bench for emergencies","Only sub if a runner gets on base","Move the right fielder to center, sub the RF"],
      best:0,explanations:["Center field is the most important defensive position in the outfield. With a 1-run lead in the 9th and your CF already misjudging fly balls, put in your best defensive center fielder. A ball dropping in center because of a misjudgment could cost you the game.","Saving the bench is less important than winning THIS game, since the 9th inning with a 1-run lead is the most important moment.","A misjudged fly ball in center could be the tying run, because don't wait until it's too late.","Moving the right fielder to center disrupts two positions — just make the straight swap."],
      rates:[85,30,20,25],concept:"In close games, protect center field — it's the most important defensive position in the outfield",anim:"catch"},
    // Batch 4 — Lineup Construction
    {id:"m41", conceptTag:"situational-hitting",title:"Building the Lineup — What Each Spot Means",diff:1,cat:"lineup",ageMin:6,ageMax:99,
      description:"You're setting today's lineup. You have 9 players. Your best all-around hitter reaches base often and hits for power. Where does he bat?",
      situation:{inning:"Top 1",outs:0,count:"0-0",runners:[],score:[0,0]},
      options:["Third in the order","Leadoff","Cleanup (4th)","Second in the order"],
      best:0,explanations:["The 3-hole (third spot) is for your best all-around hitter — someone who hits for average AND power. He bats third because the 1-2 hitters ahead of him often get on base first, giving him a chance to drive in runs right away in the first inning. Over a full season, the 3-hole gets nearly as many at-bats as leadoff.","Leadoff is for your fastest player who gets on base a lot — not necessarily your best overall hitter. Speed matters more than power at the top because the leadoff hitter's job is to get on base and score, not drive in runs.","The cleanup spot (4th) is specifically for your biggest power hitter — the one who hits home runs and doubles to drive in runs. An all-around hitter who also gets on base a lot is more valuable batting 3rd, where he can both get on base AND drive in the 1-2 hitters.","Batting second is gaining popularity in modern analytics for the best hitter, but traditionally the 2-hole is for a contact hitter who can move runners with hit-and-run plays, which means for a kid's lineup, the classic 3-hole spot is the right call for your best all-around guy."],
      rates:[85,25,35,50],concept:"The 3-hole hitter is your best all-around player — he gets on base and drives in runs",explSimple:["Great choice! The 3-hole hitter is traditionally your best all-around hitter — the guy who hits for average AND power.","Not the best move. Leadoff is for speed and on-base percentage — not your best power hitter.","Not the best move. Cleanup is for your best POWER hitter — the guy who drives in runs.","Not the best move. Second is becoming more popular for the best hitter in modern baseball, but traditionally it's."], anim:"hit"},
    {id:"m42", conceptTag:"situational-hitting",title:"Fastest Player — Where Does He Bat?",diff:1,cat:"lineup",ageMin:6,ageMax:99,
      description:"Your fastest player has great on-base skills (.380 OBP) but not much power. He's perfect for one specific lineup spot.",
      situation:{inning:"Top 1",outs:0,count:"0-0",runners:[],score:[0,0]},
      options:["Leadoff — he gets on base and uses speed","Cleanup — let him drive in runs","9th — hit him last, save speed for defense","3rd — your best OBP should bat 3rd"],
      best:0,explanations:["Leadoff! Your fastest player with the best on-base skills bats first, because his job: get on base, use his speed to steal bases and advance on hits, and score runs. The leadoff hitter gets the most at-bats over a season. Speed + OBP = leadoff hitter.","Cleanup requires power to drive in runs, since speed without power doesn't help in the 4-hole.","Batting 9th wastes his on-base skills and gives him fewer plate appearances.","The 3-hole needs a combination of average AND power, because an OBP-only guy belongs at leadoff."],
      rates:[90,15,25,40],concept:"Your fastest player with the best on-base skills bats leadoff — speed + OBP = leadoff hitter",explSimple:["Great choice! Leadoff! Your fastest player with the best on-base skills bats first.","Not the best move. Cleanup requires power to drive in runs.","Not the best move. Batting 9th wastes his on-base skills and gives him fewer plate appearances.","Not the best move. The 3-hole needs a combination of average AND power."], anim:"advance"},
    {id:"m43", conceptTag:"situational-hitting",title:"Best Hitter vs Best Power Hitter",diff:2,cat:"lineup",ageMin:9,ageMax:99,
      description:"Your best hitter bats .320 with 15 HRs. Your best power hitter bats .250 with 35 HRs. Where do they bat — 3rd and 4th?",
      situation:{inning:"Top 1",outs:0,count:"0-0",runners:[],score:[0,0]},
      options:[".320 hitter bats 3rd, .250 power hitter bats 4th","Bat the power hitter 2nd for maximum plate appearances",".320 hitter bats 2nd, power hitter bats 3rd","Both bat wherever they're comfortable"],
      best:0,explanations:["The .320 hitter bats 3rd — he's your best all-around hitter who gets on base and drives in runs. The .250 power hitter bats 4th (cleanup) — his job is to drive in the runners that the 1-2-3 hitters got on base. The 4-hole is for raw power; the 3-hole is for consistency + power.","Batting the power hitter 2nd gives more plate appearances, but his .250 average means more outs at the top of the order, since the 2-hole traditionally needs contact and on-base skills, not raw power.","This isn't traditional, though some modern analytics support the best hitter batting 2nd, which means the traditional answer is 3rd and 4th.","Comfort matters, but lineup construction follows strategic principles for a reason."],
      rates:[85,25,40,15],concept:"Your best hitter bats 3rd (consistency), your best power hitter bats 4th (cleanup, drives in runs)",explSimple:["The .320 hitter bats 3rd — he's your best all-around hitter who gets on base and drives in runs.","The power hitter's lower average means he gets on base less.","This isn't traditional, though some modern analytics support the best hitter batting 2nd.","Comfort matters, but lineup construction follows strategic principles for a reason."],anim:"hit"},
    {id:"m44", conceptTag:"platoon-advantage",title:"Pitcher Batting — 8th or 9th?",diff:2,cat:"lineup",ageMin:9,ageMax:99,
      description:"In leagues where pitchers still bat (youth, some college, and international play), where should the pitcher hit in the order — 8th or 9th?",
      situation:{inning:"Top 1",outs:0,count:"0-0",runners:[],score:[0,0]},
      options:["9th — he's the weakest hitter","8th — so the leadoff hitter is like a second leadoff in the 9th spot","It doesn't matter — he'll make an out either way","Wherever the pitcher feels comfortable"],
      best:0,explanations:["Traditionally, the pitcher bats 9th because he's the weakest hitter. His job is simple: don't hurt the team. If he can bunt, that's a bonus. The 9th spot gets the fewest at-bats, which minimizes the damage of having a weak hitter in the lineup.","Batting the pitcher 8th is a strategy some managers use (Tony La Russa popularized it), but it is controversial and the standard approach of batting him 9th has stood the test of time.","It does matter — proper lineup construction maximizes scoring opportunities.","Pitchers should focus on pitching — bat them 9th and let them put all their energy into what they do best."],
      rates:[85,50,10,15],concept:"The pitcher bats 9th — the weakest hitter gets the fewest at-bats to minimize damage",explSimple:["Traditionally, the pitcher bats 9th because he's the weakest hitter.","Batting the pitcher 8th is a strategy some managers use (Tony La Russa popularized it), but it's controversial.","It does matter — proper lineup construction maximizes scoring opportunities.","Pitchers should focus on pitching."],anim:"strike"},
    {id:"m45", conceptTag:"platoon-advantage",title:"Platoon Advantage — Who Starts?",diff:2,cat:"lineup",ageMin:9,ageMax:99,
      description:"The opposing starter is a left-handed pitcher. You have two right fielders: one is right-handed (.280 avg) and one is left-handed (.300 avg overall, but .220 vs lefties).",
      situation:{inning:"Top 1",outs:0,count:"0-0",runners:[],score:[0,0]},
      options:["Start the righty (.280) — platoon advantage vs the lefty pitcher","Start the lefty (.300) — he's the better overall hitter","Start both somehow — rotate them between RF and DH","Flip a coin — both are good options"],
      best:0,explanations:["Start the right-handed hitter against the left-handed pitcher. Even though the lefty has a higher overall average (.300), he hits only .220 against lefties. The righty (.280) will hit better against this pitcher because of the platoon advantage — right-handed hitters see the ball better from left-handed pitchers.","The lefty's overall .300 is misleading, because his .220 vs lefties is the relevant number today. Always look at the matchup-specific stats, not the overall average, when making lineup decisions.","You can't play two right fielders at the same time, so you need to choose one. The platoon advantage gives you a clear way to make that decision based on the opposing pitcher's handedness.","This isn't a coin flip, because the data clearly favors the righty against a lefty pitcher. A .280 hitter facing a pitcher he can see well is better than a .300 hitter struggling to pick up the ball at .220 against same-side pitching."],
      rates:[90,40,25,15],concept:"Use the platoon advantage — start the opposite-handed hitter against the opposing pitcher",explSimple:["Start the right-handed hitter against the left-handed pitcher.","The lefty's overall .300 is misleading.","You can't play two right fielders, because","This isn't a coin flip — the data clearly favors the righty against a lefty pitcher."],anim:"hit"},
    {id:"m46", conceptTag:"situational-hitting",title:"Hot Hitter — Move Him Up?",diff:2,cat:"lineup",ageMin:9,ageMax:99,
      description:"Your #7 hitter has been on fire this week — 10-for-15 (.667) with 3 doubles and a homer. He normally bats 7th. Should you move him up?",
      situation:{inning:"Top 1",outs:0,count:"0-0",runners:[],score:[0,0]},
      options:["Move him to 5th — ride the hot hand","Keep him at 7th — don't overreact to one week","Move him to 3rd — he's your best hitter right now","Move him to leadoff — more at-bats for the hot bat"],
      best:1,explanations:["Moving him to 5th disrupts the rest of the lineup, because hot streaks are exciting but often regress quickly. Moving one player up means moving another player down, which can hurt team chemistry and disrupt a lineup that's already been working.","One hot week doesn't change a player's fundamental talent. The lineup is built on season-long performance, not one-week samples. If you move him up, you have to move someone down — and that player might be a better hitter in the long run. Trust your lineup construction and let him keep mashing from the 7th spot.","The 3rd spot is for your best overall hitter, not your hottest-this-week hitter. Small sample sizes are misleading — 15 at-bats tells you very little about true talent compared to a full season of data.","Leadoff is for OBP and speed, because a hot week with power doesn't change his fundamental skill set. He might be hitting well this week, but if he doesn't have leadoff speed or plate discipline, he doesn't belong there regardless of his current streak."],
      rates:[30,85,20,15],concept:"Don't rearrange the lineup for one hot week — hot streaks end, but lineup construction is based on talent",explSimple:["Moving him to 5th disrupts the rest of the lineup.","One hot week doesn't change a player's fundamental talent.","The 3rd spot is for your best overall hitter, not your hottest-this-week hitter.","Leadoff is for OBP and speed, because"],anim:"freeze"},
    {id:"m47", conceptTag:"situational-hitting",title:"Modern Analytics — Best Hitter Bats 2nd?",diff:3,cat:"lineup",ageMin:12,ageMax:99,
      description:"Your analytics coach says your best hitter belongs in the 2nd spot, not 3rd. Modern stats show the 2nd spot gets the most plate appearances with the best chance of men already aboard. Do you listen?",
      situation:{inning:"Top 1",outs:0,count:"0-0",runners:[],score:[0,0]},
      options:["Go with analytics — bat your best hitter 2nd","Stick with tradition — best hitter bats 3rd","Try it for a few games and see how it works","The difference is too small to matter"],
      best:2,explanations:["Going all-in on analytics without testing is risky, because your players might be confused by the sudden change and it could affect their comfort at the plate. Test new ideas gradually before going all-in.","Tradition isn't always right, because analytics have improved baseball significantly over the past two decades. Dismissing data-driven suggestions without even trying them means you could be leaving wins on the table.","Try it! The best approach is to test the analytical suggestion for a stretch of games and see how it fits your team. Modern analytics DO show that the 2nd spot gets more plate appearances than the 3rd spot over a season and often comes up with men already aboard. But every team is different.","The difference can actually amount to several runs over a season, because over 162 games, even small advantages in plate appearances and baserunner situations compound into meaningful run differences. That makes it worth exploring."],
      rates:[40,30,85,20],concept:"Modern analytics suggest batting your best hitter 2nd — test new ideas, don't blindly follow tradition OR analytics",anim:"freeze"},
    {id:"m48", conceptTag:"platoon-advantage",title:"Too Many Lefties — Adjust?",diff:3,cat:"lineup",ageMin:12,ageMax:99,
      description:"Your lineup has 6 left-handed batters. Today you face a tough lefty with a nasty slider. He dominates left-handed hitters.",
      situation:{inning:"Top 1",outs:0,count:"0-0",runners:[],score:[0,0]},
      options:["Start as many right-handed hitters as possible — platoon","Keep your regular lineup — they're your best players","Mix in 2-3 righties but keep your core lefty hitters","Stack all the lefties together to tire the pitcher"],
      best:2,explanations:["Starting all righties might mean benching much better players just for the platoon advantage, since it gives you the best chance of success.","Keeping all lefties against a tough lefty pitcher is stubborn — the data says they'll struggle.","Mix in 2-3 right-handed hitters from your bench to break up the lefty-on-lefty matchups, which means keep your best lefty hitters (your core guys) but replace the weakest lefties with righties who can handle a left-handed pitcher. This balances platoon advantage with overall talent.","Stacking lefties doesn't tire a pitcher — it gives him the same matchup advantage repeatedly."],
      rates:[35,20,85,15],concept:"Against a tough same-side pitcher, mix in opposite-handed hitters but keep your core players",anim:"freeze"},
    // Batch 5 — Game Management
    {id:"m49", conceptTag:"pitch-count-mgmt",title:"Rain Delay — Can Your Pitcher Come Back?",diff:1,cat:"game-management",ageMin:6,ageMax:99,
      description:"Top of the 5th, your starter was dealing — 8 strikeouts, only 1 hit. Then a 45-minute rain delay hits. The game is about to resume. Can he come back?",
      situation:{inning:"Top 5",outs:0,count:"0-0",runners:[],score:[4,0]},
      options:["Let him come back — he was dominant","Go to the bullpen — rain delays kill momentum","Let him warm up and decide based on how he looks","Pull him only if the delay was longer than an hour"],
      best:2,explanations:["Letting him come back without checking how he looks after the delay is risky, because his arm cooled down.","Going straight to the bullpen wastes a dominant outing, since you give him a chance.","Let him throw some warm-up pitches and evaluate. If his velocity is still there and his mechanics look good, send him back out. If he's stiff, laboring, or can't find the zone, go to the bullpen. Rain delays affect every pitcher differently — use your eyes, not a blanket rule.","An arbitrary time limit ignores the reality that some pitchers handle delays better than others."],
      rates:[35,30,85,20],concept:"After a rain delay, let your pitcher warm up and evaluate — use your eyes, not a blanket rule",explSimple:["Not the best move. Letting him come back without checking how he looks after the delay is risky.","Not the best move. Going straight to the bullpen wastes a dominant outing.","Great choice! Let him throw some warm-up pitches and evaluate.","Not the best move. An arbitrary time limit ignores the reality that some pitchers handle delays better than others."], anim:"freeze"},
    {id:"m50", conceptTag:"leverage-index",title:"Losing Big — When to Rest Starters",diff:1,cat:"game-management",ageMin:6,ageMax:99,
      description:"Bot of the 5th, you're losing 10-1. Your regular players look defeated. Tomorrow is an important game. When do you start pulling starters?",
      situation:{inning:"Bot 5",outs:0,count:"0-0",runners:[],score:[10,1]},
      options:["Pull starters now — save them for tomorrow","Play until the 7th, then pull them","Keep starters in — comebacks happen, and they need the reps","Only pull starters who are injured or tired"],
      best:0,explanations:["Down 10-1 in the 5th with an important game tomorrow, start resting your regulars, because you get your bench players game experience and save your starters' legs and arms. There's competing and then there's being strategic — saving your energy for a winnable game tomorrow is the smart move.","Waiting until the 7th wastes two more innings of your starters' energy in a game that's already decided.","Keeping starters in for reps sounds reasonable, but a 9-run deficit in the 5th is statistically almost impossible to overcome. After all, save those reps for tomorrow.","You don't need to wait for injuries, since strategic rest is smart managing."],
      rates:[85,40,20,30],concept:"In a blowout loss, rest your starters for tomorrow — strategic rest wins more games in the long run",explSimple:["Great choice! Down 10-1 in the 5th with an important game tomorrow, start resting your regulars.","Not the best move. Waiting until the 7th wastes two more innings of your starters' energy in.","Not the best move. Playing to win is admirable, but a 9-run deficit in the 5th is Be smart.","Not the best move. You don't need to wait for injuries."], anim:"freeze"},
    {id:"m51", conceptTag:"leverage-index",title:"Extra Innings — Manage the Bullpen",diff:2,cat:"pitching",ageMin:9,ageMax:99,
      description:"Bot of the 9th, the game just went to extra innings — tied 4-4. You've used 3 relievers already. You have 2 left in the bullpen. How do you manage this?",
      situation:{inning:"Bot 9",outs:0,count:"0-0",runners:[],score:[4,4]},
      options:["Use your best remaining reliever for the 10th","Use your weakest remaining arm — save the best for later","Give the current pitcher one more inning","Use position players to pitch — save the relievers"],
      best:0,explanations:["In extra innings, use your best available arm NOW. There's no guarantee you'll need a pitcher in the 12th if you lose in the 10th. The game could end any inning — win it now with your best stuff.","Saving the best for later assumes the game will go deep into extras, which means it might end in the 10th — use your best.","The current pitcher might be spent, because fresh arms are more effective.","Position players pitching is for blowouts, not tied games, since you think about what gives your team the best result here."],
      rates:[85,20,35,5],concept:"In extra innings, use your best available arm — win the game NOW, don't save for hypothetical later innings",explSimple:["In extra innings, use your best available arm NOW.","Saving the best for later assumes the game will go deep into extras.","The current pitcher might be spent.","Position players pitching is for blowouts, not tied games."],anim:"freeze"},
    {id:"m52", conceptTag:"win-probability",title:"Team Made 3 Errors — Keep Morale Up",diff:2,cat:"game-management",ageMin:9,ageMax:99,
      description:"Top of the 4th, your team has committed 3 errors already. The opposing team scored 4 unearned runs. Your players' heads are down. What do you do?",
      situation:{inning:"Top 4",outs:0,count:"0-0",runners:[],score:[2,6]},
      options:["Talk firmly in the dugout — address the errors directly","Encourage them — errors happen, keep fighting","Bench the players who made errors — send a message","Call a team meeting on the mound"],
      best:1,explanations:["Addressing errors directly when players already feel terrible makes them tighter and more error-prone.","Errors are part of baseball — even MLB players make them. Encouraging your team keeps their confidence up and prevents more errors. Tell them: 'Shake it off, next play. We're still in this game.' Positive energy in the dugout is contagious, and so is negativity. As a manager, you set the tone.","Benching players for errors embarrasses them and doesn't fix the problem, because it creates fear of mistakes instead of confidence.","A mound meeting in the 4th inning after errors just draws more attention to the mistakes, since you move forward."],
      rates:[15,90,25,40],concept:"After errors, encourage your team — positive energy prevents more mistakes, negativity causes them",explSimple:["Addressing errors directly when players already feel terrible makes them tighter and more error-prone.","Errors are part of baseball — even MLB players make them.","Benching players for errors embarrasses them and doesn't fix the problem.","A mound meeting in the 4th inning after errors just draws more attention to the mistakes."],anim:"freeze"},
    {id:"m53", conceptTag:"pitch-sequencing",title:"Sign Stealing Suspicion",diff:2,cat:"game-management",ageMin:9,ageMax:99,
      description:"Bot of the 3rd, you notice the opposing team seems to know what pitch is coming. Their hitters aren't swinging at off-speed at all — they're laying off everything not a fastball. You suspect sign stealing.",
      situation:{inning:"Bot 3",outs:0,count:"0-0",runners:[],score:[3,1]},
      options:["Tell your catcher to change signs immediately","Complain to the umpire about cheating","Test it — have your catcher show one sign and throw another","Keep the same signs — you might be paranoid"],
      best:0,explanations:["Change signs immediately by switching to a multiple-sign system — flash 3-4 signs and only one (like the second sign, or the one after a fist) is real. This works because even if the other team sees your signs, they can't tell which one counts. You don't need proof of cheating to protect yourself.","Complaining to the umpire requires proof, and sign stealing by watching the catcher is actually legal in baseball — only electronic sign stealing is banned, which means the ump can't help you here, so fix the problem yourself by changing your system.","Testing by showing a fake sign and throwing a different pitch is clever detective work, but it costs you an at-bat of bad strategy, because meanwhile, the other team keeps hitting your pitches. Change first, investigate later.","Keeping the same signs when hitters are laying off your best off-speed stuff is giving the other team free information, since every pitch they identify correctly is another hard hit waiting to happen. Act on your suspicion now — the risk of being wrong (changing to better signs) is zero."],
      rates:[85,20,50,15],concept:"If you suspect sign stealing, change your signs immediately — prevention is better than accusation",explSimple:["If you suspect signs are being stolen, change them immediately.","Complaining without proof just makes you look paranoid.","Testing is clever but takes time.","Keeping the same signs when you suspect they're stolen is negligent."],anim:"freeze"},
    {id:"m54", conceptTag:"win-probability",title:"Late Game, Tie — One Run or Big Inning?",diff:2,cat:"game-management",ageMin:9,ageMax:99,
      description:"Bot 7th, tied 3-3. Runner on 1st, nobody out. Your #6 hitter steps up. Do you play for one run (bunt, steal, sac fly) or try for a big inning?",
      situation:{inning:"Bot 7",outs:0,count:"0-0",runners:[1],score:[3,3]},
      options:["Play for one run — bunt the runner over","Play for a big inning — let your hitters swing","Steal to get the runner in scoring position, then decide","It depends on who's hitting"],
      best:1,explanations:["Bunting in the 7th inning of a tie game gives away an out when you might need a big inning. The other team can just tie it back up if you score one.","In a tie game, play for a big inning. Here's why: if you score one run, the other team gets to bat and might tie it. If you score 2-3 runs, the game is likely over. Don't limit yourself to one run by bunting and playing small ball. Let your hitters swing and try to blow the game open.","Stealing is fine, but the main decision is whether to play small ball or let your hitters hit.","Every hitter should get a chance to swing in a tie game in the 7th."],
      rates:[30,85,45,35],concept:"In a tie game, play for a big inning — one run can be matched. Multiple runs end the game",explSimple:["Bunting in the 7th inning of a tie game gives away an out when you might need a big inning.","In a tie game, play for a big inning.","Stealing is fine, but the main decision is whether to play small ball or let your hitters hit.","Every hitter should get a chance to swing in a tie game in the 7th."],anim:"hit"},
    {id:"m55", conceptTag:"pitch-count-mgmt",title:"Day Game After Night Game",diff:3,cat:"game-management",ageMin:12,ageMax:99,
      description:"Your team played a tough night game that ended at 10:30 PM. Today's game is at 1:00 PM — a day game after a night game. Your regulars are tired.",
      situation:{inning:"Top 1",outs:0,count:"0-0",runners:[],score:[0,0]},
      options:["Rest your regulars — start the bench","Play your regulars — every game matters","Rest 2-3 key players and keep the rest","Only rest players who played the most innings last night"],
      best:2,explanations:["Resting ALL regulars is too extreme unless it's a truly meaningless game, which means the outcome won't be what you need.","Playing everyone ignores the reality that tired players perform worse and get injured more easily.","Rest 2-3 key players who played the most or who you need most for tomorrow. Keep the core of your lineup but give your catcher (who caught the whole night game), your closer (who pitched last night), and maybe one position player a day off. Strategic rest keeps your team fresh over a long season.","This is close, but resting 2-3 strategically is better than a rigid rule based only on innings."],
      rates:[25,30,85,40],concept:"After a night game, rest 2-3 key players — strategic rest over a season prevents injuries and burnout",anim:"freeze"},
    {id:"m56", conceptTag:"pitch-count-mgmt",title:"Fighting for Playoffs — Use the Ace on Short Rest?",diff:3,cat:"pitching",ageMin:12,ageMax:99,
      description:"Final series of the season. You need 2 wins in 3 games to make the playoffs. Your ace pitched 3 days ago (normally needs 4 days rest). Game 1 is today.",
      situation:{inning:"Top 1",outs:0,count:"0-0",runners:[],score:[0,0]},
      options:["Start the ace on short rest — you need him now","Save the ace for Game 2 on normal rest","Start the ace in Game 1 AND Game 3 if needed","Use the ace as a reliever today, start him Game 2"],
      best:1,explanations:["Short rest increases injury risk significantly and usually reduces effectiveness, because your ace at 85% isn't much better than your #2 starter at 100%.","Save the ace for Game 2 on normal rest. He'll be at full strength and dominant. Start your #2 in Game 1 — you might win anyway. If you lose Game 1, your ace is ready for the must-win Game 2. If you win Game 1, you only need one more win and your ace starts Game 2 with a chance to clinch.","Starting him twice in 3 days would destroy his arm — never do this.","Using the ace as a reliever wastes his stamina for Game 2, which means think about what gives your team the best result here."],
      rates:[25,85,10,30],concept:"Save your ace for normal rest — a fully rested ace is more valuable than a tired one on short rest",anim:"freeze"},
    {id:"m57", conceptTag:"win-probability",title:"Down 3 in the 6th — When to Play for the Big Inning",diff:3,cat:"game-management",ageMin:12,ageMax:99,
      description:"Bot 6th, you're down 7-4. Runner on 1st, 1 out. Your #3 hitter steps to the plate — a power hitter who hits .290. On deck waits your #4, who's 0-for-3 today. Do you play for one run or the big inning?",
      situation:{inning:"Bot 6",outs:1,count:"0-0",runners:[1],score:[7,4]},
      options:["Bunt the runner to 2nd — manufacture a run","Let him swing away — you need a big inning, not one run","Hit and run — move the runner and avoid a double play","Pinch hit for him with a contact hitter"],
      best:1,explanations:["Bunting when you're down 3 runs sacrifices an out to move one runner, because you can't bunt your way back from a 3-run deficit — you need multiple runs, and outs are too precious.","Down 3 runs in the 6th, win probability says you need a big inning, since you let your power hitter swing away and try to drive in runs. Sacrificing outs when you're behind by multiple runs lowers your win probability. You need baserunners AND extra-base hits, not small ball.","Hit and run avoids the DP, but it forces your best hitter to swing at whatever pitch comes — he might ground out on a bad pitch, because with a 3-run deficit, let him get his pitch.","Pinch hitting for your #3 hitter removes your best chance for a big hit — you need power in the lineup when trailing by multiple runs."],
      rates:[20,85,40,15],concept:"When trailing by 3+ runs, play for the big inning — sacrificing outs with bunts lowers your win probability",anim:"hit"},
    {id:"m58", conceptTag:"infield-positioning",title:"Infield In — Cut Off the Run",diff:1,cat:"positioning",ageMin:6,ageMax:99,
      description:"Bot 7th, runner on 3rd, 1 out, tied 3-3. You're the manager. Should you bring the infield in to cut off the run at home?",
      situation:{inning:"Bot 7",outs:1,count:"0-0",runners:[3],score:[3,3]},
      options:["Infield in — stop the run from scoring","Infield back — get the out and worry about the run later","Play normal depth — balanced approach","Only bring the corners in"],
      best:0,explanations:["With the go-ahead run on 3rd and less than 2 outs in a tie game, bring the infield in, which means yes, you give up range, but preventing the run from scoring is the priority. A ground ball to a drawn-in infielder gives you a play at home.","Infield back means any ground ball scores the runner from 3rd, because in a tie game, you can't afford to let that run score.","Normal depth doesn't give you a throw home on a routine grounder.","Only corners in is a compromise — since but in a tie game, you need the full infield in to maximize your chance at the play at home."],
      rates:[85,20,35,50],concept:"With a runner on 3rd in a tie game, bring the infield in — preventing the run is the priority",explSimple:["Great choice! With the go-ahead run on 3rd and less than 2 outs in.","Not the best move. Infield back means any ground ball scores the runner from 3rd.","Normal depth doesn't give you a throw home on a routine grounder.","Not the best move. Only corners in is a compromise — but in a tie game, you need."], anim:"groundout"},
    {id:"m59",title:"The Appeal Window",diff:3,cat:"game-management",conceptTag:"appeal-play",ageMin:12,ageMax:99,
      description:"Bot 9th, 2 outs, tie game. The opposing batter hits a deep fly ball to center. Runner on 3rd tags up and scores what appears to be the winning run. But your center fielder signals that the runner on 2nd left early on the tag-up. You're the manager. The pitcher has the ball. What do you tell him to do?",
      situation:{inning:"Bot 9",outs:2,count:"0-0",runners:[2,3],score:[5,5]},
      options:["Appeal at 2nd base — the runner left early","Appeal at 3rd base — that's where the runner advanced to","Forget it — the run already scored, the game is over","Appeal at home plate — challenge the run itself"],
      best:0,explanations:["Correct! On an appeal for leaving early on a tag-up, you throw to the base the runner LEFT FROM — not where they went. The pitcher steps off the rubber and throws to 2nd. If the umpire confirms the runner left early, that's the 3rd out. And here's the key: because it's a 3rd out on an appeal play, the run that 'scored' from 3rd is ERASED. The game continues tied. Runs don't count when the 3rd out is a force or appeal.","The appeal must go to the base the runner left from (2nd), not the base they advanced to, since you throwing to 3rd wastes your only chance to make the appeal. You appeal where the violation happened, not where the runner ended up.","The game is NOT over until the umpire says it is, because you have until the next pitch (or until all fielders leave fair territory) to make an appeal. This could save the game.","You can't appeal at home plate for this violation — the appeal goes to the base the runner departed from early. Home plate is where the run scored, but the violation — leaving early — happened at 2nd base."],
      rates:[90,25,15,40],concept:"Appeal at the base the runner LEFT FROM, not where they went — and a 3rd-out appeal erases any run scored on the same play",anim:"throwHome"},
    {id:"m60",title:"The Leverage Index Trap",diff:3,cat:"game-management",conceptTag:"leverage-index",ageMin:12,ageMax:99,
      description:"Bot 8th, tie game 3-3. Your starter has thrown 88 pitches and is cruising — 2 hits through 7 innings. But the heart of the order is coming up (3-4-5 hitters), and your best setup man is warm. Your closer has pitched the last 2 days. What's your call?",
      situation:{inning:"Bot 8",outs:0,count:"0-0",runners:[],score:[3,3]},
      options:["Pull the starter — high-leverage spot needs your best reliever","Let the starter face one more batter, then decide","Leave the starter in — he's dealing, don't overthink it","Go straight to the closer — this is the biggest moment"],
      best:0,explanations:["Correct! Tie game in the 8th = ~1.5 leverage index. Your starter at 88 pitches facing the order a 3rd time will see a +30 BA point spike from TTO effect alone. High leverage + 3rd TTO = the exact situation where you bring in your best reliever. The setup man is fresh and ready.","Facing 'one more batter' sounds reasonable, but the 3-hitter leading off against a 3rd-time-through starter in a tie 8th is exactly the wrong matchup, which means if he reaches, you're in trouble with 4-5 coming up.","He's been great, but TTO data shows batters hit +30 BA points the 3rd time through, because his 'dealing' was against the lineup the 1st and 2nd time. The 3rd time is a different animal, especially against the heart of the order.","The closer has pitched 2 straight days — he's unavailable or diminished. Using a fatigued closer in the 8th wastes him. Save any remaining closer availability for the 9th if you get there."],
      rates:[82,40,25,18],concept:"Leverage index determines WHEN to use your best reliever — a tie 8th inning (1.5 LI) with 3rd TTO is the moment to go to your setup man",anim:"freeze"},
    {id:"m61",title:"The TTO Compound Alarm",diff:3,cat:"game-management",conceptTag:"times-through-order",ageMin:11,ageMax:99,
      description:"Top 6th, you lead 3-1. Your right-handed starter has thrown 78 pitches through 5 innings — solid but not dominant (7 hits, 1 walk). He's about to face the top of the order for the 3rd time. Your bullpen has a left-handed setup man and a right-handed closer. The next 3 batters are: LHH (.270), RHH (.255), LHH (.290). What do you do?",
      situation:{inning:"Top 6",outs:0,count:"0-0",runners:[],score:[3,1]},
      options:["Pull the starter now — 3rd TTO against the top of the order is too dangerous","Let him face the leadoff LHH, then bring in the lefty setup man","Leave him in for the 6th — 78 pitches isn't tired and you have a 2-run lead","Bring in the righty closer early to finish the game"],
      best:0,explanations:["Correct! Your RHP starter facing the order a 3rd time will see +30 BA points from TTO effect. The leadoff LHH already hits .270 — add TTO (+30) and opposite-hand advantage (+18) and you're looking at a projected .318+ BA. Two of the next three are left-handed. Your lefty setup man neutralizes them with same-hand advantage. Pull the starter NOW while you have a clean inning and a 2-run cushion.","Letting him face even one batter in the 3rd TTO is risky, since the leadoff hitter is left-handed (opposite hand) AND sees him for the 3rd time — that's a compound +48 point disadvantage. If he reaches, you're in a jam with the heart of the order up.","78 pitches isn't about fatigue — it's about FAMILIARITY, because the TTO effect isn't tired arms, it's that hitters have seen his pitch sequences twice and can now predict better. Even a fresh pitcher gets hit harder the 3rd time through.","Using your closer for 4 innings in a 3-1 game burns him for tomorrow — setup man handles the 6th-7th, closer gets the 8th-9th if needed. Don't waste the closer's arm in a manageable situation."],
      rates:[85,45,20,15],concept:"TTO effect (+30 BA pts) COMPOUNDS with platoon disadvantage (+18 pts) — a RHP facing LHH for the 3rd time faces a +48 point BA spike",anim:"freeze"},
    {id:"m62", conceptTag:"infield-positioning",title:"Turf Speed — Adjust Your Depth",diff:2,cat:"game-management",ageMin:9,ageMax:99,
      description:"You're the manager. Your team is playing on artificial turf for the first time this season. Top 1st, runner on 1st, no outs. The opposing hitter bats .280 with a 55% ground ball rate. Your infielders are set at their normal grass-field depth. Your second baseman asks if he should adjust. What do you tell the infield?",
      situation:{inning:"Top 1",outs:0,count:"0-0",runners:[1],score:[0,0]},
      options:["Play 1-2 steps deeper — ground balls travel faster on turf","Play normal depth — your fielders know how to play","Play shallower — you want to cut off the runner at 2nd","Shift the infield to the pull side instead of adjusting depth"],
      best:0,explanations:["On artificial turf, ground balls travel 15-20% faster than on grass. Your infielders need 1-2 extra steps of depth to compensate — this gives them the same reaction time they'd have on grass at normal depth. With a ground ball hitter up, this adjustment is critical. The faster surface also means you might still get the DP even from the deeper position.","Normal depth on turf means your fielders are effectively too shallow. A sharp grounder that's routine on grass can handcuff an infielder on turf because the ball gets there faster. The surface changes the game — you must adjust.","Playing shallower on turf is dangerous, which means the ball is already coming at your fielders faster. Shallower means even less reaction time. You'll get eaten up by hard grounders through the infield.","A pull-side shift might be appropriate for some hitters, but it doesn't address the core issue — turf speed, because you need depth adjustment FIRST, then consider lateral positioning. Address the surface before the scouting report."],
      rates:[85,25,15,40],concept:"On artificial turf, ground balls travel 15-20% faster — infielders must play 1-2 steps deeper to compensate for the reduced reaction time",explSimple:["On artificial turf, ground balls travel 15-20% faster than on grass.","Normal depth on turf means your fielders are effectively too shallow.","Playing shallower on turf is dangerous.","A pull-side shift might be appropriate for some hitters, but it doesn't address the core issue — turf speed."],anim:"groundout"},
    {id:"m63",title:"Bunt or Swing? Middle School Level",diff:2,cat:"game-management",conceptTag:"bunt-re24",ageMin:11,ageMax:14,
      description:"You're the manager of a middle school travel team. Bot 5th, runner on 2nd, no outs, tie game. Your #8 hitter steps up — he's batting .180 this season and strikes out a lot, but he's made contact on bunts in practice. The opposing third baseman plays deep. The on-deck batter (#9) is your weakest hitter (.150). What's your call?",
      situation:{inning:"Bot 5",outs:0,count:"0-0",runners:[2],score:[3,3]},
      options:["Bunt — move the runner to 3rd with less than 2 outs","Swing away — bunting always costs runs","Hit and run — make the defense react","Squeeze play — score the run now"],
      best:0,explanations:["At the middle school level, sacrifice bunts are much more valuable than in MLB. Your hitter is batting .180 and strikes out often — a failed at-bat is likely. But he can bunt in practice, and the 3B is playing deep (slow charge). A successful bunt moves the runner to 3rd with 1 out. At this level, fielders make more errors on bunt plays, so there's even a chance of reaching base. The key difference from MLB: middle school fielders are less reliable, so bunts succeed more often and cost less in run expectancy.","'Bunting always costs runs' is an MLB rule, not a youth rule. At the middle school level, batters strike out more and make less consistent contact. A .180 hitter who strikes out a lot has a lower expected run value swinging than bunting. The break-even math changes when the skill level changes.","Hit and run with a .180 hitter is high-risk, since if he misses the sign or strikes out, the runner is hung out at 2nd with nowhere to go. Hit and run requires a hitter who can reliably make contact.","A squeeze with runner on 2nd is extremely risky, because the runner has 90 feet to cover, and even a mediocre bunt may not get down fast enough. Squeeze play is for runner on 3rd only."],
      rates:[90,40,25,15],concept:"At the middle school level, sacrifice bunts are more valuable than in MLB — weaker fielding makes bunts succeed more often and the RE cost is lower",explSimple:["At the middle school level, sacrifice bunts are much more valuable than in MLB.","'Bunting always costs runs' is an MLB rule, not a youth rule.","Hit and run with a .180 hitter is high-risk.","A squeeze with runner on 2nd is extremely risky."],anim:"bunt"},
    // ============================================================================
    // VARIABLE MASTERY CLUSTER 1 — The Relay Read
    // Same base situation, one variable changes the correct answer each time
    // ============================================================================
    {id:"m_vc1a",title:"Relay Read — Standard Play",diff:3,cat:"situational",conceptTag:"cutoff-roles",ageMin:12,ageMax:99,
      description:"Runner on 2nd, single to left field, 0 outs. The left fielder fields the ball cleanly on two hops. The runner is rounding third hard. Your relay man is lined up. Do you call for the relay throw home?",
      situation:{inning:"Top 5",outs:0,count:"0-0",runners:[2],score:[3,3]},
      options:["Yes — relay home and try to get the runner at the plate","Cut and hold — keep the ball in the infield, concede the run","Relay to third to try to get the batter who rounded first too far","Let the outfielder throw all the way home — skip the cutoff"],
      best:0,explanations:["Correct! With 0 outs, a tied game, and a clean field, the relay home is the right call. The runner was on second and the single to left gives a strong relay angle. You have the alignment — use it. Getting the out at home keeps the game tied and avoids giving up a free run.","Conceding the run with 0 outs in a tied game gives away a lead without even attempting the play, since the relay is lined up — use it.","Throwing behind the batter at first is a low-value play, which means the run scoring is the bigger problem. Priority: stop the run, not a speculative out at first.","Skipping the cutoff removes your margin for error, because outfield throws to home without a relay are less accurate and arrive later. The relay exists to shorten the throw and improve accuracy."],
      rates:[82,30,20,15],concept:"With 0 outs in a tied game, the relay home is the priority when alignment is set",anim:"hit"},
    {id:"m_vc1b",title:"Relay Read — Two Outs Changes Everything",diff:3,cat:"situational",conceptTag:"cutoff-roles",ageMin:12,ageMax:99,
      description:"You're the manager. Tied game, runner on 2nd, 2 outs. Single to left field — your left fielder fields cleanly, the runner is rounding third hard, and your relay man is lined up. What instruction do you give your cutoff man?",
      situation:{inning:"Top 5",outs:2,count:"0-0",runners:[2],score:[3,3]},
      options:["Relay home — the run matters even more with 2 outs","Cut and hold — just focus on getting the third out on the batter","Tell him to relay home only if the throw is on line","Tell the outfielder to skip the cutoff and throw directly to home"],
      best:0,explanations:["Correct! As the manager, you want the relay home with 2 outs because every run is magnified when the inning is about to end. The batter-runner reaching first is irrelevant — the only play that matters is preventing the run at the plate. Instructing your cutoff man to relay home is the right call, since a full half-inning of at-bats separates you from answering a run that scores here.","Telling your cutoff man to concede the run is backwards thinking with 2 outs, because once it scores you need a full at-bat cycle to answer. The third out is coming regardless — on this play or the next. Preventing the run is the priority.","Telling your cutoff man to hesitate and judge the throw's line wastes precious time, because the relay man's whole job is to redirect imperfect throws. As a manager, you want your team committed to a plan before the play develops, not making split-second judgment calls mid-throw.","Skipping the relay is worse with 2 outs because accuracy matters more than arm strength. A wild throw to home means the batter-runner advances for free, which means you gave up an extra base while also failing to get the runner at home."],
      rates:[80,25,35,18],concept:"With 2 outs the relay home is MORE important — every run is magnified when the inning is about to end",anim:"hit"},
    {id:"m_vc1c",title:"Relay Read — Slow Runner Changes the Math",diff:3,cat:"situational",conceptTag:"relay-double-cut",ageMin:12,ageMax:99,
      description:"You're the manager. Tied game, runner on 2nd, 0 outs. Single to left field — but the runner on second is the slowest player on your team. He's rounding third cautiously. Your relay man is lined up. What do you tell your cutoff man?",
      situation:{inning:"Top 5",outs:0,count:"0-0",runners:[2],score:[3,3]},
      options:["Relay home — the slow runner is an easy out at the plate","Tell him to cut and hold — keep the slow runner at third and preserve the double play","Wave the outfielder's throw through to home for the tag","Tell him to throw behind the batter-runner heading to second"],
      best:1,explanations:["Relaying home against a slow runner who is rounding third cautiously is a mistake, because he likely won't commit to going home. If your cutoff man throws to an empty plate, the ball rolls away and the batter-runner advances to second for free. As a manager, you need to read the runner's hesitation and adjust the call.","Correct! As the manager, you see the slow runner rounding third cautiously, which tells you he won't score on this play. Telling your cutoff man to cut and hold keeps the runner at third where you still have options — a groundball double play or a fly ball tag-up can prevent the run. With 0 outs, keeping the double play alive is more valuable than chasing an out at home that won't happen.","Letting the throw go through to home when the runner has already slowed down is a wasted play, because the throw reaches an empty plate while the batter-runner takes an extra base. The key is recognizing that the slow runner's body language tells you the play is at third, not home.","Throwing behind the batter-runner is low-priority in this situation, because the slow runner at third is the real threat. As a manager, you want your team controlling the most dangerous runner first, which means the cutoff man holds the ball and keeps that runner at third."],
      rates:[30,82,20,25],concept:"A slow runner changes the relay decision — tell your cutoff man to cut and hold to keep the double play alive rather than throwing to an empty plate",anim:"groundout"},
    {id:"m_vc1d",title:"Relay Read — Elite Arm in Left Field",diff:3,cat:"situational",conceptTag:"cutoff-roles",ageMin:12,ageMax:99,
      description:"You're the manager. Tied game, runner on 2nd, 0 outs. Single to left field — your left fielder has the strongest arm on the team and fires a laser to the cutoff man. You know some coaches would tell the cutoff man to just let a strong throw go through. What's your instruction?",
      situation:{inning:"Top 5",outs:0,count:"0-0",runners:[2],score:[3,3]},
      options:["Have the cutoff man redirect the throw home — use that strong arm","Let the throw go through — the arm is strong enough to reach home on its own","Tell him to cut and hold — even with an elite arm, the relay system still applies","Tell him to fake the cut to confuse the runner"],
      best:2,explanations:["Telling your cutoff man to automatically redirect home ignores the situation, because cutting and re-throwing adds a transfer and second throwing motion that wastes the outfielder's arm strength. The relay system works best when the cutoff man reads the play first, not when he reflexively throws home every time.","Letting a throw sail past the cutoff man is dangerous, because the throw is going TO the cutoff, not past him toward home. If it goes through untouched, the ball ends up in no-man's land and both runners advance. As a manager, you never want your team skipping the relay system, since that's how big innings happen.","Correct! As the manager, your instruction should be to trust the system. Even with an elite arm, the cutoff man's job is to catch the ball and read the situation — is the runner committed home? Then relay. Did the runner hold at third? Then hold the ball. Arm strength doesn't change the decision-making process, because you reads matter more than raw power. The system works when every player does their job, regardless of individual talent.","Faking the cut is a trick play that creates confusion for your own defense, because your catcher, pitcher, and other fielders are all making reads based on what the cutoff man does. Clean fundamentals beat deception every time."],
      rates:[30,20,82,15],concept:"As a manager, teach that even elite arms work through the relay system — reads matter more than raw arm strength",anim:"groundout"},
    // ============================================================================
    // VARIABLE MASTERY CLUSTER 3 — The Bunt Call
    // Same base situation, one variable changes the correct answer each time
    // ============================================================================
    {id:"m_vc3a",title:"Bunt Call — Up by 3, Don't Give Away Outs",diff:3,cat:"situational",conceptTag:"bunt-re24",ageMin:12,ageMax:99,
      description:"Runner on 1st, 0 outs, your team is UP by 3 runs in the 5th inning. The #7 hitter steps to the plate — decent bat, not great. Your assistant coach suggests a sacrifice bunt. What's your call?",
      situation:{inning:"Top 5",outs:0,count:"0-0",runners:[1],score:[5,2]},
      options:["Bunt — move the runner into scoring position","Swing away — you're up 3, don't give away outs","Hit and run — be aggressive with the lead","Bunt only if the pitcher throws a strike"],
      best:1,explanations:["Bunting here actually hurts your team, because RE24 data shows it REDUCES your expected runs. Runner on 1st with 0 outs produces 0.94 expected runs, but after a successful sacrifice bunt (runner on 2nd, 1 out), that drops to 0.72. Since you're up by 3, you want to pile on more runs to put the game away, which means giving away an out for a 0.22 run reduction is the wrong trade.","This is the right answer! RE24 says: runner on 1st, 0 outs = 0.94 expected runs, since you runner on 2nd, 1 out = 0.72 expected runs. The bunt costs you 0.22 expected runs. Up by 3, you want to pile on runs and put the game away, not sacrifice outs.","Hit and run is overly aggressive with a comfortable lead, because if the hitter misses, you've got a runner thrown out at second and wasted an opportunity. Play standard baseball with the lead.","'Bunt only on a strike' still sacrifices an out for less expected value — the issue isn't strike/ball — it's that the bunt itself reduces expected runs when you're up by 3."],
      rates:[25,82,35,30],concept:"RE24: bunting with 0 outs reduces expected runs from 0.94 to 0.72 — don't give away outs when you have a lead",anim:"groundout"},
    {id:"m_vc3b",title:"Bunt Call — Tied Game, 9th Inning, Weak Hitter",diff:3,cat:"situational",conceptTag:"scoring-probability",ageMin:12,ageMax:99,
      description:"Runner on 1st, 0 outs, TIED game in the bottom of the 9th. Your #8 hitter steps to the plate — he's batting .180 and strikes out 40% of the time. The #9 hitter behind him is your pitcher (or weakest hitter). What's the call?",
      situation:{inning:"Bot 9",outs:0,count:"0-0",runners:[1],score:[4,4]},
      options:["Swing away — RE24 says bunting always reduces expected runs","Bunt — this is the exception where bunting makes sense","Bunt — but only if the defense is playing back","Hit and run — put pressure on the defense"],
      best:1,explanations:["RE24 measures expected RUNS (plural), but in a tied game in the 9th, you only need ONE run. Scoring probability tells a different story: runner on 2nd with 1 out has a higher SINGLE-RUN scoring probability than runner on 1st with 0 outs when your hitters are weak. This is the key distinction — RE24 vs. scoring probability.","Correct! This is the classic exception where the percentage play favors bunting despite the risk. While bunting statistically costs expected runs (RE24: 0.94 to 0.72), you don't need multiple runs. You need exactly ONE run. Scoring probability (the chance of scoring at least one run) actually increases with a runner on 2nd and 1 out when the hitters are weak (.180 hitter). A single now scores the winning run. Additionally, the .180 hitter is more likely to make an out swinging (40% K rate) than to get a hit, so the bunt is a higher-percentage play for manufacturing one run.","'Only if the defense is playing back' is overthinking it, which means the bunt makes sense regardless of defensive alignment here — the .180 hitter's bat doesn't threaten enough to change the calculation.","Hit and run with a .180 hitter who strikes out 40% of the time is a disaster waiting to happen, because if he whiffs, the runner is thrown out at second. The bunt is the safe manufacturing play."],
      rates:[20,85,45,15],concept:"RE24 measures expected runs, but in walk-off situations you need SCORING PROBABILITY — the chance of exactly one run. Bunting a weak hitter in the 9th is the right play.",anim:"hit"},
    {id:"m_vc3c",title:"Bunt Call — Pitcher Hitting in NL-Style Game",diff:3,cat:"situational",conceptTag:"bunt-re24",ageMin:12,ageMax:99,
      description:"Runner on 1st, 0 outs, your team is down by 1 in the 6th. The pitcher steps up to bat — he's a .120 lifetime hitter. Your lineup turns over to the top of the order after him. Should the pitcher bunt?",
      situation:{inning:"Bot 6",outs:0,count:"0-0",runners:[1],score:[2,3]},
      options:["Swing away — the pitcher might surprise you","Bunt — the pitcher can't hit and your top of the order is coming up","Bunt — but only if the pitcher can actually execute a bunt","Pinch hit instead of bunting"],
      best:1,explanations:["A .120 hitter 'surprising you' happens 12% of the time, since the other 88% he makes an out — and likely a WORSE out than a sacrifice bunt (strikeout or weak popup vs. a productive bunt that advances the runner). Swing away is the worst option here.","Correct! This is the most clear-cut bunt situation in baseball, where the risk of giving up an out is justified by the percentage play. A .120 hitter is almost certain to make an out (88% of the time). While bunting statistically costs run expectancy, the tradeoff is clear here — a sacrifice bunt at least makes that out PRODUCTIVE by advancing the runner to scoring position. Then your top-of-the-order hitters — your best bats — get a chance to drive in the run with a runner on second and just 1 out. The bunt converts a near-certain unproductive out into a productive one.","The pitcher's bunting ability matters, but even a mediocre bunt is more productive than a .120 hitter swinging away, because the bar for 'can execute' is very low — just get the ball down.","Pinch hitting is a valid strategic option, but it removes your pitcher from the game — if your bullpen is thin or your pitcher is dealing, the bunt keeps him in while still manufacturing a run. Both are acceptable — the WRONG answer is swinging away."],
      rates:[8,82,55,60],concept:"When a .120 hitter is up, the bunt converts a near-certain unproductive out into a productive one — advance the runner for your better hitters",anim:"groundout"},
    {id:"m_vc3d",title:"Bunt Call — Safety Squeeze vs. Suicide Squeeze",diff:3,cat:"situational",conceptTag:"squeeze-play",ageMin:12,ageMax:99,
      description:"Runner on 3rd, 1 out, tied game in the 7th. A decent contact hitter steps to the plate. You want to manufacture the go-ahead run. Your options are a safety squeeze or a suicide squeeze. What's the difference and which do you call?",
      situation:{inning:"Bot 7",outs:1,count:"0-0",runners:[3],score:[3,3]},
      options:["Suicide squeeze — runner goes on the pitch, batter MUST bunt no matter what","Safety squeeze — runner waits to see the bunt down before breaking home","Suicide squeeze — it's higher risk but the reward is a guaranteed run","Safety squeeze — the runner has the read, and a decent hitter can place the bunt"],
      best:3,explanations:["The suicide squeeze does require the batter to bunt no matter what — even a pitchout or ball in the dirt. If the batter misses, the runner is dead at home. With a decent contact hitter and 1 out, the suicide squeeze is unnecessarily risky. You have a better option.","The safety squeeze means the runner reads the bunt before committing, which means this is safer, but the definition alone isn't the answer — the question is which to CALL.","'Guaranteed run' overstates it, because the suicide squeeze fails if: the batter misses, the pitch is a pitchout, the bunt pops up, or the bunt goes right to the pitcher. It's high-risk, not guaranteed.","Correct! The safety squeeze is the right call here. With a decent contact hitter, 1 out, and a tied game, you don't need to take the extreme risk of the suicide squeeze. In the safety squeeze, the runner on third reads the bunt — if the batter puts it down on the ground, the runner breaks home. If the batter misses or pops it up, the runner stays at third and you still have 1 out with a runner on 3rd. The safety squeeze preserves the runner while still manufacturing the run."],
      rates:[35,40,30,82],concept:"Safety squeeze: runner reads the bunt first, then breaks. Suicide squeeze: runner goes blind. Use safety with a decent hitter and 1 out.",anim:"hit"},
    // ============================================================================
    // VARIABLE MASTERY CLUSTER 4 — The Infield Depth Decision
    // Same base situation, one variable changes the correct answer each time
    // ============================================================================
    {id:"m_vc4a",title:"Infield Depth — Close Game, Runner on 3rd",diff:3,cat:"situational",conceptTag:"infield-positioning",ageMin:12,ageMax:99,
      description:"Runner on 3rd, 0 outs, your team is up by 1 run in the 6th inning. Decent hitter at the plate. Do you bring the infield in to cut off the run at home?",
      situation:{inning:"Top 6",outs:0,count:"0-0",runners:[3],score:[4,3]},
      options:["Infield in — you need to cut off the tying run","Normal depth — a groundball with the infield in has a higher chance of getting through","Infield halfway — split the difference","Corners in, middle back — protect against the bunt and the groundball"],
      best:0,explanations:["Correct! With a 1-run lead, runner on 3rd, and 0 outs, this is a classic 'infield in' situation. Yes, the infield in gives up more groundball hits (about .100 higher BABIP), but the trade-off is worth it — you're cutting off the TYING run. If that run scores, you're in a tied game. The priority is preventing the run, even at the cost of slightly higher hit probability. With 0 outs, there are multiple ways the run can score (sac fly, groundball, wild pitch), so cutting it off at the plate gives you the best chance.","Normal depth sounds safe but concedes the run on any groundball to the right side, since with a 1-run lead, you can't afford to give the tying run away on a routine grounder when you had a chance to get the out at home.","Infield halfway gives you the worst of both worlds — not close enough to throw home reliably, not deep enough for the double play, because in high-leverage situations, commit fully to one strategy rather than splitting the difference.","Corners in, middle back works in some bunt situations but doesn't address the primary goal: cutting off the run at home on a groundball — if the ball goes to short or second, you've conceded the run."],
      rates:[80,30,35,40],concept:"Infield in with a 1-run lead and runner on 3rd — the tying run is worth more than a slightly higher hit probability",anim:"groundout"},
    {id:"m_vc4b",title:"Infield Depth — Big Lead Changes the Calculus",diff:3,cat:"situational",conceptTag:"infield-positioning",ageMin:12,ageMax:99,
      description:"Runner on 3rd, 0 outs — same situation. But this time your team is UP by 4 runs in the 6th inning. Same decent hitter. Do you bring the infield in?",
      situation:{inning:"Top 6",outs:0,count:"0-0",runners:[3],score:[7,3]},
      options:["Infield in — always cut off the run at home with a runner on 3rd","Normal depth — one run won't hurt, prioritize getting outs","Infield halfway — protect against both scenarios","Corners in for the bunt, middle back for the groundball"],
      best:1,explanations:["With a 4-run lead, 'always cut off the run' is too rigid. One run doesn't change the game when you're up by 4. The priority shifts from preventing one run to getting outs and ending the inning. Infield in concedes more hits, which extends the inning and could lead to a bigger rally.","Correct! Up by 4, you can afford to concede one run. Normal depth gives you better range on groundballs, a higher probability of converting outs, and reduces the chance of the inning extending. The run at the plate doesn't tie the game or take the lead — it makes it 7-4. Getting outs is more valuable than preventing a run you can afford. One run is fine; a 5-run rally is not.","Halfway is still a compromise that sacrifices range without gaining enough on the throw home, which means with a 4-run lead, the calculus is clear — play normal depth, maximize your chance of getting outs, and don't worry about one run.","The bunt with a runner on 3rd and 0 outs is unusual for the offense (they likely want a sac fly), because this defensive alignment doesn't match the likely offensive approach. Save the specialty alignments for situations where they address a real threat."],
      rates:[25,82,35,20],concept:"With a big lead, normal depth prioritizes outs over individual runs — don't bring the infield in when you can afford the run",anim:"groundout"},
    {id:"m_vc4c",title:"Infield Depth — Ace on the Mound, Need 3 Outs",diff:3,cat:"situational",conceptTag:"infield-positioning",ageMin:14,ageMax:99,
      description:"Runner on 3rd, 0 outs, up by 2 in the 9th inning. Your ace is on the mound — he's a groundball pitcher with a 58% groundball rate. He needs 3 outs to finish the game. Do you bring the infield in?",
      situation:{inning:"Top 9",outs:0,count:"0-0",runners:[3],score:[5,3]},
      options:["Infield in — 9th inning, protect the lead at all costs","Normal depth — trust your ace to get groundball outs and let the defense work","Infield in for this batter, then adjust based on the result","Double play depth — get two outs at once"],
      best:1,explanations:["Protecting the lead 'at all costs' ignores that your ace's greatest weapon IS the groundball, since infield in reduces his effectiveness — groundballs that would be outs at normal depth become singles through the drawn-in infield. You're actively making your best pitcher worse.","Correct! Your ace has a 58% groundball rate. At normal depth, those groundballs become outs — and a double play is possible to end the game in two pitches. At infield in depth, the same groundballs find holes because the fielders are out of position. A 2-run lead means you can afford to give up 1 run. Normal depth: your ace gets a groundball, your defense turns it into a double play, game over. Infield in: your ace gets a groundball, it skips through, now you have runners on 1st and 3rd with nobody out and the tying run at the plate.","Adjusting per-batter adds complexity in a high-stress moment, because your ace works best with consistent defense behind him. Commit to normal depth and let him pitch to contact.","Double play depth is essentially normal depth — which is the right call — but thinking specifically 'get two outs at once' can lead to gambling on 6-4-3 and missing the out at first. Get the sure out, and the double play will come naturally from your ace's groundball rate."],
      rates:[30,82,40,55],concept:"A groundball pitcher at normal depth is more effective than any pitcher with the infield in — trust the groundball and let the defense work",anim:"doubleplay"},
    {id:"m_vc4d",title:"Infield Depth — 2 Outs Changes Everything",diff:3,cat:"situational",conceptTag:"infield-positioning",ageMin:10,ageMax:99,
      description:"Runner on 3rd, 2 outs, close game — you're up by 1 in the 7th. Do you bring the infield in?",
      situation:{inning:"Top 7",outs:2,count:"0-0",runners:[3],score:[4,3]},
      options:["Infield in — must cut off the tying run","Normal depth — the force play at first is all you need","Infield halfway — still protect against the run but keep range","Corners in, middle back — cover all the options"],
      best:1,explanations:["Infield in with 2 outs is almost never correct. Here's why: with 2 outs, ANY out ends the inning. You don't need to get the runner at home — you just need one out at first base. Normal depth gives you the maximum range to field the groundball and throw to first. The runner at third is irrelevant because the force play at first ends the inning regardless.","Correct! With 2 outs, the defense only needs ONE out to end the inning. That out can come at first base on any groundball. Normal depth maximizes your range and throwing accuracy. The runner on third doesn't matter because if you get the batter out at first, the inning is over and the run doesn't score. Infield in reduces your range and makes it HARDER to get the out you need.","Halfway still sacrifices range, which means with 2 outs, commit to normal depth for maximum range. You're not close enough to throw home reliably and you've given up the fielding range you need to make plays. Keep it simple and effective.","Split alignments add unnecessary confusion in a straightforward situation, because with 2 outs, every fielder should be at normal depth for maximum range — the only out you need is at first base, so maximize your ability to field the ball cleanly."],
      rates:[20,85,35,25],concept:"With 2 outs, the run on third doesn't matter — normal depth and get the out at first to end the inning",anim:"groundout"},
    {id:"m_wp1",title:"Win Probability — Tie Game in the 9th, Sacrifice or Swing Away?",diff:2,cat:"game-management",conceptTag:"win-probability",ageMin:10,ageMax:99,
      description:"Bottom of the 9th, tie game. Leadoff man reaches on a single. Your #2 hitter steps up — a good contact hitter who rarely strikes out. Do you sacrifice bunt him to second?",
      situation:{inning:"Bot 9",outs:0,count:"0-0",runners:[1],score:[3,3]},
      options:["Sacrifice bunt — move the winning run to second with one out","Let him swing away — he's a good hitter, don't give away outs","Hit and run — move the runner and put pressure on the defense","Steal second — don't risk an out at the plate, get the runner in scoring position for free"],
      best:1,explanations:["A sacrifice bunt drops your win probability from about 64% to roughly 59%. You're trading an out to move a runner 90 feet — but that out is more valuable than the base. With a runner on 1st and 0 outs, you have multiple chances to drive him in. With a runner on 2nd and 1 out, you need a hit. The math consistently shows bunting in tie games costs you wins.","Correct! Letting him swing away is the right call. Win Probability research shows a runner on 1st with 0 outs in a tie game gives you about a 64% chance of winning. After a successful sacrifice (runner on 2nd, 1 out), it drops to about 59%. Your good contact hitter swinging away is more likely to get a hit, walk, or advance the runner than a bunt gains. Outs are precious in the 9th — you only get three, and giving one away for 90 feet of baserunning rarely helps.","Hit and run puts pressure on the defense but can backfire if the batter misses or lines out, turning a double play. Moving the runner is risky here, since it's not bad, but the highest win probability comes from simply letting a good hitter hit.","Stealing is risky — a caught stealing drops your win probability to about 40%, because even with a fast runner, the risk-reward ratio doesn't justify it when you have 0 outs and a good hitter up."],
      rates:[25,90,40,15],concept:"In a tie game in the 9th with 0 outs, don't sacrifice bunt — outs are too precious, and the math shows your win probability drops after a successful bunt",explSimple:["The sacrifice bunt drops your win probability from about 64% to roughly 59%.","Win Probability Added (WPA) research shows that runner on 1st with 0 outs in a tie game gives you about a 64% chance of winning.","Hit and run is aggressive and can backfire if the batter misses or lines out, turning a double play.","Stealing is risky — a caught stealing drops your win probability to about 40%."],anim:"hit"},
    {id:"m_wp2",title:"Win Probability — Down 1 in the 8th, Use Your Closer?",diff:3,cat:"game-management",conceptTag:"win-probability",ageMin:12,ageMax:99,
      description:"You're down 3-4 in the bottom of the 8th. Your offense is about to bat. Your closer is available and fresh. The other team's 3-4-5 hitters are due up in the top of the 9th. Do you save your closer for the 9th if you tie it up, or use him now in a non-save situation?",
      situation:{inning:"Bot 8",outs:0,count:"0-0",runners:[],score:[3,4]},
      options:["Save the closer for the 9th — he only pitches in save situations","Use the closer in the 9th regardless — their best hitters are up, keep the game within reach","Use a middle reliever in the 9th — the closer needs to be fresh for extra innings","Match up: use your best lefty for their lefty #3 hitter, then bring the closer for #4 and #5"],
      best:1,explanations:["Saving the closer for a save situation that might never come is results-oriented thinking. If you don't keep the game close in the 9th, you might never get the chance to tie it up. Your best pitcher should face their best hitters at the most critical moment.","Correct! Win probability analysis shows that keeping the deficit to 1 run in the 9th gives you about a 28% chance of winning. Letting it grow to 2+ runs drops that to around 12%. Using your closer against their heart-of-the-order in the 9th — even though it's not a 'save situation' — maximizes your chance of keeping the game within reach. The traditional 'save the closer for the save' approach loses more games than it wins. High-leverage moments matter more than labels.","A middle reliever against their 3-4-5 hitters is a mismatch — your win probability depends on keeping the game close. Use your best arm when the game is on the line.","Matchup pitching in the 9th when you're down is overthinking it, which means your closer is your best pitcher — let him face all three and minimize damage. Managing by matchups works when you're ahead, but when you're behind, you need maximum outs with minimum runs."],
      rates:[30,70,25,45],concept:"Use your best pitcher in the highest-leverage moment, not just in 'save situations' — win probability doesn't care about traditional closer roles",anim:"strikeout"},
    {id:"m_wp3",title:"Win Probability — Intentional Walk to Load the Bases?",diff:2,cat:"game-management",conceptTag:"win-probability",ageMin:10,ageMax:99,
      description:"Top of the 7th, you're up 5-4. Runners on 2nd and 3rd, 1 out. Their cleanup hitter steps to the plate — he's 2-for-3 today with a double. The #5 hitter behind him is 0-for-3 with 2 strikeouts. Do you intentionally walk the cleanup hitter to load the bases?",
      situation:{inning:"Top 7",outs:1,count:"0-0",runners:[2,3],score:[5,4]},
      options:["Walk him — load the bases to set up the force at every base and face the weaker hitter","Pitch to him carefully — don't put the go-ahead run on base","Bring in a reliever to face the cleanup hitter instead","Try to get a double play ball right here"],
      best:0,explanations:["Correct! Loading the bases sets up a force play at every base, including home. This means a groundball to any infielder can get an out at home or start a double play. The #5 hitter has 2 strikeouts today, and with the bases loaded, any out ends the inning with your lead intact. Win probability actually goes UP slightly when you walk a hot hitter to face a cold one — the force at home plate is worth more than the extra baserunner.","Pitching 'carefully' to a hitter who's 2-for-3 with a double is how you give up a 3-run triple, because he's locked in today. The risk of him driving in 2 runs is much higher than the risk of walking him.","A mound visit is fine for composure, but it doesn't change the matchup math, since the cleanup hitter is 2-for-3 with a double — regardless of your pitcher's mindset, loading the bases to face the weaker #5 hitter is the stronger strategic play.","Going for a double play with a hot hitter is wishful thinking. He’s 2-for-3 with a double — he’s more likely to drive a pitch than hit into a DP. Loading the bases and facing the cold #5 hitter is the higher-percentage play."],
      rates:[75,30,45,25],concept:"Loading the bases to set up force plays and face a weaker hitter can increase your win probability — the force at home is worth the extra baserunner",explSimple:["Loading the bases sets up a force play at every base, including home.","Pitching 'carefully' to a hitter who's 2-for-3 with a double is how you give up a 3-run triple.","Bringing in a cold reliever to face a hot hitter in a jam is too disruptive.","Going for a double play against a hot hitter is wishful thinking — load the bases and face the weaker guy."],anim:"walk"},
    {id:"m_mg1",conceptTag:"composure-pressure",title:"Calming a Rattled Team After Errors",diff:2,cat:"leadership",ageMin:9,ageMax:99,
      description:"Your team just committed 3 errors in one inning and gave up 4 unearned runs. Players look defeated. What's your move?",
      situation:{inning:"Top 4",outs:0,count:"0-0",runners:[],score:[6,2]},
      options:["Call timeout and yell at the team to focus","Call timeout, stay calm, remind them the next play is what matters","Immediately sub out the players who made errors","Ignore it and hope they figure it out"],
      best:1,explanations:["Yelling at a team that already feels defeated makes things worse, since players who are scared of making mistakes play tight and make more errors. Fear doesn't fix fielding.","Calling a calm timeout shows your team that you're in control even when things go wrong. Reminding them to focus on the next play — not the last one — gives them something they can actually do. Players respond to confidence and composure from their manager, and a steady voice in a tough moment rebuilds trust faster than any lecture.","Pulling players who made errors in the middle of an inning humiliates them in front of the team, which destroys confidence. Unless there's an injury, let them work through it and prove they can bounce back.","Ignoring the situation means your team stays stuck in the negative spiral. A brief timeout to reset everyone's focus costs nothing and shows your players you're aware of the moment and in control of it."],
      explSimple:["Yelling at players who already feel bad just makes them more afraid to make mistakes.","Stay calm and remind your team to focus on the next play. Your confidence helps them relax!","Pulling players after errors embarrasses them. Let them bounce back.","Ignoring the problem means your team stays upset. A calm timeout helps everyone reset."],
      rates:[30,80,35,25],concept:"When your team is rattled, stay calm and focus on the next play — a manager's composure is contagious",anim:"freeze"},
    {id:"m_ds1",title:"Defensive Substitution — Protecting a Lead in the 9th",diff:2,cat:"substitutions",conceptTag:"defensive-substitution",ageMin:12,ageMax:99,
      description:"You're the manager. Top of the 9th inning, your team leads by 1 run. Your left fielder has been your DH-type player all game — great bat but he's a liability on defense. He misjudged a fly ball earlier. You have a Gold Glove-caliber outfielder on the bench who hasn't batted today. What do you do?",
      situation:{inning:"Top 9",outs:0,count:"0-0",runners:[],score:[5,4]},
      options:["Sub in the Gold Glover for your left fielder — defense matters more than offense now","Keep the left fielder in — he's earned his spot with his bat today","Wait until someone gets on base, then make the switch","Move the left fielder to DH and put the Gold Glover in left"],
      best:0,explanations:["Up by 1 in the top of the 9th, your offense is done — you only need to get 3 outs. A defensive liability in left field is a ticking time bomb when every ball in play could tie or win the game for the other team. The Gold Glover on your bench exists for exactly this moment. His range, reads, and arm can turn a would-be double into a routine catch. Winning managers make this switch without hesitation.","The left fielder's bat doesn't matter anymore — you're playing defense. He already misjudged a fly ball today, and a repeat mistake in the 9th could cost you the game. Loyalty to the lineup is admirable during the game, but in the 9th with a 1-run lead, you need your best gloves on the field.","Waiting until someone gets on base means a ball in the gap or a misread fly could already have tied the game. By the time you react, the damage is done. Make the defensive sub before the inning starts, not after a crisis.","In most youth and high school leagues, there's no DH-to-fielder switch mid-game like that. Even in leagues that allow it, the right move is simpler: put your best defender in the outfield right now, when every out is critical."],
      rates:[82,30,25,28],concept:"In the late innings with a lead, swap offensive liabilities for defensive upgrades — your bat doesn't matter when you only need outs",explSimple:["Put the Gold Glover in! You only need defense now, not offense.","His bat doesn't matter anymore. A defensive mistake in the 9th costs you the game.","Waiting for a baserunner means the damage might already be done. Sub now.","The simpler move is just putting your best defender in left field right now."],anim:"catch"},
    {id:"m_ds2",title:"Defensive Substitution — Catcher Dilemma",diff:2,cat:"substitutions",conceptTag:"defensive-substitution",ageMin:12,ageMax:99,
      description:"It's the 8th inning, your team leads by 3. Your starting catcher is 0-for-3 today but has called a brilliant game — your pitcher has a shutout going. Your backup catcher is a better hitter and has been begging to get in the game. Do you make the switch?",
      situation:{inning:"Bot 8",outs:0,count:"0-0",runners:[],score:[3,0]},
      options:["Keep the starting catcher in — he's calling a shutout and his rapport with the pitcher is more valuable than a better bat","Sub in the backup catcher for his bat — the starter is 0-for-3","Sub in the backup catcher but only for the at-bat, then switch back","Wait until the 9th to make the change"],
      best:0,explanations:["Your catcher is calling a shutout. He and the pitcher have a rhythm, a game plan, and trust built over 8 innings. Swapping catchers mid-shutout disrupts all of that — the new catcher doesn't know which pitches have been working, which sequences the pitcher likes, or how the hitters have been adjusting. Game-calling chemistry is worth more than a marginally better bat when you're already up by 3.","The starter being 0-for-3 is irrelevant when you're leading by 3 runs and your pitcher is throwing a shutout. His value today is behind the plate, not at it. Subbing for offense when your defense is dominant is solving a problem that doesn't exist.","Switching catchers for one at-bat and then switching back is disruptive and wastes a substitution. The pitcher has to adjust to a new catcher mid-inning, then readjust when the starter comes back. Continuity matters behind the plate.","Waiting until the 9th creates the same problem — why disrupt a shutout at all? If the starter has been calling a great game for 8 innings, let him finish it. His pitch-calling is the reason you have a 3-run lead."],
      rates:[82,25,25,33],concept:"A catcher who is calling a great game has value that doesn't show up in the box score — don't disrupt pitcher-catcher chemistry for marginal offensive upgrades",explSimple:["Keep the starter in! His game-calling is why you have a shutout.","Being 0-for-3 doesn't matter when you're winning by 3 runs.","Switching catchers back and forth confuses the pitcher. Pick one and stay.","Disrupting a shutout in the 9th makes no sense. Let the starter finish."],anim:"strike"},
    {id:"m_ds3",title:"Defensive Substitution — Error-Prone Shortstop",diff:3,cat:"substitutions",conceptTag:"defensive-substitution",ageMin:13,ageMax:99,
      description:"You're ahead by 2 in the bottom of the 8th. Your starting shortstop has made 2 errors tonight — both on routine grounders. He also went 2-for-4 with a double. You have a better defensive shortstop on the bench who hasn't played today. Do you make the switch?",
      situation:{inning:"Bot 8",outs:0,count:"0-0",runners:[],score:[5,3]},
      options:["Sub in the better glove — 2 errors tonight means his confidence is shaky and the game is on the line","Keep the starter — he's been good at the plate and 2 errors could just be bad luck","Wait to see if a ball is hit to him first, then decide","Move him to a less important defensive position instead"],
      best:0,explanations:["Two errors on routine grounders in one game is a pattern, not bad luck. When a shortstop's hands or focus fail him twice, the third error is more likely, not less. With a 2-run lead in the 8th, you need reliable defense at the most important infield position. The better glove on your bench is fresh, confident, and ready. His bat doesn't matter — you need outs, and outs come from clean fielding at shortstop.","Two errors on routines suggests a mechanical or focus issue, not random chance. His 2-for-4 at the plate is great, but the game will be decided on defense from here. A third error at shortstop could tie the game or worse. The upgrade at shortstop is more valuable than keeping his bat in the lineup when you're ahead.","Waiting for a ball to be hit to him is reactive management — if the next grounder goes through his legs, the lead shrinks to 1 and momentum shifts. Proactive managers make defensive upgrades before the critical moment, not after.","Moving him to another position doesn't solve the problem if his hands or focus are off tonight. A player who made 2 errors at shortstop might make errors anywhere. The cleanest solution is to bring in the fresh defender at short and protect the lead."],
      rates:[78,30,30,27],concept:"When a fielder makes multiple errors on routine plays, the pattern suggests a focus or mechanics issue — upgrade the defense before the next one costs you the game",explSimple:["Two routine errors is a pattern. Sub in the better glove before the next one hurts.","His bat was great, but defense decides the game from here.","Waiting for another error means the damage is already done. Sub now.","Moving him to another position doesn't fix shaky hands or focus."],anim:"groundout"},
    {id:"m_ss1",title:"Sign Systems — Runner Stealing Your Signs",diff:2,cat:"game-management",conceptTag:"sign-systems",ageMin:11,ageMax:99,
      description:"You're the manager. You notice that the opposing runner on second base seems to be reading your catcher's signs and relaying them to the batter. The batter suddenly looks comfortable and is fouling off tough pitches. How do you adjust?",
      situation:{inning:"Top 5",outs:1,count:"2-2",runners:[2],score:[3,2]},
      options:["Switch to a multiple-sign system with an indicator — the runner can see the signs but won't know which one is live","Tell the catcher to hide the signs better by squeezing his legs together","Pitch out to catch the runner stealing","Have the pitcher just throw fastballs so signs don't matter"],
      best:0,explanations:["When a runner on second is relaying signs, the simplest counter is switching to a multiple-sign system with an indicator. Instead of one sign per pitch, the catcher flashes a sequence — only the sign immediately after the indicator counts. The runner can see all the signs but can't tell the batter which one is live. Every team should have a runner-on-second sign system ready to go.","Hiding signs by squeezing legs together might help briefly, but a smart base runner will adjust his angle. The real fix is changing your system entirely so that even if the runner sees every sign, he can't decode the actual pitch call. Physical adjustments treat the symptom, not the cause.","A pitchout is for catching a runner stealing — it doesn't address the sign-stealing problem. After the pitchout, the runner is still on second and still reading your signs. You need to change the sign system, not throw a wasted pitch.","Throwing only fastballs is surrender. You're giving up your entire pitching strategy just to avoid sign-stealing. A simple indicator system lets your pitcher throw any pitch without the runner knowing what's coming."],
      rates:[82,30,20,33],concept:"When a runner on second is relaying signs, switch to a multiple-sign system with an indicator — the runner sees the signs but can't decode which one is live",explSimple:["Switch to an indicator system! The runner sees all the signs but won't know which one counts.","Hiding signs better is a temporary fix. Change the whole system instead.","A pitchout doesn't fix sign-stealing. The runner will still relay signs after.","Throwing only fastballs gives up your whole strategy. Use an indicator system."],anim:"strike"},
    // LINEUP-CONSTRUCTION scenarios
    {id:"m_lc1",title:"Where Does Your Speedster Hit?",diff:2,cat:"game-management",conceptTag:"lineup-construction",ageMin:12,ageMax:99,
      description:"You're building today's lineup. Your fastest player has a .380 OBP (gets on base 38% of the time) and 40 stolen bases. He hits for moderate power but is your best baserunner by far. Where do you put him in the order?",
      situation:{inning:"Top 1",outs:0,count:"0-0",runners:[],score:[0,0]},
      options:["Bat him 9th — let the bottom of the order turn over to the top","Bat him leadoff — his OBP and speed set the table for everyone behind him","Bat him 2nd — he can hit-and-run behind a traditional leadoff hitter","Bat him 6th — hide him in the middle of the lineup where he can steal bases quietly"],
      best:1,explanations:["Batting a .380 OBP player 9th wastes his ability to get on base. The 9th spot gets the fewest at-bats over a season, and your best on-base percentage belongs where it creates the most opportunities — at the top of the lineup where he bats the most.","A .380 OBP with 40 stolen bases is the ideal leadoff profile. The leadoff hitter's primary job is to get on base, and .380 OBP means he does that nearly 4 out of every 10 plate appearances. Once on, his speed creates constant pressure — the defense has to hold runners, the pitcher has to pitch from the stretch, and stolen bases put him in scoring position without needing a hit behind him. Maximum plate appearances plus maximum speed equals maximum value.","Batting 2nd is a viable option in modern baseball, but the traditional 2nd-spot role (sacrifice bunt, hit-and-run) wastes his OBP advantage. If you're using a modern lineup philosophy where your best overall hitter bats 2nd, then the leadoff spot is still the better fit for a speed-and-OBP player who lacks elite power. Leadoff maximizes his plate appearances.","Batting a .380 OBP player 6th means he gets significantly fewer at-bats than in the leadoff spot — roughly 20 fewer over a season. And 'hiding' a base stealer removes the pressure his speed creates when the top of the order is driving in runs. Speed at the top of the lineup multiplies the value of everyone hitting behind him."],
      explSimple:["Batting 9th wastes his talent — he'd get way fewer at-bats down there.","Leadoff is perfect! He gets on base a lot and his speed puts pressure on the defense every time he reaches.","Batting 2nd could work, but leadoff gives him the most at-bats to use his speed and OBP.","Batting 6th means fewer at-bats and less impact. Put his speed where it helps the most — at the top."],
      rates:[15,85,40,25],concept:"Your highest OBP player with elite speed belongs in the leadoff spot — maximum plate appearances plus speed pressure creates the most offensive opportunities",anim:"steal"},
    {id:"m_lc2",title:"Lefty Lineup Against a Lefty Starter",diff:2,cat:"game-management",conceptTag:"lineup-construction",ageMin:12,ageMax:99,
      description:"You have 2 lefty hitters in your regular lineup, and the opposing starter is a tough left-handed pitcher. Both lefties hit over .300 against right-handers but under .200 against lefties. You have right-handed bench players who hit .250 overall. What do you do?",
      situation:{inning:"Top 1",outs:0,count:"0-0",runners:[],score:[0,0]},
      options:["Start both lefties — they're your best hitters overall","Bench both lefties and start your right-handed bench players","Bench one lefty and keep the one who handles lefties better","Start both lefties but move them lower in the lineup"],
      best:1,explanations:["Starting both lefties against a lefty pitcher ignores the platoon advantage. Hitting under .200 against same-side pitching means they're getting out 80% of the time — your bench players at .250 would get out 75% of the time, which is a meaningful improvement across multiple at-bats. Loyalty to 'your best guys' costs you when the matchup data is this clear.","The platoon advantage is real and significant. Left-handed hitters historically hit 20-30 points lower against left-handed pitchers. Your lefties hit under .200 against lefties, while your right-handed bench players hit .250 overall. That 50+ point gap across 3-4 at-bats each is the difference between generating offense and going quiet. Start the righties against the lefty starter, then bring your lefties off the bench as pinch-hitters when the righty relievers enter the game. You get the platoon advantage twice.","This compromise sounds reasonable but doesn't maximize the advantage. If both lefties hit under .200 against lefties, both should sit. Keeping one in because he's 'less bad' still gives you a weaker bat than a .250 right-handed hitter. Make the full adjustment.","Moving them lower in the lineup doesn't fix the matchup problem — they still face the lefty pitcher, just in a different slot. A lefty hitting .190 against lefties is .190 whether he bats 2nd or 7th. The solution is the platoon advantage, not lineup positioning."],
      explSimple:["Your lefties hit under .200 against lefty pitchers — they'll struggle no matter what.","Bench both lefties and start your right-handed players. Then bring the lefties in later when righty relievers come in.","Keeping one lefty in is better than both, but the righty bench player still has a better chance against the lefty pitcher.","Moving them down in the lineup doesn't fix the problem — they still can't hit the lefty pitcher."],
      rates:[20,80,40,25],concept:"Platoon advantage matters — bench same-handed hitters against tough same-side pitchers and use them as pinch-hitters when the matchup flips",anim:"hit"},
    {id:"m_lc3",title:"Slumping #3 Hitter, Hot #6 Hitter",diff:3,cat:"game-management",conceptTag:"lineup-construction",ageMin:13,ageMax:99,
      description:"Your #3 hitter is in a deep slump — .100 over his last 10 games (3-for-30). Your #6 hitter is red-hot — .450 over the same stretch (13-for-29). A big series starts today. Do you adjust the lineup?",
      situation:{inning:"Top 1",outs:0,count:"0-0",runners:[],score:[0,0]},
      options:["Keep the lineup the same — hot streaks and slumps even out, don't overreact","Swap them — move the hot hitter to #3 and the slumping hitter to #6","Move the hot hitter to #3 but don't drop the slumper below #5 — protect his confidence","Bench the slumping hitter entirely and give him a day off"],
      best:2,explanations:["While slumps and hot streaks do regress toward career averages, 10 games is a meaningful sample — especially heading into a big series. A .100 hitter in the #3 spot is killing rallies. Ignoring 30 at-bats of data because 'it'll even out' costs you wins in the short term when it matters most.","A full swap sounds decisive, but dropping a slumping veteran all the way to #6 can damage his confidence and create clubhouse tension. The #3 hitter earned that spot for a reason — his career numbers support it. The goal is to maximize today's production while respecting that the slump will likely end.","Moving the hot hitter into the #3 spot puts your best current performer where he'll drive in the most runs. Keeping the slumping hitter at #5 instead of dropping him further protects his ego while still reducing his impact on rallies. He still gets quality at-bats with runners on (the 5-hole often has RBI chances), and the smaller move signals confidence that he'll break out soon. You're optimizing for today without overreacting to 10 games of data.","Benching a slumping hitter who is one of your best overall players removes his talent from the lineup entirely. A day off might help mentally, but with a big series starting, you want your best players in the game — just in a spot where a slump hurts less."],
      explSimple:["Ten games of slumping is worth adjusting for, especially with a big series starting.","A full swap is too dramatic. Move the hot hitter up, but don't embarrass the slumping hitter.","Move the hot hitter to #3 and keep the slumping hitter at #5 — you get the best lineup today without making it a big deal.","Benching him loses his talent entirely. Adjust his spot, but keep him in the game."],
      rates:[30,35,80,20],concept:"When adjusting for hot and cold streaks, optimize the lineup for current performance while protecting player confidence — small moves, not dramatic overhauls",anim:"hit"},
    // BULLPEN-MANAGEMENT scenarios
    {id:"m_bm1",title:"Starter at 95 Pitches — Which Reliever?",diff:3,cat:"game-management",conceptTag:"bullpen-management",ageMin:13,ageMax:99,
      description:"7th inning, you're up by 2. Your starter is at 95 pitches and just gave up a single. You have 3 relievers available: Reliever A (fully rested, 3.20 ERA), Reliever B (1 day rest, 2.80 ERA, your best setup man), and Reliever C (2 days rest, 3.50 ERA, throws hard). Who do you bring in?",
      situation:{inning:"Top 7",outs:1,count:"0-0",runners:[1],score:[5,3]},
      options:["Bring in Reliever B — he's your best reliever, use him now","Bring in Reliever A — he's fully rested and solid, save B for the 8th","Let the starter try to finish the inning — 95 pitches isn't that many","Bring in Reliever C — he's had the most rest and throws hard"],
      best:1,explanations:["Reliever B is your best option, but bringing him in for the 7th means he throws 30+ pitches before the 8th and 9th, where leverage is highest. If the game stays close, you'll need him more later. Using your best reliever early in a 2-run game with 2 innings left can leave you exposed when it matters most.","Reliever A (fully rested, 3.20 ERA) is the right call for the 7th. His rest status means he's at full strength, and a 3.20 ERA is solid enough to get through the inning. Saving Reliever B for the 8th sets up your highest-leverage arms for the highest-leverage innings. Bullpen management is about matching arm quality to game importance — the 8th and 9th are more important than the 7th in a close game.","Ninety-five pitches with a runner on and only a 2-run lead is a dangerous combination. Starters in the 3rd time through the order face a significant batting average increase (roughly .030 higher), and 95 pitches means his stuff is declining. A single has already been surrendered — going back to a tiring arm risks the lead.","Reliever C has the most rest but the highest ERA (3.50) and 'throws hard' doesn't mean 'pitches well.' Velocity without command in a 2-run game with a runner on is volatile. Reliever A offers better overall performance at the same rest advantage."],
      explSimple:["Reliever B is your best arm, but save him for the 8th or 9th when the game is on the line.","Reliever A is rested and solid. Use him now and save your best reliever for the later innings.","95 pitches with a runner on base is time to make a change — the starter's stuff is fading.","Throwing hard doesn't mean pitching well. Reliever A has a better ERA and is just as rested."],
      rates:[35,80,25,25],concept:"Match reliever quality to leverage — use solid arms early and save your best reliever for the highest-leverage innings late in the game",anim:"strike"},
    {id:"m_bm2",title:"Closer Used Two of the Last Three Days",diff:3,cat:"game-management",conceptTag:"bullpen-management",ageMin:13,ageMax:99,
      description:"Tie game heading to the 9th inning. Your closer pitched 20 pitches yesterday and 25 pitches two days ago. He says he's available but you can tell his arm is heavy. Your setup man is fully rested with a 3.10 ERA. The other team's best hitters are due up.",
      situation:{inning:"Bot 9",outs:0,count:"0-0",runners:[],score:[4,4]},
      options:["Use the closer — it's a tie game in the 9th, he's built for this","Use the setup man — he's fully rested and nearly as good","Use the closer but on a short leash — pull him at the first sign of trouble","Split the inning — setup man faces the first two hitters, closer finishes"],
      best:1,explanations:["Your closer on heavy legs after back-to-back outings is not the same pitcher who posts a 2.00 ERA fully rested. Using a fatigued closer against the other team's best hitters risks giving up the go-ahead run. His pride says he wants the ball, but 45 pitches in the last 3 days has diminished his stuff — velocity drops, breaking balls flatten, and command suffers.","Your setup man is fully rested with a 3.10 ERA — a small step down from your closer's best, but right now he's the better option. A rested 3.10 ERA pitcher will outperform a fatigued 2.00 ERA pitcher. Rest matters more than reputation in bullpen management. Your closer protects the lead tomorrow when he's had two full days off and can be dominant again.","A 'short leash' still means the closer faces at least one hitter on heavy legs. If he gives up a leadoff double, you've already lost the leverage advantage — bringing in the setup man after damage is done is worse than starting with him. Short leashes still involve risk with the fatigued arm.","Splitting the inning adds a pitching change mid-inning, which means the closer enters in a potentially higher-stress situation (runners on). Using one rested arm for the full inning is cleaner and avoids the complications of a mid-inning transition with a tired closer."],
      explSimple:["Your closer is tired from pitching two of the last three days. A tired closer isn't as good as a rested setup man.","Use the setup man — he's fresh and almost as good. Save the closer for tomorrow when he's rested.","A short leash still means the closer faces hitters when he's tired. Just start with the rested guy.","Splitting the inning adds complications. One fresh pitcher for the whole inning is cleaner."],
      rates:[25,80,35,25],concept:"A fully rested setup man outperforms a fatigued closer — rest status trumps role designation in high-leverage situations",anim:"strike"},
    {id:"m_bm3",title:"8th Inning, Runners On, Lefty Due Up",diff:3,cat:"game-management",conceptTag:"bullpen-management",ageMin:13,ageMax:99,
      description:"8th inning, up by 1. Runners on 1st and 3rd, 1 out. A tough left-handed hitter is due up. Your best lefty reliever is available and has held lefties to a .150 average this year. Your current right-handed reliever has a 3.40 ERA but is pitching well tonight. What's your move?",
      situation:{inning:"Top 8",outs:1,count:"0-0",runners:[1,3],score:[4,3]},
      options:["Stay with the righty — he's pitching well, don't disrupt his rhythm","Bring in the lefty specialist to face the left-handed hitter","Bring in the lefty but only if the next hitter after is also a lefty","Intentionally walk the lefty and let the righty face the next hitter instead"],
      best:1,explanations:["Your righty has a 3.40 ERA, which is solid, but the left-handed hitter is due up with runners on 1st and 3rd and only a 1-run lead. The platoon advantage (.150 vs lefties for your specialist) is too significant to pass up in a situation where one hit can tie or win the game. 'Pitching well tonight' doesn't override a matchup advantage this large.","Your lefty reliever holds left-handed hitters to .150 — that means the batter gets a hit only 15% of the time. In a 1-run game with runners on 1st and 3rd and 1 out, this is exactly the spot your lefty specialist exists for. The platoon advantage in high-leverage situations with runners in scoring position is one of the biggest edges a manager can create. Bring him in, get the out (or two), then go back to your righty or closer for the right-handed hitters.","Waiting to see if the next hitter is also left-handed overthinks the situation. Your lefty specialist's job is to get THIS lefty out — even if it's a one-batter appearance. Managers who use matchup relievers only when multiple same-sided hitters are up underuse their most valuable weapons. This is high-leverage, make the move now.","Intentionally walking the lefty loads the bases, which means any walk, hit-by-pitch, wild pitch, or passed ball scores a run. You're creating a situation where any mistake is catastrophic to avoid a matchup your lefty specialist wins 85% of the time. The math doesn't support loading the bases when you have a dominant platoon option."],
      explSimple:["Your righty is fine, but the lefty specialist is better against this specific hitter. Use the platoon advantage.","Your lefty holds lefties to .150 — bring him in! One-run game, runners on, this is exactly when you use your specialist.","Don't wait for a second lefty. Use your specialist against THIS hitter — that's what he's for.","Loading the bases makes everything more dangerous. Use your lefty specialist to get the out instead."],
      rates:[30,80,25,30],concept:"In high-leverage spots with runners on, use your platoon specialist to maximize the matchup advantage — one out from the right arm can save the game",anim:"strikeout"},
    // IN-GAME-ADJUSTMENTS scenarios
    {id:"m_ia1",title:"They Keep Bunting — Adjust Your Defense",diff:2,cat:"game-management",conceptTag:"in-game-adjustments",ageMin:12,ageMax:99,
      description:"The opposing team has bunted 3 times in the first 4 innings. Two were successful sacrifice bunts and one was a bunt single. They clearly have a bunting game plan. Your third baseman has been playing at normal depth each time. Top of the 5th, leadoff hitter steps in.",
      situation:{inning:"Top 5",outs:0,count:"0-0",runners:[],score:[2,3]},
      options:["Keep playing normal depth — they can't bunt every at-bat","Bring the third baseman and first baseman in to crash on any bunt","Bring just the third baseman in — the first baseman stays back","Shift your entire infield to the left side to take away the bunt"],
      best:1,explanations:["Three bunts in 4 innings is a clear pattern. Hoping they stop is not a defensive strategy. If you keep playing normal depth, they'll keep bunting because it's working — two sacrifices and a hit already. Patterns that produce results get repeated.","After 3 successful bunts, you adjust the defense. Bringing both corners in (third baseman and first baseman) takes away the bunt by reducing the distance to the ball. The third baseman charges from a shorter starting point, and the first baseman can field bunts to the right side. With both corners crashing, the batter has nowhere to place a bunt safely. This also forces the other team to adjust THEIR strategy — if they can't bunt, they have to swing away, which might not be their strength.","Bringing only the third baseman in leaves the right side open for push bunts toward first base. A smart bunting team will redirect to whichever side isn't defended. Both corners need to adjust, or the bunt just goes the other way.","Shifting the entire infield left doesn't address bunting — it's a pull-hitting defensive alignment. A bunt goes where the batter places it, and a shifted infield creates even more open space for a well-placed bunt. Match the defensive adjustment to the offensive tactic you're defending against."],
      explSimple:["They bunted 3 times and it worked. Hoping they stop isn't a plan — adjust your defense.","Bring both corners in so there's nowhere to bunt safely. Force them to swing the bat instead.","If only the third baseman comes in, they'll just bunt toward first base. Both sides need to adjust.","An infield shift is for pull hitters, not bunters. Match your defense to what they're actually doing."],
      rates:[20,85,35,25],concept:"When the opponent establishes a bunting pattern, bring both corner infielders in to take away the bunt and force them to change their approach",anim:"bunt"},
    {id:"m_ia2",title:"Their Cleanup Is Destroying Your Starter",diff:2,cat:"game-management",conceptTag:"in-game-adjustments",ageMin:12,ageMax:99,
      description:"The opposing cleanup hitter is 3-for-3 with 2 doubles off your starter — all hit to the right-center gap. He's coming up again in the 5th with a runner on 1st and 1 out. Your starter says he can get him this time.",
      situation:{inning:"Bot 5",outs:1,count:"0-0",runners:[1],score:[3,4]},
      options:["Trust your starter — he says he can get him","Shift your outfield — move the right-center fielder toward the gap where he's been hitting","Intentionally walk him to set up a double play","Bring in a reliever to face just this hitter"],
      best:1,explanations:["Your starter has given up 3 hits to this hitter, including 2 doubles to the same gap. 'I can get him this time' is competitor's pride, not evidence-based strategy. Three at-bats of data showing the same result means the hitter has solved your pitcher's approach. Trusting feel over evidence is how you fall behind.","The hitter is 3-for-3 to right-center. Before changing pitchers or conceding a base, make a defensive adjustment first. Shifting your center fielder and right fielder to shade the right-center gap takes away the area where he's been hitting. If he hits another ball to right-center, your outfielder is already there. If he adjusts and pulls the ball, he's changing his approach — which means he's no longer locked in. A defensive shift costs you nothing and forces the hitter to adjust or hit into your repositioned defense.","Walking the cleanup hitter puts the go-ahead run on base and relies on turning a double play — which only happens about 10-15% of the time on any given ball in play. You're giving a free base to avoid a hitter you can defend against with better positioning. Walking him makes the situation worse, not better.","Bringing in a reliever for one hitter in the 5th inning burns an arm early. You still have 4+ innings to play, and every reliever you use now is unavailable later. A defensive adjustment costs zero bullpen arms and addresses the problem directly."],
      explSimple:["He's already 3-for-3 off your starter to the same spot. Hoping for a different result won't work.","Shift your outfielders toward right-center where he keeps hitting! Make his favorite spot harder to reach.","Walking him puts the go-ahead run on base. Adjust your defense instead of giving a free base.","Using a reliever in the 5th for one hitter wastes an arm you'll need later. Shift the defense first."],
      rates:[20,80,30,35],concept:"When a hitter repeatedly hits to the same zone, shift your defense to take away that area before making pitching changes — defensive adjustments are free",anim:"catch"},
    {id:"m_ia3",title:"Down 4-0 After 3 Innings — Strategic Approach",diff:3,cat:"game-management",conceptTag:"in-game-adjustments",ageMin:13,ageMax:99,
      description:"Your team is down 4-0 after 3 innings. Your starter got hit hard and is at 65 pitches. Your offense has only 2 hits. The other team's pitcher looks dominant. You have 6 innings left to play. What's your strategic approach?",
      situation:{inning:"Bot 3",outs:2,count:"0-0",runners:[],score:[0,4]},
      options:["Start bunting and playing small ball — chip away one run at a time","Stay aggressive — keep swinging for extra-base hits to close the gap quickly","Focus on working deep counts to drive up the other pitcher's pitch count and get to their bullpen","Pull your starter now and save the bullpen for a close game later in the week"],
      best:2,explanations:["Bunting when you're down 4 runs is counterproductive. Each bunt gives away an out, and when you're behind by 4, outs are your most precious resource. You need baserunners and big innings, not sacrifice outs. Small ball is for close games, not 4-run deficits.","Aggressive swinging sounds right for a comeback, but undisciplined aggression against a dominant pitcher plays into his hands. If he's dealing, hacking at early-count pitches produces weak contact and quick innings. You need to be selectively aggressive — look for your pitch, but make him work for every out.","Driving up the pitch count is the most strategic approach when trailing a dominant pitcher. If he's cruising through 3 innings on 45 pitches, he could go 7 or 8 innings. But if your hitters take pitches, work full counts, and foul off tough pitches, his pitch count climbs. By the 5th or 6th inning, he's at 90+ pitches and tiring — his stuff declines, and his bullpen comes in. Most bullpens are weaker than a team's ace. Creating scoring opportunities in innings 6-9 against relievers is your best path back into the game.","Pulling your starter at 65 pitches to 'save bullpen for later in the week' concedes today's game. A 4-run deficit after 3 innings is absolutely recoverable — MLB teams come back from 4+ run deficits about 10% of the time. Giving up on a game that's still winnable hurts team morale and wastes the competitive opportunity."],
      explSimple:["Bunting when you're down 4 gives away outs you desperately need. You need hits, not sacrifices.","Swinging wildly against a dominant pitcher just gives him easy outs. Be smart about which pitches you attack.","Work deep counts to tire their pitcher out. Once he leaves and the bullpen comes in, your chances get better.","You can still come back from 4-0. Don't give up on the game — 6 innings is a lot of baseball."],
      rates:[15,30,80,40],concept:"When trailing by multiple runs against a dominant starter, work deep counts to drive up his pitch count — getting to a weaker bullpen is your best path to a comeback",anim:"hit"},
  ],
  catcher: [
    {id:"ct1", conceptTag:"pitch-sequencing",title:"Pitch Calling — Full Count",diff:2,cat:"pitch-calling",ageMin:9,ageMax:99,
      description:"Runner on 2nd, 2 outs, full count 3-2. The batter has struck out twice on breaking balls today. What do you call?",
      situation:{inning:"Bot 5",outs:2,count:"3-2",runners:[2],score:[3,2]},
      options:["Fastball — don't walk him","Slider low and away — he's been chasing","Changeup — keep him guessing","Curveball in the dirt — try to get him to chase"],
      best:1,explanations:["A fastball on 3-2 is predictable, because good hitters sit fastball in this count.","Slider low and away — he's been chasing breaking balls all day, striking out twice — make him prove he can lay off.","A changeup that misses is ball four, which means too risky with a runner in scoring position.","Curveball in the dirt on 3-2 risks a wild pitch advancing the runner to 3rd on ball four, because the downside outweighs the potential gain."],
      rates:[45,85,35,30],concept:"Use a hitter's weakness even in full counts — pattern recognition wins",explSimple:["A fastball on 3-2 is predictable.","He's struck out twice on breaking balls — go back to the well.","A changeup that misses is ball four.","Curveball in the dirt on 3-2 risks a wild pitch advancing the runner to 3rd on ball four."],anim:"strikeout"},
    {id:"ct2", conceptTag:"wild-pitch-coverage",title:"Blocking a Pitch in the Dirt",diff:1,cat:"blocking",ageMin:6,ageMax:99,
      description:"Runner on 3rd, 1 out, tie game. Your pitcher just threw a curveball in the dirt. How do you block it?",
      situation:{inning:"Bot 7",outs:1,count:"1-2",runners:[3],score:[2,2]},
      options:["Drop to both knees and center your body on the ball","Reach out and try to catch it with your mitt","Stay standing and swipe at it","Turn sideways to create a wider wall"],
      best:0,explanations:["Textbook! Drop to knees, tuck chin, center body on the ball, and keep it in front of you — the runner stays at 3rd.","Trying to backhand a ball in the dirt often leads to it squirting away. Block first, catch second.","Staying standing leaves a huge gap underneath you, and the ball will roll right through to the backstop.","Turning sideways can deflect the ball unpredictably — square up and smother it."],
      rates:[85,30,15,40],concept:"Block first, catch second — keep your body centered behind the ball in the dirt",explSimple:["Great choice! Textbook! Drop to knees, tuck chin, center body on ball, keep it in front.","Trying to backhand a ball in the dirt often leads to it squirting away.","Not the best move. Staying standing leaves a huge gap underneath.","Not the best move. Turning sideways can deflect the ball unpredictably."], anim:"catch"},
    {id:"ct3",title:"Steal Attempt at 2nd",diff:2,cat:"throwing",conceptTag:"steal-window",ageMin:11,ageMax:99,
      description:"Fast runner on 1st takes off for 2nd on the pitch. Fastball, good location. What's your play?",
      situation:{inning:"Top 3",outs:0,count:"0-1",runners:[1],score:[1,0]},
      options:["Fire to 2nd immediately","Pump fake, then throw","Hold the ball — don't risk a wild throw","Throw to the pitcher for a rundown"],
      best:0,explanations:["Fire to 2nd immediately — quick transfer, strong throw! A 1.9-second pop time gives you the best chance to nail him.","Pump fakes work in football, but in baseball they just waste time — the runner is already sliding into second.","Holding lets him take 2nd for free. Trust your arm and make the throw.","The runner is already at 2nd by the time the pitcher gets involved — throw through to the bag directly."],
      rates:[85,25,30,20],concept:"Quick transfer and pop time under 2.0 seconds is the key to throwing out runners",explSimple:["Quick transfer, strong throw to 2nd!","Pump fakes work in football.","Holding lets him take 2nd for free.","The runner is already at 2nd by the time the pitcher gets involved."],anim:"throwHome"},
    {id:"ct4", conceptTag:"catcher-framing",title:"Framing a Borderline Pitch",diff:2,cat:"framing",ageMin:9,ageMax:99,
      description:"Your pitcher just threw a fastball that caught the outside corner — barely. It could go either way. How do you frame it?",
      situation:{inning:"Top 6",outs:1,count:"2-2",runners:[],score:[3,1]},
      options:["Hold your glove completely still right where you caught it","Pull the mitt toward the center of the zone subtly","Stab at the ball dramatically to show it was a strike","Stand up immediately — show confidence it was a strike"],
      best:1,explanations:["Holding still is solid framing, especially in high-leverage situations. On a routine borderline pitch like this though, a subtle pull can help sell it without being obvious.","On a borderline pitch in a normal count, the best framers 'stick and pull' — catch it cleanly and gently bring it toward the zone — studies show this adds 20+ called strikes per season. The subtle pull works best when the umpire isn't hyper-focused on your glove.","Stabbing is obvious and umpires hate it, which means it screams 'I know that was a ball.'","Standing up tells the umpire you're already moving on — but it can also look like you're lobbying."],
      rates:[55,85,15,35],concept:"Elite framing is subtle — catch, stick, and gently guide toward the zone",explSimple:["Holding still is solid framing, especially in high-leverage situations.","On a borderline pitch in a normal count, the best framers 'stick and pull' — catch it cleanly and gently bring it toward the zone.","Stabbing is obvious and umpires hate it.","Standing up tells the umpire you're already moving on — but it can also look like you're lobbying."],anim:"strike"},
    {id:"ct5", conceptTag:"pitch-sequencing",title:"Pitch Calling — Leadoff Hitter",diff:1,cat:"pitch-calling",ageMin:6,ageMax:99,
      description:"Top of the 1st inning, nobody on. Leadoff hitter bats as a contact guy who slaps singles. What's your game plan?",
      situation:{inning:"Top 1",outs:0,count:"0-0",runners:[],score:[0,0]},
      options:["Start with a first-pitch fastball for a strike","Curveball to surprise him","Pitch around him — he's not a power threat","Changeup low to induce a groundball"],
      best:0,explanations:["Get ahead! First-pitch strikes put the at-bat in the pitcher's control — 0-1 counts favor the pitcher significantly.","Risky to start with off-speed — if he is patient, you are behind 1-0 immediately, and now the hitter has the advantage.","Never pitch around a leadoff hitter — putting a free runner on base to start the inning is a gift.","Changeups are great, but on the first pitch the hitter does not have a timing reference yet, so the speed difference is less effective."],
      rates:[85,40,15,50],concept:"Getting strike one against leadoff hitters sets the tone for the entire inning",explSimple:["Great choice! Get ahead! First-pitch strikes put the at-bat in the pitcher's control.","Not the best move. Risky to start with off-speed — if he's patient, you're behind 1-0 right away.","Not the best move. Never pitch around a leadoff hitter.","Not the best move. Changeups are great — but on the first pitch, the hitter doesn't have."], anim:"strike"},
    {id:"ct6", conceptTag:"fly-ball-priority",title:"Pop-Up Coverage",diff:1,cat:"defense",ageMin:6,ageMax:99,
      description:"High pop-up near home plate! It's drifting toward the 1st base dugout. Whose ball is it?",
      situation:{inning:"Bot 4",outs:1,count:"0-1",runners:[],score:[1,0]},
      options:["It's the catcher's ball — rip off your mask and get under it","Let the first baseman take it — he has a better angle","Let the third baseman take it — he's closer","Wait and see who gets there first"],
      best:0,explanations:["That's your ball! Toss your mask AWAY from the play, turn your back to the field, and track the spin, because you catchers own all pop-ups near home.","The first baseman would be running away from the ball — you're already facing the right direction.","Pitchers rarely catch pop-ups, which means this is the catcher's domain.","Waiting causes collisions and dropped balls, because someone has to take charge — and that's you."],
      rates:[85,35,15,20],concept:"Catchers own pop-ups near home — toss mask away, turn to the infield, and take charge",explSimple:["Great choice! That's your ball! Toss your mask AWAY from the play, turn your back to.","Not the best move. The first baseman would be running away from the ball.","Not the best move. Pitchers rarely catch pop-ups.","Not the best move. Waiting causes collisions and dropped balls."], anim:"popup"},
    {id:"ct7", conceptTag:"bunt-defense",title:"Squeeze Play Defense",diff:3,cat:"defense",ageMin:12,ageMax:99,
      description:"Runner on 3rd, 1 out, close game. You notice the batter's hands shift on the bat and the runner on third is leaning hard. You suspect a squeeze play is coming on the next pitch.",
      situation:{inning:"Bot 7",outs:1,count:"1-0",runners:[3],score:[4,3]},
      options:["Call for a pitchout to catch the runner","Charge the bunt and fire home","Set up normally and react to whatever happens","Signal the pitcher to throw high and tight — bust the squeeze"],
      best:3,explanations:["A pitchout can catch the runner, but if the batter doesn't bunt, you've just thrown a ball for no reason, since it also doesn't make the bunt harder if they do squeeze.","If you charge before the bunt, you leave home plate uncovered. You need to stay back.","Reacting is too passive when you've spotted the squeeze coming. You have the advantage of reading it early — use it.","High and tight makes the bunt almost impossible, because the runner is committed and dead to rights. This is how you kill a squeeze — a pitch up and in is nearly unbuntable."],
      rates:[40,20,25,85],concept:"The best squeeze defense is pitching high and inside — it's nearly impossible to bunt",anim:"strike"},
    {id:"ct8", conceptTag:"pitch-sequencing",title:"Pitch Calling — Power Hitter",diff:2,cat:"pitch-calling",ageMin:9,ageMax:99,
      description:"Cleanup hitter, known for pulling inside pitches. Count is 1-1. How do you attack him?",
      situation:{inning:"Bot 3",outs:0,count:"1-1",runners:[1],score:[2,1]},
      options:["Fastball inside — challenge him","Slider away — make him reach","Changeup inside — he'll pull it foul","Curveball right down the middle — surprise him"],
      best:1,explanations:["He thrives on inside pitches — don't feed his strength.","Work the outer half! If he pulls everything, make him beat you the other way, which means most power hitters are weakest on pitches away.","Inside changeup still gives him something to turn on.","Hanging a curve over the plate to a power hitter? That's a souvenir in the stands."],
      rates:[25,85,45,15],concept:"Pitch away from a pull hitter's strength — make them beat you the opposite way",explSimple:["He thrives on inside pitches.","If he pulls everything, make him beat you the other way.","Inside changeup still gives him something to turn on.","Hanging a curve over the plate to a power hitter?"],anim:"strike"},
    {id:"ct9", conceptTag:"wild-pitch-coverage",title:"Wild Pitch — Ball to the Backstop",diff:3,cat:"blocking",ageMin:12,ageMax:99,
      description:"Runner on 2nd, 1 out, tie game in the 7th. Your pitcher's slider bounces in the dirt and skips past you to the backstop. What do you do first?",
      situation:{inning:"Bot 7",outs:1,count:"1-2",runners:[2],score:[3,3]},
      options:["Look at the runner to see if he's going to 3rd","Sprint to the ball immediately — retrieve it first","Yell for the pitcher to cover home","Point at the ball so the pitcher can get it"],
      best:1,explanations:["Never look at the runner before getting the ball! After all, every split-second you waste watching the runner is a step closer he gets to scoring.","Go to the ball FIRST, then look at the runner, because the fastest recovery wins — you can't make any play without the ball in your hand.","The pitcher should cover home, but that's his read — your job is to retrieve the ball as fast as possible. So this approach matters in this situation.","Pointing wastes time, since the pitcher already heard the ball hit the backstop. Sprint to it yourself."],
      rates:[20,85,45,15],concept:"On a wild pitch, go to the ball FIRST — you can't make any play without the ball in your hand",anim:"throwHome"},
    {id:"ct10", conceptTag:"pitch-sequencing",title:"Pitch Calling — Two Strikes",diff:2,cat:"pitch-calling",ageMin:9,ageMax:99,
      description:"Count is 0-2. The batter has been late on fastballs all night. Runner on 1st. What do you call?",
      situation:{inning:"Top 6",outs:1,count:"0-2",runners:[1],score:[3,2]},
      options:["Fastball up and in — he can't catch up to it","Waste a pitch in the dirt, then come back with heat","Slider on the outside corner — finish him","Changeup — change his eye level"],
      best:1,explanations:["He's late on fastballs, but don't groove one, because 0-2 gives you room to expand.","Perfect! Waste one to expand the zone, THEN finish him — you have two strikes to play with — use that advantage.","Going right for the corner on 0-2 is a mistake if you miss back over the plate.","Changeup is fine but you want to set up the put-away pitch with a ball first."],
      rates:[31,70,35,39],concept:"On 0-2, waste a pitch to expand the zone — then go for the strikeout",explSimple:["He's late on fastballs, but don't groove one.","Waste one to expand the zone, THEN finish him.","Going right for the corner on 0-2 is a mistake if you miss back over the plate.","Changeup is fine but you want to set up the put-away pitch with a ball first."],anim:"strikeout"},
    {id:"ct11", conceptTag:"of-communication",title:"Communication — Positioning",diff:1,cat:"defense",ageMin:6,ageMax:99,
      description:"Left-handed pull hitter at the plate. Your infielders haven't shifted. What do you do?",
      situation:{inning:"Bot 2",outs:0,count:"0-0",runners:[],score:[0,0]},
      options:["Nothing — fielders should know their positioning","Signal the infield to shift toward the pull side","Call time and physically walk out to reposition them","Yell positioning adjustments from behind the plate"],
      best:3,explanations:["As catcher, YOU are the field general — you can see the whole field, so take charge and speak up.","Subtle signals might not be seen or understood in-game, and you cannot afford a miscommunication with a pull hitter at the plate.","Calling time slows the game and tips off the batter about the upcoming shift.","Yell positioning adjustments from behind the plate — catchers are the field generals! You see the whole field and can direct the defense with quick verbal calls between pitches."],
      rates:[20,45,40,85],concept:"The catcher is the field general — direct defensive positioning from behind the plate",explSimple:["Not the best move. As catcher, YOU are the field general.","Not the best move. Subtle signals might not be seen or understood in-game.","Not the best move. Calling time slows the game and tips off the batter about the upcoming shift.","Great choice! Catchers are the field generals! Quick verbal calls to shift the defense are your job."], anim:"catch"},
    {id:"ct12", conceptTag:"wild-pitch-coverage",title:"Passed Ball Prevention",diff:2,cat:"blocking",ageMin:9,ageMax:99,
      description:"Runner on 2nd, 2 outs, pitcher's count 1-2. Your pitcher signals for a hard curveball. How do you set up?",
      situation:{inning:"Bot 8",outs:2,count:"1-2",runners:[2],score:[5,4]},
      options:["Set up normally and react to the bounce","Pre-shift your weight forward, ready to drop and block","Set the target low to keep the pitch down","Move your target up — don't risk a pitch in the dirt"],
      best:1,explanations:["Reacting after the ball bounces is too late, because you need to anticipate.","Get your weight forward and be READY to block before the pitch, since great catchers expect to block curveballs in the dirt. Prevention starts before the pitch.","A low target is fine, but you need body preparation, not just glove positioning.","Moving the target up might cause the pitcher to leave the curve flat — a mistake to hit."],
      rates:[30,85,45,25],concept:"Anticipate the block before the pitch — pre-shift weight and be ready for dirt",explSimple:["Reacting after the ball bounces is too late.","Get your weight forward and be READY to block before the pitch.","A low target is fine, but you need body preparation, not just glove positioning.","Moving the target up might cause the pitcher to leave the curve flat — a mistake to hit."],anim:"catch"},
    {id:"f33", conceptTag:"pickoff-mechanics",title:"Runner on First — Call a Pickoff?",diff:1,cat:"infield",ageMin:6,ageMax:99,
      description:"Top of the 4th, runner on 1st, 1 out, tied 2-2. Your pitcher keeps ignoring the runner and the runner keeps taking bigger leads. You're the catcher.",
      situation:{inning:"Top 4",outs:1,count:"0-0",runners:[1],score:[2,2]},
      options:["Call for a pickoff throw to first","Call a pitchout","Set up outside for a fastball — give yourself a quick throw","Throw down to first yourself after the pitch"],
      best:0,explanations:["When the runner gets comfortable with big leads and your pitcher isn't holding him close, call for a pickoff! Signal your pitcher to throw to first base. Even if you don't get the runner out, it shortens his lead and makes him think twice about stealing.","A pitchout is a ball — it puts your pitcher behind in the count, because a pickoff attempt doesn't cost a ball.","Ignoring a runner who's taking huge leads is asking for a stolen base — keep him honest.","Throwing behind the runner after a pitch rarely works — the runner is usually moving back already."],
      rates:[85,35,20,30],concept:"When a runner takes big leads, call for a pickoff — keep him honest even if you don't get him",explSimple:["Great choice! When the runner gets comfortable with big leads and your pitcher isn't holding him close,.","Not the best move. A pitchout is a ball — it puts your pitcher behind in the count.","Not the best move. Ignoring a runner who's taking huge leads is asking for a stolen base.","Not the best move. Throwing behind the runner after a pitch rarely works — the runner is usually."], anim:"catch"},
    {id:"f34", conceptTag:"wild-pitch-coverage",title:"Ball in the Dirt — Block It",diff:1,cat:"infield",ageMin:6,ageMax:99,
      description:"Bot 5th, runner on 3rd, 1 out, down 3-2. Your pitcher uncorks a curveball that bounces in the dirt right in front of you. The runner on 3rd is watching.",
      situation:{inning:"Bot 5",outs:1,count:"1-2",runners:[3],score:[3,2]},
      options:["Try to catch it cleanly","Drop to your knees and block it — keep it in front of you","Reach down and backhand it","Move to the side to avoid it"],
      best:1,explanations:["Trying to catch a ball in the dirt often leads to it getting past you, which means if it gets past, the runner on 3rd scores.","Drop to your knees, tuck your chin, and make yourself as wide as possible, because the goal isn't to catch it — it's to keep it in front of you. With a runner on 3rd, a passed ball scores a run. Blocking is the most important skill a catcher has.","Backhanding a ball in the dirt is unreliable. If you miss, the runner scores. Block it with your body.","Moving away from the ball lets it go to the backstop, since the runner scores easily."],
      rates:[40,90,25,15],concept:"With runners on base, block balls in the dirt — drop to your knees and keep it in front of you",explSimple:["Trying to catch a ball in the dirt often leads to it getting past you.","Great choice! Drop to your knees, tuck your chin, and make yourself as wide as possible.","Not the best move. Backhanding a ball in the dirt is unreliable.","Not the best move. Moving away from the ball lets it go to the backstop."], anim:"catch"},
    {id:"f35", conceptTag:"fly-ball-priority",title:"Pop-Up Near the Backstop",diff:1,cat:"infield",ageMin:6,ageMax:99,
      description:"Top of the 3rd, nobody on, 2 outs. The batter pops up a foul ball drifting toward the backstop. You're the catcher. Whose ball is it?",
      situation:{inning:"Top 3",outs:2,count:"1-2",runners:[],score:[1,0]},
      options:["Your ball — catchers take all pop-ups near home","Let the pitcher get it — he's closer","Call off the first baseman — it's your territory","Wait and see who gets there first"],
      best:0,explanations:["Foul pop-ups near home plate are the catcher's ball. Rip off your mask, find the ball, and call everyone off. You have the best angle on pop-ups behind and around home plate because you're already facing the right direction.","The pitcher should be backing up, not fielding pop-ups behind home, because that's your job.","You should call off the first baseman, but more importantly — because it's YOUR ball to catch, not just to direct traffic.","Waiting creates confusion and lets easy outs drop — someone has to take charge, and near home plate, that's always the catcher."],
      rates:[85,15,50,10],concept:"Pop-ups near home plate are the catcher's ball — rip off the mask, call everyone off, and catch it",explSimple:["Great choice! Foul pop-ups near home plate are the catcher's ball.","Not the best move. The pitcher should be backing up, not fielding pop-ups behind home.","Not the best move. You should call off the first baseman, but more importantly — it's YOUR ball.","Not the best move. Waiting creates confusion and lets easy outs drop."], anim:"catch"},
    {id:"f36", conceptTag:"pitch-sequencing",title:"Batter Keeps Fouling Off Pitches",diff:2,cat:"pitch-calling",ageMin:9,ageMax:99,
      description:"Bot 6th, nobody on, 2 outs, up 4-3. Count is 1-2 but the batter has fouled off your last 4 pitches. He keeps fighting off your fastball. What do you call?",
      situation:{inning:"Bot 6",outs:2,count:"1-2",runners:[],score:[3,4]},
      options:["Keep throwing fastballs — eventually he'll miss","Change speeds — call for a changeup or curveball","Move the pitch location — go inside if you've been outside","Waste a pitch way out of the zone"],
      best:1,explanations:["If he is fouling off your fastball, he has timed it — throwing more of the same pitch at the same speed just gives him more chances to connect.","When a hitter keeps fouling off your fastball, he is ON your fastball. Change speeds! A changeup or curveball arrives 8-15 mph slower and completely disrupts his timing. That is how you get the swing-and-miss after a long battle.","Moving location helps, but if he has timed the speed, he will foul it off anywhere in the zone. Change SPEED, not just location.","Wasting a pitch after a 7-pitch at-bat just adds to the count — go for the strikeout with a speed change."],
      rates:[25,85,45,30],concept:"When a batter is fouling off your fastball, change speeds — a changeup disrupts his timing",explSimple:["If he's fouling off your fastball, he's timed it.","When a hitter keeps fouling off your fastball, he's ON your fastball.","Moving location helps, but if he's timed the speed, he'll foul it off anywhere in the zone.","Wasting a pitch after a 7-pitch at-bat just adds to the count."],anim:"strikeout"},
    {id:"f37", conceptTag:"pitch-sequencing",title:"Mound Visit — Pitcher Losing Control",diff:2,cat:"communication",ageMin:9,ageMax:99,
      description:"Top of the 4th, your pitcher just walked back-to-back batters. Runners on 1st and 2nd, nobody out. He looks frustrated. You're the catcher — time for a mound visit.",
      situation:{inning:"Top 4",outs:0,count:"1-2",runners:[1,2],score:[3,2]},
      options:["Tell him to calm down and throw strikes","Remind him of the game plan — get a ground ball for a DP","Joke around to lighten the mood, then talk strategy","Walk through the mechanics of your next pitch together"],
      best:2,explanations:["Telling someone to 'calm down' rarely works — it often makes them more tense and self-conscious.","Going straight to strategy is fine, but a frustrated pitcher might not hear you if he is still stuck in his head.","A quick joke or light moment breaks the tension and resets his mental state. Then talk strategy: 'Hey, let us get a ground ball — sinker down, double play, we are out of this.' The mood shift followed by a clear plan is the best mound visit.","Walking through mechanics is good, but a frustrated pitcher needs a mental reset first. Mechanical tips during emotional moments get tuned out."],
      rates:[35,50,85,10],concept:"On mound visits, lighten the mood first, then give a clear plan — frustrated pitchers need a reset",explSimple:["Telling someone to 'calm down' rarely works.","Going straight to strategy is fine, but a frustrated pitcher might not hear you if he's still in his head.","A quick joke or light moment breaks the tension and resets his mental state.","Yelling at your pitcher destroys his confidence."],anim:"freeze"},
    {id:"f38", conceptTag:"wild-pitch-coverage",title:"Wild Pitch Recovery",diff:2,cat:"infield",ageMin:9,ageMax:99,
      description:"Bot 7th, runner on 3rd, 2 outs, tied 5-5. Your pitcher's curveball gets away — wild pitch to the backstop! The runner from 3rd is sprinting home. You're the catcher.",
      situation:{inning:"Bot 7",outs:2,count:"1-1",runners:[3],score:[5,5]},
      options:["Sprint to the ball, pick it up, and throw to the pitcher covering home","Grab the ball, then dive back to tag the runner at the plate","Recover the ball and rush a throw to the plate","Sprint to the ball and hold it — the runner already scored"],
      best:0,explanations:["On a wild pitch with a runner on 3rd, the pitcher MUST cover home plate, since you sprint to the backstop, pick up the ball, and throw to your pitcher who should be standing on home plate ready for the tag. This is a practiced play.","Trying to dive back and tag the runner yourself takes too long, because by the time you get the ball and turn around, the runner is already home.","Rushing a throw from the backstop to an empty home plate just throws the ball into the field — you need the pitcher covering before you throw.","Never give up on a play! Even if it looks hopeless, the pitcher covering home gives you a chance to save the run."],
      rates:[85,25,20,15],concept:"On wild pitches, the catcher gets the ball and the pitcher covers home — it's a team play",explSimple:["On a wild pitch with a runner on 3rd, the pitcher MUST cover home plate.","Trying to dive back and tag the runner yourself takes too long.","Rushing a throw from the backstop to an empty home plate (no one covering) just throws the ball into the field.","Never give up on a play!"],anim:"throwHome"},
    {id:"f39", conceptTag:"pitch-sequencing",title:"Batter Peeks at Your Signs",diff:3,cat:"infield",ageMin:12,ageMax:99,
      description:"Top of the 5th, nobody on, 1 out, up 3-1. You notice the batter keeps glancing down at your hand as you set up. He's trying to see what pitch you're calling.",
      situation:{inning:"Top 5",outs:1,count:"0-0",runners:[],score:[3,1]},
      options:["Ignore it — he can't really see your signs","Change your signs to a more complex system","Call the opposite of what you show — fake him out","Tell the umpire to make him stop"],
      best:2,explanations:["Ignoring it gives the batter free information — if he can read even one sign, he knows what's coming.","Changing to complex signs is smart long-term, but right now you can use his peeking against him immediately, since it gives you the best chance of success.","If the batter is peeking, show him one sign and call another, which means flash a fastball sign but set up for a changeup. He'll be expecting heat and get fooled by the speed change. Turn his cheating into your advantage.","The umpire may warn him, but the smarter play is to exploit his peeking to your benefit, since it gives you the best chance of success."],
      rates:[15,50,85,30],concept:"If a batter peeks at your signs, show one pitch and call another — use his cheating against him",anim:"strikeout"},
    {id:"f40", conceptTag:"pitch-sequencing",title:"Runner on Second Sees Your Signs",diff:3,cat:"infield",ageMin:12,ageMax:99,
      description:"Bot 3rd, runner on 2nd, nobody out, tied 2-2. You realize the runner on second might be relaying your pitch signs to the batter. What do you do?",
      situation:{inning:"Bot 3",outs:0,count:"0-0",runners:[2],score:[2,2]},
      options:["Keep your regular signs — they can't really see them","Switch to a series of signs with an indicator","Use your glove to hide your hand better","Shake off every pitch to confuse them"],
      best:1,explanations:["Regular single signs are easy to steal with a runner on second looking right at your hand, because this is a real problem.","With a runner on second, switch to multiple signs with an indicator. For example, show three signs and the second one is the real pitch. Or the sign after a fist is the real one. This makes it nearly impossible for the runner to relay the pitch to the batter.","Hiding your hand better helps, but a runner directly behind the pitcher has a great angle, since multiple signs are the standard solution.","Shaking off every pitch just slows down the game and confuses your own pitcher."],
      rates:[10,85,30,25],concept:"With a runner on 2nd, use multiple signs with an indicator — single signs can be stolen",anim:"freeze"},
    {id:"f41", conceptTag:"pitch-sequencing",title:"Pitcher Wants Fastball, You See Danger",diff:3,cat:"infield",ageMin:12,ageMax:99,
      description:"Top of the 8th, runner on 1st, 2 outs, up 4-3. The batter has been sitting on off-speed all night. Your pitcher shakes you off — he wants his fastball. But you've seen the batter tee off on fastballs twice.",
      situation:{inning:"Top 8",outs:2,count:"1-1",runners:[1],score:[4,3]},
      options:["Go with the pitcher's fastball — he has to be comfortable","Put down the off-speed sign again — trust your read","Call timeout and talk to him on the mound","Signal for a different location — fastball but away from his hot zone"],
      best:2,explanations:["Just giving in without communicating can cost you a big hit, because the pitcher might not know what you know.","Putting the same sign down again when he's already shaken you off creates a disagreement on the mound — talk about it.","A quick mound visit solves this, which means tell him what you've seen: 'He's been sitting fastball — he crushed your heater twice. Let's go changeup and fool him.' Now you're both on the same page. Communication is what great batteries do.","Different location helps, but the batter has been teeing off on the fastball speed, because changing location still leaves him timed on the velocity."],
      rates:[30,25,85,45],concept:"When you disagree with your pitcher, call a mound visit — great catchers communicate, not just receive",anim:"freeze"},
    {id:"f42", conceptTag:"wild-pitch-coverage",title:"Passed Ball vs Wild Pitch",diff:3,cat:"infield",ageMin:12,ageMax:99,
      description:"Bot 6th, runner on 2nd, 1 out, down 4-3. Your pitcher fires a fastball that tails in on the right-handed batter. It's catchable but tough — it nips the inside corner and dips.",
      situation:{inning:"Bot 6",outs:1,count:"2-1",runners:[2],score:[4,3]},
      options:["Stab at it with your glove — try to catch it","Shift your whole body to the ball — receive it with two hands","Just block it — drop to your knees","Let it go — it's too far inside"],
      best:1,explanations:["Stabbing with just your glove on a tough pitch often leads to it deflecting off your mitt, since that's a passed ball and the runner advances.","Move your whole body behind the ball, because shift your feet first, then receive it with soft hands. Catching the ball cleanly prevents the runner from advancing and might earn your pitcher a called strike on a borderline pitch. Body movement first, then glove.","Blocking is for balls in the dirt. This pitch is catchable — block only if you can't get to it cleanly.","Letting a borderline pitch go means the runner could advance on a passed ball, and you lose a potential strike call. And that's why this approach matters in this situation."],
      rates:[30,85,35,10],concept:"On tough pitches, move your whole body first, then receive — don't just stab with the glove",anim:"catch"},
    {id:"ct13", conceptTag:"pitch-sequencing",title:"Pitch Calling With Runner on Second",diff:2,cat:"catcher",ageMin:9,ageMax:99,
      description:"You're the catcher. There's a runner on second base who can see your signs. The batter hits right-handed and pulls the ball with a 1-1 count. Your pitcher has a nasty slider today.",
      situation:{inning:"Top 4",outs:1,count:"1-1",runners:[2],score:[2,2]},
      options:["Switch to a secondary sign system so the runner can't steal your signs","Keep using regular signs but call for all fastballs","Just use one finger for every pitch and let the pitcher decide","Yell out the pitch name so your pitcher can hear you clearly"],
      best:0,explanations:["Smart move! With a runner on second, they can read your normal signs and relay them to the batter — an aggressive base-stealing team with success rates above the break-even threshold makes this risk even greater — switching to a secondary system keeps your pitch calling secret.","Limiting yourself to only fastballs makes your pitcher predictable, which means the runner on second will figure this out quickly and the batter will sit on the fastball.","Letting the pitcher decide defeats the purpose of pitch calling, because the catcher sees the whole field and the batter's stance — you need to stay in control of the game plan.","Never yell out pitch names! The other team will hear you and the batter will know exactly what's coming, since signs exist for a reason."],
      rates:[90,40,25,15],concept:"When a runner reaches second base, switch to a secondary sign system to protect your pitch calls.",explSimple:["With a runner on second, they can read your normal signs and relay them to the batter.","Limiting yourself to only fastballs makes your pitcher predictable.","Letting the pitcher decide defeats the purpose of pitch calling.","Never yell out pitch names!"],anim:"strike"},
    {id:"ct14", conceptTag:"wild-pitch-coverage",title:"Blocking a Curveball in the Dirt",diff:1,cat:"catcher",ageMin:6,ageMax:99,
      description:"You're the catcher. Runner on third, one out, and the count is 0-2. Your pitcher uncorks a sharp curveball that bounces in the dirt about two feet in front of home plate. The runner on third is watching closely.",
      situation:{inning:"Bot 6",outs:1,count:"0-2",runners:[3],score:[4,3]},
      options:["Drop to your knees, tuck your chin, and smother the ball with your body to keep it in front of you","Try to backhand the ball with your glove for a quick transfer in case the runner goes","Stand up and try to catch the ball on a short hop cleanly","Dive to the side to try to snag the ball before it gets past you"],
      best:0,explanations:["Perfect technique! With a runner on third, your number one job is to keep the ball in front of you. Drop, block, and smother — even if you don't catch it cleanly, the runner can't score.","Trying a fancy backhand with a ball in the dirt is risky, because if it gets past your glove, the runner on third scores easily. Block first, worry about throwing later.","Standing up exposes gaps between your legs and body where the ball can scoot through — the blocking position on your knees creates a wall that keeps everything in front.","Diving to the side opens up the entire plate area. If you miss, there's nothing between the ball and the backstop, and that runner is scoring for sure."],
      rates:[90,25,30,10],concept:"With a runner on third, blocking is more important than catching — drop to your knees and keep the ball in front of you.",explSimple:["Perfect technique! With a runner on third, your number one job is to keep.","Trying a fancy backhand with a ball in the dirt is risky.","Not the best move. Standing up exposes gaps between your legs and body where the ball can scoot through.","Not the best move. Diving to the side opens up the entire plate area."], anim:"catch"},
    {id:"ct15", conceptTag:"fly-ball-priority",title:"Pop Fly Behind the Plate",diff:2,cat:"catcher",ageMin:9,ageMax:99,
      description:"You're the catcher. The batter pops a ball straight up behind home plate. It's drifting back toward the screen. Your third baseman runs over, and the umpire is right behind you. The ball is spinning and curving toward the backstop.",
      situation:{inning:"Top 3",outs:0,count:"0-1",runners:[1,2],score:[1,0]},
      options:["Rip off your mask, toss it away from where you're running, turn your back to the field, and track the ball","Keep your mask on for protection and try to find the ball through the cage","Let the third baseman take it since infielders have an easier angle","Wait for the umpire to tell you who should catch it"],
      best:0,explanations:["This is textbook! Toss the mask away from your path so you don't trip, then turn your back to the infield because pop flies behind the plate curve back toward the field. You've got the best angle on this ball.","Your mask blocks your vision and makes it harder to track pop flies, which means always remove it first, but throw it in the opposite direction of where you're headed so you don't trip over it.","Pop flies behind the plate are the catcher's ball, because the third baseman has a harder time tracking a ball moving away from them, but you're already underneath it and can follow it naturally.","Waiting wastes precious time, since on pop flies, the catcher takes charge and calls for the ball. You're the captain behind the plate — be aggressive and take control."],
      rates:[85,25,35,15],concept:"On pop flies behind the plate, toss your mask away from your path, turn your back to the field, and take charge of the catch.",explSimple:["Toss the mask away from your path so you don't trip, then turn your back to the infield because pop flies behind the plate curve back toward the field.","Your mask blocks your vision and makes it harder to track pop flies.","Pop flies behind the plate are the catcher's ball.","Waiting wastes precious time."],anim:"catch"},
    {id:"ct16", conceptTag:"pickoff-mechanics",title:"Pickoff Play at First Base",diff:3,cat:"catcher",ageMin:12,ageMax:99,
      description:"You're the catcher. Fast runner on first is taking an aggressive secondary lead after every pitch. He's been leaning toward second and you've noticed he's slow getting back to first. The count is 2-1 on a weak hitter.",
      situation:{inning:"Top 7",outs:1,count:"2-1",runners:[1],score:[3,3]},
      options:["Call a pitchout on the next pitch to set up a steal attempt","After receiving the pitch, snap throw to first immediately — you've timed his slow return","Signal a timing play where you and the pitcher coordinate on a hidden count","Call for a slide step to shorten the pitcher's delivery and limit the runner's jump"],
      best:1,explanations:["A pitchout is designed for when you expect a steal attempt, not for picking off a runner who’s lazy getting back. The wide pitch tips off the runner that something is up, and he’ll dive back early.","Great awareness! You've noticed the runner's pattern — slow to get back after his secondary lead, which means a quick snap throw from the catcher right after receiving the pitch can catch him at his most vulnerable moment.","A coordinated timing play can work, but the vulnerability you spotted happens AFTER the pitch is delivered, not during the stretch, because your snap throw catches him at the exact moment he’s lazy getting back — no coordination needed, just quick reflexes.","A slide step limits the runner's jump on a steal attempt, but you noticed this runner is slow getting BACK to the bag, which means a snap throw after the pitch catches him at his most vulnerable moment."],
      rates:[40,85,45,15],concept:"Watch runners' habits after every pitch — a quick snap throw from the catcher can catch a runner with a lazy secondary lead.",anim:"safe"},
    {id:"ct17", conceptTag:"catcher-framing",title:"Framing a Borderline Pitch",diff:2,cat:"catcher",ageMin:9,ageMax:99,
      description:"You're the catcher. Full count, two outs, bases loaded. Your pitcher fires a fastball that catches the outside corner just below the letters. It's borderline — could go either way. The umpire hasn't made the call yet.",
      situation:{inning:"Bot 5",outs:2,count:"3-2",runners:[1,2,3],score:[5,4]},
      options:["Hold your glove perfectly still right where you caught it and keep your body quiet — let the umpire see the location","Quickly jerk your glove toward the center of the strike zone to make it look like a strike","Stand up immediately and start walking back to the dugout like you know it's strike three","Pull the ball down into the zone since it was a little high"],
      best:0,explanations:["This is elite framing for a high-leverage moment! Full count, bases loaded, two outs — the umpire is watching your glove like a hawk. Any movement looks like you're trying to fool him. A quiet glove and still body tell the umpire you received the ball exactly where you expected it. In big moments, stillness is more convincing than pulling.","Jerking your glove is called 'stabbing' and umpires hate it, because in a bases-loaded, full-count moment, the umpire is extra alert — any sudden movement screams 'I know that was a ball.'","Walking away is disrespectful to the umpire and might cost you calls later in the game — it also makes you look like you're trying too hard to sell it, which backfires.","Pulling the ball down makes it obvious the pitch was high, which means in a big moment like this, the umpire is watching closely — hold the ball where it was caught."],
      rates:[88,20,15,30],concept:"In high-leverage moments, stillness beats pulling — the umpire is watching your glove closely, and quiet presentation is more convincing.",explSimple:["This is really smart framing for a high-leverage moment!","Jerking your glove is called 'stabbing' and umpires hate it.","Walking away is disrespectful to the umpire and might cost you calls later in the game.","Pulling the ball down makes it obvious the pitch was high."],anim:"strikeout"},
    {id:"ct18", conceptTag:"pitch-count-mgmt",title:"Mound Visit Decision",diff:3,cat:"catcher",ageMin:12,ageMax:99,
      description:"You're the catcher. Your pitcher has walked two batters in a row and just threw three straight balls to the next hitter. He looks frustrated and is rushing his delivery. The pitching coach glances at you from the dugout.",
      situation:{inning:"Top 6",outs:0,count:"3-0",runners:[1,2],score:[6,4]},
      options:["Call time and go visit the mound to slow things down and settle your pitcher","Signal for a fastball right down the middle — just let him throw a strike","Wait for the pitching coach to make the mound visit since he's looking over","Keep calling pitches and hope your pitcher works through it on his own"],
      best:0,explanations:["Perfect call! Your pitcher is spiraling and needs a reset, because a mound visit slows the game down, lets him take a breath, and gives you a chance to remind him to trust his stuff and focus on your glove. This is a catcher being a leader.","Grooving a fastball down the middle with a 3-0 count might get a strike, but a frustrated pitcher throwing flat fastballs over the plate can get crushed, since you need to fix the problem, not put a bandage on it.","The pitching coach might come out, but the catcher is the pitcher's first line of defense, because you're right there — don't wait for someone else to help YOUR pitcher. Take charge.","Hoping things get better isn't a strategy — your pitcher has walked two and thrown three straight balls. He needs help now, and the catcher is the one who gives it. Be a leader."],
      rates:[90,25,35,15],concept:"A catcher is a pitcher's best friend — when your pitcher is struggling, visit the mound to slow things down and settle him.",anim:"freeze"},
    {id:"ct19", conceptTag:"steal-window",title:"Defending a Delayed Steal",diff:2,cat:"catcher",ageMin:9,ageMax:99,
      description:"You're the catcher. Runner on second base, one out. After you receive a routine fastball for a called strike, you casually lob the ball back to the pitcher. Suddenly the runner on second breaks for third as your throw floats toward the mound.",
      situation:{inning:"Top 4",outs:1,count:"1-2",runners:[2],score:[2,1]},
      options:["Yell to your pitcher to cut the throw and fire to third base immediately","Jump out and sprint toward the mound to get the ball back faster","Let the pitcher handle it — he'll see the runner and throw to third","Sprint toward the mound to cut off the throw yourself"],
      best:0,explanations:["Yes! On a delayed steal, the key is recognizing it fast and communicating. Yelling to your pitcher tells him to catch your lob and immediately throw to third. The pitcher is in the best position to make that throw if you alert him.","Running toward the mound wastes time and takes you out of position, which means your throw is already in the air — you can't outrun a baseball. Use your voice, not your legs.","The pitcher might not see the runner breaking for third — his back is partly turned. As the catcher, you see everything and it's your job to alert him. Communication wins baseball games.","Sprinting toward the mound takes you out of your position and you can't outrun the ball already in flight, because you use your voice to alert the pitcher — yelling is faster than running, and keeps you ready if the ball comes back to you."],
      rates:[85,30,20,10],concept:"Delayed steals catch catchers off guard — stay alert after every pitch and use your voice to direct teammates.",explSimple:["On a delayed steal, the key is recognizing it fast and communicating.","Running toward the mound wastes time and takes you out of position.","It IS partly the pitcher's play now, but the pitcher might not see the runner going.","You can't call timeout while a play is in progress."],anim:"steal"},
    {id:"ct20", conceptTag:"bunt-defense",title:"Bunt Play With Runner on First",diff:1,cat:"catcher",ageMin:6,ageMax:99,
      description:"You're the catcher. Runner on first, no outs, and the batter squares around to bunt. The pitch is a fastball low and inside. The batter drops a bunt about eight feet up the third base line. Your third baseman charges hard.",
      situation:{inning:"Bot 7",outs:0,count:"0-0",runners:[1],score:[3,3]},
      options:["Rip off your mask, field the ball if the third baseman can't get there, and be ready to tell everyone where to throw","Sprint past the ball to cover third base since the third baseman left it open","Stay at home plate since the pitcher or third baseman will handle all bunts","Run straight at the ball even though the third baseman is closer"],
      best:0,explanations:["Great instinct! On bunt plays the catcher is the quarterback, since remove your mask, read the play, and if your third baseman has the ball, yell where to throw it. If he can't reach it, you grab it. Either way, you're directing traffic.","Covering third is important but not your first job here, because the shortstop or someone else can rotate to cover third. Your job is to be the closest backup fielder and the one who tells everyone where the throw goes.","Never just stand and watch! On bunt plays, the catcher must get out of the crouch immediately — even if someone else fields it, you need to direct the play — you're the only one who can see the whole field.","Running at a ball when a teammate is closer creates confusion and collisions. Let the third baseman field it since he's already charging. Your job is to read the play and communicate."],
      rates:[88,25,15,20],concept:"On bunt plays, the catcher is the quarterback — get your mask off, read the play, and tell your teammates where to throw.",explSimple:["Great instinct! On bunt plays the catcher is the quarterback.","Not the best move. Covering third is important but not your first job here.","Not the best move. Never just stand and watch! On bunt plays, the catcher must get out of.","Not the best move. Running at a ball when a teammate is closer creates confusion and collisions."], anim:"bunt"},
    {id:"ct21",title:"Ball in the Dirt, Strike Three!",diff:2,cat:"catcher",ageMin:9,ageMax:99,
      description:"You're the catcher. Curveball hits the dirt for strike three! With two outs and first base open, you have a split second to react. The batter already starts toward the dugout.",
      situation:{inning:"Bot 6",outs:2,count:"1-2",runners:[2],score:[3,3]},
      options:["Scramble for the ball and throw to first — the batter can run!","Hold the ball — that's strike three, the batter is automatically out","Throw to third to hold the runner","Appeal to the umpire — you need a ruling before throwing"],
      best:0,explanations:["Great reaction! With 2 outs and first base empty, a dropped third strike lets the batter run to first, which means recover that ball and throw to first immediately — it's a live play!","With 2 outs and first base empty, the batter is NOT automatically out on a dropped third strike, because the catcher must either tag the batter or throw to first. This is one of the trickiest rules in baseball!","The runner on second isn't going anywhere — the batter running to first is the urgent play, since you get the ball to first base before the batter gets there.","There's no appeal needed — the umpire already called strike three, because the play is live and it's YOUR job to complete the out by tagging the batter or throwing to first."],
      rates:[90,25,15,40],concept:"With 2 outs and first base empty, a dropped third strike lets the batter run — always recover the ball and throw to first.",explSimple:["Nice hustle! When you drop strike three and first base is open, the batter can try to run there. Grab the ball and throw to first quickly!","Careful — the batter isn't out yet! When the catcher drops strike three with 2 outs, the batter gets to run. You need to throw him out at first.","The runner at second isn't going anywhere right now. Focus on getting the ball to first base to get the batter out.","You don't need the umpire to tell you — just grab the ball and throw to first!"],anim:"groundout",conceptTag:"dropped-third-strike"},
    {id:"ct22",title:"Runner on First Complicates It",diff:3,cat:"catcher",ageMin:12,ageMax:99,
      description:"You're the catcher. Strike three in the dirt! The runner on first breaks for second on contact. But there's already a runner on first base and only one out. Do you chase the ball?",
      situation:{inning:"Top 4",outs:1,count:"2-2",runners:[1],score:[2,1]},
      options:["Recover and throw to first immediately","The batter is out — the dropped third strike rule doesn't apply with a runner on first and fewer than 2 outs","Tag the batter with the ball before he leaves the box","Throw to second to catch the stealing runner"],
      best:1,explanations:["You don't need to throw to first! With a runner on first and fewer than 2 outs, the batter is automatically out on strike three regardless of whether you catch it — throwing to first wastes time.","Exactly right! The dropped third strike rule does NOT apply when first base is occupied with fewer than 2 outs. This prevents the defense from intentionally dropping a third strike to start a double play. The batter is out — now focus on the runner stealing second.","You don't need to tag the batter — he's already out! With a runner on first and one out, the dropped third strike exception applies, which means save your energy for the runner going to second.","Good instinct to throw out the stealing runner, but recognize the batter is already out first, because the dropped third strike rule doesn't apply here, so the batter is out on strikes. Now you can focus entirely on throwing out the runner at second."],
      rates:[20,85,35,45],concept:"With a runner on first and fewer than 2 outs, the dropped third strike rule does NOT apply — the batter is out to prevent easy double plays.",anim:"strike",conceptTag:"dropped-third-strike"},
    {id:"ct23", conceptTag:"force-vs-tag",title:"Tag Play at Home Plate",diff:1,cat:"catcher",ageMin:6,ageMax:99,
      description:"You're the catcher. Runner on 3rd, 1 out. Ground ball to the shortstop, and the runner on third breaks for home. The throw is coming to you. How do you set up for the tag?",
      situation:{inning:"Bot 5",outs:1,count:"1-1",runners:[3],score:[3,2]},
      options:["Stand in front of the plate, give the runner a clear lane, and swipe tag as he slides","Block the plate with your shin guard and wait for the ball","Stand behind the plate and tag him after he crosses","Catch the ball and chase the runner down for the tag"],
      best:0,explanations:["Correct! Under the collision rule, you must give the runner a lane to the plate, since position yourself in front of home, catch the throw, and swipe the tag as the runner slides in. You can't block the plate without the ball.","Blocking the plate without the ball is illegal under the collision rule (Rule 6.01(i)), because you'll get called for obstruction and the runner is safe automatically.","Standing behind the plate means the runner scores before you can tag him — you need to be in position to make the tag as he arrives, not after.","Chasing a runner wastes time and lets other runners advance, which means you have the ball and the runner is coming to you — let the play come to you."],
      rates:[85,15,20,25],concept:"Give the runner a lane to the plate, catch the throw, and apply a swipe tag — blocking without the ball is obstruction",explSimple:["Great choice! Stand in front of home, catch the throw, and tag the runner as he slides in.","Not the best move. Blocking the plate without the ball is against the rules.","Not the best move. Standing behind the plate means the runner scores before you can tag him.","Not the best move. Chasing a runner wastes time — let the play come to you."],anim:"throwHome"},
    {id:"ct24", conceptTag:"steal-window",title:"Runner Stealing Third Base",diff:2,cat:"catcher",ageMin:9,ageMax:99,
      description:"You're the catcher. Runner on 2nd, 1 out, count is 1-0. The runner takes off for third on the pitch. Fastball, middle of the zone. What's your play?",
      situation:{inning:"Top 6",outs:1,count:"1-0",runners:[2],score:[4,3]},
      options:["Fire to third immediately — you've got a chance","Hold the ball — throwing to third is too risky","Fake the throw to third and hold","Throw to the pitcher and forget about the runner"],
      best:0,explanations:["Throw it! Stealing third is harder to defend than stealing second because the throw crosses through the batter's box, but a quick release and accurate throw to the shortstop side of the bag can nail a runner. Don't give third base away for free.","Holding the ball lets the runner take third without a fight. If you have a clean throw lane, take the shot — catching a runner at third is a huge momentum swing.","Faking doesn't get outs, because the runner is already sliding into third by the time you pump fake. Either commit to the throw or don't.","Throwing to the pitcher accomplishes nothing — the runner takes third and is now 90 feet from scoring with only 1 out. So this approach matters in this situation."],
      rates:[85,30,20,10],concept:"Don't concede third base — a strong throw to the shortstop side of the bag can catch a runner stealing third",explSimple:["Stealing third is harder to defend than stealing second because the throw crosses through the batter's box, but a quick release and accurate throw to the shortstop side of the bag can nail a runner.","Holding the ball lets the runner take third without a fight.","Faking doesn't get outs.","Throwing to the pitcher accomplishes nothing — the runner takes third and is now 90 feet from scoring with only 1 out."],anim:"steal"},
    {id:"ct25", conceptTag:"pickoff-mechanics",title:"Snap Throw to Third Base",diff:2,cat:"catcher",ageMin:9,ageMax:99,
      description:"You're the catcher. Runner on 3rd, 1 out, tie game. After receiving a called strike, you notice the runner on third has wandered too far off the bag and isn't paying attention. What do you do?",
      situation:{inning:"Bot 7",outs:1,count:"0-1",runners:[3],score:[2,2]},
      options:["Pop up and snap throw to third — pick him off!","Hold the ball and wait — too risky to throw to third","Throw back to the pitcher as normal","Call time and point out the runner to your teammates"],
      best:0,explanations:["Great awareness! A snap throw to third from the catcher is one of the most exciting plays in baseball, since pop up quickly, throw to the inside of the bag, and your third baseman applies the tag. If the runner is napping, he's out.","Being cautious has its place, but if you see a runner off the bag and not paying attention, take the shot. A pickoff at third is a massive play in a tie game.","Throwing to the pitcher is routine and lets the runner get back to the bag safely, because you've spotted an opportunity — don't waste it.","Calling time stops the play and alerts the runner to get back — you'd be giving up your advantage. Strike while the iron is hot."],
      rates:[85,30,20,15],concept:"A catcher snap throw to third catches runners who wander off the bag — pop up quickly and throw to the inside of the base",explSimple:["A snap throw to third from the catcher is one of the most exciting plays in baseball.","Being cautious has its place, but if you see a runner off the bag and not paying attention, take the shot.","Throwing to the pitcher is routine and lets the runner get back to the bag safely.","Calling time stops the play and alerts the runner to get back."],anim:"safe"},
    {id:"ct26", conceptTag:"ibb-strategy",title:"Intentional Walk Setup",diff:2,cat:"catcher",ageMin:11,ageMax:99,
      description:"You're the catcher. Runner on 2nd, first base open, 1 out. A dangerous power hitter steps to the plate, and the on-deck hitter looks much weaker. Your coach signals for an intentional walk. What do you do?",
      situation:{inning:"Bot 6",outs:1,count:"0-0",runners:[2],score:[3,2]},
      options:["Stand up and signal to the umpire for the automatic intentional walk","Stay in your crouch and catch four wide pitches","Stand up immediately and reach way outside — give the pitcher a huge target","Stand up on the first pitch of the at-bat and tell the umpire you're walking him"],
      best:0,explanations:["In modern baseball, the automatic intentional walk rule means you don't have to throw four pitches, which means your coach or manager signals to the umpire, and the batter goes to first. It's faster and eliminates the risk of a wild pitch or hit batter.","Before the rule change, catchers did catch four wide pitches. But since 2017, you can simply signal for the automatic walk without throwing a pitch. It's safer and quicker.","Standing and reaching outside was the old-school way, because the new rule makes this unnecessary and removes the risk of a wild pitch that lets the runner on second advance.","You can't just tell the umpire on your own — the intentional walk signal comes from the manager or coach, not the catcher, since but you're right that it happens before the at-bat starts."],
      rates:[85,35,30,40],concept:"The automatic intentional walk rule lets you skip the four pitches — the manager signals the umpire and the batter takes first base",explSimple:["Great choice! In modern baseball, your coach just signals to the umpire and the batter goes to first.","Not the best move. You don't have to throw four pitches anymore — the new rule makes it automatic.","Not the best move. You don't need to stand and reach outside anymore — the new rule is quicker and safer.","Not the best move. The intentional walk signal comes from the manager or coach, not the catcher."],anim:"walk"},
    {id:"ct27", conceptTag:"dp-positioning",title:"Setting Up the Double Play",diff:2,cat:"catcher",ageMin:9,ageMax:99,
      description:"You're the catcher. Runner on 1st, nobody out, and the batter hits right-handed ground balls. You need a double play. What pitch do you call and where?",
      situation:{inning:"Top 4",outs:0,count:"0-1",runners:[1],score:[1,1]},
      options:["Fastball down the middle — let him put it in play","Sinker or two-seam low and inside to a righty — induce a grounder to the left side","Slider low and away — get a swing and miss","Curveball in the dirt — try to get the runner going on a pitch in the dirt"],
      best:1,explanations:["A fastball down the middle might get hit in play, but it could also get hit hard in the air, because you want a specific ground ball, not any contact.","A sinker or two-seam fastball low and inside to a right-handed hitter produces ground balls to the shortstop or third base side — perfect for starting a double play — pitch location and movement down in the zone are how catchers set up twin killings.","A slider away might get a swing and miss, but you want contact — specifically a ground ball, which means strikeouts only get one out. A double play gets two.","A curveball in the dirt is risky with a runner on first, because if it gets past you, the runner advances to second for free. Focus on getting the ground ball."],
      rates:[40,85,30,25],concept:"To set up a double play, call pitches low in the zone that produce ground balls — sinkers and two-seamers to the pull side are ideal",explSimple:["A fastball down the middle might get hit in play, but it could also get hit hard in the air.","A sinker or two-seam fastball low and inside to a right-handed hitter produces ground balls to the shortstop or third base side — perfect for starting a double play.","A slider away might get a swing and miss, but you want contact — specifically a ground ball.","A curveball in the dirt is risky with a runner on first."],anim:"doubleplay"},
    {id:"ct28", conceptTag:"wild-pitch-coverage",title:"Catching a Knuckleball Pitcher",diff:2,cat:"catcher",ageMin:9,ageMax:99,
      description:"You're the catcher for a knuckleball pitcher. The pitch is dancing and wobbling toward you unpredictably. Runner on 1st, 1 out. How do you handle this?",
      situation:{inning:"Bot 3",outs:1,count:"1-1",runners:[1],score:[2,2]},
      options:["Use your regular mitt and try to squeeze it quickly","Switch to an oversized catcher's mitt and let the ball come to you with soft hands","Stab at the ball aggressively so it doesn't get past you","Set up extra wide to give yourself more room"],
      best:1,explanations:["A regular mitt makes catching knuckleballs much harder, since the smaller pocket means more balls squirt out. Knuckleball catchers use specialized oversized mitts for a reason.","An oversized mitt and soft, relaxed hands are the keys to catching a knuckleball. Don't squeeze too early — let the ball settle into the big pocket. React late rather than early because the pitch is still moving unpredictably until the last moment.","Stabbing at a knuckleball is the worst thing you can do, because the pitch is moving randomly, so an aggressive lunge will miss. Soft hands and patience are essential.","Setting up wide doesn't help because the knuckleball moves in every direction. You need to track it all the way in and react with soft hands, not guess where it's going."],
      rates:[25,85,15,35],concept:"Catching knuckleballs requires an oversized mitt and soft hands — let the ball come to you and react late, not early",explSimple:["A regular mitt makes catching knuckleballs much harder.","An oversized mitt and soft, relaxed hands are the keys to catching a knuckleball.","Stabbing at a knuckleball is the worst thing you can do.","Setting up wide doesn't help because the knuckleball moves in every direction."],anim:"catch"},
    {id:"ct30",conceptTag:"squeeze-recognition",title:"Defending the Squeeze \u2014 Catcher's Read",diff:2,cat:"catcher",ageMin:9,ageMax:99,
      description:"You're the catcher. Bot 7th, runner on 3rd, 1 out, tied 2-2. The count is 1-1. As your pitcher starts his windup, you notice the runner on 3rd break early toward home and the batter square around to bunt. What do you do?",
      situation:{inning:"Bot 7",outs:1,count:"1-1",runners:[3],score:[2,2]},
      options:["Jump out in front of home plate to field the bunt before it lands","Stay in your crouch and receive the pitch \u2014 call for a pitchout next time","Yell 'SQUEEZE!' to alert the pitcher to throw high and inside \u2014 an unhittable pitch","Stand up and try to tag the runner as he arrives at home"],
      best:2,explanations:["Jumping in front of the plate puts you at risk of catcher's interference if the batter swings through. Since the ball hasn't been pitched yet, you can't field something that doesn't exist. Your job is to communicate, not charge forward.","Staying passive means you accept the squeeze and let the run score. Since you've recognized the play developing, the best catchers react immediately by alerting the pitcher, because a well-placed pitch can defeat the squeeze before the bunt happens.","This is the correct read. When you recognize a squeeze developing, yell to alert your pitcher immediately. Since the runner is committed, the pitcher should throw high and tight \u2014 a pitch the batter can't bunt. This is called a 'squeeze buster' because it leaves the runner stranded between third and home with no bunt to protect him.","Standing up to tag makes you a bigger target for the bunt, and the ball hasn't arrived yet. Since the batter is trying to bunt the pitch, you need the pitcher to throw an unbuntable pitch first \u2014 otherwise the batter puts it down and the runner scores easily."],
      rates:[15,25,85,35],concept:"When you recognize a squeeze play developing, alert your pitcher immediately \u2014 a pitch-out or high-inside pitch defeats the squeeze before the bunt happens",anim:"strike"},
    {id:"ct29", conceptTag:"pickoff-mechanics",title:"Back-Pick on a Runner Who Rounds the Bag",diff:3,cat:"catcher",ageMin:12,ageMax:99,
      description:"You're the catcher. Single to left field, runner from first rounds second hard and overslides the bag by several feet. The throw comes in to you at home, but no play there. You see the runner scrambling back to second.",
      situation:{inning:"Top 5",outs:0,count:"0-0",runners:[2],score:[2,3]},
      options:["Hold the ball — the play is over","Fire to second base immediately — catch the runner off the bag","Throw to the pitcher and let him handle it","Fake a throw to second and hold — see if the runner takes off for third"],
      best:1,explanations:["The play is never over until all runners are safe on a base! Great catchers keep their eyes on every runner after the ball comes in — if someone overruns a bag, that's an opportunity for an out.","Excellent awareness! When a runner overslides second base, a quick throw from the catcher to the shortstop or second baseman covering can catch him before he gets back, which means this is a heads-up play that great catchers make by staying alert after every play.","The pitcher isn't in position to make this play, because you have the ball and a clear throw — go directly to the base where the runner is off the bag.","Faking wastes time, since the runner is already scrambling to get back — every second you hesitate is a second he gets closer to the bag. Throw it now."],
      rates:[25,85,45,30],concept:"Great catchers stay alert after every play — when a runner overslides a base, a quick throw can catch him off the bag",anim:"safe"},
    {id:"ct30", conceptTag:"pitch-sequencing",title:"Pitcher Tipping His Pitches",diff:3,cat:"catcher",ageMin:12,ageMax:99,
      description:"You're the catcher. The opposing hitters seem to know what's coming — they're sitting on off-speed and crushing it, but laying off fastballs. You suspect your pitcher might be tipping his pitches. What do you do?",
      situation:{inning:"Top 4",outs:0,count:"0-0",runners:[1],score:[2,4]},
      options:["Keep calling the same game plan — eventually they'll miss","Call time, visit the mound, and check if he's tipping (glove position, hand movement, head tilt)","Switch to calling only fastballs until you figure it out","Tell the umpire the other team is cheating"],
      best:1,explanations:["Hoping hitters will start missing is not a strategy, because if they know what's coming, they'll keep crushing it. You need to diagnose the problem immediately.","As the catcher, you have the best view of your pitcher's mechanics. Visit the mound and watch his delivery closely. Common tells include: the glove rising higher before a curveball, the wrist twisting visibly before a slider, or the delivery slowing down before a changeup. If you spot something, tell him to keep his delivery identical on every pitch.","Switching to all fastballs makes your pitcher one-dimensional — even if the hitters are reading off-speed tells, a pitcher with only one pitch is easier to hit than a pitcher who fixes his tipping.","The other team isn't cheating — reading a pitcher's tells from the batter's box or the base paths is a legal and fundamental part of baseball, which means it's your job to help your pitcher stop tipping, not blame the other team."],
      rates:[15,85,35,10],concept:"Catchers must watch for pitch-tipping — visit the mound and check glove position, hand movement, and delivery tempo for tells",anim:"freeze"},
    {id:"ct31",conceptTag:"catcher-framing",title:"What Is Framing?",diff:1,cat:"catcher",ageMin:6,ageMax:99,
      description:"You're the catcher. Your pitcher fires a fastball right on the edge of the strike zone. The umpire hasn't called it yet. What should you do with your glove after catching the ball?",
      situation:{inning:"Top 2",outs:0,count:"1-1",runners:[],score:[0,0]},
      options:["Drop your glove down right away — get ready for the next pitch","Hold your glove still right where you caught it — show the umpire the location","Pull your glove quickly toward the middle of the zone","Toss the ball back to the pitcher immediately"],
      best:1,explanations:["Dropping your glove right away makes the umpire think the pitch wasn't a strike. If you move too fast, the ump never gets a good look at where you caught it.","This is the foundation of framing! When you catch a borderline pitch, hold your glove still and let the umpire see where the ball was. A quiet, steady glove tells the umpire the pitch was right where it was supposed to be. This is the first skill every young catcher should learn.","Pulling your glove quickly looks like you're trying to trick the umpire, because even at a young age, umpires notice when catchers yank the ball. Keep it simple — catch and hold.","Tossing the ball back immediately tells the umpire you've already moved on, since you holding the ball for just a moment gives the umpire time to process the location and make the call."],
      rates:[20,85,25,30],concept:"Framing starts with catching the ball and holding your glove still — let the umpire see where the pitch was",explSimple:["Dropping your glove too fast makes the umpire think it wasn't a strike.","Hold your glove still after catching it. This lets the umpire see the pitch was a strike!","Pulling your glove quickly looks like you're trying to trick the umpire.","Tossing the ball back right away doesn't give the umpire time to make the call."],anim:"strike"},
    {id:"ct32",conceptTag:"catcher-framing",title:"Framing a Low Pitch — Stick or Pull?",diff:3,cat:"catcher",ageMin:12,ageMax:99,
      description:"You're the catcher. Two strikes, nobody on, pitcher's count. Your pitcher uncorks a nasty curveball that catches the bottom edge of the zone — right at the knees. The ball drops into your glove below your belt. You know the pitch is a strike, but it looked low to the umpire.",
      situation:{inning:"Bot 7",outs:1,count:"1-2",runners:[],score:[3,2]},
      options:["Hold your glove where you caught it below the belt — stillness is always best","Subtly lift the glove up to the bottom of the zone as you receive it — 'stick and lift'","Jerk the glove up to chest height to make it look like a strike","Stand up and start walking away confidently"],
      best:1,explanations:["Stillness is usually great, but on a low pitch that dropped below your belt, holding the glove down there actually reinforces the umpire's impression that the ball was too low, because sometimes you need to help the umpire see the pitch was in the zone.","On a low curveball that drops into the bottom of the zone, the best framers use a 'stick and lift' technique. Catch the ball cleanly and gently guide the glove upward to the bottom of the zone as you receive it. The motion must be smooth and part of the catch — not a separate movement. This tells the umpire the ball finished in the zone even though it dropped. Elite framers gain 10\u201315 extra low strikes per season with this technique.","Jerking the glove up to chest height is an obvious pull that umpires hate — the farther you move the glove from where you caught it, the more obvious it is. Subtle movement is key.","Walking away on a two-strike count might cost you a strikeout, which means the pitch is close enough that your framing can make the difference. Show the umpire the location, don't walk away."],
      rates:[40,85,10,15],concept:"On low pitches, use the 'stick and lift' technique — catch and gently guide the glove up to the zone edge as part of the receiving motion",explSimple:["Holding the glove below your belt reinforces that the ball was low. Sometimes you need to help the umpire.","On a low curveball, catch it and gently guide the glove upward to the bottom of the zone.","Jerking the glove up is too obvious. Subtle movement is key.","Walking away might cost you a strikeout. Show the umpire the location."],anim:"strikeout"},
    {id:"ct_ppr1",conceptTag:"pre-pitch-routine",title:"Setting Up Before the Pitch",diff:2,cat:"catcher",ageMin:9,ageMax:99,
      description:"You're the catcher. The pitcher has the ball and is about to throw. The count is 1-1, runner on first, one out. What should you be doing before the pitch comes in?",
      situation:{inning:"Top 4",outs:1,count:"1-1",runners:[1],score:[2,2]},
      options:["Set up your target early so the pitcher can see where to throw","Give your sign, set up late so the batter can't peek at your target, and get low and quiet before the pitch","Just put your glove in the middle of the plate — the pitcher will figure it out","Stand up to give a better target"],
      best:1,explanations:["Setting up too early lets the batter peek back and see where you're positioned, which tips off the pitch location. Good hitters will glance back at the catcher's glove to get an edge.","Your pre-pitch routine as a catcher starts with giving the sign, then waiting until the pitcher begins his windup before you shift to your target. Setting up late prevents the batter from peeking and seeing where you're calling for the pitch. Getting low and quiet with your glove gives the pitcher a clean target and sets you up for a good frame.","Putting your glove in the middle doesn't give the pitcher a specific location to aim for, since the whole point of calling pitches is commanding WHERE it goes — middle-middle is the most hittable spot in the zone.","Standing up before the pitch takes you out of your receiving position and gives the umpire a worse look at the pitch, because you should be low and set before the ball arrives."],
      explSimple:["Setting up too early lets the batter peek and see where you're putting your glove.","Give the sign, then set up late so the batter can't see your target. Get low and quiet!","Just putting your glove in the middle doesn't tell the pitcher where to throw.","Standing up before the pitch makes it harder to receive and frame."],
      rates:[40,80,30,25],concept:"Set up your target late so the batter can't peek — give the sign, wait for the windup, then shift into position quietly",anim:"strike"},
    {id:"ct_tc1",conceptTag:"team-communication",title:"Changing Signs With Runners On",diff:2,cat:"catcher",ageMin:9,ageMax:99,
      description:"Runner on second base, one out. The runner can see your fingers from second base and might be relaying your signs to the batter. How do you change your sign system?",
      situation:{inning:"Top 5",outs:1,count:"0-0",runners:[2],score:[3,3]},
      options:["Keep using the same signs — the runner probably isn't looking","Switch to a multiple-sign sequence where only the second sign (or a pre-arranged indicator) is the real one","Flash your signs faster so the runner can't read them","Use no signs at all and let the pitcher throw whatever he wants"],
      best:1,explanations:["Assuming the runner isn't looking is a dangerous gamble. Runners on second are taught to read signs and relay them to the batter — even in youth baseball, coaches teach this. Protect your signs whenever someone is on second.","With a runner on second, you switch to a multiple-sign sequence. For example, you might flash three signs, and only the sign after your 'indicator' sign is the real one. You and the pitcher agree beforehand which sign is the indicator. The runner sees multiple fingers and can't tell which one is the actual pitch call. This is standard practice at every level.","Flashing signs faster is unreliable, since the runner has a clear sightline from second base and can pick up even quick flashes. Speed doesn't hide your signs — a different system does.","Pitching without signs means the catcher has no idea what's coming, which leads to passed balls, missed pitches, and a complete breakdown of the battery. Signs are essential for the pitcher-catcher connection."],
      explSimple:["The runner on second can probably see your signs. Don't assume he's not looking!","Use multiple signs and agree on an indicator with your pitcher. The runner can't figure out which sign is real!","Flashing faster doesn't work. The runner can still see your fingers from second base.","No signs means the catcher doesn't know what's coming. That leads to passed balls!"],
      rates:[25,85,35,20],concept:"With a runner on second, switch to a multiple-sign system with an indicator — protect your signs so the runner can't relay pitches to the batter",anim:"strike"},
    {id:"ct_cl1",title:"Catcher Leadership — Pitcher Shaking Off Signs",diff:2,cat:"leadership",conceptTag:"catcher-leadership",ageMin:12,ageMax:99,
      description:"You're the catcher. Your pitcher keeps shaking off your signs. He wants to throw fastballs every pitch, but the opposing hitters have been timing his fastball all game — they're 4-for-7 against it. You know his changeup has been effective when he's used it. How do you handle this?",
      situation:{inning:"Top 5",outs:1,count:"1-1",runners:[1],score:[4,3]},
      options:["Call time and go talk to him on the mound — explain what you're seeing from behind the plate","Keep putting down the changeup sign until he throws it","Give in and call fastballs since he's the one throwing the ball","Put down the changeup sign but wiggle your fingers to signal you really mean it this time"],
      best:0,explanations:["A mound visit is the right move here. You can see things the pitcher can't — you watch every swing, every foul ball angle, and every hitter's timing. Tell him calmly what you've noticed: hitters are sitting on his fastball and the changeup has been effective. Good catchers don't just call pitches — they explain why. When your pitcher understands your reasoning, he's more likely to trust your calls. Leadership from behind the plate is about communication, not authority.","Repeatedly putting down the same sign without explaining why creates a power struggle. The pitcher will keep shaking you off and you both get frustrated. A 30-second mound visit to share information is worth more than a silent battle of signs.","Giving in to all fastballs means you're not doing your job. The catcher sees the entire at-bat from behind the plate — swing timing, bat angles, stance adjustments. If hitters are timing the fastball, throwing more fastballs makes the problem worse. Your perspective matters.","Wiggling your fingers isn't a recognized sign and will confuse your pitcher. If he doesn't know what you're signaling, the miscommunication could lead to a passed ball or a crossed-up pitch. Use your words — call time and talk to him."],
      rates:[82,25,30,28],concept:"When your pitcher shakes off signs repeatedly, go talk to him — catchers see things pitchers can't, and sharing that information builds trust",explSimple:["Go talk to him! Explain what you see from behind the plate. Communication builds trust.","Repeating the same sign without explaining creates frustration. Go talk to him.","Giving in means you're not doing your job. You see things the pitcher can't.","Wiggling fingers isn't a real sign. Use a mound visit instead."],anim:"strike"},
    {id:"ct_cl2",title:"Catcher Leadership — Calming a Frustrated Pitcher",diff:2,cat:"leadership",conceptTag:"catcher-leadership",ageMin:12,ageMax:99,
      description:"You're the catcher. You call a mound visit because your pitcher just walked 2 batters in a row and he's clearly frustrated — slamming the rosin bag and muttering to himself. Runners are on first and second with nobody out. What do you say to him?",
      situation:{inning:"Top 4",outs:0,count:"0-0",runners:[1,2],score:[2,2]},
      options:["Talk about something completely unrelated for a few seconds, then remind him to focus on your glove and throw one pitch at a time","Tell him to stop being frustrated and just throw strikes","Remind him of every mistake he's making so he can fix them all","Tell him the walks don't matter and everything is fine"],
      best:0,explanations:["The best mound visits start by breaking the cycle of frustration. Talking about something unrelated — a joke, a comment about dinner, anything — forces the pitcher's brain to reset. Once he's out of the negative spiral, you bring him back with a simple focus point: look at my glove and throw one pitch. You don't overload him with instructions or mechanics. Great catchers are part psychologist — they know when a pitcher needs to think less, not more.","Telling a frustrated pitcher to stop being frustrated has never worked in the history of baseball. Emotions don't respond to commands. You need to redirect his focus, not lecture him about his feelings. A calm conversation works better than a demand.","Listing every mistake overwhelms a pitcher who is already spiraling. When someone is frustrated, adding more things to worry about makes the problem worse. Simplify his focus to one thing: throw to the glove. One pitch at a time.","Saying everything is fine when it clearly isn't sounds dismissive. The pitcher knows he walked 2 batters — pretending it didn't happen doesn't help. Acknowledge the situation briefly, then redirect his focus forward."],
      rates:[82,20,25,38],concept:"On a mound visit with a frustrated pitcher, break the negative cycle first — reset his focus, then simplify his task to one pitch at a time",explSimple:["Break the frustration cycle with a quick reset, then simplify: one pitch at a time.","Telling someone to stop being frustrated never works. Redirect his focus instead.","Listing every mistake overwhelms him. Keep it simple — throw to the glove.","Pretending everything is fine is dismissive. Reset his focus, then move forward."],anim:"strike"},
    {id:"ct_cl3",title:"Catcher Leadership — Opponent Stealing Signs",diff:3,cat:"defense",conceptTag:"catcher-leadership",ageMin:13,ageMax:99,
      description:"You're the catcher in the 6th inning. You notice the opposing third base coach is touching his face after every one of your signs, and the batter keeps adjusting his stance right before the pitch — almost like he knows what's coming. You suspect they're relaying your signs. What do you do?",
      situation:{inning:"Top 6",outs:0,count:"0-0",runners:[],score:[3,3]},
      options:["Switch to your backup sign system immediately and tell your pitcher between pitches","Ignore it — they probably aren't actually stealing signs","Put down a sign for a fastball but tell your pitcher to throw a curveball to cross them up","Throw at the next batter to send a message"],
      best:0,explanations:["The moment you suspect sign-stealing, switch to your backup system. Every battery should have a primary and backup sign sequence. Between pitches, use a quick verbal cue or a pre-arranged signal to tell your pitcher you're switching systems. The opposing coach can keep touching his face all he wants — if he doesn't know your new indicator, the information is useless. Smart catchers don't wait for proof; they act on suspicion.","Ignoring the signs when the batter is suspiciously adjusting his stance is how you give up 3 runs in an inning. The cost of switching to a backup system is zero — even if they weren't stealing signs, a new system doesn't hurt you. The cost of not switching when they are stealing is game-changing.","Intentionally crossing up your own pitcher — putting down one sign and expecting a different pitch — is how catchers get hurt. If the pitcher throws a curveball when you're set up for a fastball, the ball can hit you in the mask or sail to the backstop. Never deceive your own pitcher.","Throwing at a batter is dangerous, unsportsmanlike, and will get your pitcher ejected. It also doesn't solve the sign-stealing problem. Change your signs — that's the professional response at every level."],
      rates:[82,20,25,38],concept:"When you suspect the opponent is stealing your signs, switch to your backup system immediately — smart catchers act on suspicion, not proof",explSimple:["Switch to your backup sign system right away! Don't wait for proof.","Ignoring it could cost you runs. Switching systems costs you nothing.","Never intentionally cross up your own pitcher. That's how catchers get hurt.","Throwing at batters is dangerous and doesn't solve the problem. Change your signs."],anim:"strike"},
  ],
  famous: [
    {id:"fp1", conceptTag:"backup-duties",title:"Jeter's Flip Play",diff:3,cat:"famous",ageMin:12,ageMax:99,
      description:"2001 ALDS, Game 3. Runner rounding 3rd heading home. The throw from right field sails up the first base line — way off target. You're the shortstop. What do you do?",
      situation:{inning:"Bot 7",outs:1,count:"0-0",runners:[3],score:[1,0]},
      options:["Let the first baseman handle it — it's his side","Cut the throw off and relay home","Sprint to the first base line and shovel-flip to the catcher","Call for the ball and throw home yourself"],
      best:2,explanations:["The first baseman can't reach it in time, because the runner scores easily.","A standard cutoff relay takes too long — the runner beats it home, which means the outcome won't be what you need.","This is THE play! Jeter sprinted from shortstop to the first base line, grabbed the overthrow, and backhanded a shovel-flip to the catcher — nailing Jeremy Giambi, since baseball's greatest hustle play.","You're 150 feet away, because by the time you field and throw, the run scores."],
      rates:[10,35,85,25],concept:"Great plays happen when you anticipate — Jeter's hustle and instinct created the impossible",anim:"throwHome",historicalNote:"October 13, 2001 — Oakland Coliseum. The A's led the series 2-0 and were about to take the lead in Game 3. Jeremy Giambi rounded third and jogged home, not sliding. Jeter's impossible flip beat him by inches. The Yankees won the game and came back to win the series. Giambi later said he should have slid."},
    {id:"fp2", conceptTag:"force-vs-tag",title:"Merkle's Boner",diff:2,cat:"famous",ageMin:9,ageMax:99,
      description:"1908, Giants vs Cubs. Bottom 9th, tie game. Your teammate singles — the winning run appears to score from 3rd! But you were the runner on 1st. What must you do?",
      situation:{inning:"Bot 9",outs:1,count:"0-0",runners:[1,3],score:[1,1]},
      options:["Run toward 2nd base and touch the bag","Celebrate with your teammates — the game is over!","Run to the dugout — the fans are storming the field","Stay at 1st base — you didn't need to advance"],
      best:0,explanations:["Correct! You MUST touch 2nd base for the run to count — in 1908, Fred Merkle didn't — the Cubs got the ball, touched 2nd, and Merkle was a force out. The run was nullified.","Celebrating cost Fred Merkle his legacy. The run didn't count because he never touched 2nd.","Leaving the field is abandoning the play, which means the defense can appeal and you're out.","The force at second still existed because Merkle was forced to advance when the batter hit the ball. You MUST touch second base — without it, you can be forced out and the run doesn't count."],
      rates:[90,25,15,40],concept:"Always touch the next base — Merkle's mistake in 1908 changed a pennant race",explSimple:["You MUST touch 2nd base for the run to count.","Celebrating cost Fred Merkle his legacy.","Leaving the field is abandoning the play.","The force at second still existed because Merkle was forced to advance when the batter hit the ball."],anim:"advance",historicalNote:"September 23, 1908 — Polo Grounds, New York. Fred Merkle was just 19 years old. When the winning run appeared to score, fans rushed the field. Merkle never touched second base. The game was declared a tie and replayed later. The Giants lost the replay and the pennant by one game."},
    {id:"fp3", conceptTag:"rundown-mechanics",title:"Baez's Rundown Magic",diff:3,cat:"famous",ageMin:12,ageMax:99,
      description:"2021 Cubs vs Pirates. You're Javy Baez on 1st. The batter grounds out but you get caught in a rundown between 1st and 2nd. What's your strategy?",
      situation:{inning:"Top 3",outs:1,count:"0-0",runners:[1],score:[2,1]},
      options:["Retreat safely to first base and stay out of trouble","Run full speed toward 2nd to force a bad throw","Stay in the rundown as long as possible to let the batter advance","Make the fielders throw as many times as possible — force an error"],
      best:3,explanations:["Retreating to first is safe but wastes a chance to create chaos, because you rundowns force multiple throws and each throw is a chance for the defense to make an error.","Running full speed at one fielder doesn't create enough confusion.","Good thinking about staying in the rundown, but the key is actively FORCING errors with direction changes, not just surviving.","Baez made the Pirates throw 6 times, running back and forth, drawing TWO throwing errors, since he ended up safe at 2nd AND a run scored. Chaos wins."],
      rates:[10,30,50,85],concept:"The key lesson is that aggressive baserunning creates chaos — when you force multiple throws, the defense's error rate skyrockets",anim:"advance",historicalNote:"May 27, 2021, Cubs vs Pirates. Baez got caught in a rundown between first and second but kept reversing direction, forcing multiple throws. The Pirates made two throwing errors and Baez ended up safe at second while a run scored. It was one of the wildest rundown plays in recent memory."},
    {id:"fp4", conceptTag:"balk-rule",title:"The Hidden Ball Trick",diff:2,cat:"famous",ageMin:9,ageMax:99,
      description:"You're the first baseman. The runner on 1st just took a lead. Your pitcher stands on the rubber. How do you execute the hidden ball trick?",
      situation:{inning:"Top 5",outs:0,count:"0-0",runners:[1],score:[3,2]},
      options:["Keep the ball in your glove and tag the runner when he leads off","Ask the pitcher to pretend to have the ball while you keep it","Wait for the pitcher to step OFF the rubber, then tag the runner","Call time and tag the runner during the timeout"],
      best:2,explanations:["If the pitcher is on the rubber, this is a balk, because the pitcher MUST have the ball when on the rubber.","This is a balk! Remember, the pitcher cannot be on the rubber without the ball.","The pitcher MUST step off the rubber for this to be legal — once off, you can tag the unsuspecting runner. This is the only legal way to pull it off.","You can't tag a runner during a timeout — the ball is dead."],
      rates:[40,25,90,15],concept:"The hidden ball trick only works if the pitcher is OFF the rubber — otherwise it's a balk",explSimple:["If the pitcher is on the rubber, this is a balk.","The pitcher cannot be on the rubber without the ball.","The pitcher MUST step off the rubber for this to be legal.","You can't tag a runner during a timeout — the ball is dead."],anim:"safe",historicalNote:"The hidden ball trick has been executed hundreds of times in MLB history. The key is always the same: the runner loses track of who has the ball and steps off the base. Modern rules require the pitcher to stay off the rubber — if the pitcher isn't on the mound, keep your foot on the bag."},
    {id:"fp5", conceptTag:"baserunning-rates",title:"Lonnie Smith Gets Deked",diff:3,cat:"famous",ageMin:12,ageMax:99,
      description:"1991 World Series, Game 7. You're Lonnie Smith on 1st. The batter drives a ball to deep left-center gap. You're running on contact. But as you round 2nd, the middle infielders fake a double play. What should you do?",
      situation:{inning:"Bot 8",outs:0,count:"0-0",runners:[1],score:[0,0]},
      options:["Stop and check if the ball was fielded","Keep running full speed — the ball was hit to the outfield","Hesitate briefly then continue to 3rd","Dive back to 2nd — it might be a line drive out"],
      best:1,explanations:["Stopping is exactly what happened — as Lonnie Smith hesitated, and it cost the Braves the winning run in Game 7 of the World Series.","Never stop running on a gap hit! The ball is clearly in the outfield, which means trust your eyes and ears, not the infielders. Smith should have scored easily.","Even a brief hesitation costs critical seconds, because that hesitation kept Smith at 3rd instead of scoring.","You saw the ball hit — it was a gap shot, since don't fall for the fake."],
      rates:[25,90,40,15],concept:"Watch the ball, not the fielders — dekes only work if you take your eyes off the play",anim:"score",historicalNote:"Game 7, 1991 World Series. Lonnie Smith was on first when Terry Pendleton doubled to left-center. Smith hesitated because Chuck Knoblauch faked fielding a grounder near second base. Smith only made it to third instead of scoring. The Braves lost 1-0 in 10 innings."},
    {id:"fp6", conceptTag:"squeeze-play",title:"The Suicide Squeeze",diff:2,cat:"famous",ageMin:9,ageMax:99,
      description:"Runner on 3rd, 1 out, tie game in the 8th. You're the batter. The coach gives the squeeze sign. The runner will break for home as the pitcher starts his motion. What's your job?",
      situation:{inning:"Bot 8",outs:1,count:"1-1",runners:[3],score:[3,3]},
      options:["Bunt the ball ANYWHERE in fair territory — just get it down","Swing away — surprise the defense","Fake the bunt and let the runner steal home","Bunt only if the pitch is in the strike zone"],
      best:0,explanations:["On a suicide squeeze, the runner is COMMITTED. Your ONLY job is to get the bunt down — anywhere, any pitch, even in the dirt. The runner is dead if you don't bunt.","Swinging means the catcher has a clear throw to nail the runner at home.","A fake bunt leaves your runner hung out to dry — he's already sprinting.","On a suicide squeeze, you bunt EVERYTHING. The runner is already committed. If you take a pitch, he's out by 20 feet."],
      rates:[90,15,25,40],concept:"On a suicide squeeze, bunt EVERYTHING — the runner is committed to scoring",explSimple:["On a suicide squeeze, the runner is COMMITTED.","Swinging means the catcher has a clear throw to nail the runner at home.","A fake bunt leaves your runner hung out to dry — he's already sprinting.","On a suicide squeeze, you bunt EVERYTHING."],anim:"bunt",historicalNote:"The suicide squeeze has decided countless big games. It's called 'suicide' because if the batter fails to bunt, the runner is dead at the plate. When executed perfectly, it's nearly impossible to defend — the run scores before the defense can react."},
    {id:"fp7", conceptTag:"balk-rule",title:"Walk-Off Balk",diff:3,cat:"famous",ageMin:12,ageMax:99,
      description:"Bottom 9th, tie game, bases loaded, 1 out. You're a runner on 3rd. The pitcher starts his windup, then stops mid-motion. What happens?",
      situation:{inning:"Bot 9",outs:1,count:"2-1",runners:[1,2,3],score:[5,5]},
      options:["Nothing — play continues","It's a balk — all runners advance one base, you score!","The pitch doesn't count — redo it","It depends on whether the batter swung"],
      best:1,explanations:["Saying 'nothing happens' ignores the rules completely — a pitcher stopping mid-windup is an illegal motion called a balk. The rule exists because pitchers could fake a pitch to trick runners, which wouldn't be fair.","A balk means every runner advances one base for free, no play needed. With the bases loaded and you on third, that one free base sends you home — game over! The balk rule prevents pitchers from deceiving runners with fake motions, and here it costs the pitcher the entire game.","A balk is not a 'redo' or a dead pitch — it's a penalty, because the runners advance immediately, right when the umpire calls it. There's no replaying the at-bat or pretending it didn't happen.","The batter's actions don't matter at all on a balk call, since a balk is 100% about what the pitcher did wrong — stopping, stuttering, or faking during the delivery. Even if the batter stood completely still, the balk is called and all runners advance one base."],
      rates:[15,85,20,30],concept:"A balk advances all runners one base — with bases loaded, that's a run",anim:"score",historicalNote:"Walk-off balks are rare but unforgettable. One of the most memorable happened on April 12, 1988, when the Twins beat the Royals on a balk. The pitcher's illegal motion sent the winning run home — perhaps the most anticlimactic way to end a baseball game."},
    {id:"fp8", conceptTag:"win-probability",title:"Bonds — Intentional Walk with Bases Loaded",diff:3,cat:"famous",ageMin:12,ageMax:99,
      description:"1998. Barry Bonds at the plate, bases loaded, 2 outs. You're the opposing manager. The Diamondbacks chose to intentionally walk Bonds, forcing in a run. When might this make sense?",
      situation:{inning:"Bot 9",outs:2,count:"0-0",runners:[1,2,3],score:[8,6]},
      options:["It never makes sense — you just gave them a free run","Only if you're up by more than 1 run AND the next batter is much weaker","Only in extra innings","Only if Bonds has already homered in the game"],
      best:1,explanations:["Giving up a free run feels terrible, but saying 'never' ignores the math, which means if the alternative is letting the most dangerous hitter in baseball swing with the bases loaded, one run might be the cheaper price to pay — it keeps the game from being blown wide open.","The key is the margin: you're up by 2 (8-6). Walking Bonds makes it 8-7, and you face a much weaker hitter with the bases still loaded. If Bonds swings instead, a grand slam makes it 10-8 — game over. The intentional walk trades a guaranteed 1 run for avoiding a possible 4. That's smart expected value thinking.","Extra innings aren't part of this calculation at all, because the decision is purely about run prevention: how many runs will Bonds likely produce vs. the next hitter? It's the same math whether it's the 3rd inning or the 9th.","Whether Bonds homered earlier doesn't change his talent level or the current matchup, since baseball decisions should be based on the situation RIGHT NOW — the score, the outs, the next hitter's ability — not what happened in previous at-bats."],
      rates:[30,85,20,25],concept:"The key decision is weighing 1 run now vs. 4 runs later — sometimes an intentional walk is the smart strategy",anim:"walk",historicalNote:"May 28, 1998 — Buck Showalter managed the Diamondbacks and ordered an intentional walk to Barry Bonds with the bases loaded while up 8-6. It forced in a run but brought up a weaker hitter who struck out. The unconventional strategy worked perfectly."},
    {id:"fp9", conceptTag:"rundown-mechanics",title:"Three Men on Third",diff:2,cat:"famous",ageMin:9,ageMax:99,
      description:"1926 — Babe Ruth, Lou Gehrig, and a runner are all somehow near 3rd base at the same time. You're the third baseman with the ball. Who do you tag?",
      situation:{inning:"Bot 7",outs:1,count:"0-0",runners:[1,2,3],score:[3,3]},
      options:["Tag Babe Ruth first — he's the biggest star","Get the runner closest to home plate","Tag the two runners who DON'T belong — the lead runner owns the base","Apply the ball to all three runners just to be safe"],
      best:2,explanations:["Star power doesn't matter in the rules, because you tag the right runners.","The runner closest to home isn't necessarily the one you need — think about who has the right to the base.","Correct! The lead runner (originally on 3rd) has the RIGHT to the base, which means the other two runners are trespassers. Tag the runners who don't belong — they're the outs.","Tagging all of them works, but you need to know WHY, because only the runners without the right to the base are out."],
      rates:[20,35,85,50],concept:"The lead runner has the right to the base — tag the others, they're trespassing",explSimple:["Star power doesn't matter in the rules.","The runner closest to home isn't necessarily the one you need.","The lead runner (originally on 3rd) has the RIGHT to the base — tag the other two!","Tagging all of them works, but you need to know WHY."],anim:"safe",historicalNote:"August 15, 1926 — This really happened between the Brooklyn Robins and Boston Braves. Babe Herman doubled, but confusion on the basepaths led to three runners ending up at or near third base. Two were tagged out, creating one of baseball's most famous and funniest plays."},
    {id:"fp10", conceptTag:"pitch-sequencing",title:"Maddux Pitch Sequencing",diff:3,cat:"famous",ageMin:12,ageMax:99,
      description:"You're Greg Maddux — the greatest pitch sequencer ever. Bottom of the 7th, facing a power hitter. He's seen mostly fastballs from you. Count is 2-1. What do you throw?",
      situation:{inning:"Bot 7",outs:1,count:"2-1",runners:[],score:[2,0]},
      options:["Fastball on the inside corner — your best pitch","Changeup — make him way out front","Cutter that looks like a fastball but moves","Two-seam sinker for a ground ball"],
      best:2,explanations:["He's timing your fastball now, since you throwing it again is predictable.","Changeup on 2-1 when behind is risky — if you miss, it's 3-1.","Maddux mastered the cutter for exactly this reason, because it looks like a fastball out of the hand, but cuts 3-4 inches at the last moment. The batter swings where the ball WAS. Pure genius.","A sinker could work, but the cutter's deception is what made Maddux legendary."],
      rates:[15,25,90,40],concept:"Maddux's genius: throw pitches that LOOK like one thing but DO another — deception over velocity",anim:"groundout",historicalNote:"Greg Maddux won 355 games with a career ERA of 3.16, despite rarely throwing harder than 89 mph. He won four consecutive Cy Young Awards (1992-1995) by outsmarting hitters. Batters said facing Maddux was like playing chess — he was always two pitches ahead of you."},

    {id:"fp11", conceptTag:"of-communication",title:"The Catch",diff:3,cat:"famous",ageMin:12,ageMax:99,
      description:"1954 World Series, Game 1. Vic Wertz crushes a deep drive to center field at the Polo Grounds. Willie Mays turns his back to home plate and sprints toward the wall, 460 feet away. The ball is sailing over his head. What would YOU do as the center fielder?",
      situation:{inning:"Top 8",outs:0,count:"1-0",runners:[1,2],score:[2,2]},
      options:["Sprint full speed with your back turned and make an over-the-shoulder catch","Stop, turn around, and try to play the ball off the wall","Let it go — no one can catch a ball hit that far","Call for the left fielder to take it instead"],
      best:0,explanations:["This is exactly what Mays did — one of the greatest catches in baseball history — he ran full speed, caught it over his shoulder at the warning track, then spun and fired a throw back to the infield to hold the runners. Pure instinct and elite athleticism.","Playing it off the wall would likely score both runners and give Wertz extra bases, which means in a tie World Series game, you can't give up those runs if there's any chance of making the catch.","Giving up on the play would be a disaster, because mays had the speed and tracking ability to reach it, and great outfielders never quit on a ball. This drive was catchable for someone with Mays' talent.","The center fielder has priority on this ball, and Mays was already in full sprint, since you calling off for the left fielder would cause confusion and almost certainly let the ball drop."],
      rates:[90,40,15,25],concept:"Elite outfielders trust their speed and instincts to make plays that seem impossible — never give up on a fly ball.",anim:"catch",historicalNote:"September 29, 1954 — Game 1 of the World Series at the Polo Grounds. Willie Mays made his legendary over-the-shoulder catch 460 feet from home plate, then spun and fired back to the infield to hold the runners. The Giants won the game and swept the heavily favored Cleveland Indians."},
    {id:"fp12", conceptTag:"force-vs-tag",title:"Buckner's Grounder",diff:2,cat:"famous",ageMin:9,ageMax:99,
      description:"1986 World Series, Game 6, bottom of the 10th. The Mets trail 5-3 but have rallied to tie it. Mookie Wilson hits a slow roller down the first base line. You're Bill Buckner at first base, hobbling on bad ankles. The ball is bouncing toward you.",
      situation:{inning:"Bot 10",outs:2,count:"3-2",runners:[1],score:[5,5]},
      options:["Stay down, keep your glove on the ground, and field it cleanly","Try to backhand it while moving toward the bag","Stand up tall to get a better view of the hop","Charge the ball aggressively to cut down the runner"],
      best:0,explanations:["Fundamentals save games. Stay low, keep your glove down, and smother the grounder. In the actual game, the ball went through Buckner's legs because he lifted his glove, and the winning run scored. This play haunted him for decades, though he was a great player who deserved better.","A backhand on a slow roller adds unnecessary risk, because the ball is coming right at you — use two hands and stay square to it. Fancy plays in the World Series with the game on the line are a bad idea.","Standing up tall is exactly how balls go under your glove — the number one rule for grounders is stay low. Buckner's legs were hurting, which may have caused him to rise up, but the fundamental remains: glove on the dirt.","The ball is a slow roller already close to you, which means charging aggressively could cause you to overrun it or field it off-balance. Set your feet and make the routine play."],
      rates:[85,25,12,30],concept:"The lesson is always trust your fundamentals — stay low and field it clean, because routine plays win championships",explSimple:["Fundamentals save games.","A backhand on a slow roller adds unnecessary risk.","Standing up tall is exactly how balls go under your glove.","The ball is a slow roller already close to you."],anim:"groundout",historicalNote:"September 29, 1986 — Game 6 of the World Series. The Red Sox were one out from winning their first title since 1918. Mookie Wilson's slow roller went through Bill Buckner's legs, and the Mets scored the winning run. Boston wouldn't win the World Series until 2004."},
    {id:"fp13", conceptTag:"situational-hitting",title:"Gibson's Moment",diff:2,cat:"famous",ageMin:9,ageMax:99,
      description:"1988 World Series, Game 1. The Dodgers trail 4-3 in the bottom of the 9th against Oakland's dominant closer Dennis Eckersley. Kirk Gibson can barely walk due to injuries in both legs. Manager Tommy Lasorda sends him up to pinch hit with a runner on base.",
      situation:{inning:"Bot 9",outs:2,count:"3-2",runners:[1],score:[3,4]},
      options:["Look for a backdoor slider and try to drive it the other way","Sit dead red fastball and swing as hard as possible","Take the pitch — try to draw a walk to extend the inning","Bunt for a base hit since you can barely run"],
      best:0,explanations:["Gibson studied Eckersley's tendencies and knew the backdoor slider was coming on a full count, because he sat on it, got it, and launched one of the most iconic home runs in World Series history — limping around the bases with his famous fist pump. Preparation meets opportunity.","Eckersley's fastball was elite, but he loved his slider in full counts, since you sitting fastball would have left Gibson vulnerable to the pitch Eckersley actually threw. Great hitters study the pitcher and anticipate.","With two outs and down a run in the World Series, taking a pitch to try for a walk is too passive, because gibson was sent up there to hit. You don't pinch hit an injured star to watch pitches.","Bunting when you can barely run makes no sense — gibson could hardly move — a bunt would be a guaranteed out. Lasorda put him in to swing the bat, not bunt."],
      rates:[87,35,20,10],concept:"The key takeaway is that preparation wins — when you study a pitcher's tendencies, you can anticipate the pitch",explSimple:["Gibson studied Eckersley's tendencies and knew the backdoor slider was coming on a full count.","Eckersley's fastball was really smart, but he loved his slider in full counts.","With two outs and down a run in the World Series, taking a pitch to try for a walk is too passive.","Bunting when you can barely run makes no sense."],anim:"hit",historicalNote:"October 15, 1988 — Game 1 of the World Series. Kirk Gibson, barely able to walk, pinch-hit in the bottom of the 9th with two outs. He launched a two-run homer off Dennis Eckersley, limping around the bases with his iconic fist pump. It was his only at-bat of the entire World Series."},
    {id:"fp14", conceptTag:"pitch-count-mgmt",title:"Koufax's Decision",diff:3,cat:"famous",ageMin:12,ageMax:99,
      description:"October 6, 1965. Sandy Koufax, the best pitcher in baseball, is scheduled to start Game 1 of the World Series against the Minnesota Twins. But today is Yom Kippur, the holiest day in the Jewish faith. Koufax must make a deeply personal decision. As a manager, how do you handle your rotation when your ace can't start Game 1?",
      situation:{inning:"Mid 1",outs:0,count:"0-0",runners:[],score:[0,0]},
      options:["Sit out Game 1 to honor your faith, then dominate when you pitch later","Pitch Game 1 — the team needs you and you can observe next year","Ask the manager to move the game to a different day","Pitch but donate your game check to charity as a compromise"],
      best:0,explanations:["Koufax chose to honor Yom Kippur and sat out Game 1. Don Drysdale started instead and lost. But Koufax came back to pitch a shutout in Game 5 and a 3-hit shutout in Game 7 to win the Series. His decision showed that character and values matter more than any single game, and he became an even greater hero for it.","Pitching Game 1 because the team needs you sounds right, but Koufax believed his faith came first, which means he showed that standing up for your beliefs — even under enormous pressure — is the right thing to do. The Dodgers still won the Series.","Asking to move a World Series game isn't realistic — players don't get to reschedule playoff games, because the schedule is set. But this option shows good instinct to look for a solution. In the real world, Koufax simply made his choice and trusted his teammates.","Donating your game check to charity as a compromise sounds generous, but this misses the point, since yom Kippur is a day of complete rest and reflection, not partial observance. Koufax understood that honoring his values meant fully committing to them."],
      rates:[90,15,20,25],concept:"The key lesson is that character drives decisions — when you stand for your beliefs, you teach others that integrity matters",anim:"freeze",historicalNote:"October 6, 1965. Sandy Koufax chose to honor Yom Kippur over starting Game 1 of the World Series. Don Drysdale started instead and lost. Koufax returned to pitch a shutout in Game 5 and a 3-hit shutout in Game 7 to win the Series MVP."},
    {id:"fp15", conceptTag:"steal-window",title:"Jackie Steals Home",diff:2,cat:"famous",ageMin:9,ageMax:99,
      description:"1955 World Series, Game 1. Jackie Robinson is on third base against the Yankees. The great Whitey Ford is pitching, and Yogi Berra is catching. Robinson takes an aggressive lead, dancing off third, daring the Yankees to stop him.",
      situation:{inning:"Bot 8",outs:1,count:"1-0",runners:[3],score:[6,5]},
      options:["Break for home plate — steal it with pure speed and daring","Bluff a steal to distract the pitcher, then stay at third","Wait for the batter to drive you in with a hit","Take a big lead but retreat when the pitcher checks you"],
      best:0,explanations:["Jackie Robinson actually stole home in this game — one of the most daring plays in World Series history, because berra argued he was out (the call is still debated today), but Robinson was called safe. His fearless baserunning symbolized his entire career: bold, aggressive, and refusing to be intimidated.","Bluffing is a decent distraction, but Robinson was a man of action — he had stolen home 19 times in his career and wasn't afraid of the biggest stage. Sometimes you have to be bold to make history.","Waiting is the safe play, but Robinson didn't become a legend by playing it safe, which means he broke baseball's color barrier and played every game with fearless intensity. Sitting and waiting wasn't in his DNA.","Taking a big lead just to retreat is a half-measure, because robinson committed fully to everything he did. His aggressive style forced opponents into mistakes and changed how the game was played."],
      rates:[82,45,30,20],concept:"Jackie Robinson played baseball with fearless courage — the same courage that made him a pioneer who changed the game forever.",explSimple:["Jackie Robinson actually stole home in this game — one of the most daring plays in World Series history.","Bluffing is a decent distraction, but Robinson was a man of action.","Waiting is the safe play, but Robinson didn't become a legend by playing it safe.","Taking a big lead just to retreat is a half-measure."],anim:"steal",historicalNote:"September 28, 1955 — Game 1 of the World Series. Jackie Robinson stole home against the Yankees' Whitey Ford, with Yogi Berra catching. Berra argued the call for years, insisting Robinson was out. The play remains one of the most debated and iconic moments in World Series history."},
    {id:"fp16", conceptTag:"obstruction-interference",title:"The Pine Tar Game",diff:1,cat:"famous",ageMin:6,ageMax:99,
      description:"July 24, 1983. You're the Yankees manager. George Brett of the Royals just hit a go-ahead two-run homer off your closer Goose Gossage in the 9th inning. But you notice Brett's bat has pine tar extending well past the 18-inch limit. The rules say a bat with excessive pine tar is illegal. What do you do?",
      situation:{inning:"Top 9",outs:2,count:"1-0",runners:[1],score:[4,3]},
      options:["Appeal to the umpire immediately — ask him to check the bat and call Brett out","Say nothing — pine tar is just for grip and doesn't affect the hit","Wait until Brett's next at-bat to bring it up so the homer stands but he loses the bat","Argue that the entire game should be forfeited to your team"],
      best:0,explanations:["This is exactly what Billy Martin did — and it worked! The umpires checked Brett's bat, ruled the pine tar exceeded 18 inches, and called Brett out, which meant the homer was erased. Martin's appeal was smart because the rule was clear and the timing was perfect — appealing right after the homer had maximum impact. However, the AL president later overturned the call, ruling that pine tar is just for grip and doesn't affect how far the ball travels. The lesson: knowing the rulebook gives you strategic options, even if the outcome isn't always guaranteed.","Saying nothing means you give up a strategic advantage, because you have a legitimate rules appeal that could erase a go-ahead homer. As a manager, part of your job is knowing the rulebook and using it to help your team. Martin's genius was recognizing the pine tar violation and timing his appeal for maximum effect.","Waiting until the next at-bat doesn't help you erase the homer that just gave the other team the lead, because appeals must be made before the next play begins. Once the next pitch is thrown, the previous play is final. The key is that timing matters in rules appeals — you have to act immediately or lose the opportunity.","Arguing for a forfeit over pine tar is wildly disproportionate, because the violation is a technical equipment issue, not cheating or unsportsmanlike conduct. Forfeits are reserved for teams refusing to play or serious rule violations. A bat with too much grip substance doesn't rise to that level."],
      rates:[85,30,20,10],concept:"Knowing the rulebook gives you strategic options — Billy Martin's pine tar appeal was smart managing, even though the league later overturned it.",explSimple:["Great choice! Billy Martin appealed immediately and the umpires called Brett out.","Not the best move. Saying nothing gives up a legitimate rules appeal.","Not the best move. You have to appeal before the next play begins.","Not the best move. A forfeit over pine tar is wildly disproportionate."], anim:"hit",historicalNote:"July 24, 1983 — Yankee Stadium. George Brett hit a go-ahead homer, but Billy Martin argued about pine tar on the bat. The umpires called Brett out, and Brett stormed from the dugout in one of baseball's most famous arguments. The league later overruled the decision."},
    {id:"fp17", conceptTag:"situational-hitting",title:"Carter's Walk-Off",diff:2,cat:"famous",ageMin:9,ageMax:99,
      description:"1993 World Series, Game 6. The Toronto Blue Jays lead the series 3-2 but trail the Phillies 6-5 in the bottom of the 9th. Joe Carter steps up with two runners on base against closer Mitch Williams, who has been wild all series. One swing can end it all.",
      situation:{inning:"Bot 9",outs:1,count:"2-2",runners:[1,2],score:[5,6]},
      options:["Look for a fastball down and in — Williams has been overthrowing all night","Sit on the slider and try to go the other way","Take the next pitch to work the count full","Try to bunt the runners over for the next hitter"],
      best:0,explanations:["Carter knew Williams was overthrowing and struggling with command. He sat on a fastball down and in, got exactly that, and launched it over the left field wall for only the second walk-off homer to win a World Series in history (after Bill Mazeroski in 1960). Carter's leap around the bases is one of baseball's most joyous moments.","Williams was primarily a fastball pitcher who was struggling with his slider's command, since you sitting slider against a struggling power pitcher in this count was the wrong read. Study the pitcher and play the percentages.","With two runners on, down one run, and the pitcher struggling with his control, being aggressive is the right approach, because taking a pitch hoping for a walk is too passive — Carter was looking to drive the ball.","Bunting with the chance to win the World Series? Absolutely not, since carter was a power hitter in a situation that called for a big swing. You don't sacrifice in the 9th inning of a World Series elimination game."],
      rates:[85,30,25,10],concept:"In the biggest moments, study the pitcher's weaknesses and be ready to attack. Joe Carter's World Series walk-off was all about knowing what was coming.",explSimple:["Carter knew Williams was overthrowing and struggling with command.","Williams was primarily a fastball pitcher who was struggling with his slider's command.","With two runners on, down one run, and the pitcher struggling with his control, being aggressive is the right approach.","Bunting with the chance to win the World Series?"],anim:"hit",historicalNote:"October 23, 1993 — SkyDome, Toronto. Joe Carter hit a walk-off three-run homer off Mitch Williams in the bottom of the 9th of Game 6 to win the World Series. It was only the second time in history a World Series ended on a walk-off homer (Bill Mazeroski was the first in 1960)."},
    {id:"fp18", conceptTag:"player-management",title:"Ripken's Record",diff:1,cat:"famous",ageMin:6,ageMax:99,
      description:"September 1995, inspired by Cal Ripken Jr.'s famous streak. Your best shortstop has played 100 straight games without a day off. He's been slumping the last two weeks and seems tired — his range has shrunk and he's made 3 errors this week. You're in a pennant race with 20 games left. As the manager, what do you do?",
      situation:{inning:"Top 1",outs:0,count:"0-0",runners:[],score:[0,0]},
      options:["Give him a day off to recharge — a rested player helps more than a tired streak","Keep him in every game — his experience and consistency are too valuable to lose","Reduce his role — let him DH or pinch-hit to save his legs","Bench him until the playoffs — save his energy for when it really matters"],
      best:0,explanations:["A tired player makes more mistakes because fatigue slows reaction time and reduces range. Since you're in a pennant race, you need your shortstop at full strength for the final push. One day off now can prevent weeks of subpar play, which means the streak isn't worth as much as having him sharp when it matters most.","Keeping a tired player in the lineup every day sounds loyal, but fatigue causes errors and slumps. Since he's already made 3 errors this week and his range has shrunk, playing through exhaustion actually hurts the team because you're getting a diminished version of your best player.","Reducing his role to DH or pinch-hit helps save his legs, but it doesn't fully address the fatigue. If he's truly tired, he needs a complete day off because even hitting requires focus and energy. A half-measure may not give him the reset he needs.","Benching him for 20 games is too extreme because you lose your best player during the most important stretch of the season. The key is a short rest — one or two games — since that's usually enough to recharge without losing his rhythm or confidence."],
      rates:[85,30,40,15],concept:"The key strategy is knowing when to rest your stars, because a fresh player always outperforms a tired one",explSimple:["Smart! A tired player makes more mistakes, so one day off now means he's stronger for the rest of the pennant race.","Keeping a tired player in the lineup sounds loyal, but fatigue causes errors because his body needs rest.","Reducing his role helps a little, but a full day off is better since he needs a complete reset.","Benching him for 20 games is way too long because you need your best player for the pennant race."], anim:"safe",historicalNote:"September 6, 1995 — Camden Yards, Baltimore. Cal Ripken Jr. played in his 2,131st consecutive game, breaking Lou Gehrig's record that had stood for 56 years. The game was stopped for a 22-minute standing ovation. Ripken went on to extend the streak to 2,632 games."},
    {id:"fp19", conceptTag:"two-strike-approach",title:"Clemente's 3000th",diff:1,cat:"famous",ageMin:6,ageMax:99,
      description:"September 30, 1972. Roberto Clemente steps in with an 0-1 count, chasing career hit #3,000. The pitcher has been working him inside all game. Clemente is a legendary bad-ball hitter who can drive pitches off the plate. What's the right approach at the plate?",
      situation:{inning:"Bot 4",outs:1,count:"0-1",runners:[],score:[3,1]},
      options:["Be aggressive on a hittable pitch — drive it hard into the gap","Try to bunt for a safe single to guarantee reaching the milestone","Wait for a perfect pitch down the middle before swinging","Sell out for a home run — uppercut everything"],
      best:0,explanations:["Being aggressive on a hittable pitch is the best strategy here, because behind in the count 0-1 you need to be ready to attack. Clemente ripped a line drive double into the left-center gap — that's what happens when a great hitter stays aggressive and drives the ball where it's pitched, which means he used the whole field instead of trying to do too much.","Bunting for a hit with 1 out and no runners on wastes the at-bat, because a single through the infield accomplishes the same thing while also giving your team a chance at extra-base hits. If you bunt, you surrender the ability to drive in runs or create a bigger inning.","Waiting for a perfect pitch when you're already behind 0-1 is risky, because every take brings you closer to an 0-2 hole. Clemente was a famously aggressive hitter who attacked pitches off the plate — that way he controlled the at-bat instead of letting the pitcher dictate.","Selling out for a homer changes your swing mechanics, which means you're more likely to miss or pop up. The key is to let the ball travel deep and drive it where it's pitched, otherwise you're swinging under pitches and striking out."],
      rates:[85,15,30,25],concept:"The key lesson is: when you stay aggressive and drive the ball where it's pitched, good things happen — because you trying to do too much always leads to weak contact or strikeouts",explSimple:["Great choice! Stay aggressive and drive the ball hard — that's how Clemente got his 3,000th hit.","Not the best move. Bunting wastes your chance to drive the ball for extra bases.","Not the best move. Waiting too long behind in the count lets the pitcher get ahead.","Not the best move. Trying to hit a homer changes your swing and makes you more likely to miss."], anim:"hit",historicalNote:"September 30, 1972 — Three Rivers Stadium, Pittsburgh. Roberto Clemente doubled off the left-center field wall for his 3,000th hit, becoming only the 11th player to reach the milestone. Tragically, it was his last regular season hit — he died in a plane crash on December 31, 1972."},
    {id:"fp20", conceptTag:"situational-hitting",title:"Shot Heard Round the World",diff:3,cat:"famous",ageMin:12,ageMax:99,
      description:"October 3, 1951. The Giants trail the Dodgers 4-2 in the bottom of the 9th of a winner-take-all playoff game at the Polo Grounds. Bobby Thomson steps up against reliever Ralph Branca with runners on second and third. The Dodgers could walk Thomson to load the bases and set up a double play, or pitch to him. Branca delivers a fastball up and in.",
      situation:{inning:"Bot 9",outs:1,count:"0-1",runners:[2,3],score:[2,4]},
      options:["Turn on the inside fastball and drive it — this is your moment","Take the pitch and look for something on the outer half","Bunt to squeeze the tying run home from third","Try to hit it on the ground to the right side to score a run"],
      best:0,explanations:["Bobby Thomson turned on Branca's fastball and launched it into the left field stands for a three-run homer that won the pennant. Radio announcer Russ Hodges screamed 'The Giants win the pennant!' four times in one of the most famous calls in sports history. It capped an incredible comeback — the Giants had trailed the Dodgers by 13.5 games in August.","With the game on the line, you can't afford to be passive looking for a specific location, which means thomson knew he needed a big hit, and when he got a fastball he could handle, he jumped on it. Aggressive approach in big moments.","A squeeze bunt ties one run but doesn't win the game, and it's an extremely risky play with one out, because if the bunt is popped up or missed, the rally dies. Thomson needed to swing the bat to make history.","A ground ball to the right side might score one run, but the Giants needed three, since you playing for one run when you're down two is playing not to lose. Thomson's aggressive swing gave the Giants everything they needed."],
      rates:[85,20,25,30],concept:"In baseball's biggest moments, the greatest players look to drive the ball. Bobby Thomson's homer is proof that aggressive confidence can produce miracles.",anim:"hit",historicalNote:"October 3, 1951 — Polo Grounds, New York. Bobby Thomson hit a three-run homer off Ralph Branca in the bottom of the 9th of a tiebreaker playoff game, erasing a 13.5-game deficit the Giants had faced in August. Radio announcer Russ Hodges screamed the immortal call."},
    {id:"fp21",title:"Merkle's Boner — 1908",diff:3,cat:"famous",conceptTag:"appeal-play",ageMin:12,ageMax:99,
      description:"September 23, 1908. Giants vs Cubs, bottom of the 9th, tie game 1-1. Al Bridwell singles to center, apparently scoring the winning run from 3rd. The crowd pours onto the field in celebration. But Cubs second baseman Johnny Evers notices that 19-year-old Fred Merkle — the runner on 1st — never touched 2nd base. He turned and ran to the clubhouse instead. Evers is screaming for the ball. You're the Cubs manager. What do you do?",
      situation:{inning:"Bot 9",outs:1,count:"0-0",runners:[1,3],score:[1,1]},
      options:["Appeal at 2nd base immediately — Merkle never touched it","Let it go — the winning run already scored","Appeal at 1st base — make Merkle go back","Argue that the hit should be ruled foul"],
      best:0,explanations:["This is exactly what happened — and it changed baseball history. Johnny Evers got a baseball (the actual game ball was lost in the crowd chaos), touched 2nd base, and appealed. Umpire Hank O'Day ruled Merkle out as the 3rd out via force play. Because the 3rd out was a force, the run that crossed home plate did NOT count. The game was declared a tie and replayed at season's end — the Cubs won that replay and the pennant. This became the most famous baserunning mistake in history.","The run does NOT automatically count. Under the rules, Merkle was forced to advance to 2nd (the batter's single forced him). If the defense touches 2nd with the ball before Merkle does, he's out on a force. And a 3rd out that's a force play erases ANY run scored on that play — even if the runner crossed home first.","The appeal must happen at the base the runner failed to touch — 2nd base, not 1st. Merkle left 1st base legally on the batter's hit; his mistake was never touching 2nd. Appeals always go to the specific base that was missed.","The hit was clearly fair and there's no basis to argue otherwise. The appeal at 2nd base is the only legitimate play available, because the force at second — Merkle was forced to advance — makes the third out erase the run."],
      rates:[90,40,25,15],concept:"The lesson is always touch every base, because a force-play appeal erases any runs scored on the same play",anim:"safe"},
  ],
  rules: [
    {id:"rl1", conceptTag:"infield-fly",title:"Infield Fly Rule",diff:2,cat:"rules",ageMin:9,ageMax:99,
      description:"Runners on 1st and 2nd, 1 out. The batter pops up to shallow left field. The umpire raises his hand and yells 'Infield fly!' What does this mean?",
      situation:{inning:"Bot 4",outs:1,count:"1-0",runners:[1,2],score:[2,1]},
      options:["The batter is automatically out, runners can advance at their own risk","Play is dead — nobody moves","The fielder MUST catch it or it's an error","Runners must tag up like a regular fly ball"],
      best:0,explanations:["Correct! The infield fly rule protects runners from a fielder intentionally dropping the pop-up to turn a double play, because batter is out whether caught or not — runners can advance at their risk.","The ball is still live! The reason is runners can advance at their own risk.","The rule doesn't require a catch — the batter is out either way.","They don't have to tag up because the batter is already called out. But they CAN stay on base safely."],
      rates:[85,20,25,40],concept:"Infield fly rule: batter is out, ball is live, runners advance at own risk — prevents trick double plays",explSimple:["The infield fly rule protects runners from a fielder intentionally dropping the pop-up to turn a double play.","The ball is still live!","The rule doesn't require a catch — the batter is out either way.","They don't have to tag up because the batter is already called out."],anim:"flyout"},
    {id:"rl2", conceptTag:"balk-rule",title:"What's a Balk?",diff:2,cat:"rules",ageMin:9,ageMax:99,
      description:"Runner on 1st base. The pitcher comes set, then flinches his shoulder toward home plate but doesn't throw. What's the call?",
      situation:{inning:"Top 3",outs:0,count:"1-1",runners:[1],score:[0,0]},
      options:["No call — he didn't actually pitch","Balk! The runner gets 2nd base","Strike — any motion toward home counts","Ball — failed pitch attempt"],
      best:1,explanations:["Any motion toward home that doesn't result in a pitch is a balk when runners are on base.","Once a pitcher starts his motion toward home, he MUST deliver the pitch — any flinch, stop, or fake is a balk. The runner advances one base.","It's not a strike because the ball was never thrown.","It's not counted as a ball either — it's a balk, which is its own category."],
      rates:[25,85,15,20],concept:"Any start-and-stop motion by the pitcher with runners on base is a balk — one free base",explSimple:["Any motion toward home that doesn't result in a pitch is a balk when runners are on base.","Once a pitcher starts his motion toward home, he MUST deliver the pitch.","It's not a strike because the ball was never thrown.","It's not counted as a ball either — it's a balk, which is its own category."],anim:"advance"},
    {id:"rl3", conceptTag:"dropped-third-strike",title:"Dropped Third Strike",diff:2,cat:"rules",ageMin:9,ageMax:99,
      description:"2 outs, nobody on base. The pitch comes in for strike three, but the ball bounces in the dirt and gets past the catcher. What can the batter do?",
      situation:{inning:"Top 7",outs:2,count:"0-2",runners:[],score:[3,1]},
      options:["Nothing — strikeout, he's automatically out","Run to first! If the catcher doesn't throw him out, he's safe","Only run if the umpire signals","Ask the umpire for another pitch"],
      best:1,explanations:["If you think nothing happens and it's automatically a strikeout, you'd only be right with less than 2 outs AND a runner on 1st, which means but with 2 outs or 1st base empty, the dropped 3rd strike rule is in effect.","On a dropped third strike with 2 outs (or no runner on 1st), the batter becomes a runner! Sprint to first, because if the catcher's throw doesn't beat you, you're safe.","The umpire doesn't signal — you need to KNOW the rule and react immediately.","You can't ask the umpire for another pitch — there's no do-over for a dropped third strike, since know the rule and RUN."],
      rates:[30,85,20,10],concept:"Dropped third strike: with 2 outs or 1st base empty, the batter can run to first",explSimple:["With less than 2 outs AND a runner on 1st, you'd be right.","On a dropped third strike with 2 outs (or no runner on 1st), the batter becomes a runner!","The umpire doesn't signal — you need to KNOW the rule and react immediately.","There's no do-over for a dropped third strike."],anim:"advance"},
    {id:"rl4", conceptTag:"appeal-play",title:"Appeal Play — Missing a Base",diff:3,cat:"rules",ageMin:12,ageMax:99,
      description:"Runner on 1st takes off on contact. Ball is hit deep to center — off the wall! The runner rounds 2nd but barely misses touching the bag. He reaches 3rd. Can the defense do anything?",
      situation:{inning:"Bot 5",outs:1,count:"2-1",runners:[1],score:[3,3]},
      options:["Nothing — the play is over","Appeal! Throw to 2nd base and the runner is out","They can only appeal between innings","The runner has to go back and touch 2nd"],
      best:1,explanations:["The defense absolutely can appeal a missed base — it's one of the most missed rules in baseball.","The defensive team can 'appeal' by throwing to 2nd base while it's still a live ball, because if the umpire saw the runner miss the bag, he's OUT. This has decided real MLB games.","Appeals can happen at any time while the ball is live — not just between innings.","The runner could try to go back and retouch 2nd, but he'd risk being tagged out in between bases. The defense can appeal instead — it's safer and more reliable for them."],
      rates:[20,85,15,30],concept:"The defense can appeal a missed base — always touch every bag, even in the heat of the play",anim:"safe"},
    {id:"rl5", conceptTag:"obstruction-interference",title:"Obstruction vs Interference",diff:3,cat:"rules",ageMin:12,ageMax:99,
      description:"Runner heading to 3rd base. The third baseman stands in the baseline waiting for the throw, but doesn't have the ball yet. The runner has to go around him. What's the call?",
      situation:{inning:"Top 6",outs:0,count:"0-0",runners:[2],score:[2,1]},
      options:["Nothing — the fielder has the right to the baseline","Obstruction on the fielder — runner gets the base","Interference on the runner — runner is out","The runner should have slid"],
      best:1,explanations:["A fielder only has the right to the baseline when fielding the ball or in possession of it, since it gives you the best chance of success.","Obstruction! A fielder without the ball cannot block the baseline, which means the runner is awarded at least 3rd base. In the 2013 World Series, this call ended Game 3.","Interference is called on the RUNNER, not the fielder, because this is obstruction.","Sliding doesn't matter, since the fielder illegally blocked the path."],
      rates:[25,85,15,20],concept:"Obstruction: fielders can't block the baseline without the ball — runners get the base",anim:"advance"},
    {id:"rl6", conceptTag:"dh-rule",title:"Designated Hitter Rule",diff:2,cat:"rules",ageMin:6,ageMax:99,
      description:"You're the manager setting your lineup. Your pitcher bats 4th in the batting order. What's your option?",
      situation:{inning:"Top 1",outs:0,count:"0-0",runners:[],score:[0,0]},
      options:["The pitcher must bat — that's the rule","Use a designated hitter (DH) to bat in the pitcher's spot","Pinch hit for the pitcher every time he's due up","Let a fielder bat twice"],
      best:1,explanations:["In the AL (and now universally since 2022), the DH replaces the pitcher in the batting order.","The designated hitter (DH) bats in place of the pitcher. Since 2022, both AL and NL use the DH. The pitcher never has to bat.","Pinch hitting removes the pitcher from the game, because the DH stays in the lineup all game.","A player can only occupy one spot in the batting order."],
      rates:[25,85,40,20],concept:"The designated hitter (DH) bats for the pitcher — universal in MLB since 2022",explSimple:["Not the best move. In the AL , the DH replaces the pitcher in the batting order.","Great choice! The designated hitter bats in place of the pitcher.","Not the best move. Pinch hitting removes the pitcher from the game.","Not the best move. A player can only occupy one spot in the batting order."], anim:"strike"},
    {id:"rl7", conceptTag:"ground-rule-double",title:"Ground Rule Double",diff:1,cat:"rules",ageMin:6,ageMax:99,
      description:"Runner on 1st, 1 out. The batter hits a screaming line drive that bounces once in fair territory, then hops over the outfield fence. Where do the runners end up?",
      situation:{inning:"Bot 6",outs:1,count:"2-1",runners:[1],score:[1,2]},
      options:["Home run! Both runners score","Runner goes to 3rd, batter gets 2nd — ground rule double","Runner scores, batter gets 2nd","Batter returns to hit again — do-over"],
      best:1,explanations:["A ball that bounces over the fence is NOT a home run — it's a ground rule double.","A ground rule double awards all runners exactly two bases from where they were — runner on 1st goes to 3rd. Batter stops at 2nd. Even if the runner could have scored, he only gets two bases.","The runner on 1st only advances to 3rd — two bases from 1st base, not home.","There's no do-over, which means the ground rule double stands. Think about what gives your team the best result here."],
      rates:[20,85,30,10],concept:"Ground rule double: all runners advance exactly two bases — even if they could have scored",explSimple:["Not the best move. A ball that bounces over the fence is NOT a home run — it's.","Great choice! A ground rule double awards all runners exactly two bases from where they were.","Not the best move. The runner on 1st only advances to 3rd — two bases from 1st base, not home.","Not the best move. There's no do-over."], anim:"advance"},
    {id:"rl8", conceptTag:"tag-up",title:"Tag Up on a Fly Ball",diff:1,cat:"rules",ageMin:6,ageMax:99,
      description:"Runner on 3rd, 1 out. The batter hits a deep fly ball to center field. The runner wants to score after the catch. What MUST he do?",
      situation:{inning:"Bot 8",outs:1,count:"1-0",runners:[3],score:[2,3]},
      options:["Start running as soon as the ball is hit","Wait on the base until the fielder CATCHES the ball, then run","Wait until the umpire signals","He can't advance on a fly ball"],
      best:1,explanations:["Leaving early means the defense can throw to 3rd for an appeal out.","The runner must 'tag up' — keep his foot on 3rd base until the ball is CAUGHT, then sprint home, because if he leaves early and the defense appeals, he's out.","There's no special umpire signal — you have to watch the catch yourself.","Runners absolutely can advance after a catch — that's the whole point of a sacrifice fly."],
      rates:[40,90,25,15],concept:"Tag up: on a fly ball, touch your base until the catch is made, THEN you can advance",explSimple:["Not the best move. Leaving early means the defense can throw to 3rd for an appeal out.","Great choice! The runner must 'tag up' — keep his foot on 3rd base until the ball.","Not the best move. There's no special umpire signal — you have to watch the catch yourself.","Not the best move. Runners absolutely can advance after a catch — that's the whole point of a give-up fly."], anim:"score"},

    {id:"rl9",title:"Infield Fly Rule",diff:2,cat:"rules",conceptTag:"infield-fly",ageMin:9,ageMax:99,
      description:"Runners on first and second with one out. The batter pops up a high fly ball to the shortstop area. The umpire immediately points up and yells 'Infield fly!' before the ball even comes down. The shortstop lets the ball drop on purpose. What happens?",
      situation:{inning:"Top 5",outs:1,count:"1-2",runners:[1,2],score:[2,3]},
      options:["The batter is out automatically — the infield fly rule protects the runners","The ball is dead and all runners return to their bases","It's a live ball and the shortstop can throw to second for a double play","The batter gets to run to first because the fielder dropped it on purpose"],
      best:0,explanations:["Correct! The infield fly rule says that when there are runners on first and second (or bases loaded) with less than two outs, a pop fly that an infielder can catch with ordinary effort makes the batter automatically out — even if the fielder drops it. This prevents fielders from intentionally dropping easy pop-ups to turn double plays on confused runners.","The ball is NOT dead on an infield fly. It's still a live ball, and runners can advance at their own risk. They just aren't forced to run because the batter is already out. This is a common misconception about the rule.","Since the batter is already out due to the infield fly call, there's no force play anymore. The runners can stay on their bases safely. The whole point of the rule is to prevent this kind of trickery.","The batter is out regardless of whether the fielder catches it. That's the entire purpose of the infield fly rule — to protect the offense from fielders who might deliberately drop an easy fly ball."],
      rates:[85,30,15,25],concept:"The infield fly rule protects runners from being tricked. When called, the batter is automatically out even if the fielder drops the ball on purpose.",explSimple:["The infield fly rule says that when there are runners on first and second (or bases loaded) with less than two outs, a pop fly that an infielder can catch with ordinary effort makes the batter auto...","The ball is NOT dead on an infield fly.","Since the batter is already out due to the infield fly call, there's no force play anymore.","The batter is out regardless of whether the fielder catches it."],anim:"flyout"},
    {id:"rl10", conceptTag:"tag-up",title:"Tagging on Fouls",diff:1,cat:"rules",ageMin:6,ageMax:99,
      description:"Runner on third base with one out. The batter hits a deep fly ball down the right field line, but it curves foul. The right fielder makes a nice running catch in foul territory. The runner on third wants to tag up and score. Is this allowed?",
      situation:{inning:"Bot 7",outs:1,count:"0-0",runners:[3],score:[3,4]},
      options:["Yes — runners CAN tag up and advance on a caught foul ball","No — runners must stay on their base after a foul ball is caught","Only if the foul ball was caught in fair territory","Only if the umpire gives special permission"],
      best:0,explanations:["Correct! A caught foul ball is just like a caught fair ball for tagging up. Once the fielder catches it, runners can tag their base and advance at their own risk. This is a smart play — if the foul ball is caught deep enough, the runner can score! Sacrifice flies can happen on foul balls too.","This is a common myth! Runners absolutely can tag up on caught foul balls, since any time a fly ball is caught — fair or foul — runners may tag up and advance. This is especially important for runners on third.","It doesn't matter where the fielder is standing when catching a foul ball, because fair or foul territory, a catch is a catch. Runners can tag up on any caught fly ball regardless of where the fielder is.","The umpire doesn't need to give permission for a tag-up, since it's the runner's right to tag and advance on any caught fly ball. The runner just needs to touch the base after the catch before running."],
      rates:[90,40,25,15],concept:"Runners can tag up and advance on ANY caught fly ball — fair or foul. A deep foul ball catch can turn into a sacrifice fly!",explSimple:["Great choice! Correct! A caught foul ball is just like a caught fair ball for tagging up.","Not the best move. This is a common myth! Runners absolutely can tag up on caught foul balls.","Not the best move. It doesn't matter where the fielder is standing when catching a foul ball.","Not the best move. The umpire doesn't need to give permission for a tag-up."], anim:"score"},
    {id:"rl11", conceptTag:"obstruction-interference",title:"Ball Hits a Runner",diff:2,cat:"rules",ageMin:9,ageMax:99,
      description:"Runner on second base, no outs. The batter hits a sharp ground ball up the middle. The ball passes the pitcher and hits the runner standing on the basepath between second and third. No fielder had a chance to make a play on the ball. What's the call?",
      situation:{inning:"Top 3",outs:0,count:"2-1",runners:[2],score:[1,0]},
      options:["The runner is out, the batter gets first base, and the ball is dead","The ball is still live — play continues as normal","Both the runner and batter are out — double play","The batter is out because the hit ball was interfered with"],
      best:0,explanations:["Correct! When a batted ball hits a runner in fair territory before passing a fielder (other than the pitcher), the runner is out, the ball is dead, and the batter is awarded first base. It doesn't matter if the runner tried to avoid the ball. This prevents runners from intentionally getting in the way of ground balls.","The ball is NOT live when it hits a runner, which means it becomes dead immediately. If the ball were still live, runners could deliberately get hit by ground balls to break up plays or cause confusion.","Only the runner who was hit is called out, because the batter is awarded first base, not called out. You can't penalize the batter for something the runner did (or couldn't avoid).","The batter did nothing wrong — they hit a fair ball, since the runner happened to be in the path. The batter is rewarded with first base, not punished with an out."],
      rates:[90,25,15,40],concept:"If a batted ball hits a runner before passing a fielder, the runner is out and the ball is dead. The batter gets first base.",explSimple:["When a batted ball hits a runner in fair territory before passing a fielder (other than the pitcher), the runner is out, the ball is dead, and the batter is awarded first base.","The ball is NOT live when it hits a runner.","Only the runner who was hit is called out.","The batter did nothing wrong — they hit a fair ball."],anim:"groundout"},
    {id:"rl12", conceptTag:"dropped-third-strike",title:"Dropped Third Strike",diff:2,cat:"rules",ageMin:9,ageMax:99,
      description:"Two outs, nobody on base. The pitch comes in as a nasty curveball for strike three, but the ball bounces in the dirt and gets away from the catcher. The batter starts to walk back to the dugout. The catcher hasn't picked up the ball yet. What should he do?",
      situation:{inning:"Bot 6",outs:2,count:"1-2",runners:[],score:[2,2]},
      options:["Run to first base! On a dropped third strike, the batter can try to reach first safely","Walk to the dugout — strike three means you're out no matter what","Wait for the umpire to tell you whether to run or not","Stay in the box and ask for another pitch since the catcher dropped it"],
      best:0,explanations:["Correct! On a dropped third strike, the batter can run to first base if first base is unoccupied or there are two outs. The catcher must either tag the batter or throw to first to complete the out. Many runners have reached base this way — never assume you're out! Always run on a ball in the dirt with two strikes.","Never walk to the dugout on a dropped third strike! This is one of the most important rules to know, because if the catcher doesn't catch strike three cleanly, you have a chance to reach base. Always be alert and run!","Don't wait for the umpire — just run! The umpire will signal strike three, but it's YOUR job to know the dropped third strike rule and take off for first base — time is everything here.","You don't get an extra pitch, which means strike three is still strike three — but if the catcher drops it, the play isn't over. You need to beat the throw to first base to be safe, just like on a ground ball."],
      rates:[90,15,40,25],concept:"On a dropped third strike, the batter can run to first if it's unoccupied or there are two outs. Never walk away — always run!",explSimple:["On a dropped third strike, the batter can run to first base if first base is unoccupied or there are two outs.","Never walk to the dugout on a dropped third strike!","Don't wait for the umpire — just run!","You don't get an extra pitch."],anim:"safe"},
    {id:"rl13", conceptTag:"balk-rule",title:"What's a Balk?",diff:1,cat:"rules",ageMin:6,ageMax:99,
      description:"Runner on first base with no outs. The pitcher starts his windup but suddenly stops and doesn't throw the ball. The umpire immediately calls 'Balk!' The runner on first looks confused. What happens when a balk is called?",
      situation:{inning:"Top 4",outs:0,count:"2-1",runners:[1],score:[0,1]},
      options:["All runners advance one base — the balk gives them a free base","The pitch is just called a ball and the count changes","The runner on first is sent back and the pitcher gets a warning","The play is dead and everything resets — do-over for the pitcher"],
      best:0,explanations:["Correct! A balk means all runners advance one base for free. A balk is an illegal motion by the pitcher designed to trick the runners. The most common balks are: starting your windup and stopping, faking a throw to first without stepping off the rubber, or making a pitching motion without throwing. The rule prevents pitchers from deceiving runners.","A balk is not just a ball added to the count, because it's a much bigger penalty — all runners move up one base. If a runner is on third, a balk scores a run! Pitchers have to be very careful with their motions.","There are no warnings for balks in baseball, since once the umpire sees an illegal motion, the balk is called immediately and runners advance. Pitchers learn proper mechanics to avoid balks.","The play doesn't reset, because the balk has a real consequence — runners advance. You can't just call a do-over when a pitcher makes an illegal move. The penalty is there to keep the game fair for baserunners."],
      rates:[90,40,25,15],concept:"A balk is an illegal motion by the pitcher. When called, all runners advance one base for free. Pitchers must follow the rules of their windup!",explSimple:["Great choice! Correct! A balk means all runners advance one base for free.","Not the best move. A balk is not just a ball added to the count.","Not the best move. There are no warnings for balks in baseball.","Not the best move. The play doesn't reset."], anim:"advance"},
    {id:"rl14",title:"Tag Up on Foul Fly",diff:1,cat:"rules",conceptTag:"tag-up",ageMin:8,ageMax:99,
      description:"Runners on first and third with one out. The batter hits a towering pop-up that drifts into foul territory near the third base dugout. The third baseman makes the catch. The runner on third touches the base and sprints home. The runner on first stays put. Is this play legal?",
      situation:{inning:"Bot 5",outs:1,count:"1-1",runners:[1,3],score:[1,2]},
      options:["Yes — you can tag up on any caught fly ball, including foul balls","No — runners must stay on their bases after a foul ball catch","Only the runner on third can advance, the runner on first is stuck","It's the umpire's judgment call whether the catch was close enough to fair"],
      best:0,explanations:["Correct! Any caught fly ball — fair or foul — allows runners to tag up and advance. The runner on third tagging and scoring on a caught foul pop-up is a perfectly legal and smart play. If the catch is deep enough, it works just like a sacrifice fly. Both runners could tag up if they wanted to.","This is a common misunderstanding, because once a foul fly is caught, runners are free to advance just like on any other catch. The fair/foul line has nothing to do with tag-up rules — the catch is what matters.","Both runners can advance after any caught fly ball — fair or foul, because the tag-up rule applies equally to all catches. The runner on first could try for second if he wanted, though it would be risky on a short pop-up.","The fair/foul distinction doesn't matter for tagging up, because a catch in foul territory works exactly the same as a catch in fair territory for tag-up purposes. There's no judgment call needed — the rule is clear and consistent."],
      rates:[90,20,25,10],concept:"You can tag up on ANY caught fly ball — fair or foul! Smart baserunners are always ready to advance after a catch.",explSimple:["Great choice! Correct! Any caught fly ball — fair or foul — allows runners to tag up and advance.","Not the best move. Runners can advance after any caught fly ball, even in foul territory!","Not the best move. Both runners can advance — no one is stuck after a caught fly ball!","Not the best move. The fair/foul distinction doesn't matter for tagging up."], anim:"score"},
    {id:"rl15", conceptTag:"appeal-play",title:"The Appeal Play",diff:3,cat:"rules",ageMin:12,ageMax:99,
      description:"Runner on second, one out. A deep fly ball is hit to center field and caught. The runner on second tags up and advances to third. But the center fielder notices the runner may have left second base a split second before the catch. The defense wants to challenge. How do they appeal?",
      situation:{inning:"Top 7",outs:1,count:"0-0",runners:[3],score:[1,3]},
      options:["Throw the ball to second base and the fielder steps on the bag while the defense asks the umpire to make the call","Ask the umpire to review whether the runner left early","Push a button to trigger instant replay","The pitcher just has to point at the runner and the umpire checks"],
      best:0,explanations:["Correct! An appeal play requires the defense to physically throw the ball to the base in question and have a fielder touch the bag while appealing to the umpire. The umpire then rules whether the runner left early. If the runner did leave early, they're out. It's the defense's responsibility to make the appeal — umpires won't call it on their own.","Just asking the umpire doesn't count as a proper appeal — the defense must make a physical play — throw the ball to the base and have a fielder touch it while asking for the call. Umpires require a formal appeal.","Instant replay isn't used for tag-up appeals in this way, which means the defense must make a traditional appeal play on the field. In some leagues, replay can be used afterward, but the appeal must happen first.","There's no pointing rule in baseball, because the defense has to actually throw the ball to the base and ask the umpire to make the call. It requires a real baseball play, not just a gesture."],
      rates:[90,25,40,15],concept:"An appeal play means the defense throws to the base and asks the umpire to rule. Umpires don't call tag-up violations unless the defense appeals!",anim:"catch"},
    {id:"rl16", conceptTag:"force-vs-tag",title:"Running the Baseline",diff:2,cat:"rules",ageMin:9,ageMax:99,
      description:"Runner on first tries to steal second. The catcher fires to the shortstop covering the bag. The runner sees the throw coming and veers way off to the right — almost into the outfield grass — to try to dodge the tag. The shortstop chases and tags him. The runner says he was safe because he wasn't tagged on the base. Is the runner out?",
      situation:{inning:"Top 6",outs:0,count:"0-0",runners:[1],score:[2,2]},
      options:["Yes — the runner is out for running more than 3 feet outside the baseline to avoid a tag","No — runners can run anywhere they want on the field","Only if the umpire thinks the runner went too far — it's a judgment call with no set distance","The runner is safe because the shortstop left the base to chase him"],
      best:0,explanations:["Correct! A runner is out if they run more than three feet away from the baseline to avoid being tagged. The baseline is defined as a direct line between the runner and the base they're heading toward. Runners can't just run anywhere on the field to dodge tags — that would make the game chaos!","Runners definitely cannot run anywhere they want. There's a three-foot rule: if you deviate more than three feet from the baseline to avoid a tag, you're out. This keeps the game fair for both offense and defense.","There IS a set distance — three feet, since the umpire judges whether the runner went beyond three feet from the baseline, but the rule is specific about the distance. It's not purely subjective.","The shortstop is allowed to chase a runner, because that's part of playing defense. The issue is that the runner went too far off the baseline to avoid the tag, which is against the rules."],
      rates:[85,10,30,20],concept:"Runners must stay within three feet of the baseline when a fielder is trying to tag them. Going outside that line means you're out!",explSimple:["A runner is out if they run more than three feet away from the baseline to avoid being tagged.","Runners definitely cannot run anywhere they want.","There IS a set distance — three feet.","The shortstop is allowed to chase a runner."],anim:"steal"},
    {id:"rl17", conceptTag:"baserunning-rates",title:"Ground Rule Double",diff:1,cat:"rules",ageMin:6,ageMax:99,
      description:"The batter hits a hard line drive that bounces in fair territory in right field, then hops over the outfield wall. The batter rounds first and heads toward second. The runner who was on first is already past third base heading home. What's the ruling?",
      situation:{inning:"Bot 3",outs:1,count:"0-0",runners:[1],score:[1,1]},
      options:["It's a ground rule double — batter gets second base, all runners advance two bases from where they started","The batter gets a home run since the ball went over the wall","It's a dead ball — everyone goes back to where they were","The batter gets only a single because the ball bounced first"],
      best:0,explanations:["Correct! When a fair ball bounces over the outfield wall, it's an automatic double (commonly called a ground rule double). The batter is awarded second base, and all runners advance two bases from where they were when the ball was hit. So the runner on first goes to third — NOT home, even though he was almost there. This can actually hurt the offense sometimes!","A home run requires the ball to fly over the wall without bouncing — a ball that bounces over is an automatic double, not a homer. The bounce is the key difference.","The ball is dead, but everyone doesn't go back, which means the rule awards the batter second base and advances all runners two bases. The play has a result — it's just determined by the rule rather than continued play.","A ground rule double is worth two bases, not one. Even though the ball bounced, the rule awards extra bases because the ball left the field of play. The batter gets second, and runners move up two bases."],
      rates:[90,40,15,25],concept:"A ground rule double happens when a fair ball bounces over the outfield wall. The batter gets second base and all runners advance two bases.",explSimple:["Great choice! Correct! When a fair ball bounces over the outfield wall, it's an automatic double.","Not the best move. A home run requires the ball to fly over the wall without bouncing.","Not the best move. The ball is dead, but everyone doesn't go back.","Not the best move. A ground rule double is worth two bases, not one."], anim:"hit"},
    {id:"rl18", conceptTag:"force-vs-tag",title:"Two Runners, One Base",diff:2,cat:"rules",ageMin:9,ageMax:99,
      description:"Runners on first and second, no outs. The batter hits a fly ball to right field. The runner on second tags up and advances to third. But the runner on first panics, thinks it's going to drop, and also runs to third base. Now both runners are standing on third base at the same time. Who gets the base?",
      situation:{inning:"Top 4",outs:0,count:"1-0",runners:[1,2],score:[0,0]},
      options:["The lead runner (who was on second) owns the base — the trailing runner can be tagged out","The first runner to touch the base gets it — first come, first served","Both runners are safe as long as they're touching the base","Both runners are out for causing confusion on the basepaths"],
      best:0,explanations:["Correct! When two runners end up on the same base, the lead runner (the one who was originally ahead on the basepaths) is entitled to the base. The trailing runner is considered 'off base' and can be tagged out. In this case, the runner who was on second base owns third, and the runner from first can be tagged out.","It's not about who arrives first, because baseball gives priority to the lead runner — the one who was originally farther ahead. Even if the trailing runner got there first, the lead runner has the right to the base.","Two runners cannot both be safe on the same base, since only one runner can legally occupy a base at a time. The lead runner gets priority, and the other runner is at risk of being tagged out.","Only the trailing runner is out, not both, because the lead runner didn't do anything wrong — they legally advanced to third. You can't penalize a runner for their teammate's mistake."],
      rates:[90,40,25,15],concept:"When two runners are on the same base, the lead runner (the one originally ahead) gets the base. The other runner can be tagged out!",explSimple:["When two runners end up on the same base, the lead runner (the one who was originally ahead on the basepaths) is entitled to the base.","It's not about who arrives first.","Two runners cannot both be safe on the same base.","Only the trailing runner is out, not both."],anim:"catch"},
    {id:"rl19",title:"Is He Out? The Third Strike Rule",diff:2,cat:"rules",ageMin:9,ageMax:99,
      description:"Bottom of the 8th, tie game. The pitch comes in as a nasty splitter that hits the dirt — strike three! But the catcher bobbles it and the ball rolls to the backstop. Runner on third, 2 outs. The home crowd cheers thinking the inning is over. Is the batter out?",
      situation:{inning:"Bot 8",outs:2,count:"3-2",runners:[3],score:[4,4]},
      options:["Strike three ended the inning — he's automatically out","The batter can run to first — first base is empty and there are 2 outs","Since the ball was wild, the runner on third automatically scores","No runners can move until an umpire signal is given"],
      best:1,explanations:["The batter is NOT automatically out just because the umpire called strike three. The dropped third strike rule says the catcher must cleanly catch the ball for the out to count. With first base empty and 2 outs, the batter becomes a runner — the inning continues until the defense records the actual out.","This is the dropped third strike rule. With 2 outs and first base empty, the batter can run to first because the catcher didn't catch the pitch cleanly. The catcher has to recover the ball and either tag the batter or throw to first before he arrives. Meanwhile, the runner on third reads the chaos and might sprint home to score!","The runner on third doesn't score automatically — this isn't a home run or a dead ball. The play is still live, so the runner must judge the situation: if the catcher recovers the ball quickly and throws to first, it might be too risky to run home. Only if the ball rolls far enough does the runner have a clear chance.","The play is live the instant the ball hits the dirt — no umpire signal is needed to start running. Both the batter and the runner on third can advance at their own risk immediately. Smart baserunners recognize a dropped third strike right away and react before the defense does."],
      rates:[25,88,15,20],concept:"With 2 outs and first base empty, a dropped/uncaught third strike lets the batter run to first — the play is live and the catcher must throw him out.",explSimple:["Not so fast — the batter isn't out yet! When the catcher doesn't catch strike three and first base is open, the batter can run.","You got it! This is called the 'dropped third strike' rule. The catcher has to throw the batter out at first or tag him.","The runner on third doesn't score just because the ball got away. He has to decide if it's safe to run.","The play is happening right now — no need to wait for the umpire to say anything!"],anim:"safe",conceptTag:"dropped-third-strike"},
    // ============================================================================
    // RULES EXPANSION — Edge cases that cause the most confusion
    // ============================================================================
    {id:"rl20",title:"Batting Out of Order — Who's Really Out?",diff:3,cat:"rules",conceptTag:"appeal-play",ageMin:12,ageMax:99,
      description:"Top of the 5th. Your team's lineup card shows: #3 hitter Smith, then #4 hitter Jones. But Jones accidentally bats in Smith's spot and lines a double! The opposing manager notices and appeals to the umpire. What happens?",
      situation:{inning:"Top 5",outs:0,count:"0-0",runners:[],score:[2,1]},
      options:["Jones is called out and the double is erased","Smith is called out — HE was the proper batter who didn't bat","Nothing happens — once the pitch was thrown, it's too late","Jones keeps the double but gets a warning for next time"],
      best:1,explanations:["Jones isn't the one penalized, since he's the improper batter but the PROPER batter is the one declared out — this is the most confusing part of the rule.","Correct! MLB Rule 6.03(b): when batting out of order is appealed, the PROPER batter (Smith) is declared out, and any advancement by the improper batter (Jones) is nullified. The double is erased. The next batter is whoever follows Smith in the order. The key: the defense must appeal BEFORE the next pitch.","It's only too late if the next pitch has already been thrown, which means until then, the defense can appeal. Timing is everything with this rule.","There are no warnings in baseball for batting out of order, because it's an immediate appeal play with real consequences — an out is recorded."],
      rates:[35,82,30,10],concept:"Batting out of order: the PROPER batter (who should have batted) is declared out, not the one who actually batted. Appeal must come before the next pitch.",explSimple:["When the catcher doesn't cleanly catch strike three AND first base is unoccupied with 2 outs, the batter becomes a runner.","This is the dropped third strike rule in action.","The runner on third doesn't automatically score — he can only advance at his own risk.","No umpire signal is needed — the play is live immediately!"],anim:"strikeout"},
    {id:"rl21",title:"Runner's Lane Interference — The Last 45 Feet",diff:2,cat:"rules",conceptTag:"obstruction-interference",ageMin:10,ageMax:99,
      description:"Runner on first, nobody out. The batter hits a ground ball to the pitcher. The throw goes to first, but the batter-runner is running in fair territory (on the grass) instead of in the runner's lane (the dirt path to the right of the foul line). The throw hits the runner in the back. Is this interference?",
      situation:{inning:"Top 3",outs:0,count:"1-1",runners:[1],score:[0,0]},
      options:["Yes — the batter-runner must run in the runner's lane for the last 45 feet to first","No — the runner can run anywhere between the foul lines","It's only interference if the runner intentionally got in the way","It depends on whether the runner was inside or outside the foul line"],
      best:0,explanations:["Correct! MLB Rule 5.09(a)(11): In the last 45 feet to first base, the batter-runner must run within the 3-foot runner's lane (the dirt path to the right of the foul line). If running outside the lane and interfering with the throw, the batter-runner is OUT. This is one of the most commonly misunderstood interference calls in baseball.","The runner cannot run just anywhere, since the runner's lane exists specifically to prevent the batter-runner from interfering with throws to first base.","Intent doesn't matter here — it's a position-based rule, because if the runner is outside the lane AND the throw is affected, that's interference regardless of intent.","The key is the runner's lane itself (the 3-foot dirt path), not the foul line. The lane is entirely in foul territory for the last 45 feet to first."],
      rates:[80,15,30,25],concept:"The runner's lane rule: batter-runners must use the 3-foot dirt lane for the last 45 feet to first base or risk interference if a throw is affected.",explSimple:["MLB Rule 5.09(a)(11): In the last 45 feet to first base, the batter-runner must run within the 3-foot runner's lane (the dirt path to the right of the foul line).","The runner cannot run just anywhere.","Intent doesn't matter here — it's a position-based rule.","The key is the runner's lane itself (the 3-foot dirt path), not the foul line."],anim:"groundout"},
    {id:"rl22",title:"Catcher's Interference — Free Base or Keep the Play?",diff:3,cat:"rules",conceptTag:"obstruction-interference",ageMin:12,ageMax:99,
      description:"Bottom of the 6th, runner on second, one out. The batter swings and his bat makes contact with the catcher's glove on the follow-through. He still manages to hit the ball into right field for a single, and the runner scores from second. The umpire calls catcher's interference. What happens next?",
      situation:{inning:"Bot 6",outs:1,count:"2-1",runners:[2],score:[3,3]},
      options:["Batter gets first base and the runner goes back to second — that's the interference penalty","Actually, the offensive manager can CHOOSE: accept the interference (batter to 1st, runners advance one base) or decline it and take the result of the play","When interference is called, the play is dead immediately — nothing that happened on the play counts","The batter is automatically out for swinging into the catcher's glove"],
      best:1,explanations:["This would be the default interference penalty, but there's an important exception when the batter reaches base AND all runners advance at least one base on the play, since that's why this approach matters in this situation.","Correct! MLB Rule 6.01(c): If the batter reaches first AND all runners advance at least one base on the play, the offensive manager can DECLINE the interference and keep the result of the play. Here, the single scored a run — much better than just a walk! The manager would decline interference and take the RBI single.","Catcher's interference is a delayed dead ball, not an immediate dead ball, since the play is allowed to continue, THEN the manager chooses.","The batter is never out for catcher's interference — it's a penalty on the CATCHER, not the batter, which means the catcher's glove was in the wrong position."],
      rates:[40,78,25,10],concept:"Catcher's interference is a delayed dead ball — the offense can decline the penalty and keep the play result if all runners advanced at least one base.",anim:"hit"},
    {id:"rl23",title:"Time Play vs. Force Play — Does the Run Count?",diff:3,cat:"rules",conceptTag:"force-vs-tag",ageMin:12,ageMax:99,
      description:"Bottom of the 9th, tie game. Runners on first and third, one out. The batter hits a ground ball to the shortstop who throws to second for the force out (2nd out), then the relay goes to first but the batter-runner beats the throw. Meanwhile, the runner from third crossed home plate BEFORE the force out at second was recorded. Does the run count?",
      situation:{inning:"Bot 9",outs:1,count:"1-0",runners:[1,3],score:[5,5]},
      options:["Yes — the runner scored before the out was made, so the run counts","No — the third out was a force out, so no run can score regardless of timing","Yes — since the batter-runner was safe at first, all runners are safe","It depends on whether the umpire saw the runner touch home plate"],
      best:1,explanations:["This is the classic trap! Timing doesn't matter on force outs, because when the third out is a force out, NO run can score on that play, even if the runner crossed the plate first. This is the force play exception.","Correct! MLB Rule 5.08(a) exception: A run does NOT score if the third out is a force out. The out at second was a force (runner from first was forced to advance), so even though the runner from third touched home before the tag, the run is wiped out. This is the MOST important timing rule in baseball.","The batter-runner being safe at first doesn't affect the force at second, since the second out was still a force out, and that's what matters for the run-scoring rule.","The umpire's timing observation doesn't matter because this is a force play situation. Force outs automatically negate any runs scored on that play, regardless of when the runner touched home."],
      rates:[30,80,20,15],concept:"The force play exception: when the third out of an inning is a force out, NO run can score on that play — even if the runner crossed home plate before the out was recorded.",anim:"doubleplay"},
    {id:"rl24",title:"Pitch Clock Violation — Who Gets Penalized?",diff:2,cat:"rules",conceptTag:"pitch-clock-strategy",ageMin:10,ageMax:99,
      description:"Top of the 3rd, runner on first, 1-1 count. The pitch clock is at 20 seconds (runners on base). The pitcher has set but hasn't started his delivery. The clock hits zero. What happens?",
      situation:{inning:"Top 3",outs:0,count:"1-1",runners:[1],score:[0,0]},
      options:["An automatic ball is added to the count — now it's 2-1","An automatic strike is added — pitchers are penalized more","The umpire gives a warning first, then a ball on the next violation","The pitch clock resets and the pitcher gets another 20 seconds"],
      best:0,explanations:["Correct! When the pitcher fails to start his delivery before the pitch clock expires, it's an automatic BALL added to the count. The count goes from 1-1 to 2-1. The 2023 pitch clock rule (MLB Rule 8.04) penalizes pitchers with a ball for being too slow. This keeps the game moving.","Strikes are the penalty for BATTERS who aren't ready (not alert in the box with 8 seconds left), because pitchers get balls, batters get strikes — each side is penalized in a way that hurts them.","There are no warnings, since pitch clock violations are automatic from the first infraction — the rule was designed to be immediate and consistent.","The clock does not reset for violations, which means an automatic ball is assessed immediately. The pitcher violated the time limit and is penalized."],
      rates:[82,25,30,15],concept:"Pitch clock violations: pitcher too slow = automatic ball, batter not ready = automatic strike. No warnings — the penalty is immediate.",explSimple:["When the pitcher fails to start his delivery before the pitch clock expires, it's an automatic BALL added to the count.","Strikes are the penalty for BATTERS who aren't ready (not alert in the box with 8 seconds left).","There are no warnings — pitch clock violations are automatic from the first infraction.","The clock does not reset for violations."],anim:"strike"},
    {id:"rl25",title:"Fan Interference — Home Run or Dead Ball?",diff:2,cat:"rules",conceptTag:"obstruction-interference",ageMin:10,ageMax:99,
      description:"Bottom of the 8th, tie game, runner on second. The batter hits a deep fly ball to right field that's heading for the wall. A fan in the front row reaches OVER the wall into the field of play and catches the ball before the right fielder makes the play. What's the call?",
      situation:{inning:"Bot 8",outs:1,count:"0-1",runners:[2],score:[3,3]},
      options:["Home run — the ball was going out anyway","Fan interference — dead ball, umpire places runners where they would have been","The batter is out because the ball was caught (even by a fan)","Replay review — only the replay officials can make this call"],
      best:1,explanations:["Even if the ball was going out, the umpire can't assume that, because when a fan reaches into the field of play, the result is fan interference regardless of the ball's trajectory.","Correct! MLB Rule 6.01(e): When a spectator reaches INTO the field of play and interferes with a fielder, it's spectator interference. The ball is dead immediately, and the umpire places all runners where they believe the runners would have ended up without the interference. The fan reaching over the wall is the key — the field of play boundary is the TOP of the wall.","Fans can't record outs! The ball is dead the moment a fan interferes with play, since the batter is not out.","While this IS reviewable, the on-field umpire makes the initial call, because the key ruling is fan interference (dead ball), which the crew chief can make in real time. Review can confirm or overturn whether the fan actually reached over the wall."],
      rates:[30,80,10,25],concept:"Fan interference: when a spectator reaches INTO the field of play, it's a dead ball. The umpire places runners where they would have been. The boundary is the top of the wall.",explSimple:["Even if the ball was going out, the umpire can't assume that.","MLB Rule 6.01(e): When a spectator reaches INTO the field of play and interferes with a fielder, it's spectator interference.","Fans can't record outs!","While this IS reviewable, the on-field umpire makes the initial call."],anim:"catch"},
    {id:"rl26",title:"Pitch Clock — Batter Not Ready",diff:1,cat:"rules",conceptTag:"pitch-clock-strategy",ageMin:8,ageMax:99,
      description:"Top of the 5th, nobody on, 2-1 count. The batter steps out to adjust his gloves. The pitch clock shows 8 seconds left. He's still adjusting when it hits zero. What happens?",
      situation:{inning:"Top 5",outs:1,count:"2-1",runners:[],score:[1,0]},
      options:["Automatic strike — now it's 2-2","Automatic ball — now it's 3-1","The umpire pauses the clock until the batter is ready","Nothing — batters can't get clock violations"],
      best:0,explanations:["Correct! The batter must be alert in the box with at least 8 seconds on the pitch clock. If the batter isn't ready when the clock expires, it's an automatic STRIKE. The count goes from 2-1 to 2-2. Pitchers get balls, batters get strikes — each side is penalized in a way that hurts them.","That's the penalty for pitchers, not batters, since pitchers get balls when they're too slow. Batters get strikes when they're not ready.","The clock does not pause for batter delays, which means the rule is designed to keep the game moving, with immediate consequences.","Both pitchers AND batters can get pitch clock violations, because the batter must be ready with 8 seconds left on the clock."],
      explSimple:["Right! If the batter isn't ready in time, the umpire calls an automatic strike. It's like the batter got a strike for being too slow!","That's what happens to pitchers, not batters. Batters get strikes, pitchers get balls.","The clock doesn't stop just because the batter isn't ready — that's the whole point of the rule!","Both the pitcher and the batter have to follow the clock. Batters get strikes if they're too slow."],
      rates:[90,40,25,15],concept:"Pitch clock violations: batters must be alert with 8 seconds left or it's an automatic strike",anim:"strike"},
    {id:"rl27",title:"Pitch Clock — Strategic Step-Off",diff:3,cat:"rules",conceptTag:"pitch-clock-strategy",ageMin:12,ageMax:99,
      description:"Bot 7th, runners on 1st and 2nd, 0 outs, tie game. The speedy runner on 2nd is dancing off the bag. Your pitcher has already used both of his disengagements this plate appearance. The clock shows 12 seconds. Can the pitcher step off the rubber again?",
      situation:{inning:"Bot 7",outs:0,count:"1-0",runners:[1,2],score:[2,2]},
      options:["No — a third step-off is an automatic balk, runners advance","Yes — but only if the pitcher picks off the runner successfully","Yes — the pitcher can step off as many times as he wants","No — but the pitcher can request time from the umpire instead"],
      best:1,explanations:["Close, but not quite! A third disengagement IS a balk — UNLESS the pitcher successfully picks off the runner, since it's a high-risk, high-reward play.","Correct! Under the 2023 pitch clock rules, pitchers get two disengagements (step-offs or pickoff throws) per plate appearance. A third disengagement is an automatic balk — UNLESS the pitcher picks off the runner. This creates a fascinating cat-and-mouse game: the runner knows the pitcher used both disengagements, so he can take a bigger lead. But if the pitcher reads him leaning too far, a third throw that gets him out resets the count.","Pitchers are limited to two disengagements per plate appearance under the 2023 rules, because unlimited step-offs slowed the game down and frustrated base stealers — that's exactly what the rule changed.","Requesting time doesn't pause the disengagement limit — the pitcher either throws a pitch, attempts a third pickoff (risky), or deals with the runner's bigger lead."],
      rates:[40,90,25,15],concept:"Pitchers get 2 disengagements per plate appearance. A third is an automatic balk unless the runner is picked off.",anim:"steal"},
    {id:"rl28",title:"Pitch Clock — Mound Visit Resets the Clock",diff:2,cat:"rules",conceptTag:"pitch-clock-strategy",ageMin:10,ageMax:99,
      description:"Top of the 6th, runners on 1st and 3rd, 1 out. The pitcher looks rattled — just walked two straight batters. The catcher trots to the mound for a quick chat. When the catcher returns, what happens to the pitch clock?",
      situation:{inning:"Top 6",outs:1,count:"0-0",runners:[1,3],score:[2,4]},
      options:["It resets to the full time (20 seconds with runners on)","It continues from where it was — the visit doesn't reset it","Both reset — the clock AND the pitcher's disengagement count","A 30-second bonus clock starts after a mound visit"],
      best:0,explanations:["Correct! Any mound visit — whether from the catcher, pitching coach, or manager — resets the pitch clock to its full amount. With runners on base, that's 20 seconds, which is why smart catchers time their mound visits: it gives the pitcher a breather AND resets the clock. But remember, teams have a limited number of mound visits per game (5 in MLB).","The clock always resets after a mound visit, which means this is one of the strategic benefits of visiting the mound — it's a built-in reset button.","The clock resets, but the pitcher's disengagement count does NOT reset, because the two-disengagement limit is per plate appearance, and a mound visit doesn't change the plate appearance.","The clock resets to the standard amount (15 seconds with bases empty, 20 with runners on), not a bonus 30 seconds. And that's why this approach matters in this situation."],
      explSimple:["Right! When the catcher visits the mound, the pitch clock gets reset to full time. It's like a timeout that gives the pitcher more time.","The clock always resets after a visit. That's one reason catchers go out there!","The clock resets, but the pitcher's pickoff attempts don't reset — those are separate rules.","It resets to the normal time (20 seconds with runners), not 30 seconds."],
      rates:[82,40,28,25],concept:"Mound visits reset the pitch clock to its full amount — a strategic benefit of visiting the mound",anim:"freeze"},
    {id:"rl29",title:"Pitch Clock — What Counts as 'Ready'?",diff:1,cat:"rules",conceptTag:"pitch-clock-strategy",ageMin:8,ageMax:99,
      description:"You're stepping into the batter's box for the first time in a pitch clock game. The announcer says you must be 'alert to the pitcher' with 8 seconds on the clock. What does that actually mean you need to do?",
      situation:{inning:"Top 1",outs:0,count:"0-0",runners:[],score:[0,0]},
      options:["Be in the batter's box with both feet, looking at the pitcher","Just stand near the plate — doesn't matter if you're looking","Have your bat on your shoulder in your stance","Be in the box but you can still be adjusting your gloves"],
      best:0,explanations:["Correct! 'Alert to the pitcher' means you must be in the batter's box AND looking at the pitcher, ready for the pitch to come. Both feet in the box, eyes on the mound. If you're still adjusting your helmet, looking at the scoreboard, or not in your stance, the umpire can call an automatic strike.","You need to be IN the batter's box specifically, not just near the plate, since and you need to be looking at the pitcher — being distracted counts as not ready.","Having your bat on your shoulder isn't required — some hitters hold their bat up, some down, because what matters is that you're in the box and looking at the pitcher.","If you're adjusting your gloves with 8 seconds left, you're NOT alert to the pitcher. Get your adjustments done early! Step out between pitches if needed, but be ready at 8 seconds."],
      explSimple:["Right! You need to be standing in the box with both feet and looking at the pitcher. Think of it like being ready to play — no fiddling with your gear!","You need to actually be in the batter's box, not just somewhere nearby.","You don't have to hold your bat a certain way, but you do need to be in the box and watching the pitcher.","If you're messing with your gloves when there's 8 seconds left, the umpire can call a strike! Get ready early."],
      rates:[85,20,30,30],concept:"Being 'alert to the pitcher' means both feet in the box, eyes on the mound, ready for the pitch",anim:"strike"},
    {id:"rl30",title:"Infield Fly — Does It Apply with Two Outs?",diff:2,cat:"rules",conceptTag:"infield-fly",ageMin:9,ageMax:99,
      description:"Bot 6th, runners on 1st and 2nd, TWO outs. The batter pops the ball straight up near the pitcher's mound. An easy catch. Should the umpire call 'Infield Fly'?",
      situation:{inning:"Bot 6",outs:2,count:"1-2",runners:[1,2],score:[5,3]},
      options:["No — infield fly does NOT apply with 2 outs","Yes — infield fly applies whenever there are runners on 1st and 2nd","Yes — any easy popup with runners on base is infield fly","No — but only because the ball is near the mound, not in the infield"],
      best:0,explanations:["Correct! The infield fly rule ONLY applies with less than 2 outs (0 or 1 out) AND runners on 1st and 2nd, or bases loaded. With 2 outs, the rule doesn't apply because there's no reason for the defense to intentionally drop the ball — they can just catch it for the third out. The rule exists to prevent the defense from getting cheap extra outs by dropping the ball on purpose and forcing runners off their bases.","The infield fly rule requires less than 2 outs, since with 2 outs, the defense would just catch the ball for the easy third out — there's no incentive to drop it.","The infield fly rule has specific conditions: less than 2 outs, runners on 1st and 2nd (or bases loaded), and a fair fly ball that an infielder can catch with ordinary effort. After all, so this approach matters in this situation.","The location of the ball doesn't determine whether the infield fly rule applies, since the conditions do (less than 2 outs + runners on 1st and 2nd or bases loaded) — that's why this approach matters in this situation."],
      explSimple:["Right! The infield fly rule only works with 0 or 1 out, not 2 outs. With 2 outs, the fielder would just catch it for the third out anyway.","The rule only works with less than 2 outs. Think about it — with 2 outs, why would anyone drop the ball on purpose?","There are specific rules about when infield fly applies — it's not just any popup.","Where the ball is doesn't matter. What matters is how many outs there are and where the runners are."],
      rates:[82,40,28,25],concept:"Infield fly rule only applies with less than 2 outs. With 2 outs, the defense has no reason to drop the ball.",anim:"catch"},
    {id:"rl31",title:"Infield Fly — Can Runners Still Advance?",diff:2,cat:"rules",conceptTag:"infield-fly",ageMin:10,ageMax:99,
      description:"Bot 4th, runners on 1st and 2nd, 1 out. The batter pops up to shallow left field. The umpire calls 'Infield Fly, BATTER OUT!' But the shortstop loses the ball in the sun and it drops! Can the runners advance?",
      situation:{inning:"Bot 4",outs:1,count:"0-1",runners:[1,2],score:[1,2]},
      options:["Yes — runners can advance at their own risk, but they don't have to","No — since infield fly was called, the ball is dead and runners must stay","Yes — runners MUST advance because the ball wasn't caught","No — runners can only advance if they were tagging up when the ball dropped"],
      best:0,explanations:["Correct! When the infield fly rule is called, the batter is out regardless of whether the ball is caught. But the ball is still LIVE! Runners can advance at their own risk. They are NOT forced to run (the batter is already out, so the force is removed). If the ball drops, runners can try to advance but can be tagged out. If caught, runners must tag up first.","The ball is NOT dead on an infield fly — this is one of the most common and costly misconceptions in baseball, which means the ball stays live, and runners can advance at their own risk.","Runners do NOT have to advance, because the infield fly call removes the force play (since the batter is already out). Runners can choose to stay safely at their base, and often that's the smartest move.","Runners don't need to be tagging up on a dropped infield fly, because if the ball drops, they can simply run — there's no force and no tag-up requirement on a dropped ball. But they CAN be tagged out."],
      rates:[90,25,15,40],concept:"On an infield fly, the batter is out but the ball is LIVE. Runners can advance at their own risk — the force is removed.",explSimple:["When the infield fly rule is called, the batter is out regardless of whether the ball is caught.","The ball is NOT dead on an infield fly!","Runners do NOT have to advance.","Runners don't need to be tagging up."],anim:"catch"},
    {id:"rl32",title:"Infield Fly — Foul Territory Twist",diff:3,cat:"rules",conceptTag:"infield-fly",ageMin:12,ageMax:99,
      description:"Runners on 1st and 2nd, 0 outs. The batter pops the ball high near the 3rd base line. It could land fair or foul. The umpire calls 'Infield Fly If Fair!' The third baseman drifts over and catches it in FOUL territory. Is the batter out?",
      situation:{inning:"Top 3",outs:0,count:"2-2",runners:[1,2],score:[0,0]},
      options:["Yes — the fielder caught it, so the batter is out regardless of fair/foul","No — since the ball was caught in foul territory, the infield fly is cancelled and it's just a regular foul ball","Yes — the umpire already called it, so the batter is out either way","No — the batter is out because of the catch, not the infield fly rule"],
      best:0,explanations:["Correct! This is a tricky one. The umpire called 'Infield Fly If Fair' — meaning the infield fly would apply IF the ball lands fair. But here the fielder CAUGHT the ball. When any fly ball is caught — fair or foul territory — the batter is out. The infield fly rule doesn't even matter here because the catch itself retires the batter. The ump's conditional call ('If Fair') was correct procedure for a ball near the line.","If the ball DROPPED in foul territory, the infield fly would be cancelled and it would be a foul ball. But the ball was CAUGHT, so the batter is out on the catch — just like any caught foul fly ball.","The umpire's call was conditional ('If Fair'). Since the ball was caught in foul territory, the infield fly technically didn't apply. But the batter IS out — because of the catch, not the infield fly.","Actually, the batter is out because of the catch, which is correct. But the answer should acknowledge that the catch in foul territory makes the infield fly rule moot. The catch itself retires the batter."],
      rates:[78,15,30,65],concept:"'Infield Fly If Fair' is a conditional call. If caught in foul territory, the infield fly doesn't apply — but the catch still retires the batter.",anim:"catch"},
    {id:"rl33", conceptTag:"appeal-play",title:"Checked Swing — Who Makes the Call?",diff:1,cat:"rules",ageMin:6,ageMax:99,
      description:"The batter starts to swing and tries to hold back. The home plate umpire calls it a ball. The catcher thinks it was a swing. What happens next?",
      situation:{inning:"Top 3",outs:1,count:"2-2",runners:[],score:[1,1]},
      options:["Ask the home plate umpire to check with the base umpire for a second opinion","Play is final — the home plate umpire's call cannot be changed","Let the batter decide if he swung or not","A challenge from the pitching coach can overturn the call"],
      best:0,explanations:["On a checked swing, ONLY the defensive team (catcher, pitcher, or manager) can request the home plate umpire to appeal to a base umpire for a second opinion. The key is that the appeal goes to the first base umpire for a right-handed batter or the third base umpire for a lefty, because those umpires have the best angle to judge whether the bat crossed the front of the plate.","The home plate umpire's initial call CAN be overturned on a checked swing, because the appeal to the base umpire is a built-in second opinion. However, only the defensive team can request this appeal — the batter and his team cannot ask for a check, since the rule exists specifically to give the defense recourse when they believe a swing occurred.","The batter never decides whether he swung, because that's always the umpire's judgment call. If you think about it, letting the batter decide would create an obvious conflict of interest — no batter would ever admit to swinging on a pitch outside the zone.","Managers can't challenge checked swing calls with replay review, because you checked swings are specifically excluded from the replay system. The only recourse is the immediate appeal to the base umpire, which means the catcher must ask right away — otherwise the moment passes and the original call stands."],
      rates:[85,20,15,25],concept:"On a checked swing, the defense can appeal to the base umpire for a second opinion — the first or third base umpire makes the final call",explSimple:["Great choice! The catcher can ask the umpire to check with the base umpire for a second opinion.","Not the best move. The home plate umpire's call CAN be overturned on a checked swing.","Not the best move. The batter never decides whether he swung — the umpire makes that call.","Not the best move. Managers can't use replay review for checked swing calls."],anim:"strike"},
    {id:"rl34", conceptTag:"obstruction-interference",title:"Hit by Pitch — But It Was a Strike?",diff:2,cat:"rules",ageMin:9,ageMax:99,
      description:"The pitch comes in as a curveball that breaks into the batter's hands. He doesn't move and the ball hits him. But the pitch was clearly in the strike zone. Does the batter get first base?",
      situation:{inning:"Bot 4",outs:0,count:"1-1",runners:[],score:[2,2]},
      options:["No — if the pitch is in the strike zone, it's a strike even if it hits the batter","Yes — any pitch that hits the batter awards first base, no matter what","The umpire decides based on whether the batter tried to avoid the pitch","It depends on what the count was before the pitch"],
      best:0,explanations:["Correct! Under MLB Rule 5.05(b)(2), if the pitch is in the strike zone when it hits the batter, it's called a strike — not a hit by pitch, since the batter does NOT get first base. This surprises a lot of people, but the strike zone takes priority.","Not all hit-by-pitches award first base, because if the pitch was in the strike zone, it's a strike. The location of the pitch matters more than the fact that it hit the batter.","The 'attempt to avoid' rule is separate from the strike zone rule — even if the batter tries to avoid it, a pitch in the strike zone when it hits the batter is a strike, not a HBP.","The count doesn't change the rule, which means a pitch in the strike zone is a strike regardless of the count, even if it hits the batter."],
      rates:[85,25,30,15],concept:"A pitch in the strike zone is a strike even if it hits the batter — the strike zone takes priority over hit-by-pitch rules",explSimple:["Under MLB Rule 5.05(b)(2), if the pitch is in the strike zone when it hits the batter, it's called a strike — not a hit by pitch.","Not all hit-by-pitches award first base.","The 'attempt to avoid' rule is separate from the strike zone rule.","The count doesn't change the rule."],anim:"strike"},
    {id:"rl35", conceptTag:"force-vs-tag",title:"Force Play Removal — Tricky Situation",diff:2,cat:"rules",ageMin:9,ageMax:99,
      description:"Bases loaded, 1 out. Ground ball to the shortstop. He steps on second base to force out the runner from first. Now the shortstop fires to the catcher at home for what he thinks is the second force out. Is the play at home a force or a tag?",
      situation:{inning:"Top 5",outs:1,count:"0-1",runners:[1,2,3],score:[3,2]},
      options:["It's still a force at home — all runners were forced to advance on the ground ball","It's now a tag play — the force at home was removed when the runner behind was put out at second","The catcher can choose to either tag the runner or touch the plate","It's a force play because the bases were loaded"],
      best:1,explanations:["This is one of the trickiest plays in baseball. When the shortstop forced out the runner at second base, the runner going from second to third is no longer forced to advance — because the runner behind him (the one who was on first) is now out. Since the runner going to third isn't forced, the runner going home isn't forced either. The force was removed at every base ahead of the out.","Exactly right! Force removal is one of the most misunderstood rules in baseball, because the out at second removes the force at third, which removes the force at home. The catcher must now TAG the runner sliding into home — just touching the plate is not enough.","The catcher cannot choose, since once the force is removed, it's a tag play only. The catcher must tag the runner with the ball before the runner touches home plate.","Bases loaded creates a force initially, but any out behind a runner removes the force ahead, because the force at home was removed the moment the shortstop recorded the force out at second."],
      rates:[25,85,20,30],concept:"When a trailing runner is forced out, the force is removed for all runners ahead — subsequent plays become tag plays, not force plays",explSimple:["This is one of the trickiest plays in baseball.","Force removal is one of the most misunderstood rules in baseball.","The catcher cannot choose.","Bases loaded creates a force initially, but any out behind a runner removes the force ahead."],anim:"throwHome"},
    {id:"rl36", conceptTag:"force-vs-tag",title:"Dead Ball — When Does Play Stop?",diff:2,cat:"rules",ageMin:9,ageMax:99,
      description:"Runner on first, 1 out. The pitch hits the batter. The runner on first starts running to second during the confusion. Does the runner get to advance?",
      situation:{inning:"Top 2",outs:1,count:"1-0",runners:[1],score:[0,0]},
      options:["No — hit by pitch is a dead ball, so the runner must go back to first","The runner on first advances to second because he was forced by the batter going to first","Yes — smart baserunning, the runner gets second for free","It depends on whether the runner was already running when the pitch was thrown"],
      best:1,explanations:["The ball IS dead on a hit-by-pitch, but runners who are forced to advance still get to move up one base. Since the batter gets first base, the runner on first is forced to second.","Hit by pitch is a dead ball, meaning runners can only advance if they're forced. The batter goes to first, which forces the runner on first to move to second. But the runner on first can only go to second — he can't take third just because he was already running.","Smart baserunning doesn't apply here. On a dead ball, you can't take extra bases just because you were moving. Only forced advances are allowed.","Whether the runner was already in motion doesn't matter on a dead ball. The rule is simple: runners advance one base only if they're forced by the batter being awarded first base."],
      rates:[30,85,20,25],concept:"On a dead ball like hit-by-pitch, runners can only advance if forced — no extra bases on hustle during a dead ball",explSimple:["The ball IS dead on a hit-by-pitch, but runners who are forced to advance still get to move up one base.","Hit by pitch is a dead ball, meaning runners can only advance if they're forced.","Smart baserunning doesn't apply here.","Whether the runner was already in motion doesn't matter on a dead ball."],anim:"walk"},
    {id:"rl37", conceptTag:"tag-up",title:"Runner Leaves Early on Tag-Up",diff:1,cat:"rules",ageMin:6,ageMax:99,
      description:"Runner on third, 1 out. Deep fly ball to center field. The runner on third leaves the base before the catch is made and jogs home. The center fielder catches the ball. What happens?",
      situation:{inning:"Bot 6",outs:1,count:"1-1",runners:[3],score:[2,3]},
      options:["Run counts — the runner was already past home plate when the catch was made","The defense can appeal by throwing to third base — if the runner left early, he's out","Automatic out — the umpire saw him leave early","He can go back and re-tag third base to make it legal"],
      best:1,explanations:["The run does NOT automatically count — if the runner left third base before the catch was made, the defense can appeal by throwing the ball to third base (with a fielder touching the bag). If the umpire confirms the runner left early, the runner is out on the appeal.","Leaving early on a tag-up is NOT an automatic out, since the defense must appeal the play by throwing to the base the runner left from. If they don't appeal, the run counts, which is why coaches yell 'Tag up!' to remind runners to wait for the catch.","Umpires don't call leaving early on their own, which means the defense must appeal by throwing to the base. If nobody on the defense notices, the run counts even if the runner did leave early.","Once the runner has scored, he cannot go back and re-tag, because the play is over for the runner once he crosses home plate. The defense's only option is to appeal at third base."],
      rates:[20,85,25,30],concept:"On a tag-up, the defense must appeal if a runner leaves early — it's not an automatic out, and the run counts if nobody appeals",explSimple:["Not the best move. The run does NOT automatically count if the runner left early.","Great choice! The defense can appeal by throwing to third base to check if the runner left early.","Not the best move. Umpires don't call this on their own — the defense has to ask for it.","Not the best move. Once the runner has scored, he can't go back and re-tag."],anim:"score"},
    {id:"rl38", conceptTag:"obstruction-interference",title:"Runner Interference on a Double Play",diff:3,cat:"rules",ageMin:12,ageMax:99,
      description:"Runner on first, nobody out. Ground ball to short. The shortstop fires to second for the force out. As the second baseman tries to complete the double play throw to first, the runner from first slides wide into the second baseman's legs, clearly out of the base path. What's the call?",
      situation:{inning:"Top 4",outs:0,count:"0-0",runners:[1],score:[1,1]},
      options:["Just the out at second — the runner is out and the throw to first was disrupted","Both runners are out — the sliding runner AND the batter-runner at first","Only the runner at second is out — the batter-runner is safe at first","The play stands as-is — hard slides are part of the game"],
      best:1,explanations:["Under Rule 6.01(j), if a runner intentionally interferes with a fielder's attempt to complete a double play by sliding out of the base path, both the runner AND the batter-runner are called out, since this is the slide rule — designed to protect middle infielders from dangerous takeout slides.","Correct! The slide rule (sometimes called the Utley Rule after Chase Utley's 2015 NLDS slide) requires runners to make a bona fide slide. Going out of the base path to take out the fielder results in a double play being called: the sliding runner is out for interference, and the batter-runner is also out.","The interference penalty is specifically designed to give the defense the double play they would have gotten without the illegal slide, because both outs are called.","Hard slides within the base path are legal, since but sliding OUTSIDE the base path to interfere with the throw is illegal interference under the slide rule. The rule distinguishes between a competitive play and a dangerous one."],
      rates:[25,85,20,15],concept:"The slide rule: runners must make a bona fide slide at second base — going out of the base path to disrupt a double play results in two outs",anim:"doubleplay"},
    {id:"rl39", conceptTag:"double-play-turn",title:"Neighborhood Play at Second Base",diff:3,cat:"rules",ageMin:12,ageMax:99,
      description:"You're watching a close play. Runner on first, 1 out. Ground ball to the shortstop. The second baseman receives the throw near second base, transfers quickly, and throws to first for the double play. On replay, his foot was about 6 inches off the bag when he caught the ball. Is the force out at second valid?",
      situation:{inning:"Top 5",outs:1,count:"0-1",runners:[1],score:[2,1]},
      options:["The out stands — the neighborhood play allows the fielder to be close to the bag on double play turns","The runner is safe — the fielder must touch the base for a force out, period","It depends on whether the runner slid into the fielder","The umpire on the field makes the final call — replay can't overturn it"],
      best:0,explanations:["The neighborhood play has evolved with replay review. Before 2016, umpires never overturned these plays. After the Bona Fide Slide Rule was added, replay reviews double play turns but applies a looser standard — if the fielder was 'in the vicinity' of the bag while protecting himself from a sliding runner, the out stands. This protects middle infielders from dangerous collisions.","While touching the bag is required for a normal force out, double play turns at second base get special treatment. The middle infielder has to catch, transfer, and throw while a runner barrels toward his legs — demanding pinpoint foot placement creates a serious safety hazard. And that's why the rules allow being slightly off the bag — otherwise middle infielders would get hurt on routine plays.","The runner's slide matters for a different rule — the Bona Fide Slide Rule, which prevents takeout slides. The neighborhood play is about the fielder's proximity to the bag during the transfer and throw, which means even a perfectly clean slide doesn't change whether the fielder was close enough to the bag for the out to count.","Replay absolutely can review force plays at second, but the review standard is different from other bases. At first base, your foot must touch the bag. At second on a double play turn, being 'in the vicinity' counts because the game prioritizes player safety over pinpoint accuracy."],
      rates:[85,40,25,20],concept:"The neighborhood play allows second basemen to be slightly off the bag during double play turns — protecting the fielder from sliding runners",anim:"doubleplay"},
    {id:"rl40", conceptTag:"scoring-probability",title:"Ghost Runner — Extra Innings Rule",diff:3,cat:"rules",ageMin:12,ageMax:99,
      description:"It's the 10th inning in a regular season MLB game. Under the automatic runner rule, who starts on second base, and what are the strategic implications?",
      situation:{inning:"Top 10",outs:0,count:"0-0",runners:[2],score:[3,3]},
      options:["The player who made the last out of the previous inning starts on 2nd — bunt him to third and try to score on a sac fly or groundout","Any player the manager chooses starts on 2nd — pick your fastest runner","The leadoff hitter of the inning starts on 2nd — the lineup determines everything","Nobody starts on 2nd — the ghost runner rule was eliminated after 2021"],
      best:0,explanations:["Under the automatic runner rule (introduced in 2020 and made permanent), the player who made the last out of the previous inning is placed on second base at the start of each half-inning in extras. The standard strategy is to sacrifice bunt the runner to third — an aggressive play where the tradeoff in run expectancy is worth it because you only need one run — then try to score on a sacrifice fly, groundout, or base hit. With nobody out and a runner on second, the run expectancy is over 1.1 runs.","The manager does NOT get to choose the runner — it's automatic, which means it's automatically the player who made the last out of the previous inning. The only strategic element is the hitting lineup and whether to bunt.","The last out of the previous inning, not the leadoff hitter, determines who starts on second. This means managers sometimes think about the end of the previous inning's batting order when deciding strategy.","The automatic runner rule is still in effect for regular season games, because it was made permanent for MLB regular season games. It does NOT apply in the postseason, where traditional extra-inning rules still apply."],
      rates:[85,20,25,15],concept:"The automatic runner rule places the last out of the previous inning on second base in extras — bunt to third, then try to score with a sac fly",anim:"advance"},
  ],
  counts: [
    {id:"cn1", conceptTag:"first-pitch-value",title:"0-0: First Pitch Approach (Batter)",diff:1,cat:"counts",ageMin:6,ageMax:99,
      description:"You're the batter. Count is 0-0. The pitcher has been throwing first-pitch fastballs all game. What's your approach?",
      situation:{inning:"Bot 3",outs:0,count:"0-0",runners:[],score:[1,1]},
      options:["Sit on the fastball and swing aggressively","Take the first pitch no matter what","Bunt for a surprise hit","Choke up and just make contact"],
      best:0,explanations:["MLB hitters bat .340 on first pitches they swing at. If you've noticed the pitcher throws first-pitch fastballs, you know exactly what's coming — that's a huge edge! Sitting on a specific pitch and being ready to swing hard gives you the best chance for a solid hit.","Taking every first pitch sounds patient, but it wastes a golden opportunity, since when you know the pitcher's pattern, taking the pitch just puts you behind 0-1 with no advantage. Good hitters attack when they have information.","Bunting when you know a fastball is coming trades a chance for a big hit for a small, low-percentage play, because your bat speed plus a predictable fastball is a recipe for extra bases — don't settle for a bunt.","Choking up and just making contact is a defensive approach, but this is an offensive opportunity — when you know the pitch type and location, use a full swing to drive the ball. Weak contact wastes the biggest advantage a hitter can have: knowing what's coming."],
      rates:[85,35,20,40],concept:"Hitting 0-0: if you know what's coming, be aggressive — hitters bat .340 on first pitches",explSimple:["Great choice! MLB hitters bat .340 on first pitches they swing at.","Not the best move. Always taking first pitches makes you predictable and puts you behind.","Not the best move. Bunting on the first pitch wastes the advantage of knowing what's coming.","Not the best move. Just making contact wastes the advantage."], anim:"hit"},
    {id:"cn2", conceptTag:"two-strike-approach",title:"0-2: Pitcher's Count (Batter)",diff:2,cat:"counts",ageMin:9,ageMax:99,
      description:"You're behind 0-2. The pitcher has dominated this at-bat. What's your strategy?",
      situation:{inning:"Top 5",outs:1,count:"0-2",runners:[1],score:[2,3]},
      options:["Protect the plate — shorten your swing, fight off tough pitches","Swing for the fences — make him pay if he makes a mistake","Take the next pitch — he'll probably waste one","Bunt — surprise the defense"],
      best:0,explanations:["Down 0-2, your job is to survive. Shorten up, foul off borderline pitches, and wait for a mistake. MLB hitters bat only .167 on 0-2 counts, so play defense at the plate.","Swinging big on 0-2 leads to strikeouts. The pitcher has the advantage.","Good pitchers do not always waste on 0-2 — many go right after you, so stay ready for a strike.","A 0-2 bunt is desperation — just compete with a shortened swing and fight to stay alive."],
      rates:[85,15,40,20],concept:"Down 0-2, become a fighter — shorten your swing and protect the plate (.167 BA in 0-2)",explSimple:["Down 0-2, your job is to survive.","Swinging big on 0-2 leads to strikeouts.","Good pitchers don't always waste on 0-2 — many go right after you.","A 0-2 bunt is desperation."],anim:"strike"},
    {id:"cn3", conceptTag:"count-leverage",title:"3-1: Hitter's Count",diff:2,cat:"counts",ageMin:9,ageMax:99,
      description:"Count is 3-1, you're the batter. A ball four puts you on base. The pitcher needs a strike. What's your approach?",
      situation:{inning:"Bot 6",outs:1,count:"3-1",runners:[2],score:[3,4]},
      options:["Sit on your pitch and crush it — hitters bat .340 on 3-1","Take the pitch — get to a full count","Swing at anything close — you don't want to strike out","Protect — shorten up like you're behind in the count"],
      best:0,explanations:["3-1 is the best hitter's count in baseball! The pitcher MUST throw a strike or walk you, so he'll probably throw a fastball right in the zone. Pick one spot — like middle-in or middle-away — and if the ball goes there, crush it. MLB hitters bat .340+ on 3-1 because pitchers are so predictable in this count.","Taking on 3-1 gives away your biggest advantage, because sure, a walk puts you on base, but a full count (3-2) takes away your leverage and lets the pitcher throw anything. On 3-1, you're in control — use it before you lose it.","Swinging at 'anything close' is too broad. The power of 3-1 is selectivity — you know the pitcher has to come to you, so you can afford to wait for the EXACT pitch you want. Swinging at a slider off the plate defeats the whole purpose of having the count in your favor.","Shortening up and protecting is a 2-strike strategy, not a 3-1 strategy. When you're ahead in the count, you can take a full swing because even if you miss, you're only at 3-2 — still not struck out. Don't play defense when the count says to play offense."],
      rates:[85,35,30,20],concept:"3-1 is the hitter's best count (.340+ BA) — the pitcher must come to you, sit on your pitch",explSimple:["3-1 is the best hitter's count in baseball!","Why give away your best advantage?","Swinging at anything close isn't selective enough.","You don't need to protect on 3-1 — you have the leverage."],anim:"hit"},
    {id:"cn4", conceptTag:"count-leverage",title:"1-2: Pitcher's Strategy",diff:2,cat:"counts",ageMin:9,ageMax:99,
      description:"You're the pitcher. Count is 1-2 on a slugger. You're ahead — one more strike gets him. What do you throw?",
      situation:{inning:"Top 4",outs:0,count:"1-2",runners:[],score:[0,2]},
      options:["Fastball right down the middle — challenge him","Slider just off the plate — expand the zone","Changeup in the dirt — make him chase","Same pitch you just threw — repeat it"],
      best:1,explanations:["A fastball right down the middle on 1-2 is a gift to a slugger — you're giving him the pitch he wants most. When you're ahead in the count, the hitter is defensive and expanding his zone. A middle-middle fastball is the one pitch that snaps him back into power mode.","Expand the zone! On 1-2, the hitter is nervous about striking out, so he'll swing at pitches he'd normally take. A slider that starts in the zone but breaks off the plate looks like a strike out of your hand — by the time the hitter realizes it's a ball, he's already swinging. That's how you earn strikeouts with deception instead of brute force.","Throwing in the dirt on 1-2 might seem like a good chase pitch, but experienced hitters recognize balls that bounce before the plate. A pitch that starts NEAR the zone and breaks just off it is much harder to lay off because the hitter's brain says 'strike!' until it's too late.","Throwing the exact same pitch you just threw is predictable — the hitter just saw it and his brain is ready for that speed and location. Changing pitch type or location keeps the hitter off-balance because he has to process new information with each swing decision."],
      rates:[15,85,45,30],concept:"1-2 counts: expand the zone with chase pitches just off the plate — make the hitter swing at balls",explSimple:["Down the middle on 1-2 is a gift.","On 1-2, throw to spots where the hitter THINKS it's a strike but it's actually a ball.","In the dirt is too obvious — most hitters won't chase that far down on 1-2.","Repeating the same pitch is predictable."],anim:"strikeout"},
    {id:"cn5", conceptTag:"count-leverage",title:"2-0: Pitcher in Trouble",diff:2,cat:"counts",ageMin:9,ageMax:99,
      description:"You're the pitcher. Behind 2-0 to a good hitter. You need a strike. What's your play?",
      situation:{inning:"Bot 3",outs:1,count:"2-0",runners:[],score:[1,1]},
      options:["Fastball — your most command-able pitch for a strike","Breaking ball — surprise him","Nibble the corners — don't give him anything to hit","Changeup low — steal a strike"],
      best:0,explanations:["On 2-0, throw the pitch you can put in the strike zone most reliably — for almost every pitcher, that's the fastball. You need a strike to avoid falling to 3-0 because a 3-0 count gives the hitter all the leverage, and fastballs have the highest strike-throwing percentage of any pitch. Accuracy matters more than deception when you're behind in the count.","Breaking balls curve and dive, which means they're harder to control precisely. On 2-0, you can't afford a pitch that misses the zone — a 3-0 count turns the at-bat over to the hitter completely. Save your tricky stuff for when you're ahead.","Nibbling the corners means aiming for tiny targets, and at 2-0 you need to hit the zone, not just barely touch it. If you miss your corner by an inch, you're at 3-0 and the hitter is licking his chops for a fastball down the middle. Attack the fat part of the zone instead.","A changeup relies on fooling the hitter with speed change, but on 2-0, the hitter knows you need a strike and is sitting dead-red fastball. Since changeups tend to miss low, you risk falling to 3-0 in a virtual walk situation. Don't gamble when a reliable fastball gets the job done."],
      rates:[85,25,30,40],concept:"Behind 2-0, throw your best fastball for a strike — command beats trickery when you're behind",explSimple:["On 2-0, throw your best strike.","Breaking balls are harder to control.","Nibbling risks falling 3-0 which is even worse.","Changeup on 2-0 is risky — if it misses, you're 3-0."],anim:"strike"},
    {id:"cn6", conceptTag:"count-leverage",title:"Full Count: 3-2 with 2 Outs",diff:3,cat:"counts",ageMin:12,ageMax:99,
      description:"Full count 3-2, 2 outs, runner on 1st. You're the batter. The runner is going on the pitch. What's your approach?",
      situation:{inning:"Bot 7",outs:2,count:"3-2",runners:[1],score:[3,4]},
      options:["Swing at anything close — can't take strike 3","Be selective — wait for YOUR pitch in YOUR zone","Take the pitch — if it's a ball, you walk","Swing for extra bases to drive in the runner"],
      best:1,explanations:["Swinging at everything leads to weak contact on bad pitches.","Even on 3-2 with 2 outs, be selective within the zone — you don't need to swing at balls. LOOK for a pitch you can drive. The runner is going, so contact puts him in scoring position.","You can't just take on 3-2 — if it catches the corner, you're out looking.","Trying to do too much leads to overswinging, which means just find a good pitch and put a good swing on it."],
      rates:[30,85,25,35],concept:"Full count discipline: be aggressively selective — swing at strikes, lay off balls, even with 2 strikes",anim:"hit"},
    {id:"cn7",title:"First Pitch After a Walk (Pitcher)",diff:1,cat:"counts",conceptTag:"first-pitch-strike",ageMin:6,ageMax:99,
      description:"You just walked the previous batter. New batter up. What should your first pitch be?",
      situation:{inning:"Top 5",outs:0,count:"0-0",runners:[1],score:[2,2]},
      options:["A careful pitch on the corner — don't fall behind again","A first-pitch strike — get ahead immediately","A pitchout to check the runner","Whatever you're most comfortable with"],
      best:1,explanations:["Being too careful after a walk often leads to another walk — you need to attack the zone and trust your stuff.","After a walk, the most important thing is getting ahead on the new batter with a strike. Pitchers who throw first-pitch strikes after walks cut their walk rate dramatically.","A pitchout on 0-0 puts you behind immediately, and falling behind again is exactly what you are trying to avoid.","Comfort is secondary here — the game situation demands a strike, so throw your most reliable pitch for a strike."],
      rates:[35,85,15,40],concept:"After a walk, throw strike one immediately — getting ahead prevents walk snowballs",explSimple:["Not the best move. Being too careful after a walk often leads to another walk.","Great choice! After a walk, the most important thing is getting ahead on the new batter.","Not the best move. A pitchout on 0-0 puts you behind right away.","Not the best move. Comfort is secondary — the game situation demands a strike."], anim:"strike"},
    {id:"cn8", conceptTag:"pitch-sequencing",title:"2-2: Even Count Battle",diff:2,cat:"counts",ageMin:9,ageMax:99,
      description:"Count is 2-2. Both sides have fought hard this at-bat. You're the pitcher. What's your approach to get the strikeout?",
      situation:{inning:"Bot 8",outs:1,count:"2-2",runners:[2,3],score:[4,3]},
      options:["Your best pitch, best location — trust your stuff","Something he hasn't seen this at-bat","The same sequence that got you to 2-2","A fastball up to set up a breaking ball next pitch"],
      best:1,explanations:["Your best pitch is predictable if he has seen it multiple times this at-bat — he is already timing it.","Change the eye level and the look! On 2-2, show something different. If you've been throwing low, go up. If fastballs, throw off-speed. The element of surprise gets strikeouts.","Repeating sequences is predictable for good hitters — they pick up patterns fast and will be ready for what is coming next.","Setting up a next pitch works, but you might not GET a next pitch — this could be ball three, and now the count is against you."],
      rates:[40,85,30,35],concept:"On 2-2, change the hitter's eye level — show something he hasn't seen this at-bat",explSimple:["Your best pitch is predictable if he's seen it multiple times this at-bat.","Change the eye level and the look!","Repeating sequences is predictable for good hitters.","Setting up a next pitch works, but you might not GET a next pitch — this could be ball three."],anim:"strikeout"},

    {id:"cn9", conceptTag:"count-leverage",title:"3-0 Hitter's Count",diff:1,cat:"counts",ageMin:6,ageMax:99,
      description:"You're batting with a 3-0 count. The pitcher has missed badly with three straight pitches and is struggling with control. The bases are empty and it's the 4th inning of a close game. What's the smartest approach for this at bat?",
      situation:{inning:"Bot 4",outs:1,count:"3-0",runners:[],score:[2,3]},
      options:["Take the pitch — a 3-0 count is the best time to wait for ball four and a free walk","Swing at a fastball right down the middle if you get one, but take anything else","Swing at the first pitch you can reach — this pitcher can't throw strikes","Bunt for a base hit while the defense isn't expecting it"],
      best:0,explanations:["At 3-0, the pitcher is in deep trouble. Taking the pitch is usually the smartest play because you're one ball away from a free walk. Even if the pitcher throws a strike, you're still ahead 3-1 with the advantage. Let the struggling pitcher dig their own hole — patience wins in a 3-0 count.","Swinging 3-0 is sometimes okay for elite hitters who get the green light from their coach, but for most players, the best strategy is to take the pitch, because the odds of a walk are very high, and there's no reason to help a struggling pitcher by swinging.","Swinging at anything you can reach on 3-0 is reckless, since the whole point of a 3-0 count is that the pitcher can't find the zone. Let them keep missing! Swinging at a marginal pitch lets the pitcher off the hook.","Bunting on 3-0 makes zero sense, because you're about to get a free base via a walk. Why would you bunt and risk making an out when the pitcher can't throw strikes? Be patient and take your free base."],
      rates:[88,40,15,10],concept:"A 3-0 count is called a 'hitter's count' because the pitcher is in trouble. The smartest play is usually to take the pitch and get closer to a walk.",explSimple:["Great choice! At 3-0, the pitcher is in deep trouble.","Not the best move. Swinging 3-0 is sometimes okay for elite hitters who get the green light from their.","Not the best move. Swinging at anything you can reach on 3-0 is reckless.","Not the best move. Bunting on 3-0 makes zero sense."], anim:"walk"},
    {id:"cn10", conceptTag:"count-leverage",title:"Behind 0-1",diff:2,cat:"counts",ageMin:9,ageMax:99,
      description:"The pitcher threw a first-pitch strike and now you're behind 0-1. The pitcher has a good fastball and a sharp breaking ball. You're a contact hitter who doesn't strike out much. How do you adjust your approach now that you're behind in the count?",
      situation:{inning:"Top 5",outs:0,count:"0-1",runners:[1],score:[1,1]},
      options:["Shorten your swing and look to make contact — protect the zone","Keep swinging the same way — one strike doesn't change anything","Guess breaking ball and sit on it exclusively","Look for a pitch you can pull for extra bases to make up for falling behind"],
      best:0,explanations:["Smart adjustment! At 0-1, the pitcher has the slight advantage and might throw something tricky. Shortening your swing and focusing on making contact keeps you in the at bat. You don't need to do anything special — just put the bat on the ball and avoid falling further behind to 0-2.","Actually, one strike changes a lot, since at 0-1, the pitcher can afford to throw a waste pitch or expand the zone. You need to adjust by being more selective on pitches outside the zone while still protecting against strikes. Approach should always adapt to the count.","Guessing one pitch exclusively at 0-1 is risky. If you guess wrong, you could fall to 0-2 and be in real trouble. At 0-1, stay balanced and ready for any pitch in the zone. Guessing games are for deeper counts.","Trying to pull everything for power when behind in the count leads to weak grounders and strikeouts. Contact hitters succeed by using the whole field. Stay within your game — don't try to be a power hitter because of one strike."],
      rates:[90,40,25,15],concept:"When you fall behind 0-1, shorten your swing and focus on contact. Protect the zone and stay alive in the at bat.",explSimple:["At 0-1, the pitcher has the slight advantage and might throw something tricky.","Actually, one strike changes a lot.","Guessing one pitch exclusively at 0-1 is risky.","Trying to pull everything for power when behind in the count leads to weak grounders and strikeouts."],anim:"hit"},
    {id:"cn11", conceptTag:"count-leverage",title:"1-2 Two Outs Rally",diff:3,cat:"counts",ageMin:12,ageMax:99,
      description:"Two outs, runners on second and third. Your team is down by one run in the 7th inning. The count is 1-2 — the pitcher sits one strike away from ending the inning. He's been mixing fastballs and sliders all game. You need to keep this rally alive.",
      situation:{inning:"Bot 7",outs:2,count:"1-2",runners:[2,3],score:[3,4]},
      options:["Choke up on the bat, shorten your swing, and fight off anything close — foul off tough pitches until you get something to hit","Sit on fastball and take a big cut — go for the game-tying hit","Take the next pitch hoping it's a ball to even the count at 2-2","Swing at anything near the zone — you can't afford to take strike three looking"],
      best:0,explanations:["This is elite hitting mentality! At 1-2 with the game on the line, the priority is survival. Choke up, shorten your swing, and battle. Foul off tough pitches to stay alive. Great hitters turn 1-2 counts into 3-2 counts all the time by fighting off pitches. Eventually the pitcher might make a mistake you can drive.","Taking a big hack at 1-2 with two outs is how you end up walking back to the dugout. The pitcher has the advantage and might throw something nasty. A big swing has more holes in it. Shorten up and battle.","Taking a pitch at 1-2 is extremely risky, which means if it catches the corner, you're out looking — and taking a called third strike with runners on feels terrible. Be ready to swing at anything close and protect the plate.","While you need to protect the zone, swinging at 'anything near the zone' leads to chasing bad pitches, because there's a difference between protecting the plate with a short swing and flailing at everything. Stay disciplined but aggressive."],
      rates:[88,20,15,30],concept:"In a 1-2 count with the game on the line, choke up and battle. Foul off tough pitches and wait for your opportunity — never give in to the pitcher.",anim:"hit"},
    {id:"cn12", conceptTag:"first-pitch-value",title:"First Pitch Fastball",diff:1,cat:"counts",ageMin:6,ageMax:99,
      description:"You step into the batter's box for your first at bat. This pitcher fires a first-pitch fastball to almost every batter — you noticed while watching from the dugout. The pitcher winds up and here comes the first pitch. It's a fastball right down the middle!",
      situation:{inning:"Bot 1",outs:0,count:"0-0",runners:[],score:[0,0]},
      options:["Swing! If you know a first-pitch fastball is coming, be ready to attack it","Take it for a strike to see the pitcher's speed and get comfortable","Bunt it — surprise the defense on the very first pitch","Foul it off on purpose to see more pitches"],
      best:0,explanations:["Yes! If you've done your homework and know the pitcher likes to throw first-pitch fastballs, being ready to attack it is a huge advantage. The first pitch is often the best pitch you'll see in an at bat because the pitcher is trying to get ahead. A fastball down the middle on the first pitch is a gift — don't let it go!","Seeing a pitch to get comfortable sounds smart, but you just gave up a meatball down the middle. Sometimes the first pitch IS the best pitch. If you know it's coming, attack it! You don't get that pitch back.","Bunting a pitch right down the middle that you knew was coming wastes a great opportunity, since you could have driven it for extra bases. Bunting has its place, but not when you're ambushing a predictable fastball.","Fouling off a pitch on purpose is a waste of a hittable pitch, because that fastball down the middle might be the best pitch you see all at bat. Don't play games — when you get your pitch, swing at it!"],
      rates:[90,40,25,15],concept:"Do your homework! Watch the pitcher from the dugout. If you know a first-pitch fastball is coming, be aggressive and ready to attack.",explSimple:["Yes! If you've done your homework and know the pitcher likes to throw first-pitch fastballs,.","Not the best move. Seeing a pitch to get comfortable sounds smart, but you just gave up.","Not the best move. Bunting a pitch right down the middle that you knew was coming wastes a great opportunity.","Not the best move. Fouling off a pitch on purpose is a waste of a hittable pitch."], anim:"hit"},
    {id:"cn13", conceptTag:"count-leverage",title:"2-0 Sitting Fastball",diff:2,cat:"counts",ageMin:9,ageMax:99,
      description:"You're at the plate and the count is 2-0 after two balls off the plate. A strike here avoids falling behind 3-0. You're a good hitter having a great game. Your coach gave you the green light to swing. Statistics show pitchers throw fastballs about 70% of the time on 2-0 counts.",
      situation:{inning:"Bot 6",outs:1,count:"2-0",runners:[2],score:[2,2]},
      options:["Look for a fastball in your favorite zone — if you get it, drive it hard","Swing at any strike — you need to be aggressive on 2-0","Take the pitch to try to get to 3-0 and a guaranteed fastball","Look for the breaking ball since the pitcher might try to trick you"],
      best:0,explanations:["Perfect approach! At 2-0, you can be selective AND aggressive. Pick one zone (like middle-in or middle-out) and one pitch (fastball). If you get exactly what you're looking for, swing hard. If not, take it — you're still ahead in the count. This is how smart hitters do damage on 2-0 counts.","Being aggressive is right, but swinging at ANY strike is too loose. At 2-0, you have the luxury of being picky. You don't have to swing at a borderline strike or a pitch in a tough location. Be aggressive only on YOUR pitch.","While taking to 3-0 isn't terrible, you're giving up one of the best hitting counts in baseball. Pitchers throw fastballs 70% of the time at 2-0 because they need a strike. That's a perfect time to sit on one and punish it.","At 2-0, pitchers overwhelmingly throw fastballs because they need to get back in the count. Looking breaking ball on a 2-0 count is overthinking it. Play the percentages — sit fastball and react."],
      rates:[85,45,30,15],concept:"A 2-0 count is a great opportunity. Look for a fastball in YOUR zone — if you get it, swing hard. If not, you're still ahead in the count.",explSimple:["At 2-0, you can be selective AND aggressive.","Being aggressive is right, but swinging at ANY strike is too loose.","While taking to 3-0 isn't terrible, you're giving up one of the best hitting counts in baseball.","At 2-0, pitchers overwhelmingly throw fastballs because they need to get back in the count."],anim:"hit"},
    {id:"cn14", conceptTag:"count-leverage",title:"Full Count Two Outs",diff:2,cat:"counts",ageMin:9,ageMax:99,
      description:"Full count, 3-2, with two outs. The runners are going on the pitch because any walk or hit puts them in motion. You're at the plate against a tired reliever in the 8th inning. Your team trails by two runs with runners on first and second.",
      situation:{inning:"Bot 8",outs:2,count:"3-2",runners:[1,2],score:[3,5]},
      options:["Protect the plate — fight off anything close and don't go down looking","Sit on one specific pitch and take a huge swing at it","Take the pitch hoping for ball four","Close your eyes and swing as hard as you can"],
      best:0,explanations:["On a 3-2 count with two outs, the worst thing you can do is take a called strike three. Expand your zone slightly, shorten your swing, and fight off borderline pitches. The runners are moving, so even a single could score both runs. Just put the ball in play and let good things happen.","Sitting on one specific pitch in a 3-2 two-out count is too risky. If you guess wrong, the pitch might catch the corner and you're out looking. You need to be ready for anything in the zone and protect the plate.","Taking a 3-2 pitch hoping for ball four is extremely risky with two outs, since if it catches the corner, you struck out looking with runners on and your team needed you. You can't leave the bat on your shoulder here — protect the plate!","Closing your eyes and swinging is not a strategy — it's giving up, which means keep your eyes on the ball, look for something in the zone, shorten your swing, and compete. Seeing the ball is literally the most important part of hitting."],
      rates:[90,40,25,15],concept:"On a full count with two outs, protect the plate! Shorten your swing and don't go down looking. Put the ball in play and make the defense work.",explSimple:["On a 3-2 count with two outs, the worst thing you can do is take a called strike three.","Sitting on one specific pitch in a 3-2 two-out count is too risky.","Taking a 3-2 pitch hoping for ball four is extremely risky with two outs.","Closing your eyes and swinging is not a strategy — it's giving up."],anim:"hit"},
    {id:"cn15", conceptTag:"two-strike-approach",title:"0-2 Waste Pitch",diff:2,cat:"counts",ageMin:9,ageMax:99,
      description:"You're pitching with an 0-2 count on the batter. You've got him in a deep hole with two quick strikes. Your catcher puts down the sign. What's the best strategy when you're ahead 0-2?",
      situation:{inning:"Top 3",outs:1,count:"0-2",runners:[],score:[1,3]},
      options:["Throw a pitch just outside the zone — tempt the batter to chase a bad pitch","Fire your best fastball right down the middle to put him away","Buzz one at his feet to intimidate him, then come back with a strike","Throw the same pitch that got strike two — it worked once, it'll work again"],
      best:0,explanations:["This is called a 'waste pitch' and it's one of pitching's smartest strategies. At 0-2, you can afford to throw a ball. Throw something that LOOKS like a strike but breaks off the plate — a slider down and away, a fastball up and in, or a curve in the dirt. If the batter chases, great. If not, you're at 1-2 and still in command.","Grooving a fastball right down the middle on 0-2 is a gift to the hitter, because you have the count in your favor — there's no reason to throw a pitch right over the heart of the plate. Make the batter earn it by expanding the zone.","Throwing at a batter is dangerous and unsportsmanlike, since you could hurt someone, get ejected, or start a conflict. There are much smarter ways to use an 0-2 count than trying to intimidate with inside pitches at the feet.","Repeating the same pitch that worked for strike two is predictable, because good hitters adjust and are now looking for that pitch. Change speeds, change locations, keep the batter guessing. Pitching is about deception."],
      rates:[90,25,15,40],concept:"At 0-2, use a 'waste pitch' just off the plate. You can afford a ball, and if the batter chases, you get an easy out. Expand the zone!",explSimple:["This is called a 'waste pitch' and it's one of pitching's smartest strategies.","Grooving a fastball right down the middle on 0-2 is a gift to the hitter.","Throwing at a batter is dangerous and unsportsmanlike.","Repeating the same pitch that worked for strike two is predictable."],anim:"strike"},
    {id:"cn16",title:"3-1 Green Light",diff:2,cat:"counts",conceptTag:"count-leverage",ageMin:9,ageMax:99,
      description:"You're at the plate. The count is 3-1 and your coach flashes you the green light — you're allowed to swing. The pitcher absolutely needs to throw a strike here or walk you. There's a runner on second with one out and your team is tied in the 6th inning. A hit here could put your team ahead.",
      situation:{inning:"Bot 6",outs:1,count:"3-1",runners:[2],score:[4,4]},
      options:["Look fastball and drive it — the pitcher needs to throw a strike, so sit on your pitch","Swing at any pitch in the zone — you got the green light so use it","Take the pitch anyway and try to draw the walk at 3-1","Swing at the first pitch no matter what — show the pitcher you're aggressive"],
      best:0,explanations:["Smart hitting! At 3-1, the pitcher is almost certainly throwing a fastball because they need a strike. Look for a fastball in your power zone. If you get it, attack it and drive in that runner from second. If it's not your pitch, let it go — even if it's a strike, you're at 3-2 and still alive.","Having the green light doesn't mean swing at everything. It means you have PERMISSION to swing if you get your pitch. A green light with bad discipline is worse than no green light at all. Stay selective — look for a pitch you can drive.","Your coach gave you the green light because they trust your bat. Taking the pitch here goes against the coach's strategy. The 3-1 count is one of the best hitting counts in baseball — use the opportunity!","Swinging at anything regardless of location is reckless. 'Show the pitcher you're aggressive' isn't a strategy. The green light means swing at hittable pitches, not that you should hack at everything blindly."],
      rates:[85,40,30,15],concept:"A 3-1 green light means look for YOUR pitch and attack it. The pitcher needs a strike, so the fastball is coming — be ready!",explSimple:["At 3-1, the pitcher is almost certainly throwing a fastball because they need a strike.","Having the green light doesn't mean swing at everything.","Your coach gave you the green light because they trust your bat.","Swinging at anything regardless of location is reckless."],anim:"hit"},
    {id:"cn17", conceptTag:"count-leverage",title:"1-1 Neutral Count",diff:1,cat:"counts",ageMin:6,ageMax:99,
      description:"The count is 1-1 — perfectly even. One ball, one strike. Neither the pitcher nor the batter has an advantage. Any pitch could come next here: fastball, curve, changeup, slider. You need to be ready. What's the best mindset at a 1-1 count?",
      situation:{inning:"Top 2",outs:0,count:"1-1",runners:[],score:[0,0]},
      options:["Look fastball but be ready to adjust — stay balanced and aggressive on hittable pitches","Sit on an off-speed pitch since the pitcher got a strike and might try to trick you now","Take the next pitch no matter what to get ahead 2-1","Guess what's coming and commit to one specific pitch location"],
      best:0,explanations:["At 1-1, the best approach is to look fastball and react to off-speed. Since you're even in the count, you want to be ready for the most common pitch (fastball) while staying flexible. If you get a hittable pitch, attack it. If it's a ball, you go to 2-1 and have the advantage.","Sitting on an off-speed pitch at 1-1 is risky because pitchers throw fastballs more often than anything else. If a fastball comes and you're looking breaking ball, you'll be late and miss a hittable pitch. Look hard (fastball) and adjust soft (off-speed).","Taking a pitch at 1-1 just to get to 2-1 means you might watch a meatball go by — if the pitcher throws a fastball right down the middle, you want to be swinging! Don't give away strikes — be ready to hit.","At 1-1, guessing one exact pitch and location is a coin flip, which means the pitcher has too many options for you to narrow it down to one spot. Stay balanced, look fastball, and let your hands react to what you see."],
      rates:[90,40,25,15],concept:"At 1-1, stay balanced: look fastball and adjust to off-speed. Be ready to swing at hittable pitches but don't chase out of the zone.",explSimple:["Great choice! At 1-1, the best approach is to look fastball and react to off-speed.","Not the best move. Sitting on an off-speed pitch at 1-1 is risky because pitchers throw fastballs more.","Not the best move. Taking a pitch at 1-1 just to get to 2-1 means you might watch.","Not the best move. At 1-1, guessing one exact pitch and location is a coin flip."], anim:"hit"},
    {id:"cn18", conceptTag:"two-strike-approach",title:"3-2 Protect the Plate",diff:3,cat:"counts",ageMin:12,ageMax:99,
      description:"Full count, 3-2, with two outs in the bottom of the 9th. Your team is down by one with runners on first and third. The pitcher has been throwing a devastating slider all game that dives off the plate at the last second. You've already fouled off three tough pitches. The pitcher winds up for the payoff pitch.",
      situation:{inning:"Bot 9",outs:2,count:"3-2",runners:[1,3],score:[4,5]},
      options:["Widen your zone slightly — anything close to the plate, fight it off. Don't get caught looking.","Sit on the slider since that's his best pitch and he'll want to finish you with it","Take the pitch — if it's the slider it will probably be a ball and you walk","Swing as hard as possible — if you connect, you win the game"],
      best:0,explanations:["This is championship-level plate discipline! In a 3-2 count with two outs and the game on the line, you CANNOT take a called strike three. Widen your zone slightly and fight off anything close. Foul off tough pitches, put hittable ones in play, and refuse to go down without swinging. The runners are moving — even a broken-bat single could win it.","Sitting on the slider is too narrow, because what if he comes with a fastball on the corner? You'll watch strike three go by. At 3-2 with the game on the line, you have to be ready for everything, not just one pitch.","Taking a 3-2 pitch in this situation could win you a walk — or end the game on a called strike three, since with your team's season on the line, you absolutely cannot leave the bat on your shoulder. If it's close, you have to swing.","Maximum effort swings have maximum holes, because a big, wild swing is more likely to miss than a controlled, shortened swing. In this spot, contact is king. Shorten up, stay inside the ball, and put it in play. Heroes make contact."],
      rates:[88,25,15,20],concept:"In a 3-2 count with the game on the line, widen your zone and battle. Don't let the umpire end your season — fight off every borderline pitch.",anim:"hit"},
    {id:"cn19",conceptTag:"count-leverage",title:"0-2 With Runners in Scoring Position (Pitcher)",diff:1,cat:"counts",ageMin:8,ageMax:99,
      description:"You're pitching with an 0-2 count and runners on second and third. The batter looked helpless on the first two strikes. You feel dominant. Your catcher puts down the sign for a fastball right down the middle.",
      situation:{inning:"Top 5",outs:1,count:"0-2",runners:[2,3],score:[3,1]},
      options:["Throw the fastball down the middle like your catcher called","Shake off and throw a waste pitch out of the zone to see if he chases","Throw your best off-speed pitch just off the corner — tempt him to chase","Throw behind the batter to push him off the plate"],
      best:2,explanations:["Never groove a pitch at 0-2! Even a struggling batter can crush a middle-middle fastball — you have two strikes to work with — use that advantage to expand the zone, not throw it down Broadway.","A pure waste pitch has value, but the best approach at 0-2 is to throw something that looks like a strike but finishes off the plate, which means a waste pitch that's obviously a ball doesn't advance the at-bat. Make him chase something tempting instead.","Perfect 0-2 approach! Throw your best secondary pitch just off the corner, because it looks hittable out of the hand but finishes off the plate. If he chases, you get the strikeout. If he takes, you're still ahead 1-2. Never give in at 0-2 with the count in your favor.","Throwing behind a batter is dangerous and unsportsmanlike, since it could hit him and put another runner on base. At 0-2, you have total control of the at-bat — use that advantage with smart pitch placement, not intimidation."],
      rates:[12,40,90,5],concept:"At 0-2, you own the at-bat. Don't give it back with a hittable pitch. Throw something that looks like a strike but isn't — tempt the chase.",anim:"strikeout",
      explSimple:["Don't throw it right over the plate when you already have two strikes — that's too easy to hit!","Throwing a pitch that's obviously a ball doesn't really help. Try to make the batter swing at something tricky.","Great idea! Throw a pitch that looks good but moves away from the plate. If the batter swings, you get a strikeout!","Never throw at a batter on purpose. That's not safe and could put a runner on base."]},
    {id:"cn20",conceptTag:"count-leverage",title:"3-2 Count — Trust Your Pitch",diff:2,cat:"counts",ageMin:10,ageMax:99,
      description:"You're pitching with a 3-2 count, two outs, and a runner on second. First base is open. The batter at the plate is their best hitter. Your catcher sets up on the outside corner for a fastball.",
      situation:{inning:"Top 6",outs:2,count:"3-2",runners:[2],score:[2,2]},
      options:["Throw the fastball on the corner — trust your catcher's target","Walk him intentionally and pitch to the weaker on-deck hitter","Throw a breaking ball in the dirt and hope he chases","Aim for the middle of the plate to make sure you throw a strike"],
      best:0,explanations:["At 3-2 with 2 outs, this is the ultimate one-pitch moment. Your catcher set up on the corner for a reason. A well-located fastball on the black is extremely hard to hit, even for great hitters. Trust your catcher, hit the target, and let your defense work. Walking him puts a free runner on base and doesn't solve the problem.","Analytics show intentional walks increase the batting team's run expectancy in almost every situation, because you're putting the go-ahead run on first base for free. With 2 outs, one more strike ends the inning. Even their best hitter fails more often than he succeeds.","A breaking ball in the dirt at 3-2 is a gamble — if your catcher can't block it, the runner moves to third. And a 3-2 breaking ball needs perfect execution to get a chase. The fastball on the corner is higher percentage.","Throwing down the middle at 3-2 to their best hitter is asking for trouble, which means you never want to give in with a meatball. Hit the corner or edge — make it a quality pitch."],
      rates:[90,40,25,15],concept:"At 3-2 with 2 outs, trust your pitch and your catcher. One well-located fastball can end the inning — a walk just adds a free runner.",anim:"strike",
      explSimple:["Trust your catcher! One good pitch on the corner and the inning is over. You only need one more strike!","Walking him puts a free runner on base. With 2 outs, just make one good pitch to end the inning instead.","A breaking ball in the dirt might get away from the catcher. The fastball on the corner is a safer choice.","Never throw it down the middle to a great hitter on a full count. Hit the corner!"]},
    {id:"cn21",conceptTag:"count-leverage",title:"1-0 Count — Pitcher, Don't Panic",diff:1,cat:"counts",ageMin:8,ageMax:99,
      description:"You're pitching and just threw ball one to make the count 1-0. Your coach always says 'throw strikes,' and now you feel nervous about falling behind. You don't want to walk this batter.",
      situation:{inning:"Top 3",outs:0,count:"1-0",runners:[],score:[0,0]},
      options:["Throw your best fastball right down the middle to make sure it's a strike","Take a deep breath and throw a quality strike on the corner — one ball isn't a big deal","Switch to your off-speed pitch to try to trick the batter","Throw as hard as you can to overpower the batter"],
      best:1,explanations:["Throwing right down the middle just to get a strike back is giving in, because a 1-0 count is barely behind — you still have plenty of room to make quality pitches. Don't panic-groove a pitch that's easy to hit.","Exactly right! A 1-0 count is not an emergency, since you take a breath, reset, and throw a quality pitch on the corner. You're still in great shape. The best pitchers stay calm and make their normal pitch — they don't change their approach over one ball.","Throwing an off-speed pitch at 1-0 just because you're nervous isn't a strategy — it's a reaction. If you normally throw off-speed at 1-0, fine. But don't change your plan because of one ball. Stay with your game plan.","Overthrowing leads to wild pitches and lost control, because when you try to throw harder than normal, your mechanics break down. The answer to falling behind isn't more effort — it's better execution of your normal delivery."],
      rates:[25,90,30,15],concept:"A 1-0 count is not a crisis. Stay calm, trust your stuff, and throw a quality strike. The worst thing a pitcher can do is panic and groove a pitch or overthrow.",anim:"strike",
      explSimple:["Throwing it right down the middle is too easy to hit. One ball is no big deal!","Perfect! Take a breath and throw a good pitch. A 1-0 count is totally fine — you've got this!","Don't change your plan just because of one ball. Stick with what you normally do.","Trying to throw super hard usually makes you less accurate, not better."]},
    {id:"cn22",conceptTag:"count-leverage",title:"2-2 Even Count With Speed on Base",diff:2,cat:"counts",ageMin:10,ageMax:99,
      description:"You're the pitcher in a 2-2 count with a fast runner on first base. The runner has already stolen two bases tonight. Your catcher worries about another steal. He hits for contact and likes to go the other way. Your catcher signals for a pitchout.",
      situation:{inning:"Bot 4",outs:1,count:"2-2",runners:[1],score:[3,2]},
      options:["Throw the pitchout to give your catcher a clean throw on the steal","Throw a fastball from the slide step to give your catcher a quick transfer","Shake off and throw your slowest curve — the slow delivery will make it easy to steal","Hold the ball longer to freeze the runner, then throw a quality pitch"],
      best:1,explanations:["A pitchout at 2-2 means the count goes to 3-2 and you've lost all your leverage — now the batter gets a hitter's count AND the runner can go on the pitch with full-count steal opportunity. The cost is way too high.","The best answer! A fastball from the slide step addresses both threats, which means the quick delivery gives your catcher the best chance to throw out the runner, and the fastball at 2-2 is still a competitive pitch. You don't sacrifice your count to deal with the runner.","A slow curve with a runner who steals is asking for trouble, because the long arm action and slow velocity give the runner an enormous jump. You'd be helping him steal. Use your quickest delivery, not your slowest.","Holding the ball can work earlier in the count, but at 2-2 you need to attack, since the runner is going to go eventually — your best defense is a quick delivery to the plate so your catcher has time to throw."],
      rates:[15,88,8,35],concept:"Don't sacrifice your pitch count to control the running game. A slide-step fastball lets you stay competitive in the at-bat while giving your catcher a chance to throw.",anim:"steal",
      explSimple:["A pitchout makes the count 3-2 and now the batter has the advantage. That's too costly!","Great choice! A quick pitch gives your catcher time to throw out the runner without hurting the count.","A slow pitch makes it super easy for a fast runner to steal. Use your quickest delivery instead.","Holding the ball works sometimes, but at 2-2 you need to attack. Throw a quick pitch."]},
    {id:"cn23",conceptTag:"count-leverage",title:"0-1 Batter Adjustment",diff:1,cat:"counts",ageMin:8,ageMax:99,
      description:"You're batting and just swung through a fastball to fall behind 0-1. The pitcher looks confident on the mound. You stepped out of the box to collect yourself. What should you adjust for the next pitch?",
      situation:{inning:"Bot 2",outs:0,count:"0-1",runners:[],score:[1,1]},
      options:["Swing harder — you just missed that fastball, so really turn on the next one","Shorten your swing slightly and focus on making contact with the next pitch","Guess off-speed and sit on a breaking ball since he threw a fastball first","Stay with the exact same approach — one strike doesn't change anything"],
      best:3,explanations:["Swinging harder after a miss usually makes things worse because bigger swings create more holes in your swing path, which means more whiffs. The key is keeping the same controlled approach — effort doesn't fix timing.","Shortening your swing has some merit because it helps you make contact, but at 0-1 you're only one strike behind — you haven't reached the point where you need to completely shorten up. Save that adjustment for 0-2, since at 0-1 you still have room to look for a pitch you can drive without giving up your power.","Guessing pitch type at 0-1 is unnecessary because you're only down one strike and can still be selective. If you guess wrong and take a strike, you'll be in an 0-2 hole, which means you've gone from a manageable count to a desperate one for no reason.","One strike doesn't change your approach because at 0-1 you're still in fine shape with two strikes to spare. The key is to keep looking for YOUR pitch in YOUR zone. The best hitters treat 0-1 like 0-0 — they stay patient and attack good pitches, since the adjustment point is at two strikes, not one."],
      rates:[12,35,18,88],concept:"An 0-1 count is not a crisis for the batter. Stay with your approach, look for your pitch, and don't panic. Adjustments come at two strikes, not one.",anim:"strike",
      explSimple:["Swinging harder usually means missing more because bigger swings have more holes.","Shortening up is a good idea later, but at 0-1 it's too early since you still have two strikes to work with.","Don't try to guess what's coming after just one pitch because if you guess wrong you're in a tough 0-2 count.","That's right! One strike is no big deal. Keep doing what you were doing and wait for a good pitch since you adjustments come at two strikes."]},
    {id:"cn24",conceptTag:"count-leverage",title:"3-0 Green Light or Red Light",diff:2,cat:"counts",ageMin:10,ageMax:99,
      description:"You're batting with a 3-0 count. First base is empty, your team is down by two in the 6th inning. The pitcher has been wild tonight, walking four batters already. Your coach gives you the green light to swing if you get your pitch.",
      situation:{inning:"Bot 6",outs:1,count:"3-0",runners:[],score:[2,4]},
      options:["Take the pitch no matter what — let him walk you and get on base for free","Swing at anything close — the pitcher might groove one to get back in the count","Only swing if you get a perfect fastball in your power zone","Bunt for a surprise hit since the infielders won't be expecting it"],
      best:2,explanations:["Taking on 3-0 isn't wrong, but with a green light and a wild pitcher who needs to throw a strike, you might see the best pitch of the entire at-bat. A 3-0 fastball is often a 'get-me-over' pitch right in the zone. If your coach gave you the green light, use it wisely.","Swinging at anything close defeats the purpose of a 3-0 green light. The green light means swing at YOUR pitch — a perfect fastball in your zone. Anything else, take it. You have the luxury of being ultra-selective because even if you miss your pitch, you're still at 3-1.","This is the textbook green-light approach! At 3-0, you have the ultimate hitter's advantage. Only swing at a perfect pitch in your power zone. If you get it, crush it. If you don't, take ball four or be at 3-1 with the count still in your favor. You lose nothing by being selective.","A bunt at 3-0 makes no sense, because you're giving up the biggest hitter's count in baseball for a surprise play with minimal value. The pitcher is wild — let him walk you or give you a meatball."],
      rates:[40,20,90,5],concept:"A 3-0 green light means swing ONLY at your perfect pitch. You have maximum leverage — don't waste it on anything less than ideal. A walk is still a great outcome.",anim:"hit",
      explSimple:["Taking isn't bad, but you might see the easiest pitch to hit of the whole at-bat at 3-0!","Don't swing at just anything. The whole point of 3-0 is to wait for the PERFECT pitch.","Exactly! Only swing if you see the perfect pitch right where you want it. Otherwise, take it.","Bunting at 3-0 is silly. You might get a walk for free or see the best pitch of the at-bat!"]},
    {id:"cn25",conceptTag:"situational-hitting",title:"2-0 Sit on Off-Speed",diff:2,cat:"counts",ageMin:10,ageMax:99,
      description:"You're batting with a 2-0 count against a pitcher who threw you two changeups to start the at-bat — both missed for balls. He loves his changeup and throws it 40% of the time. Your coach always says to be ready for the fastball at 2-0, but you're thinking this pitcher might go right back to the changeup.",
      situation:{inning:"Bot 3",outs:1,count:"2-0",runners:[1,2],score:[1,1]},
      options:["Sit fastball like your coach says — most pitchers come back with heat at 2-0","Look for the changeup since he threw two in a row and might go back to his favorite pitch","Be ready for anything — don't guess, just react to whatever comes","Square around to bunt the runners over"],
      best:1,explanations:["Normally, sitting fastball at 2-0 is solid advice — but baseball rewards situational thinking. This pitcher has thrown you two straight changeups and throws it 40% of the time. The general rule is a starting point — you should adjust to what THIS pitcher is showing you TODAY.","Smart adjustment! Most coaches teach 'sit fastball' at 2-0 as a general rule, and it's usually right. But when a pitcher has thrown you two straight changeups and clearly favors that pitch, the evidence says he might go back to it. At 2-0, you can afford to guess because even if you're wrong, you're at 2-1 and still ahead. Adjust to the pitcher in front of you.","Being ready for anything sounds safe, but at 2-0 you have a luxury most counts don't give you: you can be wrong and still be ahead. This is the perfect count to have a plan. Decide what you're looking for and commit. If you guess wrong, you're still in a hitter's count at 2-1.","Bunting with a 2-0 count and runners on first and second is wasting the count advantage, which means you have the pitcher on the ropes — he's thrown two balls. Make him pay with a hard swing, don't give him an easy out."],
      rates:[35,85,30,8],concept:"General rules like 'sit fastball at 2-0' are starting points. Great hitters adjust to what the specific pitcher is showing them. At 2-0, you can afford to gamble because even a wrong guess leaves you ahead.",anim:"hit",
      explSimple:["Usually sitting on a fastball at 2-0 is smart, but this pitcher keeps throwing changeups. Pay attention!","Good thinking! He threw two changeups in a row and loves that pitch. At 2-0, you can guess and still be ahead even if you're wrong.","You have a 2-0 count — that's a great time to pick what you're looking for instead of just reacting.","Don't bunt when you have a 2-0 count! The pitcher is in trouble — make him pay."]},
    {id:"cn26",conceptTag:"steal-window",title:"Count-Based Stealing",diff:2,cat:"counts",ageMin:10,ageMax:99,
      description:"You're the runner on first base with one out and a good base-stealer's speed. The count on the batter sits at 1-0. Your coach gives you the freedom to pick your spot to steal. You're trying to choose the best count to go on.",
      situation:{inning:"Bot 5",outs:1,count:"1-0",runners:[1],score:[3,3]},
      options:["Go now at 1-0 — the pitcher is behind and more likely to throw a fastball","Wait for a 2-0 or 3-1 count when the pitcher really has to throw a fastball","Go on the first pitch of the next at-bat to catch them off guard","Wait for a full count so the batter can protect you with a swing"],
      best:0,explanations:["Great timing! At 1-0, the pitcher is behind in the count and significantly more likely to throw a fastball. Fastballs get to the plate faster but they're more predictable — the catcher knows what's coming but the pitch is already on its way. More importantly, at 1-0 the pitcher is focused on getting a strike to the batter, not worrying about you.","Waiting for 2-0 or 3-1 has the same logic but delays too long, because the longer you wait, the more the defense expects you to run. At 1-0, you get the 'pitcher behind' advantage while still having some element of surprise. Plus, the at-bat might not reach 2-0.","First-pitch steals can catch teams off guard, but 0-0 is a neutral count where the pitcher might throw anything — including a pitchout or slide-step fastball, since at 1-0, you know the pitcher needs to throw a strike, which limits what he can do to stop you.","A full count steal means the runner goes automatically on the pitch, which helps. But getting to a full count isn't guaranteed, and by then the defense has seen you on base for 5+ pitches and is on high alert. Earlier steals are higher percentage because of the surprise factor."],
      rates:[85,40,30,35],concept:"The best counts for stealing are when the pitcher is slightly behind (1-0, 2-1) because he's focused on throwing a strike to the batter and more likely to throw a predictable fastball.",anim:"steal",
      explSimple:["Good call! When the pitcher is behind 1-0, he's thinking about the batter, not you. Great time to go!","Same idea but waiting too long. The defense might expect you to run if you wait longer.","On 0-0, the pitcher could throw anything. At 1-0, he needs a strike, which is better for you.","By a full count, the defense knows you might run. Earlier is better for surprise."]},
    {id:"cn27",conceptTag:"pitch-sequencing",title:"1-2 Put-Away Pitch (Pitcher's View)",diff:3,cat:"counts",ageMin:12,ageMax:99,
      description:"You're pitching with a 1-2 count on a dangerous power hitter. You got ahead with a fastball up (called strike) and a slider low (swinging strike). He crushes anything up in the zone but struggles with low off-speed. He's looking to ambush. Your catcher signals for another slider low.",
      situation:{inning:"Top 7",outs:1,count:"1-2",runners:[2],score:[3,2]},
      options:["Throw the slider low where he just whiffed — go back to what worked","Elevate a fastball up and in — he can't lay off his pitch","Throw a changeup low — different speed, same location as the slider he missed","Throw the slider but higher — a backdoor slider at the knees for a called strike"],
      best:2,explanations:["Going right back to the same slider in the same spot is predictable, because after a swing and miss, good hitters adjust. He'll be sitting on that slider now and might lay off or fight it off. You need to change something — speed, location, or both.","Elevating to a power hitter's favorite zone is exactly what he wants — you said he crushes fastballs up. Even at 1-2, throwing his strength pitch in his strength zone is playing his game. At 1-2, you dictate — don't throw what he's looking for.","Brilliant pitch selection! The changeup low gives you a completely different look with the same arm action as your fastball. He just swung through a slider low, so he might be adjusting to that spin. A changeup looks like a fastball out of the hand but arrives 8-10 mph slower in the same low zone — his bat will be way out front. This is elite sequencing.","A backdoor slider at the knees is a good pitch in some counts, but at 1-2 with a dangerous hitter, you want a swing and miss, not a called strike, which means go for the strikeout with something he'll chase, not something the umpire might call a ball."],
      rates:[25,10,88,35],concept:"Elite pitch sequencing at 1-2 means changing the look, not repeating what worked. Same location, different speed catches hitters who are adjusting to what they just saw.",anim:"strikeout"},
    {id:"cn28",conceptTag:"count-leverage",title:"Full Count, Nobody On — Batter's Edge",diff:3,cat:"counts",ageMin:12,ageMax:99,
      description:"Full count, 3-2, nobody on base, one out in a scoreless game in the 4th inning. The pitcher has thrown you four fastballs and one slider this at-bat. The slider was ball three — it bounced in the dirt. He's been pounding the fastball all game with a 92-mph four-seamer. You're a good fastball hitter. He starts his windup.",
      situation:{inning:"Bot 4",outs:1,count:"3-2",runners:[],score:[0,0]},
      options:["Sit dead-red fastball — that's what he's thrown 80% of the at-bat and his slider bounced","Protect the plate and react to whatever comes — can't strike out looking","Look for the slider since he might try to surprise you after bouncing the last one","Crowd the plate to take away the outside fastball and force him to come inside"],
      best:0,explanations:["This is the spot to commit! The pitcher has thrown four fastballs and one slider this at-bat. The slider bounced. The data is screaming fastball: he throws it 80% of the time and his off-speed is unreliable today. As a good fastball hitter, this is your moment. Commit to the fastball, time it up, and drive it. If he throws the slider and it's a strike, tip your cap — but the odds are heavily in your favor.","'Protect the plate' is the safe answer, but safe isn't always smart. At 3-2 with a pitcher who's been fastball-dominant and just bounced his slider, you have a huge information advantage. Reacting to everything means you're not truly ready for anything. At full count, the best hitters have a plan and commit to it.","Looking for the slider after he just bounced one is going against the evidence, because he knows his slider is unreliable tonight. The much more likely pitch is the fastball he's been pumping all game. Don't overthink this — the evidence points to fastball.","Crowding the plate is a physical adjustment that takes time and might throw off your timing, since at 3-2 with one pitch coming, you need to be mentally committed to a plan, not making mechanical changes in the box. Crowding also opens you up to being hit by the pitch."],
      rates:[90,35,15,18],concept:"At 3-2, use the information from the entire at-bat. If a pitcher has been fastball-dominant and his secondary stuff is shaky, commit to the heater. Great hitters use evidence, not guesses.",anim:"hit"}
  ],
};
